(function() {
var al_ch_1_Verses = [
  {num:1,words:[["O Lenei sa oo,", "Now it came to pass that in the first year of the reign of the judges over the people of Nephi,"], ["o le tausaga muamua o le nofoaiga a faamasino i le nuu o Nifae,", "from this time forward,"], ["mai le taimi nei e oo atu i luma,", "king Mosiah having gone the way of all the earth,"], ["ona ua alu le tupu o Mosaea i le ala o le lalolagi uma,", "having warred a good warfare,"], ["ina ua uma ona tau e ia o se taua lelei, ma savali sao i luma o le Atua,", "walking uprightly before God,"], ["ma lē tuua se tasi e nofotupu e sui ia te ia;", "leaving none to reign in his stead;"], ["e ui i lea sa faatutu e ia tulafono ,", "nevertheless he had established laws,"], ["ma sa talia ia tulafono e le nuu;", "and they were acknowledged by the people;"], ["o lea na faamalosia ai i latou ia latou ola e tusa ai ma tulafono na faia e ia.", "therefore they were obliged to abide by the laws which he had made."]]},
  {num:2,words:[["Ma sa oo i le tausaga muamua o le nofoaiga a Alema i le nofoa-faamasino,", "And it came to pass that in the first year of the reign of Alma in the judgment - seat,"], ["sa i ai se tagata sa aumai i ona luma ina ia faamasinoina,", "there was a man brought before him to be judged,"], ["o se tagata tino ese,", "a man who was large,"], ["ma sa lauiloa i lona malosi tele.", "and was noted for his much strength."]]},
  {num:3,words:[["Ma sa fealuai solo o ia i totonu o le nuu,", "And he had gone about among the people,"], ["ma talai atu ia te i latou se mea sa ia taua o le afioga a le Atua,", "preaching to them that which he termed to be the word of God,"], ["e tuuaia malosi ai i lalo e faasaga i le ekalesia;", "bearing down against the church;"], ["ma fai atu i tagata e tatau i faitaulaga uma ma aoao ona avea ma tagata e tausi e tagata lautele;", "declaring unto the people that every priest and teacher ought to become popular;"], ["ma e lē tatau ona latou galulue i o latou lima,", "and they ought not to labor with their hands,"], ["ae tatau ona tausi i latou e le nuu.", "but that they ought to be supported by the people."]]},
  {num:4,words:[["Ma sa molimau atu foi o ia i le nuu o le a faaolaina tagata uma i le aso mulimuli;", "And he also testified unto the people that all mankind should be saved at the last day,"], ["ma e lē tatau ona latou fefefe pe tetete,", "and that they need not fear nor tremble,"], ["ae ia ea i luga o latou ulu ma olioli;", "but that they might lift up their heads and rejoice;"], ["ona na foafoa e le Alii tagata uma,", "for the Lord had created all men,"], ["ma ua togiola foi e ia tagata uma;", "and had also redeemed all men;"], ["ma,", "and,"], ["i le iuga,", "in the end,"], ["o le a maua e tagata uma le ola e faavavau.", "all men should have eternal life."]]},
  {num:5,words:[["Ma sa oo ina sa matua tele ona ia aoao atu o nei mea sa toatele naua i latou sa talitonu i ana upu,", "And it came to pass that he did teach these things so much that many did believe on his words,"], ["sa matua toatele lava sa amata ona latou lagolagoina o ia ma avatu tupe ia te ia.", "even so many that they began to support him and give him money."]]},
  {num:6,words:[["Ma sa amata ona faafefeteina o ia i le faamaualuga o lona loto,", "And he began to be lifted up in the pride of his heart,"], ["ma ofu i ofu e sili ona taugata,", "and to wear very costly apparel,"], ["ioe,", "yea,"], ["ma sa oo lava ina amata ona ia faatuina se ekalesia e tusa ma le ala o lana talaiga.", "and even began to establish a church after the manner of his preaching."]]},
  {num:7,words:[["Ma a'o alu atu o ia e talai atu ia i latou o e na talitonu i ana upu,", "And it came to pass as he was going,"], ["sa fetaiai o ia ma se tagata o sē na auai i le ekalesia a le Atua,", "to preach to those who believed on his word,"], ["ioe,", "he met a man who belonged to the church of God,"], ["o se tasi lava o o latou aoao;", "yea,"], ["ma sa amata ona ia finau malosi ma ia,", "even one of their teachers; and he began to contend with him sharply,"], ["ina ia mafai ona ia taitai ese tagata o le ekalesia;", "that he might lead away the people of the church;"], ["peitai sa tutetee malosi atu lenei tagata ia te ia,", "but the man withstood him,"], ["ma aoai o ia i le afioga a le Atua.", "admonishing him with the words of God."]]},
  {num:8,words:[["O lenei o le igoa o lenei tagata o Kitiona ;", "Now the name of the man was Gideon;"], ["ma o ia lea o lē na avea ma auupega i aao o le Atua i le laveaiina o le nuu o Limae mai le pologa.", "and it was he who was an instrument in the hands of God in delivering the people of Limhi out of bondage."]]},
  {num:9,words:[["O lenei,", "Now,"], ["ona sa tutetee malosi atu Kitiona ia te ia e ala i afioga a le Atua, sa oo ina ita o ia ia Kitiona,", "because Gideon withstood him with the words of God he was wroth with Gideon,"], ["ma sei lana pelu ma amata ona ta o ia.", "and drew his sword and began to smite him."], ["O lenei ona ua toeaina lava Kitiona i le tele o ona tausaga,", "Now Gideon being stricken with many years,"], ["o lea sa lē mafai ai e ia ona talitalia ana ta,", "therefore he was not able to withstand his blows,"], ["o lea na fasiotia ai o ia i le pelu.", "therefore he was slain by the sword."]]},
  {num:10,words:[["Ma o le tagata o lē na fasiotia o ia sa ave e tagata o le ekalesia,", "And the man who slew him was taken by the people of the church,"], ["ma aumai o ia i luma o Alema,", "and was brought before Alma,"], ["ina ia faamasinoina e tusa ma solitulafono na ia faia.", "to be judged according to the crimes which he had committed."]]},
  {num:11,words:[["Ma sa oo ina tu atu o ia i luma o Alema ma tali atu mo ia lava ma le lotoa tele.", "And it came to pass that he stood before Alma and pleaded for himself with much boldness."]]},
  {num:12,words:[["Peitai sa fai atu Alema ia te ia:", "But Alma said unto him:"], ["Faauta,", "Behold,"], ["o le taimi muamua lenei ua tulai mai ai le faafaitaulaga pepelo i totonu o le nuu lenei.", "this is the first time that priestcraft has been introduced among this people."], ["Ma faauta,", "And behold,"], ["ua lē gata ona e sala i le faia o le faafaitaulaga pepelo,", "thou art not only guilty of priestcraft,"], ["ae ua e taumafai foi e faamalosia i le pelu; ma afai e tuu le faafaitaulaga pepelo ia faamalosia i totonu o le nuu lenei,", "but hast endeavored to enforce it by the sword;"], ["o le a avea ma mea e mautinoa ai le faaumatiaina atoa o i latou.", "and were priestcraft to be enforced among this people it would prove their entire destruction."]]},
  {num:13,words:[["Ma ua e faamaligiina le toto o se tagata amiotonu,", "And thou hast shed the blood of a righteous man,"], ["ioe,", "yea,"], ["o se tagata o lē na faia mea lelei e tele i totonu o lenei nuu; ma afai matou te faasaoina oe,", "a man who has done much good among this people;"], ["o le a oo mai lona toto i o matou luga ia tauimasui .", "and were we to spare thee his blood would come upon us for vengeance."]]},
  {num:14,words:[["O le mea lea ua faasala ai oe i le oti,", "Therefore thou art condemned to die,"], ["e tusa ma le tulafono na tuu mai ia te i tatou e Mosaea,", "according to the law which has been given us by Mosiah,"], ["lo tatou tupu mulimuli;", "our last king;"], ["ma ua talia e lenei nuu;", "and it has been acknowledged by this people;"], ["o lea e ao ai i lenei nuu ona ola e tusa ai ma le tulafono.", "therefore this people must abide by the law."]]},
  {num:15,words:[["Ma sa oo ina latou ave o ia;", "And it came to pass that they took him;"], ["ma o lona igoa o Ne'oa ;", "and his name was Nehor;"], ["ma sa latou ave o ia i luga i le tumutumu o le maupuepue o Maneti,", "and they carried him upon the top of the hill Manti,"], ["ma o iina na uunaiina ai o ia,", "and there he was caused,"], ["pe na ia tautino mai ai,", "or rather did acknowledge,"], ["i le va o le lagi ma le lalolagi,", "between the heavens and the earth,"], ["o mea sa ia aoao atu i tagata sa ese mai le afioga a le Atua;", "that what he had taught to the people was contrary to the word of God;"], ["ma o iina na ia mafatia ai i se oti maasiasi lava.", "and there he suffered an ignominious death."]]},
  {num:16,words:[["E ui i lea,", "Nevertheless,"], ["sa lē iu i lenei mea le sosolo o le faafaitaulaga pepelo i le laueleele;", "this did not put an end to the spreading of priestcraft through the land;"], ["ona e toatele e sa i ai sa fiafia i mea le aoga a le lalolagi,", "for there were many who loved the vain things of the world,"], ["ma sa latou o atu ma talai atu mataupu faavae sese;", "and they went forth preaching false doctrines;"], ["ma sa latou faia lenei mea mo le faamoemoe o le mauaina o oa ma le mamalu.", "and this they did for the sake of riches and honor."]]},
  {num:17,words:[["E ui i lea,", "Nevertheless,"], ["sa latou fefefe e pepelo ,", "they durst not lie,"], ["pe afai e iloa,", "if it were known,"], ["ona o le fefefe i le tulafono,", "for fear of the law,"], ["ona sa faasalaina tagata pepelo;", "for liars were punished;"], ["o lea sa latou faatagā talai atu ai e faapea ua latou talai atu e tusa ai ma o latou talitonuga;", "therefore they pretended to preach according to their belief;"], ["ma o lenei sa lē mafai ona maua e le tulafono se pule i luga o soo se tagata ona o lona talitonuga.", "and now the law could have no power on any man for his belief."]]},
  {num:18,words:[["Ma sa latou fefefe e gaoi ,", "And they durst not steal,"], ["ona o le matatau i le tulafono,", "for fear of the law,"], ["ona o tagata faapena sa faasalaina; pe sa latou totoa e faomea,", "for such were punished;"], ["pe fasioti tagata,", "neither durst they rob,"], ["ona o ia o lē e fasioti tagata,", "nor murder,"], ["sa faasala i le oti .", "for he that murdered was punished unto death."]]},
  {num:19,words:[["Peitai sa oo ina o soo se tasi sa lē auai i le ekalesia a le Atua, sa amata ona latou sauaina i latou o e sa auai i le ekalesia a le Atua,", "But it came to pass that whosoever did not belong to the church of God began to persecute those that did belong to the church of God,"], ["ma ua ave i o latou luga le suafa o Keriso.", "and had taken upon them the name of Christ."]]},
  {num:20,words:[["Ioe,", "Yea,"], ["sa latou sauaina i latou,", "they did persecute them,"], ["ma faatiga ia te i latou i ituaiga uma o upu eseese,", "and afflict them with all manner of words,"], ["ma o lenei ona o lo latou lotomaualalo;", "and this because of their humility;"], ["ona sa latou lē faamaualuluga i o latou lava mata,", "because they were not proud in their own eyes,"], ["ma ona sa latou faasoa atu le afioga a le Atua,", "and because they did impart the word of God,"], ["o le tasi i le isi,", "one with another,"], ["e aunoa ma se tupe ma aunoa ma se tau.", "without money and without price."]]},
  {num:21,words:[["O lenei sa i ai se tulafono sa'olele i totonu o tagata o le ekalesia,", "Now there was a strict law among the people of the church that there should not any man,"], ["ia leai se tagata e auai i le ekalesia,", "belonging to the church,"], ["e tu a'e ma sauaina i latou o e e lē auai i le ekalesia,", "arise and persecute those that did not belong to the church,"], ["ma ia leai ni sauaga e i ai i totonu o i latou lava.", "and that there should be no persecution among themselves."]]},
  {num:22,words:[["E ui i lea,", "Nevertheless,"], ["sa i ai le toatele i totonu o i latou o e sa amata ona faamaualuluga,", "there were many among them who began to be proud,"], ["ma amata ona finau malolosi ma o latou fili,", "and began to contend warmly with their adversaries,"], ["na oo lava ina fepa'ia'i ai;", "even unto blows;"], ["ioe,", "yea,"], ["sa latou taua'ifusu.", "they would smite one another with their fists."]]},
  {num:23,words:[["O lenei sa tupu lenei mea i le tausaga lona lua o le nofoaiga a Alema,", "Now this was in the second year of the reign of Alma,"], ["ma sa avea ma pogai o le puapuaga tele i le ekalesia;", "and it was a cause of much affliction to the church;"], ["ioe,", "yea,"], ["sa avea ma pogai o tofotofoga tele i le ekalesia.", "it was the cause of much trial with the church."]]},
  {num:24,words:[["Ona sa faamaaa loto o le toatele,", "For the hearts of many were hardened,"], ["ma sa soloia ese o latou igoa,", "and their names were blotted out,"], ["sa lē toe manatua ai i latou i totonu o le nuu o le Atua. Ma e toatele foi sa latou aveese i latou lava mai totonu o i latou.", "that they were remembered no more among the people of God. And also many withdrew themselves from among them."]]},
  {num:25,words:[["O lenei mea sa avea ma tofotofoga tele ia te i latou o e sa tutu mausali i le faatuatua;", "Now this was a great trial to those that did stand fast in the faith;"], ["e ui i lea,", "nevertheless,"], ["sa latou mausali ma le lē mafaagaeetia i le tausiga o poloaiga a le Atua,", "they were steadfast and immovable in keeping the commandments of God,"], ["ma sa latou talia ma le onosai sauaga sa faafaulai i o latou luga.", "and they bore with patience the persecution which was heaped upon them."]]},
  {num:26,words:[["Ma a tuu e faitaulaga a latou galuega ina ia talai atu le afioga a le Atua i tagata,", "And when the priests left their labor to impart the word of God unto the people,"], ["sa tuu foi e tagata a latou galuega ina ia faalogologo atu i le afioga a le Atua.", "the people also left their labors to hear the word of God."], ["Ma a uma ona talai atu e le faitaulaga ia te i latou le afioga a le Atua,", "And when the priest had imparted unto them the word of God they all returned again diligently unto their labors;"], ["sa latou toe foi atu uma ia latou galuega ma le filiga;", "and the priest,"], ["ma o le faitaulaga, sa lē manatu ua sili atu o ia i luga o e na faalogologo mai ia te ia,", "not esteeming himself above his hearers,"], ["ona sa lē sili atu le lelei o lē sa talai atu nai lo lē sa faalogologo mai ia te ia,", "for the preacher was no better than the hearer,"], ["pe sa sili atu foi le lelei o lē na aoao atu,", "neither was the teacher any better than the learner;"], ["i lē na aoaoina; ma sa faapea ona latou tutusa uma,", "and thus they were all equal,"], ["ma sa latou galulue uma,", "and they did all labor,"], ["o tagata taitoatasi uma e tusa ma lona lava malosi.", "every man according to his strength."]]},
  {num:27,words:[["Ma sa latou faasoa atu a latou mea,", "And they did impart of their substance,"], ["o tagata taitoatasi uma e tusa ma mea sa ia te ia,", "every man according to that which he had,"], ["i e ua matitiva ,", "to the poor,"], ["ma e ua lē tagolima,", "and the needy,"], ["ma e ua mamai,", "and the sick,"], ["ma e ua puapuagatia;", "and the afflicted;"], ["ma sa latou lē oofu i ofu taugata,", "and they did not wear costly apparel,"], ["ae sa latou mama ma lalelei.", "yet they were neat and comely."]]},
  {num:28,words:[["Ma sa faapea ona latou faatulaga o mataupu o le ekalesia;", "And thus they did establish the affairs of the church;"], ["ma sa faapea ona amata ona latou toe maua o le filemu alualu pea,", "and thus they began to have continual peace again,"], ["e ui i o latou puapuaga uma.", "notwithstanding all their persecutions."]]},
  {num:29,words:[["Ma o lenei,", "And now,"], ["ona o le mautu o le ekalesia sa amata ona latou mauoa tele,", "because of the steadiness of the church they began to be exceedingly rich,"], ["i le mau tele i soo se mea o mea uma sa latou manaomia—o le mau i lafu ma fagaga,", "having abundance of all things whatsoever they stood in need—an abundance of flocks and herds,"], ["ma manu pepeti o ituaiga uma,", "and fatlings of every kind,"], ["ma le mau foi i kuranuma,", "and also abundance of grain,"], ["ma auro,", "and of gold,"], ["ma ario,", "and of silver,"], ["ma mea taua,", "and of precious things,"], ["ma le mau i le silika ma ie lino miloa lelei,", "and abundance of silk  and fine–twined linen,"], ["ma ituaiga uma o ie papa lelei.", "and all manner of good homely cloth."]]},
  {num:30,words:[["Ma sa faapea,", "And thus,"], ["i o latou tulaga tamaoaiga ,", "in their prosperous circumstances,"], ["ona latou lē auina ese atu soo se tasi sa lē lavalavā po o se sa fia 'ai,", "they did not send away any who were naked,"], ["po o se sa fia inu,", "or that were hungry,"], ["po o se sa mai,", "or that were athirst,"], ["po o se sa lē tausia;", "or that were sick,"], ["ma sa latou lē tuu atu o latou loto i luga o oa;", "or that had not been nourished; and they did not set their hearts upon riches;"], ["o lea sa latou limafoai i tagata uma,", "therefore they were liberal to all,"], ["o e matutua ma e laiti,", "both old and young,"], ["o e pologa ma e saoloto,", "both bond and free,"], ["o tane ma fafine,", "both male and female,"], ["pe e i fafo o le ekalesia pe e i totonu o le ekalesia,", "whether out of the church or in the church,"], ["sa leai so latou faailoga tagata e faatatau ia te i latou o e na manaomia le fesoasoani.", "having no respect to persons as to those who stood in need."]]},
  {num:31,words:[["Ma sa faapea ona latou manuia ma sili atu ona mauoa nai lo i latou o e sa lē auai i la latou ekalesia.", "And thus they did prosper and become far more wealthy than those who did not belong to their church."]]},
  {num:32,words:[["Ona o i latou o e sa lē auai i la latou ekalesia,", "For those who did not belong to their church did indulge themselves in sorceries,"], ["sa latou auai i le faia o mea faataulaitu,", "and in idolatry or idleness,"], ["ma le ifo i tupua po o le paie ,", "and in babblings,"], ["ma le fai o tala lē aoga,", "and in envyings and strife;"], ["ma i losilosivalega ma finauga;", "wearing costly apparel;"], ["ma oofu i ofu taugata;", "being lifted up in the pride of their own eyes;"], ["ma faafefeteina i le faamaualuluga o o latou lava mata;", "persecuting,"], ["ma faasaua,", "lying,"], ["pepelo,", "thieving,"], ["gaoi,", "robbing,"], ["faomea ma le faitaaga,", "committing whoredoms,"], ["ma fasioti tagata,", "and murdering,"], ["ma ituaiga amioleaga uma;", "and all manner of wickedness;"], ["e ui i lea,", "nevertheless,"], ["sa faaaoga le tulafono i luga o i latou uma o e sa solia,", "the law was put in  force upon all those who did transgress it,"], ["i le tele sa mafai ai.", "inasmuch as it was possible."]]},
  {num:33,words:[["Ma sa oo o le faaaoga faapea o le tulafono i luga o i latou,", "And it came to pass that by thus exercising the law upon them,"], ["e mafatia tagata taitoatasi e tusa ai ma le mea na ia faia,", "every man suffering according to that which he had done,"], ["sa atili ai ona latou fifilemu, ma fefefe ai e fai se amioleaga pe afai e iloa;", "they became more still,"], ["o lea,", "and durst not commit any wickedness if it were known;"], ["sa i ai le filemu tele i totonu o le nuu o Nifae,", "therefore,"], ["seia oo mai i le lona lima o tausaga o le nofoaiga a faamasino.", "there was much peace among the people of Nephi until the fifth year of the reign of the judges."]]},
];
renderVerseSet(al_ch_1_Verses, 'al-ch1-verses');

var al_ch_2_Verses = [
  {num:1,words:[["Ma sa oo,", "And it came to pass in the commencement of the fifth year of their reign there began to be a contention among the people;"], ["i le amataga o le lona lima o tausaga o la latou nofoaiga,", "for a certain man,"], ["sa amata ai ona i ai o se finauga i totonu o le nuu; ona sa i ai se tasi tagata,", "being called Amlici,"], ["sa igoa ia Amiliki,", "he being a very cunning man,"], ["o ia o se tagata faitogafiti tele,", "yea,"], ["ioe, o se tagata poto tele e tusa ai ma le poto o le lalolagi,", "a wise man as to the wisdom of the world,"], ["ma o ia o sē o le faatulagaga a le tagata lea na fasiotia Kitiona i le pelu,", "he being after the order of the man that slew Gideon by the sword,"], ["lea na fasioti e tusa ai ma le tulafono—", "who was executed according to the law—"]]},
  {num:2,words:[["O lenei o le Amiliki lenei na ia taitai ese,", "Now this Amlici had,"], ["i lona faitogafiti,", "by his cunning,"], ["le toatele o tagata, ia mulimuli atu ia te ia;", "drawn away much people after him;"], ["sa matua toatele lava i latou sa amata ona latou malosi tele;", "even so much that they began to be very powerful;"], ["ma sa amata ona latou taumafai e faatu Amiliki e avea ma tupu i le nuu.", "and they began to endeavor to establish Amlici to be king over the people."]]},
  {num:3,words:[["O lenei sa popole tagata o le ekalesia i lenei mea, ma faapea foi i latou uma o e sa lē taitaieseina i faatauanauga a Amiliki;", "Now this was alarming to the people of the church,"], ["ona sa latou iloa,", "and also to all those who had not been drawn away after the persuasions of Amlici;"], ["e tusa ma la latou tulafono, o mea faapea e ao ina faatutuina i le leo o le nuu.", "for they knew that according to their law that such things must be established by the voice of the people."]]},
  {num:4,words:[["O lea,", "Therefore,"], ["afai e mafai ona maua e Amiliki le leo o le nuu,", "if it were possible that Amlici should gain the voice of the people,"], ["o ia,", "he,"], ["o se tagata amioleaga,", "being a wicked man,"], ["o le a aveese e ia mai ia te i latou a latou aiā ma avanoa o le ekalesia;", "would deprive them of their rights and privileges of the church;"], ["ona o lona faamoemoe ia faaumatia le ekalesia a le Atua.", "for it was his intent to destroy the church of God."]]},
  {num:5,words:[["Ma sa oo ina faapotopoto faatasi e tagata i latou lava i le laueleele atoa,", "And it came to pass that the people assembled themselves together throughout all the land,"], ["i tino potopoto eseese,", "every man according to his mind,"], ["i le finau tele ma fefinauaiga tetele o le tasi ma le isi,", "whether it were for or against Amlici,"], ["e taitasi le tagata e tusa ma lona manatu,", "in separate bodies,"], ["pe mo Amiliki pe tetee ia te ia.", "having much dispute and wonderful contentions one with another."]]},
  {num:6,words:[["Ma sa faapea ona latou faapotopoto faatasi i latou lava e tuu atu o latou leo e faatatau i le mataupu;", "And thus they did assemble themselves together to cast in their voices concerning the matter;"], ["ma sa folasia atu o latou leo i luma o faamasino.", "and they were laid before the judges."]]},
  {num:7,words:[["Ma sa oo ina sa tetee le leo o le nuu ia Amiliki,", "And it came to pass that the voice of the people came against Amlici,"], ["ma lē faia ai o ia ma tupu i le nuu.", "that he was not made king over the people."]]},
  {num:8,words:[["O lenei sa avea lenei mea ma mea sa tupu ai le olioli tele i loto o i latou o e sa tetee ia te ia; peitai sa faaoso e Amiliki i latou o e na mananao ia te ia,", "Now this did cause much joy in the hearts of those who were against him;"], ["ia feitai ia te i latou o e na lē mananao ia te ia.", "but Amlici did stir up those who were in his favor to anger against those who were not in his favor."]]},
  {num:9,words:[["Ma sa oo ina latou faapotopoto faatasi i latou lava,", "And it came to pass that they gathered themselves together,"], ["ma faapaia Amiliki e avea ma o latou tupu.", "and did consecrate Amlici to be their king."]]},
  {num:10,words:[["O lenei ina ua avea Amiliki ma tupu i luga o i latou, sa ia faatonuina i latou ia latou sii atu auupega o taua e faasaga i o latou uso;", "Now when Amlici was made king over them he commanded them that they should take up arms against their brethren;"], ["ma sa faia e ia lenei mea, ina ia mafai ai ona pule o ia ia te i latou.", "and this he did that he might subject them to him."]]},
  {num:11,words:[["O lenei sa faailoga ese tagata o Amiliki i le igoa o Amiliki,", "Now the people of Amlici were distinguished by the name of Amlici,"], ["sa ta'ua o sa Amilikī;", "being called Amlicites;"], ["ma o e na totoe sa ta'ua o sa Nifaē,", "and the remainder were called Nephites,"], ["po o tagata o le Atua.", "or the people of God."]]},
  {num:12,words:[["O lea,", "Therefore the people of the Nephites were aware of the intent of the Amlicites,"], ["sa iloa e tagata o sa Nifaē le faamoemoega o sa Amilikī,", "and therefore they did prepare to meet them;"], ["ma o lea sa latou sauni ai e fetaia'i ma i latou;", "yea,"], ["ioe,", "they did arm themselves with swords,"], ["sa latou faaauupegaina i latou lava i pelu,", "and with cimeters,"], ["ma simetea, ma aufana,", "and with bows,"], ["ma u fanafana,", "and with arrows,"], ["ma maa,", "and with stones,"], ["ma maatā,", "and with slings,"], ["ma ituaiga uma o auupega eseese,", "and with all manner of weapons of war,"], ["o taua.", "of every kind."]]},
  {num:13,words:[["Ma sa faapea ona latou saunia e fetaia'i ma sa Amilikī i le taimi latou te o mai ai. Ma sa tofia ni kapeteni,", "And thus they were prepared to meet the Amlicites at the time of their coming. And there were appointed captains,"], ["ma kapeteni maualuluga,", "and higher captains,"], ["ma kapeteni sili,", "and chief captains,"], ["e tusa ai ma lo latou faitau aofai.", "according to their numbers."]]},
  {num:14,words:[["Ma sa oo ina faaauupega e Amiliki ana tagata i ituaiga uma o auupega eseese o taua;", "And it came to pass that Amlici did arm his men with all manner of weapons of war of every kind;"], ["ma sa ia tofia foi ni pule ma ni taitai i luga o ona tagata,", "and he also appointed rulers and leaders over his people,"], ["e taitai i latou i le taua e faasaga i o latou uso.", "to lead them to war against their brethren."]]},
  {num:15,words:[["Ma sa oo ina o mai sa Amilikī i le maupuepue o Aminisu,", "And it came to pass that the Amlicites came upon the hill Amnihu,"], ["sa i le itu i sasae o le vaitafe o Saitonu,", "which was east of the river Sidon,"], ["lea sa tafe i tafatafa ane o le laueleele o Sara'emila,", "which ran by the land of Zarahemla,"], ["ma o iina na amata ai ona latou tau ma sa Nifaē.", "and there they began to make war with the Nephites."]]},
  {num:16,words:[["O lenei o Alema,", "Now Alma,"], ["ona o ia o le faamasino sili ma kovana o le nuu o Nifae,", "being the chief judge and the governor of the people of Nephi,"], ["o lea na alu a'e ai o ia faatasi ma ona tagata,", "therefore he went up with his people,"], ["ioe,", "yea,"], ["faatasi ma ana kapeteni,", "with his captains,"], ["ma kapeteni sili,", "and chief captains,"], ["ioe,", "yea,"], ["i le ulu o ana autau,", "at the head of his armies,"], ["e faasaga ia sa Amilikī i le taua.", "against the Amlicites to battle."]]},
  {num:17,words:[["Ma sa amata ona latou fasi o sa Amilikī i luga o le maupuepue i le itu i sasae o Saitonu. Ma sa tau sa Amilikī ma sa Nifaē ma le malosi tele,", "And they began to slay the Amlicites upon the hill east of Sidon. And the Amlicites did contend with the Nephites with great strength,"], ["sa oo ina pauu le toatele o sa Nifaē i luma o sa Amilikī.", "insomuch that many of the Nephites did fall before the Amlicites."]]},
  {num:18,words:[["E ui i lea sa faamalosia e le Alii le lima o sa Nifaē,", "Nevertheless the Lord did strengthen the hand of the Nephites,"], ["sa oo ina latou fasi sa Amilikī i se fasiga tele,", "that they slew the Amlicites with great slaughter,"], ["sa oo ina amata ona latou sosola ese mai i o latou luma.", "that they began to flee before them."]]},
  {num:19,words:[["Ma sa oo ina tuli e sa Nifaē sa Amilikī i le aso atoa lena,", "And it came to pass that the Nephites did pursue the Amlicites all that day,"], ["ma fafasi i latou i se fasiga tele,", "and did slay them with much slaughter,"], ["sa oo ina fasia ai sa Amilikī e sefulu lua afe lima selau tolu sefulu ma le lua;", "insomuch that there were slain of the Amlicites twelve thousand five hundred thirty and two souls;"], ["ma o sa Nifaē na fasia e ono afe lima selau ono sefulu ma le lua tagata.", "and there were slain of the Nephites six thousand five hundred sixty and two souls."]]},
  {num:20,words:[["Ma sa oo ina ua lē mafai e Alema ona toe tuli o sa Amilikī, sa faia e ia ia faatutu e ona tagata o latou faleie i le vanu o Kitiona,", "And it came to pass that when Alma could pursue the Amlicites no longer he caused that his people should pitch their tents in the valley of Gideon,"], ["le vanu lea sa faaigoa i le igoa o Kitiona,", "the valley being called after that Gideon who was slain by the hand of Nehor with the sword;"], ["o lē na fasioti i le pelu e le lima o Ne'oa ; ma o le vanu lenei sa faatutu ai e sa Nifaē o latou faleie mo le po.", "and in this valley the Nephites did pitch their tents for the night."]]},
  {num:21,words:[["Ma sa auina atu e Alema sipai e mulimuli i e na totoe o sa Amilikī,", "And Alma sent spies to follow the remnant of the Amlicites,"], ["ina ia mafai ona iloa e ia e uiga ia latou fuafuaga ma a latou taupulepulega,", "that he might know of their plans and their plots,"], ["ina ia mafai ona ia leoleoina o ia lava e faasaga ia te i latou,", "whereby he might guard himself against them,"], ["ina ia mafai ona ia faasaoina ona tagata mai le faaumatiaina.", "that he might preserve his people from being destroyed."]]},
  {num:22,words:[["O lenei o i latou o e na ia auina atu e vaavaai le tolauapiga a sa Amilikī,", "Now those whom he had sent out to watch the camp of the Amlicites were called Zeram,"], ["sa igoa o Serama,", "and Amnor,"], ["ma Aminoa, ma Maneti,", "and Manti,"], ["ma Limea;", "and Limher;"], ["o i latou nei o e na o atu i fafo ma a latou tagata e vaavaai le togalauapiga a sa Amilikī.", "these were they who went out with their men to watch the camp of the Amlicites."]]},
  {num:23,words:[["Ma o le aso na sosoo ai na latou toe foi mai ai i le tolauapiga a sa Nifaē ma le faanatinati tele,", "And it came to pass that on the morrow they returned into the camp of the Nephites in great haste,"], ["ma le ofo tele,", "being greatly astonished,"], ["ua taia i le matau tele,", "and struck with much fear,"], ["fai mai:", "saying:"]]},
  {num:24,words:[["Faauta,", "Behold,"], ["sa matou mulimuli i le tolauapiga a sa Amilikī,", "we followed the camp of the Amlicites,"], ["ma sa matou ofo tele lava,", "and to our great astonishment,"], ["i lo matou vaaia,", "in the land of Minon,"], ["i le laueleele o Minona, i luga a'e o le laueleele o Sara'emila,", "above the land of Zarahemla,"], ["i le ala i le laueleele o Nifae ,", "in the course of the land of Nephi,"], ["se autau toatele lava a sa Lamanā;", "we saw a numerous host of the Lamanites;"], ["ma faauta,", "and behold,"], ["ua faatasi atu sa Amilikī ia te i latou;", "the Amlicites have joined them;"]]},
  {num:25,words:[["Ma ua i ai nei i latou i luga o o tatou uso i le laueleele lena;", "And they are upon our brethren in that land;"], ["ma ua latou sosola mai i o latou luma ma a latou lafu,", "and they are fleeing before them with their flocks,"], ["ma a latou ava,", "and their wives,"], ["ma a latou fanau,", "and their children,"], ["agai mai i lo tatou aai; ma vagana ai ua tatou faavavevave atu,", "towards our city;"], ["o le a latou maua lo tatou aai e fai mo i latou,", "and except we make haste they obtain possession of our city,"], ["ma o le a fasiotia o tatou tamā,", "and our fathers,"], ["ma a tatou ava,", "and our wives,"], ["ma a tatou fanau.", "and our children be slain."]]},
  {num:26,words:[["Ma sa oo ina ave e tagata o Nifae o latou faleie,", "And it came to pass that the people of Nephi took their tents,"], ["ma o ese atu i fafo o le vanu o Kitiona agai i lo latou aai,", "and departed out of the valley of Gideon towards their city,"], ["le aai lea o Sara'emila .", "which was the city of Zarahemla."]]},
  {num:27,words:[["Ma faauta,", "And behold,"], ["a'o latou sopoia le vaitafe o Saitonu,", "as they were crossing the river Sidon,"], ["sa o mai i o latou luga sa Lamanā ma sa Amilikī,", "the Lamanites and the Amlicites,"], ["e toetoe ina tusa lo latou toatele ,", "being as numerous almost,"], ["e pei ona i ai,", "as it were,"], ["ma oneone o le sami,", "as the sands of the sea,"], ["e faaumatia i latou.", "came upon them to destroy them."]]},
  {num:28,words:[["E ui i lea,", "Nevertheless,"], ["ona sa faamalolosia sa Nifaē e le aao o le Alii,", "the Nephites being strengthened by the hand of the Lord,"], ["ona sa latou tatalo malosi atu ia te ia, ia laveai e ia i latou mai lima o o latou fili,", "having prayed mightily to him that he would deliver them out of the hands of their enemies,"], ["o lea na faafofoga mai ai le Alii ia latou tagi,", "therefore the Lord did hear their cries,"], ["ma faamalolosia i latou,", "and did strengthen them,"], ["ma pauu ai sa Lamanā ma sa Amilikī i o latou luma.", "and the Lamanites and the Amlicites did fall before them."]]},
  {num:29,words:[["Ma sa oo ina tau Alema ma Amiliki i le pelu,", "And it came to pass that Alma fought with Amlici with the sword,"], ["faafesagai lava;", "face to face;"], ["ma sa la tau malolosi tele,", "and they did contend mightily,"], ["o le tasi i le isi.", "one with another."]]},
  {num:30,words:[["Ma sa oo o Alema,", "And it came to pass that Alma,"], ["ona o ia o se tagata o le Atua,", "being a man of God,"], ["ma ona sa uunaia o ia i le faatuatua tele,", "being exercised with much faith,"], ["o lea na tagi atu ai o ia,", "cried,"], ["ua fai atu:", "saying:"], ["Le Alii e,", "O Lord,"], ["ia e alofa mutimutivale mai ma faasaoina lo'u ola,", "have mercy and spare my life,"], ["ina ia mafai ona avea a'u ma meafaigaluega i ou aao e laveai ma faasaoina lenei nuu.", "that I may be an instrument in thy hands to save and preserve this people."]]},
  {num:31,words:[["O lenei ina ua uma ona fai atu e Alema o nei upu,", "Now when Alma had said these words he contended again with Amlici;"], ["sa toe tau o ia ma Amiliki; ma sa faamalosia o ia,", "and he was strengthened,"], ["sa oo ina fasioti e ia Amiliki i le pelu.", "insomuch that he slew Amlici with the sword."]]},
  {num:32,words:[["Ma sa tau foi o ia ma le tupu o sa Lamanā; peitai sa sola i tua le tupu o sa Lamanā mai luma o Alema,", "And he also contended with the king of the Lamanites;"], ["ma ia auina mai ana leoleo e tau ma Alema.", "but the king of the Lamanites fled back from before Alma and sent his guards to contend with Alma."]]},
  {num:33,words:[["Peitai,", "But Alma,"], ["sa tau Alema ma ana leoleo ma leoleo a le tupu o sa Lamanā,", "with his guards,"], ["seia oo ina ia fasiotia ma tutuli i latou i tua.", "contended with the guards of the king of the Lamanites until he slew and drove them back."]]},
  {num:34,words:[["Ma sa faapea ona ia tafi o le eleele, po o le auvai,", "And thus he cleared the ground,"], ["sa i le itu i sisifo o le vaitafe o Saitonu,", "or rather the bank,"], ["i le lafo o tino o sa Lamanā na fasiotia, i vai o Saitonu,", "which was on the west of the river Sidon,"], ["ina ia mafai ona maua e ona tagata,", "throwing the bodies of the Lamanites who had been slain into the waters of Sidon,"], ["se avanoa e sopo atu ai ma tau ma sa Lamanā ma sa Amilikī, i le itu i sisifo o le vaitafe o Saitonu.", "that thereby his people might have room to cross and contend with the Lamanites and the Amlicites on the west side of the river Sidon."]]},
  {num:35,words:[["Ma sa oo ina ua latou sopoia uma atu le vaitafe o Saitonu, sa oo ina amata ona sosola o sa Lamanā ma sa Amilikī mai o latou luma,", "And it came to pass that when they had all crossed the river Sidon that the Lamanites and the Amlicites began to flee before them,"], ["e ui ina sa matuai toatele lava i latou sa lē mafai ona faitauina i latou.", "notwithstanding they were so numerous that they could not be numbered."]]},
  {num:36,words:[["Ma sa latou sosola mai luma o sa Nifaē agai i le vao sa i le itu i sisifo ma matu,", "And they fled before the Nephites towards the wilderness which was west and north,"], ["e mamao i tala atu o tuaoi o le laueleele,", "away beyond the borders of the land;"], ["ma sa tuliloa i latou e sa Nifaē ma lo latou malosi,", "and the Nephites did pursue them with their might,"], ["ma fasioti i latou.", "and did slay them."]]},
  {num:37,words:[["Ioe,", "Yea,"], ["sa faafetaia'ia i latou i itu uma,", "they were met on every hand,"], ["ma fasiotia ma tutulia,", "and slain and driven,"], ["seia oo ina faataapeapeina i latou i le itu i sisifo,", "until they were scattered on the west,"], ["ma le itu i matu,", "and on the north,"], ["seia oo ina latou tau atu i le vao,", "until they had reached the wilderness,"], ["lea sa ta'ua o Heremauga;", "which was called Hermounts;"], ["ma o le vaega lena o le vao sa tumu i manu aivao ma feai.", "and it was that part of the wilderness which was infested by wild and ravenous beasts."]]},
  {num:38,words:[["Ma sa oo ina sa toatele na oti i le vao i o latou manua,", "And it came to pass that many died in the wilderness of their wounds,"], ["ma 'aina e ia manu feai ma taie foi o le 'ea;", "and were devoured by those beasts and also the vultures of the air;"], ["ma ua maua o latou ivi,", "and their bones have been found,"], ["ma ua faufaula'i i luga o le eleele.", "and have been heaped up on the earth."]]},
];
renderVerseSet(al_ch_2_Verses, 'al-ch2-verses');

var al_ch_3_Verses = [
  {num:1,words:[["Ma sa oo o sa Nifaē o e sa lei fasiotia i auupega o taua,", "And it came to pass that the Nephites who were not slain by the weapons of war,"], ["ina ua uma ona tanu o e na fasiotia—o lenei o le aofai o e na fasiotia sa lē mafai ona faitauina,", "after having buried those who had been slain—now the number of the slain were not numbered,"], ["ona o le toatele nauā o lo latou aofai—ina ua uma ona latou tanu o o latou tagata oti, sa latou toe foi uma atu i o latou laueleele,", "because of the greatness of their number—after they had finished burying their dead they all returned to their lands,"], ["ma o latou fale,", "and to their houses,"], ["ma a latou ava,", "and their wives,"], ["ma a latou fanau.", "and their children."]]},
  {num:2,words:[["O lenei e toatele fafine ma tamaiti sa fasiotia i le pelu,", "Now many women and children had been slain with the sword,"], ["ma le tele foi o a latou lafu ma a latou fagaga;", "and also many of their flocks and their herds;"], ["ma sa tele foi a latou faatoaga saito sa faaleagaina,", "and also many of their fields of grain were destroyed,"], ["ona sa soli i lalo e autau a tagata.", "for they were trodden down by the hosts of men."]]},
  {num:3,words:[["Ma o lenei o le toatele o sa Lamanā ma sa Amilikī o e na fasiotia i luga o le auvai o le vaitafe o Saitonu,", "And now as many of the Lamanites and the Amlicites who had been slain upon the bank of the river Sidon were cast into the waters of Sidon;"], ["sa lafo i vai o Saitonu; ma faauta o o latou ivi ua i ai i mea loloto o le sami ,", "and behold their bones are in the depths of the sea,"], ["ma ua tele lava i latou.", "and they are many."]]},
  {num:4,words:[["Ma sa faailoga ese sa Amilikī mai sa Nifaē, ona sa latou faailoga i latou lava i le lanu mūmū i o latou muaulu,", "And the Amlicites were distinguished from the Nephites,"], ["e tusa ma le tu a sa Lamanā;", "for they had marked themselves with red in their foreheads after the manner of the Lamanites;"], ["e ui i lea sa lei selemoleina o latou ulu, e pei o sa Lamanā.", "nevertheless they had not shorn their heads like unto the Lamanites."]]},
  {num:5,words:[["O lenei sa selemole ulu o sa Lamanā;", "Now the heads of the Lamanites were shorn;"], ["ma sa lē lavalava i latou,", "and they were naked,"], ["vagana ai se pau manu sa fusi faataamilo i o latou sulugatiti,", "save it were skin which was girded about their loins,"], ["ma o o latou ofutau foi,", "and also their armor,"], ["sa fusi faataamilo ia te i latou,", "which was girded about them,"], ["ma a latou aufana,", "and their bows,"], ["ma a latou ufanafana,", "and their arrows,"], ["ma a latou maa,", "and their stones,"], ["ma a latou maata,", "and their slings,"], ["ma isi mea faapena.", "and so forth."]]},
  {num:6,words:[["Ma o pa'u o sa Lamanā sa uliuli,", "And the skins of the Lamanites were dark,"], ["e tusa ma le faailoga na tuu i luga o o latou tamā,", "according to the mark which was set upon their fathers,"], ["o se fetuu na tuu i o latou luga ona o lo latou solitulafono ma lo latou fouvale faasaga i o latou uso,", "which was a curse upon them because of their transgression and their rebellion against their brethren,"], ["o e o Nifae,", "who consisted of Nephi,"], ["Iakopo,", "Jacob,"], ["ma Iosefa,", "and Joseph,"], ["ma Sama,", "and Sam,"], ["o e o ni tagata amiotonu ma paia.", "who were just and holy men."]]},
  {num:7,words:[["Ma sa saili o latou uso e faaumatia i latou,", "And their brethren sought to destroy them,"], ["o lea na fetuu ai i latou;", "therefore they were cursed;"], ["ma ua tuuina e le Alii le Atua se faailoga i luga o i latou,", "and the Lord God set a mark upon them,"], ["ioe,", "yea,"], ["i luga o Lamana ma Lemuelu,", "upon Laman and Lemuel,"], ["ma atalii foi o Isamaeli,", "and also the sons of Ishmael,"], ["ma fafine Isamaelī.", "and Ishmaelitish women."]]},
  {num:8,words:[["Ma sa faia lenei mea ina ia mafai ona faailogaese a latou fanau mai fanau a o latou uso,", "And this was done that their seed might be distinguished from the seed of their brethren,"], ["ina ia mafai ona faasaoina ai e le Alii le Atua ona tagata, ina ia lē mafai ona fefiloi ai i latou ma talitonu i uputuu sese,", "that thereby the Lord God might preserve his people,"], ["ia e mautinoa ona faaumatia ai o i latou.", "that they might not mix and believe in incorrect traditions which would prove their destruction."]]},
  {num:9,words:[["Ma sa oo ina o soo se tasi sa ia faafefiloiai lona sua ma le sua o sa Lamanā, sa ia aumai lea lava fetuu i luga o ana fanau.", "And it came to pass that whosoever did mingle his seed with that of the Lamanites did bring the same curse upon his seed."]]},
  {num:10,words:[["O lea,", "Therefore,"], ["o soo se tasi na te tuu atu o ia lava ia taitai ese e sa Lamanā, sa taua i lalo o lena igoa,", "whosoever suffered himself to be led away by the Lamanites was called under that head,"], ["ma sa i ai se faailoga sa tuu i ona luga.", "and there was a mark set upon him."]]},
  {num:11,words:[["Ma sa oo ina o soo se tasi sa lē fia talitonu i uputuu a sa Lamanā,", "And it came to pass that whosoever would not believe in the tradition of the Lamanites,"], ["ae sa talitonu i talafaamaumau ia na aumai i fafo mai le laueleele o Ierusalema,", "but believed those records which were brought out of the land of Jerusalem,"], ["ma uputuu foi a o latou tamā,", "and also in the tradition of their fathers,"], ["ia sa sa'o,", "which were correct,"], ["o e sa talitonu i poloaiga a le Atua ma tausi i ai,", "who believed in the commandments of God and kept them,"], ["sa taua o sa Nifaē,", "were called the Nephites,"], ["po o le nuu o Nifae,", "or the people of Nephi,"], ["mai i le taimi lena seia oo atu i luma—", "from that time forth—"]]},
  {num:12,words:[["Ma o i latou ia o e na tausia talafaamaumau moni o o latou tagata,", "And it is they who have kept the records which are true of their people,"], ["ma tagata foi o sa Lamanā.", "and also of the people of the Lamanites."]]},
  {num:13,words:[["O lenei o le a tatou toe foi atu i tagata sa Amilikī,", "Now we will return again to the Amlicites,"], ["ona sa i ai foi se faailoga sa tuu i luga o i latou;", "for they also had a mark set upon them;"], ["ioe,", "yea,"], ["sa latou tuu lea faailoga i luga o i latou lava,", "they set the mark upon themselves,"], ["ioe,", "yea,"], ["o se faailoga mūmū i luga o o latou muaulu.", "even a mark of red upon their foreheads."]]},
  {num:14,words:[["Ua faapea ona faataunuu ai o le afioga a le Atua, ona o afioga nei na ia fetalai mai ia Nifae:", "Thus the word of God is fulfilled,"], ["Faauta,", "for these are the words which he said to Nephi:"], ["ua ou fetuuina sa Lamanā, ma o le a ou tuuina se faailoga i luga o i latou,", "Behold,"], ["ina ia mafai ona vavae ese o i latou ma a latou fanau,", "the Lamanites have I cursed,"], ["mai ia te oe ma au fanau, mai le taimi nei seia oo atu i luma ma le faavavau,", "and I will set a mark on them that they and their seed may be separated from thee and thy seed,"], ["vagana ai ua latou salamo i lo latou amioleaga,", "from this time henceforth and forever,"], ["ma liliu mai ia te au, ina ia mafai ona ou alofa mutimutivale atu i luga o i latou.", "except they repent of their wickedness and turn to me that I may have mercy upon them."]]},
  {num:15,words:[["Ma e toe fai atu:", "And again:"], ["O le a ou tuuina se faailoga i luga o ia o lē na te faafefiloiai lona sua ma ou uso,", "I will set a mark upon him that mingleth his seed with thy brethren,"], ["ina ia fetuuina foi i latou.", "that they may be cursed also."]]},
  {num:16,words:[["Ma e toe fai atu:", "And again:"], ["O le a ou tuuina se faailoga i luga o ia o lē e faasagatau mai ia te oe ma lau fanau.", "I will set a mark upon him that fighteth against thee and thy seed."]]},
  {num:17,words:[["Ma e toe fai atu,", "And again,"], ["ou te fai atu o ia o lē e alu ese atu mai ia te oe,", "I say he that departeth from thee shall no more be called thy seed;"], ["e lē toe taua o sau fanau; ma o le a ou faamanuiaina oe,", "and I will bless thee,"], ["ma soo se tasi o le a taua o au fanau,", "and whomsoever shall be called thy seed,"], ["mai le taimi nei ma le faavavau;", "henceforth and forever;"], ["ma o folafolaga nei a le Alii ia Nifae ma ana fanau.", "and these were the promises of the Lord unto Nephi and to his seed."]]},
  {num:18,words:[["O lenei sa lē iloa e sa Amilikī ua latou faataunuuina afioga a le Atua,", "Now the Amlicites knew not that they were fulfilling the words of God when they began to mark themselves in their foreheads;"], ["ina ua amata ona latou faailoga o i latou lava i o latou muaulu; e ui i lea sa latou o mai i fafo i le fouvale aliali e faasaga i le Atua;", "nevertheless they had come out in open rebellion against God;"], ["o lea sa tatau ai ona pau ifo o le fetuu i o latou luga.", "therefore it was expedient that the curse should fall upon them."]]},
  {num:19,words:[["O lenei ou te manao ia outou iloa o i latou lava na aumaia le fetuu i o latou lava luga; ma e faapea foi ona aumai e tagata taitoatasi ua fetuuina,", "Now I would that ye should see that they brought upon themselves the curse;"], ["i ona lava luga, lona lava tausalaga.", "and even so doth every man that is cursed bring upon himself his own condemnation."]]},
  {num:20,words:[["O lenei sa oo ina sa lei tele ni aso ina ua mavae le taua lea sa tau i le laueleele o Sara'emila,", "Now it came to pass that not many days after the battle which was fought in the land of Zarahemla,"], ["e sa Lamanā ma sa Amilikī,", "by the Lamanites and the Amlicites,"], ["sa i ai se tasi autau a sa Lamanā sa o mai i totonu i luga o le nuu o Nifae,", "that there was another army of the Lamanites came in upon the people of Nephi,"], ["i le nofoaga lava lea e tasi na fetaiai ai le autau muamua ma sa Amilikī.", "in the same place where the first army met the Amlicites."]]},
  {num:21,words:[["Ma sa oo ina sa i ai se autau sa auina atu e tutuli ese i latou i fafo mai lo latou laueleele.", "And it came to pass that there was an army sent to drive them out of their land."]]},
  {num:22,words:[["O lenei, ona sa mafatia Alema lava ia i se manua , o lea sa lē alu atu ai o ia e tau i le taimi lea e faasaga ia sa Lamanā;", "Now Alma himself being afflicted with a wound did not go up to battle at this time against the Lamanites;"]]},
  {num:23,words:[["Ae sa ia auina atu se autau toatele e faasaga ia te i latou;", "But he sent up a numerous army against them;"], ["ma sa latou o atu ma fasioti le toatele o sa Lamanā, ma tutuli ese i fafo e na totoe o i latou,", "and they went up and slew many of the Lamanites,"], ["mai tuaoi o lo latou laueleele.", "and drove the remainder of them out of the borders of their land."]]},
  {num:24,words:[["Ma ona latou toe foi mai ai lea, ma amata ona faatu o le filemu i le laueleele,", "And then they returned again and began to establish peace in the land,"], ["ma lē toe faalavelavea ai mo se taimi e o latou fili.", "being troubled no more for a time with their enemies."]]},
  {num:25,words:[["O lenei o nei mea uma sa faia,", "Now all these things were done,"], ["ioe,", "yea,"], ["o nei taua uma ma finauga na amata ma iu i le lona lima o tausaga o le nofoaiga a faamasino.", "all these wars and contentions were commenced and ended in the fifth year of the reign of the judges."]]},
  {num:26,words:[["Ma i le tausaga e tasi na auina atu ai le afe ma afe ma sefulu o afe o agaga i le lalolagi faavavau,", "And in one year were thousands and tens of thousands of souls sent to the eternal world,"], ["ina ia mafai ona latou selesele o latou taui e tusa ma a latou galuega,", "that they might reap their rewards according to their works,"], ["pe sa lelei pe sa leaga,", "whether they were good or whether they were bad,"], ["e selesele le fiafia e faavavau po o le pagatia e faavavau,", "to reap eternal happiness or eternal  misery,"], ["e tusa ma le agaga sa latou filifili e usiusitai i ai,", "according to the spirit which they listed to obey,"], ["pe o se agaga lelei po o se agaga leaga.", "whether it be a good spirit or a bad one."]]},
  {num:27,words:[["Auā e maua e tagata taitoatasi taui a ia o lē e filifili o ia e usiusitai i ai,", "For every man receiveth wages of him whom he listeth to obey,"], ["ma ua tusa lenei mea ma upu a le agaga o valoaga;", "and this according to the words of the spirit of prophecy;"], ["o lea ia faia ai lava e tusa ma le upumoni. Ma sa faapea ona iu o le lona lima o tausaga o le nofoaiga a faamasino.", "therefore let it be according to the truth. And thus endeth the fifth year of the reign of the judges."]]},
];
renderVerseSet(al_ch_3_Verses, 'al-ch3-verses');

var al_ch_4_Verses = [
  {num:1,words:[["O lenei sa oo i le lona ono o tausaga o le nofoaiga a faamasino i le nuu o Nifae,", "Now it came to pass in the sixth year of the reign of the judges over the people of Nephi,"], ["sa lē i ai ni finauga po o ni taua i le nuu o Sara'emila.", "there were no contentions nor wars in the land of Zarahemla;"]]},
  {num:2,words:[["Peitai sa puapuagatia le nuu,", "But the people were afflicted,"], ["ioe,", "yea,"], ["puapuagatia tele lava i le toesea o o latou uso,", "greatly afflicted for the loss of their brethren,"], ["ma le toesea foi o a latou lafu ma fagaga,", "and also for the loss of their flocks and herds,"], ["ma le faatamaia foi o a latou faatoaga saito,", "and also for the loss of their fields of grain,"], ["ia na soli i lalo e vae ma lepeti e sa Lamanā.", "which were trodden under foot and destroyed by the Lamanites."]]},
  {num:3,words:[["Ma sa tetele naua o latou puapuagatia sa i ai i tagata taitoatasi se pogai na faanoanoa ai;", "And so great were their afflictions that every soul had cause to mourn;"], ["ma sa latou talitonu o ia mea o faamasinoga ia a le Atua ua auina mai i o latou luga ona o lo latou amioleaga ma a latou mea inosia;", "and they believed that it was the judgments of God sent upon them because of their wickedness and their abominations;"], ["o lea na fagua ai i latou i le manatuaina o lo latou tiute.", "therefore they were awakened to a remembrance of their duty."]]},
  {num:4,words:[["Ma sa amata ona latou faatu atoatoa atili le ekalesia;", "And they began to establish the church more fully;"], ["ioe,", "yea,"], ["ma e toatele sa papatisoina i vai o Saitonu ma faaauai i le ekalesia a le Atua;", "and many were baptized in the waters of Sidon and were joined to the church of God;"], ["ioe,", "yea,"], ["sa papatisoina i latou i le lima o Alema,", "they were baptized by the hand of Alma,"], ["o lē na faapaia o le faitaulaga sili i luga o tagata o le ekalesia,", "who had been consecrated the high priest over the people of the church,"], ["e le lima o lona tamā o Alema.", "by the hand of his father Alma."]]},
  {num:5,words:[["Ma sa oo i le lona fitu o tausaga o le nofoaiga a faamasino, sa i ai e tusa o le tolu afe lima selau agaga sa faatasi atu i latou lava i le ekalesia a le Atua ma papatisoina.", "And it came to pass in the seventh year of the reign of the judges there were about three thousand five hundred souls that united themselves to the church of God and were baptized."], ["Ma sa faapea ona iu o le lona fitu o tausaga o le nofoaiga a faamasino i le nuu o Nifae,", "And thus endeth the seventh year of the reign of the judges over the people of Nephi;"], ["ma sa i ai le filemu faaauau pea i lena taimi atoa.", "and there was continual peace in all that time."]]},
  {num:6,words:[["Ma sa oo i le lona valu o tausaga o le nofoaiga a faamasino,", "And it came to pass in the eighth year of the reign of the judges,"], ["sa amata ona faasolo faamaualuluga tagata o le ekalesia,", "that the people of the church began to wax proud,"], ["ona o lo latou mauoa tele,", "because of their exceeding riches,"], ["ma a latou silika lelei,", "and their fine silks,"], ["ma a latou ie lino miloa lelei,", "and their fine–twined linen,"], ["ma ona o le tele o a latou lafu ma fagaga,", "and because of their many flocks and herds,"], ["ma a latou auro ma a latou ario,", "and their gold and their silver,"], ["ma ituaiga uma o mea taua eseese,", "and all manner of precious things,"], ["ia sa latou maua e ala i lo latou toaaga;", "which they had obtained by their industry;"], ["ma o nei mea uma sa faafefeteina ai i latou i le faamaualuluga o o latou mata,", "and in all these things were they lifted up in the pride of their eyes,"], ["ona sa amata ona latou ofu o ofu taugata tele.", "for they began to wear very costly apparel."]]},
  {num:7,words:[["O lenei sa avea lenei mea ma pogai o le puapuaga tele o Alema,", "Now this was the cause of much affliction to Alma,"], ["ioe,", "yea,"], ["ma le toatele o tagata o e na faauu e Alema e avea ma aoao,", "and to many of the people whom Alma had consecrated to be teachers,"], ["ma faitaulaga,", "and priests,"], ["ma toeaina i luga o le ekalesia;", "and elders over the church;"], ["ioe,", "yea,"], ["o le toatele o i latou sa faanoanoa tele i le amioleaga sa latou vaai ua amata ona i ai i totonu o o latou tagata.", "many of them were sorely grieved for the wickedness which they saw had begun to be among their people."]]},
  {num:8,words:[["Ona sa latou iloa ma vaai atu ma le faanoanoa tele i le amata ona fefete i luga o tagata o le ekalesia i le faamaualuluga o o latou mata,", "For they saw and beheld with great sorrow that the people of the church began to be lifted up in the pride of their eyes,"], ["ma tuu atu o latou loto i luga o oa ma luga o mea lē aoga o le lalolagi,", "and to set their hearts  upon riches and upon the vain things of the world,"], ["sa amata ai ona latou inoino,", "that they began to be scornful,"], ["o le tasi i le tasi,", "one towards another,"], ["ma amata ona latou sauaina ai i latou o e sa lē talitonu e tusa ma o latou lava loto ma filifiliga.", "and they began to persecute those that did not believe according to their own will and pleasure."]]},
  {num:9,words:[["Ma sa faapea,", "And thus,"], ["i le lona valu o tausaga o le nofoaiga a faamasino,", "in this eighth year of the reign of the judges,"], ["ona amata ona i ai o finauga tetele i totonu o tagata o le ekalesia;", "there began to be great contentions among the people of the church;"], ["ioe,", "yea,"], ["sa i ai losilosivalega ,", "there were envyings,"], ["ma finauga,", "and strife,"], ["ma le lotoleaga,", "and malice,"], ["ma sauaga,", "and persecutions,"], ["ma le faamaualuga,", "and pride,"], ["sa sili atu i le faamaualuluga o i latou o e sa lē auai i le ekalesia a le Atua.", "even to exceed the pride of those who did not belong to the church of God."]]},
  {num:10,words:[["Ma sa faapea ona iu o le lona valu o tausaga o le nofoaiga a faamasino;", "And thus ended the eighth year of the reign of the judges;"], ["ma o le amioleaga o le ekalesia, sa avea o se maa tu'ia tele ia te i latou o e sa lē auai i le ekalesia;", "and the wickedness of the church was a great stumbling–block to those who did not belong to the church;"], ["ma sa faapea ona amata ona vaivai o le ekalesia i lona alualu i luma.", "and thus the church began to fail in its progress."]]},
  {num:11,words:[["Ma sa oo i le amataga o le lona iva o tausaga, sa vaaia ai e Alema le amioleaga o le ekalesia,", "And it came to pass in the commencement of the ninth year,"], ["ma sa ia vaai atu foi ua amata ona taitai atu e faataitaiga a tagata o le ekalesia,", "Alma saw the wickedness of the church,"], ["i latou o e sa lē talitonu,", "and he saw also that the example of the church began to lead those who were unbelievers on from one piece of iniquity to another,"], ["mai sia fasi amioletonu i sia fasi amioletonu, ma faapea ona aumai ai o le faafanoga o le nuu.", "thus bringing on the destruction of the people."]]},
  {num:12,words:[["Ioe,", "Yea,"], ["sa ia vaaia le lē tutusa tele i totonu o tagata,", "he saw great inequality among the people,"], ["o ni isi ua latou faafefete a'e i latou lava i lo latou faamaualuluga,", "some lifting themselves up with their pride,"], ["ua inoino i isi, ua fuli atu o latou tua i e ua lē tagolima ma e ua lē lavalavā,", "despising others,"], ["ma i latou o e ua fia aai,", "turning their backs upon the needy and the naked and those who were hungry,"], ["ma i latou o e ua fia feinu,", "and those who were athirst,"], ["ma i latou o e ua mamai ma puapuagatia.", "and those who were sick and afflicted."]]},
  {num:13,words:[["O lenei sa avea lenei mea ma pogai o auega i totonu o le nuu,", "Now this was a great cause for lamentations among the people,"], ["a'o isi sa latou faalotomaualalaloina i latou lava,", "while others were abasing themselves,"], ["i le fesoasoani atu lea ia te i latou o e na manaomia la latou fesoasoani,", "succoring those who stood in need of their succor,"], ["e pei o le faasoa atu o a latou mea i e ua matitiva ma e ua lē tagolima,", "such as imparting their substance to the poor and the needy,"], ["ma fafaga i e sa fia aai,", "feeding the hungry,"], ["ma mafatia i ituaiga o puapuaga uma,", "and suffering all manner of afflictions,"], ["mo Keriso,", "for Christ's sake,"], ["o lē o le a afio mai e tusa ma le agaga o valoaga;", "who should come according to the spirit of prophecy;"]]},
  {num:14,words:[["Ma tulimatai i luma i lena aso,", "Looking forward to that day,"], ["ma faapea ona faatumauina ai le faamagaloina o a latou agasala;", "thus retaining a remission of their sins;"], ["ua faatumuina i le olioli tele ona o le toetutū mai o e ua oti,", "being filled with great joy because of the resurrection of the dead,"], ["e tusa ma le finagalo ma le mana ma le laveaiga a Iesu Keriso mai fusi o le oti.", "according to the will and power and deliverance of Jesus Christ from the bands of death."]]},
  {num:15,words:[["Ma o lenei sa oo ina ua vaai atu Alema i puapuaga o soo lotomaualalalo o le Atua,", "And now it came to pass that Alma,"], ["ma sauaga sa faafaulalai i o latou luga e le vaega na totoe o ona tagata,", "having seen the afflictions of the humble followers of God,"], ["ma vaai i mea uma sa latou le tutusa ai,", "and the persecutions which were heaped upon them by the remainder of his people, and seeing all their inequality,"], ["sa amata ona faanoanoa tele o ia;", "began to be very sorrowful;"], ["e ui i lea sa lē tuulafoaiina o ia e le Agaga o le Alii.", "nevertheless the Spirit of the Lord did not fail him."]]},
  {num:16,words:[["Ma sa ia filifilia se tagata poto sa i ai i totonu o toeaina o le ekalesia,", "And he selected a wise man who was among the elders of the church,"], ["ma tuu atu ia te ia le pule e tusa ma le leo o le nuu,", "and gave him power according to the voice of the people,"], ["ina ia mafai e ia ona maua o le pule e fai ai tulafono e tusa ma tulafono na tuuina mai,", "that he might have power to enact laws according to the laws which had been given,"], ["ma faamalolosi ia tulafono e tusa ma amioleaga ma solitulafono a tagata.", "and to put them in force according to the wickedness and the crimes of the people."]]},
  {num:17,words:[["O lenei o le igoa o lenei tagata o Nifaea,", "Now this man's name was Nephihah,"], ["ma sa tofia o ia e avea ma faamasino sili;", "and he was appointed chief judge;"], ["ma sa nofo o ia i le nofoa-faamasino e faamasino ma pulea le nuu.", "and he sat in the  judgment– seat to judge and to govern the people."]]},
  {num:18,words:[["O lenei sa lē tuuina atu e Alema ia te ia le tofiga o le avea ma faitaulaga sili i le ekalesia,", "Now Alma did not grant unto him the office of being high priest over the church,"], ["ae sa ia taofi pea le tofiga o le faitaulaga sili ia te ia lava;", "but he retained the office of high priest unto himself;"], ["ae sa ia tuuina atu le nofoa-faamasino ia Nifaea.", "but he delivered the judgment–seat unto Nephihah."]]},
  {num:19,words:[["Ma sa ia faia lenei mea ina ia mafai e ia lava ona alu atu i totonu o ona tagata,", "And this he did that he himself might go forth among his people,"], ["po o tagata o Nifae, ina ia mafai ona ia talai atu le afioga a le Atua ia te i latou,", "or among the people of Nephi,"], ["e uunai ai i latou,", "that he might preach the word of God unto them,"], ["ia latou manatua lo latou tiute, ma ina ia mafai ona ia toso i lalo,", "to stir them up in remembrance of their duty,"], ["e ala i le afioga a le Atua,", "and that he might pull down,"], ["le faamaualuga uma ma le pepelo ma finauga uma sa i ai i totonu o lona nuu,", "by the word of God,"], ["i le vaai atu ua leai se auala e mafai ai ona ia toe aumai o i latou, vagana ai le faamamafa malosi atu,", "all the pride and craftiness and all the contentions which were among his people,"], ["e ala atu i le molimau manino e faasaga ia te i latou.", "seeing no way that he might reclaim them save it were in bearing down in pure testimony against them."]]},
  {num:20,words:[["Ma sa faapea i le amataga o le lona iva o tausaga o le nofoaiga a faamasino i le nuu o Nifae,", "And thus in the commencement of the ninth year of the reign of the judges over the people of Nephi,"], ["ona tuuina atu e Alema o le nofoa-faamasino ia Nifaea ,", "Alma delivered up the judgment–seat to Nephihah,"], ["ma tuu atu atoatoa o ia lava i le perisitua maualuga o le faatulagaga paia a le Atua,", "and confined himself wholly to the high priesthood of the holy order of God,"], ["i le molimau o le afioga,", "to the testimony of the word,"], ["e tusa ai ma le agaga o faaaliga ma valoaga.", "according to the spirit of revelation and prophecy."]]},
];
renderVerseSet(al_ch_4_Verses, 'al-ch4-verses');

var al_ch_5_Verses = [
  {num:1,words:[["O lenei sa oo ina amata e Alema ona talai atu le afioga a le Atua i tagata,", "Now it came to pass that Alma began to deliver the word of God unto the people,"], ["muamua i le nuu o Sara'emila,", "first in the land of Zarahemla,"], ["ma mai iina seia oo atu i le laueleele atoa.", "and from thence throughout all the land."]]},
  {num:2,words:[["Ma o upu nei sa ia tautala atu ai i tagata i totonu o le ekalesia lea sa faatu i le aai o Sara'emila,", "And these are the words which he spake to the people in the church which was established in the city of Zarahemla,"], ["e tusa ai ma lana lava talafaamaumau,", "according to his own record,"], ["ua fai atu:", "saying:"]]},
  {num:3,words:[["O au o Alema,", "I,"], ["sa faauu e lo'u tamā,", "Alma,"], ["o Alema,", "having been consecrated by my father,"], ["e avea o se faitaulaga sili i le ekalesia a le Atua,", "Alma,"], ["ona sa ia te ia le mana ma le pule mai le Atua e fai ai nei mea,", "to be a high priest over the church of God,"], ["faauta,", "he having power and authority from God to do these things,"], ["ou te fai atu ia te outou,", "behold,"], ["sa amata ona ia faatuina o se ekalesia i le laueleele sa i tuaoi o Nifae;", "I say unto you that he began to establish a church in the land which was in the borders of Nephi;"], ["ioe,", "yea,"], ["o le laueleele lea sa taua o le laueleele o Mamona;", "the land which was called the land of Mormon;"], ["ioe,", "yea,"], ["ma sa ia papatisoina ona uso i vai o Mamona.", "and he did baptize his brethren in the waters of Mormon."]]},
  {num:4,words:[["Ma faauta,", "And behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["sa laveaiina i latou mai lima o le nuu o le tupu o Noa,", "they were delivered out of the hands of the people of king Noah,"], ["i le alofa mutimutivale ma le mana o le Atua.", "by the mercy and power of God."]]},
  {num:5,words:[["Ma faauta,", "And behold,"], ["ina ua mavae lena, sa aumai i latou i le pologa i le vao,", "after that,"], ["e lima o sa Lamanā;", "they were brought into bondage by the hands of the Lamanites in the wilderness;"], ["ioe,", "yea,"], ["ou te fai atu ia te outou, sa faatagataotauaina i latou,", "I say unto you,"], ["ma sa toe laveaiina i latou e le Alii mai le pologa ,", "they were in captivity,"], ["e ala i le mana o lana afioga;", "and again the Lord did deliver them out of bondage by the power of his word;"], ["ma sa aumai i tatou i le laueleele lenei, ma o iinei na amata ona tatou faatuina ai o le ekalesia a le Atua,", "and we were brought into this land,"], ["i lenei foi laueleele atoa.", "and here we began to establish the church of God throughout this land also."]]},
  {num:6,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ou uso e,", "my brethren,"], ["outou ua auai i lenei ekalesia,", "you that belong to this church,"], ["ua lava ea ona outou manatua o le faatagataotauaina o o outou tamā? Ioe,", "have you sufficiently retained in remembrance the captivity of your fathers? Yea,"], ["ma ua lava ea ona outou manatua o lona alofa mutimutivale ma lona tali-tiga ia te i latou? Ma e le gata i lea,", "and have you sufficiently retained in remembrance his mercy  and long–suffering towards them? And moreover,"], ["ua lava ea ona outou manatua ua ia laveaiina o latou agaga mai seoli?", "have ye sufficiently retained in remembrance that he has delivered their souls from hell?"]]},
  {num:7,words:[["Faauta,", "Behold,"], ["sa ia liua o latou loto;", "he changed their hearts;"], ["ioe,", "yea,"], ["sa ia fafagu i latou mai se moe gase,", "he awakened them out of a deep sleep,"], ["ma sa latou ala mai i le Atua. Faauta,", "and they awoke unto God. Behold,"], ["sa i ai i latou i totonugalemu o le pogisa;", "they were in the midst of darkness;"], ["e ui i lea,", "nevertheless,"], ["sa faapupulaina o latou agaga i le malamalama o le afioga tumau-faavavau;", "their souls were illuminated by the light of the everlasting word;"], ["ioe,", "yea,"], ["sa fusia faataamilo i latou i fusi o le oti,", "they were encircled about by the bands of death,"], ["ma filifili o seoli,", "and the chains of hell,"], ["ma sa faatalitali mai ia te i latou se faafanoga tumau-faavavau.", "and an everlasting destruction did await them."]]},
  {num:8,words:[["Ma o lenei ou te fesili atu ia te outou,", "And now I ask of you,"], ["ou uso e,", "my brethren,"], ["pe na faaumatia ea i latou? Faauta,", "were they destroyed? Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["E leai,", "Nay,"], ["sa lei faaumatiaina i latou.", "they were not."]]},
  {num:9,words:[["Ma ou te toe fesili atu,", "And again I ask,"], ["pe na motusia ea fusi o le oti,", "were the bands of death broken,"], ["ma filifili o seoli ia na fusi faataamilo ai i latou,", "and the chains of hell which encircled them about,"], ["pe na tatalaina ea i latou? Ou te fai atu ia te outou,", "were they loosed? I say unto you,"], ["Ioe,", "Yea,"], ["sa tatalaina i latou,", "they were loosed,"], ["ma sa faalauteleina o latou agaga,", "and their souls did expand,"], ["ma sa latou pepeseina le alofa togiola. Ma ou te fai atu ia te outou ua faaolaina i latou.", "and they did sing redeeming love. And I say unto you that they are saved."]]},
  {num:10,words:[["Ma o lenei ou te fesili atu ia te outou o a tulaga na faaolaina ai i latou? Ioe,", "And now I ask of you on what conditions are they saved? Yea,"], ["o a pogai sa ia te i latou sa faamoemoe ai mo le olataga? O le a le pogai o le tatalaina o i latou mai fusi o le oti,", "what grounds had they to hope for salvation? What is the cause of their being loosed from the bands of death,"], ["ioe,", "yea,"], ["ma filifili foi o seoli?", "and also the chains of hell?"]]},
  {num:11,words:[["Faauta,", "Behold,"], ["e mafai ona ou tau atu ia te outou—pe sa lei talitonu ea lo'u tamā o Alema i upu ia na tuuina mai i le fofoga o Apinati ? Ma pe sa lē o ia ea o se perofeta paia? Sa lei fofoga mai ea e ia afioga a le Atua,", "I can tell you—did not my father Alma believe in the words which were delivered by the mouth of Abinadi? And was he not a holy prophet? Did he not speak the words of God,"], ["ma talitonu i ai lo'u tamā o Alema?", "and my father Alma believe them?"]]},
  {num:12,words:[["Ma e tusa ma lona faatuatua, sa i ai se liuga tele na oo mai i lona loto.", "And according to his faith there was a mighty change wrought in his heart."], ["Faauta ou te fai atu ia te outou, ua moni nei mea uma.", "Behold I say unto you that this is all true."]]},
  {num:13,words:[["Ma faauta,", "And behold,"], ["sa ia talai atu le afioga i o outou tamā,", "he preached the word unto your fathers,"], ["ma sa oo mai foi se liuga tele i o latou loto,", "and a mighty change was also wrought in their hearts,"], ["ma sa latou faamaualalaloina i latou lava ma tuu atu lo latou faalagolago i le Atua moni ma soifua . Ma faauta,", "and they humbled themselves and put their trust in the true and living God. And behold,"], ["sa latou faamaoni seia oo i le iuga ;", "they were faithful until the end;"], ["o lea na faaolaina ai i latou.", "therefore they were saved."]]},
  {num:14,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te fesili atu ia te outou,", "I ask of you,"], ["ou uso e o le ekalesia,", "my brethren of the church,"], ["ua fanauina ea outou faaleagaga i la le Atua? Ua outou maua ea ona foliga i o outou mata? Ua oo ea lenei liuga tele i o outou loto?", "have ye spiritually been born of God? Have ye received his image in your countenances? Have ye experienced this mighty change in your hearts?"]]},
  {num:15,words:[["Ua outou faaaoga ea le faatuatua i le togiola a ia o lē na foafoaina outou? O outou tulimatai ea i luma ma le mata o le faatuatua,", "Do ye exercise faith in the redemption of him who created you? Do you look forward with an eye of faith,"], ["ma vaaia le faatuina mai o lenei tino faaletino i le tino ola pea,", "and view this mortal body raised in immortality,"], ["ma le faatuina mai o lenei tinopala i le tinolēpala,", "and this corruption raised in incorruption,"], ["e tu i luma o le Atua e faamasinoina e tusa ma galuega na faia i le tino faaletino?", "to stand before God to be judged according to the deeds which have been done in the mortal body?"]]},
  {num:16,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["e mafai ea ona outou mafaufau ifo ia te outou lava e peiseai ua outou faalogo atu i le siufofoga o le Alii,", "can you imagine to yourselves that ye hear the voice of the Lord,"], ["ua fetalai mai ia te outou,", "saying unto you,"], ["i lena aso: O mai ia ia te au,", "in that day:"], ["outou o e ua faamanuiaina ,", "Come unto me ye blessed,"], ["aua faauta,", "for behold,"], ["o ā outou galuega o galuega ia o le amiotonu i luga o le lalolagi?", "your works have been the works of righteousness upon the face of the earth?"]]},
  {num:17,words:[["Pe o outou mafaufau ifo ia te outou lava e mafai ona outou pepelo atu i le Alii i lena aso,", "Or do ye imagine to yourselves that ye can lie unto the Lord in that day,"], ["ma fai atu—Le Alii e,", "and say—Lord,"], ["o a matou galuega sa o ni galuega amiotonu i luga o le lalolagi—ma faapea o le a ia faaolaina ai outou?", "our works have been righteous works upon the face of the earth—and that he will save you?"]]},
  {num:18,words:[["Po o i se tasi itu,", "Or otherwise,"], ["e mafai ona outou mafaufau ifo i le aumai o outou lava i luma o le nofoa-faamasino o le Atua ma o outou agaga ua tumu i le sala ma le faanoanoa,", "can ye imagine yourselves brought before the tribunal of God with your souls filled with guilt and remorse,"], ["ma se manatua o lo outou sala atoatoa,", "having a remembrance of all your guilt,"], ["ioe,", "yea,"], ["o se manatua atoatoa o a outou amioleaga uma,", "a perfect remembrance of all your wickedness,"], ["ioe,", "yea,"], ["o se manatua o lo outou tutetee i poloaiga a le Atua?", "a remembrance that ye have set at defiance the commandments of God?"]]},
  {num:19,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["e mafai ea ona outou tepa a'e i le Atua i lena aso ma le loto mamā ma lima mamā? Ou te fai atu ia te outou,", "can ye look up to God at that day with a pure heart and clean hands? I say unto you,"], ["e mafai ea ona outou tepa a'e i luga,", "can you look up,"], ["ma foliga o le Atua ua togitogia i luga o o outou mata?", "having the image of God engraven upon your countenances?"]]},
  {num:20,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["e mafai ea ona outou mafaufau e faaolaina outou pe afai ua outou tuu atu outou lava e avea ma e e pulea e le tiapolo?", "can ye think of being saved when you have yielded yourselves to become subjects to the devil?"]]},
  {num:21,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["o le a outou iloa i lena aso e lē mafai ona faaolaina o outou;", "ye will know at that day that ye cannot be saved;"], ["ona e leai se tagata e mafai ona faaolaina sei vagana ai ua tatā faasinasina ona ofu ;", "for there can no man be saved except his garments are washed white;"], ["ioe,", "yea,"], ["e ao ina faamamaina ona ofu seia oo ina faamama mai pisia uma,", "his garments must be purified until they are cleansed from all stain,"], ["e ala i le toto o ia o lē na tautatala mai ai o tatou tamā,", "through the blood of him of whom it has been spoken by our fathers,"], ["o lē o le a afio mai e togiola ona tagata mai ia latou agasala.", "who should come to redeem his people from their sins."]]},
  {num:22,words:[["Ma o lenei ou te fesili atu ia te outou,", "And now I ask of you,"], ["ou uso e,", "my brethren,"], ["o le a se lagona o le a oo i soo se tasi o outou,", "how will any of you feel,"], ["pe afai o le a outou tutu i luma o le pa faamasino a le Atua,", "if ye shall stand before the bar of God,"], ["ma le pisipisia o o outou ofu i le toto ma ituaiga uma o mea eleelea ? Faauta,", "having your garments stained with blood and all manner of filthiness? Behold,"], ["o le a se molimau a nei mea e faasaga ia te outou?", "what will these things testify against you?"]]},
  {num:23,words:[["Faauta,", "Behold will they not testify that ye are murderers,"], ["o le a latou lē molimau mai ea o outou o tagata fasioti tagata, ioe,", "yea,"], ["ma ua outou sala foi i ituaiga o amioleaga eseese uma?", "and also that ye are guilty of all manner of wickedness?"]]},
  {num:24,words:[["Faauta,", "Behold,"], ["ou uso e,", "my brethren,"], ["tou te manatu ea e mafai e se tasi faapena ona maua se nofoaga e nofo ai i lalo i totonu o le malo o le Atua,", "do ye suppose that such an one can have a place to sit down in the kingdom of God,"], ["faatasi ma Aperaamo ,", "with Abraham,"], ["ma Isaako,", "with Isaac,"], ["ma Iakopo,", "and with Jacob,"], ["ma perofeta paia uma foi,", "and also all the holy prophets,"], ["o e ua faamamaina o latou ofu ma ua lē pisia,", "whose garments are cleansed and are spotless,"], ["ua mamā ma sinasina?", "pure and white?"]]},
  {num:25,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["E leai;", "Nay;"], ["sei vagana ai ua outou ave lo tatou Foafoa o se pepelo mai le amataga,", "except ye make our Creator a liar from the beginning,"], ["pe tou te manatu o ia o se pepelo mai le amataga,", "or suppose that he is a liar from the beginning,"], ["e lē mafai ona outou manatu e maua e se tasi faapena se nofoaga i totonu o le malo o le lagi;", "ye cannot suppose that such can have place in the kingdom of heaven;"], ["ae o le a tutuli i latou i fafo ona o i latou ia o fanau a le malo o le tiapolo.", "but they shall be cast out for they are the children of the kingdom of the devil."]]},
  {num:26,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ou uso e,", "my brethren,"], ["afai ua oo ia te outou se liuga o le loto,", "if ye have experienced a change of heart,"], ["ma afai ua outou lagona le fia pepese i le pese o le alofa togiola,", "and if ye have felt to sing the song of redeeming love,"], ["ou te fia fesili atu,", "I would ask,"], ["e mafai ea ona outou lagonaina nei?", "can ye feel so now?"]]},
  {num:27,words:[["Ua outou savavali ea,", "Have ye walked,"], ["ma tausi outou lava i le lē pōnā i luma o le Atua? E mafai ea ona outou fai ifo,", "keeping yourselves blameless before God? Could ye say,"], ["i totonu ia te outou lava,", "if ye were called to die at this time,"], ["pe afai e valaaulia outou e feoti i le taimi nei,", "within yourselves,"], ["ua lava lo outou lotomaualalalo ? Ua faamamaina o outou ofu ma ua faasinasinaina e ala i le toto o Keriso,", "that ye have been sufficiently humble? That your garments have been cleansed and made white through the blood of Christ,"], ["o lē o le a afio mai e togiola ona tagata mai ia latou agasala?", "who will come to redeem his people from their sins?"]]},
  {num:28,words:[["Faauta,", "Behold,"], ["ua tafi ese ea le faamaualuga mai ia te outou? Ou te fai atu ia te outou,", "are ye stripped of pride? I say unto you,"], ["afai e leai ua outou lē saunia e fetaiai ma le Atua. Faauta e ao ina vave ona outou saunia;", "if ye are not ye are not prepared to meet God. Behold ye must prepare quickly;"], ["ona ua lata ona oo mai o le malo o le lagi,", "for the kingdom of heaven is soon at hand,"], ["ma o se tasi faapena e lē maua e ia le ola e faavavau.", "and such an one hath not eternal life."]]},
  {num:29,words:[["Faauta,", "Behold,"], ["ou te fai atu,", "I say,"], ["pe i ai ea se tasi o i totonu o outou e lei tafiesea mai ai le mataua ? Ou te fai atu ia te outou o se tasi faapena ua lē saunia o ia;", "is there one among you who is not stripped of envy? I say unto you that such an one is not prepared;"], ["ma ou te manao ia vave ona saunia o ia,", "and I would that he should prepare quickly,"], ["ona ua lata mai le itula,", "for the hour is close at hand,"], ["ma na te lē iloa po o afea e oo mai ai le taimi;", "and he knoweth not when the time shall come;"], ["ona o se tasi faapena e lē maua i le lē sala.", "for such an one is not found guiltless."]]},
  {num:30,words:[["Ma ou te toe fai atu ia te outou,", "And again I say unto you,"], ["o i ai ea se tasi i totonu o outou ua faatauemu i lona uso,", "is there one among you that doth make a mock of his brother,"], ["pe ua ia faafaula'i i luga o ia o sauaga?", "or that heapeth upon him persecutions?"]]},
  {num:31,words:[["Oi talofa i se tasi faapena, ona ua lē saunia o ia,", "Wo unto such an one,"], ["ma ua oo mai le taimi e ao ai ona salamo o ia,", "for he is not prepared,"], ["a leai, e lē mafai ona faaolaina o ia!", "and the time is at hand that he must repent or he cannot be saved!"]]},
  {num:32,words:[["Ioe,", "Yea,"], ["e oo ia te outou uma o e ua faia amioletonu oi talofa;", "even wo unto all ye workers of iniquity;"], ["ia salamo,", "repent,"], ["ia salamo,", "repent,"], ["ona ua fetalai mai ai le Alii le Atua!", "for the Lord God hath spoken it!"]]},
  {num:33,words:[["Faauta,", "Behold,"], ["ua ia auina mai se valaaulia i tagata uma,", "he sendeth an invitation unto all men,"], ["ona ua faaloaloa mai ia te i latou aao o le alofa mutimutivale,", "for the arms of mercy are extended towards them,"], ["ma ua ia fetalai:", "and he saith:"], ["Ia salamo,", "Repent,"], ["ona ou talia lea o outou.", "and I will receive you."]]},
  {num:34,words:[["Ioe,", "Yea,"], ["ua fetalai mai o ia:", "he saith:"], ["O mai ia ia te au ma o le a outou aai ai i le fua o le laau o le ola;", "Come unto me and ye shall partake of the fruit of the tree of life;"], ["ioe,", "yea,"], ["o le a outou aai ma feinu saoloto i le areto ma vai o le ola;", "ye shall eat and drink of the bread and the waters of life freely;"]]},
  {num:35,words:[["Ioe,", "Yea,"], ["o mai ia ia te au ma aumai galuega o le amiotonu,", "come unto me and bring forth works of righteousness,"], ["ma o le a lē salaina ai outou i lalo ma lafo i le afi—", "and ye shall not be hewn down and cast into the fire—"]]},
  {num:36,words:[["Aua faauta,", "For behold,"], ["ua oo mai le taimi,", "the time is at hand that whoso– ever bringeth forth not good fruit,"], ["ai soo se tasi na te lē aumai ni fua lelei, po o soo se tasi na te lē faia galuega o le amiotonu,", "or whosoever doeth not the works of righteousness,"], ["o ia lava lea ua i ai se pogai e tagiaue ma faanoanoa ai.", "the same have cause to wail and mourn."]]},
  {num:37,words:[["E,", "O ye workers of iniquity;"], ["outou e o e ua faia le amioletonu;", "ye that are puffed up in the vain things of the world,"], ["outou o e ua faafefeteina i luga i mea lē aoga o le lalolagi, outou o e ua fai mai ua outou iloa ala o le amiotonu e ui i lea ua outou o ese mai ai,", "ye that have professed to have known the ways of righteousness nevertheless have gone astray,"], ["e pei o ni mamoe ua leai se leoleo mamoe,", "as sheep having no shepherd,"], ["e ui ina sa valaau atu se leoleo mamoe ia te outou ma o loo valaau atu pea ia te outou,", "notwithstanding a shepherd hath called after you and is still calling after you,"], ["ae ua outou le fia faalogo mai i lona siufofoga!", "but ye will not hearken unto his voice!"]]},
  {num:38,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["o loo valaau mai le leoleo mamoe lelei ia te outou;", "that the good shepherd doth call you;"], ["ioe,", "yea,"], ["ma o lona lava suafa ua ia valaauina ai outou,", "and in his own name he doth call you,"], ["o le suafa lava lea o Keriso;", "which is the name of Christ;"], ["ma afai tou te lē faalogo i le siufofoga o le leoleo mamoe lelei,", "and if ye will not hearken unto the voice of the good shepherd,"], ["i le suafa lea ua valaauina ai outou,", "to the name by which ye are called,"], ["faauta,", "behold,"], ["e lē o outou o ni mamoe a le leoleo mamoe lelei.", "ye are not the sheep of the good shepherd."]]},
  {num:39,words:[["Ma o lenei afai e lē o outou o ni mamoe a le leoleo mamoe lelei,", "And now if ye are not the sheep of the good shepherd,"], ["o le lafu a ai outou? Faauta,", "of what fold are ye? Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["o le tiapolo lava o lo outou leoleo mamoe lea,", "that the devil is your shepherd,"], ["ma o outou o lana lafu;", "and ye are of his fold;"], ["ma o lenei,", "and now,"], ["o ai e mafai ona ia faafitia lenei mea? Faauta,", "who can deny this? Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ai se tasi na te faafitia lenei mea o se pepelo ma se tama a ia a le tiapolo.", "whosoever denieth this is a liar and a child of the devil."]]},
  {num:40,words:[["Ona ou te fai atu ia te outou soo se mea ua lelei ua sau mai le Atua,", "For I say unto you that whatsoever is good cometh from God,"], ["ma o soo se mea ua leaga ua sau mai le tiapolo.", "and whatsoever is evil cometh from the devil."]]},
  {num:41,words:[["O lea,", "Therefore,"], ["afai e aumai e se tagata galuega lelei ua faalogo o ia i le siufofoga o le leoleo mamoe lelei,", "if a man bringeth forth good works he hearkeneth unto the voice of the good shepherd,"], ["ma ua mulimuli atu o ia ia te ia;", "and he doth follow him;"], ["ae o soo se tasi na te aumai galuega leaga,", "but whosoever bringeth forth evil works,"], ["o ia lava lea e avea o se tama a le tiapolo,", "the same becometh a child of the devil,"], ["ona ua faalogo o ia i lona leo,", "for he hearkeneth unto his voice,"], ["ma mulimuli atu ia te ia.", "and doth follow him."]]},
  {num:42,words:[["Ma o soo se tasi e faia lenei mea e ao lava ona ia maua ona taui mai ia te ia;", "And whosoever doeth this must receive his wages of him;"], ["o lea e maua e ia mo ona taui le oti ,", "therefore,"], ["e faatatau i mea tau i le amiotonu,", "for his wages he receiveth death, as to things pertaining unto righteousness,"], ["ona ua oti o ia e faatatau i galuega lelei uma.", "being dead unto all good works."]]},
  {num:43,words:[["Ma o lenei,", "And now,"], ["ou uso e,", "my brethren,"], ["ou te manao ia outou faalologo mai ia te au,", "I would that ye should hear me,"], ["ona ou te tautala atu ma le malosi o lo'u agaga;", "for I speak in the energy of my soul;"], ["aua faauta,", "for behold,"], ["ua manino ona ou tautala atu ia te outou e lē mafai ona outou sese,", "I have spoken unto you plainly that ye cannot err,"], ["pe ua ou tautala atu e tusa ai ma poloaiga a le Atua.", "or have spoken according to the commandments of God."]]},
  {num:44,words:[["Ona ua valaaulia au ou te tautala atu i lenei ala,", "For I am called to speak after this manner,"], ["e tusa ai ma le faatulagaga paia a le Atua,", "according to the holy order of God,"], ["lea ua ia Keriso Iesu; ioe,", "which is in Christ Jesus;"], ["ua poloaiina au ou te tu ma molimau atu i lenei nuu mea na tautalagia e o tatou tamā,", "yea,"], ["e uiga i mea o le a oo mai.", "I am commanded to stand and testify unto this people the things which have been spoken by our fathers concerning the things which are to come."]]},
  {num:45,words:[["Ma ua lē ona pau lea.", "And this is not all."], ["Tou te lē manatu ea ua ou iloa e au ia lava nei mea? Faauta, ou te molimau atu ia te outou,", "Do ye not suppose that I know of these things myself? Behold,"], ["ua ou iloa o mea ua ou tautala atu ai, ua moni.", "I testify unto you that I do know that these things whereof I have spoken are true."], ["Ma o le a so outou manatu e faapefea ona ou iloa lo latou moni?", "And how do ye suppose that I know of their surety?"]]},
  {num:46,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te outou sa faailoa mai i latou ia te au e ala i le Agaga Paia o le Atua. Faauta,", "I say unto you they are made known unto me by the Holy Spirit of God. Behold,"], ["sa ou anapogi ma tatalo i aso e tele ina ia mafai ona ou iloa nei mea mo au lava ia. Ma o lenei ua ou iloa mo au lava ia ua moni nei mea;", "I have fasted and prayed many days that I might know these things of myself. And now I do know of myself that they are true;"], ["ona o le Alii le Atua na ia faailoa mai nei mea ia te au e ala mai i lona Agaga Paia;", "for the Lord God hath made them manifest unto me by his Holy Spirit;"], ["ma o le agaga lea o faaaliga ua ia te au.", "and this is the spirit of revelation which is in me."]]},
  {num:47,words:[["Ma e lē gata i lea,", "And moreover,"], ["ou te fai atu ia te outou sa faapea foi ona faaali mai ia te au,", "I say unto you that it has thus been revealed unto me,"], ["ua moni upu na tautatala mai ai o tatou tamā,", "that the words which have been spoken by our fathers are true,"], ["e tusa lava ma le agaga o valoaga ua ia te au,", "even so according to the spirit of prophecy which is in me,"], ["lea foi na ala mai i faaaliga a le Agaga o le Atua.", "which is also by the manifestation of the Spirit of God."]]},
  {num:48,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["ua ou iloa mo au lava ia o soo se mea o le a ou tautala atu ai ia te outou,", "that I know of myself that whatsoever I shall say unto you,"], ["e uiga i mea o le a oo mai,", "concerning that which is to come,"], ["ua moni;", "is true;"], ["ma ou te fai atu ia te outou,", "and I say unto you,"], ["ua ou iloa o le a afio mai Iesu Keriso;", "that I know that Jesus Christ shall come,"], ["ioe,", "yea,"], ["le Atalii e Toatasi na Fanaua e le Tamā,", "the Son,"], ["ua tumu i le alofa tunoa,", "the Only Begotten of the Father,"], ["ma le alofa mutimutivale,", "full of grace,"], ["ma le upumoni. Ma faauta,", "and mercy,"], ["o ia lea e afio mai na te aveese agasala a le lalolagi,", "and truth. And behold,"], ["ioe,", "it is he that cometh to take away the sins of the world,"], ["agasala a tagata uma taitoatasi,", "yea,"], ["o e e tutumau i le talitonu i lona suafa.", "the sins of every man who steadfastly believeth on his name."]]},
  {num:49,words:[["Ma o lenei ou te fai atu ia te outou o le faatulagaga lenei ua valaaulia i ai au,", "And now I say unto you that this is the order after which I am called,"], ["ioe,", "yea,"], ["e talai atu i o'u uso pele,", "to preach unto my beloved brethren,"], ["ioe,", "yea,"], ["ma tagata uma taitoatasi ua nonofo i le laueleele;", "and every one that dwelleth in the land;"], ["ioe,", "yea,"], ["e talai atu i tagata uma,", "to preach unto all,"], ["o e matutua ma e laiti, o e pologa ma e saoloto;", "both old and young,"], ["ioe,", "both bond and free;"], ["ou te fai atu ia te outou o e ua matutua,", "yea,"], ["ma outou foi o e ua faamatuatagata,", "I say unto you the aged,"], ["ma le tupulaga faia'e;", "and also the middle aged,"], ["ioe,", "and the rising generation;"], ["ou te alaga atu ia te i latou,", "yea,"], ["e ao ina latou salamo ma toe fanauina.", "to cry unto them that they must repent and be born again."]]},
  {num:50,words:[["Ioe,", "Yea,"], ["sa faapea ona fetalai mai o le Agaga:", "thus saith the Spirit:"], ["Ia salamo,", "Repent,"], ["outou tuluiga uma o le lalolagi,", "all ye ends of the earth,"], ["ona ua lata mai le malo o le lagi;", "for the kingdom of heaven is soon  at hand;"], ["ioe,", "yea,"], ["ua afio mai le Alo o le Atua i lona mamalu ,", "the Son of God cometh in his glory,"], ["i lona malosi,", "in his might,"], ["maoae,", "majesty,"], ["mana,", "power,"], ["ma le pule. Ioe,", "and dominion. Yea,"], ["ou uso pele e,", "my beloved brethren,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ua fetalai mai le Agaga:", "that the Spirit saith:"], ["Faauta i le mamalu o le Tupu o le lalolagi aoao;", "Behold the glory of the King of all the earth;"], ["ma ua lata foi ona susulu atu o le Tupu o le lagi i totonu o le fanauga uma a tagata.", "and also the King of heaven shall very soon shine forth among all the children of men."]]},
  {num:51,words:[["Ma ua fetalai mai foi le Agaga ia te au,", "And also the Spirit saith unto me,"], ["ioe,", "yea,"], ["ua alaga mai ia te au i se siufofoga malosi, ua fetalai mai:", "crieth unto me with a mighty voice,"], ["Alu atu ia ma fai atu i lenei nuu—Ia salamo,", "saying:"], ["ona sei vagana ai ua outou salamo,", "Go forth and say unto this people—Repent,"], ["e lē mafai lava i soo se ala ona outou mautofi i le malo o le lagi .", "for except ye repent ye can in nowise inherit the kingdom of heaven."]]},
  {num:52,words:[["Ma ou te toe fai atu ia te outou,", "And again I say unto you,"], ["ua fetalai mai le Agaga:", "the Spirit saith:"], ["Faauta,", "Behold,"], ["ua faataatia nei le matau i le tafue o le laau,", "the ax is laid at the root of the tree;"], ["o lea o laau uma e lē fua mai i fua lelei, o le a sala i lalo ma lafo i le afi,", "therefore every tree that bringeth not forth good fruit shall be hewn down and cast into the fire,"], ["ioe,", "yea,"], ["o se afi e lē mafai ona mate,", "a fire which cannot be consumed,"], ["o se afi lava e lē matineia.", "even an unquenchable fire."], ["Faauta,", "Behold,"], ["ma ia manatua,", "and remember,"], ["o le Paia e Toatasi ua fetalai mai ai.", "the Holy One hath spoken it."]]},
  {num:53,words:[["Ma o lenei ou uso pele e,", "And now my beloved brethren,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["e mafai ea ona outou tetee nei fetalaiga;", "can ye withstand these sayings;"], ["ioe,", "yea,"], ["e mafai ea ona outou tuu ese nei mea,", "can ye lay aside these things,"], ["ma soli le Paia e Toatasi i lalo o o outou vae;", "and trample the Holy One under your feet;"], ["ioe,", "yea,"], ["e mafai ea ona faafefete a'e outou i luga i le faamaualuluga o o outou loto;", "can ye be puffed up in the pride of your hearts;"], ["ioe,", "yea,"], ["tou te tausisi pea ea i le ofuina o ofu taugata ma tuu atu o outou loto i luga o mea lē aoga o le lalolagi,", "will ye still persist in the wearing of costly apparel and setting your hearts upon the vain things of the world,"], ["i luga o a outou oa ?", "upon your riches?"]]},
  {num:54,words:[["Ioe,", "Yea,"], ["o le a outou tausisi pea ea i le manatu faapea ua sili atu lo outou lelei nai lo o se tasi;", "will ye persist in supposing that ye are better one than another;"], ["ioe,", "yea,"], ["o le a outou tausisi pea ea i le sauaina o o outou uso,", "will ye persist in the persecution of your brethren,"], ["o e ua latou faalotomaualalalo i latou lava ma ua savavali e tusa ma le faatulagaga paia a le Atua,", "who humble themselves and do walk after the holy order of God,"], ["lea na aumai ai i latou i lenei ekalesia,", "wherewith they have been brought into this church,"], ["ina ua faapaiaina e le Agaga Paia,", "having been sanctified by the Holy Spirit,"], ["ma ua latou aumai galuega lelei ua tatau ai mo le salamo—", "and they do bring forth works which are meet for repentance—"]]},
  {num:55,words:[["Ioe,", "Yea,"], ["ma o le a outou tausisi pea ea i le fuli atu o o outou tua i e ua matitiva ,", "and will you persist in turning your backs upon the poor,"], ["ma e ua lē tagolima,", "and the needy,"], ["ma i le taofi o a outou mea mai ia te i latou?", "and in withholding your substance from them?"]]},
  {num:56,words:[["Ma mulimuli lava,", "And finally,"], ["o outou uma o e e tausisi pea i lo outou amioleaga, ou te fai atu ia te outou,", "all ye that will persist in your wickedness,"], ["o i latou ia o i latou o le a sala i lalo ma lafo i le afi vagana ai ua vave ona latou salamo.", "I say unto you that these are they who shall be hewn down and cast into the fire except they speedily repent."]]},
  {num:57,words:[["Ma o lenei ou te fai atu ia te outou,", "And now I say unto you,"], ["outou uma o e e fia mulimuli i le siufofoga o le leoleo mamoe lelei,", "all you that are desirous to follow the voice of the good shepherd,"], ["ia outou o ese mai i e amioleaga,", "come ye out from the wicked,"], ["ma ia outou tuese ,", "and be ye separate,"], ["ma aua nei pai atu ia latou mea lē mamā;", "and touch not their unclean things;"], ["ma faauta,", "and behold,"], ["o le a soloia ese o latou igoa,", "their names shall be blotted out,"], ["ina ia lē faitauina igoa o e amioleaga i totonu o igoa o e amiotonu,", "that the names of the wicked shall not be numbered among the names of the righteous,"], ["ina ia mafai ona faataunuuina le afioga a le Atua,", "that the word of God may be fulfilled,"], ["ua fai mai:", "which saith:"], ["O le a lē faafefiloiina igoa o e amioleaga ma igoa o o'u tagata;", "The names of the wicked shall not be mingled with the names of my people;"]]},
  {num:58,words:[["Ona o igoa o e amiotonu o le a tusia i le tusi o le ola,", "For the names of the righteous shall be written in the book of life,"], ["ma o le a ou tuu atu ia te i latou se nofoaga i lo'u lima taumatau. Ma o lenei,", "and unto them will I grant an inheritance at my right hand. And now,"], ["ou uso e,", "my brethren,"], ["se a fa a outou e faasaga i lenei mea? Ou te fai atu ia te outou,", "what have ye to say against this? I say unto you,"], ["afai tou te tautatala tetee i ai,", "if ye speak against it,"], ["e le afaina,", "it matters not,"], ["ona e faataunuuina lava le afioga a le Atua.", "for the word of God must be fulfilled."]]},
  {num:59,words:[["Ona o ai se leoleo mamoe o i totonu o outou,", "For what shepherd is there among you having many sheep doth not watch over them,"], ["ua ia te ia ni mamoe e tele, ae ua ia lē leoleo i luga o i latou,", "that the wolves enter not and devour his flock? And behold,"], ["ina ia lē ulu mai luko ma ai lana lafu? Ma faauta,", "if a wolf enter his flock doth he not drive him out? Yea,"], ["afai e ulu mai se luko i lana lafu pe na te lē tuli ese ea o ia i fafo? Ioe,", "and at the last,"], ["ma mulimuli lava, afai na te mafaia,", "if he can,"], ["na te fasimate o ia.", "he will destroy him."]]},
  {num:60,words:[["Ma o lenei ou te fai atu ia te outou,", "And now I say unto you that the good shepherd doth call after you;"], ["o loo valaau mai le leoleo mamoe lelei ia te outou; ma afai tou te faalogo i lona siufofoga,", "and if you will hearken unto his voice he will bring you into his fold,"], ["o le a ia aumai outou i lana lafu,", "and ye are his sheep;"], ["ma o outou o ana mamoe; ma ua ia poloaiina outou ia aua ne'i o outou tuu se luko feai ia ulu mai i totonu o outou,", "and he commandeth you that ye suffer no ravenous wolf to enter among you,"], ["ina ia lē mafai ona faaumatiaina outou.", "that ye may not be destroyed."]]},
  {num:61,words:[["Ma o lenei,", "And now I,"], ["o au o Alema,", "Alma,"], ["ou te poloai atu ia te outou i le gagana a ia o lē na ia poloaiina au,", "do command you in the language of him who hath commanded me,"], ["ia outou vaai ia outou faia upu ia sa ou tautala atu ai ia te outou.", "that ye observe to do the words which I have spoken unto you."]]},
  {num:62,words:[["Ou te tautala atu faapoloaiga ia te outou o e ua auai i le ekalesia;", "I speak by way of command unto you that belong to the church;"], ["ma ia i latou o e ua lē auai i le ekalesia,", "and unto those who do not belong to the church I speak by way of invitation,"], ["ou te tautala atu i ai faalevalaaulia, ma fai atu:", "saying:"], ["O mai ma ia papatiso i le salamo,", "Come and be baptized unto repentance,"], ["ina ia avea foi outou ma e mafai ona aai i le fua o le laau o le ola.", "that ye also may be partakers of the fruit of the tree of life."]]},
];
renderVerseSet(al_ch_5_Verses, 'al-ch5-verses');

var al_ch_6_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina ua uma ona tautala atu o Alema i tagata o le ekalesia,", "And now it came to pass that after Alma had made an end of speaking unto the people of the church,"], ["lea sa faatu i le aai o Sara'emila,", "which was established in the city of Zarahemla,"], ["sa ia faauuina faitaulaga ma toeaina , i le faaee atu o ona lima ,", "he ordained priests and elders,"], ["e tusa ma le faatulagaga a le Atua,", "by laying on his hands according to the order of God,"], ["e pulefaamalumalu ma leoleo i luga o le ekalesia.", "to preside and watch over the church."]]},
  {num:2,words:[["Ma sa oo ina o soo se tasi sa lē auai i le ekalesia o e na salamo ia latou agasala sa papatisoina i le salamo,", "And it came to pass that whosoever did not belong to the church who repented of their sins were baptized unto repentance,"], ["ma taliaina i le ekalesia.", "and were received into the church."]]},
  {num:3,words:[["Ma sa oo foi ina o soo se tasi sa auai i le ekalesia o e sa lē salamo ia latou amioleaga ma sa lē faamaualalalo i latou lava i luma o le Atua—o le uiga o la'u tala o i latou ia o e sa faafefeteina i luga i le faamaualuluga o o latou loto—o i latou lava ia sa lē taliaina,", "And it also came to pass that whosoever did belong to the church that did not repent of their wickedness and humble themselves before God—I mean those who were lifted up in the pride of their hearts—the same were rejected,"], ["ma soloi ese o latou igoa,", "and their names were blotted out,"], ["ina ia lē faitauina o latou igoa i totonu o igoa o e ua amiotonu.", "that their names were not numbered among those of the righteous."]]},
  {num:4,words:[["Ma sa faapea ona amata ona latou faatu o le faatulagaga o le ekalesia i le aai o Sara'emila.", "And thus they began to establish the order of the church in the city of Zarahemla."]]},
  {num:5,words:[["O lenei ou te manao ina ia outou malamalama sa tuufua mai le afioga a le Atua i tagata uma,", "Now I would that ye should understand that the word of God was liberal unto all,"], ["sa leai se tasi sa taofi mai i le avanoa e potopoto faatasi ai i latou lava e faalogologo i le afioga a le Atua.", "that none were deprived of the privilege of assembling themselves together to hear the word of God."]]},
  {num:6,words:[["E ui i lea sa poloaiina fanau a le Atua e tatau ona latou faapotopoto faatasi soo i latou lava,", "Nevertheless the children of God were commanded that they should gather themselves together oft,"], ["ma aufaatasi i le anapogi ma le tatalo malosi mo le manuia o agaga o i latou o e sa latou lē iloaina le Atua.", "and join in fasting and mighty prayer in behalf of the welfare of the souls of those who knew not God."]]},
  {num:7,words:[["Ma o lenei sa oo ina ua uma ona faia e Alema nei faatonuga sa alu ese atu o ia mai ia te i latou,", "And now it came to pass that when Alma had made these regulations he departed from them,"], ["ioe,", "yea,"], ["mai le ekalesia lea sa i le aai o Sara'emila,", "from the church which was in the city of Zarahemla,"], ["ma alu a'e i luga i le itu i sasae o le vaitafe o Saitonu,", "and went over upon the east of the river Sidon,"], ["i le vanu o Kitiona,", "into the valley of Gideon,"], ["lea sa faatu ai iina se aai,", "there  having been a city built,"], ["lea sa taua o le aai o Kitiona,", "which was called the city of Gideon,"], ["lea sa i le vanu sa taua o Kitiona,", "which was in the valley that was called Gideon,"], ["lea sa faaigoa i le tagata o lē na fasioti e le lima o Ne'oa i le pelu.", "being called after the man who was slain by the hand of Nehor with the sword."]]},
  {num:8,words:[["Ma sa alu atu Alema ma amata ona alaga atu o le afioga a le Atua i le ekalesia lea sa faatu i le vanu o Kitiona,", "And Alma went and began to declare the word of God unto the church which was established in the valley of Gideon,"], ["e tusa ma le faaaliga o le moni o le afioga lea na tautalagia e ona tamā,", "according to the revelation of the truth of the word which had been spoken by his fathers,"], ["ma e tusa ma le agaga o valoaga sa ia te ia,", "and according to the spirit of prophecy which was in him,"], ["e tusa ma le molimau e uiga ia Iesu Keriso,", "according to the testimony of Jesus Christ,"], ["le Alo o le Atua,", "the Son of God,"], ["o lē o le a afio mai e togiola ona tagata mai ia latou agasala,", "who should come to redeem his people from their sins,"], ["ma e tusa ma le faatulagaga paia lea na valaaulia i ai o ia. Ma ua faapea ona tusia. Amene.", "and the holy order by which he was called. And thus it is written. Amen."]]},
];
renderVerseSet(al_ch_6_Verses, 'al-ch6-verses');

var al_ch_7_Verses = [
  {num:1,words:[["Faauta ou uso pele e,", "Behold my beloved brethren,"], ["talu ai ona ua ou saofia mai ou te sau ia te outou,", "seeing that I have been permitted to come unto you,"], ["o lea ou te taumafai ai e tautala atu ia te outou i la'u gagana;", "therefore I attempt to address you in my language;"], ["ioe,", "yea,"], ["i lo'u lava gutu,", "by my own mouth,"], ["talu ai ona o le taimi muamua lenei ua ou tautala atu ai ia te outou i upu a lo'u gutu,", "seeing that it is the first time that I have spoken unto you by the words of my mouth,"], ["ona sa taofiofia atoatoa au i le nofoa-faamasino ,", "I having been wholly confined to the judgment– seat,"], ["ona o le tele o pisinisi sa lē mafai ai ona ou sau ia te outou.", "having had much business that I could not come unto you."]]},
  {num:2,words:[["Ma sa oo lava semanu po ua lē mafai ona ou sau nei ia te outou i le taimi nei, pe a na lē tuuina atu le nofoa-faamasino i se tasi,", "And even I could not have come now at this time were it not that the judgment– seat hath been given to another,"], ["e nofotupu e sui ia te au;", "to reign in my stead;"], ["ma ua tuuina mai e le Alii i lona alofa mutimutivale tele, ia ou sau ia te outou.", "and the Lord in much mercy hath granted that I should come unto you."]]},
  {num:3,words:[["Ma faauta,", "And behold,"], ["ua ou sau ma faamoemoega tetele ma le naunau tele o le a ou maua mai outou o outou faamaualalaloina outou lava i luma o le Atua,", "I have come having great hopes and much desire that I should find that ye had humbled yourselves before God,"], ["ma o loo outou aioi atu pea e lē aunoa mo lona alofa tunoa,", "and that ye had continued in the supplicating of his grace,"], ["ma o le a ou maua mai outou o outou lē ponā i ona luma,", "that I should find that ye were blameless before him,"], ["o le a ou maua mai outou tou te lē o i ai i le lugaluga leaga tele sa i ai i totonu o o tatou uso i Sara'emila.", "that I should find that ye were not in the awful dilemma that our brethren were in at Zarahemla."]]},
  {num:4,words:[["Ae ia faamanuina lava le suafa o le Atua,", "But blessed be the name of God,"], ["ona ua ia tuuina mai ia te au ia ou iloa,", "that he hath given me to know,"], ["ioe, tuuina mai ia te au le olioli tele naua,", "yea,"], ["i le iloa ua toe faatutuina i latou i le ala o lana amiotonu.", "hath given unto me the exceedingly great joy of knowing that they are established again in the way of his righteousness."]]},
  {num:5,words:[["Ma ou te faamoemoe,", "And I trust,"], ["e tusa ma le Agaga o le Atua ua ia te au,", "according to the Spirit of God which is in me,"], ["o le a ou maua foi le olioli ia te outou; e ui i lea ou te lē manao ia ou maua lo'u olioli i luga o outou e ala i puapuaga e tele ma le faanoanoa sa oo mai ia te au i le au uso i Sara'emila,", "that I shall also have joy over you;"], ["aua faauta,", "nevertheless I do not desire that my joy over you should come by the cause of so much afflictions and sorrow which I have had for the brethren at Zarahemla,"], ["sa oo mai lo'u olioli i luga o i latou,", "for behold,"], ["ina ua mavae ona ou asa atu i le puapuaga tele ma le faanoanoa.", "my joy cometh over them after wading through much affliction and sorrow."]]},
  {num:6,words:[["Ae faauta,", "But behold,"], ["ou te faalagolago tou te lē o i ai i se tulaga o le lē talitonu tele e pei ona sa i ai o outou uso;", "I trust that ye are not in a state of so much unbelief as were your brethren;"], ["ou te faalagolago e lē o faafefeteina outou i luga i le faamaualuluga o o outou loto;", "I trust that ye are not lifted up in the pride of your hearts;"], ["ioe,", "yea,"], ["ou te faalagolago tou te lei tuu atu o outou loto i luga o oa ma mea lē aoga o le lalolagi;", "I trust that ye have not set your hearts upon riches and the vain things of the world;"], ["ioe,", "yea,"], ["ou te faalagolago tou te lē o tapuai atu i tupua ,", "I trust that you do not worship idols,"], ["ae o loo outou tapuai atu i le Atua moni soifua,", "but that ye do worship the true and living God,"], ["ma o outou tulimatai i luma ma le faatuatua tumau-faavavau,", "and that ye look forward for the remission of your sins,"], ["mo le faamagaloina o a outou agasala,", "with an everlasting faith,"], ["lea o le a oo mai.", "which is to come."]]},
  {num:7,words:[["Aua faauta,", "For behold,"], ["ou te fai atu ia te outou,", "I say unto you there be many things to come;"], ["e tele mea o le a oo mai; ma faauta,", "and behold,"], ["e i ai se mea e tasi ua sili atu ona taua nai lo ia mea uma—aua faauta,", "there is one thing which is of more importance than they all—for behold,"], ["ua lē o toe mamao le taimi o le a soifua ma afio mai ai le Togiola i totonu o ona tagata.", "the time is not far distant that the Redeemer liveth and cometh among his people."]]},
  {num:8,words:[["Faauta,", "Behold,"], ["ou te lē o fai atu o le a afio mai o ia i totonu o i tatou i le taimi o lona soifuaga i lona fale apitaga faaletino;", "I do not say that he will come among us at the time of his dwelling in his mortal tabernacle;"], ["aua faauta,", "for behold,"], ["sa lei fetalai mai le Agaga ia te au o le tulaga lena o le a i ai. O lenei e faatatau i lenei mea ou te lē iloa;", "the Spirit hath not said unto me that this should be the case. Now as to this thing I do not know;"], ["ae o le tele lenei o le mea ua ou iloa,", "but this much I do know,"], ["ua i ai i le Alii le Atua le mana na te faia ai mea uma e tusa ai ma lana afioga.", "that the Lord God hath power to do all things which are according to his word."]]},
  {num:9,words:[["Ae faauta,", "But behold,"], ["o le tele lenei o le mea na fetalai mai e le Agaga ia te au,", "the Spirit hath said this much unto me,"], ["ua fetalai mai:", "saying:"], ["Alaga atu i lenei nuu,", "Cry unto this people,"], ["ia fai atu—Ia outou salamo ,", "saying—Repent ye,"], ["ma teuteu le ala o le Alii,", "and prepare the way of the Lord,"], ["ma savavali i ona ala,", "and walk in his paths,"], ["ua sasa'o;", "which are straight;"], ["ona faauta,", "for behold,"], ["ua lata mai le malo o le lagi,", "the kingdom of heaven is at hand,"], ["ma ua afio mai le Alo o le Atua i luga o le lalolagi.", "and the Son of God cometh upon the face of the earth."]]},
  {num:10,words:[["Ma faauta,", "And behold,"], ["o le a fanau mai o ia ia Maria ,", "he shall be born of Mary,"], ["i Ierusalema,", "at Jerusalem which is the land of our forefathers,"], ["le laueleele lea o o tatou tua'ā,", "she being a virgin,"], ["ona o ia o se taupou , o se ipu pele ma filifilia,", "a precious and chosen vessel,"], ["o lē o le a faamalumaluina ma to i le mana o le Agaga Paia,", "who shall be overshadowed and conceive by the power of the Holy Ghost,"], ["ma fanau mai se atalii,", "and bring forth a son,"], ["ioe,", "yea,"], ["o le Alo lava o le Atua.", "even the Son of God."]]},
  {num:11,words:[["Ma o le a afio atu o ia, ma mafatia i tiga ma puapuaga ma faaosoosoga o ituaiga eseese uma;", "And he shall go forth,"], ["ma o le a oo ia te ia nei mea,", "suffering pains and afflictions and temptations of every kind;"], ["ina ia mafai ona faataunuuina o le upu ua fai mai, o le a ia ave i ona luga tiga ma ma'i o ona tagata.", "and this that the word might be fulfilled which saith he will take upon him the pains and the sicknesses of his people."]]},
  {num:12,words:[["Ma o le a ia ave i ona luga le oti ,", "And he will take upon him death,"], ["ina ia mafai ona ia tatalaina fusi o le oti ia ua noatia ai ona tagata; ma o le a ia ave i ona luga o latou vaivaiga,", "that he may loose the bands of death which bind his people;"], ["ina ia mafai ona faatumuina ona loto i le alofa mutimutivale,", "and he will take upon him their infirmities,"], ["e tusa ai ma la le tino,", "that his bowels may be filled with mercy,"], ["ina ia mafai ona ia silafia e tusa ai ma la le tino, le ala e fesoasoani ai i ona tagata,", "according to the flesh,"], ["e tusa ma o latou vaivaiga.", "that he may know according to the flesh how to succor his people according to their infirmities."]]},
  {num:13,words:[["O lenei ua silafia e le Agaga mea uma;", "Now the Spirit knoweth all things;"], ["e ui i lea, e mafatia le Alo o le Atua e tusa ai ma la le tino,", "nevertheless the Son of God suffereth according to the flesh that he might take upon him the sins of his people,"], ["ina ia mafai ona ia ave i ona luga agasala a ona tagata,", "that he might blot out their transgressions according to the power of his deliverance;"], ["ina ia mafai ona ia soloi ese a latou solitulafono e tusa ai ma le mana o lana laveaiga; ma o lenei faauta,", "and now behold,"], ["o le molimau lenei ua i ai ia te au.", "this is the testimony which is in me."]]},
  {num:14,words:[["O lenei ou te fai atu ia te outou e ao ina outou salamo,", "Now I say unto you that ye must repent,"], ["ma toe fanauina;", "and be born again;"], ["ona o loo fetalai mai le Agaga afai e lē toe fanauina outou,", "for the Spirit saith if ye are not born again ye cannot inherit the kingdom of heaven;"], ["e lē mafai ona outou mautofi i le malo o le lagi;", "therefore come and be baptized unto repentance,"], ["o lea ia o mai ia ma papatiso i le salamo, ina ia mafai ona fufuluina outou mai ia outou agasala,", "that ye may be washed from your sins,"], ["ina ia mafai ona outou maua le faatuatua i le Tamai Mamoe a le Atua,", "that ye may have faith on the Lamb of God,"], ["o lē na te aveesea agasala a le lalolagi,", "who taketh away the sins of the world,"], ["o lē ua malosi e faaola ma faamama mai i amioletonu uma.", "who is mighty to save and to cleanse from all unrighteousness."]]},
  {num:15,words:[["Ioe,", "Yea,"], ["ou te fai atu ia te outou, ia o mai ia,", "I say unto you come and fear not,"], ["ma aua le fefefe,", "and lay aside every sin,"], ["ma tuu ese agasala taitasi uma,", "which easily doth beset you,"], ["ia ua faigofie ona outou lavelavea ai, ia ua noatia ai outou i lalo i le faafanoga,", "which doth bind you down to destruction,"], ["ioe,", "yea,"], ["o mai ia ma o atu,", "come and go forth,"], ["ma faaali atu i lo outou Atua ua outou loto e salamo ia outou agasala, ma ulu atu i se feagaiga faatasi ma ia e tausi i ana poloaiga,", "and show unto your God that ye are willing to repent of your sins and enter into a covenant with him to keep his command–  ments,"], ["ma molimau atu lenei mea ia te ia i le asō i le tou o ifo ai i totonu o vai o le papatisoga.", "and witness it unto him this day by going into the waters of baptism."]]},
  {num:16,words:[["Ma o soo se tasi e faia lenei mea,", "And whosoever doeth this,"], ["ma tausi i poloaiga a le Atua mai le taimi lena seia oo i luma,", "and keepeth the commandments of God from thenceforth,"], ["o ia lava lea o le a ia manatua ua ou fai atu ia te ia,", "the same will remember that I say unto him,"], ["ioe,", "yea,"], ["o le a manatua e ia na ou fai atu ia te ia,", "he will remember that I have said unto him,"], ["o le a maua e ia le ola e faavavau,", "he shall have eternal life,"], ["e tusa ma le molimau a le Agaga Paia,", "according to the testimony of the Holy Spirit,"], ["lea ua molimau mai ia te au.", "which testifieth in me."]]},
  {num:17,words:[["Ma o lenei ou uso pele e,", "And now my beloved brethren,"], ["tou te talitonu ea i nei mea? Faauta,", "do you believe these things? Behold,"], ["ou te fai atu ia te outou, ioe,", "I say unto you,"], ["ua ou iloa ua outou talitonu i ai;", "yea,"], ["ma o le ala ua ou iloa ai ua outou talitonu i ai,", "I know that ye believe them;"], ["o le faaaliga lea a le Agaga ua i totonu o au.", "and the way that I know that ye believe them is by the manifestation of the Spirit which is in me."], ["Ma o lenei ona o le malosi o lo outou faatuatua e uiga i lena mea,", "And now because your faith is strong concerning that,"], ["ioe,", "yea,"], ["e uiga i mea ua ou tautala atu ai,", "concerning the things which I have spoken,"], ["ua tele lava lo'u olioli.", "great is my joy."]]},
  {num:18,words:[["Ona e pei ona sa ou fai atu ia te outou mai le amataga,", "For as I said unto you from the beginning,"], ["sa ou naunau tele lava ia outou lē i ai i le tulaga lugaluga e pei o o outou uso,", "that I had much desire that ye were not in the state of dilemma like your brethren,"], ["ua faapea lava ona ou iloa ua faamalieina o'u moomooga.", "even so I have found that my desires have been gratified."]]},
  {num:19,words:[["Ona ua ou vaai atu ua outou i ai i totonu o le ala o le amiotonu;", "For I perceive that ye are in the paths of righteousness;"], ["ua ou vaai atu ua outou i ai i totonu o le ala e tau atu i le malo o le Atua;", "I perceive that ye are in the path which leads to the kingdom of God;"], ["ioe,", "yea,"], ["ua ou vaai atu ua outou faasa'osa'oina ona ala .", "I perceive that ye are making his paths straight."]]},
  {num:20,words:[["Ua ou vaai atu ua uma ona faailoa mai ia te outou,", "I perceive that it has been made known unto you,"], ["e ala i le molimau a lana afioga,", "by the testimony of his word,"], ["e lē mafai ona savali o ia i ala pi'opi'o;", "that he cannot walk in crooked paths;"], ["pe alu ese o ia mai le mea na ia fetalai mai ai;", "neither doth he vary from that which he hath said;"], ["pe o ia te ia se foliga o le liliu mai le itu taumatau i le itu tauagavale,", "neither hath he a shadow of turning from the right to the left,"], ["pe mai le mea sa'o i le mea sese;", "or from that which is right to that which is wrong;"], ["o lea,", "therefore,"], ["o lona ala o se taamilosaga faavavau e tasi.", "his course is one eternal round."]]},
  {num:21,words:[["Ma e lē afio o ia i ni malumalu ua lē paia;", "And he doth not dwell in unholy temples;"], ["pe mafai foi ona talia se mea eleelea po o se mea ua lē mama i le malo o le Atua;", "neither can filthiness or anything which is unclean be received into the kingdom of God;"], ["o lea ou te fai atu ai ia te outou, o le a oo mai le taimi,", "therefore I say unto you the time shall come,"], ["ioe,", "yea,"], ["ma o le aso mulimuli lea o le a oo mai ai,", "and it shall be at the last day,"], ["o ia o lē ua eleelea o le a tumau pea i lona eleelea.", "that he who is filthy shall remain in his filthiness."]]},
  {num:22,words:[["Ma o lenei ou uso pele e,", "And now my beloved brethren,"], ["ua ou fai atu nei mea ia te outou ina ia mafai ai ona ou fagua o outou i se lagona o lo outou tiute i le Atua,", "I have said these things unto you that I might awaken you to a sense of your duty to God,"], ["ina ia mafai ona outou savavali ma le lē ponā i ona luma,", "that ye may walk blameless before him,"], ["ina ia mafai ona outou savavali e tusa ai ma le faatulagaga paia a le Atua,", "that ye may walk after the holy order of God,"], ["lea ua talia i ai outou.", "after which ye have been received."]]},
  {num:23,words:[["Ma o lenei ou te manao ina ia outou lotomaualalalo ,", "And now I would that ye should be humble,"], ["ma augofie ma agamalu;", "and be submissive and gentle;"], ["e faigofie ona faaoleoleina;", "easy to be entreated;"], ["tumu i le onosai ma le tali-tiga;", "full of patience and long– suffering;"], ["ma faautauta i mea uma;", "being temperate in all things;"], ["ma filiga i le tausiga o poloaiga a le Atua i taimi uma;", "being diligent in keeping the commandments of God at all times;"], ["ma ole atu mo soo se mea tou te manaomia,", "asking for whatsoever things ye stand in need,"], ["faaleagaga ma faaletino;", "both spiritual and temporal;"], ["ma faafoi atu i taimi uma le faafetai i le Atua mo soo se mea o mea uma tou te maua.", "always returning thanks unto God for whatsoever things ye do receive."]]},
  {num:24,words:[["Ma vaai ia i ai ia te outou le faatuatua ,", "And see that ye have faith,"], ["faamoemoe,", "hope,"], ["ma le alofa mama,", "and charity,"], ["ona tumu ai lea o outou i galuega lelei i taimi uma.", "and then ye will always abound in good works."]]},
  {num:25,words:[["Ma talosia ia faamanuia mai le Alii ia te outou,", "And may the Lord bless you,"], ["ma tausi o outou ofu i le lē pisipisia,", "and keep your garments spotless,"], ["ina ia mafai ona aumai o outou i le taimi mulimuli e nonofo faatasi i lalo ma Aperaamo,", "that ye may at last be brought to sit down with Abraham,"], ["Isaako,", "Isaac,"], ["ma Iakopo,", "and Jacob,"], ["ma perofeta paia o e na i ai talu mai le amataga o le lalolagi,", "and the holy prophets who have been ever since the world began,"], ["ma le lē pisipisia o o outou ofu e pei lava o le lē pisipisia o o latou ofu,", "having your garments spotless  even as their garments are spotless,"], ["i totonu o le malo o le lagi e lē toe o ese atu i fafo.", "in the kingdom of heaven to go no more out."]]},
  {num:26,words:[["Ma o lenei ou uso pele e,", "And now my beloved brethren,"], ["ua ou tautala atu nei upu ia te outou e tusa ma le Agaga lea ua molimau mai i totonu o au;", "I have spoken these words unto you according to the Spirit which testifieth in me;"], ["ma ua olioli tele lava lo'u agaga,", "and my soul doth exceedingly rejoice,"], ["ona o le filiga tele ma le gauai ua outou tuuina mai i au upu.", "because of the exceeding diligence and heed which ye have given unto my word."]]},
  {num:27,words:[["Ma o lenei,", "And now,"], ["talosia ia mau i o outou luga le filemu a le Atua,", "may the peace of God rest upon you,"], ["ma luga o o outou fale ma laueleele,", "and upon your houses and lands,"], ["ma luga o a outou lafu ma fagaga,", "and upon your flocks and herds,"], ["ma a outou mea uma ua maua,", "and all that you possess,"], ["o outou fafine ma a outou fanau,", "your women and your children,"], ["e tusa ma o outou faatuatua ma a outou galuega lelei,", "according to your faith and good works,"], ["mai le taimi nei e oo atu i luma ma le faavavau. Ma ua faapea ona ou tautala atu. Amene.", "from this time forth and forever. And thus I have spoken. Amen."]]},
];
renderVerseSet(al_ch_7_Verses, 'al-ch7-verses');

var al_ch_8_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina toe foi mai Alema mai le nuu o Kitiona,", "And now it came to pass that Alma returned from the land of Gideon,"], ["ina ua uma ona ia aoaoina le nuu o Kitiona i mea e tele e lē mafai ona tusia,", "after having taught the people of Gideon many things which cannot be written,"], ["ina ua uma ona ia faatuina le faatulagaga o le ekalesia,", "having established the order of the church,"], ["e pei ona sa ia faia muamua i le laueleele o Sara'emila,", "according as he had before done in the land of Zarahemla,"], ["ioe,", "yea,"], ["sa ia toe foi atu i lona lava fale i Sara'emila e malolo ai o ia lava mai galuega na ia faia.", "he returned to his own house at Zarahemla to rest himself from the labors which he had performed."]]},
  {num:2,words:[["Ma sa faapea ona iu o le lona iva o tausaga o le nofoaiga a faamasino i le nuu o Nifae.", "And thus ended the ninth year of the reign of the judges over the people of Nephi."]]},
  {num:3,words:[["Ma sa oo i le amataga o le lona sefulu o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae,", "And it came to pass in the commencement of the tenth year of the reign of the judges over the people of Nephi,"], ["na alu ese atu ai Alema mai iina ma alu atu lana malaga i le laueleele o Meleka,", "that Alma departed from thence and took his journey over into the land of Melek,"], ["i le itu i sisifo o le vaitafe o Saitonu,", "on the west of the river Sidon,"], ["i le itu i sisifo i tafatafa o tuaoi o le vao.", "on the west by the borders of the wilderness."]]},
  {num:4,words:[["Ma sa amata ona ia aoao atu i tagata o le laueleele o Meleka e tusa ma le faatulagaga paia a le Atua,", "And he began to teach the people in the land of Melek according to the holy order of God,"], ["lea sa valaaulia i ai o ia;", "by which he had been called;"], ["ma sa amata ona ia aoaoina tagata i le laueleele atoa o Meleka.", "and he began to teach the people throughout all the land of Melek."]]},
  {num:5,words:[["Ma sa oo ina o mai tagata ia te ia mai tuaoi uma o le laueleele ia sa i tafatafa o le vao. Ma sa papatisoina i latou i le laueleele atoa;", "And it came to pass that the people came to him throughout all the borders of the land which was by the wilderness side. And they were baptized throughout all the land;"]]},
  {num:6,words:[["Sa oo ina ua uma lana galuega i Meleka sa alu ese atu o ia mai iina,", "So that when he had finished his work at Melek he departed thence,"], ["ma malaga atu i se malaga e tolu aso i le itu i matu o le laueleele o Meleka;", "and traveled three days' journey on the north of the land of Melek;"], ["ma sa oo atu o ia i se aai sa taua o Amonaea.", "and he came to a city which was called Ammonihah."]]},
  {num:7,words:[["O lenei sa avea o se tu masani i tagata o Nifae le faaigoa o o latou laueleele,", "Now it was the custom of the people of Nephi to call their lands,"], ["ma o latou aai,", "and their cities,"], ["ma o latou nuu,", "and their villages,"], ["ioe,", "yea,"], ["e oo i o latou nuu laiti uma,", "even all their small villages,"], ["i le igoa o ia o lē na muai nofoia i latou;", "after the name of him who first possessed them;"], ["ma sa faapea le tulaga sa i ai le laueleele o Amonaea.", "and thus it was with the land of Ammonihah."]]},
  {num:8,words:[["Ma sa oo ina ua oo atu Alema i le aai o Amonaea sa amata ona ia talai atu le afioga a le Atua ia te i latou.", "And it came to pass that when Alma had come to the city of Ammonihah he began to preach the word of God unto them."]]},
  {num:9,words:[["O lenei sa malosi tele le 'uu a Satani i loto o tagata o le aai o Amonaea;", "Now Satan had gotten great hold upon the hearts of the people of the city of Ammonihah;"], ["o lea sa latou lē fia faalogo ai i upu a Alema.", "therefore they would not hearken unto the words of Alma."]]},
  {num:10,words:[["E ui i lea sa galue malosi Alema i le agaga,", "Nevertheless Alma labored much in the spirit,"], ["ma fagatua ma le Atua i le tatalo malosi,", "wrestling with God in mighty prayer,"], ["ma ia sasaa ifo lona Agaga i luga o tagata o e sa i le aai;", "that he would pour out his Spirit upon the people who were in the city;"], ["ma ia ona tuu mai foi ia mafai ona ia papatisoina i latou i le salamo.", "that he would also grant that he might baptize them unto repentance."]]},
  {num:11,words:[["E ui i lea,", "Nevertheless,"], ["sa latou faamaaa o latou loto,", "they hardened their hearts,"], ["ua fai mai ia te ia:", "saying unto him:"], ["Faauta,", "Behold,"], ["ua matou iloa o oe o Alema;", "we know that thou art Alma;"], ["ma ua matou iloa o oe o le faitaulaga sili o le ekalesia lea ua e faatuina i le tele o vaega o le laueleele,", "and we know that thou art high priest over the church which thou hast established in many parts of the land,"], ["e tusa ai ma lau masani;", "according to your tradition;"], ["ma e lē o i matou o ni o o lau ekalesia,", "and we are not of thy church,"], ["ma e matou te lē talitonu i ni tu valea faapena.", "and we do not believe in such foolish traditions."]]},
  {num:12,words:[["Ma o lenei ua matou iloa ona o i matou e lē o ni o o lau ekalesia ua matou iloa e leai sau pule i luga o i matou;", "And now we know that because we are not of thy church we know that thou hast no power over us;"], ["ma ua e tuu atu le nofoa-faamasino ia Nifaea ;", "and thou hast delivered up the judgment– seat unto Nephihah;"], ["o lea ua lē o oe ai o se faamasino sili i luga o i matou.", "therefore thou art not the chief judge over us."]]},
  {num:13,words:[["O lenei ina ua uma ona fai mai e tagata nei upu,", "Now when the people had said this,"], ["ma tututetee mai i ana upu uma,", "and withstood all his words,"], ["ma faifai mai ia te ia,", "and reviled him,"], ["ma tuufeanu i ona luga,", "and spit upon him,"], ["ma faatonu ia tuli ese o ia i fafo mai lo latou aai,", "and caused that he should be cast out of their city,"], ["sa ia alu ese atu mai iina ma alu atu lana malaga agai i le aai sa taua o Arona.", "he departed thence and took his journey towards the city which was called Aaron."]]},
  {num:14,words:[["Ma sa oo ina o malaga atu o ia iina,", "And it came to pass that while he was journeying thither,"], ["ma le mamafa o le faanoanoa i ona luga,", "being weighed down with sorrow,"], ["ma asa atu i le puapuaga tele ma le mafatia o le agaga,", "wading through much tribulation and anguish of soul,"], ["ona o le amioleaga o tagata o e sa i le aai o Amonaea, sa a'o faapea ona mamafa o le faanoanoa i luga o Alema,", "because of the wickedness of the people who were in the city of Ammonihah,"], ["faauta,", "it came to pass while Alma was thus weighed down with sorrow,"], ["sa afio ifo se agelu a le Alii ia te ia,", "behold an angel of the Lord appeared unto him,"], ["ua fetalai mai:", "saying:"]]},
  {num:15,words:[["Amuia lava oe,", "Blessed art thou,"], ["Alema;", "Alma;"], ["o lea,", "therefore,"], ["inā ea ia i luga lou ulu ma olioli,", "lift up thy head and rejoice,"], ["ona ua ia te oe se pogai tele e te olioli ai;", "for thou hast great cause to rejoice;"], ["ona sa e faamaoni i le tausiga o poloaiga a le Atua mai i le taimi lava na e maua ai lau savali muamua mai ia te ia. Faauta,", "for thou hast been faithful in keeping the commandments of God from the time which thou receivedst thy first message from him. Behold,"], ["o au o ia o lē na aumaia lena savali ia te oe.", "I am he that delivered it unto you."]]},
  {num:16,words:[["Ma faauta,", "And behold,"], ["ua auina mai au e poloaiina oe,", "I am sent to command thee that thou return to the city of Ammonihah,"], ["ia e toe foi atu i le aai o Amonaea, ma toe talai atu i tagata o le aai;", "and preach again unto the people of the city;"], ["ioe,", "yea,"], ["talai atu ia te i latou.", "preach unto them."], ["Ioe,", "Yea,"], ["fai atu ia te i latou, vagana ai ua latou salamo,", "say unto them,"], ["o le a faaumatia i latou e le Alii le Atua.", "except they repent the Lord God will destroy them."]]},
  {num:17,words:[["Aua faauta,", "For behold,"], ["o loo latou suesue i le taimi nei ia mafai ona latou faaumatia le saolotoga o lou nuu,", "they do study at this time that they may destroy the liberty of thy people,"], ["(ona sa faapea ona fetalai mai ai o le Alii) o se mea ua lē tusa ai ma tulafono, ma faamasinoga,", "(for thus saith the Lord) which is contrary to the statutes,"], ["ma poloaiga,", "and judgments,"], ["ia na ia tuu mai i ona tagata.", "and commandments which he has given unto his people."]]},
  {num:18,words:[["O lenei sa oo ina ua uma ona maua e Alema lana savali mai le agelu a le Alii sa vave ona ia toe foi atu i le laueleele o Amonaea. Ma sa ia ulu atu i le aai i se tasi auala,", "Now it came to pass that after Alma had received his message from the angel of the Lord he returned speedily to the land of Ammonihah. And he entered the city by another way,"], ["ioe,", "yea,"], ["i le ala lea o loo i le itu i saute o le aai o Amonaea.", "by the way which is on the south of the city of Ammonihah."]]},
  {num:19,words:[["Ma a'o ulu atu o ia i le aai,", "And as he entered the city he was an hungered,"], ["sa fia ai o ia, ma sa ia fai atu i se alii:", "and he said to a man:"], ["E te tuuina mai ea sina meaai i se auauna faatauvaa a le Atua?", "Will ye give to an humble servant of God something to eat?"]]},
  {num:20,words:[["Ma sa fai mai lea alii ia te ia:", "And the man said unto him:"], ["O au o se sa Nifaē,", "I am a Nephite,"], ["ma ua ou iloa o oe o se perofeta paia a le Atua,", "and I know that thou art a holy prophet of God,"], ["ona o oe o le tagata lea o lē na fetalai mai ai se agelu i se faaaliga vaaia:", "for thou art the man whom an angel said in a  vision:"], ["Ia e talia o ia. O lea,", "Thou shalt receive. Therefore,"], ["ta o faatasi ma au i lo'u fale ma o le a ou avatu ia te oe ni a'u meaai;", "go with me into my house and I will impart unto thee of my food;"], ["ma ua ou iloa o le a avea oe ma faamanuiaga ia te au ma lo'u aiga.", "and I know that thou wilt be a blessing unto me and my house."]]},
  {num:21,words:[["Ma sa oo ina talia o ia e lenei alii i lona fale;", "And it came to pass that the man received him into his house;"], ["ma o le igoa o lenei alii o Amoleka ;", "and the man was called Amulek;"], ["ma sa ia aumai areto ma aano o manu ma laulau atu i luma o Alema.", "and he brought forth bread and meat and set before Alma."]]},
  {num:22,words:[["Ma sa oo ina taumafa e Alema areto ma laulelei ai;", "And it came to pass that Alma ate bread and was filled;"], ["ma sa faamanuia atu o ia ia Amoleka ma lona aiga,", "and he blessed Amulek and his house,"], ["ma sa ia avatu le faafetai i le Atua.", "and he gave thanks unto God."]]},
  {num:23,words:[["Ma ina ua uma ona taumafa o ia ma ua laulelei sa ia fai atu ia Amoleka:", "And after he had eaten and was filled he said unto Amulek:"], ["O au o Alema,", "I am Alma,"], ["ma o au o le faitaulaga sili i luga o le ekalesia a le Atua i le laueleele atoa.", "and am the high priest over the church of God throughout the land."]]},
  {num:24,words:[["Ma faauta,", "And behold,"], ["ua valaauina au e talai atu le afioga a le Atua i totonu o nei tagata uma,", "I have been called to preach the word of God among all this people,"], ["e tusa ma le agaga o faaaliga ma valoaga;", "according to the spirit of revelation and prophecy;"], ["ma sa ou i ai i le laueleele lenei ae sa latou lē taliaina au,", "and I was in this land and they would not receive me,"], ["ae sa latou tuli ese au i fafo ma sa toeitiiti ou fulitua mai e faavavau i lenei laueleele.", "but they cast me out and I was about to set my back towards this land forever."]]},
  {num:25,words:[["Peitai faauta,", "But behold,"], ["ua poloaiina au ia ou toe liliu mai ma vavalo atu i lenei nuu,", "I have been commanded that I should turn again and prophesy unto this people,"], ["ioe,", "yea,"], ["ma molimau faasaga atu ia te i latou e uiga ia latou amioletonu.", "and to testify against them concerning their iniquities."]]},
  {num:26,words:[["Ma o lenei,", "And now,"], ["Amoleka e,", "Amulek,"], ["ona ua e fafaga ia te au ma e ave au i totonu o lou fale,", "because thou hast fed me and taken me in,"], ["ua faamanuiaina oe;", "thou art blessed;"], ["ona sa ou fia ai,", "for I was an hungered,"], ["aua sa ou anapogi i aso e tele.", "for I had fasted many days."]]},
  {num:27,words:[["Ma sa tele aso sa nofo ai Alema faatasi ma Amoleka ae lei amata ona ia talai atu i tagata.", "And Alma tarried many days with Amulek before he began to preach unto the people."]]},
  {num:28,words:[["Ma sa oo ina faasolo amioleaga tele tagata ia latou amioletonu.", "And it came to pass that the people did wax more gross in their iniquities."]]},
  {num:29,words:[["Ma sa oo mai le afioga ia Alema,", "And the word came to Alma,"], ["ua fetalai mai:", "saying:"], ["Alu ia;", "Go;"], ["ma fai atu foi i la'u auauna o Amoleka,", "and also say unto my servant Amulek,"], ["ia alu ma vavalo atu i lenei nuu, ia fai atu—Ia outou salamo ,", "go forth and prophesy unto this people,"], ["ona ua faapea ona fetalai mai o le Alii,", "saying—Repent ye,"], ["vagana ai ua outou salamo,", "for thus saith the Lord,"], ["o le a ou asiasi atu i lenei nuu i lo'u ita;", "except ye repent I will visit this people in mine anger;"], ["ioe,", "yea,"], ["ma o le a ou lē liliu ese lo'u ita tele.", "and I will not turn my fierce anger away."]]},
  {num:30,words:[["Ma sa alu atu Alema,", "And Alma went forth,"], ["ma Amoleka foi,", "and also Amulek,"], ["i totonu o tagata,", "among the people,"], ["e alaga atu afioga a le Atua ia te i latou;", "to declare the words of God unto them;"], ["ma sa tutumu i laua i le Agaga Paia.", "and they were filled with the Holy Ghost."]]},
  {num:31,words:[["Ma sa ia te i laua se mana sa tuuina mai ia te i laua,", "And they had power given unto them,"], ["sa oo ina lē mafai ona taofiofia o i laua i falepuipui;", "insomuch that they could not be confined in dungeons;"], ["pe na mafai foi e se tagata ona fasioti ia te i laua;", "neither was it possible that any man could slay them;"], ["e ui i lea sa la lē faaaogaina lo laua mana seia oo lava ina saisai i laua i fusi ma lafo i totonu o le falepuipui. O lenei,", "nevertheless they did not exercise their power until they were bound in bands and cast into prison. Now,"], ["sa faia lenei mea ina ia mafai ona faaali mai ai e le Alii lona mana e ala mai ia te i laua.", "this was done that the Lord might show forth his power in them."]]},
  {num:32,words:[["Ma sa oo ina laua o atu, ma amata ona talai ma vavalo atu i tagata,", "And it came to pass that they went forth and began to preach and to prophesy unto the people,"], ["e tusa ai ma le agaga ma le mana na tuu mai e le Alii ia te i laua.", "according to the spirit and power which the Lord had given them."]]},
];
renderVerseSet(al_ch_8_Verses, 'al-ch8-verses');

var al_ch_9_Verses = [
  {num:1,words:[["Ma ou te toe fai atu,", "And again,"], ["o au,", "I,"], ["o Alema,", "Alma,"], ["ina ua poloaiina au e le Atua ia ou ave Amoleka ma alu atu ma toe talai atu i lenei nuu,", "having been commanded of God that I should take Amulek and go forth and preach again unto this people,"], ["po o tagata o e sa i le aai o Amonaea,", "or the people  who were in the city of Ammonihah,"], ["sa oo ina a'o amata ona ou talai atu ia te i latou,", "it came to pass as I began to preach unto them,"], ["sa amata ona latou finau mai ia te au,", "they began to contend with me,"], ["fai mai:", "saying:"]]},
  {num:2,words:[["O ai oe? E te manatu ea o le a matou talitonu i le molimau a se tagata e toatasi ,", "Who art thou? Suppose ye that we shall believe the testimony of one man,"], ["e ui ina faapea e talai mai ia te i matou e faapea o le a mavae atu le lalolagi?", "although he should preach unto us that the earth should pass away?"]]},
  {num:3,words:[["O lenei sa latou lē malamalama i upu na latou tautatala mai ai;", "Now they understood not the words which they spake;"], ["ona sa latou lē iloa o le a mavae atu le lalolagi.", "for they knew not that the earth should pass away."]]},
  {num:4,words:[["Ma sa latou fai mai foi:", "And they said also:"], ["Matou te lē talitonu i au upu pe afai e te vavalo mai o le a faaumatia lenei aai tele i se aso e tasi.", "We will not believe thy words if thou shouldst prophesy that this great city should be destroyed in one day."]]},
  {num:5,words:[["O lenei sa latou lē iloa e mafai e le Atua ona fai o galuega ofoofogia faapena,", "Now they knew not that God could do such marvelous works,"], ["ona o i latou o ni tagata loto-maaa ma ua maaa.", "for they were a hard– hearted and a stiffnecked people."]]},
  {num:6,words:[["Ma sa latou fai mai:", "And they said:"], ["O ai le Atua,", "Who is God,"], ["ua ia lē auina mai ai i totonu o lenei nuu se pule tele atu i lo o se tagata e toatasi,", "that sendeth no more authority than one man among this people,"], ["e alaga mai ia te i latou le moni o ia mea tetele ma ofoofogia faapea?", "to declare unto them the truth of such great and marvelous things?"]]},
  {num:7,words:[["Ma sa latou tutu mai e fetagofi mai o latou lima ia te au;", "And they stood forth to lay their hands on me;"], ["ae faauta,", "but behold,"], ["sa latou lē fetagofi mai. Ma sa ou tu atu ma le lotoa e tautino atu ia te i latou,", "they did not. And I stood with boldness to declare unto them,"], ["ioe,", "yea,"], ["sa ou molimau atu ma le lotoa ia te i latou,", "I did boldly testify unto them,"], ["ua ou fai atu:", "saying:"]]},
  {num:8,words:[["Faauta,", "Behold,"], ["E,", "O ye wicked and perverse generation,"], ["outou e le tupulaga amioleaga ma faapi'opi'o, ua vave lava ona galo ia te outou le uputuu a o outou tamā;", "how have ye forgotten the tradition of your fathers;"], ["ioe,", "yea,"], ["ua vave lava ona galo ia te outou poloaiga a le Atua.", "how soon ye have forgotten the commandments of God."]]},
  {num:9,words:[["Tou te lē manatua ea o lo tatou tamā,", "Do ye not remember that our father,"], ["o Liae,", "Lehi,"], ["na aumai i fafo mai Ierusalema e le aao o le Atua? Tou te lē manatua ea na ia taitaiina i latou uma i le vao?", "was brought out of Jerusalem by the hand of God? Do ye not remember that they were all led by him through the wilderness?"]]},
  {num:10,words:[["Ma pe ua vave ea ona galo ia te outou le tele o taimi na ia laveai ai o tatou tamā i fafo mai lima o o latou fili,", "And have ye forgotten so soon how many times he delivered our fathers out of the hands of their enemies,"], ["ma faasaoina i latou mai le faaumatiaina,", "and preserved them from being destroyed,"], ["i lima o o latou lava uso?", "even by the hands of  their own brethren?"]]},
  {num:11,words:[["Ioe,", "Yea,"], ["ma a na leai lona mana lē mafaatusalia,", "and if it had not been for his matchless power,"], ["ma lona alofa mutimutivale,", "and his mercy,"], ["ma lona tali-tiga mai ia i tatou,", "and his long– suffering towards us,"], ["po ua lē maalofia le leva ona vavae ese o i tatou mai luga o le lalolagi ae lei taitai ona oo mai i le vaitaimi nei,", "we should unavoidably have been cut off from the face of the earth long before this period of time,"], ["ma atonu ua tuu i tatou i se tulaga o le pagatia ma le malaia e lē gata.", "and perhaps been consigned to a state of endless misery and woe."]]},
  {num:12,words:[["Faauta,", "Behold,"], ["ou te fai atu nei ia te outou ua ia poloai mai ia te outou ia outou salamo;", "now I say unto you that he commandeth you to repent;"], ["ma vagana ai ua outou salamo,", "and except ye repent,"], ["e lē mafai lava i soo se auala ona outou mautofi i le malo o le Atua. Ae faauta,", "ye can in nowise inherit the kingdom of God. But behold,"], ["ua lē ona pau lea—ua ia poloaiina outou ia outou salamo,", "this is not all—he has commanded you to repent,"], ["a leai o le a ia faaumatiaina ese atoa outou mai luga o le lalolagi;", "or he will utterly destroy you from off the face of the earth;"], ["ioe,", "yea,"], ["o le a ia asiasi mai ia te outou i lona toasa,", "he will visit you in his anger,"], ["ma o le a ia lē liliu ese mai lona toasa tele.", "and in his fierce anger he will not turn away."]]},
  {num:13,words:[["Faauta,", "Behold,"], ["tou te lē manatua ea afioga na ia fetalai mai ia Liae,", "do ye not remember the words which he spake unto Lehi,"], ["na fetalai mai e faapea:", "saying that:"], ["O le tulaga e oo i ai la outou tausiga o au poloaiga,", "Inasmuch as ye shall keep my command– ments,"], ["o le a outou manuia i le laueleele? Ma sa toe fetalai mai e faapea:", "ye shall prosper in the land? And again it is said that:"], ["O le tulaga e oo i ai la outou lē tausia o au poloaiga o le a vavae ese outou mai luma o le Alii.", "Inasmuch as ye will not keep my commandments ye shall be cut off from the presence of the Lord."]]},
  {num:14,words:[["O lenei ou te manao ia outou manatua,", "Now I would that ye should remember,"], ["o le tulaga na oo i ai le lē tausia e sa Lamanā poloaiga a le Atua,", "that inasmuch as the Lamanites have not kept the  commandments of God,"], ["ua vavae ese i latou mai luma o le Alii. O lenei ua tatou vaai ua faamaonia le afioga a le Alii i lenei mea,", "they have been cut off from the presence of the Lord. Now we see that the word of the Lord has been verified in this thing,"], ["ma ua vavae ese sa Lamanā mai i ona luma,", "and the Lamanites have been cut off from his presence,"], ["mai le amataga o a latou solitulafono i le laueleele.", "from the beginning of their transgressions in the land."]]},
  {num:15,words:[["E ui i lea ou te fai atu ia te outou,", "Nevertheless I say unto you,"], ["o le a sili atu ona gafatiaina mo i latou nai lo outou i le aso faamasino,", "that it shall be more tolerable for them in the day of judgment than for you,"], ["pe afai tou te tutumau ia outou agasala,", "if ye remain in your sins,"], ["ioe,", "yea,"], ["ma sili atili atu ona gafatiaina mo i latou i le olaga nei nai lo outou,", "and even more tolerable for them in this life than for you,"], ["vagana ai ua outou salamo.", "except ye repent."]]},
  {num:16,words:[["Ona e i ai folafolaga e tele ua tuuina atu ia sa Lamanā;", "For there are many promises which are extended to the Lamanites;"], ["ona o uputuu a o latou tamā ua ala ai ona latou tutumau i lo latou tulaga o le lē malamalama;", "for it is because of the traditions of their fathers that caused them to remain in their state of ignorance;"], ["o lea o le a alofa mutimutivale ai le Alii ia te i latou ma faalevaleva lo latou ola i le laueleele.", "therefore the Lord will be merciful unto them and prolong their existence in the land."]]},
  {num:17,words:[["Ma e i ai se vaitaimi o le a aumai ai i latou ia talitonu i lana afioga,", "And at some period of time they will be brought to believe in his word,"], ["ma latou iloa le sese o uputuu a o latou tamā;", "and to know of the incorrectness of the traditions of their fathers;"], ["ma e toatele i latou o le a faaolaina,", "and many of them will be saved,"], ["ona o le a alofa mutimutivale le Alii ia te i latou uma o e e valaau atu i lona suafa.", "for the Lord will be merciful unto all who call on his name."]]},
  {num:18,words:[["Ae faauta,", "But behold,"], ["ou te fai atu ia te outou afai tou te tausisi pea i lo outou amioleaga o le a lē faalevalevaina o outou aso i le laueleele,", "I say unto you that if ye persist in your wickedness that your days shall not be prolonged in the land,"], ["ona o le a auina mai sa Lamanā i o outou luga;", "for the Lamanites shall be sent upon you;"], ["ma afai tou te lē salamo o le a latou o mai i se taimi tou te lē iloa,", "and if ye repent not they shall come in a time when you know not,"], ["ma o le a asia outou i le faafanoga atoa;", "and ye shall be visited with utter destruction;"], ["ma o le a faia e tusa ai ma le toasa tele o le Alii.", "and it shall be according to the fierce anger of the Lord."]]},
  {num:19,words:[["Ona o le a ia lē tuu outou ia outou ola ia outou amioletonu,", "For he will not suffer you that ye shall live in your iniquities,"], ["e faaumatia ai ona tagata. Ou te fai atu ia te outou,", "to destroy his people. I say unto you,"], ["E leai;", "Nay;"], ["e sili ia te ia le tuu o sa Lamanā ia mafai ona latou faaumatiaina ona tagata uma o e ua taua o le nuu o Nifae,", "he would rather suffer that the Lamanites might destroy all his people who are called the people of Nephi,"], ["pe afai e mafai ona latou pauu atu i agasala ma solitulafono,", "if it were possible that they could fall into sins and transgressions,"], ["ina ua mavae lea ona tuuina mai ia te i latou le malamalama tele naua ma le poto tele naua e le Alii lo latou Atua;", "after having had so much light and so much knowledge given unto them of the Lord their God;"]]},
  {num:20,words:[["Ioe,", "Yea,"], ["ina ua mavae lea ona avea ma tagata sili ona faapitoa o le Alii;", "after having been such a highly favored people of the Lord;"], ["ioe,", "yea,"], ["ina ua mavae lea ona faapitoa silisili atu i luga o isi atunuu uma,", "after having been favored above every other nation,"], ["ituaiga,", "kindred,"], ["gagana,", "tongue,"], ["po o nuu;", "or people;"], ["ina ua mavae lea ona faaali mai o mea uma ia te i latou,", "after having had all things made known unto them,"], ["e tusa ai ma o latou manao,", "according to their desires,"], ["ma o latou faatuatua,", "and their faith,"], ["ma tatalo,", "and prayers,"], ["e uiga i mea sa i ai,", "of that which has been,"], ["ma mea o i ai,", "and which is,"], ["ma mea o le a oo mai;", "and which is to come;"]]},
  {num:21,words:[["Ina ua mavae lea ona asia o i latou e le Agaga o le Atua;", "Having been visited by the Spirit of God;"], ["ma fetautalatalaai ma agelu,", "having conversed with angels,"], ["ma fetalai mai i ai le siufofoga o le Alii;", "and having been spoken unto by the voice of the Lord;"], ["ma ina ua latou maua le agaga o valoaga,", "and having the spirit of prophecy,"], ["ma le agaga o faaaliga,", "and the spirit of revelation,"], ["ma meaalofa foi e tele,", "and also many gifts,"], ["o le meaalofa o le tautatala i gagana,", "the gift of speaking with tongues,"], ["ma le meaalofa o le talai atu,", "and the gift of preaching,"], ["ma le meaalofa a le Agaga Paia,", "and the gift of the Holy Ghost,"], ["ma le meaalofa o le faamatalaina o gagana;", "and the gift of translation;"]]},
  {num:22,words:[["Ioe,", "Yea,"], ["ma ina ua mavae lea ona laveaiina o i latou e le Atua i fafo o le laueleele o Ierusalema,", "and after having been delivered of God out of the land of Jerusalem,"], ["i le aao o le Alii;", "by the hand of the Lord;"], ["ina ua faaolaina i latou mai le oge,", "having been saved from famine,"], ["ma mai i ma'i,", "and from sickness,"], ["ma ituaiga uma o faama'i eseese;", "and all manner of diseases of every  kind;"], ["ma ina ua latou faasolo malolosi i taua,", "and they having waxed strong in battle,"], ["ina ia lē mafai ona faaumatiaina o i latou;", "that they might not be destroyed;"], ["ma aveesea soo i fafo mai le pologa i lea taimi ma lea taimi,", "having been brought out of bondage time after time,"], ["ma tausia ma faasaoina seia oo mai i le taimi nei;", "and having been kept and preserved until now;"], ["ma ua faamanuiaina i latou seia oo ina latou mauoa i ituaiga o mea eseese uma—", "and they have been prospered until they are rich in all manner of things—"]]},
  {num:23,words:[["Ma o lenei faauta ou te fai atu ia te outou,", "And now behold I say unto you,"], ["afai e solitulafono lenei nuu,", "that if this people,"], ["o e ua latou maua faamanuiaga e tele mai le aao o le Alii,", "who have received so many blessings from the hand of the Lord,"], ["e lē tusa ai ma le malamalama ma le poto ua latou maua, ou te fai atu ia te outou afai o le tulaga lea e oo i ai,", "should transgress contrary to the light and knowledge which they do have,"], ["pe afai o le a latou pauu atu i le solitulafono,", "I say unto you that if this be the case,"], ["o le a sili atu ona gafatiaina mo sa Lamanā,", "that if they should fall into transgression,"], ["nai lo mo i latou.", "it would be far more tolerable for the Lamanites than for them."]]},
  {num:24,words:[["Aua faauta,", "For behold,"], ["ua tuuina atu ia sa Lamanā folafolaga a le Alii,", "the promises of the Lord are extended to the Lamanites,"], ["ae ua lē tuuina atu ia folafolaga ia te outou pe afai tou te solitulafono;", "but they are not unto you if ye transgress;"], ["ona e lei folafola manino mai ea ma poloaia tumau e le Alii,", "for has not the Lord expressly promised and firmly decreed,"], ["e faapea afai tou te fouvale faasaga atu ia te ia o le a faaumatia atoa ese outou mai luga o le lalolagi?", "that if ye will rebel against him that ye shall utterly be destroyed from off the face of the earth?"]]},
  {num:25,words:[["Ma o lenei ina ia lē faaumatiaina outou,", "And now for this cause,"], ["o le pogai lea na auina mai ai e le Alii lana agelu e asiasi mai i le toatele o ona tagata,", "that ye may not be destroyed,"], ["e alaga mai ia te i latou e ao ina latou o atu ma alalaga malosi atu i lenei nuu,", "the Lord has sent his angel to visit many of his people, declaring unto them that they must go forth and cry mightily unto this people,"], ["ia fai atu:", "saying:"], ["Ia outou salamo ,", "Repent ye,"], ["ona ua latalata oo mai le malo o le lagi;", "for the kingdom of heaven is nigh at hand;"]]},
  {num:26,words:[["Ma ua lē tele ni aso mai le taimi nei ae o le a afio mai le Atalii o le Atua i lona mamalu;", "And not many days hence the Son of God shall come in his glory;"], ["ma o lona mamalu o le mamalu lea o le Toatasi na Fanaua e le Tamā,", "and his glory shall be the glory of the Only Begotten of the Father,"], ["ua tumu i le alofa tunoa,", "full of grace,"], ["fai mea tutusa,", "equity,"], ["ma le upumoni,", "and truth,"], ["ua tumu i le onosai,", "full of patience,"], ["alofa mutimutivale,", "mercy,"], ["ma le tali-tiga,", "and long– suffering,"], ["e vave ona faafofoga mai i tagi a ona tagata ma tali a latou tatalo.", "quick to hear the cries of his people and to answer their prayers."]]},
  {num:27,words:[["Ma faauta,", "And behold,"], ["e afio mai o ia e togiola i latou o e e papatiso i le salamo,", "he cometh to redeem those who will be baptized unto repentance,"], ["e ala i le faatuatua i lona suafa.", "through faith on his name."]]},
  {num:28,words:[["O lea,", "Therefore,"], ["ia outou teuteu le ala o le Alii,", "prepare ye the way of the Lord,"], ["ona ua lata mai le taimi e selesele ai e tagata uma se taui o a latou galuega ,", "for the time is at hand that all men shall reap a reward of their works,"], ["e tusa ma tulaga sa latou i ai—afai sa latou amiotonu o le a latou selesele le olataga mo o latou agaga,", "according to that which they have been—if they have been righteous they shall reap the salvation of their souls,"], ["e tusa ma le mana ma le laveaiga a Iesu Keriso;", "according to the power and deliverance of Jesus Christ;"], ["ae afai sa latou amioleaga o le a latou selesele le malaia mo o latou agaga,", "and if they have been evil they shall reap the damnation of their souls,"], ["e tusa ma le mana ma le faatagataotauaina a le tiapolo.", "according to the power and captivation of the devil."]]},
  {num:29,words:[["O lenei faauta,", "Now behold,"], ["o le siufofoga lea o le agelu,", "this is the voice of the angel,"], ["ua alaga atu i tagata.", "crying unto the people."]]},
  {num:30,words:[["Ma o lenei,", "And now,"], ["ou uso pele e,", "my beloved brethren,"], ["ona o outou o ou uso,", "for ye are my brethren,"], ["ma e ao ina pele o outou,", "and ye ought to be beloved,"], ["ma e ao ina outou aumai galuega ua tatau ai mo le salamo,", "and ye ought to bring forth works which are meet for repentance,"], ["ona ua vaaia ua matua faamaaa o outou loto e faasaga i le afioga a le Atua,", "seeing that your hearts have been grossly hardened against the word of God,"], ["ma ona ua vaai ua avea outou ma ni tagata se ma pauu.", "and seeing that ye are a lost and a fallen people."]]},
  {num:31,words:[["O lenei sa oo ina ua uma ona tautala atu e au,", "Now it came to pass that when I,"], ["o Alema,", "Alma,"], ["nei upu,", "had spoken these words,"], ["faauta,", "behold,"], ["sa feita tagata ia te au ona sa ou fai atu ia te i latou o i latou o ni tagata loto-maaa ma ua maaa.", "the people were wroth with me because I said unto them that they were a hard– hearted and a stiffnecked people."]]},
  {num:32,words:[["Ma ona sa ou fai atu foi ia te i latou o i latou o ni tagata ua se ma pauu,", "And also because I said unto them that they were a lost and a fallen people they were angry with me,"], ["sa latou feita mai ia te au, ma taumafai e fetagofi mai o latou lima ia te au,", "and sought to lay their hands upon me,"], ["ina ia mafai ona latou lafo o au i le falepuipui.", "that they might cast me into prison."]]},
  {num:33,words:[["Peitai sa oo ina sa lei tuuina atu e le Alii ia i latou ia latou ave au i le taimi lena ma lafo au i le falepuipui.", "But it came to pass that the Lord did not suffer them that they should take me at that time and cast me into prison."]]},
  {num:34,words:[["Ma sa oo ina alu atu Amoleka ma tulai atu,", "And it came to pass that Amulek went and stood forth,"], ["ma amata ona talai atu foi ia te i latou. Ma o lenei ua lē tusia upu uma a Amoleka,", "and began to preach unto them also. And now the words of Amulek are not all written,"], ["e ui i lea ua tusia se vaega o ana upu i lenei tusi.", "nevertheless a part of his words are written in this book."]]},
];
renderVerseSet(al_ch_9_Verses, 'al-ch9-verses');

var al_ch_10_Verses = [
  {num:1,words:[["O lenei o upu nei na talai atu ai Amoleka i tagata o e sa i le laueleele o Amonaea,", "Now these are the words which Amulek preached unto the people who were in the land of Ammonihah,"], ["ua fai atu:", "saying:"]]},
  {num:2,words:[["O au o Amoleka;", "I am Amulek;"], ["o au o le atalii o Kitona,", "I am the son of Giddonah,"], ["o ia o lē o le atalii o Isamaeli,", "who was the son of Ishmael,"], ["o o lē na tupuga mai ia Aminati;", "who was a descendant of Aminadi;"], ["ma o Aminati lava lea o lē na faaliliuina le tusitusiga sa i luga o le pa o le malumalu,", "and it was the same Aminadi who interpreted the writing which was upon the wall of the temple,"], ["lea na tusia e le tamatamaiaao o le Atua.", "which was written by the finger of God."]]},
  {num:3,words:[["Ma o Aminati o sē e tupuga mai ia Nifae,", "And Aminadi was a descendant of Nephi,"], ["o lē o le atalii o Liae,", "who was the son of Lehi,"], ["o lē na sau i fafo mai le laueleele o Ierusalema,", "who came out of the land of Jerusalem,"], ["o lē o sē na tupuga mai ia Manase ,", "who was a descendant of Manasseh,"], ["o lē o le atalii o Iosefa o lē na faatau atu i Aikupito i lima o ona uso.", "who was the son of Joseph who was sold into Egypt by the hands of his brethren."]]},
  {num:4,words:[["Ma faauta,", "And behold,"], ["o au foi o se tagata e lē itiiti le taualoa i totonu o i latou uma o e ua latou iloaina au;", "I am also a man of no small reputation among all those who know me;"], ["ioe,", "yea,"], ["ma faauta,", "and behold,"], ["e toatele o'u aiga ma a'u uo ,", "I have many kindreds and friends,"], ["ma ua ou maua foi oa e tele e ala i lo'u lima toaga.", "and I have also acquired much riches by the hand of my industry."]]},
  {num:5,words:[["E ui i lea,", "Nevertheless,"], ["e ui i nei mea uma,", "after all this,"], ["sa lei tele ni mea sa ou iloa e uiga i ala o le Alii,", "I never have known much of the ways of the Lord,"], ["ma ana mealilo ma lona mana ofoofogia. Ua ou fai atu sa lei tele ni mea sa ou iloa e uiga i nei mea;", "and his mysteries and marvelous power. I said I never had known much of these things;"], ["ae faauta,", "but behold,"], ["ua ou sese,", "I mistake,"], ["ona ua ou vaai i le tele o ana mealilo ma lona mana ofoofogia;", "for I have seen much of his mysteries and his marvelous power;"], ["ioe,", "yea,"], ["e oo lava i le faasaoina o ola o lenei nuu.", "even in the preservation of the lives of this people."]]},
  {num:6,words:[["E ui i lea,", "Nevertheless,"], ["sa ou faamaaa lo'u loto,", "I did harden my heart,"], ["ona sa valaauina au i le tele o taimi ae sa ou lē fia faalogo ;", "for I was called many times and I would not hear;"], ["o lea sa ou iloa e uiga i nei mea,", "therefore I knew concerning these things,"], ["peitai sa ou lē fia iloaina;", "yet I would not know;"], ["o lea na ou alu ai pea lava i le fouvale faasaga i le Atua,", "therefore I went on rebelling against God,"], ["i le amioleaga o lo'u loto,", "in the wickedness of my heart,"], ["seia oo mai i le aso fa o le masina lona fitu lenei,", "even until the fourth day of this seventh month,"], ["o le lona sefulu lea o tausaga o le nofoaiga a faamasino.", "which is in the tenth year of the reign of the judges."]]},
  {num:7,words:[["A'o ou malaga atu e vaai i se tasi o lo'u aiga latalata mai lava,", "As I was journeying to see a very near kindred,"], ["faauta sa oo mai se agelu a le Alii ia te au ma fetalai mai:", "behold an angel of the Lord appeared unto me and said:"], ["Amoleka,", "Amulek,"], ["foi atu i lou lava fale,", "return to thine own house,"], ["ona o le a e fafagaina se perofeta a le Alii;", "for thou shalt feed a prophet of the Lord;"], ["ioe,", "yea,"], ["o se tagata paia,", "a holy man,"], ["o sē o se tagata filifilia o le Atua;", "who is a chosen man of God;"], ["ona sa anapogi o ia i aso e tele ona o agasala a lenei nuu,", "for he has fasted many days because of the sins of this people,"], ["ma ua matelaina o ia i le fia ai,", "and he is an hungered,"], ["ma ia e talia o ia i lou fale ma fafaga ia te ia,", "and thou shalt receive him into thy house and feed him,"], ["ma o le a ia faamanuiaina oe ma lou aiga;", "and he shall bless thee and thy house;"], ["ma o le a mau i ou luga ma lou aiga le faamanuiaga a le Alii.", "and the blessing of the Lord shall rest upon thee and thy house."]]},
  {num:8,words:[["Ma sa oo ina ou usiusitai i le siufofoga o le agelu,", "And it came to pass that I obeyed the voice of the angel,"], ["ma ou toe foi agai mai i lo'u fale. Ma a'o ou alu atu iina sa ou maua le tagata na fetalai mai ai le agelu ia te au:", "and returned towards my house. And as I was going thither I found the man whom the angel said unto me:"], ["Ia e talia i lou fale—ma faauta o le tagata lava lenei o lē sa tautala atu ia te outou e uiga i mea a le Atua.", "Thou shalt receive into thy house—and behold it was this same man who has been speaking unto you concerning the things of God."]]},
  {num:9,words:[["Ma sa fetalai mai le agelu ia te au o ia o se tagata paia;", "And the angel said unto me he is a holy man;"], ["o le mea lea ua ou iloa ai o ia o se tagata paia ona na fetalai mai ai se agelu a le Atua.", "wherefore I know he is a holy man because it was said by an angel of God."]]},
  {num:10,words:[["Ma ou te toe fai atu,", "And again,"], ["ua ou iloa ua moni mea ua ia molimau mai ai;", "I know that the things whereof he hath testified are true;"], ["aua faauta ou te fai atu ia te outou,", "for behold I say unto you,"], ["e pei ona soifua le Alii,", "that as the Lord liveth,"], ["sa faapea lava ona ia auina mai o lana agelu e faailoa mai ia te au nei mea;", "even so has he sent his angel to make these things manifest unto me;"], ["ma sa ia faia lenei mea a'o nofo le Alema lenei i lo'u fale.", "and this he has done while this Alma hath dwelt at my house."]]},
  {num:11,words:[["Aua faauta,", "For behold,"], ["ua ia faamanuiaina lo'u aiga,", "he hath blessed mine house,"], ["ua ia faamanuiaina au,", "he hath blessed me,"], ["ma o'u fafine,", "and my women,"], ["ma au fanau,", "and my children,"], ["ma lo'u tamā ma o'u aiga;", "and my father and my kinsfolk;"], ["ioe,", "yea,"], ["e oo i o'u aiga uma ua ia faamanuiaina,", "even all my kindred hath he blessed,"], ["ma ua mau i o matou luga le faamanuiaga a le Alii e tusa ma afioga na ia fetalai mai ai.", "and the blessing of the Lord hath rested upon us according to the words which he spake."]]},
  {num:12,words:[["Ma o lenei,", "And now,"], ["ina ua uma ona tautala atu e Amoleka nei upu sa amata ona taufaiofo o tagata,", "when Amulek had spoken these words the people began to be astonished,"], ["ona ua vaai ua sili atu nai le tasi le molimau o e ua molimau mai e uiga i mea ua tuuaia ai i latou,", "seeing there was more than one witness who testified of the things whereof they were accused,"], ["ma mea foi o le a oo mai,", "and also of the things which were to come,"], ["e tusa ma le agaga o valoaga sa i ai ia te i laua;", "according to the spirit of prophecy which was in them."]]},
  {num:13,words:[["E ui i lea,", "Nevertheless,"], ["sa i ai ni isi sa i totonu o i latou o e sa manatu e fesiligia i laua,", "there were some among them who thought to question them,"], ["ina ia mafai e ala ia latou togafiti popoto ona latou maua i laua ia laua upu,", "that by their cunning devices they might catch them in their words,"], ["ina ia mafai ona latou maua ai se molimau e faasaga ia te i laua,", "that they might find witness against them,"], ["ina ia mafai ona latou avatu o i laua i o latou faamasino ina ia mafai ona faamasinoina i laua e tusa ma le tulafono,", "that they might deliver them to their judges that they might be judged according to the law,"], ["ma ina ia mafai ona fasioti o i laua pe lafo i le falepuipui,", "and that they might be slain or cast into prison,"], ["e tusa ma le solitulafono e mafai ona latou faafoliga mai ua la solia pe ua molimau faasaga ia te i laua.", "according to the crime which they could make appear or witness against them."]]},
  {num:14,words:[["O lenei o i latou o alii o e na saili e faaumatia i laua,", "Now it was those men who sought to destroy them,"], ["o i latou ia o e o loia ,", "who were lawyers,"], ["o e na totogi pe na tofia e le nuu e faatautaia le tulafono i taimi o a latou faamasinoga,", "who were hired or appointed by the people to administer the law at their times of trials,"], ["po o i taimi o faamasinoga o solitulafono a tagata i luma o faamasino.", "or at the trials of the crimes of the people before the judges."]]},
  {num:15,words:[["O lenei o nei loia sa aoaoina i auala ma togafiti popoto uma a le nuu;", "Now these lawyers were learned in all the arts and cunning of the people;"], ["ma sa latou faia lenei mea ina ia mafai ai ona latou atamamai i la latou galuega.", "and this was to enable them that they might be skillful in their profession."]]},
  {num:16,words:[["Ma sa oo ina amata ona latou tuu fesili atu ia Amoleka,", "And it came to pass that they began to question Amulek,"], ["ina ia mafai ona latou faasese ana upu,", "that thereby they might make him cross his words,"], ["pe faaeseese ai upu o le a ia tautala mai ai.", "or contradict the words which he should speak."]]},
  {num:17,words:[["O lenei sa latou le iloa e mafai e Amoleka ona iloa a latou fuafuaga.", "Now they knew not that Amulek could know of their designs."], ["Ae sa oo ina o amata ona latou tuu fesili atu ia te ia,", "But it came to pass as they began to question him,"], ["sa ia iloa o latou mafaufauga,", "he perceived their thoughts,"], ["ma sa ia fai atu ia te i latou:", "and he said unto them:"], ["E, outou e le tupulaga amioleaga ma le faapiopio,", "O ye wicked and perverse generation,"], ["outou loia ma tagata pepelo,", "ye lawyers and hypocrites,"], ["ona ua outou faataatitiaina faavae a le tiapolo;", "for ye are laying the foundation of the devil;"], ["ona ua outou tataoina mailei ma togafiti e pupue ai i tagata paia o le Atua.", "for ye are laying traps and snares to catch the holy ones of God."]]},
  {num:18,words:[["Ua outou faataatitiaina fuafuaga e faapiopio ai ala o e amiotonu,", "Ye are laying plans to pervert the ways of the righteous,"], ["ma aumai ai i lalo le toasa o le Atua i luga o o outou ulu,", "and to bring down the wrath of God upon your heads,"], ["e oo ina faaumatia atoa ai lenei nuu.", "even to the utter destruction of this people."]]},
  {num:19,words:[["Ioe,", "Yea,"], ["ua tonu ona fai mai o Mosaea,", "well did Mosiah say,"], ["o lē o lo tatou tupu mulimuli,", "who was our last king,"], ["ina o le a tuu atu e ia le malo,", "when he was about to deliver up the kingdom,"], ["ina ua leai se tasi e tuu atu i ai, ma ia faatonuina ai ia pulea lenei nuu e o latou lava leo—ioe,", "having no one to confer it upon,"], ["ua tonu lava ona ia fai mai,", "causing that this people should be governed by their own voices—yea,"], ["afai e oo mai le taimi e filifili ai e le leo o lenei nuu le amioletonu,", "well did he say that if the time should come that the voice of this people should choose iniquity,"], ["o lona uiga,", "that is,"], ["afai e oo mai le taimi e pauu atu ai lenei nuu i le solitulafono,", "if the time should come that this people should fall into transgression,"], ["o le a matua i latou mo le faafanoga.", "they would be ripe for destruction."]]},
  {num:20,words:[["Ma o lenei ou te fai atu ia te outou ua tonu le faamasinoga a le Alii ia outou amioletonu;", "And now I say unto you that well doth the Lord judge of your iniquities;"], ["ua tonu le fetalai mai o ia i lenei nuu,", "well doth he cry unto this people,"], ["e ala mai i siufofoga o ana agelu :", "by the voice of his angels:"], ["Ia outou salamo,", "Repent ye,"], ["salamo ia,", "repent,"], ["ona ua lata mai le malo o le lagi.", "for the kingdom of heaven is at hand."]]},
  {num:21,words:[["Ioe,", "Yea,"], ["ua tonu le fetalai mai o ia,", "well doth he cry,"], ["e ala mai i siufofoga o ana agelu e faapea:", "by the voice of his angels that:"], ["O le a ou alu atu i lalo i totonu o o'u tagata,", "I will come down among my people,"], ["faatasi ma le fai mea tutusa ma le faamasinotonu i o'u lima.", "with equity and justice in my hands."]]},
  {num:22,words:[["Ioe,", "Yea,"], ["ma ou te fai atu ia te outou,", "and I say unto you that if it were not for the prayers of the righteous,"], ["a na leai talosaga a e amiotonu,", "who are now in the land,"], ["o e o loo i ai nei i le laueleele,", "that ye would even now be visited with utter destruction;"], ["po ua asia nei lava outou i le faafanoga atoatoa; peitai o le a lē oo mai i le lolo ,", "yet it would not be by flood,"], ["e pei ona faia i tagata i ona po o Noa,", "as were the people in the days of Noah,"], ["ae o le a oo mai i le oge,", "but it would be by famine,"], ["ma i faama'i,", "and by pestilence,"], ["ma le pelu.", "and the sword."]]},
  {num:23,words:[["Ae o talosaga a e amiotonu,", "But it is by the prayers of the righteous that ye are spared;"], ["ua faasaoina ai outou;", "now therefore,"], ["o lenei la, afai tou te tutuli ese i fafo mai totonu o outou e ua amiotonu,", "if ye will cast out the righteous from among you then will not the Lord stay his hand;"], ["ona lē taofia ai lea e le Alii lona aao;", "but in his fierce anger he will come out against you;"], ["ae o le a afio mai o ia i fafo i lona toasa tele e faasaga ia te outou;", "then ye shall be smitten by famine,"], ["ona taia ai lea o outou i le oge, ma faamai,", "and by pestilence,"], ["ma le pelu;", "and by the sword;"], ["ma ua lata mai lava le taimi vagana ai ua outou salamo.", "and the time is soon at hand except ye repent."]]},
  {num:24,words:[["Ma o lenei sa oo ina faateteleina le feita o tagata ia Amoleka,", "And now it came to pass that the people were more angry with Amulek,"], ["ma sa latou alalaga mai,", "and they cried out,"], ["fai mai:", "saying:"], ["Ua faifai le tagata lenei faasaga ia tatou tulafono ua tonu,", "This man doth revile against our laws which are just,"], ["ma a tatou loia popoto o e ua tatou filifilia.", "and our wise lawyers whom we have selected."]]},
  {num:25,words:[["Peitai sa faaloaloa atu e Amoleka lona lima,", "But Amulek stretched forth his hand,"], ["ma alaga malosi tele atu ia te i latou,", "and cried the mightier unto them,"], ["ua fai atu:", "saying:"], ["E,", "O ye wicked and perverse generation,"], ["outou e le tupulaga amioleaga ma le faapiopio, aisea ea ua maua ai e Satani se 'u'u malosi tele faapea i o outou loto? Aisea ea tou te tuu atu ai outou lava ia te ia ina ia mafai e ia ona maua o le mana i luga o outou,", "why hath Satan got such great hold upon your hearts? Why will ye yield yourselves unto him that he may have power over you,"], ["e faatauaso ai o outou mata,", "to blind your eyes,"], ["ia outou lē fia malamalama ai i upu ua tautala atu,", "that ye will not understand the words which are spoken,"], ["e tusa ma lo latou moni?", "according to their truth?"]]},
  {num:26,words:[["Aua faauta,", "For behold,"], ["ua ou molimau tetee atu ea i la outou tulafono? Ua outou lē malamalama;", "have I testified against your law? Ye do not understand;"], ["ua outou fai mai ua ou tautala tetee i la outou tulafono;", "ye say that I have spoken against your law;"], ["peitai ou te lei tautala tetee i ai,", "but I have not,"], ["ae ua ou tautala lagolago i la outou tulafono,", "but I have spoken in favor of your law,"], ["i lo outou tausalaina.", "to your condemnation."]]},
  {num:27,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["o le faavae o le faafanoga o lenei nuu ua amata ona faataatia e le amioletonu o o outou loia ma o outou faamasino.", "that the foundation of the destruction of this people is beginning to be laid by the unrighteousness of your lawyers and your judges."]]},
  {num:28,words:[["Ma o lenei sa oo ina ua uma ona tautala atu e Amoleka nei upu sa alalaga mai tagata e faasaga ia te ia,", "And now it came to pass that when Amulek had spoken these words the people cried out against him,"], ["fai mai:", "saying:"], ["O lenei ua tatou iloa nei o lenei tagata o se tama a le tiapolo,", "Now we know that this man is a child of the devil,"], ["ona ua pepelo mai o ia ia te i tatou,", "for he hath lied unto us;"], ["ona ua tautala tetee o ia i la tatou tulafono. Ma o lenei ua ia fai mai e lei tautala tetee i ai.", "for he hath spoken against our law. And now he says that he has not spoken against it."]]},
  {num:29,words:[["O lenei foi,", "And again,"], ["ua faifai o ia ia tatou loia,", "he has reviled against our lawyers,"], ["ma o tatou faamasino.", "and our judges."]]},
  {num:30,words:[["Ma sa oo ina tuu e loia i totonu o o latou loto, ia latou manatua nei mea e faasaga ia te ia.", "And it came to pass that the lawyers put it into their hearts that they should remember these things against him."]]},
  {num:31,words:[["Ma sa i ai i totonu o i latou se tasi o lona igoa o Seseroma.", "And there was one among them whose name was Zeezrom."], ["O lenei,", "Now he was the foremost to accuse Amulek and Alma,"], ["o ia lea sa tausolomua i le tuuaia o Amoleka ma Alema, ona o ia o se tasi o e sa sili ona atamamai i totonu o i latou,", "he being one of the most expert among them,"], ["ona o le tele o ana pisinisi na faia i totonu o le nuu.", "having much business to do among the people."]]},
  {num:32,words:[["O lenei o le faamoemoega o nei loia, o le maua lea o le oa;", "Now the object of these lawyers was to get gain;"], ["ma sa latou maua le oa e tusa ma a latou galuega.", "and they got gain according to their employ."]]},
];
renderVerseSet(al_ch_10_Verses, 'al-ch10-verses');

var al_ch_11_Verses = [
  {num:1,words:[["O lenei sa i ai i le tulafono a Mosaea e faapea o tagata uma taitoatasi o e sa avea ma faamasino o le tulafono,", "Now it was in the law of Mosiah that every man who was a judge of the law,"], ["po o i latou o e na tofia e avea ma faamasino,", "or those who were appointed to be judges,"], ["e tatau ona maua se totogi e tusa ma le taimi na latou galulue ai e faamasino i latou o e na aumai i o latou luma e faamasino.", "should receive wages according to the time which they labored to judge those who were brought before them to be judged."]]},
  {num:2,words:[["O lenei afai sa aitalafu se tagata i se tasi tagata,", "Now if a man owed another,"], ["ma sa ia lē fia totogi atu le mea na ia aitalafu ai,", "and he would not pay that which he did owe,"], ["sa molia o ia i le faamasino;", "he was complained of to the judge;"], ["ma sa faaaoga e le faamasino le pule,", "and the judge executed authority,"], ["ma auina atu leoleo e aumai le tagata i ona luma;", "and sent forth officers that the man should be brought before him;"], ["ma sa ia faamasinoina le tagata e tusa ma le tulafono ma faamaoniga sa aumai e faasaga ia te ia,", "and he judged the man according to the law and the evidences which were brought against him,"], ["ma sa faapea ona faamalosia o le tagata e totogi atu le mea na ia aitalafu ai,", "and thus the man was compelled to pay that which he owed,"], ["pe tafi o ia,", "or be stripped,"], ["pe tuli ese i fafo mai totonu o le nuu o se gaoi ma se faomea.", "or be cast out from among the people as a thief and a robber."]]},
  {num:3,words:[["Ma sa maua e le faamasino mo ona totogi e tusa ma lona taimi—o le senine auro mo le aso,", "And the judge received for his wages according to his time—a senine of gold for a day,"], ["po o le senuma ario,", "or a senum of silver,"], ["sa tutusa ma le senine auro;", "which is equal to a senine of gold;"], ["ma o lenei mea sa faia e tusa ma le tulafono lea na tuuina mai.", "and this is according to the law which was given."]]},
  {num:4,words:[["O lenei o igoa nei o a latou fasi auro eseese,", "Now these are the names of the different pieces of their gold,"], ["ma a latou ario,", "and of their silver,"], ["e tusa ma o latou tau. Ma o igoa sa faia lava e sa Nifaē,", "according to their value. And the names are given by the Nephites,"], ["ona sa latou lē faitau e tusa ma le ala a tagata Iutaia o e sa i Ierusalema;", "for they did not reckon after the manner of the Jews who were at Jerusalem;"], ["pe sa latou fua foi e tusa ma le ala a tagata Iutaia;", "neither did they measure after the manner of the Jews;"], ["ae sa latou sui la latou faitau ma la latou fua,", "but they altered their reckoning and their measure,"], ["e tusa ma mafaufau ma tulaga o tagata,", "according to the minds and the circumstances of the people,"], ["i tupulaga uma taitasi,", "in every generation,"], ["sei oo mai i le nofoaiga a faamasino,", "until the reign of the judges,"], ["ina ua faatutuina ia alafaitau ma alafua e le tupu o Mosaea.", "they having been established by king Mosiah."]]},
  {num:5,words:[["O lenei e faapenei le faitauga o tupe—o le senine auro,", "Now the reckoning is thus—a senine of gold,"], ["o le seone auro,", "a seon of gold,"], ["o le sume auro,", "a shum of gold,"], ["ma le limena auro.", "and a limnah of gold."]]},
  {num:6,words:[["O le senuma ario,", "A senum of silver,"], ["o le aminoa ario,", "an amnor of silver,"], ["o le eseroma ario,", "an ezrom of silver,"], ["ma le oneti ario.", "and an onti of silver."]]},
  {num:7,words:[["O le senuma ario e tutusa ma le senine auro,", "A senum of silver was equal to a senine of gold,"], ["ma o soo se tasi o ia mea e tutusa ma le fuataga e tasi o le karite,", "and either for a measure of barley,"], ["po o le fuataga foi e tasi o ituaiga eseese o saito.", "and also for a measure of every kind of grain."]]},
  {num:8,words:[["O lenei o le aofai o le seone auro e faaluaina le tau o le senine.", "Now the amount of a seon of gold was twice the value of a senine."]]},
  {num:9,words:[["Ma o le sume auro e faaluaina le tau o se seone.", "And a shum of gold was twice the value of a seon."]]},
  {num:10,words:[["Ma o le limena auro o lo latou tau uma lena.", "And a limnah of gold was the value of them all."]]},
  {num:11,words:[["Ma o le aminoa ario e tusa lona telē ma senuma e lua.", "And an amnor of silver was as great as two senums."]]},
  {num:12,words:[["Ma o le eseroma ario e tusa lona telē ma senuma e fa.", "And an ezrom of silver was as great as four senums."]]},
  {num:13,words:[["Ma o le oneti e tusa lona tau ma lo latou aofai uma.", "And an onti was as great as them all."]]},
  {num:14,words:[["O lenei o le tau lenei o a latou numera laiti i la latou faitauga—", "Now this is the value of the lesser numbers of theirreckoning—"]]},
  {num:15,words:[["O le sipelona o le afa lena o le senuma;", "A shiblon is half of a senum;"], ["o lea,", "therefore,"], ["o le sipelona mo le afa fuataga karite.", "a shiblon for half a measure of barley."]]},
  {num:16,words:[["Ma o le sipelumo o le afa lena o le sipelona.", "And a shiblum is a half of a shiblon."]]},
  {num:17,words:[["Ma o le lea o le afa lena o se sipelumo.", "And a leah is the half of a shiblum."]]},
  {num:18,words:[["O lenei o la latou numera lenei,", "Now this is their number,"], ["e tusa ma la latou faitauga.", "according to their reckoning."]]},
  {num:19,words:[["O lenei o le anetione auro e tasi e tutusa ma sipelone e tolu.", "Now an antion of gold is equal to three shiblons."]]},
  {num:20,words:[["O lenei,", "Now,"], ["sa faia lenei mea mo le faamoemoe e tasi o le mauaina o le oa,", "it was for the sole purpose to get gain,"], ["ona sa latou maua o latou totogi e tusa ma a latou galuega,", "because they received their wages according to their employ,"], ["o lea,", "therefore,"], ["sa latou faaoso ai tagata i vesiga,", "they did stir up the people to riotings,"], ["ma ituaiga uma o faasoesa ma amioleaga eseese,", "and all manner of distur– bances and wickedness,"], ["ina ia mafai ona faatele ai o a latou galuega,", "that they might have more employ,"], ["ina ia mafai ona latou maua ai tupe e tusa ma tagi sa aumai i o latou luma;", "that they might get money according to the suits which were brought before them;"], ["o lea na latou faaoso ai tagata ia tetee ia Alema ma Amoleka.", "therefore they did stir up the people against Alma and Amulek."]]},
  {num:21,words:[["Ma sa amata e Seseroma lenei ona tuu fesili mai ia Amoleka,", "And this Zeezrom began to question Amulek,"], ["fai mai:", "saying:"], ["E mafai ona e tali mai i nai fesili itiiti o le a ou fesili atu ia te oe? O lenei o Seseroma o se tagata o lē sa poto tele i ala a le tiapolo,", "Will ye answer me a few questions which I shall ask you? Now Zeezrom was a man who was expert in the devices of the devil,"], ["ina ia mafai ona ia faaumatia o mea lelei;", "that he might destroy that which was good;"], ["o lea,", "therefore,"], ["na ia fai mai ai ia Amoleka:", "he said unto Amulek:"], ["E te tali mai i fesili o le a ou tuu atu ia te oe?", "Will ye answer the questions which I shall put unto you?"]]},
  {num:22,words:[["Ma sa fai atu Amoleka ia te ia:", "And Amulek said unto him:"], ["Ioe,", "Yea,"], ["pe afai e tusa ai ma le Agaga o le Alii,", "if it be according to the Spirit of the Lord,"], ["lea o loo i totonu ia te au;", "which is in me;"], ["ona o le a ou lē fai atu se mea e lē tusa ai ma le Agaga o le Alii. Ma sa fai mai Seseroma ia te ia:", "for I shall say nothing which is contrary to the Spirit of the Lord. And Zeezrom said unto him:"], ["Faauta,", "Behold,"], ["o oneti ario nei e ono,", "here are six onties of silver,"], ["ma o nei mea uma o le a ou avatu ia te oe pe afai e te faafitia le i ai o sē Silisili.", "and all these will I give thee if thou wilt deny the existence of a Supreme Being."]]},
  {num:23,words:[["O lenei sa fai atu Amoleka:", "Now Amulek said:"], ["E, oē le tama a seoli,", "O thou child of hell,"], ["aisea ua e tofotofoina ai au? E te iloa e lē lolo atu e amiotonu i ni tofotofoga faapena?", "why tempt ye me? Knowest thou that the righteous yieldeth to no such temptations?"]]},
  {num:24,words:[["E te talitonu ea ua leai se Atua? Ou te fai atu ia te oe,", "Believest thou that there is no God? I say unto you,"], ["E leai,", "Nay,"], ["ua e iloa o loo i ai se Atua,", "thou knowest that there is a God,"], ["peitai ua sili atu lou alofa i oa nai lo o ia.", "but thou lovest that lucre more than him."]]},
  {num:25,words:[["Ma o lenei ua e pepelo mai ia te au i luma o le Atua.", "And now thou hast lied before God unto me."], ["Ua e fai mai ia te au—Faauta o oneti e ono,", "Thou saidst unto me—Behold these six onties,"], ["ua matua tele lo latou tau,", "which are of great worth,"], ["ou te avatu ia te oe—ae ua i ai i lou loto e taofi mai ia te au;", "I will give unto thee—when thou hadst it in thy heart to retain them from me;"], ["ma ua nao lou manao ia ou faafitia le Atua moni ma soifua,", "and it was only thy desire that I should  deny the true and living God,"], ["ina ia mafai ona e maua ai o se pogai e te faaumatia ai au.", "that thou mightest have cause to destroy me."], ["Ma o lenei faauta, ona o lenei mea leaga tele ua e faia,", "And now behold,"], ["o le a e maua ai lava lou taui.", "for this great evil thou shalt have thy reward."]]},
  {num:26,words:[["Ma sa fai mai Seseroma ia te ia:", "And Zeezrom said unto him:"], ["Ua e fai mai ea ua i ai se Atua moni ma soifua?", "Thou sayest there is a true and living God?"]]},
  {num:27,words:[["Ma sa fai atu Amoleka:", "And Amulek said:"], ["Ioe,", "Yea,"], ["ua i ai se Atua moni ma soifua.", "there is a true and living God."]]},
  {num:28,words:[["O lenei sa fai mai Seseroma:", "Now Zeezrom said:"], ["E sili atu ea i le tasi le Atua o i ai?", "Is there more than one God?"]]},
  {num:29,words:[["Ma sa ia tali atu,", "And he answered,"], ["E leai.", "No."]]},
  {num:30,words:[["O lenei sa toe fai mai Seseroma ia te ia:", "Now Zeezrom said unto him again:"], ["E faapefea ona e iloa o nei mea?", "How knowest thou these things?"]]},
  {num:31,words:[["Ma sa fai atu o ia:", "And he said:"], ["O se agelu na ia faaalia mai ia mea ia te au.", "An angel hath made them known unto me."]]},
  {num:32,words:[["Ma sa toe fai mai Seseroma:", "And Zeezrom said again:"], ["O ai o ia o le a afio mai? O le Alo ea o le Atua?", "Who is he that shall come? Is it the Son of God?"]]},
  {num:33,words:[["Ma sa fai atu o ia ia te ia,", "And he said unto him,"], ["Ioe.", "Yea."]]},
  {num:34,words:[["Ma sa toe fai mai Seseroma:", "And Zeezrom said again:"], ["O le a ia faaolaina ea ona tagata ia latou agasala ? Ma sa tali atu Amoleka ma fai atu ia te ia:", "Shall he save his people in their sins? And Amulek answered and said unto him:"], ["Ou te fai atu ia te oe e lē faaolaina e ia,", "I say unto you he shall not,"], ["ona e lē mafai e ia ona faafitia lana afioga.", "for it is impossible for him to deny his word."]]},
  {num:35,words:[["O lenei sa fai atu Seseroma i tagata:", "Now Zeezrom said unto the people:"], ["Vaai ia outou manatua nei mea;", "See that ye remember these things;"], ["ona ua fai mai o ia ua nao le tasi lava le Atua;", "for he said there is but one God;"], ["peitai ua ia fai mai o le a afio mai le Alo o le Atua,", "yet he saith that the Son of God shall come,"], ["ae o le a ia lē faaolaina ona tagata—e peiseai ua ia te ia le pule e faatonu ai le Atua.", "but he shall not save his people—as though he had authority to command God."]]},
  {num:36,words:[["O lenei sa toe fai atu Amoleka ia te ia:", "Now Amulek saith again unto him:"], ["Faauta ua e pepelo,", "Behold thou hast lied,"], ["ona ua e fai mai na ou tautala atu e peiseai ua ia te au le pule e faatonu ai le Atua ona sa ou fai atu o le a ia lē faaolaina ona tagata ia latou agasala.", "for thou sayest that I spake as though I had authority to command God because I said he shall not save his people in their sins."]]},
  {num:37,words:[["Ma ou te toe fai atu ia te oe,", "And I say unto you again that he cannot save them in their sins;"], ["e lē mafai ona ia faaolaina i latou ia latou agasala ;", "for I cannot deny his word,"], ["ona e lē mafai ona ou faafitia lana afioga;", "and he hath said that no unclean thing can inherit the kingdom of heaven;"], ["ma ua ia fetalai mai e lē mafai e se mea ua lē mama ona mautofi i le malo o le lagi; o lea,", "therefore,"], ["e mafai faapefea ona faaolaina oe,", "how can ye be saved,"], ["vagana ai ua e mautofi i le malo o le lagi? O lea,", "except ye inherit the kingdom of heaven? Therefore,"], ["e lē mafai ona faaolaina o oe i au agasala.", "ye cannot be saved in your sins."]]},
  {num:38,words:[["O lenei sa toe fai mai Seseroma ia te ia:", "Now Zeezrom saith again unto him:"], ["O le Atalii ea o le Atua o le Tamā Faavavau lava lea?", "Is the Son of God the very Eternal Father?"]]},
  {num:39,words:[["Ma sa fai atu Amoleka ia te ia:", "And Amulek said unto him:"], ["Ioe,", "Yea,"], ["o ia lava lea o le Tamā Faavavau o le lagi ma le lalolagi,", "he is the very Eternal Father of heaven and of earth,"], ["ma mea uma o i ai;", "and all things which in them are;"], ["o ia o le amataga ma le gataaga,", "he is the beginning and the end,"], ["o lē muamua ma lē mulimuli;", "the first and the last;"]]},
  {num:40,words:[["Ma o le a afio mai o ia i le lalolagi e togiola ona tagata;", "And he shall come into the world to redeem his people;"], ["ma o le a ia ave i ona luga solitulafono a i latou o e e talitonu i lona suafa;", "and he shall take upon him the transgressions of those who believe on his name;"], ["ma o i latou ia o e o le a latou maua le ola e faavavau,", "and these are they that shall have eternal life,"], ["ma e leai se tasi e ese mai ai e oo mai i ai le olataga.", "and salvation cometh to none else."]]},
  {num:41,words:[["O lea e tumau ai e e amioleaga e peiseai e leai se togiola na faia mo i latou,", "Therefore the wicked remain as though there had been no redemption made,"], ["vagana ai le tatalaina o fusi o le oti;", "except it be the loosing of the bands of death;"], ["aua faauta,", "for behold,"], ["e oo mai le aso e toetutu ai tagata uma mai le oti ma laulaututu i luma o le Atua,", "the day cometh that all shall rise from the dead and stand before God,"], ["ma faamasinoina e tusa ma a latou galuega.", "and be judged according to their works."]]},
  {num:42,words:[["O lenei,", "Now,"], ["ua i ai se oti ua taua o le oti faaletino;", "there is a death which is called a temporal death;"], ["ma o le maliu o Keriso o le a tatalaina fusi o lenei oti faaletino,", "and the death of Christ shall loose the bands of this temporal death,"], ["o le a faatutu mai ai tagata uma mai lenei oti faaletino.", "that all shall be raised from this temporal death."]]},
  {num:43,words:[["O le a toe faatasia le agaga ma le tino i ona foliga atoatoa;", "The spirit and the body shall be reunited again in its perfect form;"], ["o lima ma vae ma soogaoivi o le a toefuataiina i ona tulaga e tatau ai,", "both limb and joint shall be restored to its proper frame,"], ["e pei lava ona tatou i ai nei i le taimi nei;", "even as we now are at this time;"], ["ma o le a aumai i tatou e laulaututu i luma o le Atua,", "and we shall be brought to stand before God,"], ["ma le iloa e pei ona tatou iloa nei,", "knowing even as we know now,"], ["ma maua se manatua pupula o lo tatou sala atoatoa.", "and have a bright recollection of all our guilt."]]},
  {num:44,words:[["O lenei,", "Now,"], ["o lenei toefuataiga o le a oo mai i tagata uma,", "this restoration shall come to all,"], ["o e matutua ma e laiti,", "both old and young,"], ["o e pologa ma e saoloto,", "both bond and free,"], ["o tane ma fafine,", "both male and female,"], ["o e e amioleaga ma e e amiotonu;", "both the wicked and the righteous;"], ["ma e oo lava i se lauulu e tasi o o latou ulu o le a lē toesea;", "and even there shall not so much as a hair of their heads be lost;"], ["ae o le a toefuataiina mea taitasi i lona tulaga atoatoa,", "but every thing shall be restored to its perfect frame,"], ["e pei ona i ai nei,", "as it is now,"], ["po o i le tino,", "or in the body,"], ["ma o le a aumai ma molia i luma o le pa faamasino a Keriso le Atalii,", "and shall be brought and be arraigned before the bar of Christ the Son,"], ["ma le Atua le Tamā ,", "and God the Father,"], ["ma le Agaga Paia,", "and the Holy Spirit,"], ["o ni Atua Faavavau ua tasi,", "which is one Eternal God,"], ["e faamasinoina e tusa ma a latou galuega,", "to be judged according to their works,"], ["pe ua lelei pe ua leaga.", "whether they be good or whether they be evil."]]},
  {num:45,words:[["O lenei,", "Now,"], ["faauta,", "behold,"], ["ua ou tautala atu ia te outou e uiga i le oti o le tino faaletino,", "I have spoken unto you concerning the death of the mortal body,"], ["ma e uiga foi i le toetu mai o le tino faaletino. Ou te fai atu ia te outou o lenei tino faaletino e faatu mai i se tino ola pea,", "and also concerning the resurrection of the mortal body. I say unto you that this mortal body is raised to an immortal body,"], ["o lona uiga mai le oti,", "that is from death,"], ["mai le oti muamua lava i le ola,", "even from the first death unto life,"], ["e lē mafai ona toe oti i latou;", "that they can die no more;"], ["ae faatasia o latou agaga ma o latou tino,", "their spirits uniting with their bodies,"], ["e lē toe tuueseeseina;", "never to be divided;"], ["ma faapea ona avea ai le tino atoa ma tino faaleagaga ma ola pea,", "thus the whole becoming spiritual and immortal,"], ["e lē mafai ona toe oo le pala ia i latou.", "that they can no more see corruption."]]},
  {num:46,words:[["O lenei,", "Now,"], ["ina ua uma ona fai atu e Amoleka nei upu, sa toe amata ona taufaiofo o tagata,", "when Amulek had finished these words the people began again to be astonished,"], ["ma sa amata foi ona tete o Seseroma.", "and also Zeezrom began to tremble."], ["Ma sa faapea ona iu o upu a Amoleka,", "And thus ended the words of Amulek,"], ["pe ona pau ia o upu ua ou tusia.", "or this is all that I have written."]]},
];
renderVerseSet(al_ch_11_Verses, 'al-ch11-verses');

var al_ch_12_Verses = [
  {num:1,words:[["O lenei,", "Now Alma,"], ["ina ua vaai atu Alema ua lē gagana Seseroma i upu a Amoleka,", "seeing that the words of Amulek had silenced Zeezrom,"], ["ona sa ia vaai atu ua maua o ia e Amoleka i lona pepelo ma lona taufaasese e faaumatia ai o ia,", "for he beheld that Amulek had caught him in his lying and deceiving to destroy him,"], ["ma ina ua vaai atu ua amata ona tetete o ia i lalo i lona iloa o lona agasala,", "and seeing that he began to tremble under a consciousness of his guilt,"], ["sa ia tatala lona fofoga ma amata ona tautala atu ia te ia,", "he opened his mouth and began to speak unto him,"], ["ma faamautu atu upu a Amoleka,", "and to establish the words of Amulek,"], ["ma faamalamalama atu mea i tua atu,", "and to explain things beyond,"], ["pe ua tala atu tusitusiga paia i tua atu o mea na faia e Amoleka.", "or to unfold the scriptures beyond that which Amulek had done."]]},
  {num:2,words:[["O lenei o upu sa tautala atu e Alema ia Seseroma sa lagona mai e tagata sa faataamilo ane;", "Now the words that Alma spake unto Zeezrom were heard by the people round about;"], ["ona sa matua toatele le motu o tagata,", "for the multitude was great,"], ["ma sa ia tautala atu e faapea:", "and he spake on this wise:"]]},
  {num:3,words:[["O lenei Seseroma,", "Now Zeezrom,"], ["ona ua vaai ua maua oe i lou pepelo ma lou taufaasese,", "seeing that thou hast been taken in thy lying and craftiness,"], ["ona ua le nao tagata ua e pepelo i ai ae ua e pepelo foi i le Atua;", "for thou hast not lied unto men only but thou hast lied unto God;"], ["aua faauta,", "for behold,"], ["ua ia silafia ou mafaufauga uma,", "he knows all thy thoughts,"], ["ma ua e vaai ua faailoa mai ou manatu ia te i maua e lona Agaga;", "and thou seest that thy thoughts are made known unto us by his Spirit;"]]},
  {num:4,words:[["Ma ua e vaai ua ma iloa o lau fuafuaga o se fuafuaga faitogafiti tele,", "And thou seest that we know that thy plan was a very subtle plan,"], ["e tusa ai ma le faitogafiti o le tiapolo,", "as to the subtlety of the devil,"], ["e pepelo ma faasese ai lenei nuu ina ia mafai ona e faatutu mai i latou e tetee ia te i maua,", "for to lie and to deceive this people that thou mightest set them against us,"], ["e faifai mai ia te i maua ma tutuli ese i maua i fafo—", "to revile us and to cast us out—"]]},
  {num:5,words:[["O lenei o se fuafuaga lenei a lou fili ,", "Now this was a plan of thine adversary,"], ["ma ua ia faaaoga lona mana ia te oe.", "and he hath exercised his power in thee."], ["O lenei ou te manao ia e manatua o le mea ou te fai atu ai ia te oe, ou te fai atu ai i tagata uma.", "Now I would that ye should remember that what I say unto thee I say unto all."]]},
  {num:6,words:[["Ma faauta ou te fai atu ia te outou uma o lenei mea o se mailei a le fili,", "And behold I say unto you all that this was a snare of the adversary,"], ["lea ua ia tatao e pupue ai lenei nuu,", "which he has laid to catch this people,"], ["ina ia mafai ona ia aumai outou i lalo o lana pule,", "that he might bring you into subjection unto him,"], ["ina ia mafai ona ia sio faataamilo outou i ana filifili ,", "that he might encircle you about with his chains,"], ["ina ia mafai ona ia noatia outou i lalo i filifili i le faafanoga e faavavau,", "that he might chain you down to everlasting destruction,"], ["e tusa ma le mana o lana faatagataotauaina.", "according to the power of his captivity."]]},
  {num:7,words:[["O lenei ina ua uma ona tautala atu e Alema nei upu,", "Now when Alma had spoken these words,"], ["sa amata ona tetete atili tele Seseroma,", "Zeezrom began to tremble more exceedingly,"], ["ona ua ia talitonu atili i le mana a le Atua;", "for he was convinced more and more of the power of God;"], ["ma sa ia talitonu foi ua maua e Alema ma Amoleka se malamalamaaga e uiga ia te ia,", "and he was also convinced that Alma and Amulek had a knowledge of him,"], ["ona sa ia talitonu ua la iloa mafaufauga ma faamoemoega o lona loto;", "for he was convinced that they knew the thoughts and intents of his heart;"], ["ona ua tuuina mai ia te i laua le mana e mafai ai ona la iloa ia mea e tusa ai ma le agaga o valoaga.", "for power was given unto them that they might know of these things according to the spirit of prophecy."]]},
  {num:8,words:[["Ma sa amata ona fesili mai o Seseroma ia te i laua ma le filiga,", "And Zeezrom began to inquire of them diligently,"], ["ina ia mafai ona ia iloa atili e uiga i le malo o le Atua. Ma sa ia fai mai ia Alema:", "that he might know more concerning the kingdom of God. And he said unto Alma:"], ["O le a le uiga o lenei mea na fai mai ai Amoleka e uiga i le toetutu mai o e ua oti,", "What does this mean which Amulek hath spoken concerning the resurrection of the dead,"], ["e faapea o le a toetutu mai tagata uma mai le oti,", "that all shall rise from the dead,"], ["o e e amiotonu ma e e amioletonu,", "both the just and the unjust,"], ["ma aumai e tutu i luma o le Atua e faamasinoina e tusa ma a latou galuega?", "and are brought to stand before God to be judged according to their works?"]]},
  {num:9,words:[["Ma o lenei sa amata ona faamalamalama atu e Alema ia mea ia te ia,", "And now Alma began to expound these things unto him,"], ["ua fai atu:", "saying:"], ["Ua tuuina mai i le toatele ia latou iloa mealilo a le Atua;", "It is given unto many to know the mysteries of God;"], ["e ui i lea ua tuuina i latou i lalo o se poloaiga saolele ia latou lē faaali atu ia mea tau lava e tusa ai ma le vaega o lana afioga na te tuuina mai i le fanauga a tagata,", "nevertheless they are laid under a strict command that they shall not impart only according to the portion of his word which he doth grant unto the children of men,"], ["e tusa ma le gauai ma le filiga latou te tuu atu ia te ia.", "according to the heed and diligence which they give unto him."]]},
  {num:10,words:[["Ma o lea,", "And therefore,"], ["o ia o lē e faamaaa lona loto, o ia lava lea na te maua le vaega itiiti o le afioga;", "he that will harden his heart,"], ["ae o ia o lē e lē faamaaaina lona loto,", "the same receiveth the lesser portion of the word;"], ["o ia lea e tuuina mai i ai le vaega tele o le afioga,", "and he that will not harden his heart,"], ["seia oo ina tuuina mai ia te ia, ia ona iloa mealilo a le Atua,", "to him is given the greater portion of the word,"], ["seia oo ina ia iloaina atoatoa.", "until it is given unto him to know the mysteries of God until he know them in full."]]},
  {num:11,words:[["Ma o i latou o e e faamaaa o latou loto,", "And they that will harden their hearts,"], ["e tuu mai ia i latou le vaega itiiti o le afioga,", "to them is given the lesser portion of the word until they know nothing concerning his mysteries;"], ["seia oo ina latou lē iloaina se mea e uiga i ana mealilo; ma ona ave ai lea o i latou faatagataotaua e le tiapolo,", "and then they are taken captive by the devil,"], ["ma taitai atu e lona loto i lalo i le faafanoga.", "and led by his will down to destruction."], ["O lenei o le uiga lenei o upu o filifili o seoli .", "Now this is what is meant by the chains of hell."]]},
  {num:12,words:[["Ma sa tautala manino atu Amoleka e uiga i le oti ,", "And Amulek hath spoken plainly concerning death,"], ["ma le faatuina mai o lenei tino faaletino i se tulaga ola pea,", "and being raised from this mortality to a state of immortality,"], ["ma aumai i luma o le pa faamasino a le Atua,", "and being brought before the bar of God,"], ["e faamasinoina e tusa ma a tatou galuega.", "to be judged according to our works."]]},
  {num:13,words:[["Ona oo lea afai sa faamaaa o tatou loto,", "Then if our hearts have been hardened,"], ["ioe,", "yea,"], ["afai sa tatou faamaaa o tatou loto e faasaga i le afioga,", "if we have hardened our hearts against the word,"], ["ua oo ina lē maua ai i totonu o i tatou,", "insomuch that it has not been found in us,"], ["ona matua matautia ai lea o le leaga o lo tatou tulaga,", "then will our state be awful,"], ["ona o le taimi lena o le a tausalaina ai i tatou.", "for then we shall be condemned."]]},
  {num:14,words:[["Ona o a tatou upu o le a tausalaina ai i tatou,", "For our words will condemn us,"], ["ioe, o a tatou galuega uma o le a tausalaina ai i tatou;", "yea,"], ["ma o le a lē maua i tatou i le lē ponā;", "all our works will condemn us;"], ["ma o le a tausalaina foi i tatou i o tatou mafaufauga;", "we shall not be found spotless;"], ["ma i lenei tulaga leaga matautia,", "and our thoughts will also condemn us;"], ["o le a tatou lē fia vaai a'e ai i luga i lo tatou Atua; ma o le a sili ai ona tatou fiafia pe a na mafai ona tatou faatonu atu i papa ma mauga ia pauu mai i o tatou luga,", "and in this awful state we shall not dare to look up to our God;"], ["e pupuni ai i tatou mai ona luma.", "and we would fain be glad if we could command the rocks and the mountains to fall upon us to hide us from his presence."]]},
  {num:15,words:[["Ae e lē mafai ona faia o lenei mea;", "But this cannot be;"], ["e ao lava ina tatou o atu ma tutu i ona luma i lona mamalu,", "we must come forth and stand before him in his glory,"], ["ma i lona mana, ma i lona malosi,", "and in his power,"], ["silisili,", "and in his might,"], ["ma lana puleaga,", "majesty,"], ["ma tautino atu i lo tatou maasiasi e faavavau,", "and dominion,"], ["ua tonu ana faamasinoga uma;", "and acknowledge to our everlasting shame that all his judgments are just;"], ["ma ua tonu o ia i ana galuega uma, ma ua alofa mutimutivale o ia i le fanauga a tagata,", "that he is just in all his works,"], ["ma ua ia te ia le mana uma e faaolaina ai tagata taitoatasi,", "and that he is merciful unto the children of men,"], ["o e e talitonu i lona suafa ma aumai fua e tatau ai mo le salamo.", "and that he has all power to save every man that believeth on his name and bringeth forth fruit meet for repentance."]]},
  {num:16,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te fai atu ia te outou,", "I say unto you then cometh a death,"], ["ona oo mai ai lea o se oti,", "even a second death,"], ["o se oti faalua lea,", "which is a spiritual death;"], ["o se oti lea faaleagaga; o le taimi lena o soo se tasi na oti i ana agasala,", "then is a time that whosoever dieth in his sins,"], ["e faatatau i le oti faaletino,", "as to a temporal death,"], ["o le a oti foi o ia i se oti faaleagaga;", "shall also die a spiritual death;"], ["ioe,", "yea,"], ["o le a oti o ia e faatatau i mea tau i le amiotonu.", "he shall die as to things pertaining unto righteousness."]]},
  {num:17,words:[["O le taimi lena o le a tusa ai o latou mafatia e pei o se lepa afi ma le teio,", "Then is the time when their torments shall be as a lake of fire and brimstone,"], ["o lona apeafi mumū e alu a'e i luga e faavavau faavavau lava;", "whose flame ascendeth up forever and ever;"], ["ma o le taimi lena o le a noatia ai i latou i lalo i se faafanoga e faavavau,", "and then is the time that they shall be chained down to an everlasting destruction,"], ["e tusa ma le mana ma le faatagataotauaina a Satani,", "according to the power and captivity of Satan,"], ["ona ua ia pulea i latou e tusa ma lona loto.", "he having subjected them according to his will."]]},
  {num:18,words:[["O le taimi lena,", "Then,"], ["ou te fai atu ai ia te outou,", "I say unto you,"], ["o le a avea ai i latou e peiseai ua leai se togiola na faia mo i latou;", "they shall be as though there had been no redemption made;"], ["ona e lē mafai ona togiolaina i latou e tusa ai ma le faamasinotonu o le Atua;", "for they cannot be redeemed according to God's justice;"], ["ma e lē mafai ona latou toe oti ,", "and they cannot die,"], ["ona ua le toe i ai se pala.", "seeing there is no more corruption."]]},
  {num:19,words:[["O lenei sa oo ina ua uma ona tautala atu e Alema nei upu,", "Now it came to pass that when Alma had made an end of speaking these words,"], ["sa amata ona taufaiofo atili tagata;", "the people began to be more astonished;"]]},
  {num:20,words:[["Peitai sa i ai se tasi tagata e igoa ia Anetiona,", "But there was one Antionah,"], ["o lē sa avea ma pule sili i totonu o i latou,", "who was a chief ruler among them,"], ["na sau i luma ma fai mai ia te ia: O le a lenei mea na e fai mai ai,", "came forth and said unto him:"], ["o le a tu mai le tagata mai le oti ma liua mai lenei tino faaletino i se tulaga ola pea,", "What is this that thou hast said,"], ["ma e lē mafai ona oti o le agaga?", "that man should rise from the dead and be changed from this mortal to an immortal state that the soul can never die?"]]},
  {num:21,words:[["O le a le uiga o le mau,", "What does the scripture mean,"], ["lea ua faapea mai na tuu e le Atua kerupi ma se pelu afi mumū i le itu i sasae o le faatoaga o Etena ,", "which saith that God placed cherubim and a flaming sword on the east of the garden of Eden,"], ["ne'i ulu atu o tatou uluai matua ma aai i le fua o le laau o le ola,", "lest our first parents should enter and partake of the fruit of the tree of life,"], ["ma ola ai e faavavau? Ma ua faapea ona tatou vaai ai sa leai se avanoa e mafai ai ona laua ola ai e faavavau.", "and live forever? And thus we see that there was no possible chance that they should live forever."]]},
  {num:22,words:[["O lenei sa fai atu Alema ia te ia:", "Now Alma said unto him:"], ["O le mea lenei sa ou tau faamatala atu. O lenei ua tatou vaai na pau Atamu i lona ai i le fua na faasaina,", "This is the thing which I was about to explain,"], ["e tusa ma le afioga a le Atua;", "now we see that Adam did fall by the partaking of the forbidden  fruit, according to the word of God;"], ["ma ua faapea ona tatou vaai ai,", "and thus we see,"], ["o lona pau,", "that by his fall,"], ["na avea ai le fanauga uma a tagata ma tagata leiloa ma pauu.", "all mankind became a lost and fallen people."]]},
  {num:23,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te fai atu ia te outou,", "I say unto you that if it had been possible for Adam to have partaken of the fruit of the tree of life at that time,"], ["a na mafai e Atamu ona ai i le fua o le laau o le ola i le taimi lena,", "there would have been no death,"], ["po ua leai se oti, ma po ua noa le afioga,", "and the word would have been void,"], ["ma avea ai le Atua o se pepelo,", "making God a liar,"], ["ona sa fetalai o ia:", "for he said:"], ["Afai e te ai o le a e oti moni lava.", "If thou eat thou shalt surely die."]]},
  {num:24,words:[["Ma ua tatou vaai ua oo mai le oti i le fanauga uma tagata,", "And we see that death comes upon mankind,"], ["ioe,", "yea,"], ["le oti lea na tautala i ai Amoleka,", "the death which has been spoken of by Amulek,"], ["o le oti lea faaletino;", "which is the temporal death;"], ["e ui i lea sa i ai se avanoa na tuu mai i le tagata e mafai ai ona ia salamo; o lea ua avea ai le olaga lenei ma tulaga nofovaavaai;", "neverthe– less there was a space granted unto man in which he might repent;"], ["o se taimi e saunia ai e fetaiai ma le Atua;", "therefore this life became a probationary state;"], ["o se taimi e saunia ai mo lena olaga e lē gata,", "a time to prepare to meet God;"], ["lea na ma tautatala atu ai,", "a time to prepare for that endless state which has been spoken of by us,"], ["lea pe a mavae atu le toetutu mai o e ua oti.", "which is after the resurrection of the dead."]]},
  {num:25,words:[["O lenei,", "Now,"], ["a na leai le fuafuaga o le togiolaina,", "if it had not been for the plan of redemption,"], ["lea na faataatia mai le faavaega o le lalolagi,", "which was laid from the foundation of the world,"], ["po ua lē mafai ona i ai o se toetutu mai o e ua oti;", "there could have been no resurrection of the dead;"], ["peitai sa i ai se fuafuaga o le togiolaina na faataatia,", "but there was a plan of redemption laid,"], ["lea o le a faataunuu ai le toetutu mai o e ua oti,", "which shall bring to pass the resurrection of the dead,"], ["lea sa tautalagia.", "of which has been spoken."]]},
  {num:26,words:[["Ma o lenei faauta,", "And now behold,"], ["a na mafai ona o atu o tatou uluai matua ma aai i le fua o le laau o le ola,", "if it were possible that our first parents could have gone forth and partaken of the tree of life they would have been forever miserable,"], ["po ua pagatia i laua e faavavau, ua aunoa ma se olaga sauniuni;", "having no preparatory state;"], ["ma faapea ona semanu ua lē taulau ai le fuafuaga o le togiolaina,", "and thus the plan of redemption would have been frustrated,"], ["ma po ua noa ai le afioga a le Atua,", "and the word of God would have been void,"], ["ua leai se aoga.", "taking none effect."]]},
  {num:27,words:[["Peitai faauta,", "But behold,"], ["sa lē faapea;", "it was not so;"], ["ae na tofia i tagata e ao ina oti i latou;", "but it was appointed unto men that they must die;"], ["ma a mavae le oti,", "and after death,"], ["e ao ina latou o atu i le faamasinoga ,", "they must come to judgment,"], ["le faamasinoga lava lea na ma tautatala atu ai,", "even that same judgment of which we have spoken,"], ["o le iuga lea.", "which is the end."]]},
  {num:28,words:[["Ma ina ua uma ona tofia e le Atua ia oo mai nei mea i le tagata,", "And after God had appointed that these things should come unto man,"], ["faauta,", "behold,"], ["sa ia silafia e tatau ona iloa e le tagata e uiga i mea ua ia tofia mo i latou;", "then he saw that it was expedient that man should know concerning the things whereof he had appointed unto them;"]]},
  {num:29,words:[["O lea na ia auina mai ai agelu e fetautalatalaai ma i latou,", "Therefore he sent angels to converse with them,"], ["o e na faia ia vaai tagata i lona mamalu.", "who caused men to behold of his glory."]]},
  {num:30,words:[["Ma sa amata mai i le taimi lena e oo mai i luma,", "And they began from that time forth to call on his name;"], ["ona latou valaau atu i lona suafa; o lea na fetautalatalaai ai le Atua ma tagata,", "therefore God conversed with men,"], ["ma faaali mai ia te i latou le fuafuaga o le togiolaina,", "and made known unto them the plan of redemption,"], ["lea na saunia mai le faavaega o le lalolagi; ma sa ia faaali mai lenei mea ia te i latou,", "which had been prepared from the foundation of the world;"], ["e tusa ma lo latou faatuatua ma le salamo ma a latou galuega paia.", "and this he made known unto them according to their faith and repentance and their holy works."]]},
  {num:31,words:[["O le mea lea,", "Wherefore,"], ["na ia tuuina mai ai poloaiga i tagata,", "he gave commandments unto men,"], ["ona ua latou muamua soli poloaiga muamua e faatatau i mea faaletino,", "they having first transgressed the first commandments as to things which were temporal,"], ["ma avea ai e pei o ni atua,", "and becoming as Gods,"], ["i le iloa o le lelei mai le leaga,", "knowing good from evil,"], ["ma tuu ai i latou lava i se tulaga e gaioi ai,", "placing themselves in a state to act,"], ["pe tuu ai i se tulaga e gaioi ai e tusa ai ma o latou loto ma filifiliga,", "or being placed in a state to act according to their wills and pleasures,"], ["pe fai le leaga pe fai le lelei—", "whether to do evil or to do good—"]]},
  {num:32,words:[["O lea na tuu mai ai e le Atua poloaiga ia te i latou,", "Therefore God gave unto them commandments,"], ["ina ua uma ona ia faaali mai ia te i latou le fuafuaga o le togiolaina,", "after having made known unto them the plan of redemption,"], ["ia latou lē faia le leaga,", "that they should not do evil,"], ["o lona faasalaga o le oti lona lua lea,", "the penalty thereof being a second death,"], ["o se oti lea ua faavavau e faatatau i mea tau i le amiotonu;", "which was an everlasting death as to things pertaining unto righteousness;"], ["ona o tagata faapena e lē mafai ona i ai se mana o le fuafuaga o le togiolaina i ai,", "for on such the plan of redemption could have no power,"], ["ona e lē mafai ona faaumatiaina galuega a le faamasinotonu ,", "for the works of justice could not be destroyed,"], ["e tusa ma le agalelei silisili o le Atua.", "according to the supreme goodness of God."]]},
  {num:33,words:[["Peitai ua fetalai mai le Atua i tagata,", "But God did call on men,"], ["i le suafa o lona Atalii,", "in the name of his Son,"], ["(ona o le fuafuaga lenei o le togiolaina sa faataatia) ua fetalai mai:", "(this being the plan of redemption which was laid) saying:"], ["Afai tou te salamo ma lē faamaaaina o outou loto,", "If ye will repent and harden not your hearts,"], ["ona ou alofa mutimutivale atu ai lea i luga o outou,", "then will I have mercy upon you,"], ["e ala i lou Atalii e Toatasi na Fanaua;", "through mine Only Begotten Son;"]]},
  {num:34,words:[["O lea,", "Therefore,"], ["ai soo se tasi e salamo,", "whosoever repenteth,"], ["ma lē faamaaaina lona loto,", "and hardeneth not his heart,"], ["o le a ia te ia le aia i le alofa mutimutivale e ala atu i lou Atalii e Toatasi na Fanaua,", "he shall have claim on mercy through mine Only Begotten Son,"], ["mo se faamagaloga o ana agasala;", "unto a remission of his sins;"], ["ma o i latou ia o le a ulufale mai i lo'u malologa .", "and these shall enter into my rest."]]},
  {num:35,words:[["Ma ai se tasi e faamaaa lona loto ma faia le amioletonu,", "And whosoever will harden his heart and will do iniquity,"], ["faauta, ou te tauto atu i lo'u ita,", "behold,"], ["e lē ulufale mai lava o ia i lo'u malologa.", "I swear in my wrath that he shall not enter into my rest."]]},
  {num:36,words:[["Ma o lenei,", "And now,"], ["ou uso e,", "my brethren,"], ["faauta ou te fai atu ia te outou, afai tou te faamaaa o outou loto,", "behold I say unto you,"], ["tou te lē ulufale atu lava i le malologa o le Alii;", "that if ye will harden your hearts ye shall not enter into the rest of the Lord;"], ["o lea o lo outou amioletonu o le a faaoso ai o ia e auina mai i lalo lona toasa i o outou luga,", "therefore your iniquity provoketh him that he sendeth down his wrath upon you as in the first provocation,"], ["e pei o le taimi o le faa'ono'ono muamua,", "yea,"], ["ioe,", "according to his word in the last provocation as well as the first,"], ["e tusa ma lana fetalaiga i le faa'ono'ono mulimuli e pei lava o le muamua,", "to the everlasting destruction of your souls;"], ["i le faaumatiaga e faavavau o o outou agaga;", "therefore,"], ["o lea, e tusa ma lana fetalaiga,", "according to his word,"], ["i le oti mulimuli,", "unto the last death,"], ["e pei foi i le oti muamua.", "as well as the first."]]},
  {num:37,words:[["Ma o lenei,", "And now,"], ["ou uso e,", "my brethren,"], ["ona ua vaai ua tatou iloa nei mea,", "seeing we know these things,"], ["ma ua moni i latou,", "and they are true,"], ["ia tatou salamo, ma aua le faamaaaina o tatou loto,", "let us repent,"], ["ina ia tatou lē faaoso ai le Alii lo tatou Atua e to mai i lalo i o tatou luga lona toasa,", "and harden not our hearts,"], ["i le lona lua lenei o ana poloaiga ua ia tuuina mai ia te i tatou;", "that we provoke not the Lord our God to pull down his wrath upon us in these his second commandments which he has given unto us;"], ["ae ia tatou ulu atu i le malologa o le Atua,", "but let us enter into the rest of God,"], ["lea ua saunia mai e tusa ma lana fetalaiga.", "which is prepared according to his word."]]},
];
renderVerseSet(al_ch_12_Verses, 'al-ch12-verses');

var al_ch_13_Verses = [
  {num:1,words:[["Ma ou te toe fai atu,", "And again,"], ["ou uso e,", "my brethren,"], ["ou te fia sii o outou mafaufau i luma i le taimi na tuu mai ai e le Alii le Atua nei poloaiga i ana fanau;", "I would cite your minds forward to the time when the Lord God gave these commandments unto his children;"], ["ma ou te manao ia outou manatua na faauu e le Alii le Atua o faitaulaga,", "and I would that ye should remember that the Lord God ordained priests,"], ["e tusa ma lana faatulagaga paia,", "after his holy order,"], ["lea na tusa ma le faatulagaga a lona Alo,", "which was after the order of his Son,"], ["e aoao atu nei mea i tagata.", "to teach these things unto the people."]]},
  {num:2,words:[["Ma o na faitaulaga sa faauuina e tusa ma le faatulagaga a lona Alo,", "And those priests were ordained after the order of his Son,"], ["i se auala e mafai ai e tagata ona iloa le ala latou te tepa taulai ai i luma i lona Alo mo le togiolaina.", "in a manner that thereby the people might know in what manner to look forward to his Son for redemption."]]},
  {num:3,words:[["Ma o le ala lenei sa faauuina ai i latou—sa valaauina ma saunia i latou mai le faavaega o le lalolagi e tusa ma le muai silafia o le Atua,", "And this is the manner after which they were ordained—being called and prepared from the foundation of the world according to the foreknowledge of God,"], ["ona o lo latou faatuatua tele ma a latou galuega lelei;", "on account of their exceeding faith and good works;"], ["o le mea muamua i le tuuina atu o i latou e filifili i le lelei po o le leaga;", "in the first place being left to choose good or evil;"], ["o lea ona sa latou filifili le lelei,", "therefore they having chosen good,"], ["ma faaaoga le faatuatua tele nauā,", "and exercising  exceedingly great faith, are called with a holy calling,"], ["ua valaauina ai i latou i se valaauga paia,", "yea,"], ["ioe,", "with that holy calling which was prepared with,"], ["i lena valaauga paia lea na saunia faatasi,", "and according to,"], ["ma e tusa ma se togiolaina sauniuni mo e faapena.", "a preparatory redemption for such."]]},
  {num:4,words:[["Ma sa faapea ona valaauina i latou i lenei valaauga paia ona o lo latou faatuatua,", "And thus they have been called to this holy calling on account of their faith,"], ["a'o isi sa latou teena le Agaga o le Atua ona o le maaa o o latou loto ma le tauaso o o latou mafaufau,", "while others would reject the Spirit of God on account of the hardness of their hearts and blindness of their minds,"], ["ae, a na leai lenei mea,", "while,"], ["po ua mafai foi ona latou maua se avanoa tele faapea e pei o o latou uso.", "if it had not been for this they might have had as great privilege as their brethren."]]},
  {num:5,words:[["Po o i se aotelega,", "Or in fine,"], ["o le mea muamua sa i ai i latou i le tulaga e tasi faatasi ma o latou uso;", "in the first place they were on the same standing with their brethren;"], ["o lea o lenei valaauga paia na saunia mai le faavaega o le lalolagi mo i latou faapea, o e e lē faamaaaina o latou loto,", "thus this holy calling being prepared from the foundation of the world for such as would not harden their hearts,"], ["ua i ai ma ala mai i le togiola a le Alo e Toatasi na Fanaua,", "being in and through the atonement of the Only Begotten Son,"], ["o lē na saunia—", "who was prepared—"]]},
  {num:6,words:[["Ma sa faapea ona valaauina i latou i lenei valaauga paia,", "And thus being called by this holy calling,"], ["ma faauuina i latou i le perisitua maualuga o le faatulagaga paia a le Atua,", "and ordained unto the high priesthood of the holy order of God,"], ["e aoao atu ana poloaiga i le fanauga a tagata,", "to teach his commandments unto the children of men,"], ["ina ia mafai foi ona latou ulu atu i lona malologa —", "that they also might enter into his rest—"]]},
  {num:7,words:[["O lenei perisitua maualuga ua tusa ma le faatulagaga a lona Alo,", "This high priesthood being after the order of his Son,"], ["o le faatulagaga lea sa i ai mai le faavaega o le lalolagi;", "which order was from the foundation of the world;"], ["po o i ni isi upu,", "or in other words,"], ["ua leai se amataga o ona aso po o se gataaga o ona tausaga,", "being without beginning of days or end of years,"], ["ona ua saunia mai le vavau e oo i le faavavau atoa,", "being prepared from eternity to all eternity,"], ["e tusa ma lona muai silafia o mea uma—", "according to his foreknowledge of all things—"]]},
  {num:8,words:[["O lenei sa faauuina i latou e tusa ma le ala lenei—sa valaauina i latou i se valaauga paia,", "Now they were ordained after this manner—being called with a holy calling,"], ["ma faauuina i se sauniga paia,", "and ordained with a holy ordinance,"], ["ma latou ave ai i o latou luga le perisitua maualuga o le faatulagaga paia,", "and taking upon them the high priesthood of the holy order,"], ["o lea valaauga,", "which calling,"], ["ma le sauniga,", "and ordinance,"], ["ma le perisitua maualuga,", "and high priesthood,"], ["ua leai sona amataga po o sona gataaga—", "is without beginning or end—"]]},
  {num:9,words:[["Ua faapea ona avea ai i latou ma faitaulaga sili e faavavau,", "Thus they become high priests forever,"], ["e tusa ma le faatulagaga a le Alo,", "after the order of the Son,"], ["o le Toatasi na Fanaua e le Tamā,", "the Only Begotten of the Father,"], ["o lē ua leai se amataga o ona aso po o se gataaga o ona tausaga,", "who is without beginning of days or end of years,"], ["o lē ua tumu i le alofa tunoa,", "who is full of grace,"], ["fai mea tutusa,", "equity,"], ["ma le upumoni. Ma ua faapea lava. Amene.", "and truth. And thus it is. Amen."]]},
  {num:10,words:[["O lenei,", "Now,"], ["e pei ona ou fai atu e uiga i le faatulagaga paia,", "as I said concerning the holy order,"], ["po o lenei perisitua maualuga,", "or this high priesthood,"], ["e toatele i latou o e sa faauuina ma avea ma faitaulaga sili a le Atua;", "there were many who were ordained and became high priests of God;"], ["ma sa faauuina i latou i lenei tofi ona o lo latou faatuatua tele ma lo latou salamo ,", "and it was on account of their exceeding faith and repentance,"], ["ma lo latou amiotonu i luma o le Atua,", "and their righteousness before God,"], ["ona sa latou filifili e salamo ma fai le amiotonu nai lo le fano;", "they choosing to repent and work righteousness rather than to perish;"]]},
  {num:11,words:[["O lea na valaauina ai i latou i lenei faatulagaga paia,", "Therefore they were called after this holy order,"], ["ma faapaiaina i latou,", "and were sanctified,"], ["ma sa tatā sinasina o latou ofu e ala i le toto o le Tamai Mamoe.", "and their garments were washed white through the blood of the Lamb."]]},
  {num:12,words:[["O lenei o i latou,", "Now they,"], ["ina ua uma ona faapaiaina e le Agaga Paia,", "after being sanctified by the Holy Ghost,"], ["ina ua faasinasinaina o latou ofu,", "having their garments made white,"], ["ua mama ma ua lē pisipisia i luma o le Atua,", "being pure and spotless before God,"], ["sa lē mafai ona latou vaai atu i le agasala e aunoa ma le inoino i ai;", "could not look upon sin save it were with abhorrence;"], ["ma sa i ai le toatele,", "and there were many,"], ["sa matua toatele lava,", "exceedingly great many,"], ["o e sa faamamāina ma ulu atu i le malologa o le Alii lo latou Atua.", "who were made pure and entered into the rest of the Lord their God."]]},
  {num:13,words:[["Ma o lenei,", "And now,"], ["ou uso e,", "my brethren,"], ["ou te manao ia outou faalotomaualalalo outou lava i luma o le Atua,", "I would that ye should humble yourselves before God,"], ["ma aumai fua e tatau ai mo le salamo,", "and bring forth fruit meet for repentance,"], ["ina ia mafai foi ona outou ulu atu i lena malologa.", "that ye may also enter into that rest."]]},
  {num:14,words:[["Ioe,", "Yea,"], ["ia outou faamaualalalo outou lava e pei o tagata i ona po o Mekisateko ,", "humble yourselves even as the people in the days of Melchizedek,"], ["o lē foi sa avea o se faitaulaga sili e tusa ma lenei lava faatulagaga paia na ou tautala atu ai,", "who was also a high priest after this same order which I have spoken,"], ["o lē foi sa ia ave i ona luga le perisitua maualuga e faavavau.", "who also took upon him the high priesthood forever."]]},
  {num:15,words:[["Ma o Mekisateko lava lenei na totogi atu i ai e Aperaamo o sefuluai ;", "And it was this same Melchizedek to whom Abraham paid tithes;"], ["ioe,", "yea,"], ["e oo i lo tatou tamā o Aperaamo sa ia totogi sefuluai o le tasi vaesefulu o mea uma na ia maua.", "even our father Abraham paid tithes of one– tenth part of all he possessed."]]},
  {num:16,words:[["O lenei o nei sauniga sa tuuina mai e tusa ma lenei ala,", "Now these ordinances were given after this manner,"], ["ina ia mafai ai e tagata ona tepa taulai i luma i le Alo o le Atua,", "that thereby the people might look forward on the Son of God,"], ["o se faatusa lea o lana faatulagaga,", "it being a type of his order,"], ["po o lana faatulagaga lava lea,", "or it being his order,"], ["ma sa faia lenei mea ina ia mafai ona latou tepa taulai atu ai i luma ia te ia mo se faamagaloga o a latou agasala,", "and this that they might look forward to him for a remission of their sins,"], ["ina ia mafai ona latou ulu atu i le malologa o le Alii.", "that they might enter into the rest of the Lord."]]},
  {num:17,words:[["O lenei o Mekisateko lenei sa avea o se tupu i le laueleele o Salema;", "Now this Melchizedek was a king over the land of Salem;"], ["ma sa faasolo malolosi ona tagata i le faia o le amioletonu ma mea inosia;", "and his people had waxed strong in iniquity and abomination;"], ["ioe,", "yea,"], ["sa latou se ese uma;", "they had all gone astray;"], ["sa tumu i latou i ituaiga uma o amioleaga eseese;", "they were full of all manner of wickedness;"]]},
  {num:18,words:[["Peitai ona sa faaaoga e Mekisateko le faatuatua tele,", "But Melchizedek having exercised mighty faith,"], ["ma ia maua le tofi o le perisitua maualuga e tusa ma le faatulagaga paia a le Atua,", "and received the office of the high priesthood according to the holy order of God,"], ["sa ia talai atu ai le salamo i ona tagata. Ma faauta,", "did preach repentance unto his people. And behold,"], ["sa latou salamo;", "they did repent;"], ["ma sa faatu e Mekisateko le filemu i le laueleele i ona aso;", "and Melchizedek did establish peace in the land in his days;"], ["o lea na taua ai o ia o le aloalii o le filemu,", "therefore he was called the prince of peace,"], ["ona o ia sa avea ma tupu o Salema;", "for he was the king of Salem;"], ["ma sa nofotupu o ia i lalo o lona tamā.", "and he did reign under his father."]]},
  {num:19,words:[["O lenei,", "Now,"], ["e toatele sa i luma atu o ia,", "there were many before him,"], ["ma e toatele foi sa i tua mai o ia,", "and also there were many afterwards,"], ["peitai e leai se tasi na sili atu ia te ia;", "but none were greater;"], ["o lea,", "therefore,"], ["ua latou taua faapitoa mai ai lava o ia.", "of him they have more particularly made mention."]]},
  {num:20,words:[["O lenei e lē manaomia ona ou faamatala tele atu le mataupu;", "Now I need not rehearse the matter;"], ["atonu ua lava mea ua ou fai atu ai. Faauta,", "what I have said may suffice. Behold,"], ["ua i ai i o outou luma tusitusiga paia;", "the scriptures are before you;"], ["afai tou te femilosaiina i latou o le a avea ma o outou lava faaumatiaga.", "if ye will wrest them it shall be to your own destruction."]]},
  {num:21,words:[["Ma o lenei sa oo ina ua uma ona fai atu e Alema o nei upu ia te i latou,", "And now it came to pass that when Alma had said these words unto them,"], ["sa ia faaloaloa atu lona lima ia te i latou ma alaga atu ma le leo tele,", "he stretched forth his hand unto them and cried with a mighty voice,"], ["ua fai atu:", "saying:"], ["O le taimi lenei e salamo ai,", "Now is the time to repent,"], ["ona ua latalata mai le aso o le olataga;", "for the day of salvation draweth nigh;"]]},
  {num:22,words:[["Ioe,", "Yea,"], ["ma o le siufofoga o le Alii,", "and the voice of the Lord,"], ["e ala i fofoga o agelu,", "by the mouth of angels,"], ["ua alagaina atu lenei mea i atunuu uma;", "doth declare it unto all nations;"], ["ioe,", "yea,"], ["ua latou alagaina atu,", "doth declare it,"], ["ina ia mafai ona latou maua tala fiafia o le olioli tele;", "that they may have glad tidings of great joy;"], ["ioe,", "yea,"], ["ma ua ia logo atu nei tala fiafia i totonu o ona tagata uma,", "and he doth sound these glad tidings among all his people,"], ["ioe,", "yea,"], ["e oo lava ia i latou o e ua faataapeapeina i luga o le lalolagi;", "even to them that are scattered abroad upon the face of the earth;"], ["o le mea lea ua oo mai ai nei tala fiafia ia te i tatou.", "wherefore they have come unto us."]]},
  {num:23,words:[["Ma ua faailoa mai nei tala fiafia ia i tatou i upu manino,", "And they are made known unto us in plain terms,"], ["ina ia mafai ona tatou malamalama,", "that we may understand,"], ["e lē mafai ona tatou sese;", "that we cannot err;"], ["ma ua faia lenei mea ona o le avea o i tatou ma tagata maumausolo i se laueleele ese;", "and this because of our being wanderers in a strange land;"], ["o lea,", "therefore,"], ["ua faapea ona matua faapitoa ai lava o i tatou,", "we are thus highly favored,"], ["ona ua alaga mai ia i tatou nei tala fiafia i vaega uma o lo tatou tovine.", "for we have these glad tidings declared unto us in all parts of our vineyard."]]},
  {num:24,words:[["Aua faauta,", "For behold,"], ["o loo alaga atu e agelu lenei mea i le toatele i le taimi nei i lo tatou laueleele;", "angels are declaring it unto many at this time in our land;"], ["ma ua faia lenei mea mo le faamoemoe o le sauniaina o loto o le fanauga a tagata e talia lana afioga i le taimi o lona afio mai i lona mamalu.", "and this is for the purpose of preparing the hearts of the children of men to receive his word at the time of his coming in his glory."]]},
  {num:25,words:[["Ma o lenei ua nao na tatou talitali e faalologo i tala fiafia e alaga mai ia i tatou e fofoga o agelu,", "And now we only wait to hear the joyful news declared unto us by the mouth of angels,"], ["e uiga i lona afio mai;", "of his coming;"], ["ona e oo mai le taimi,", "for the time cometh,"], ["tatou te lē iloa po o le a le vave mai. Ou te moomoo i le Atua ma'umau pe a na oo mai i o'u aso;", "we know not how soon. Would to God that it might be in my day;"], ["peitai ia tuu ia pe vave mai pe tuai mai,", "but let it be sooner or later,"], ["ae o le a ou olioli i ai.", "in it I will rejoice."]]},
  {num:26,words:[["Ma o le a faaalia ia mea i tagata amiotonu ma paia,", "And it shall be made known unto just and holy men,"], ["e fofoga o agelu,", "by the mouth of angels,"], ["i le taimi o lona afio mai,", "at the time of his coming,"], ["ina ia mafai ona faataunuuina upu a o tatou tamā,", "that the words of our fathers may be fulfilled,"], ["e tusa ma mea na latou fofogaina e uiga ia te ia,", "according to that which they have spoken concerning him,"], ["e tusa ai ma le agaga o valoaga sa ia te i latou.", "which was according to the spirit of prophecy which was in them."]]},
  {num:27,words:[["Ma o lenei,", "And now,"], ["ou uso e,", "my brethren,"], ["ou te moomoo mai le vaega totonugalemu o lo'u loto,", "I wish from the inmost part of my heart,"], ["ioe,", "yea,"], ["ma le atuatuvale tele e oo lava i le tiga,", "with great anxiety even unto pain,"], ["ina ia outou faalogo mai i au upu,", "that ye would hearken unto my words,"], ["ma lafo ese a outou agasala,", "and cast off your sins,"], ["ma aua le faatuatuai le aso o lo outou salamo;", "and not procrastinate the day of your repentance;"]]},
  {num:28,words:[["Ae ia outou faamaualalalo outou lava i luma o le Alii,", "But that ye would humble yourselves before the Lord,"], ["ma valaau atu i lona suafa paia,", "and call on his holy name,"], ["ma mataala ma tatalo e lē aunoa,", "and watch and pray continually,"], ["ina ia lē faaosoosoina outou i luga atu o le mea e mafai ona outou lavatia,", "that ye may not be tempted above that which ye can bear,"], ["ma faapea ona taitaiina ai outou e le Agaga Paia,", "and thus be led by the Holy Spirit,"], ["ma lotomaualalalo ai,", "becoming humble,"], ["agamalu ,", "meek,"], ["agamalolo,", "submissive,"], ["onosai,", "patient,"], ["tumu i le alofa ma le tali-tiga atoa;", "full of love and all long– suffering;"]]},
  {num:29,words:[["Ua faatuatua i le Alii;", "Having faith on the Lord;"], ["ua i ai se faamoemoe o le a outou maua le ola e faavavau;", "having a hope that ye shall receive eternal life;"], ["ua i ai le alofa o le Atua e le aunoa i o outou loto,", "having the love of God always in your hearts,"], ["ina ia mafai ona sii a'e outou i luga i le aso mulimuli ma ulu atu i lona malologa .", "that ye may be lifted up at the last day and enter into his rest."]]},
  {num:30,words:[["Ma tau ina ia tuuina mai e le Alii ia te outou le salamo,", "And may the Lord grant unto you repentance,"], ["ina ia outou le aumai i lalo i o outou luga lona toasa,", "that ye may not bring down his wrath upon you,"], ["ina ia le noatia outou i lalo i filifili a seoli ,", "that ye may not be bound down by the chains of hell,"], ["ina ia outou le mafatia i le oti faalua.", "that ye may not suffer the second death."]]},
  {num:31,words:[["Ma e tele atu lava upu sa tautala atu ai Alema i tagata,", "And Alma spake many more words unto the people,"], ["ia ua le tusia i lenei tusi.", "which are not written in this book."]]},
];
renderVerseSet(al_ch_13_Verses, 'al-ch13-verses');

var al_ch_14_Verses = [
  {num:1,words:[["Ma sa oo ina ua uma ona ia faaiu o lona tautala atu i tagata,", "And it came to pass after he had made an end of speaking unto the people many of them did believe on his words,"], ["sa toatele i latou sa talitonu i ana upu, ma amata ona salamo,", "and began to repent,"], ["ma suesue i tusitusiga paia.", "and to search the scriptures."]]},
  {num:2,words:[["Peitai o le vaega toatele atu o i latou,", "But the more part of them were desirous that they might destroy Alma and Amulek;"], ["sa mananao ia mafai ona latou fasioti ia Alema ma Amoleka;", "for they were angry with Alma,"], ["ona sa latou feita ia Alema, ona o le tuusa'o atu o ana upu ia Seseroma;", "because of the plainness of his words unto Zeezrom;"], ["ma sa latou fai mai foi ua pepelo atu Amoleka ia te i latou,", "and they also said that Amulek had lied unto them,"], ["ma ua ia faifai e faasaga i la latou tulafono ma faasaga foi ia latou loia ma faamasino.", "and had reviled against their law and also against their lawyers and judges."]]},
  {num:3,words:[["Ma sa latou feita foi ia Alema ma Amoleka;", "And they were also angry with Alma and Amulek;"], ["ma talu ai ona sa laua molimau manino atu e faasaga ia latou amioleaga,", "and because they had testified so plainly against their wickedness,"], ["sa latou saili e fasioti faalilolilo i laua.", "they sought to put them away privily."]]},
  {num:4,words:[["Peitai sa oo ina latou le faia;", "But it came to pass that they did not;"], ["ae sa latou ave i laua ma ua saisai ia te i laua i maea malolosi,", "but they took them and bound them with strong cords,"], ["ma ave i laua i luma o le faamasino sili o le laueleele.", "and took them before the chief judge of the land."]]},
  {num:5,words:[["Ma sa o atu tagata ma molimau faasaga ia te i laua—ua molimau atu e faapea ua laua faifai e faasaga i le tulafono,", "And the people went forth and witnessed against them—testifying that they had reviled against the law,"], ["ma o latou loia ma faamasino o le laueleele,", "and their lawyers and judges of the land,"], ["ma tagata uma foi sa i le laueleele;", "and also of all the people that were in the land;"], ["ma e faapea sa laua molimau mai foi ua nao le tasi le Atua o i ai,", "and also testified that here was but one God,"], ["ma e faapea o le a ia auina mai lona Alo i totonu o tagata,", "and that he should send his Son among the people,"], ["ae o le a ia le faaolaina i latou;", "but he should not save them;"], ["ma le tele o mea faapena sa molimau atu ai tagata e faasaga ia Alema ma Amoleka. O lenei sa faia lenei mea i luma o le faamasino sili o le laueleele.", "and many such things did the people testify against Alma and Amulek. Now this was done before the chief judge of the land."]]},
  {num:6,words:[["Ma sa oo ina meia Seseroma i upu sa tautalaina;", "And it came to pass that Zeezrom was astonished at the words which had been spoken;"], ["ma sa ia iloa foi e uiga i le faatauasoina o mafaufau,", "and he also knew concerning the blindness of the minds,"], ["lea na ia faatupuina i totonu o tagata i ana upu pepelo;", "which he had caused among the people by his lying words;"], ["ma sa amata ona atuatuvale a'e lona agaga i lona iloa o lona lava agasala;", "and his soul began to be harrowed up under a consciousness of his own guilt;"], ["ioe,", "yea,"], ["sa amata ona siomia o ia i tiga o seoli.", "he began to be encircled about by the pains of hell."]]},
  {num:7,words:[["Ma sa oo ina amata ona ia tagi atu i tagata,", "And it came to pass that he began to cry unto the people,"], ["ua fai atu:", "saying:"], ["Faauta,", "Behold,"], ["ua ou sala ,", "I am guilty,"], ["ma o nei alii ua le ponā i laua i luma o le Atua. Ma sa amata ona ia aioi atu mo i laua mai i le taimi lena;", "and these men are spotless before God. And he began to plead for them from that time forth;"], ["peitai sa latou faifai ia te ia,", "but they reviled him,"], ["fai mai:", "saying:"], ["Pe ua ulutinoina foi oe e le tiapolo? Ma sa latou tuufeanu ia te ia,", "Art thou also possessed with the devil? And they spit upon him,"], ["ma tuli ese o ia mai totonu o i latou,", "and cast him out from among them,"], ["ma i latou uma foi o e na talitonu i upu na tautatala atu ai Alema ma Amoleka;", "and also all those who believed in the words which had been spoken by Alma and Amulek;"], ["ma sa latou tutuli ese i latou i fafo,", "and they cast them out,"], ["ma auina mai tagata e fetogi i latou i maa.", "and sent men to cast stones at them."]]},
  {num:8,words:[["Ma sa latou aumai faatasi a latou ava ma fanau,", "And they brought their wives and children together,"], ["ma o soo se tasi sa talitonu pe sa aoaoina ia talitonu i le afioga a le Atua,", "and whosoever believed or had been taught to believe in the word of God they caused that they should be cast into the fire,"], ["sa latou faatonu ia lafo i latou i le afi; ma sa latou aumai foi a latou talafaamaumau sa i ai i totonu tusitusiga paia,", "and they also brought forth their records which contained the holy scriptures,"], ["ma lafo foi i latou i le afi,", "and cast them into the fire also,"], ["ina ia susunuina i latou ma faaumatia i le afi.", "that they might be burned and destroyed by fire."]]},
  {num:9,words:[["Ma sa oo ina latou ave Alema ma Amoleka,", "And it came to pass that they took Alma and Amulek,"], ["ma ave i laua i le nofoaga o le faamaturoga,", "and carried them forth to the place of martyrdom,"], ["ina ia laua vaai i le faaumatiaga o i latou o e na susunu i le afi.", "that they might witness the destruction of those who were consumed by ire."]]},
  {num:10,words:[["Ma ina ua vaai atu Amoleka i tiga o fafine ma fanau o e na susunu i le afi,", "And when Amulek saw the pains of the women and children who were consuming in the fire,"], ["sa tiga foi o ia;", "he also was pained;"], ["ma sa ia fai atu ia Alema: E mafai faapefea ona ta vaai atu i lenei vaaiga leaga matautia? O lea,", "and he said unto Alma:"], ["ia ta faaloaloa atu o ta lima,", "How can we witness this awful scene? Therefore let us stretch forth our hands,"], ["ma faaaoga le mana o le Atua lea ua ia te i taua,", "and exercise the power of God which is in us,"], ["ma laveai i latou mai apeafi mumū.", "and save them from the flames."]]},
  {num:11,words:[["Peitai sa fai atu Alema ia te ia:", "But Alma said unto him:"], ["Ua taofia au e le Agaga ia aua ne'i ou faaloaloa atu lo'u lima;", "The Spirit constraineth me that I must not stretch forth mine hand;"], ["aua faauta ua aveina a'e i latou e le Alii ia te ia lava,", "for behold the Lord receiveth them up unto himself,"], ["i le mamalu ;", "in glory;"], ["ma ua ia tuuina ia mafai ona latou faia lenei mea,", "and he doth suffer that they may do this thing,"], ["pe ia mafai e tagata ona faia lenei mea ia te i latou,", "or that the people may do this thing unto them,"], ["e tusa ma le maaa o o latou loto,", "according to the hardness of their hearts,"], ["ina ia tonu faamasinoga o le a ia faia i luga o i latou i lona toasa;", "that the judgments which he shall exercise upon them in his wrath may be just;"], ["ma o le a tutu mai toto o e ua mama o se molimau e faasaga ia te i latou,", "and the blood of the innocent shall stand as a witness against them,"], ["ioe,", "yea,"], ["ma alaga malosi mai e faasaga ia te i latou i le aso gataaga.", "and cry mightily against them at the last day."]]},
  {num:12,words:[["O lenei sa fai mai Amoleka ia Alema:", "Now Amulek said unto Alma:"], ["Faauta,", "Behold,"], ["atonu o le a latou susunuina foi i taua.", "perhaps they will burn us also."]]},
  {num:13,words:[["Ma sa fai atu Alema:", "And Alma said:"], ["Ia faia lava e tusa ai ma le finagalo o le Alii.", "Be it according to the will of the Lord."], ["Ae faauta,", "But,"], ["e lei uma la ta galuega;", "behold, our work is not finished;"], ["o lea latou te le susunuina ai i taua.", "therefore they burn us not."]]},
  {num:14,words:[["O lenei sa oo ina ua uma ona mu o tino o i latou o e na lafo i le afi,", "Now it came to pass that when the bodies of those who had been cast into the fire were consumed,"], ["faapea ma talafaamaumau foi ia na lafo i le afi faatasi ma i latou,", "and also the records which were cast in with them,"], ["sa sau le faamasino sili o le laueleele ma ua tu i luma o Alema ma Amoleka,", "the chief judge of the land came and stood before Alma and Amulek,"], ["a'o noatia i laua;", "as they were bound;"], ["ma ua ia fetu'i i laua i lona lima i o laua alafau,", "and he smote them with his hand upon their cheeks,"], ["ma fai mai ia te i laua:", "and said unto them:"], ["Ona o mea ua oulua vaai i ai,", "After what ye have seen,"], ["pe lua te toe talai atu ea i lenei nuu,", "will ye preach again unto this people,"], ["o le a lafo i latou i se lepa afi ma le teio?", "that they shall be cast into a lake of fire and brimstone?"]]},
  {num:15,words:[["Faauta,", "Behold,"], ["ua oulua vaai ua leai se mana ua ia te oulua e laveai ai i latou o e na lafo i le afi;", "ye see that ye had not power to save those who had been cast into the fire;"], ["pe na laveaiina foi i latou e le Atua ona o i latou o la oulua faatuatuaga. Ma sa toe tu'i i laua e le faamasino i o laua alafau,", "neither has God saved them because they were of thy faith. And the judge smote them again upon their cheeks,"], ["ma fesili mai:", "and asked:"], ["O le a se lua famatalaga ia te oulua lava?", "What say ye for yourselves?"]]},
  {num:16,words:[["O lenei o lea faamasino sa mulimuli i le faatulagaga ma le faatuatuaga a Ne'oa ,", "Now this judge was after the order and faith of Nehor,"], ["o lē na fasiotia Kitiona.", "who slew Gideon."]]},
  {num:17,words:[["Ma sa oo ina sa le tali atu Alema ma Amoleka ia te ia i se mea e tasi;", "And it came to pass that Alma and Amulek answered him nothing;"], ["ma sa ia toe tu'i ia te i laua,", "and he smote them again,"], ["ma tuu atu i laua i leoleo e lafo i le falepuipui.", "and delivered them to the officers to be cast into prison."]]},
  {num:18,words:[["Ma ina ua mavae aso e tolu talu ona lafo o i laua i le falepuipui,", "And when they had been cast into prison three days,"], ["sa o ane ni loia e toatele,", "there came many lawyers,"], ["ma faamasino,", "and judges,"], ["ma faitaulaga,", "and priests,"], ["ma aoao,", "and teachers,"], ["o e sa auai i le faatuatuaga a Ne'oa;", "who were of the profession of Nehor;"], ["ma sa latou o atu i totonu o le falepuipui e vaai ia te i laua,", "and they came in unto the prison to see them,"], ["ma sa latou fesilisiligia i laua e uiga i upu e tele;", "and they questioned them about many words;"], ["peitai sa laua le tali atu ia i latou i se mea.", "but they answered them nothing."]]},
  {num:19,words:[["Ma sa oo ina tu mai le faamasino i o laua luma ma fai mai:", "And it came to pass that the judge stood before them,"], ["Aisea lua te le tali mai ai i upu a lenei nuu? Lua te le iloa ea ua ia te au le mana e tuu atu ai oulua e lafo i apeafi mumū? Ma sa ia faatonuina i laua ia tautatala mai;", "and said: Why do ye not answer the words of this people? Know ye not that I have power to deliver you up unto the flames? And he commanded them to speak;"], ["peitai sa laua le tali atu i se mea e tasi.", "but they answered nothing."]]},
  {num:20,words:[["Ma sa oo ina latou o ese atu ma o atu i o latou ala,", "And it came to pass that they departed and went their ways,"], ["ae sa latou toe o ane i le aso na sosoo ai;", "but came again on the morrow;"], ["ma sa toe fetu'i foi i laua e le faamasino i o laua alafau. Ma sa toatele foi na o ane,", "and the judge also smote them again on their cheeks. And many came forth also,"], ["ma fetu'i ia te i laua,", "and smote them,"], ["ua fai mai:", "saying:"], ["Pe lua te toe tutu ea ma faamasino i lenei nuu,", "Will ye stand again and judge this people,"], ["ma tauleaga la matou tulafono? Afai ua ia te oulua se mana tele faapena aisea lua te le laveai ai oulua lava?", "and condemn our law? If ye have such great power why do ye not deliver yourselves?"]]},
  {num:21,words:[["Ma e tele mea faapena sa latou fai mai ai ia te i laua,", "And many such things did they say unto them,"], ["ma le lilivau o o latou nifo ia te i laua,", "gnashing their teeth upon them,"], ["ma tuufeanu i o laua luga,", "and spitting upon them,"], ["ma fai mai:", "and saying:"], ["E faape'ī o matou foliga pe a faasalaina i matou?", "How shall we look when we are damned?"]]},
  {num:22,words:[["Ma e tele mea faapena,", "And many such things,"], ["ioe,", "yea,"], ["ituaiga o mea uma faapena sa latou fai mai ia te i laua;", "all manner of such things did they say unto them;"], ["ma sa faapena ona latou tauemu ia te i laua mo aso e tele. Ma sa latou taofi meaai mai ia te i laua ina ia laua fia aai,", "and thus they did mock them for many days. And they did withhold food from them that they might hunger,"], ["faapea ma vai ina ia laua fia feinu;", "and water that they might thirst;"], ["ma sa latou aveese foi mai ia te i laua o laua ofu sa laua le lavalavā ai;", "and they also did take from them their clothes that they were naked;"], ["ma sa faapea ona saisaitia o i laua i maea malolosi,", "and thus they were bound with strong cords,"], ["ma tuu i le falepuipui.", "and confined in prison."]]},
  {num:23,words:[["Ma sa oo ina ua mavae ona mafatia i laua faapea mo aso e tele,", "And it came to pass after they had thus suffered for many days,"], ["(ma o le aso sefulu lua,", "(and it was on the twelfth day,"], ["o le masina lona sefulu, i le lona sefulu o tausaga o le nofoaiga a faamasino i le nuu o Nifae) sa o atu ai le faamasino sili i luga o le nuu o Amonaea ma le toatele o o latou aoao ma o latou loia i le falepuipui,", "in the tenth month,"], ["lea sa saisaitia ai Alema ma Amoleka i maea.", "in the tenth year of the reign of the judges over the people of Nephi) that the chief judge over the land of Ammonihah and many of their teachers and their lawyers went in unto the prison where Alma and Amulek were bound with cords."]]},
  {num:24,words:[["Ma sa tu le faamasino sili i o laua luma,", "And the chief judge stood before them,"], ["ma toe fetu'i i laua,", "and smote them again,"], ["ma fai mai ia te i laua: Afai ua ia te oulua le mana o le Atua,", "and said unto them:"], ["ia oulua laveai ia te oulua lava mai nei fusi,", "If ye have the power of God deliver yourselves from these bands,"], ["ona matou talitonu ai lea o le a faaumatia e le Alii le nuu lenei e tusa ma a oulua upu.", "and then we will believe that the Lord will destroy this people according to your words."]]},
  {num:25,words:[["Ma sa oo ina latou o atu uma ma fetu'i ia te i laua,", "And it came to pass that they all went forth and smote them,"], ["ma fai atu ia lava upu tutusa,", "saying the same words,"], ["seia oo lava i le tagata mulimuli; ma ina ua uma ona tautala atu o le tagata mulimuli ia te i laua,", "even until the last;"], ["sa oo ina oo ifo le mana o le Atua i luga o Alema ma Amoleka,", "and when the last had spoken unto them the power of God was upon Alma and Amulek,"], ["ma sa laua tutulai ma tutu i luga i o laua vae.", "and they rose and stood upon their feet."]]},
  {num:26,words:[["Ma sa alaga atu Alema,", "And Alma cried,"], ["ua fai atu:", "saying:"], ["O le a le umi ma te onosaia ai nei puapuaga tetele,", "How long shall we suffer these great afflictions,"], ["le Alii e? Le Alii e,", "O Lord? O Lord,"], ["ia tuu mai ia te i maua le malosi e tusa ma lo maua faatuatua ua ia Keriso,", "give us strength according to our faith which is in Christ,"], ["seia laveaiina ai i maua. Ona laua motusi ai lea o maea sa saisai ai i laua;", "even unto deliverance. And they broke the cords with which they were bound;"], ["ma ina ua vaai mai tagata i lenei mea,", "and when the people saw this,"], ["sa amata ona latou sosola,", "they began to flee,"], ["ona ua oo mai i o latou luga le matau i le faafanoga.", "for the fear of destruction had come upon them."]]},
  {num:27,words:[["Ma sa oo ina sa matua tele lava lo latou matatau ma sa latou pauu i le eleele,", "And it came to pass that so great was their fear that they fell to the earth,"], ["ma latou le maua le faitotoa i fafo o le falepuipui ;", "and did not obtain the outer door of the prison;"], ["ma sa matua luluina tetele le eleele,", "and the earth shook mightily,"], ["ma sa vetelua puipui o le falepuipui,", "and the walls of the prison were rent in twain,"], ["sa latou pauu ai i le eleele;", "so that they fell to the earth;"], ["ma o le faamasino sili,", "and the chief judge,"], ["ma loia,", "and the lawyers,"], ["ma faitaulaga,", "and priests,"], ["ma aoao,", "and teachers,"], ["o e na fetu'ia Alema ma Amoleka,", "who smote upon Alma and Amulek,"], ["sa fasiotia i le pau o le falepuipui.", "were slain by the fall thereof."]]},
  {num:28,words:[["A'o Alema ma Amoleka,", "And Alma and Amulek came forth out of the prison,"], ["sa o mai i fafo o le falepuipui,", "and they were not hurt;"], ["ma sa le lavevea i laua; ona sa tuu mai e le Alii ia te i laua le mana,", "for the Lord had granted unto them power,"], ["e tusa ma lo laua faatuatua sa ia Keriso.", "according to their faith which was in Christ."], ["Ma sa laua o mai sa'o i fafo o le falepuipui;", "And they straightway came forth out of the prison;"], ["ma ua tatalaina i laua mai i o laua noataga;", "and they were loosed from their bands;"], ["ma ua pau le falepuipui i le eleele,", "and the prison had fallen to the earth,"], ["ma o tagata uma sa i totonu o ona puipui,", "and every soul within the walls thereof,"], ["vagana ai Alema ma Amoleka,", "save it were Alma and Amulek,"], ["sa fasiotia;", "was slain;"], ["ma sa la o atu sa'o i le aai.", "and they straightway came forth into the city."]]},
  {num:29,words:[["O lenei ina ua faalogo mai tagata i se gogolo tele,", "Now the people having heard a great noise came running together by multitudes to know the cause of it;"], ["sa latou taufetuli mai faatasi i motu o tagata e fia iloa lona pogai;", "and when they saw Alma and Amulek coming forth out of the prison,"], ["ma ina ua latou vaai mai ia Alema ma Amoleka ua o mai i fafo o le falepuipui, ma ua pauu i le eleele ona puipui,", "and the walls thereof had fallen to the earth,"], ["sa taia i latou i le matau tele,", "they were struck with great fear,"], ["ma ua sosola ese mai luma o Alema ma Amoleka e pei ona sola ese se 'oti ma lana tama mai ni leona se lua;", "and fled from the presence of Alma and Amulek even as a goat fleeth with her young from two lions;"], ["ma sa faapea ona latou sosola ese mai luma o Alema ma Amoleka.", "and thus they did flee from the presence of Alma and Amulek."]]},
];
renderVerseSet(al_ch_14_Verses, 'al-ch14-verses');

var al_ch_15_Verses = [
  {num:1,words:[["Ma sa oo ina poloaiina Alema ma Amoleka ia o ese atu i fafo mai lena aai;", "And it came to pass that Alma and Amulek were commanded to depart out of that city;"], ["ma sa la o ese atu,", "and they departed,"], ["ma o mai seia oo mai i le laueleele o Saitoma;", "and came out even into the land  of Sidom;"], ["ma faauta,", "and behold,"], ["o iina na la maua i ai tagata uma o e na o ese atu i fafo mai le laueleele o Amonaea ,", "there they found all the people who had departed out of the land of Ammonihah,"], ["o e na tutuli ese i fafo ma fetogia i maa,", "who had been cast out and stoned,"], ["ona sa latou talitonu i upu a Alema.", "because they believed in the words of Alma."]]},
  {num:2,words:[["Ma sa la faamatala atu ia te i latou mea uma na tutupu ia latou ava ma fanau,", "And they related unto them all that had happened unto their wives and children,"], ["ma e uiga foi ia i laua lava,", "and also concerning themselves,"], ["ma e uiga i lo laua mana o le laveaiga.", "and of their power of deliverance."]]},
  {num:3,words:[["Ma sa faataotolia foi Seseroma i Saitoma ua mai,", "And also Zeezrom lay sick at Sidom,"], ["i se fiva mumū,", "with a burning fever,"], ["lea na mafua mai i le puapuagatia tele o lona mafaufau ona o lona amioleaga ,", "which was caused by the great tribulations of his mind on account of his wickedness,"], ["ona sa manatu o ia ua le toe i ai Alema ma Amoleka;", "for he supposed that Alma and Amulek were no more;"], ["ma sa manatu o ia ua fasiotia i laua ona o lona amioletonu. Ma o lenei agasala tele,", "and he supposed that they had been slain because of his iniquity. And this great sin,"], ["ma le tele o isi ana agasala,", "and his many other sins,"], ["sa atuatuvale ai lona mafaufau sa oo ina matua tiga tele lava,", "did harrow up his mind until it did become exceedingly sore,"], ["sa leai se mapu mai ai;", "having no deliverance;"], ["o lea na amata ai ona mū o ia i se vevela mumū.", "therefore he began to be scorched with a burning heat."]]},
  {num:4,words:[["O lenei,", "Now,"], ["ina ua faalogo o ia ua i ai Alema ma Amoleka i le laueleele o Saitoma,", "when he heard that Alma and Amulek were in the land of Sidom,"], ["sa amata ona lototele lona loto;", "his heart began to take courage;"], ["ma sa ia auina atu vave se feau ia te i laua,", "and he sent a message immediately unto them,"], ["e manao ia i laua ia o mai ia te ia.", "desiring them to come unto him."]]},
  {num:5,words:[["Ma sa oo ina o atu vave i laua,", "And it came to pass that they went immediately,"], ["i le usiusitai i le feau lea sa ia auina mai ia te i laua;", "obeying the message which he had sent unto them;"], ["ma sa la o atu i totonu o le fale ia Seseroma; ma sa la maua atu o ia i luga o lona moega,", "and they went in unto the house unto Zeezrom;"], ["ua gasegase,", "and they found him upon his bed,"], ["ua vaivai lava i se fiva mumū;", "sick,"], ["ma sa mafatia tele foi lona mafaufau ona o ana amioletonu;", "being very low with a burning fever;"], ["ma ina ua vaai mai o ia ia te i laua, sa ia faaloloa mai lona lima,", "and his mind also was exceedingly sore because of his iniquities;"], ["ma aioi mai ia te i laua,", "and when he saw them he stretched forth his hand,"], ["ina ia la faamaloloina o ia.", "and besought them that they would heal him."]]},
  {num:6,words:[["Ma sa oo ina fai atu Alema ia te ia,", "And it came to pass that Alma said unto him,"], ["ma tago atu ia te ia i le lima:", "taking him by the hand:"], ["Ua e talitonu ea i le mana o Keriso mo le olataga?", "Believest thou in the power of Christ unto salvation?"]]},
  {num:7,words:[["Ma sa tali mai o ia ma fai mai:", "And he answered and said:"], ["Ioe,", "Yea,"], ["ua ou talitonu i upu uma na e aoao mai.", "I believe all the words that thou hast taught."]]},
  {num:8,words:[["Ma sa fai atu Alema:", "And Alma said:"], ["Afai ua e talitonu i le togiola a Keriso e mafai ona faamaloloina oe.", "If thou believest in the redemption of Christ thou canst be healed."]]},
  {num:9,words:[["Ma sa fai mai o ia:", "And he said:"], ["Ioe,", "Yea,"], ["ua ou talitonu e tusa ma au upu.", "I believe according to thy words."]]},
  {num:10,words:[["Ma ona tagi atu ai lea o Alema i le Alii,", "And then Alma cried unto the Lord,"], ["ua fai atu:", "saying:"], ["Le Alii e, lo matou Atua,", "O Lord our God,"], ["ia e alofa mutimutivale mai i lenei alii,", "have mercy on this man,"], ["ma faamaloloina o ia e tusa ma lona faatuatua lea ua ia Keriso.", "and heal him according to his faith which is in Christ."]]},
  {num:11,words:[["Ma ina ua uma ona fai atu e Alema o nei upu,", "And when Alma had said these words,"], ["sa oso i luga Seseroma i ona vae,", "Zeezrom leaped upon his feet,"], ["ma amata ona savali;", "and began to walk;"], ["ma sa faia lenei mea ma le ofo tele o tagata uma;", "and this was done to the great astonish– ment of all the people;"], ["ma sa alu atu le tala o lenei mea i le laueleele atoa o Saitoma.", "and the knowledge of this went forth throughout all the land of Sidom."]]},
  {num:12,words:[["Ma sa papatiso Seseroma e Alema mo le Alii; ma sa amata mai i le taimi lena e oo atu i luma,", "And Alma baptized Zeezrom unto the Lord;"], ["ona ia talai atu i tagata.", "and he began from that time forth to preach unto the people."]]},
  {num:13,words:[["Ma sa faatu e Alema se aulotu i le laueleele o Saitoma,", "And Alma established a church in the land of Sidom,"], ["ma faapaia faitaulaga ma aoao i le laueleele,", "and consecrated priests and teachers in the land,"], ["e papatiso mo le Alii soo se tasi o e sa mananao e papatiso.", "to baptize unto the Lord whosoever were desirous to be baptized."]]},
  {num:14,words:[["Ma sa oo ina sa toatele i latou;", "And it came to pass that they were many;"], ["ona sa latou lolofi mai itulagi uma faataamilo ia Saitoma,", "for they did flock in from all the region round about Sidom,"], ["ma papatisoina.", "and were baptized."]]},
  {num:15,words:[["Ae o tagata sa i ai i le laueleele o Amonaea,", "But as to the people that were in the land of Ammonihah,"], ["sa tumau pea i latou o ni tagata loto-maaa ma ua maaa;", "they yet remained a hard– hearted and a stiffnecked people;"], ["ma sa latou le salamo ia latou agasala,", "and they repented not of their sins,"], ["ma latou tuua'i le mana uma o Alema ma Amoleka i le tiapolo;", "ascribing all the power of Alma and Amulek to the devil;"], ["ona sa latou auai i le faatuatuaga a Ne'oa ,", "for they were of the profession of Nehor,"], ["ma sa latou le talitonu i le salamo mai ia latou agasala.", "and did not believe in the repentance of their sins."]]},
  {num:16,words:[["Ma o Alema ma Amoleka,", "And it came to pass that Alma and Amulek,"], ["ina ua lafoai atu e Amoleka o ana auro uma,", "Amulek having forsaken all his gold,"], ["ma ario,", "and silver,"], ["ma ana mea taua uma,", "and his precious things,"], ["ia sa i le laueleele o Amonaea,", "which were in the land of Ammonihah,"], ["mo le afioga a le Atua,", "for the word of God,"], ["ina ua teena o ia e i latou o e sa avea ma ana uo ma lona tamā foi ma ona aiga;", "he being rejected by those who were once his friends and also by his father and his kindred;"]]},
  {num:17,words:[["O lea,", "Therefore,"], ["ina ua uma ona faatu e Alema le ekalesia i Saitoma,", "after Alma having established the church at Sidom,"], ["ina ua vaaia se vaosia tele,", "seeing a great check,"], ["ioe,", "yea,"], ["ina ua vaaia ua vaosia tagata e faatatau i le faamaualuluga o o latou loto,", "seeing that the people were checked as to the pride of their hearts,"], ["ma amata ona latou faalotomaualalalo i latou lava i luma o le Atua,", "and began to humble themselves before God,"], ["ma amata ona latou faapotopoto faatasi i latou lava i o latou falesa e tapuai i le Atua i luma o le fatafaitaulaga,", "and began to assemble themselves together at their sanctuaries to worship God before the altar,"], ["ma mataala ma tatalo e le aunoa,", "watching and praying continually,"], ["ina ia laveaiina i latou mai ia Satani,", "that they might be delivered from Satan,"], ["ma mai le oti ,", "and from death,"], ["ma mai le faafanoga—", "and from destruction—"]]},
  {num:18,words:[["O lenei e pei ona ou fai atu,", "Now as I said,"], ["ina ua vaai Alema i nei mea uma,", "Alma having seen all these things,"], ["o lea na ia ave ai Amoleka ma o mai i le laueleele o Sara'emila,", "therefore he took Amulek and came over to the land of Zarahemla,"], ["ma sa ia ave o ia i lona lava fale,", "and took him to his own house,"], ["ma tausi ia te ia i ona puapuaga,", "and did administer unto him in his tribulations,"], ["ma faamalosi o ia i la le Alii.", "and strengthened him in the Lord."]]},
  {num:19,words:[["Ma sa faapea ona iu o le lona sefulu o tausaga o le nofoaiga a faamasino i luga o le laueleele o Nifae.", "And thus ended the tenth year of the reign of the judges over the people of Nephi."]]},
];
renderVerseSet(al_ch_15_Verses, 'al-ch15-verses');

var al_ch_16_Verses = [
  {num:1,words:[["Ma sa oo i le lona sefulu tasi o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae,", "And it came to pass in the eleventh year of the reign of the judges over the people of Nephi,"], ["i le aso lona lima o le masina lona lua,", "on the fifth day of the second month,"], ["sa i ai le filemu tele i le laueleele o Sara'emila,", "there having been much peace in the land of Zarahemla,"], ["ona sa leai ni taua po o ni finauga mo se aofaiga faapitoa o tausaga,", "there having been no wars nor contentions for a certain number of years,"], ["seia oo mai i le aso lona lima o le masina lona lua i le sefulu tasi o tausaga,", "even until the fifth day of the second month in the eleventh year,"], ["lea na faalogoina ai se alaga o le taua i le laueleele atoa.", "there was a cry of war heard throughout the land."]]},
  {num:2,words:[["Aua faauta,", "For behold,"], ["sa o mai autau a sa Lamanā i luga i le itu i le vao,", "the armies of the Lamanites had come in upon the wilderness side,"], ["i tuaoi o le laueleele,", "into the borders of the land,"], ["seia oo mai i le aai o Amonaea ,", "even into the city of Ammonihah,"], ["ma amata ona fasioti o tagata ma faaumatia le aai.", "and began to slay the people and destroy the city."]]},
  {num:3,words:[["Ma o lenei sa oo ina lei mafai e sa Nifaē ona faatu se autau ia lava e tutuli ese ai i latou i fafo mai le laueleele,", "And now it came to pass,"], ["sa latou faaumatiaina tagata o e sa i le aai o Amonaea,", "before the Nephites could raise a sufficient army to drive them out of the land,"], ["ma isi foi sa i tuaoi o Noa,", "they had destroyed the people who were in the city of Ammonihah, and also some around the borders of Noah,"], ["ma ave isi faatagataotaua i le vao.", "and taken others captive into the wilderness."]]},
  {num:4,words:[["O lenei sa oo ina mananao sa Nifaē ia maua mai i latou o e na aveese atu faatagataotaua i le vao.", "Now it came to pass that the Nephites were desirous to obtain those who had been carried away captive into the wilderness."]]},
  {num:5,words:[["O lea,", "Therefore,"], ["o ia o le na tofia e avea ma kapeteni sili i luga o autau a sa Nifaē,", "he that had been appointed chief captain over the armies of the Nephites,"], ["(ma o lona igoa o Sorama,", "(and his name was Zoram,"], ["ma sa ia te ia ni atalii e toalua,", "and he had two sons,"], ["o Liae ma Asa)—o lenei ina ua iloa e Sorama ma ona atalii e toalua,", "Lehi and Aha)—now Zoram and his two sons,"], ["o Alema o le faitaulaga sili o le ekalesia,", "knowing that Alma was high priest over the church,"], ["ma ina ua faalogo ua ia te ia le agaga o valoaga,", "and having heard that he had the spirit of prophecy,"], ["o lea na latou o atu ai ia te ia ma talosaga atu ia te ia e fia iloa po o fea e finagalo le Alii latou te o atu i ai i le vao e saili ai o latou uso,", "therefore they went unto him and desired of him to know whither the Lord would that they should go into the wilderness in search of their brethren,"], ["o e na ave faatagataotaua e sa Lamanā.", "who had been taken captive by the Lamanites."]]},
  {num:6,words:[["Ma sa oo ina ole atu Alema i le Alii e uiga i le mataupu. Ma sa toe foi mai Alema ma fai atu ia te i latou:", "And it came to pass that Alma inquired of the Lord concerning the matter. And Alma returned and said unto them:"], ["Faauta,", "Behold,"], ["o le a sopoia e sa Lamanā le vaitafe o Saitonu i le vao i le itu i saute,", "the Lamanites will cross the river Sidon in the south wilderness,"], ["e mamao ese i luga i tala atu o tuaoi o le laueleele o Maneti. Ma faauta o iina o le a outou fetaiai ai ma i latou,", "away up beyond the borders of the land of Manti. And behold there shall ye meet them,"], ["i le itu i sasae o le vaitafe o Saitonu,", "on the east of the river Sidon,"], ["ma o iina o le a tuu atu ai e le Alii ia te oe ou uso o e ua ave faatagataotaua e sa Lamanā.", "and there the Lord will deliver unto thee thy brethren who have been taken captive by the Lamanites."]]},
  {num:7,words:[["Ma sa oo ina sopoia e Sorama ma ona atalii le vaitafe o Saitonu,", "And it came to pass that Zoram and his sons crossed over the river Sidon,"], ["faatasi ma a latou autau,", "with their armies,"], ["ma savavali ese atu i tala atu o tuaoi o Maneti i le vao i le itu i saute,", "and marched away beyond the borders of Manti into the south wilderness,"], ["lea sa i le itu i sasae o le vaitafe o Saitonu.", "which was on the east side of the river Sidon."]]},
  {num:8,words:[["Ma sa latou o atu i autau a sa Lamanā,", "And they came upon the armies of the Lamanites,"], ["ma sa faataapeapeina sa Lamanā ma tutulia i le vao;", "and the Lamanites were scattered and driven into the wilderness;"], ["ma sa latou ave o latou uso o e na ave faatagataotaua e sa Lamanā,", "and they took their brethren who had been taken captive by the Lamanites,"], ["ma sa leai se tagata e toatasi o i latou o e na ave faatagataotauaina na leiloa. Ma sa aumai i latou e o latou uso e nonofo i o latou lava laueleele.", "and there was not one soul of them had been lost that were taken captive. And they were brought by their brethren to possess their own lands."]]},
  {num:9,words:[["Ma sa faapea ona iu o le lona sefulu tasi o tausaga o faamasino,", "And thus ended the eleventh year of the judges,"], ["ua tutuli ese i fafo sa Lamanā mai le laueleele,", "the Lamanites having been driven out of the land,"], ["ma ua faaumatia tagata o Amonaea;", "and the people of Ammonihah were destroyed;"], ["ioe,", "yea,"], ["sa faaumatia tagata ola uma o sa Amonaeā,", "every living soul of the Ammonihahites was destroyed,"], ["ma lo latou aai tele foi,", "and also their great city,"], ["lea sa latou fai mai e le mafai e le Atua ona faaumatia,", "which they said God could not destroy,"], ["ona o lona tele.", "because of its greatness."]]},
  {num:10,words:[["Ae faauta,", "But behold,"], ["e tasi le aso ua tuufua;", "in one day it was left desolate;"], ["ma sa faataugā e uli ma manu feai o le vao tino o tagata oti.", "and thecarcasses were mangled by dogs and wild beasts of the wilderness."]]},
  {num:11,words:[["E ui i lea,", "Nevertheless,"], ["ina ua mavae ni aso e tele, sa faufaulalai o latou tino oti i luga o le eleele,", "after many days their dead bodies were heaped up upon the face of the earth,"], ["ma sa tanu i latou i se tanuga papa'u.", "and they were covered with a shallow covering."], ["Ma o lenei sa matua malosi tele lo latou manogi sa le o atu i ai tagata mo le tele o tausaga e fai mo i latou le laueleele o Amonaea.", "And now so great was the scent thereof that the people did not go in to possess the land of Ammonihah for many years."], ["Ma sa taua o le Tafunaiga o sa Ne'oā;", "And it was called Desolation of Nehors;"], ["ona o i latou o e na fasiotia,", "for they were of the profession of Nehor,"], ["o i latou ia o le faatuatuaga a Ne'oa ;", "who were slain;"], ["ma ua tumau le tuufua o latou laueleele.", "and their lands remained desolate."]]},
  {num:12,words:[["Ma sa le toe o mai sa Lamanā e tau faasaga mai ia sa Nifaē seia oo i le lona sefulu fa o tausaga o le nofoaiga a faamasino i nuu o Nifae. Ma sa faapea ona maua ai e le nuu o Nifae le filemu e le aunoa i le laueleele atoa mo le tolu o tausaga.", "And the Lamanites did not come again to war against the Nephites until the fourteenth year of the reign of the judges over the people of Nephi. And thus for three years did the people of Nephi have continual peace in all the land."]]},
  {num:13,words:[["Ma sa o atu Alema ma Amoleka ma talai atu le salamo i tagata i o latou malumalu ,", "And Alma and Amulek went forth preaching repentance to the people in their temples,"], ["ma i o latou falesa,", "and in their sanctuaries,"], ["ma i o latou sunako foi,", "and also in their synagogues,"], ["ia na fausia e tusa ma le ala a tagata Iutaia.", "which were built after the manner of the Jews."]]},
  {num:14,words:[["Ma o le toatele o e na fia faalogologo ia laua upu,", "And as many as would hear their words,"], ["o i latou ia sa la avatu pea lava i ai le afioga a le Atua,", "unto them they did impart the word of God, without any respect of persons,"], ["e aunoa ma se faailoga tagata.", "continually."]]},
  {num:15,words:[["Ma sa faapea ona o atu o Alema ma Amoleka,", "And thus did Alma and Amulek go forth,"], ["ma le toatele atu foi o e na filifilia mo le galuega,", "and also many more who had been chosen for the work,"], ["e talai atu le afioga i le laueleele atoa. Ma sa lautele le faatuina o le ekalesia i le laueleele atoa,", "to preach the word throughout all the land. And the establishment of the church became general throughout the land,"], ["i itulagi uma faataamilo ai,", "in all the region round about,"], ["i totonu o tagata uma o sa Nifaē.", "among all the people of the Nephites."]]},
  {num:16,words:[["Ma sa leai se lē tutusa i totonu o i latou;", "And there was no inequality among them;"], ["sa liligi ifo e le Alii lona Agaga i luga o le laueleele atoa e saunia ai mafaufau o le fanauga a tagata, pe saunia ai o latou loto ,", "the Lord did pour out his Spirit on all the face of the land to prepare the minds of the children of men,"], ["e talia le afioga lea o le a aoaoina i totonu o i latou i le taimi o lona afio mai—", "or to prepare their hearts to receive the word which should be taught among them at the time of his coming—"]]},
  {num:17,words:[["Ina ia latou le faamaaa e faasaga i le afioga,", "That they might not be hardened against the word,"], ["ina ia le mafai ona latou le talitonu,", "that they might not be unbelieving,"], ["ma o atu ai i le faafanoga,", "and go on to destruction,"], ["ae ia mafai ai ona latou talia o le afioga ma le olioli,", "but that they might receive the word with joy,"], ["ma sulu i totonu o le vine moni o se lālā moni,", "and as a branch be grafted into the true vine,"], ["ina ia mafai ona latou ulu atu i le malologa o le Alii lo latou Atua.", "that they might enter into the rest of the Lord their God."]]},
  {num:18,words:[["O lenei o faitaulaga na o e na o atu i totonu o le nuu sa latou talai atu e faasaga i pepelo uma,", "Now those priests who did go forth among the people did preach against all lyings,"], ["ma taufaaseseega ,", "and deceivings,"], ["ma losilosivalega ,", "and envyings,"], ["ma finauga,", "and strifes,"], ["ma le taufaaleaga,", "and malice,"], ["ma le taufaifai,", "and revilings,"], ["ma le gaoi, faomea,", "and stealing,"], ["vete,", "robbing,"], ["fasioti tagata,", "plundering,"], ["faia o le mulilua,", "murdering,"], ["ma ituaiga uma o faitaaga;", "committing adultery,"], ["ma alalaga atu,", "and all manner of lasciviousness,"], ["e le tatau ona i ai o nei mea—", "crying that these things ought not so to be—"]]},
  {num:19,words:[["Ma folafola atu mea ua lata ona oo mai;", "Holding forth things which must shortly come;"], ["ioe,", "yea,"], ["folafola atu le afio mai o le Alo o le Atua,", "holding forth the coming of the Son of God,"], ["o ona mafatiaga ma lona maliu,", "his sufferings and death,"], ["ma le toetutu mai foi o e ua oti.", "and also the resurrection of the dead."]]},
  {num:20,words:[["Ma e toatele tagata sa fesili e uiga i le nofoaga o le a afio mai i ai le Alo o le Atua;", "And many of the people did inquire concerning the place where the Son of God should come;"], ["ma sa aoaoina i latou o le a afio mai o ia ia te i latou pe a mavae lona toetu mai;", "and they were taught that he would appear unto them after his resurrection;"], ["ma o lenei mea sa faalogo mai i ai tagata ma le olioli tele ma le fiafia.", "and this the people did hear with great joy and gladness."]]},
  {num:21,words:[["Ma o lenei ina ua uma ona faatumauina o le ekalesia i le laueleele atoa—ina ua maua le manumalo i le tiapolo,", "And now after the church had been established throughout all the land—having got the victory over the devil,"], ["ma ua talai atu le afioga a le Atua i lona mama i le laueleele atoa,", "and the word of God being preached in its purity in all the land,"], ["ma ua liligi mai e le Alii ana faamanuiaga i luga o tagata—sa faapea ona iu o le lona sefulu fa o tausaga o le nofoaiga a faamasino i le nuu o Nifae.", "and the Lord pouring out his blessings upon the people—thus ended the fourteenth year of the reign of the judges over the people of Nephi."]]},
];
renderVerseSet(al_ch_16_Verses, 'al-ch16-verses');

var al_ch_17_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina a'o malaga atu Alema mai le laueleele o Kitiona agai i le itu i saute,", "And now it came to pass that as Alma was journeying from the land of Gideon southward,"], ["e alu ese atu i le laueleele o Maneti,", "away to the land of Manti,"], ["faauta, sa ofo o ia,", "behold,"], ["i lona feiloai ma atalii o Mosaea,", "to his astonishment,"], ["o malaga atu agai i le laueleele o Sara'emila.", "he met with the sons of Mosiah journeying towards the land of Zarahemla."]]},
  {num:2,words:[["O lenei o atalii nei o Mosaea sa faatasi ma Alema i le taimi na afio muamua ifo ai le agelu ia te ia;", "Now these sons of Mosiah were with Alma at the time the angel first appeared unto him;"], ["o lea sa olioli tele Alema i le vaai atu i ona uso;", "therefore Alma did rejoice exceedingly to see his brethren;"], ["ma o le mea na faatele atili ai lona olioli,", "and what added more to his joy,"], ["ona sa avea pea i latou ma ona uso i le Alii;", "they were still his brethren in the Lord;"], ["ioe,", "yea,"], ["ma sa latou matua malolosi i le malamalama o le upumoni;", "and they had waxed strong in the knowledge of the truth;"], ["ona o i latou o ni alii mafaufau lelei ma sa latou suesue i tusitusiga paia ma le filiga,", "for they were men of a sound under– standing and they had searched the scriptures diligently,"], ["ina ia latou iloa le afioga a le Atua.", "that they might know the word of God."]]},
  {num:3,words:[["Ae sa le ona pau lea;", "But this is not all;"], ["sa latou tuu atu i latou lava i le tatalo tele,", "they had given themselves to much prayer,"], ["ma le anapogi ;", "and fasting;"], ["o lea na i ai ai ia i latou le agaga o valoaga,", "therefore they had the spirit of prophecy,"], ["ma le agaga o faaaliga,", "and the spirit of revelation,"], ["ma a latou aoao atu,", "and when they taught,"], ["sa latou aoao atu ma le mana ma le pule mai le Atua.", "they taught with power and authority of God."]]},
  {num:4,words:[["Ma sa latou aoao atu le afioga a le Atua i totonu o sa Lamanā mo le va o le sefulu fa tausaga,", "And they had been teaching the word of God for the space of fourteen years among the Lamanites,"], ["ona sa faamanuiaina tele i latou i lo latou aumaia o le toatele i le malamalama o le upumoni;", "having had much success in bringing many to the knowledge of the truth;"], ["ioe,", "yea,"], ["o le mana o a latou upu na aumai ai le toatele i luma o le fatafaitaulaga a le Atua,", "by the power of their words many were brought before the altar of God,"], ["e valaau atu i lona suafa ma tautau atu a latou agasala i ona luma.", "to call on his name and confess their sins before him."]]},
  {num:5,words:[["O lenei o tulaga nei na oo ia te i latou ia latou malaga,", "Now these are the circumstances which attended them in their journeyings,"], ["ona sa tele o latou puapuaga;", "for they had many afflictions;"], ["sa latou mafatia tele,", "they did suffer much,"], ["i le tino ma le mafaufau,", "both in body and in mind,"], ["e pei o le fia aai,", "such as hunger,"], ["fia inu ma le le lavavā,", "thirst and fatigue,"], ["ma le tele foi o tauiviga i la le agaga.", "and also much labor in the spirit."]]},
  {num:6,words:[["O lenei o a latou malaga nei:", "Now these were their journeyings:"], ["Ina ua latou tuua lo latou tamā,", "Having taken leave of their father,"], ["o Mosaea,", "Mosiah,"], ["i le tausaga muamua o faamasino;", "in the first year of the judges;"], ["ina ua latou teena le malo lea sa manao lo latou tamā e faaee i o latou luga,", "having refused the kingdom which their father was desirous to confer upon them,"], ["ma o le mea foi lenei sa i mafaufau o le nuu;", "and also this was the minds of the people;"]]},
  {num:7,words:[["E ui i lea sa latou o ese atu i fafo o le laueleele o Sara'emila,", "Nevertheless they departed out of the land of Zarahemla,"], ["ma ave a latou pelu,", "and took their swords,"], ["ma a latou tao,", "and their spears,"], ["ma a latou aufana,", "and their bows,"], ["ma a latou ufanafana,", "and their arrows,"], ["ma a latou maata;", "and their slings;"], ["ma sa latou faia lenei mea ina ia mafai ona latou maua o ni meaai mo i latou lava a'o latou i ai i le vao.", "and this they did that they might provide food for themselves while in the wilderness."]]},
  {num:8,words:[["Ma sa faapea ona latou o ese atu i le vao faatasi ma a latou aofai o tagata sa latou filifilia,", "And thus they departed into the wilderness with their numbers which they had selected,"], ["e o a'e i le laueleele o Nifae,", "to go up to the land of Nephi,"], ["e talai atu le afioga a le Atua ia sa Lamanā.", "to preach the word of God unto the Lamanites."]]},
  {num:9,words:[["Ma sa oo ina latou malaga atu i le vao mo aso e tele,", "And it came to pass that they journeyed many days in the wilderness,"], ["ma sa latou anapopogi soo ma tatalo soo ina ia tuu mai e le Alii se vaega o lona Agaga e o faatasi ma i latou,", "and they fasted much and prayed much that the Lord would grant unto them a portion of his Spirit to go with them,"], ["ma mafuta faatasi ma i latou,", "and abide with them,"], ["ina ia mafai ona avea i latou o ni 'auupega i aao o le Atua e aumai,", "that they might be an instrument in the hands of God to bring,"], ["pe afai e mafai,", "if it were possible,"], ["o latou uso,", "their brethren,"], ["o sa Lamanā,", "the Lamanites,"], ["i le malamalama o le upumoni,", "to the knowledge of the truth,"], ["i le malamalama i le leaga o uputuu a o latou tamā,", "to the knowledge of the baseness of the traditions of their fathers,"], ["ia ua le sa'o.", "which were not correct."]]},
  {num:10,words:[["Ma sa oo ina asiasi mai le Alii ia te i latou e ala i lona Agaga ,", "And it came to pass that the Lord did visit them with his Spirit,"], ["ma fetalai mai ia te i latou:", "and said unto them:"], ["Ia faamafanafanaina outou. Ma sa faamafanafanaina i latou.", "Be comforted. And they were comforted."]]},
  {num:11,words:[["Ma sa fetalai mai foi le Alii ia te i latou:", "And the Lord said unto them also:"], ["Ia outou o atu i totonu o sa Lamanā,", "Go forth among the Lamanites,"], ["o outou uso,", "thy brethren,"], ["ma faatu la'u upu;", "and establish my word;"], ["peitai ia outou onosai i le tali-tiga ma puapuaga,", "yet ye shall be patient in long– suffering and afflictions,"], ["ina ia mafai ona outou faaali atu faataitaiga lelei ia te i latou e ala atu ia te au,", "that ye may  show forth good examples unto them in me,"], ["ma o le a ou faia outou o se mea faigaluega i o'u lima mo le olataga o agaga e toatele.", "and I will make an instrument of thee in my hands unto the salvation of many souls."]]},
  {num:12,words:[["Ma sa oo ina lotoa loto o atalii o Mosaea,", "And it came to pass that the hearts of the sons of Mosiah,"], ["ma i latou foi o e na faatasi ma i latou,", "and also those who were with them,"], ["e o atu ia sa Lamanā e alaga atu ia te i latou le afioga a le Atua.", "took courage to go forth unto the Lamanites to declare unto them the word of God."]]},
  {num:13,words:[["Ma sa oo ina ua latou taunuu atu i tuaoi o le laueleele o sa Lamanā,", "And it came to pass when they had arrived in the borders of the land of the Lamanites,"], ["sa latou faataape i latou lava ma alu ese atu le tasi mai le isi,", "that they separated themselves and departed one from another,"], ["ma faalagolago i le Alii o le a latou toe feiloai i le faaiuga o la latou seleselega ;", "trusting in the Lord that they should meet again at the close of their harvest;"], ["ona sa latou manatu ua tele lava le galuega lea ua latou ave e fai.", "for they supposed that great was the work which they had undertaken."]]},
  {num:14,words:[["Ma e moni lava sa matua tele lava,", "And assuredly it was great,"], ["ona sa latou ave e talai atu le afioga a le Atua i ni tagata aivao ,", "for they had undertaken to preach the word of God to a wild and a hardened and a ferocious people;"], ["ma lotomaaa ma feai;", "a people who delighted in murdering the Nephites,"], ["o ni tagata sa fiafia i le fasioti o sa Nifaē,", "and robbing and plundering them;"], ["ma le fao ma le vete o a latou mea; ma sa tuu o latou loto i luga o oa,", "and their hearts were set upon riches,"], ["po o luga o auro ma ario,", "or upon gold and silver,"], ["ma maa taua;", "and precious stones;"], ["ae sa latou saili ia maua nei mea i le fasioti tagata ma le vete,", "yet they sought to obtain these things by murdering and plundering,"], ["ina ia latou le galulue i o latou lava lima mo nei mea.", "that they might not labor for them with their own hands."]]},
  {num:15,words:[["Sa faapea ona avea ai i latou o ni tagata paie tele,", "Thus they were a very indolent people,"], ["o le toatele o i latou sa tapuai i tupua,", "many of whom did worship idols,"], ["ma sa pau ifo i o latou luga le fetuu a le Atua ona o uputuu a o latou tamā;", "and the curse of God had fallen upon them because of the traditions of their fathers;"], ["e ui i lea sa tuu atu ia te i latou folafolaga a le Alii i luga o tulaga o le salamo.", "notwithstanding the promises of the Lord were extended unto them on the conditions of repentance."]]},
  {num:16,words:[["O lea,", "Therefore,"], ["o le pogai lenei na ave ai e atalii o Mosaea le galuega e fai,", "this was the cause for which the sons of Mosiah had undertaken the work,"], ["ina atonu e mafai ai ona latou aumai o i latou i le salamo;", "that perhaps they might bring them unto repentance;"], ["ina atonu e mafai ai ona latou aumai o i latou ia latou iloa e uiga i le fuafuaga o le togiola.", "that perhaps they might bring them to know of the plan of redemption."]]},
  {num:17,words:[["O lea na latou faataape ai i latou lava mai le tasi,", "Therefore they separated themselves one from another,"], ["ma o atu i a i latou,", "and went forth among them,"], ["e taitoatasi le tagata nao ia,", "every man alone,"], ["e tusa ma le afioga ma le mana a le Atua na tuuina mai ia te ia.", "according to the word and power of God which was given unto him."]]},
  {num:18,words:[["O lenei ona o Amona sa taitai i a i latou,", "Now Ammon being the chief among them,"], ["pe ona sa ia auauna atu ia te i latou,", "or rather he did administer unto them,"], ["sa alu ese atu o ia mai ia i latou,", "and he departed from them,"], ["ina ua uma ona ia faamanuia ia te i latou e tusa ma o latou tulaga eseese,", "after having blessed them according to their several stations,"], ["ina ua uma ona ia tuu atu o le afioga a le Atua ia te i latou,", "having imparted the word of God unto them,"], ["pe auauna atu ia te i latou ae lei alu ese atu o ia;", "or administered unto them before his departure;"], ["ma sa faapea ona latou o atu ia latou malaga eseese i le laueleele atoa.", "and thus they took their several journeys throughout the land."]]},
  {num:19,words:[["Ma sa alu atu Amona i le laueleele o Isamaeli,", "And Ammon went to the land of Ishmael,"], ["o le laueleele lea na faaigoa i atalii o Isamaeli ,", "the land being called after the sons of Ishmael,"], ["o e ua avea foi ma sa Lamanā.", "who also became Lamanites."]]},
  {num:20,words:[["Ma ina ua ulu atu Amona i le laueleele o Isamaeli,", "And as Ammon entered the land of Ishmael,"], ["sa ave o ia e sa Lamanā ma saisai o ia,", "the Lamanites took him and bound him,"], ["e tusa ma la latou masani o le saisai o sa Nifaē uma e pauu atu i o latou lima,", "as was their custom to bind all the Nephites who fell into their hands,"], ["ma ave i latou i luma o le tupu;", "and carry them before the king;"], ["ma sa faapea ona tuu ai i le filifiliga a le tupu pe fasioti i latou,", "and thus it was left to the pleasure of the king to slay them,"], ["pe taofi i latou e faatagataotauaina,", "or to retain them in captivity,"], ["pe lafo i latou i le falepuipui,", "or to cast them into prison,"], ["pe tutuli ese i latou i fafo mai lona laueleele,", "or to cast them out of his land,"], ["e tusa ma lona loto ma lana filifiliga.", "according to his will and pleasure."]]},
  {num:21,words:[["Ma sa faapea ona avatu o Amona i luma o le tupu o le na pule i le laueleele o Isamaeli;", "And thus Ammon was carried before the king who was over the land of Ishmael;"], ["ma o lona igoa o Lamonae;", "and his name was Lamoni;"], ["ma o ia o se e tupuga mai ia Isamaeli.", "and he was a descendant of Ishmael."]]},
  {num:22,words:[["Ma sa fesili atu le tupu ia Amona po o lona manao e fia nofo i le laueleele i totonu o sa Lamanā,", "And the king inquired of Ammon if it were his desire to dwell in the land among the Lamanites,"], ["po o totonu o lona nuu.", "or among his people."]]},
  {num:23,words:[["Ma sa fai atu Amona ia te ia:", "And Ammon said unto him:"], ["Ioe,", "Yea,"], ["ou te manao ou te nofo i totonu o lenei nuu mo se taimi;", "I desire to dwell among this people for a time;"], ["ioe,", "yea,"], ["ma atonu foi seia oo i le aso ou te oti ai.", "and perhaps until the day I die."]]},
  {num:24,words:[["Ma sa oo ina fiafia tele le tupu o Lamonae ia Amona,", "And it came to pass that king Lamoni was much pleased with Ammon,"], ["ma faatonu atu ia tatalaina ona noanoaga;", "and caused that his bands should be loosed;"], ["ma sa ia manao ia ave e Amona se tasi o ona afafine e avea ma ana ava.", "and he would that Ammon should take one of his daughters to wife."]]},
  {num:25,words:[["Peitai sa fai atu Amona ia te ia:", "But Ammon said unto him:"], ["E leai,", "Nay,"], ["ae o le a ou avea ma āu auauna. O lea na avea ai Amona ma se auauna i le tupu o Lamonae. Ma sa oo ina tuu o ia i totonu faatasi ma isi auauna e leoleo lafu manu a Lamonae,", "but I will be thy servant. Therefore Ammon became a servant to king Lamoni. And it came to pass that he was set among other servants to watch the flocks of Lamoni,"], ["e tusa ma masani a sa Lamanā.", "according to the custom of the Lamanites."]]},
  {num:26,words:[["Ma ina ua mavae aso e tolu talu ona auauna atu o ia i le tupu,", "And after he had been in the service of the king three days,"], ["a'o latou faatasi ma auauna sa Lamanā o o atu ma a latou lafu manu i se mea sa i ai vai,", "as he was with the Lamanitish servants going forth with their flocks to the place of water,"], ["lea sa taua o le vai o Sevusa,", "which was called the water of Sebus,"], ["ma o iina sa tulituli atu i ai e sa Lamanā a latou lafu manu,", "and all the Lamanites drive their flocks hither,"], ["ina ia mafai ona latou maua o vai—", "that they may have water—"]]},
  {num:27,words:[["O lea a'o tulituli atu e Amona ma auauna a le tupu a latou lafu manu i lenei nofoaga o le vai,", "Therefore,"], ["faauta,", "as Ammon and the servants of the king were driving forth their flocks to this place of water,"], ["sa tutu mai ni isi o sa Lamanā,", "behold, a certain number of the Lamanites,"], ["o e sa i le vai faatasi ma a latou lafu manu,", "who had been with their flocks to water,"], ["ma faasalalau lafu manu a Amona ma auauna a le tupu,", "stood and scattered the flocks of Ammon and the servants of the king,"], ["ma sa latou faasalalauina i latou na oo ina latou sosola i ala eseese.", "and they scattered them insomuch that they fled many ways."]]},
  {num:28,words:[["O lenei sa amata ona muimui o auauna a le tupu,", "Now the servants of the king began to murmur,"], ["fai mai:", "saying:"], ["O le a fasioti nei i tatou e le tupu,", "Now the king will slay us,"], ["e pei ona ia faia i o tatou uso ona sa faasalalauina a latou lafu manu e le amioleaga o nei tagata. Ma sa amata ona latou fetagisi tetele,", "as he has our brethren because their flocks were scattered by the wickedness of these men. And they began to weep exceedingly,"], ["fai mai:", "saying:"], ["Faauta,", "Behold,"], ["ua faasalalauina a tatou lafu manu.", "our flocks are scattered already."]]},
  {num:29,words:[["O lenei sa latou fetagisi ona o le matatau ne'i fasiotia i latou. O lenei ina ua vaai atu Amona i lenei mea sa faatumulia lona loto i totonu o ia i le olioli;", "Now they wept because of the fear of being slain. Now when Ammon saw this his heart was swollen within him with joy;"], ["ona,", "for,"], ["sa faapea ifo o ia,", "said he,"], ["o le a ou faaali atu lo'u mana ia te i latou nei o o'u uso a auauna,", "I will show forth my power unto these my fellow– servants,"], ["po o le mana ua ia te a'u,", "or the power which is in me,"], ["e toe aumai ai nei lafu manu i le tupu,", "in restoring these flocks unto the king,"], ["ina ia mafai ona ou maua o loto o o'u uso a auauna nei,", "that I may win the hearts of these my fellow– servants,"], ["ina ia mafai ona ou taitai mai o i latou ia talitonu i a'u upu.", "that I may lead them to believe in my words."]]},
  {num:30,words:[["Ma o lenei,", "And now,"], ["o manatu ia o Amona,", "these were the thoughts of Ammon,"], ["ina ua vaai atu o ia i puapuaga o i latou o e na ia taua o ona uso.", "when he saw the afflictions of those whom he termed to be his brethren."]]},
  {num:31,words:[["Ma sa oo ina ia faalototeteleina i latou i ana upu,", "And it came to pass that he flattered them by his words,"], ["ua fai atu:", "saying:"], ["O'u uso e,", "My brethren,"], ["ia outou lototetele ma ia tatou o e saili mai lafu manu,", "be of good cheer and let us go in search of the flocks,"], ["ma o le a tatou faapotopoto faatasi mai i latou ma toe aumai i latou i le nofoaga o le vai;", "and we will gather them together and bring them back unto the place of water;"], ["ma o le a faapea ona tatou faasaoina ai lafu manu mo le tupu ma o le a ia le fasiotia ai i tatou.", "and thus we will preserve the flocks unto the king and he will not slay us."]]},
  {num:32,words:[["Ma sa oo ina latou o atu e saili mai lafu manu,", "And it came to pass that they went in search of the flocks,"], ["ma sa latou mulimuli atu ia Amona,", "and they did follow Ammon, and they rushed forth with much swiftness and did head the flocks of the king,"], ["ma sa latou taufetuli atu ma le vave tele ma sisio mai lafu manu a le tupu ma toe faapotopoto faatasi mai i latou i le nofoaga o le vai.", "and did gather them together again to the place of water."]]},
  {num:33,words:[["Ma sa toe tutu mai na tagata e faasalalau a latou lafu manu;", "And those men again stood to scatter their flocks;"], ["peitai sa fai atu Amona i ona uso:", "but Ammon said unto his brethren:"], ["Siosio faataamilo le lafu manu ina ia le sosola;", "Encircle the flocks round about that they flee not;"], ["ma o le a ou alu atu e fetapai ma tagata ia o e ua latou faasalalauina a tatou lafu manu.", "and I go and contend with these men who do scatter our flocks."]]},
  {num:34,words:[["O lea sa latou faia e pei ona faatonuina ai i latou e Amona,", "Therefore,"], ["ma ua alu atu o ia ma tu e fetapai ma i latou o e na tutu i tafatafa o vai o Sevusa;", "they did as Ammon commanded them, and he went forth and stood to contend with those who stood by the waters of Sebus;"], ["ma sa le toaitiiti lo latou aofai.", "and they were in number not a few."]]},
  {num:35,words:[["O lea sa latou lē fefefe ia Amona,", "Therefore they did not fear Ammon,"], ["ona sa latou manatu e mafai e le toatasi o o latou tagata ona fasioti ia te ia e tusa ma la latou filifiliga,", "for they supposed that one of their men could slay him according to their pleasure,"], ["ona sa latou le iloa sa folafola mai le Alii ia Mosaea o le a ia laveaiina ona atalii mai o latou lima;", "for they knew not that the Lord had promised Mosiah that he would deliver his sons out of their hands;"], ["pe sa latou iloa foi se mea e uiga i le Alii;", "neither did they know anything concerning the Lord;"], ["o lea sa latou fiafia ai i le faaumatiaina o o latou uso;", "therefore they delighted in the destruction of their brethren;"], ["ma o le pogai lea na latou tutu mai ai e faasalalau lafu manu a le tupu.", "and for this cause they stood to scatter the flocks of the king."]]},
  {num:36,words:[["Peitai sa tu atu Amona ma amata ona ia sasau atu o maa ia te i latou i lana maata;", "But Ammon stood forth and began to cast stones at them with his sling;"], ["ioe sa ia liai atu maa ma le mana malosi i totonu o i latou;", "yea,"], ["ma sa faapea ona ia fasiotia ai o se aofai faapitoa o i latou,", "with mighty power he did sling stones amongst them;"], ["sa oo ina amata ona latou ofo i lona mana;", "and thus he slew a certain number of them insomuch that they began to be astonished at his power;"], ["e ui i lea sa latou feita ona o o latou uso ua fasiotia,", "nevertheless they were angry because of the slain of their brethren,"], ["ma sa latou mauai ia faapau o ia;", "and they were determined that he should fall;"], ["o lea,", "therefore,"], ["ina ua vaai ua le mafai ona lavea o ia ia latou maa,", "seeing that they could not hit him with their stones,"], ["sa latou o mai i luma ma a latou uatogi e fasioti o ia.", "they came forth with clubs to slay him."]]},
  {num:37,words:[["Ae faauta,", "But behold,"], ["o tagata uma taitoatasi na sii i luga lana uatogi e ta Amona,", "every man that lifted his club to smite Ammon,"], ["sa ia sala ese o latou lima i lana pelu;", "he smote off their arms with his sword;"], ["ona sa ia talitalia a latou ta i le ta o o latou lima i le mata o lana pelu,", "for he did withstand their blows by smiting their arms with the edge of his sword,"], ["sa oo ina amata ona latou ofo,", "insomuch that they began to be astonished,"], ["ma amata ona sosola mai ona luma;", "and began to flee before him;"], ["ioe,", "yea,"], ["ma sa le toaitiiti lo latou aofai;", "and they were not few in number;"], ["ma sa ia faia ia latou sosola ese e ala i le malosi o lona lima.", "and he caused them to flee by the strength of his arm."]]},
  {num:38,words:[["O lenei e toaono i latou na pauu i le maata,", "Now six of them had fallen by the sling,"], ["ae sa ia lei fasiotia se tasi i lana pelu vagana ai lo latou taitai;", "but he slew none save it were their leader with his sword;"], ["ma sa ia sala ese le tele o o latou lima na sii mai e faasaga ia te ia,", "and he smote off as many of their arms as were lifted against him,"], ["ma sa le toaitiiti i latou.", "and they were not a few."]]},
  {num:39,words:[["Ma ina ua uma ona ia tutuli mamao i latou,", "And when he had driven them afar off,"], ["sa ia toe foi mai ma latou faafeinu a latou lafu manu ma toe faafoi atu i latou i fanua faatataa manu a le tupu,", "he returned and they watered their flocks and returned them to the pasture of the king,"], ["ma ona latou o atu ai lea i le tupu,", "and then went in unto the king,"], ["ma avatu lima na sala ese i le pelu a Amona,", "bearing the arms which had been smitten off by the sword of Ammon,"], ["o i latou o e na saili e fasioti ia te ia;", "of those who sought to slay him;"], ["ma avatu i latou i totonu i le tupu mo se molimau o mea na latou faia.", "and they were carried in unto the king for a testimony of the things which they had done."]]},
];
renderVerseSet(al_ch_17_Verses, 'al-ch17-verses');

var al_ch_18_Verses = [
  {num:1,words:[["Ma sa oo ina faatonu atu le tupu o Lamonae ia tutulai mai ana auauna ma molimau mai i mea uma ia sa latou vaai i ai e uiga i le mataupu.", "And it came to pass that king Lamoni caused that his servants should stand forth and testify to  all the things which they had seen concerning the matter."]]},
  {num:2,words:[["Ma ina ua uma ona latou molimau atu uma i mea na latou vaai i ai,", "And when they had all testified to the things which they had seen,"], ["ma ua iloa ai e ia le faamaoni o Amona i le faasaoina o ana lafu manu,", "and he had learned of the faithfulness of Ammon in preserving his flocks,"], ["ma e uiga foi i lona mana tele i le fepaiaiga e tetee atu ia te i latou o e na saili e fasioti ia te ia,", "and also of his great power in contending against those who sought to slay him,"], ["sa ofo tele o ia,", "he was astonished exceedingly,"], ["ma fai mai:", "and said:"], ["E moni lava,", "Surely,"], ["ua sili atu lenei nai lo o se tagata. Faauta,", "this is more than a man. Behold,"], ["pe le o le Agaga Silisili ea lenei o le ua ia auina mai faasalaga tetele faapea i luga o lenei nuu,", "is not this the Great Spirit who doth send such great punishments upon this people,"], ["ona o lo latou fasioti tagata?", "because of their murders?"]]},
  {num:3,words:[["Ma sa latou tali atu i le tupu,", "And they answered the king,"], ["ma fai atu:", "and said:"], ["Pe o ia o le Agaga Silisili po o se tagata,", "Whether he be the Great Spirit or a man,"], ["matou te le iloa;", "we know not;"], ["ae ona pau lenei o le mea ua matou iloa,", "but this much we do know,"], ["e le mafai ona fasiotia o ia e fili o le tupu;", "that he cannot be slain by the enemies of the king;"], ["pe mafai foi ona latou faataapeapeina o lafu manu a le tupu pe a faatasi o ia ma i matou,", "neither can they scatter the king's flocks when he is with us,"], ["ona o lona atamai ma lona malosi tele;", "because of his expertness and great strength;"], ["o lea,", "therefore,"], ["ua matou iloa ai o ia o se uo a le tupu. Ma o lenei,", "we know that he is a friend to the king. And now,"], ["le tupu e,", "O king,"], ["matou te le talitonu ua i ai i se tagata se mana tele faapea,", "we do not believe that a man has such great power,"], ["ona ua matou iloa e le mafai ona fasiotia o ia.", "for we know he cannot be slain."]]},
  {num:4,words:[["Ma o lenei,", "And now,"], ["ina ua uma ona faalogo mai o le tupu i nei upu,", "when the king heard these words,"], ["sa ia fai mai ia te i latou:", "he said unto them:"], ["Ua ou iloa nei o ia o le Agaga Silisili;", "Now I know that it is the Great Spirit;"], ["ma ua afio mai o ia i le taimi nei e faasao o outou ola,", "and he has come down at this time to preserve your lives,"], ["ina ia le mafai ona ou fasioti ia te outou e pei ona sa ou faia i o outou uso. O lenei o le Agaga Silisili lenei na tautatala e uiga i ai o tatou tamā.", "that I might not slay you as I did your brethren. Now this is the Great Spirit of whom our fathers have spoken."]]},
  {num:5,words:[["O lenei o le uputuu lenei a Lamonae,", "Now this was the tradition of Lamoni,"], ["lea na ia maua mai i lona tamā,", "which he had received from his father,"], ["e faapea ua i ai se Agaga Silisili.", "that there was a Great Spirit."], ["Peitai e ui ina sa latou talitonu i se Agaga Silisili,", "Notwithstanding they believed in a Great Spirit they supposed that whatso– ever they did was right;"], ["sa latou manatu o soo se mea sa latou faia ua sa'o;", "nevertheless,"], ["e ui i lea, sa amata ona matau tele Lamonae,", "Lamoni began to fear exceedingly,"], ["i le fefe ne'i meaane ua ia faia le mea sese i le fasioti o ana auauna;", "with fear lest he had done wrong in slaying his servants;"]]},
  {num:6,words:[["Aua sa ia fasiotia le toatele o i latou ona sa faasalalauina e o latou uso a latou lafu manu i le nofoaga o le vai;", "For he had slain many of them because their brethren had scattered their flocks at the place of water;"], ["ma o lea,", "and thus,"], ["na fasioti ai i latou ona sa latou tuu a latou lafu manu ia faasalalauina.", "because they had had their flocks scattered they were slain."]]},
  {num:7,words:[["O lenei sa avea ma masani a nei sa Lamanā le tutu i tafatafa o vai o Sevusa e faasalalau lafu manu a tagata,", "Now it was the practice of these Lamanites to stand by the waters of Sebus to scatter the flocks of the people,"], ["ina ia mafai ona latou tutuli ese atu ai i o latou lava laueleele le tele o manu e faasalalauina,", "that thereby they might drive away many that were scattered unto their own land,"], ["ona o se masani lea o le faia o le vete i totonu o i latou.", "it being a practice of plunder among them."]]},
  {num:8,words:[["Ma sa oo ina fesili mai le tupu o Lamonae i ana auauna,", "And it came to pass that king Lamoni inquired of his servants,"], ["fai mai:", "saying:"], ["O fea o i ai lenei tagata ua i ai lena mana tele faapea?", "Where is this man that has such great power?"]]},
  {num:9,words:[["Ma sa latou fai atu ia te ia:", "And they said unto him:"], ["Faauta,", "Behold,"], ["o loo fafaga e ia au solofanua. O lenei sa poloaiina e le tupu ana auauna,", "he is feeding thy horses. Now the king had commanded his servants,"], ["ae lei oo i le taimi lea na faainu ai a latou lafu manu,", "previous to the time of the watering of their flocks,"], ["ia latou saunia ana solofanua ma ana kariota,", "that they should prepare his horses and chariots,"], ["ma momoli atu o ia i le laueleele o Nifae;", "and conduct him forth to the land of Nephi;"], ["ona sa i ai se aiga tele sa filifilia e faia i le laueleele o Nifae,", "for there had been a great feast appointed at the land of Nephi,"], ["e le tamā o Lamonae,", "by the father of Lamoni,"], ["o le sa tupu i le laueleele atoa.", "who was king over all the land."]]},
  {num:10,words:[["O lenei ina ua faalogo mai le tupu o Lamonae o loo sauni e Amona ana solofanua ma ana kariota sa atili ofo o ia,", "Now when king Lamoni heard that Ammon was preparing his horses and his chariots he was more astonished,"], ["ona o le faamaoni o Amona,", "because of the faithfulness of Ammon,"], ["ua fai mai:", "saying:"], ["E moni e lei i ai lava se auauna i totonu o au auauna uma sa faamaoni e pei o lenei tagata;", "Surely there has not been any servant among all my servants that has been so  faithful as this man;"], ["ona e oo i au poloaiga uma ua ia manatua ia faia i latou.", "for even he doth remember all my commandments to execute them."]]},
  {num:11,words:[["O lenei ua ou iloa moni lava o le Agaga Silisili lenei;", "Now I surely know that this is the Great Spirit,"], ["ma ou te manao ia te ia ia sau i totonu ia te au,", "and I would desire him that he come in unto me,"], ["ae ou te fefe.", "but I durst not."]]},
  {num:12,words:[["Ma sa oo ina ua uma ona saunia e Amona o solofanua ma kariota mo le tupu ma ana auauna,", "And it came to pass that when Ammon had made ready the horses and the chariots for the king and his servants,"], ["sa alu atu o ia i totonu i le tupu,", "he went in unto the king,"], ["ma sa vaai atu o ia ua sui foliga o le tupu;", "and he saw that the countenance of the king was changed;"], ["o lea na ia tau foi ai i fafo mai ona luma.", "therefore he was about to return out of his presence."]]},
  {num:13,words:[["Peitai sa fai mai se tasi o auauna a le tupu ia te ia,", "And one of the king's servants said unto him,"], ["Rapana e,", "Rabbanah,"], ["o lona uiga,", "which is,"], ["pe a faaliliuina,", "being interpreted,"], ["o le tupu mamana po o le tupu silisili,", "power– ful or great king,"], ["i lo latou manatu i o latou tupu ua mamana lava i latou;", "considering their kings to be powerful;"], ["ma sa faapea ona ia fai atu ia te ia:", "and thus he said unto him:"], ["Rapana e,", "Rabbanah,"], ["ua finagalo le tupu ia e nofo mai.", "the king desireth thee to stay."]]},
  {num:14,words:[["O lea na liliu atu ai e Amona o ia lava i le tupu,", "Therefore Ammon turned himself unto the king,"], ["ma fai atu ia te ia:", "and said unto him:"], ["Le tupu e,", "What wilt thou that I should do for thee,"], ["o se a se mea ua e finagalo i ai ou te faia mo oe? Ma sa le tali mai le tupu ia te ia mo le va o se itula,", "O king? And the king answered him not for the space of an hour,"], ["e tusa ma la latou taimi,", "according to their time,"], ["ona sa le iloa e ia se mea e tatau ona ia fai mai ia te ia.", "for he knew not what he should say unto him."]]},
  {num:15,words:[["Ma sa oo ina toe fai atu Amona ia te ia:", "And it came to pass that Ammon said unto him again:"], ["O le a se mea ua e finagalo i ai mai ia te au? Peitai sa le tali mai lava le tupu ia te ia.", "What desirest thou of me? But the king answered him not."]]},
  {num:16,words:[["Ma sa oo ina ua faatumuina Amona i le Agaga o le Atua,", "And it came to pass that Ammon, being filled with the Spirit of God,"], ["o lea na ia iloa ai manatu o le tupu.", "therefore he perceived the thoughts of the king."], ["Ma sa ia fai atu ia te ia:", "And he said unto him:"], ["Pe ona ua e faafofoga ea sa ou puipuia au auauna ma au lafu manu,", "Is it because thou hast heard that I defended thy servants and thy flocks,"], ["ma fasioti le toafitu o o latou uso i le maata ma le pelu,", "and slew seven of their brethren with the sling and with the sword,"], ["ma sala ese lima o isi,", "and smote off the arms of others,"], ["ina ia puipuia ai au lafu manu ma au auauna;", "in order to defend thy flocks and thy servants;"], ["faauta,", "behold,"], ["o le pogai ea lenei ua e ofo ai?", "is it this that causeth thy marvelings?"]]},
  {num:17,words:[["Ou te fai atu ia te oe,", "I say unto you,"], ["o le a ea le mea,", "what is it,"], ["ua e ofo tele ai faapea? Faauta,", "that thy marvelings are so great? Behold,"], ["o au o se tagata,", "I am a man,"], ["ma o au o lau auauna;", "and am thy servant;"], ["o lea,", "therefore,"], ["soo se mea e te finagalo i ai ua sa'o,", "whatsoever thou desirest which is right,"], ["o le mea lena ou te faia.", "that will I do."]]},
  {num:18,words:[["O lenei ina ua faalogo mai le tupu i nei upu,", "Now when the king had heard these words,"], ["sa toe ofo o ia,", "he marveled again,"], ["ona ua iloa e ia ua mafai e Amona ona iloa ona mafaufauga;", "for he beheld that Ammon could discern his thoughts;"], ["ae e ui i lea,", "but notwithstanding this,"], ["sa tatala e le tupu o Lamonae lona fofoga,", "king Lamoni did open his mouth,"], ["ma fai mai ia te ia:", "and said unto him:"], ["O ai ea oe? O oe ea o le Agaga Silisili lena,", "Who art thou? Art thou that Great Spirit,"], ["o le ua ia silafiaina mea uma?", "who knows all things?"]]},
  {num:19,words:[["Sa tali atu Amona ma fai atu ia te ia:", "Ammon answered and said unto him:"], ["E le o au lea.", "I am not."]]},
  {num:20,words:[["Ma sa fai mai le tupu:", "And the king said:"], ["E faapefea ona e iloa mafaufauga o lo'u loto? E mafai ona e tautala mai ma le lototele,", "How knowest thou the thoughts of my heart? Thou mayest speak boldly,"], ["ma faamatala mai ia te au e uiga i nei mea; ma faamatala mai foi ia te au po o le a le mana na e fasiotia ma sala ese ai lima o o'u uso,", "and tell me concerning these things;"], ["o e na faataapeapeina a'u lafu manu—", "and also tell me by what power ye slew and smote off the arms of my brethren that scattered my flocks—"]]},
  {num:21,words:[["Ma o lenei,", "And now,"], ["afai e te faamatala mai nei mea ia te au,", "if thou wilt tell me concerning these things,"], ["soo se mea e te manao i ai ou te avatu ia te oe;", "whatsoever thou desirest I will give unto thee;"], ["ma afai e manaomia ai,", "and if it were needed,"], ["ou te leoleoina oe i au autau; peitai ua ou iloa ua sili atu lou mamana nai lo i latou uma;", "I would guard thee with my armies;"], ["e ui i lea,", "but I know that thou art more powerful than all they;"], ["soo se mea e te manao i ai mai ia te au,", "nevertheless,"], ["ou te tuu atu ia te oe.", "whatsoever thou desirest of me I will grant it unto thee."]]},
  {num:22,words:[["O lenei ona sa poto Amona,", "Now Ammon being wise,"], ["ae sa le gaoia,", "yet harmless,"], ["sa ia fai atu ai ia Lamonae:", "he said unto Lamoni:"], ["E te faafofoga mai i a'u upu,", "Wilt thou hearken unto my words,"], ["pe afai ou te faamatala atu ia te oe po o le a le mana na ou faia ai nei mea? Ma o le mea lenei ou te manao i ai mai ia te oe.", "if I tell thee by what power I do these things? And this is the thing that I desire of thee."]]},
  {num:23,words:[["Ma sa tali mai le tupu ia te ia,", "And the king answered him,"], ["ma fai mai:", "and said:"], ["Ioe,", "Yea,"], ["o le a ou talitonu i au upu uma. Ma sa faapea ona maua o ia i le taufaasee.", "I will believe all thy words. And thus he was caught with guile."]]},
  {num:24,words:[["Ma sa amata ona tautala atu o Amona ia te ia ma le lototele ,", "And Ammon began to speak unto him with boldness,"], ["ma fai atu ia te ia:", "and said unto him:"], ["E te talitonu ea e i ai se Atua?", "Believest thou that there is a God?"]]},
  {num:25,words:[["Ma sa tali mai o ia,", "And he answered,"], ["ma fai mai ia te ia:", "and said unto him:"], ["Ou te le iloa le uiga o lena mea.", "I do not know what that meaneth."]]},
  {num:26,words:[["Ma ona fai atu lea o Amona:", "And then Ammon said:"], ["E te talitonu ea o loo i ai se Agaga Silisili?", "Believest thou that there is a Great Spirit?"]]},
  {num:27,words:[["Ma sa fai mai o ia,", "And he said,"], ["Ioe.", "Yea."]]},
  {num:28,words:[["Ma sa fai atu Amona:", "And Ammon said:"], ["O le Atua lena. Ma sa toe fai atu Amona ia te ia:", "This is God. And Ammon said unto him again:"], ["E te talitonu ea o lenei Agaga Silisili,", "Believest thou that this Great Spirit,"], ["o lē o le Atua lea,", "who is God,"], ["na foafoaina mea uma ua i le lagi ma i le lalolagi?", "created all things which are in heaven and in the earth?"]]},
  {num:29,words:[["Ma sa tali mai o ia:", "And he said:"], ["Ioe,", "Yea,"], ["ou te talitonu o ia na foafoaina mea uma ua i le lalolagi;", "I believe that he created all things which are in the earth;"], ["ae ou te le iloa le lagi.", "but I do not know the heavens."]]},
  {num:30,words:[["Ma sa fai atu Amona ia te ia:", "And Ammon said unto him:"], ["O le lagi o se nofoaga lea ua afio ai le Atua ma ana agelu paia uma.", "The heavens is a place where God dwells and all his holy angels."]]},
  {num:31,words:[["Ma sa fai mai le tupu o Lamonae:", "And king Lamoni said:"], ["Pe ua i luga a'e ea o le lalolagi?", "Is it above the earth?"]]},
  {num:32,words:[["Ma sa fai atu Amona:", "And Ammon said:"], ["Ioe,", "Yea,"], ["ma ua silasila mai o ia i lalo i le fanauga uma a tagata;", "and he looketh down upon all the children of men;"], ["ma ua silafia e ia mafaufauga ma faamoemoega uma o le loto;", "and he knows all the thoughts and intents of the heart;"], ["aua o lona aao na foafoaina ai i latou uma lava mai i le amataga.", "for by his hand were they all created from the beginning."]]},
  {num:33,words:[["Ma sa fai mai le tupu o Lamonae:", "And king Lamoni said:"], ["Ou te talitonu i nei mea uma ua e tautala mai ai. Pe na auina mai ea oe mai le Atua?", "I believe all these things which thou hast spoken. Art thou sent from God?"]]},
  {num:34,words:[["Sa fai atu Amona ia te ia:", "Ammon said unto him:"], ["O au o se tagata;", "I am a man;"], ["ma o le tagata i le amataga sa foafoaina e tusa ma foliga o le Atua,", "and man in the beginning was created after the image of God,"], ["ma ua valaaulia au e lona Agaga Paia ou te aoao atu nei mea i lenei nuu,", "and I am called by his Holy Spirit to teach these things unto this people,"], ["ina ia mafai ona aumai i latou i le malamalama o mea ua tonu ma moni;", "that they may be brought to a knowledge of that which is just and true;"]]},
  {num:35,words:[["Ma ua nofo i totonu ia te au se vaega o lena Agaga ,", "And a portion of that Spirit dwelleth in me,"], ["lea ua ia tuuina mai ia te au le malamalama ,", "which giveth me knowledge,"], ["ma le mana foi e tusa ma lo'u faatuatua ma manaoga ia ua i ai i le Atua.", "and also power according to my faith and desires which are in God."]]},
  {num:36,words:[["O lenei ina ua uma ona fai atu e Amona nei upu,", "Now when Ammon had said these words,"], ["sa ia amata mai i le foafoaga o le lalolagi,", "he began at the creation of the world,"], ["ma le foafoaga foi o Atamu,", "and also the creation of Adam,"], ["ma faamatala atu ia te ia mea uma e uiga i le pau o le tagata,", "and told him all the things concerning the fall of man,"], ["ma faamatala ma fola atu i ona luma talafaamaumau ma tusitusiga paia a le nuu,", "and rehearsed and laid before him the records and the holy scriptures of the people, which had been spoken by the prophets,"], ["ia na fetalaia e perofeta ,", "even down to the time that their father,"], ["seia oo mai i lalo i le taimi na tuua ai e lo latou tamā o Liae,", "Lehi,"], ["Ierusalema.", "left Jerusalem."]]},
  {num:37,words:[["Ma sa ia faamatala atu foi ia te i latou (ona o le tupu ma ana auauna sa tautala atu i ai) malaga uma a o latou tamā i le vao,", "And he also rehearsed unto them (for it was unto the king and to his servants) all the journeyings of their fathers in the wilderness,"], ["ma o latou mafatiaga uma i le fia aai ma le fia feinu,", "and all their sufferings with hunger and thirst,"], ["ma o latou puapuaga,", "and their travail,"], ["ma isi mea faapena.", "and so forth."]]},
  {num:38,words:[["Ma sa ia faamatala atu foi ia te i latou e uiga i fouvalega a Lamana ma Lemuelu,", "And he also rehearsed unto them concerning the rebellions of Laman and Lemuel,"], ["ma atalii o Isamaeli,", "and the sons of Ishmael,"], ["ioe,", "yea,"], ["o a latou fouvalega uma sa ia faamatala atu ia te i latou;", "all their rebellions did he  relate unto them;"], ["ma sa ia faamalamalama atu foi ia te i latou talafaamaumau ma tusitusiga paia uma mai le taimi na tuua ai e Liae Ierusalema seia oo mai i lalo i le taimi nei.", "and he expounded unto them all the records and scriptures from the time that Lehi left Jerusalem down to the present time."]]},
  {num:39,words:[["Ae sa le ona pau lea;", "But this is not all;"], ["ona sa ia faamalamalama atu foi ia te i latou le fuafuaga o le togiola,", "for he expounded unto them the plan of redemption,"], ["lea na saunia mai le faavaega o le lalolagi;", "which was prepared from the foundation of the world;"], ["ma sa ia faailoa atu foi ia te i latou e uiga i le afio mai o Keriso,", "and he also made known unto them concerning the coming of Christ,"], ["ma sa ia faailoa atu ia te i latou galuega uma a le Alii.", "and all the works of the Lord did he make known unto them."]]},
  {num:40,words:[["Ma sa oo ina ua uma ona fai atu e ia nei mea uma,", "And it came to pass that after he had said all these things,"], ["ma faamalamalama atu ia mea i le tupu,", "and expounded them to the king,"], ["sa oo ina talitonu le tupu i ana upu uma.", "that the king believed all his words."]]},
  {num:41,words:[["Ma sa amata ona ia tagi atu i le Alii,", "And he began to cry unto the Lord,"], ["ua fai atu:", "saying:"], ["Le Alii e,", "O Lord,"], ["ia e alofa mutimutivale mai; ia i ai i o'u luga,", "have mercy;"], ["ma luga o lo'u nuu,", "according to thy abundant mercy which thou hast had upon the people of Nephi,"], ["lou alofa mutimutivale,", "have upon me,"], ["e tusa ma lou alofa mutimutivale tele ua i ai ia te oe i luga o le nuu o Nifae.", "and my people."]]},
  {num:42,words:[["Ma o lenei,", "And now,"], ["ina ua uma ona fai mai e ia nei upu,", "when he had said this,"], ["sa pau o ia i le eleele,", "he fell unto the earth,"], ["e peiseai ua oti o ia.", "as if he were dead."]]},
  {num:43,words:[["Ma sa oo ina ave o ia e ana auauna ma avatu o ia i totonu i lana masiofo,", "And it came to pass that his servants took him and carried him in unto his wife,"], ["ma faataoto o ia i luga o se moega;", "and laid him upon a bed;"], ["ma sa taoto o ia mo le va o ao e lua ma po e lua e peiseai ua oti o ia;", "and he lay as if he were dead for the space of two days and two nights;"], ["ma sa fetagisi faanoanoa lana masiofo,", "and his wife,"], ["ma ona atalii,", "and his sons,"], ["ma ona afafine i ona luga,", "and his daughters mourned over him,"], ["e tusa ma le tu a sa Lamanā,", "after the manner of the Lamanites,"], ["ua fetagisi aueue lava i le toesea o ia.", "greatly lamenting his loss."]]},
];
renderVerseSet(al_ch_18_Verses, 'al-ch18-verses');

var al_ch_19_Verses = [
  {num:1,words:[["Ma sa oo ina ua mavae ao e lua ma po e lua sa latou faia o le a ave lona tino ma tuu i se tuugamau,", "And it came to pass that after two days and two nights they were about to take his body and lay it in a sepulchre,"], ["lea sa latou faia mo le faamoemoe e tanu ai o latou tagata oti.", "which they had made for the purpose of burying their dead."]]},
  {num:2,words:[["O lenei ina ua faalogo le masiofo i le tautaua o Amona,", "Now the queen having heard of the fame of Ammon,"], ["o lea na ia auina atu ai se feau ia te ia ma manao ia sau o ia i totonu ia te ia.", "therefore she sent and desired that he should come in unto her."]]},
  {num:3,words:[["Ma sa oo ina faia e Amona e pei ona poloaiina ai o ia,", "And it came to pass that Ammon did as he was commanded,"], ["ma ua alu atu i totonu i le masiofo,", "and went in unto the queen,"], ["ma fia iloa po o le a le mea ua ia finagalo i ai na te faia.", "and desired to know what she would that he should do."]]},
  {num:4,words:[["Ma sa ia fai mai ia te ia:", "And she said unto him:"], ["Sa faailoa mai ia te au e auauna a lau tane e faapea o oe o se perofeta a se Atua paia,", "The servants of my husband have made it known unto me that thou art a prophet of a holy God,"], ["ma ua ia te oe le mana e fai ai galuega mamana e tele i lona suafa;", "and that thou hast power to do many mighty works in his name;"]]},
  {num:5,words:[["O lea,", "Therefore,"], ["afai o le tulaga lea,", "if this is the case,"], ["ou te manao ia e maliu atu i totonu ma silasila i lau tane,", "I would that ye should go in and see my husband,"], ["ona ua taoto nei o ia i luga o lona moega mo le va o ao e lua ma po e lua;", "for he has been laid upon his bed for the space of two days and two nights;"], ["ma ua fai mai ni isi e lei oti o ia,", "and some say that he is not dead,"], ["ae fai mai isi ua oti o ia ma ua manogi,", "but others say that he is dead and that he stinketh,"], ["ma ua tatau ona tuu o ia i le tuugamau;", "and that he ought to be placed in the sepulchre;"], ["ae ia te au lava ia,", "but as for myself,"], ["e lei manogi o ia ia te au.", "to me he doth not stink."]]},
  {num:6,words:[["O lenei,", "Now,"], ["o le mea lenei sa manao i ai Amona,", "this was what Ammon desired,"], ["ona sa ia iloa ua i ai le tupu o Lamonae i lalo o le mana a le Atua;", "for he knew that king Lamoni was under the power of God;"], ["sa ia iloa o loo to ese le veli pogisa o le le talitonu mai lona mafaufau,", "he knew that the dark veil of unbelief was being cast away from his mind,"], ["ma o le malamalama lea ua faamalamalamaina ai lona mafaufau,", "and the light which did light up his mind,"], ["o le malamalama lea o le mamalu o le Atua,", "which was the light of the glory of God,"], ["o se malamalama ofoofogia lea o lona agalelei—ioe,", "which was a marvelous light of his goodness—yea,"], ["o lenei malamalama sa faatumulia ai lona agaga i le olioli tele naua,", "this light had infused such joy into his soul,"], ["ua tafi ese ai le ao o le pogisa,", "the cloud of darkness having been dispelled,"], ["ma ua faamumū a'e ai i lona agaga le malamalama o le ola tumau-faavavau,", "and that the light of  everlasting life was lit up in his soul,"], ["ioe,", "yea,"], ["sa ia iloa o lenei mea ua lofituina ai lona tino natura,", "he knew that this had overcome his natural frame,"], ["ma ua segia ese atu ai o ia i la le Atua—", "and he was carried away in God—"]]},
  {num:7,words:[["O lea,", "Therefore,"], ["o le mea na manao mai ai le masiofo ia te ia ona pau lea o le mea na manao i ai.", "what the queen desired of him was his only desire."], ["O lea na alu atu ai o ia i totonu e vaai i le tupu e tusa ma le manao mai o le masiofo ia te ia;", "Therefore,"], ["ma sa vaai o ia i le tupu,", "he went in to see the king according as the queen had desired him; and he saw the king,"], ["ma sa ia iloa e lei maliu o ia.", "and he knew that he was not dead."]]},
  {num:8,words:[["Ma sa fai atu o ia i le masiofo:", "And he said unto the queen:"], ["E lei maliu o ia,", "He is not dead,"], ["ae o loo moe o ia i la le Atua,", "but he sleepeth in God,"], ["ma o le a toe tulai mai o ia i le aso a taeao;", "and on the morrow he shall rise again;"], ["o lea aua nei tanuina o ia.", "therefore bury him not."]]},
  {num:9,words:[["Ona fai atu lea o Amona ia te ia:", "And Ammon said unto her:"], ["E te talitonu ea i lenei mea? Ma sa fai mai o ia ia te ia:", "Believest thou this? And she said unto him:"], ["Ua leai se molimau o ia te au vagana ai lau upu,", "I have had no witness save thy word,"], ["ma le upu a a maua auauna;", "and the word of our servants;"], ["e ui i lea ou te talitonu o le a faapea lava e pei ona e fai mai.", "nevertheless I believe that it shall be according as thou hast said."]]},
  {num:10,words:[["Ma sa fai atu Amona ia te ia:", "And Ammon said unto her:"], ["Amuia lava oe ona o lou faatuatua tele;", "Blessed art thou because of thy exceeding faith;"], ["ou te fai atu ia te oe,", "I say unto thee,"], ["le tamaitai e,", "woman,"], ["e lei i ai lava se faatuatua tele faapea i totonu o tagata uma o sa Nifaē.", "there has not been such great faith among all the people of the Nephites."]]},
  {num:11,words:[["Ma sa oo ina leoleo o ia i luga o le moega o lana tane, mai le taimi lena seia oo mai i le taimi o le aso na sosoo ai,", "And it came to pass that she watched over the bed of her husband,"], ["lea na tau mai e Amona o le a tulai mai ai o ia.", "from that time even until that time on the morrow which Ammon had appointed that he should rise."]]},
  {num:12,words:[["Ma sa oo ina tulai mai o ia,", "And it came to pass that he arose,"], ["e tusa ma upu a Amona;", "according to the words of Ammon;"], ["ma a'o tulai a'e o ia,", "and as he arose,"], ["sa ia faaloloa mai lona lima i le fafine,", "he stretched forth his hand unto the woman,"], ["ma fai mai:", "and said:"], ["Ia faamanuina lava le suafa o le Atua,", "Blessed be the name of God,"], ["ma ia e manuia lava.", "and blessed art thou."]]},
  {num:13,words:[["Ona e pei ona mautinoa o loo e ola,", "For as sure as thou livest,"], ["faauta,", "behold,"], ["sa ou vaai i lo'u Togiola;", "I have seen my Redeemer;"], ["ma o le a afio mai o ia,", "and he shall come forth,"], ["ma fanau mai i se fafine ,", "and be born of a woman,"], ["ma o le a ia togiolaina tagata uma o e e talitonu i lona suafa. O lenei,", "and he shall redeem all mankind who believe on his name. Now,"], ["ina ua uma ona ia fai mai o nei upu,", "when he had said these words,"], ["sa malena a'e lona loto i totonu ia te ia,", "his heart was swollen within him,"], ["ma toe pau o ia i le olioli;", "and he sunk again with joy;"], ["ma sa pau foi le masiofo,", "and the queen also sunk down,"], ["ona ua lofituina i le Agaga.", "being overpowered by the Spirit."]]},
  {num:14,words:[["O lenei ina ua vaai atu Amona ua sasaa ifo le Agaga o le Alii e tusa ma ana tatalo i luga o sa Lamanā,", "Now Ammon seeing the Spirit of the Lord poured out according to his prayers upon the Lamanites,"], ["o ona uso,", "his brethren,"], ["o e sa avea ma pogai o le faanoanoa tele i totonu o sa Nifaē,", "who had been the cause of so much mourning among the Nephites,"], ["po o totonu o tagata uma o le Atua ona o a latou amioletonu ma a latou uputuu ,", "or among all the people of God because of their iniquities and their traditions,"], ["sa ia faapau ifo i luga o ona tulivae,", "he fell upon his knees,"], ["ma amata ona sasaa atu lona agaga i le tatalo ma le faafetai i le Atua mo mea na ia faia mo ona uso;", "and began to pour out his soul in prayer and thanksgiving to God for what he had done for his brethren;"], ["ma sa lofituina foi o ia i le olioli ;", "and he was also overpowered with joy;"], ["ma sa faapea ona pauu uma le toatolu o i latou i le eleele.", "and thus they all three had sunk to the earth."]]},
  {num:15,words:[["O lenei,", "Now,"], ["ina ua vaai atu auauna a le tupu ua latou pauu i lalo,", "when the servants of the king had seen that they had fallen,"], ["sa amata foi ona latou tagi atu i le Atua,", "they also began to cry unto God,"], ["ona ua oo mai foi le matatau i le Alii ia te i latou,", "for the fear of the Lord had come upon them also,"], ["ona o i latou ia sa tutu i luma o le tupu ma molimau atu ia te ia e uiga i le mana tele o Amona.", "for it was they who had stood before the king and testified unto him concerning the great power of Ammon."]]},
  {num:16,words:[["Ma sa oo ina latou valaau atu i le suafa o le Alii,", "And it came to pass that they did call on the name of the Lord,"], ["ma lo latou malosi,", "in their might,"], ["seia oo ina latou pauu uma i le eleele,", "even until they had all fallen to the earth,"], ["vagana ai se tasi o fafine sa Lamanā,", "save it were one of the Lamanitish women,"], ["o lona igoa o Apiso,", "whose name was Abish,"], ["o ia o se sa faaliliuina i le Alii i le tele o tausaga,", "she having been converted unto the Lord for many  years,"], ["ona o se faaaliga vaaia maoae a lona tamā—", "on account of a remarkable vision of her father—"]]},
  {num:17,words:[["O lea,", "Thus,"], ["ona ua liliu mai i le Alii,", "having been converted to the Lord,"], ["ma sa ia le faailoa atu lava,", "and never having made it known,"], ["o lea,", "therefore,"], ["ina ua ia vaai atu ua pauu uma auauna a Lamonae i le eleele,", "when she saw that all the servants of Lamoni had fallen to the earth,"], ["ma lona matai tamaitai foi,", "and also her mistress,"], ["le masiofo,", "the queen, and the king,"], ["ma o le tupu,", "and Ammon lay prostrate upon the earth,"], ["ma Amona ua taatitia fāō i luga o le eleele,", "she knew that it was the power of God;"], ["sa ia iloa o le mana lea o le Atua;", "and supposing that this opportunity,"], ["ma i le manatu o le avanoa lenei e faailoa atu ai i tagata mea na tutupu i totonu ia te i latou,", "by making known unto the people what had happened among them,"], ["o lo latou vaai i lenei vaaiga o le a uunaia ai i latou ia talitonu i le mana o le Atua,", "that by beholding this scene it would cause them to believe in the power of God,"], ["o lea na ia momoe atu ai mai lea fale i lea fale,", "therefore she ran forth from house to house,"], ["ma faailoa atu i tagata.", "making it known unto the people."]]},
  {num:18,words:[["Ma sa oo ina amata ona latou faapotopoto mai faatasi i latou lava i le maota o le tupu. Ma sa o mai se motu o tagata,", "And they began to assemble themselves together unto the house of the king. And there came a multitude,"], ["ma i lo latou ofo sa latou vaai atu ai i le tupu,", "and to their astonishment they beheld the king,"], ["ma le masiofo,", "and the queen,"], ["ma a laua auauna ua fāō i luga o le eleele,", "and their servants prostrate upon the earth,"], ["ma sa latou taatitia iina e peiseai ua feoti i latou;", "and they all lay there as though they were dead;"], ["ma sa latou vaai atu foi ia Amona,", "and they also saw Ammon,"], ["ma faauta,", "and behold,"], ["o ia o se sa Nifaē.", "he was a Nephite."]]},
  {num:19,words:[["Ma o lenei sa amata ona mumumumu o tagata i totonu o i latou lava;", "And now the people began to murmur among themselves;"], ["ua fai mai ni isi o se mea leaga tele lenei ua oo mai i o latou luga,", "some saying that it was a great evil that had come upon them,"], ["po o luga o le tupu ma lona auaiga,", "or upon the king and his house,"], ["ona ua ia tuu le sa Nifaē e nofo i le laueleele.", "because he had suffered that the Nephite should remain in the land."]]},
  {num:20,words:[["Ae o isi,", "But others rebuked them,"], ["ua tetee mai ia te i latou,", "saying:"], ["fai mai: Ua aumai e le tupu lenei leaga i lona auaiga,", "The king hath brought this evil upon his house,"], ["ona sa ia fasiotia ana auauna o e sa latou tuu ia faataapeapeina a latou lafu manu i vai o Sevusa.", "because he slew his servants who had had their flocks scattered at the waters of Sebus."]]},
  {num:21,words:[["Ma sa tetee mai foi ia te i latou tagata ia sa tutu i vai o Sevusa ma faataapeape lafu manu a le tupu,", "And they were also rebuked by those men who had stood at the waters of Sebus and scattered the flocks which belonged to the king,"], ["ona sa latou feita ia Amona ona o ni isi o o latou uso na ia fasiotia i vai o Sevusa,", "for they were angry with Ammon because of the number which he had slain of their brethren at the waters of Sebus,"], ["a'o puipuia e ia lafu manu a le tupu.", "while defending the flocks of the king."]]},
  {num:22,words:[["O lenei,", "Now,"], ["o se tasi o i latou ia,", "one of them,"], ["o le o lona uso lea na fasiotia i le pelu a Amona,", "whose brother had been slain with the sword of Ammon,"], ["ona o lona ita tele ia Amona,", "being exceedingly angry with Ammon,"], ["na sei ai lana pelu ma alu atu ia mafai ona ia faapauina i luga o Amona,", "drew his sword and went forth that he might let it fall upon Ammon,"], ["e fasioti ai o ia;", "to slay him;"], ["ma a'o ia sii a'e le pelu e ta ia te ia,", "and as he lifted the sword to smite him,"], ["faauta,", "behold,"], ["na pau o ia ua oti.", "he fell dead."]]},
  {num:23,words:[["O lenei ua tatou iloa sa le mafai ona fasiotia Amona,", "Now we see that Ammon could not be slain,"], ["ona sa fetalai mai le Alii ia Mosaea,", "for the Lord had said unto Mosiah,"], ["lona tamā:", "his father:"], ["O le a ou faasaoina o ia,", "I will spare him,"], ["o le a faia ia te ia e tusa ma lou faatuatua—o lea,", "and it shall be unto him according to thy faith—therefore,"], ["na tuufaatuatuaina atu ai o ia e Mosaea i le Alii.", "Mosiah trusted him unto the Lord."]]},
  {num:24,words:[["Ma sa oo ina ua vaai mai le motu o tagata ua pau le tagata lea ua oti,", "And it came to pass that when the multitude beheld that the man had fallen dead,"], ["o le na sii a'e lana pelu e fasioti ia Amona,", "who lifted the sword to slay Ammon,"], ["sa oo ifo le matatau i luga o i latou uma, ma sa latou fefefe e aapa atu o latou lima e pai ia te ia,", "fear came upon them all,"], ["po o soo se tasi o i latou o e ua pauu;", "and they durst not put forth their hands to touch him or any of those who had fallen;"], ["ma sa amata ona latou toe taufaiofo i totonu o i latou lava po o le a le mafuaaga o lenei mana tele,", "and they began to marvel again among themselves what could be the cause of this great power,"], ["pe o le a foi le uiga o nei mea uma.", "or what all these things could mean."]]},
  {num:25,words:[["Ma sa oo ina sa i ai se toatele i totonu o i latou o e na fai mai o Amona o le Agaga Silisili lea,", "And it came to pass that there were many among them who said that Ammon was the Great Spirit,"], ["ae sa fai mai isi na auina mai o ia e le Agaga Silisili;", "and others said he was sent by the Great Spirit;"]]},
  {num:26,words:[["Ae o isi, ua latou tetee atu ia i latou uma,", "But others rebuked them all,"], ["fai mai,", "saying that he was a monster,"], ["o ia o se sauai, o le ua auina mai e sa Nifaē e faamafatia mai ia i latou.", "who had been sent from the Nephites to torment them."]]},
  {num:27,words:[["Ma sa i ai ni isi sa fai mai o Amona na auina mai e le Agaga Silisili e faapuapuagatia i latou ona o a latou amioletonu;", "And there were some who said that Ammon was sent by the Great Spirit to afflict them because of their iniquities;"], ["ma o le Agaga Silisili lea sa i ai pea ia sa Nifaē,", "and that it was the Great Spirit that had always attended the Nephites,"], ["o le ua ia laveai pea i latou i fafo mai o latou lima;", "who had ever delivered them out of their hands;"], ["ma sa latou fai mai o le Agaga Silisili lenei o le na ia faaumatiaina le toatele o o latou uso,", "and they said that it was this Great Spirit who had destroyed so many of their brethren,"], ["sa Lamanā.", "the Lamanites."]]},
  {num:28,words:[["Ma sa faapea ona amata ona matua tetele o le finauga i totonu o i latou.", "And thus the contention began to be exceedingly sharp among them."], ["Ma a'o faapea ona latou fefinauai,", "And while they were thus contending,"], ["sa sau le auauna fafine o le na ala ai ona faapotopoto faatasi le motu o tagata,", "the woman servant who had caused the multitude to be gathered together came,"], ["ma ina ua vaai atu o ia i le finauga ua i ai i totonu o le motu o tagata, sa faanoanoa tele o ia,", "and when she saw the contention which was among the multitude she was exceedingly sorrowful,"], ["ua oo ina tagi.", "even unto tears."]]},
  {num:29,words:[["Ma sa oo ina alu atu o ia ma tago i le lima o le masiofo,", "And it came to pass that she went and took the queen by the hand,"], ["atonu pe mafai ona ia faatulai mai o ia mai le eleele;", "that perhaps she might raise her from the ground;"], ["ma o le vave lava na pai atu ai o ia i lona lima na tulai mai ai o ia ma ua tu i luga i ona vae, ma alaga i le leo tele,", "and as soon as she touched her hand she arose and stood upon her feet,"], ["fai mai:", "and cried with a loud voice,"], ["E,", "saying:"], ["Iesu e faamanuina, o le ua ia laveai au mai se seoli matautia! E,", "O blessed Jesus,"], ["le Atua e faamanuina,", "who has saved me from an awful hell! O blessed God,"], ["ia e alofa mutimutivale mai i lenei nuu!", "have mercy on this people!"]]},
  {num:30,words:[["Ma ina ua uma ona ia fai mai o nei upu,", "And when she had said this,"], ["sa opo e ia ona lima,", "she clasped her hands,"], ["i le tumu i le olioli,", "being filled with joy,"], ["ma tautala mai i upu e tele sa le malamalama i ai se tasi;", "speaking many words which were not understood;"], ["ma ina ua uma ona ia faia o lenei mea, sa tago atu o ia i le tupu,", "and when she had done this,"], ["o Lamonae,", "she took the king,"], ["i le lima,", "Lamoni,"], ["ma faauta ua tulai mai o ia,", "by the hand,"], ["ma ua tu i luga i ona vae.", "and behold he arose and stood upon his feet."]]},
  {num:31,words:[["Ma o ia,", "And he,"], ["i le taimi lava lea,", "immediately,"], ["i le vaai atu i le finauga ua i totonu o lona nuu,", "seeing the contention among his people,"], ["ua ia alu atu ma amata ona ia aoaiina i latou, ma aoao atu ia te i latou upu na ia faalogo i ai mai le fofoga o Amona;", "went forth and began to rebuke them,"], ["ma o le toatele o i latou sa faalogo i ana upu,", "and to teach them the words which he had heard from the mouth of Ammon;"], ["sa talitonu,", "and as many as heard his words believed,"], ["ma liliu mai i le Alii.", "and were converted unto the Lord."]]},
  {num:32,words:[["Peitai sa i ai le toatele i totonu o i latou o e sa le fia faalogo i ana upu;", "But there were many among them who would not hear his words;"], ["o lea sa latou o ese atu ai i o latou ala.", "therefore they went their way."]]},
  {num:33,words:[["Ma sa oo ina ua tulai mai Amona,", "And it came to pass that when Ammon arose he alsoadministered unto them,"], ["sa ia auauna atu foi ia te i latou,", "and also did all the servants of Lamoni;"], ["ma sa faapea foi ona faia e auauna uma a Lamonae; ma sa latou tautino uma atu i le nuu le mea e tasi—e faapea ua liua o latou loto;", "and they did all declare unto the people the selfsame thing—that their hearts had been changed;"], ["ua le toe i ai ia te i latou se manao e fai mea leaga.", "that they had no more desire to do evil."]]},
  {num:34,words:[["Ma faauta,", "And behold,"], ["e toatele sa latou tautino atu i le nuu,", "many did declare unto the people that they had seen angels and had conversed with them;"], ["sa latou vaai i agelu ma fetautalatalaai ma i latou; ma o lea na latou tau atu ai ia te i latou mea a le Atua,", "and thus they had told them things of God,"], ["ma lana amiotonu.", "and of his righteousness."]]},
  {num:35,words:[["Ma sa oo ina sa i ai le toatele sa talitonu ia latou upu;", "And it came to pass that there were many that did believe in their words;"], ["ma o le toatele na talitonu sa papatisoina ;", "and as many as did believe were baptized;"], ["ma sa oo ina avea i latou ma tagata amiotonu,", "and they became a righteous people,"], ["ma sa latou faatuina se aulotu i totonu o i latou.", "and they did establish a church among them."]]},
  {num:36,words:[["Ma sa faapea ona amata o le galuega a le Alii i totonu o sa Lamanā;", "And thus the work of the Lord did commence among the Lamanites;"], ["sa faapea ona amata ona liligi ifo e le Alii lona Agaga i luga o i latou; ma ua tatou vaai,", "thus the Lord did begin to pour out his Spirit upon them;"], ["ua faaloaloa mai lona aao i tagata uma o e e salamo ma talitonu i lona suafa.", "and we see that his arm is extended to all people who will repent and believe on his name."]]},
];
renderVerseSet(al_ch_19_Verses, 'al-ch19-verses');

var al_ch_20_Verses = [
  {num:1,words:[["Ma sa oo ina ua uma ona latou faatuina se aulotu i lena laueleele,", "And it came to pass that when they had established a church in that land,"], ["sa manao le tupu o Lamonae ia Amona la te o faatasi ma ia i le laueleele o Nifae,", "that king Lamoni desired that Ammon should go with him to the land of Nephi,"], ["ina ia mafai ona ia faailoa atu o ia i lona tamā.", "that he might show him unto his father."]]},
  {num:2,words:[["Ma sa oo mai le siufofoga o le Alii ia Amona,", "And the voice of the Lord came to Ammon saying:"], ["ua fetalai mai:", "Thou shalt not go up to the land of Nephi,"], ["Aua e te alu a'e i le laueleele o Nifae, aua faauta,", "for behold,"], ["o le a saili e le tupu lou ola;", "the king will seek thy life;"], ["ae ia e alu i le laueleele o Mitonae;", "but thou shalt go to the land of Middoni;"], ["aua faauta, o lou uso o Arona,", "for behold,"], ["ma Muloki foi ma Ama,", "thy brother Aaron,"], ["ua i ai i le falepuipui.", "and also Muloki and Ammah are in prison."]]},
  {num:3,words:[["O lenei sa oo ina ua faalogo Amona i lenei mea,", "Now it came to pass that when Ammon had heard this,"], ["sa ia fai atu ia Lamonae:", "he said unto Lamoni:"], ["Faauta, o lo'u uso ma le au uso,", "Behold,"], ["ua i ai i le falepuipui i Mitonae,", "my brother and brethren are in prison at Middoni,"], ["ma ou te alu ina ia mafai ona ou laveaiina i latou.", "and I go that I may deliver them."]]},
  {num:4,words:[["O lenei sa fai mai Lamonae ia Amona:", "Now Lamoni said unto Ammon:"], ["Ua ou iloa,", "I know,"], ["e mafai ona e faia o mea uma i le malosi o le Alii. Ae faauta,", "in the strength of the Lord thou canst do all things. But behold,"], ["o le a ou alu atu faatasi ma oe i le laueleele o Mitonae;", "I will go with thee to the land of Middoni;"], ["ona o le tupu o le laueleele o Mitonae,", "for the king of the land of Middoni,"], ["o lona igoa o Anetiomino,", "whose name is Antiomno,"], ["o se uo ia te au;", "is a friend unto me;"], ["o lea ou te alu atu ai i le laueleele o Mitonae,", "therefore I go to the land of Middoni,"], ["ina ia mafai ona ou faalupelupeina le tupu o le laueleele,", "that I may flatter the king of the land,"], ["ma o le a ia tatala ai i fafo ou uso mai le falepuipui . O lenei sa fai mai Lamonae ia te ia:", "and he will cast thy brethren out of prison. Now Lamoni said unto him:"], ["O ai na ia tau atu ia te oe ua i ai ou uso i le falepuipui?", "Who told thee that thy brethren were in prison?"]]},
  {num:5,words:[["Ma sa fai atu Amona ia te ia:", "And Ammon said unto him:"], ["E leai se tasi na ia tau mai ia te au,", "No one hath told me,"], ["vagana ai le Atua;", "save it be God;"], ["ma sa ia fetalai mai ia te au—Alu e laveai ou uso,", "and he said unto me—Go and deliver thy brethren,"], ["ona ua i ai i latou i le falepuipui i le laueleele o Mitonae.", "for they are in prison in the land of Middoni."]]},
  {num:6,words:[["O lenei ina ua faalogo mai Lamonae i lenei mea, sa ia faatonu atu ia saunia e ana auauna ana solofanua ma ana kariota.", "Now when Lamoni had heard this he caused that his servants should make ready his horses and his chariots."]]},
  {num:7,words:[["Ma sa ia fai mai ia Amona:", "And he said unto Ammon:"], ["Maliu mai ia,", "Come,"], ["o le a ou alu atu faatasi ma oe i le laueleele o Mitonae,", "I will go with thee down to the land of Middoni,"], ["ma o le a ou aioi atu i le tupu iina o le a ia tatala mai ai i fafo ou uso mai le falepuipui.", "and there I will plead with the king that he will cast thy brethren out of prison."]]},
  {num:8,words:[["Ma sa oo ina a'o malaga atu Amona ma Lamonae iina,", "And it came to pass that as Ammon and Lamoni were journeying thither,"], ["sa latou fetaui ma le tamā o Lamonae,", "they met the father of Lamoni,"], ["o le sa tupu i luga o le laueleele atoa.", "who was king over all the land."]]},
  {num:9,words:[["Ma faauta,", "And behold,"], ["sa fai mai le tamā o Lamonae ia te ia:", "the father of Lamoni said unto him:"], ["Aisea na e le sau ai i le aiga i le aso tele lena na ou faia ai se aiga mo o'u atalii uma,", "Why did ye not come to the feast on that great day when I made a feast unto my sons,"], ["ma mo lo'u nuu?", "and unto my people?"]]},
  {num:10,words:[["Ma sa ia fai mai foi:", "And he also said:"], ["O fea o le a e alu i ai ma lenei sa Nifaē,", "Whither art thou going with this Nephite,"], ["o se tasi o fanau a se tagata pepelo ?", "who is one of the children of a liar?"]]},
  {num:11,words:[["Ma sa oo ina faamatala atu e Lamonae ia te ia le mea o loo ia alu atu i ai,", "And it came to pass that Lamoni rehearsed unto him whither he was going,"], ["ona sa fefe o ia e faaita ia te ia.", "for he feared to offend him."]]},
  {num:12,words:[["Ma sa ia faamatala atu foi ia te ia le pogai atoa o lona nofo ai pea i lona lava malo,", "And he also told him all the cause of his tarrying in his own kingdom,"], ["na ia le alu atu ai i lona tamā i le aiga lea na ia sauniaina.", "that he did not go  unto his father to the feast which he had prepared."]]},
  {num:13,words:[["Ma o lenei ina ua uma ona faamatala atu e Lamonae nei mea uma ia te ia,", "And now when Lamoni had rehearsed unto him all these things,"], ["faauta,", "behold,"], ["i lona ofo tele,", "to his astonish– ment,"], ["sa ita mai lona tamā ia te ia,", "his father was angry with him,"], ["ma fai mai:", "and said:"], ["Lamonae,", "Lamoni,"], ["o le a e alu atu e laveai nei sa Nifaē,", "thou art going to deliver these Nephites,"], ["o e o atalii o se tagata pepelo. Faauta,", "who are sons of a liar. Behold,"], ["na ia faoa o tatou tamā;", "he robbed our fathers;"], ["ma o lenei ua o mai foi ana fanau i totonu o i tatou ina ia mafai,", "and now his children are also come amongst us that they may,"], ["e ala i lo latou faitogafiti ma a latou pepelo,", "by their cunning and their lyings,"], ["ona latou faasese i tatou,", "deceive us,"], ["ina ia mafai ona latou toe faoa i tatou ia tatou meatotino.", "that they again may rob us of our property."]]},
  {num:14,words:[["O lenei sa faatonu mai le tamā o Lamonae ia te ia, ia ona fasioti Amona i le pelu.", "Now the father of Lamoni commanded him that he should slay Ammon with the sword."], ["Ma sa ia faatonu mai foi ia te ia, ia aua ne'i alu atu o ia i le laueleele o Mitonae,", "And he also commanded him that he should not go to the land of Middoni,"], ["ae ia toe foi atu o ia faatasi ma ia i le laueleele o Isamaeli .", "but that he should return with him to the land of Ishmael."]]},
  {num:15,words:[["Peitai sa fai atu Lamonae ia te ia:", "But Lamoni said unto him:"], ["Ou te le fasiotia Amona,", "I will not slay Ammon,"], ["pe ou te toe foi atu i le laueleele o Isamaeli,", "neither will I return to the land of Ishmael,"], ["ae ou te alu i le laueleele o Mitonae ina ia mafai ona ou tatalaina uso o Amona,", "but I go to the land of Middoni that I may release the brethren of Ammon,"], ["ona ua ou iloa o i latou o ni tagata amiotonu ma ni perofeta paia a le Atua moni.", "for I know that they are just men and holy prophets of the true God."]]},
  {num:16,words:[["O lenei ina ua faalogo mai lona tamā i nei upu,", "Now when his father had heard these words,"], ["sa ita o ia ia te ia,", "he was angry with him,"], ["ma sa ia sei lana pelu ina ia mafai ona ia taiaina o ia i le eleele.", "and he drew his sword that he might smite him to the earth."]]},
  {num:17,words:[["Ae sa tu atu Amona ma fai atu ia te ia:", "But Ammon stood forth and said unto him:"], ["Faauta,", "Behold,"], ["aua e te fasioti i lou atalii;", "thou shalt not slay thy son;"], ["e ui i lea,", "neverthe– less,"], ["e sili ona lelei pe a pau o ia nai lo oe,", "it were better that he should fall than thee,"], ["aua faauta,", "for behold,"], ["ua salamo o ia i ana agasala;", "he has repented of his sins;"], ["ae afai e te pau i le taimi nei,", "but if thou shouldst fall at this time,"], ["i lou ita,", "in thine anger,"], ["e le mafai ona faaolaina lou agaga.", "thy soul could not be saved."]]},
  {num:18,words:[["O lenei foi,", "And again,"], ["e tatau lava ona e onosai;", "it is expedient that thou shouldst forbear;"], ["ona afai e te fasioti i lou atalii,", "for if thou shouldst slay thy son,"], ["ona o ia o se tagata le sala,", "he being an innocent man,"], ["o le a tagi a'e lona toto mai le eleele i le Alii lona Atua,", "his blood would cry from the ground to the Lord his God,"], ["mo se tauimasui ia oo mai i ou luga;", "for vengeance to come upon thee;"], ["ma atonu o le a fano ai lou agaga .", "and perhaps thou wouldst lose thy soul."]]},
  {num:19,words:[["O lenei ina ua uma ona fai atu e Amona nei upu ia te ia,", "Now when Ammon had said these words unto him,"], ["sa ia tali mai ia te ia,", "he answered him,"], ["fai mai:", "saying:"], ["Ua ou iloa afai ou te fasiotia lo'u atalii,", "I know that if I should slay my son,"], ["o le a ou faamaligiina le toto le sala;", "that I should shed innocent blood;"], ["aua o oe lea ua saili e faaumatia o ia.", "for it is thou that hast sought to destroy him."]]},
  {num:20,words:[["Ma sa ia faaloloa mai lona lima e fasioti Amona. Peitai sa talitali e Amona ana ta,", "And he stretched forth his hand to slay Ammon. But Ammon withstood his blows,"], ["ma ia ta foi lona lima sa le mafai ai ona ia faaaogaina.", "and also smote his arm that he could not use it."]]},
  {num:21,words:[["O lenei ina ua vaai atu le tupu e mafai e Amona ona fasioti o ia,", "Now when the king saw that Ammon could slay him,"], ["sa amata ona ia aioi mai ia Amona ia faasaoina e ia lona ola.", "he began to plead with Ammon that he would spare his life."]]},
  {num:22,words:[["Peitai sa sii e Amona lana pelu,", "But Ammon raised his sword,"], ["ma fai atu ia te ia:", "and said unto him:"], ["Faauta,", "Behold,"], ["o le a ou taiaina oe vagana ai ua e tuu mai ia te au ia mafai ona ou tatalaina i fafo o'u uso mai le falepuipui.", "I will smite thee except thou wilt grant unto me that my brethren may be cast out of prison."]]},
  {num:23,words:[["O lenei o le tupu,", "Now the king,"], ["i le fefe nei aveeseina lona ola,", "fearing he should lose his life,"], ["ua fai mai: Afai e te faasaoina au,", "said:"], ["o le a ou tuu atu ia te oe soo se mea e te fai mai ai,", "If thou wilt spare me I will grant unto thee whatsoever thou wilt ask,"], ["e oo lava i le afa o le malo.", "even to half of the kingdom."]]},
  {num:24,words:[["O lenei ina ua vaai atu Amona ua ia uunaia le tupu matua e tusa ma lona manao,", "Now when Ammon saw that he had wrought upon the old king according to his desire,"], ["sa ia fai atu ia te ia:", "he said  unto him:"], ["Afai e te tuu mai ia mafai ona tatala i fafo o'u uso mai le falepuipui,", "If thou wilt grant that my brethren may be cast out of prison,"], ["ma ia taofi foi e Lamonae lona malo,", "and also that Lamoni may retain his kingdom,"], ["ma ia aua e te toatamai ia te ia,", "and that ye be not displeased with him,"], ["ae tuu mai ia mafai ona ia faia e tusa ai ma ona lava manao i soo se mea e mafaufau i ai o ia,", "but grant that he may do according to his own desires in whatsoever thing he thinketh,"], ["ona ou faasaoina lea o oe;", "then will I spare thee;"], ["a leai o le a ou taiaina oe i le eleele.", "otherwise I will smite thee to the earth."]]},
  {num:25,words:[["O lenei ina ua uma ona fai atu e Amona nei upu,", "Now when Ammon had said these words,"], ["sa amata ona olioli le tupu mo lona ola.", "the king began to rejoice because of his life."]]},
  {num:26,words:[["Ma ina ua ia vaai atu ua leai se manao ia Amona e faaumatia o ia,", "And when he saw that Ammon had no desire to destroy him,"], ["ma ina ua ia vaai foi i le alofa tele o ia i lona atalii o Lamonae,", "and when he also saw the great love he had for his son Lamoni,"], ["sa ofo tele o ia,", "he was astonished exceedingly,"], ["ma fai mai:", "and said:"], ["Talu ai ona ua pau nei o mea ua e manao i ai,", "Because this is all that thou hast desired,"], ["ia ou tatalaina ou uso,", "that I would release thy brethren,"], ["ma tuu atu ia taofi pea e lou atalii o Lamonae lona malo,", "and suffer that my son Lamoni should retain his kingdom,"], ["faauta,", "behold,"], ["o le a ou tuu atu ia te oe ia taofi pea e lo'u atalii lona malo mai i le taimi nei ma le faavavau;", "I will grant unto you that my son may retain his kingdom from this time and forever;"], ["ma o le a ou le toe pulea o ia—", "and I will govern him no more—"]]},
  {num:27,words:[["Ma o le a ou tuu atu foi ia te oe ia mafai ona tatala i fafo ou uso mai le falepuipui,", "And I will also grant unto thee that thy brethren may be cast out of prison,"], ["ma ia mafai ona o mai o oe ma ou uso ia te au,", "and thou and thy brethren may come unto me,"], ["i lo'u malo;", "in my kingdom;"], ["ona o le a ou fia vaai tele ia te oe. Ona sa ofo tele le tupu i upu na ia tautala atu ai,", "for I shall greatly desire to see thee. For the king was greatly astonished at the words which he had spoken,"], ["ma upu foi na tautala atu ai lona atalii o Lamonae,", "and also at the words which had been spoken by his son Lamoni,"], ["o lea na ia manao ai e aoao i ai.", "therefore he was desirous to learn them."]]},
  {num:28,words:[["Ma sa oo ina faaauau e Amona ma Lamonae la laua malaga agai i le laueleele o Mitonae. Ma sa talileleia Lamonae i le silafaga a le tupu o le laueleele;", "And it came to pass that Ammon and Lamoni proceeded on their journey towards the land of Middoni. And Lamoni found favor in the eyes of the king of the land;"], ["o lea na aumai ai i fafo uso o Amona mai le falepuipui.", "therefore the brethren of Ammon were brought forth out of prison."]]},
  {num:29,words:[["Ma ina ua feiloai Amona ma i latou sa faanoanoa tele o ia,", "And when Ammon did meet them he was exceedingly sorrowful,"], ["ona faauta sa le lavalava i latou,", "for behold they were naked,"], ["ma sa aiaia tetele o latou pau ona sa saisaia i maea malolosi. Ma sa mafatia foi i latou i le fia 'ai,", "and their skins were worn exceedingly because of being bound with strong cords. And they also had suffered hunger,"], ["fia inu,", "thirst,"], ["ma ituaiga uma o puapuaga;", "and all kinds of afflictions;"], ["e ui i lea sa latou onosai i o latou mafatiaga uma.", "nevertheless they were patient in all their sufferings."]]},
  {num:30,words:[["Ma,", "And,"], ["e pei ona tupu,", "as it happened,"], ["o lo latou lafo le pauu atu i lima o ni tagata sili ona maaa ma ua maaa;", "it was their lot to have fallen into the hands of a more hardened and a more stiffnecked people;"], ["o lea sa latou le fia faalogo ai ia latou upu,", "therefore they would not hearken unto their words,"], ["ma latou tutuli ese ai i latou i fafo,", "and they had cast them out,"], ["ma sasa i latou,", "and had smitten them,"], ["ma tutuli i latou mai lea fale i lea fale,", "and had driven them from house to house,"], ["ma mai i lea mea i lea mea,", "and from place to place,"], ["seia oo ina latou taunuu mai i le laueleele o Mitonae;", "even until they had arrived in the land of Middoni;"], ["ma o iina na ave ai i latou ma lafo i le falepuipui,", "and there they were taken and cast into prison,"], ["ma saisai i maea malolosi,", "and bound with strong cords,"], ["ma taofi i latou i le falepuipui mo aso e tele,", "and kept in prison for many days,"], ["ma laveai mai ai e Lamonae ma Amona.", "and were delivered by Lamoni and Ammon."]]},
];
renderVerseSet(al_ch_20_Verses, 'al-ch20-verses');

var al_ch_21_Verses = [
  {num:1,words:[["O lenei ina ua faataapeape e Amona ma ona uso i latou lava i tuaoi o le laueleele o sa Lamanā,", "Now when Ammon and his brethren separated themselves in the borders of the land of the Lamanites,"], ["faauta o Arona,", "behold Aaron took his journey towards the land which was called by the Lamanites,"], ["sa alu lana malaga agai i le laueleele lea sa taua e sa Lamanā, o Ierusalema,", "Jerusalem,"], ["sa faaigoa i le laueleele na soifua mai ai o latou tamā;", "calling it after the land of  their fathers' nativity;"], ["ma sa mamao ese atu e fesootai ma tuaoi o Mamona.", "and it was away joining the borders of Mormon."]]},
  {num:2,words:[["O lenei sa faatu e sa Lamanā ma sa Amalekā ma tagata o Amulona se aai tele,", "Now the Lamanites and the Amalekites and the people of Amulon had built a great city,"], ["lea sa taua o Ierusalema.", "which was called Jerusalem."]]},
  {num:3,words:[["O lenei o sa Lamanā lava latou,", "Now the Lamanites of themselves were sufficiently hardened,"], ["sa lava lo latou maaa,", "but the Amalekites and the Amulonites were still harder;"], ["ae sa sili atu ai le maaa o sa Amalekā ma sa Amulonā; o lea na latou faaoso ai sa Lamanā ia faamaaa o latou loto,", "therefore they did cause the Lamanites that they should harden their hearts,"], ["ina ia latou solo malolosi i le amioleaga ma a latou mea inosia.", "that they should wax strong in wickedness and their abominations."]]},
  {num:4,words:[["Ma sa oo ina alu atu Arona i le aai o Ierusalema,", "And it came to pass that Aaron came to the city of Jerusalem,"], ["ma amata talai muamua atu ia Amalekā. Ma sa amata ona ia talai atu ia te i latou i o latou sunako,", "and first began to preach to the Amalekites. And he began to preach to them in their synagogues,"], ["ona sa latou fausia sunako e tusa ma le faatulagaga a Ne'oa;", "for they had built synagogues after the order of the Nehors;"], ["ona o le toatele o sa Amalekā ma sa Amulonā o e sa mulimuli atu i le faatulagaga a Ne'oa.", "for many of the Amalekites and the Amulonites were after the order of the Nehors."]]},
  {num:5,words:[["O lea,", "Therefore,"], ["a'o ulu atu Arona i se tasi o o latou sunako e talai atu i tagata,", "as Aaron entered into one of their synagogues to preach unto the people,"], ["ma a'o tautala atu o ia ia te i latou,", "and as he was speaking unto them,"], ["faauta sa tulai mai se sa Amaleka ma amata ona finau mai ia te ia,", "behold there arose an Amalekite and began to contend with him,"], ["fai mai:", "saying:"], ["O le a lena mea ua e molimau mai ai? Na e vaai i se agelu ? Aisea ua le afifio mai ai ni agelu ia te i matou? Faauta ua lē lelei ea nei tagata e pei o ou tagata?", "What is that thou hast testified? Hast thou seen an angel? Why do not angels appear unto us? Behold are not this people as good as thy people?"]]},
  {num:6,words:[["Ua e fai mai foi,", "Thou also sayest,"], ["o le a matou fano vagana ai ua matou salamo. E faapefea ona e iloa o mafaufauga ma faamoemoega o o matou loto? E faapefea ona e iloa ua i ai se pogai matou te salamo ai? E faapefea ona e iloa e le o i matou o ni tagata amiotonu? Faauta,", "except we repent we shall perish. How knowest thou the thought and intent of our hearts? How knowest thou that we have cause to repent? How knowest thou that we are not a righteous people? Behold,"], ["ua matou fausia falesa,", "we have built sanctuaries,"], ["ma ua matou faapotopoto faatasi i matou lava e tapuai atu i le Atua. Matou te talitonu o le a faaolaina e le Atua tagata uma.", "and we do assemble ourselves together to worship God. We do believe that God will save all men."]]},
  {num:7,words:[["O lenei sa fai atu Arona ia te ia:", "Now Aaron said unto him:"], ["E te talitonu ea o le a afio mai le Alo o le Atua e togiola tagata mai a latou agasala?", "Believest thou that the Son of God shall come to redeem mankind from their sins?"]]},
  {num:8,words:[["Ma sa fai mai lea tagata ia te ia:", "And the man said unto him:"], ["Matou te le talitonu ua e iloaina se mea faapena. Matou te le talitonu i nei uputuu valea. Matou te le talitonu ua e iloaina e uiga i mea o le a oo mai,", "We do not believe that thou knowest any such thing. We do not believe in these foolish traditions. We do not believe that thou knowest of things to come,"], ["pe matou te talitonu foi na iloa e ou tamā ma o matou tamā foi e uiga i mea na latou tautatala mai ai,", "neither do we believe that thy fathers and also that our fathers did know concerning the things which they spake,"], ["e uiga i mea o le a oo mai.", "of that which is to come."]]},
  {num:9,words:[["O lenei sa amata ona fofola atu e Arona ia te i latou tusitusiga paia e uiga i le afio mai o Keriso,", "Now Aaron began to open the scriptures unto them concerning the coming of Christ,"], ["ma e uiga foi i le toetutu mai o e ua oti,", "and also concerning the resurrection of the dead,"], ["ma e faapea e le mafai ona i ai se togiola mo tagata vagana ua ala mai i le maliu ma mafatia o Keriso,", "and that there could be no redemption for mankind save it were through the death and sufferings of Christ,"], ["ma le togiola a lona toto.", "and the atonement of his blood."]]},
  {num:10,words:[["Ma sa oo ina ua amata ona ia faamatala atu nei mea ia te i latou,", "And it came to pass as he began to expound these things unto them they were angry with him,"], ["sa latou feita mai ia te ia, ma amata ona tauemu mai ia te ia;", "and began to mock him;"], ["ma latou le fia faalogo mai i upu na ia tautala atu ai.", "and they would not hear the words which he spake."]]},
  {num:11,words:[["O lea,", "Therefore,"], ["ina ua ia vaai atu ua latou le fia faalogo mai i ana upu,", "when he saw that they would not hear his words,"], ["sa alu ese atu o ia i fafo o o latou sunako,", "he departed out of their synagogue,"], ["ma alu atu i se nuu sa taua o Ani-Aneti,", "and came over to a village which was called Ani– Anti,"], ["ma o iina na ia maua i ai Muloki o talai atu le afioga ia te i latou;", "and there he found Muloki preaching the word unto them;"], ["ma Ama foi ma ona uso. Ma sa latou finau ma le toatele e uiga i le afioga.", "and also  Ammah and his brethren. And they contended with many about the word."]]},
  {num:12,words:[["Ma sa oo ina latou vaai atu ua faamaaa e tagata o latou loto,", "And it came to pass that they saw that the people would harden their hearts,"], ["o lea na latou o ese ai ma o mai i le laueleele o Mitonae. Ma sa latou talai atu le afioga i le toatele,", "therefore they departed and came over into the land of Middoni. And they did preach the word unto many,"], ["ma e toaitiiti na talitonu i upu sa latou aoao atu.", "and few believed on the words which they taught."]]},
  {num:13,words:[["E ui i lea, sa ave Arona ma ni isi o ona uso ma ua lafo i le falepuipui,", "Nevertheless,"], ["ma o e na totoe o i latou,", "Aaron and a certain number of his brethren were taken and cast into prison,"], ["na sosola i fafo mai le laueleele o Mitonae, i itulagi faataamilo ai.", "and the remainder of them fled out of the land of Middoni unto the regions round about."]]},
  {num:14,words:[["Ma o i latou o e na lafo i le falepuipui,", "And those who were cast into prison suffered many things,"], ["sa mafatia i mea e tele, ma sa laveaiina i latou i lima o Lamonae ma Amona,", "and they were delivered by the hand of Lamoni and Ammon,"], ["ma sa fafagaina i latou ma faalavalavaina.", "and they were fed and clothed."]]},
  {num:15,words:[["Ma sa latou toe o atu e talai atu le afioga,", "And they went forth again to declare the word,"], ["ma sa faapea ona laveaiina o i latou i le taimi muamua i fafo mai le falepuipui;", "and thus they were delivered for the first time out of prison;"], ["ma sa faapea ona latou mafatia.", "and thus they had suffered."]]},
  {num:16,words:[["Ma sa latou o atu i soo se mea sa taitaiina i ai i latou e le Agaga o le Alii,", "And they went forth whithersoever they were led by the Spirit of the Lord,"], ["ma talai atu le afioga a le Atua i sunako taitasi o sa Amalekā,", "preaching the word of God in every synagogue of the Amalekites,"], ["po o i faapotopotoga taitasi o sa Lamanā sa mafai ona faatagaina ai i latou.", "or in every assembly of the Lamanites where they could be admitted."]]},
  {num:17,words:[["Ma sa oo ina amata ona faamanuiaina i latou e le Alii,", "And it came to pass that the Lord began to bless them,"], ["sa oo ina latou aumai tagata e toatele i le malamalama o le upumoni;", "insomuch that they brought many to the knowledge of the truth;"], ["ioe,", "yea,"], ["sa latou faatalitonuina tagata e toatele e uiga ia latou agasala,", "they did convince many of their sins,"], ["ma e uiga i uputuu a o latou tamā,", "and of the traditions of their fathers,"], ["ia sa le sa'o.", "which were not correct."]]},
  {num:18,words:[["Ma sa oo ina toe foi mai Amona ma Lamonae mai le laueleele o Mitonae i le laueleele o Isamaeli,", "And it came to pass that Ammon and Lamoni returned from the land of Middoni to the land of Ishmael,"], ["le laueleele lea o lo latou tofi.", "which was the land of their inheritance."]]},
  {num:19,words:[["Ma sa le tuuina atu Amona e le tupu o Lamonae ia auauna mai ia te ia,", "And king Lamoni would not suffer that Ammon should serve him,"], ["pe ia avea ma ana auauna.", "or be his servant."]]},
  {num:20,words:[["Ae sa ia faatonu atu ia fausia ni sunako i le laueleele o Isamaeli;", "But he caused that there should be synagogues built in the land of Ishmael;"], ["ma sa ia faatonu atu ia faapotopoto faatasi e ona tagata,", "and he caused that his people,"], ["po o tagata o e sa i lalo o lana puleaga,", "or the people who were under his reign,"], ["i latou lava.", "should assemble themselves together."]]},
  {num:21,words:[["Ma sa olioli o ia ia te i latou,", "And he did rejoice over them,"], ["ma sa ia aoao atu ia te i latou mea e tele.", "and he did teach them many things."], ["Ma sa ia tautino atu foi ia te i latou,", "And he did also declare unto them that they were a people who were under him,"], ["o i latou o ni tagata ua i ai i lalo o ia,", "and that they were a free people,"], ["ma o i latou o ni tagata ua saoloto, e faapea ua latou saoloto mai mea saua a le tupu,", "that they were free from the oppressions of the king,"], ["lona tamā;", "his father;"], ["ona ua tuu mai e lona tamā ia te ia ia pule o ia i luga o tagata o e sa i le laueleele o Isamaeli,", "for that his father had granted unto him that he might reign over the people who were in the land of Ishmael,"], ["ma le laueleele atoa faataamilo ai.", "and in all the land round about."]]},
  {num:22,words:[["Ma sa ia tautino atu foi ia te i latou,", "And he also declared unto them that they might have the liberty of worshiping the Lord their God according to their desires,"], ["ua mafai ona latou maua le saolotoga e tapuai ai i le Alii lo latou Atua e tusa ma o latou manao, i soo se mea ua latou i ai,", "in whatsoever place they were in,"], ["pe afai ua i ai i totonu o le laueleele lea ua i lalo o le pule a le tupu o Lamonae.", "if it were in the land which was under the reign of king Lamoni."]]},
  {num:23,words:[["Ma sa talai atu Amona i tagata o le tupu o Lamonae;", "And Ammon did preach unto the people of king Lamoni;"], ["ma sa oo ina aoao atu e ia ia te i latou mea uma e faatatau i mea tau i le amiotonu. Ma sa ia apoapoai atu ia te i latou i aso uma,", "and it came to pass that he did teach them all things concerning things pertaining to righteousness. And he did exhort them daily,"], ["ma le filiga atoa;", "with all diligence;"], ["ma sa latou gauai mai i lana upu,", "and they gave  heed unto his word,"], ["ma sa latou finafinau i le tausiga o poloaiga a le Atua.", "and they were zealous for keeping the commandments of God."]]},
];
renderVerseSet(al_ch_21_Verses, 'al-ch21-verses');

var al_ch_22_Verses = [
  {num:1,words:[["O lenei,", "Now,"], ["ao faapea ona aoaoina pea e Amona le nuu o Lamonae, o le a tatou toe foi atu i le tala ia Arona ma ona uso;", "as Ammon was thus teaching the people of Lamoni continually,"], ["aua,", "we will return to the account of Aaron and his brethren;"], ["ina ua mavae ona ia alu ese mai le laueleele o Mitonae,", "for after he departed from the land of Middoni he was led by the Spirit to the land of Nephi,"], ["sa taitai atu o ia e le Agaga i le laueleele o Nifae, i le maota lava o le tupu lea sa pule i luga o le laueleele atoa vagana ai le laueleele o Isamaeli;", "even to the house of the king which was over all the land save it were the land of Ishmael;"], ["ma o ia lea o le tamā o Lamonae.", "and he was the father of Lamoni."]]},
  {num:2,words:[["Ma sa oo ina alu atu o ia ia te ia i totonu o le maota o le tupu,", "And it came to pass that he went in unto him into the king's palace,"], ["faatasi ma ona uso,", "with his brethren,"], ["ma ifo atu o ia i luma o le tupu,", "and bowed himself before the king,"], ["ma fai atu ia te ia:", "and said unto him:"], ["Faauta,", "Behold,"], ["le tupu e,", "O king,"], ["o i matou o uso o Amona,", "we are the brethren of Ammon,"], ["o e na e laveai i fafo mai le falepuipui.", "whom thou hast delivered out of prison."]]},
  {num:3,words:[["Ma o lenei,", "And now,"], ["le tupu e,", "O king,"], ["afai e te faasaoina o matou ola,", "if thou wilt spare our lives,"], ["o le a avea i matou ma au auauna. Ma sa fai mai le tupu ia te i latou:", "we will be thy servants. And the king said unto them:"], ["Tutulai ia,", "Arise,"], ["ona o le a ou tuu atu ia te outou o outou ola,", "for I will grant unto you your lives,"], ["ma o le a ou le tuu outou ia outou avea ma au auauna;", "and I will not suffer that ye shall be my servants;"], ["ae o le a ou tautu atu pea ia outou fesoasoani mai ia te au,", "but I will insist that ye shall administer unto me;"], ["ona ua ou atuatuvale tele i lou mafaufau ona o le alofa ma le silisili o upu a lou uso o Amona;", "for I have been somewhat troubled in mind because of the generosity and the greatness of the words of thy brother Ammon;"], ["ma ou te fia iloa le pogai pe aisea ua le sau ai o ia i fafo o Mitonae faatasi ma oe.", "and I desire to know the cause why he has not come up out of Middoni with thee."]]},
  {num:4,words:[["Ma sa fai atu Arona i le tupu:", "And Aaron said unto the king:"], ["Faauta,", "Behold,"], ["ua valaauina o ia e le Agaga o le Alii i se isi ala;", "the Spirit of the Lord has called him another way;"], ["ua alu atu o ia i le laueleele o Isamaeli,", "he has gone to the land of Ishmael,"], ["e aoao le nuu o Lamonae.", "to teach the people of Lamoni."]]},
  {num:5,words:[["O lenei sa fai mai le tupu ia te i latou:", "Now the king said unto them:"], ["O le a lenei mea sa outou fai mai ai e uiga i le Agaga o le Alii? Faauta,", "What is this that ye have said concerning the Spirit of the Lord? Behold,"], ["o le mea lenei ua faaatuatuvaleina ai au.", "this is the thing which doth trouble me."]]},
  {num:6,words:[["O lenei foi,", "And also,"], ["o le a lenei mea na fai mai ai Amona— Afai e te salamo o le a faaolaina oe,", "what is this that Ammon said—If ye will repent ye shall be saved,"], ["ma afai e te le salamo,", "and if ye will not repent,"], ["o le a lafoai ese oe i le aso gataaga?", "ye shall be cast off at the last day?"]]},
  {num:7,words:[["Ma sa tali atu Arona ia te ia ma fai atu ia te ia:", "And Aaron answered him and said unto him:"], ["E te talitonu o loo i ai se Atua? Ma sa fai mai le tupu:", "Believest thou that there is a God? And the king said:"], ["Ua ou iloa ua fai mai sa Amalekā o loo i ai se Atua,", "I know that the Amalekites say that there is a God,"], ["ma ua ou tuu atu ia te i latou ia latou fausia ni falesa,", "and I have granted unto them that they should build sanctuaries,"], ["ina ia mafai ona latou faapotopoto faatasi i latou lava e tapuai atu ia te ia.", "that they may assemble themselves together to worship him."], ["Ma afai ua e fai mai nei o loo i ai se Atua, faauta,", "And if now thou sayest there is a God,"], ["o le a ou talitonu i ai.", "behold I will believe."]]},
  {num:8,words:[["Ma o lenei ina ua faalogo Arona i lenei mea,", "And now when Aaron heard this,"], ["sa amata ona olioli o lona loto,", "his heart began to rejoice,"], ["ma sa ia fai atu:", "and he said:"], ["Faauta,", "Behold,"], ["Le tupu e,", "assuredly as thou livest,"], ["e pei ona mautinoa o loo e soifua,", "O king,"], ["o loo i ai se Atua.", "there is a God."]]},
  {num:9,words:[["Ma sa fai mai le tupu:", "And the king said:"], ["O le Atua ea o le Agaga Silisili lea na aumaia o tatou tamā i fafo mai le laueleele o Ierusalema?", "Is God that Great Spirit that brought our fathers out of the land of Jerusalem?"]]},
  {num:10,words:[["Ma sa fai atu Arona ia te ia:", "And Aaron said unto him:"], ["Ioe,", "Yea,"], ["o ia lena o lea lava Agaga Silisili,", "he is that Great Spirit,"], ["ma o ia na foafoaina mea uma i le lagi ma le lalolagi. E te talitonu i lenei mea?", "and he created all things both in heaven and in earth. Believest thou this?"]]},
  {num:11,words:[["Ma sa fai mai o ia:", "And he said:"], ["Ioe,", "Yea,"], ["ou te talitonu o le Agaga Silisili na foafoaina mea uma,", "I believe that the Great Spirit created all things,"], ["ma ou te manao ia e faamatala mai ia te au e uiga i nei mea uma,", "and I desire that ye should tell me concerning all these things,"], ["ma o le a ou talitonu i au upu.", "and I will believe thy words."]]},
  {num:12,words:[["Ma sa oo ina ua vaai atu Arona o le a talitonu le tupu i ana upu,", "And it came to pass that when Aaron saw that the king would believe his words,"], ["sa ia amata mai i le foafoaga o Atamu,", "he began from the creation of Adam,"], ["ma faitau atu tusitusiga paia i le tupu—le ala na foafoa ai e le Atua le tagata i lona lava faatusa,", "reading the scriptures unto the king—how God created man after his own image,"], ["ma e faapea na tuuina atu e le Atua ia te ia o poloaiga,", "and that God gave him commandments,"], ["ma e faapea ona o le solitulafono,", "and that because of transgression,"], ["ua pau ai le tagata.", "man had fallen."]]},
  {num:13,words:[["Ma sa faamatala auiliili atu e Arona ia te ia tusitusiga paia mai i le foafoaga o Atamu,", "And Aaron did expound unto him the scriptures from the creation of Adam,"], ["ma faataoto atu i ona luma le pau o le tagata,", "laying the fall of man before him,"], ["ma lo latou tulaga faaletino ma le fuafuaga foi o le togiolaina,", "and their carnal state and also the plan of redemption,"], ["lea na saunia mai le faavaega o le lalolagi,", "which was prepared from the foundation of the world,"], ["e ala ia Keriso,", "through Christ,"], ["mo soo se tasi o i latou uma o e e talitonu i lona suafa.", "for all whosoever would believe on his name."]]},
  {num:14,words:[["Ma talu ai ona ua pau le tagata,", "And since man had fallen he could not merit anything of himself;"], ["ua le mafai ona agavaa o ia i soo se mea na te faia mo ia lava;", "but the sufferings and death of Christ atone for their sins,"], ["ae o mafatiaga ma le maliu o Keriso ua togiola mo a latou agasala,", "through faith and repentance,"], ["e ala i le faatuatua ma le salamo,", "and so forth;"], ["ma isi mea faapena; ma ua motusia e ia noataga o le oti,", "and that he breaketh the bands of death,"], ["o le a leai ai se manumalo o le tuugamau ,", "that the grave shall have no victory,"], ["ma o le a tofatumoanaina le tui o le oti i faamoemoega o le mamalu;", "and that the sting of death should be swallowed up in the hopes of glory;"], ["ma sa faamatala atu e Arona nei mea uma i le tupu.", "and Aaron did expound all these things unto the king."]]},
  {num:15,words:[["Ma sa oo ina ua uma ona faamatala atu e Arona nei mea ia te ia,", "And it came to pass that after Aaron had expounded these things unto him,"], ["sa fai mai le tupu:", "the king said:"], ["O le a se mea ou te faia ina ia mafai ona ou maua o lenei ola faavavau ua e tautala i ai? Ioe,", "What shall I do that I may have this eternal life of which thou hast spoken? Yea,"], ["o le a se mea ou te faia ina ia mafai ai ona fanauina o au i la le Atua,", "what shall I do that I may be born of God,"], ["ina ia se'ia ese ai i fafo lenei agaga leaga mai lo'u fatafata,", "having this wicked spirit rooted out of my breast,"], ["ma ou maua ai lona Agaga,", "and receive his Spirit,"], ["ina ia mafai ona faatumuina o au i le olioli,", "that I may be filled with joy,"], ["ina ia le mafai ona lafoaia ese o au i le aso gataaga? Faauta,", "that I may not be cast off at the last day? Behold,"], ["ua fai mai o ia,", "said he,"], ["o le a ou tuu atu mea uma ua ou maua,", "I will give up all that I possess,"], ["ioe,", "yea,"], ["o le a ou lafoai i lou malo,", "I will forsake my kingdom,"], ["ina ia mafai ona ou maua lenei olioli tele.", "that I may receive this great joy."]]},
  {num:16,words:[["Ae sa fai atu Arona ia te ia:", "But Aaron said unto him:"], ["Afai ua e naunau i lenei mea,", "If thou desirest this thing,"], ["afai e te ifo i lalo i luma o le Atua,", "if thou wilt bow down before God,"], ["ioe,", "yea,"], ["afai e te salamo i au agasala uma,", "if thou wilt repent of all thy sins,"], ["ma ifo i lalo i luma o le Atua,", "and will bow down before God,"], ["ma valaau atu i lona suafa i le faatuatua,", "and call on his name in faith,"], ["ma le talitonu o le a e maua,", "believing that ye shall receive,"], ["ona e maua lea o le faamoemoe ua e naunau i ai.", "then shalt thou receive the hope which thou desirest."]]},
  {num:17,words:[["Ma sa oo ina ua uma ona fai atu e Arona nei upu,", "And it came to pass that when Aaron had said these words,"], ["sa ifo i lalo le tupu i luma o le Alii,", "the king did bow down before the Lord,"], ["i luga o ona tulivae;", "upon his knees;"], ["ioe,", "yea,"], ["sa fao lava o ia i luga o le eleele,", "even he did prostrate himself upon the earth,"], ["ma alaga ma le malosi,", "and cried mightily,"], ["fai mai:", "saying:"]]},
  {num:18,words:[["Le Atua e,", "O God,"], ["ua tau mai e Arona ia te au o loo i ai se Atua;", "Aaron hath told me that there is a God;"], ["ma afai o loo i ai se Atua,", "and if there is a God,"], ["ma afai o oe o le Atua,", "and if thou art God,"], ["sei e faailoa mai oe lava ia te au,", "wilt thou make thyself known unto me,"], ["ma o le a ou lafoai ese au agasala uma ina ia ou iloa oe,", "and I will give away all my sins to know thee,"], ["ma ia mafai ona faatuina o au mai le oti,", "and that I may be raised from the dead,"], ["ma faaolaina i le aso gataaga. Ma o lenei ina ua uma ona fai mai e le tupu nei upu,", "and be saved at the last day. And now when the king had said these words,"], ["sa taia o ia e peiseai ua oti.", "he was struck as if he were dead."]]},
  {num:19,words:[["Ma sa oo ina taufetuli atu ana auauna ma tau atu i le masiofo mea uma ua oo i le tupu. Ma sa sau o le ia i totonu i le tupu;", "And it came to pass that his servants ran and told the queen all that had happened unto the king. And she came in unto the king;"], ["ma ina ua vaai atu o ia ua taoto mai o ia e peiseai ua oti,", "and when she saw him lay as if he were dead,"], ["ma o tutu atu foi Arona ma ona uso e peiseai o i latou na ala ai lona pau,", "and also Aaron and his brethren standing as though they had been the cause of his fall,"], ["sa ita o ia ia te i latou,", "she was angry with them,"], ["ma ia faatonu ia o ane ana auauna,", "and commanded that her servants,"], ["po o auauna a le tupu,", "or  the servants of the king,"], ["e ave i latou ma fasioti ia te i latou.", "should take them and slay them."]]},
  {num:20,words:[["O lenei sa vaai auauna i le pogai o le pau o le tupu,", "Now the servants had seen the cause of the king's fall,"], ["o lea sa latou fefefe ai e fetagofi atu o latou lima ia Arona ma ona uso;", "therefore they durst not lay their hands on Aaron and his brethren;"], ["ma sa latou talosaga atu i le masiofo ua fai atu:", "and they pled with the queen saying:"], ["Aisea ua e faatonu ai i matou ia fasioti i nei tagata,", "Why commandest thou that we should slay these men,"], ["ae faauta ua sili atu le malosi o le toatasi o i latou nai lo i matou uma? O lea o le a matou pauu ai i o latou luma.", "when behold one of them is mightier than us all? Therefore we shall fall before them."]]},
  {num:21,words:[["O lenei ina ua vaai atu le masiofo i le fefefe o auauna, sa amata foi ona matau tele o ia,", "Now when the queen saw the fear of the servants she also began to fear exceedingly,"], ["nei oo mai se leaga i ona luga.", "lest there should some evil come upon her."], ["Ma sa ia faatonu atu i ana auauna, ia latou o atu ma valaau i le nuu,", "And she commanded her servants that they should go and call the people,"], ["ina ia mafai ona latou fasioti ia Arona ma ona uso.", "that they might slay Aaron and his brethren."]]},
  {num:22,words:[["O lenei ina ua vaai atu Arona i le mauai o le masiofo,", "Now when Aaron saw the determination of the queen,"], ["o ia,", "he,"], ["i lona iloa o le maaa o loto o le nuu,", "also knowing the hardness of the hearts of the people,"], ["sa fefe nei faapotopoto faatasi e le motu o tagata i latou lava,", "feared lest that a multitude should assemble themselves together,"], ["ma tupu mai ai se finauga tele ma se fevesiaiga i totonu o i latou;", "and there should be a great contention and a disturbance among them;"], ["o lea na ia tuu atu ai lona lima ma faatulai le tupu mai le eleele,", "therefore he put forth his hand and raised the king from the earth,"], ["ma fai atu ia te ia:", "and said unto him:"], ["Tulai ia. Ma sa tu mai o ia i luga i ona vae,", "Stand. And he stood upon his feet,"], ["ua maua lona malosi.", "receiving his strength."]]},
  {num:23,words:[["O lenei sa faia lenei mea i luma o le masiofo ma le toatele o auauna.", "Now this was done in the presence of the queen and many of the servants."], ["Ma ina ua latou vaai atu i ai, sa latou ofo tele,", "And when they saw it they greatly marveled,"], ["ma amata ona matatau.", "and began to fear."], ["Ma sa tulai mai le tupu,", "And the king stood forth,"], ["ma amata ona ia aoao atu ia te i latou.", "and began to minister unto them."], ["Ma sa ia aoao atu ia te i latou,", "And he did minister unto them,"], ["sa oo ina faaliliuina lona auaiga atoa i le Alii.", "insomuch that his whole household were converted unto the Lord."]]},
  {num:24,words:[["O lenei sa i ai se motu o tagata sa faapotopoto faatasi ona o le poloaiga a le masiofo, ma sa amata ona i ai ni muimuiga tetele i totonu o i latou,", "Now there was a multitude gathered together because of the commandment of the queen,"], ["ona o Arona ma ona uso.", "and there began to be great murmurings among them because of Aaron and his brethren."]]},
  {num:25,words:[["Peitai sa tulai atu le tupu i totonu o i latou ma faato'ato'a atu ia te i latou. Ma sa faamalilieina i latou e faasaga ia Arona ma i latou o e na faatasi ma ia.", "But the king stood forth among them and administered unto them. And they were pacified towards Aaron and those who were with him."]]},
  {num:26,words:[["Ma sa oo ina ua vaai atu le tupu ua faamalilieina le nuu,", "And it came to pass that when the king saw that the people were pacified,"], ["sa ia faatonuina e tatau ia Arona ma ona uso ona tutu i totonu o le lotolotoi o le motu o tagata,", "he caused that Aaron and his brethren should stand forth in the midst of the multitude,"], ["ma tatau ia i latou ona talai atu le afioga ia te i latou.", "and that they should preach the word unto them."]]},
  {num:27,words:[["Ma sa oo ina auina atu e le tupu se folafolaga i le laueleele atoa,", "And it came to pass that the king sent a proclamation throughout all the land,"], ["i totonu o ona tagata uma o e sa i ai i lona laueleele atoa,", "amongst all his people who were in all his land,"], ["o e sa i ai i itulagi uma faataamilo ai,", "who were in all the regions round about,"], ["ia sa tuaoi e oo atu lava i le sami,", "which was bordering even to the sea,"], ["i le itu i sasae ma le itu i sisifo,", "on the east and on the west,"], ["ma lea sa vavae mai le laueleele o Sara'emila i se vaivao lauitiiti,", "and which was divided from the land of Zarahemla by a narrow strip of wilderness,"], ["lea na sau mai i le sami i sasae e oo atu i le sami i sisifo,", "which ran from the sea east even to the sea west,"], ["ma taamilo ane i tuaoi o le matafaga,", "and round about on the borders of the seashore,"], ["ma tuaoi o le vao lea sa i le itu i matu i tafatafa o le laueleele o Sara'emila,", "and the borders of the wilderness which was on the north by the land of Zarahemla,"], ["e oo atu i tuaoi o Maneti,", "through the borders of Manti,"], ["i tafatafa o le mata o le vaitafe o Saitonu,", "by the head of the river Sidon,"], ["e sau mai sasae agai i sisifo—ma sa faapea ona vavaeina o sa Lamanā ma sa Nifaē.", "running from the east towards the west—and thus were the Lamanites and the Nephites divided."]]},
  {num:28,words:[["O lenei,", "Now,"], ["o le vaega sili ona paie o sa Lamanā sa nonofo i le vao,", "the more idle part of the Lamanites lived in the wilderness,"], ["ma sa mau i faleie;", "and dwelt in tents;"], ["ma sa salalau atu i latou i le vao i le itu i sisifo,", "and they were spread through the wilderness on the west,"], ["i le laueleele o Nifae;", "in the land of Nephi;"], ["ioe,", "yea,"], ["ma le itu foi i sisifo o le laueleele o Sara'emila,", "and also on the west of the land of Zarahemla,"], ["i tuaoi latalata i le matafaga,", "in the borders by the seashore,"], ["ma le itu i sisifo o le laueleele o Nifae,", "and on the west in the land of Nephi,"], ["i le nofoaga o le tofi muamua o o latou tamā,", "in the place of their fathers' first inheritance,"], ["ma faapea ona tuaoi ai e alu atu i tafatafa o le matafaga.", "and thus bordering along by the seashore."]]},
  {num:29,words:[["Ma sa toatele foi sa Lamanā sa i ai i le itu i sasae latalata i le matafaga,", "And also there were many Lamanites on the east by the seashore,"], ["i le mea na tutuli i ai i latou e sa Nifaē. Ma sa faapea ona toetoe a siosiomia sa Nifaē e sa Lamanā;", "whither the Nephites had driven them. And thus the Nephites were nearly surrounded by the Lamanites;"], ["e ui i lea sa ave e sa Nifaē le vaega uma i matu o le laueleele e tuaoi ma le vao,", "nevertheless the Nephites had taken possession of all the northern parts of the land bordering on the wilderness,"], ["i le mata o le vaitafe o Saitonu,", "at the head of the river Sidon,"], ["mai sasae i sisifo,", "from the east to the west,"], ["e taamilo atu i le itu i le vao;", "round about on the wilderness side;"], ["i le itu i matu,", "on the north,"], ["seia oo ina latou oo atu lava i le laueleele lea sa latou taua o Nuumau .", "even until they came to the land which they called Bountiful."]]},
  {num:30,words:[["Ma sa tuaoi ma le laueleele lea sa latou taua o Tuufua ,", "And it bordered upon the land which they called Desolation,"], ["lea sa matua mamao tele lava i matu sa oo atu i le laueleele lea sa aina e ni tagata ua faaumatia,", "it being so far northward that it came into the land which had been peopled and been destroyed,"], ["o e e ona ivi na matou tautatala atu ai,", "of whose bones we have spoken,"], ["lea na maua e le nuu o Sara'emila,", "which was discovered by the people of Zarahemla,"], ["le nofoaga lea na latou tau muamua i ai.", "it being the place of their first landing."]]},
  {num:31,words:[["Ma sa latou o mai i luga mai iina i le vao i saute. O lea na taua ai le laueleele i matu o Tuufua ,", "And they came from there up into the south wilderness. Thus the land on the northward was called Desolation,"], ["ma o le laueleele i saute sa taua o Nuumau,", "and the land on the south– ward was called Bountiful,"], ["ona o le vao lea sa tumu i ituaiga uma o manu aivao eseese,", "it being the wilder– ness which is filled with all manner of wild animals of every kind,"], ["o se vaega o ia manu na o mai mai le laueleele i matu mo meaai.", "a part of which had come from the land northward for food."]]},
  {num:32,words:[["Ma o lenei,", "And now,"], ["sa nao se aso e tasi ma le afa i le malaga a se sa Nifaē le mamao o le laina o Nuumau ma le laueleele o Tuufua,", "it was only the distance of a day and a half's journey for a Nephite,"], ["mai sasae i le sami i sisifo;", "on the line Bountiful and the land Desolation, from the east to the west sea;"], ["ma sa faapea ona toetoe a siomia ai le laueleele o Nifae ma le laueleele o Sara'emila i le vai,", "and thus the land of Nephi and the land of Zarahemla were nearly surrounded by water,"], ["ona sa i ai iina se laueleele lauiti laitiiti i le va o le laueleele i matu ma le laueleele i saute.", "there being a small neck of land between the land northward and the land southward."]]},
  {num:33,words:[["Ma sa oo ina aina e sa Nifaē le laueleele o Nuumau,", "And it came to pass that the Nephites had inhabited the land Bountiful,"], ["e mai lava i sasae e oo atu i le sami i sisifo,", "even from the east unto the west sea,"], ["ma sa faapea,", "and thus the Nephites in their wisdom,"], ["i lo latou popoto ma a latou leoleo ma a latou autau,", "with their guards and their armies,"], ["ona pupuni i totonu e sa Nifae sa Lamanā i le itu i saute,", "had hemmed in the Lamanites on the south,"], ["ina ia le mafai ai ona latou toe maua ni isi laueleele i le itu i matu,", "that thereby they should have no more possession on the north,"], ["ina ia le mafai ona latou faatumutumuina le laueleele i matu.", "that they might not overrun the land northward."]]},
  {num:34,words:[["O lea sa le mafai ona toe maua e sa Lamanā ni isi laueleele nao i le laueleele o Nifae,", "Therefore the Lamanites could have no more possessions only in the land of Nephi,"], ["ma le vao faataamilo ai. O lenei o le poto lenei na faia ai e sa Nifaē lenei mea—talu ai ona o sa Lamanā o se fili ia te i latou,", "and the wilderness round about. Now this was wisdom in the Nephites—as the Lamanites were an enemy to them,"], ["sa latou le fia tuua a latou faatiga ia oo mai i soo se itu,", "they would not suffer their afflictions on every hand,"], ["ma ina ia mafai ai foi ona latou maua o se itu-laueleele e mafai ona latou sosola atu i ai,", "and also that they might have a country whither they might flee,"], ["e tusa ma o latou manao.", "according to their desires."]]},
  {num:35,words:[["Ma o lenei o au,", "And now I,"], ["ina ua uma ona ou fai atu o lenei mea,", "after having said this,"], ["ou te toe foi i le tala e uiga ia Amona ma Arona,", "return again to the account of Ammon and Aaron,"], ["Ominea ma Himinae,", "Omner and Himni,"], ["ma o latou uso.", "and their brethren."]]},
];
renderVerseSet(al_ch_22_Verses, 'al-ch22-verses');

var al_ch_23_Verses = [
  {num:1,words:[["Faauta,", "Behold,"], ["o lenei sa oo ina auina atu e le tupu o sa Lamanā se folafolaga i totonu o lona nuu atoa,", "now it came to pass that the king of the Lamanites sent a proclamation among all his people,"], ["ia aua nei pai atu o latou lima ia Amona,", "that they should not lay their hands on Ammon,"], ["po o Arona,", "or Aaron,"], ["po o Ominea,", "or Omner,"], ["po o Himinae,", "or Himni,"], ["po o se tasi o o latou uso o e e o atu e talai atu le afioga a le Atua,", "nor either of their brethren who should go forth preaching the word of God,"], ["i soo se mea latou te i ai,", "in whatsoever place they should be,"], ["i soo se vaega o lo latou laueleele.", "in any part of their land."]]},
  {num:2,words:[["Ioe,", "Yea,"], ["sa ia auina atu se folafolaga i totonu ia te i latou,", "he sent a decree among them,"], ["ia aua nei pai atu o latou lima ia te i latou e saisai i latou,", "that they should not lay their hands on them to bind them,"], ["pe lafo i latou i le falepuipui;", "or to cast them into prison;"], ["pe latou te tuufeanu i luga o i latou,", "neither should they spit upon them,"], ["pe fasi ia te i latou,", "nor smite them,"], ["pe tutuli ese i latou i fafo mai o latou sunako,", "nor cast them out of their synagogues,"], ["pe sasa ia te i latou;", "nor scourge them;"], ["pe latou te fetogia foi i latou i maa,", "neither should they cast stones at them,"], ["ae e tatau ona latou maua le faatagaga saoloto e ulu atu i o latou fale,", "but that they should have free access to their houses,"], ["ma o latou malumalu foi,", "and also their temples,"], ["ma o latou falesa.", "and their sanctuaries."]]},
  {num:3,words:[["Ma ia faapea ona mafai ai ona latou o atu ma talai atu le afioga e tusa ai ma o latou manao,", "And thus they might go forth and preach the word according to their desires,"], ["ona ua faaliliuina le tupu i le Alii,", "for the king had been converted unto the Lord,"], ["ma lona auaiga atoa;", "and all his household;"], ["o lea na ia auina atu ai lana folafolaga i le laueleele atoa i ona tagata,", "therefore he sent his proclamation throughout the land unto his people,"], ["ina ia leai se puniala i le afioga a le Atua,", "that the word of God might have no obstruction,"], ["ae ia mafai ona oo atu i le laueleele atoa,", "but that it might go forth throughout all the land,"], ["ina ia mafai ona faatalitonuina ona tagata i uputuu leaga a o latou tamā,", "that his people might be convinced concerning the wicked traditions of their fathers,"], ["ma ia mafai ona faatalitonuina i latou o i latou uma o uso,", "and that they might be convinced that they were all brethren,"], ["ma e le tatau ona latou fasioti tagata,", "and that they ought not to murder,"], ["pe vete,", "nor to plunder,"], ["pe gaoi,", "nor to steal,"], ["pe mulilulua,", "nor to commit adultery,"], ["pe faia soo se ituaiga o amioleaga.", "nor to commit any manner of wickedness."]]},
  {num:4,words:[["Ma o lenei sa oo ina ua uma ona auina atu e le tupu lenei folafolaga,", "And now it came to pass that when the king had sent forth this proclamation,"], ["sa oo ina o atu Arona ma ona uso mai lea aai i lea aai,", "that Aaron and his brethren went forth from city to city,"], ["ma mai le tasi fale tapuai i le tasi,", "and from one house of worship to another,"], ["ma faatutu aulotu,", "establishing churches,"], ["ma faauu faitaulaga ma aoao i le laueleele atoa i totonu o sa Lamanā,", "and consecrating priests and teachers throughout the land among the Lamanites,"], ["e talai ma aoao atu le afioga a le Atua i totonu o i latou;", "to preach and to teach the word of God among them;"], ["ma sa faapea ona amata ona latou maua le manuia tele.", "and thus they began to have great success."]]},
  {num:5,words:[["Ma e afe ma afe sa aumai i le malamalama o le Alii,", "And thousands were brought to the knowledge of the Lord,"], ["ioe,", "yea,"], ["e afe ma afe na aumai ia talitonu i uputuu a sa Nifaē;", "thousands were brought to believe in the traditions of the Nephites;"], ["ma sa aoaoina i latou i talafaamaumau ma valoaga ia sa tuulima faasolo mai i lalo seia oo mai lava i le taimi nei.", "and they were taught the records and prophecies which were handed down even to the present time."]]},
  {num:6,words:[["Ma e pei ona mautinoa o loo soifua le Alii,", "And as sure as the Lord liveth,"], ["mautinoa tele lava e pei o le toatele o e na talitonu,", "so sure as many as believed,"], ["pe e pei le toatele o e na aumai i le malamalama o le upumoni,", "or as many as were brought to the knowledge of the truth,"], ["e ala i le talaiga a Amona ma ona uso,", "through the preaching of Ammon and his brethren,"], ["e tusa ma le agaga o faaaliga ma valoaga,", "according to the spirit of revelation and of prophecy,"], ["ma le faia e le mana o le Atua o vavega e ala atu ia te i latou—ioe,", "and the power of God working miracles in them—yea,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["e pei ona soifua le Alii,", "as the Lord liveth,"], ["o le toatele o sa Lamanā o e na talitonu i la latou talaiga,", "as many of the Lamanites as believed in their preaching,"], ["ma faaliliuina i le Alii,", "and were converted unto the Lord,"], ["sa lei pauu ese lava.", "never did fall away."]]},
  {num:7,words:[["Ona sa avea i latou ma tagata amiotonu;", "For they became a righteous people;"], ["sa latou tuu i lalo auupega o lo latou fouvale,", "they did lay down the weapons of their rebellion,"], ["sa latou le toe tau faasaga i le Atua,", "that they did not fight against God any more,"], ["pe faasaga i soo se tasi o o latou uso.", "neither against any of their brethren."]]},
  {num:8,words:[["O lenei,", "Now,"], ["o i latou nei o e na faaliliuina i le Alii:", "these are they who were converted unto the Lord:"]]},
  {num:9,words:[["O tagata o sa Lamanā o e sa i le laueleele o Isamaeli;", "The people of the Lamanites who were in the land of Ishmael;"]]},
  {num:10,words:[["Ma tagata sa Lamanā foi o e sa i le laueleele o Mitonae;", "And also of the people of the Lamanites who were in the land of Middoni;"]]},
  {num:11,words:[["Ma tagata sa Lamanā foi o e sa i ai i le aai o Nifae;", "And also of the people of the Lamanites who were in the city of Nephi;"]]},
  {num:12,words:[["Ma tagata sa Lamanā foi sa i le laueleele o Seloma ,", "And also of the people of the Lamanites who were in the land of Shilom,"], ["ma e sa i le laueleele o Semulona,", "and who were in the land of Shemlon,"], ["ma i le aai o Lemuelu,", "and in the city of Lemuel,"], ["ma i le aai o Semineloma.", "and in the city of Shimnilom."]]},
  {num:13,words:[["Ma o igoa nei o aai o sa Lamanā sa faaliliuina i le Alii;", "And these are the names of the cities of the Lamanites which were converted unto the Lord;"], ["ma o i latou nei o e sa tuu i lalo auupega o lo latou fouvale,", "and these are they that laid down the weapons of their rebellion,"], ["ioe,", "yea,"], ["a latou auupega uma o le taua;", "all their weapons of war;"], ["ma o i latou uma o sa Lamanā.", "and they were all Lamanites."]]},
  {num:14,words:[["Ma o sa Amalekā sa lei liliu ,", "And the Amalekites were not converted,"], ["vagana ai nao se toatasi;", "save only one;"], ["po o se tasi foi o sa Amulonā;", "neither were any of the Amulonites;"], ["ae sa latou faamaaa o latou loto,", "but they did harden their hearts,"], ["ma loto foi o sa Lamanā i le vaega lena o le laueleele i soo se mea sa latou nonofo ai,", "and also the hearts of the Lamanites in that part of the land wheresoever they dwelt,"], ["ioe,", "yea,"], ["ma o latou nuu uma ma o latou aai uma.", "and all their villages and all their cities."]]},
  {num:15,words:[["O lea,", "Therefore,"], ["ua matou tau atu igoa o aai uma o sa Lamanā ia sa latou salamo ma o mai i le malamalama o le upumoni,", "we have named all the cities of the Lamanites in which they did repent and come to the knowledge of the truth,"], ["ma liliu.", "and were converted."]]},
  {num:16,words:[["Ma o lenei sa oo ina mananao le tupu ma i latou o e na liliu ia i ai so latou igoa,", "And now it came to pass that the king and those who were converted were desirous that they might have a name,"], ["ina ia mafai ona faailoga ese ai i latou mai o latou uso;", "that thereby they might be distinguished from their brethren;"], ["o lea na talatala ai le tupu faatasi ma Arona ma le toatele o o latou faitaulaga,", "therefore the king consulted with Aaron and many of their priests,"], ["e uiga i le igoa e tatau ona latou ave i o latou luga,", "concerning the name that they should take upon them,"], ["ina ia mafai ona faailoga ese ai i latou.", "that they might be distinguished."]]},
  {num:17,words:[["Ma sa oo ina latou taua o latou igoa o Aneti-Nifae-Liae ;", "And it came to pass that they called their names Anti– Nephi– Lehies;"], ["ma sa taua i latou i lenei igoa ma sa le toe taua i latou o ni sa Lamanā.", "and they were called by this name and were no more called Lamanites."]]},
  {num:18,words:[["Ma sa amata ona avea i latou o ni tagata toaaga tele;", "And they began to be a very industrious people;"], ["ioe,", "yea,"], ["ma sa latou fealofani ma tagata sa Nifaē;", "and they were friendly with the Nephites;"], ["o lea,", "therefore,"], ["sa latou amata ai se fesootaiga ma i latou,", "they did open a corres– pondence with them,"], ["ma sa le toe mulimuli ia te i latou le fetuu a le Atua.", "and the curse of God did no more follow them."]]},
];
renderVerseSet(al_ch_23_Verses, 'al-ch23-verses');

var al_ch_24_Verses = [
  {num:1,words:[["Ma sa oo ina o sa Amalekā ma sa Amulonā ma sa Lamanā o e sa i le laueleele o Amulona,", "And it came to pass that the Amalekites and the Amulonites and the Lamanites who were in the land of Amulon,"], ["ma ia sa i le laueleele foi o Helama,", "and also in the land of Helam,"], ["ma e sa i le laueleele o Ierusalema ,", "and who were in the land of Jerusalem,"], ["ma i se aotelega,", "and in fine,"], ["sa i le laueleele atoa faataamilo ai,", "in all the land round about,"], ["o e sa lei liliu ma sa lei avea i o latou luga le igoa o Aneti-Nifae-Liae ,", "who had not been converted and had not taken upon them the name of Anti– Nephi– Lehi,"], ["sa faaoso e sa Amalekā ma sa Amulonā ia feita faasaga i o latou uso.", "were stirred up by the Amalekites and by the Amulonites to anger against their brethren."]]},
  {num:2,words:[["Ma sa oo ina matua tetele lava lo latou feita e faasaga ia te i latou,", "And their hatred became exceedingly sore against them,"], ["sa oo lava ina amata ona latou fouvale faasaga i lo latou tupu,", "even insomuch that they began to rebel against their king,"], ["sa oo ina latou le mananao ia avea o ia mo o latou tupu;", "insomuch that they would not that he should be their king;"], ["o lea,", "therefore,"], ["na latou ave ai auupega o taua e faasaga i le nuu o Aneti-Nifae-Liae.", "they took up arms against the people of Anti– Nephi– Lehi."]]},
  {num:3,words:[["O lenei sa faaee e le tupu le malo i luga o lona atalii,", "Now the king conferred the kingdom upon his son,"], ["ma sa ia faaigoa ia te ia o Aneti-Nifae-Liae.", "and he called his name Anti– Nephi– Lehi."]]},
  {num:4,words:[["Ma sa maliu le tupu i le tausaga lava lena na amata ai ona faia e sa Lamanā sauniuniga mo le taua e faasaga i tagata o le Atua.", "And the king died in that selfsame year that the Lamanites began to make preparations for war against the people of God."]]},
  {num:5,words:[["O lenei ina ua vaai Amona ma ona uso ma i latou uma o e na o mai i luga faatasi ma ia i sauniuniga a sa Lamanā e faaumatia o latou uso,", "Now when Ammon and his brethren and all those who had come up with him saw the preparations of the Lamanites to destroy their brethren,"], ["sa latou o mai i le laueleele o Mitiana,", "they came forth to the land of Midian,"], ["ma o iina na feiloai ai Amona ma ona uso uma; ma sa latou o mai mai iina i le laueleele o Isamaeli,", "and there Ammon met all his brethren;"], ["ina ia mafai ona latou faia o se fono faatasi ma Lamonae ma lona uso foi o Aneti-Nifae-Liae,", "and from thence they came to the land of Ishmael that they might hold a council with Lamoni and also with his brother Anti– Nephi– Lehi,"], ["po o se mea e tatau ona latou faia e puipui ai i latou lava e faasaga ia sa Lamanā.", "what they should do to defend themselves against the Lamanites."]]},
  {num:6,words:[["O lenei sa leai se tagata e toatasi i totonu o tagata uma o e na liliu i le Alii,", "Now there was not one soul among all the people who had been converted unto the Lord that would take up arms against their brethren;"], ["na manao e tago i auupega o taua e faasaga i o latou uso;", "nay,"], ["e leai, sa latou le fia faia foi se sauniuniga mo le taua;", "they would not even make any preparations for war;"], ["ioe,", "yea,"], ["ma sa poloaiina foi i latou e lo latou tupu ia aua latou te faia.", "and also their king commanded them that they should not."]]},
  {num:7,words:[["O lenei,", "Now,"], ["o upu nei sa ia fai atu i le nuu e uiga i le mataupu:", "these are the words which he said unto the people concerning the matter:"], ["Ou te faafetai i lo'u Atua,", "I thank my God,"], ["lo'u nuu pele e,", "my beloved people,"], ["ua auina mai ia te i tatou e lo tatou Atua silisili i lona agalelei, o tatou uso nei,", "that our great God has in goodness sent these our brethren,"], ["o sa Nifaē,", "the Nephites,"], ["e talai mai ia te i tatou,", "unto us to preach unto us,"], ["ma faatalitonu i tatou e uiga i uputuu a o tatou tamā amioleaga.", "and to convince us of the traditions of our wicked fathers."]]},
  {num:8,words:[["Ma faauta,", "And behold,"], ["ou te faafetai i lo'u Atua silisili ona ua ia tuuina mai ia te i tatou se vaega o lona Agaga,", "I thank my great God that he has given us a portion of his Spirit to soften our hearts,"], ["e faamalulu o tatou loto, ua tatou amata ai se fesootaiga ma nei uso,", "that we have opened a corres– pondence with these brethren,"], ["o sa Nifaē.", "the Nephites."]]},
  {num:9,words:[["Ma faauta,", "And behold,"], ["ou te faafetai foi i lo'u Atua,", "I also thank my God,"], ["o le amataina o lenei fesootaiga ua tatou talitonu ai e uiga ia tatou agasala ,", "that by opening this correspondence we have been convinced of our sins,"], ["ma e uiga i le tele o le fasiotiga tagata sa tatou faia.", "and of the many murders which we have committed."]]},
  {num:10,words:[["Ma ou te faafetai foi i lo'u Atua,", "And I also thank my God,"], ["ioe,", "yea,"], ["lo'u Atua silisili,", "my great God,"], ["ona ua ia tuuina mai ia te i tatou ina ia mafai ona tatou salamo i nei mea,", "that he hath granted unto us that we might repent of these things,"], ["ma ua ia faamagaloina foi i tatou mai ia tatou agasala ma fasiotiga tagata e tele na tatou faia,", "and also that he hath forgiven us of those our many sins and murders which we have committed,"], ["ma aveese le lagona sala mai i o tatou loto,", "and taken away the guilt from our hearts,"], ["e ala i galuega a lona Alo.", "through the merits of his Son."]]},
  {num:11,words:[["Ma o lenei faauta,", "And now behold,"], ["ou uso e,", "my brethren,"], ["talu ai ona pau lea o le mea e mafai ona tatou faia (ona sa avea i tatou ma tagata sili ona se mamao i tagata uma) tatou te salamo ai mai ia tatou agasala uma ma fasiotiga tagata e tele sa tatou faia,", "since it has been all that we could do, (as we were the most lost of all mankind) to repent of all our sins and the many murders which we have committed,"], ["ma faia i le Atua ia ona aveese i latou mai o tatou loto,", "and to get God to take them away from our hearts,"], ["aua ona pau lea o le mea sa mafai ona tatou faia ia lava ai lo tatou salamo i luma o le Atua e aveese ai e ia o tatou pisia—", "for it was all we could do to repent sufficiently before God that he would take away our stain—"]]},
  {num:12,words:[["O lenei,", "Now,"], ["ou uso e ua sili ona pele,", "my best beloved brethren,"], ["talu ai ona ua aveese e le Atua o tatou pisia,", "since God hath taken away our stains,"], ["ma ua iila a tatou pelu,", "and our swords have become bright,"], ["o lea ia tatou le toe faapisipisia ai a tatou pelu i le toto o o tatou uso.", "then let us stain our swords no more with the blood of our brethren."]]},
  {num:13,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["E leai,", "Nay,"], ["a ia tatou taofi a tatou pelu ina ia le pisia i le toto o o tatou uso;", "let us retain our swords that they be not stained with the blood of our brethren;"], ["aua atonu,", "for perhaps,"], ["afai tatou te toe faapisipisia a tatou pelu o le a le mafai ona toe fufulu iila i latou e ala i le toto o le Alo o lo tatou Atua silisili,", "if we should stain our swords again they can no more be washed bright through the blood of the Son of our great God,"], ["lea o le a faamaligi mo le togiolaina o a tatou agasala.", "which shall be shed for the atonement of our sins."]]},
  {num:14,words:[["Ma ua alofa mutimutivale mai le Atua silisili ia te i tatou,", "And the great God has had mercy on us,"], ["ma faailoa mai nei mea ia i tatou ina ia tatou le fano;", "and made these things known unto us that we might not perish;"], ["ioe,", "yea,"], ["ma ua ia muai faailoa mai nei mea ia i tatou,", "and he has made these things known unto us beforehand,"], ["ona ua alofa o ia i o tatou agaga e pei ona alofa o ia ia tatou fanau; o lea,", "because he loveth our souls as well as he loveth our children;"], ["o lona alofa mutimutivale ua ia asiasi mai ai ia i tatou e ala i ana agelu,", "therefore,"], ["ina ia mafai ona faaali mai ia te i tatou le fuafuaga o le olataga,", "in his mercy he doth visit us by his angels,"], ["e faapea foi i tupulaga i le lumanai.", "that the plan of salvation might be made known unto us as well as unto future generations."]]},
  {num:15,words:[["E,", "Oh,"], ["ua alofa mutimutivale tele lo tatou Atua! Ma o lenei faauta,", "how merciful is our God! And now behold,"], ["talu ai ona ua pau lea o se mea ua mafai ona tatou faia e aveese ai o tatou pisia mai ia i tatou,", "since it has been as much as we could do to get our stains taken away from us,"], ["ma faaiila ai a tatou pelu,", "and our swords are made bright,"], ["ia tatou natia i latou ina ia mafai ona tausia pea lo latou iila, o se molimau i lo tatou Atua,", "let us hide them away that they may be kept bright,"], ["i le aso gataaga,", "as a testimony to our God at the last day,"], ["po o le aso o le a aumai ai i tatou e tutu i ona luma e faamasinoina,", "or at the day that we shall be brought to stand before him to be judged,"], ["sa tatou le faapisipisiaina a tatou pelu i le toto o o tatou uso talu ona ia tuuina mai lana afioga ia te i tatou ma ia faamamaina ai i tatou.", "that we have not stained our swords in the blood of our brethren since he imparted his word unto us and has made us clean thereby."]]},
  {num:16,words:[["Ma o lenei,", "And now,"], ["ou uso e,", "my brethren,"], ["afai e saili o tatou uso e faaumatia i tatou,", "if our brethren seek to destroy us,"], ["faauta,", "behold,"], ["o le a tatou natia ese a tatou pelu,", "we will hide away our swords,"], ["ioe,", "yea,"], ["o le a tatou tanu loloto i latou i le eleele, ina ia tausia pea lo latou iila,", "even we will bury them deep in the earth,"], ["o se molimau,", "that they may be kept bright,"], ["i le aso gataaga,", "as a testimony that we have never used them,"], ["sa tatou le faaaogaina lava i latou;", "at the last day;"], ["ma afai e faaumatia i tatou e o tatou uso,", "and if our brethren destroy us,"], ["faauta,", "behold,"], ["o le a tatou o atu i lo tatou Atua ma o le a faaolaina i tatou.", "we shall go to our God and shall be saved."]]},
  {num:17,words:[["Ma o lenei sa oo ina ua uma ona faaiu atu e le tupu nei upu,", "And now it came to pass that when the king had made an end of these sayings,"], ["ma sa faapotopoto faatasi le nuu atoa,", "and all the people were assembled together,"], ["sa latou ave a latou pelu,", "they took their swords,"], ["ma auupega uma ia sa faaaoga i le faamaligiina o toto o tagata,", "and all the weapons which were used for the shedding of man's blood,"], ["ma ua latou tanumia loloto i latou i le eleele.", "and they did bury them up deep in the earth."]]},
  {num:18,words:[["Ma sa latou faia lenei mea,", "And this they did,"], ["o se mea sa avea i la latou vaaiga o se molimau i le Atua, ma i tagata foi,", "it being in their view a testimony to God,"], ["o le a latou le toe faaaogaina auupega mo le faamaligiina o le toto o tagata;", "and also to men,"], ["ma sa latou faia lenei mea,", "that they never would use weapons again for the shedding of man's blood;"], ["e faamaonia ma osifeagaiga ai ma le Atua, nai lo le faamaligiina o le toto o o latou uso,", "and this they did,"], ["o le a latou tuuina atu o latou lava ola;", "vouching and covenanting with God,"], ["ma nai lo le aveese mai i se uso,", "that rather than shed the blood of their brethren they would give up their own lives;"], ["o le a latou foai atu ia te ia; ma nai lo le faama'umau o o latou aso i le paie,", "and rather than take away from a brother they would give unto him;"], ["o le a latou galulue malolosi i o latou lava lima.", "and rather than spend their days in idleness they would labor abundantly with their hands."]]},
  {num:19,words:[["Ma ua faapea ona tatou iloa ai,", "And thus we see that,"], ["ina ua aumai nei sa Lamanā ia talitonu ma ia latou iloa le upumoni,", "when these Lamanites were brought to believe and to know the truth,"], ["sa tutumau i latou,", "they were firm,"], ["ma latou tuu ia oo mai lava le oti ia te i latou, nai lo le faia o le agasala;", "and would suffer even unto death rather than commit sin;"], ["ma ua faapea ona tatou vaai ai ua latou tanumiaina a latou auupega o le filemu,", "and thus we see that they buried their weapons of peace,"], ["pe ua latou tanumiaina auupega o taua,", "or they buried the weapons of war,"], ["mo le filemu.", "for peace."]]},
  {num:20,words:[["Ma sa oo ina faia e o latou uso,", "And it came to pass that their brethren,"], ["o sa Lamanā,", "the Lamanites,"], ["sauniuniga mo le taua,", "made preparations for war,"], ["ma o ae i le laueleele o Nifae mo le faamoemoe e fasioti le tupu,", "and came up to the land of Nephi for the purpose of destroying the king,"], ["ma tuu se tasi e sui ia te ia,", "and to place another in his  stead,"], ["ma le faamoemoe foi e faaumatia ese tagata o Aneti-Nifae-Liae mai le laueleele.", "and also of destroying the people of Anti– Nephi– Lehi out of the land."]]},
  {num:21,words:[["O lenei ina ua vaai atu le nuu ua o mai i latou e faasaga ia te i latou,", "Now when the people saw that they were coming against them they went out to meet them,"], ["sa latou o atu i fafo e faafeiloai i latou,", "and prostrated themselves before them to the earth,"], ["ma latou faapauu fao i latou lava i le eleele i o latou luma, ma amata ona latou valaau atu i le suafa o le Alii;", "and began to call on the name of the Lord;"], ["ma o le tulaga lea sa faapea ona latou i ai ina ua amata ona pau mai o sa Lamanā i luga o i latou,", "and thus they were in this attitude when the Lamanites began to fall upon them,"], ["ma amata ona latou fasioti o i latou i le pelu.", "and began to slay them with the sword."]]},
  {num:22,words:[["Ma sa faapea,", "And thus without meeting any resistance,"], ["e aunoa ma lo latou feagai ma se tetee,", "they did slay a thousand and five of them;"], ["ona latou fasioti o le tasi le afe ma le lima o i latou; ma ua tatou iloa ua faamanuiaina i latou,", "and we know that they are blessed,"], ["ona ua latou o atu e mau faatasi ma lo latou Atua.", "for they have gone to dwell with their God."]]},
  {num:23,words:[["O lenei ina ua vaai mai sa Lamanā ua le sosola ese o latou uso mai le pelu,", "Now when the Lamanites saw that their brethren would not flee from the sword,"], ["pe liliu faatafa foi i latou i le itu taumatau po o le itu tauagavale,", "neither would they turn aside to the right hand or to the left,"], ["ae ua latou taooto i lalo ma fano ,", "but that they would lie down and perish,"], ["ma vivii atu i le Atua i le taimi lava o fano ai i le pelu—", "and praised God even in the very act of perishing under the sword—"]]},
  {num:24,words:[["O lenei ina ua vaai mai sa Lamanā i lenei mea, sa latou taofi mai le fasioti o i latou;", "Now when the Lamanites saw this they did forbear from slaying them;"], ["ma sa toatele i latou o e na malelena o latou loto i totonu o i latou,", "and there were many whose hearts had swollen in them for those of their brethren who had fallen under the sword,"], ["mo i latou o o latou uso o e ua pauu i lalo i le pelu, ona ua latou salamo i mea na latou faia.", "for they repented of the things which they had done."]]},
  {num:25,words:[["Ma sa oo ina latou lafo i lalo a latou auupega o taua,", "And it came to pass that they threw down their weapons of war,"], ["ma sa latou le fia toe avea,", "and they would not take them again,"], ["ona ua tuia i latou i fasiotiga tagata ua latou faia;", "for they were stung for the murders which they had committed;"], ["ma sa latou o ifo i lalo e pei lava o o latou uso,", "and they came down even as their brethren,"], ["ma faalagolago i le alofa mutimutivale o i latou o e na sii a'e o latou lima e fasioti i latou.", "relying upon the mercies of those whose arms were lifted to slay them."]]},
  {num:26,words:[["Ma sa oo ina faatasi atu i tagata o le Atua i lena aso ni tagata e sili atu nai lo le aofai o e na fasiotia;", "And it came to pass that the people of God were joined that day by more than the number who had been slain;"], ["ma o i latou o e na fasiotia o ni tagata sa amiotonu,", "and those who had been slain were righteous people,"], ["o lea ua leai ai se pogai tatou te masalosalo ai ae ua faaolaina i latou.", "therefore we have no reason to doubt but what they were saved."]]},
  {num:27,words:[["Ma sa leai se tagata amioleaga sa i totonu o i latou o e na fasiotia;", "And there was not a wicked man slain among them;"], ["ae sa sili atu i le afe i latou o e na aumai i le malamalama o le upumoni;", "but there were more than a thousand brought to the knowledge of the truth;"], ["ua faapea ona tatou vaai ai e tele auala e galue ai le Alii e aumai ai le olataga i ona tagata.", "thus we see that the Lord worketh in many ways to the salvation of his people."]]},
  {num:28,words:[["O lenei o le aofai sili ona toatele o i latou o sa Lamanā o e na latou fasiotia le toatele naua o o latou uso, o sa Amalekā ma sa Amulonā,", "Now the greatest number of those of the Lamanites who slew so many of their brethren were Amalekites and Amulonites,"], ["o le toatele o i latou sa mulimuli i le faatulagaga a sa Ne'oa .", "the greatest number of whom were after the order of the Nehors."]]},
  {num:29,words:[["O lenei,", "Now,"], ["i totonu o i latou o e na aufaatasi mai i tagata o le Alii,", "among those who joined the people of the Lord,"], ["sa leai se sa Amalekā po o se sa Amulonā sa i ai,", "there were none who were Amalekites or Amulonites,"], ["po o ni e sa i ai i le faatulagaga a Ne'oa,", "or who were of the order of Nehor,"], ["ae nao i latou o e na tupuga moni mai ia Lamana ma Lemuelu.", "but they were actual descendants of Laman and Lemuel."]]},
  {num:30,words:[["Ma ua faapea ona tatou iloa manino ai,", "And thus we can plainly discern,"], ["pe a uma ona faamalamalamaina o se nuu e ala i le Agaga o le Atua,", "that after a people have been once enlightened by the Spirit of God,"], ["ma latou maua le poto tele e uiga i mea tau i le amiotonu,", "and have had great knowledge of things pertaining to righteousness,"], ["ma ona pauu ese atu ai lea i le agasala ma le solitulafono,", "and then have fallen away into sin and transgression,"], ["o le a sili atu lo latou maaa,", "they become more hardened,"], ["ma faapea ona sili atu ai ona leaga lo latou tulaga nai lo pe a na latou le iloaina nei mea.", "and thus their state becomes worse than though they had never known these things."]]},
];
renderVerseSet(al_ch_24_Verses, 'al-ch24-verses');

var al_ch_25_Verses = [
  {num:1,words:[["Ma faauta,", "And behold,"], ["o lenei sa oo ina feita tele sa Lamanā na,", "now it came to pass that those Lamanites were more angry because they had slain their brethren;"], ["ona ua latou fasiotia o latou uso; o lea na latou tauto ai le taui ma sui i luga o sa Nifaē;", "therefore they swore vengeance upon the Nephites;"], ["ma sa latou le toe taumafai e fasioti tagata o Aneti-Nifae-Liae i le taimi lena.", "and they did no more attempt to slay the people of Anti– Nephi– Lehi at that time."]]},
  {num:2,words:[["Ae sa latou ave a latou autau ma o atu i tuaoi o le laueleele o Sara'emila,", "But they took their armies and went over into the borders of the land of Zarahemla,"], ["ma pauu i luga o tagata o e sa i le laueleele o Amonaea,", "and fell upon the people who were in the land of Ammonihah,"], ["ma faaumatia i latou.", "and destroyed them."]]},
  {num:3,words:[["Ma ina ua mavae lena,", "And after that,"], ["sa latou tauina taua e tele ma sa Nifaē,", "they had many battles with the Nephites,"], ["ia na tutulia ai i latou ma fasiotia.", "in the which they were driven and slain."]]},
  {num:4,words:[["Ma i totonu o sa Lamanā o e na fasiotia,", "And among the Lamanites who were slain were almost all the seed of Amulon and his brethren,"], ["sa toetoe lava o fanau uma a Amulona ma ona uso, o e sa avea ma faitaulaga a Noa,", "who were the priests of Noah,"], ["ma sa fasiotia i latou i lima o sa Nifaē;", "and they were slain by the hands of the Nephites;"]]},
  {num:5,words:[["Ma o e na totoe,", "And the remainder,"], ["ina ua sosola atu i le vao i sasae,", "having fled into the east wilderness,"], ["ma ina ua latou ave faamalosi le mana ma le pule i luga o sa Lamanā,", "and having usurped the power and authority over the Lamanites,"], ["sa latou faatonuina ia faafanoina le toatele o sa Lamanā i le afi ona o lo latou talitonuga—", "caused that many of the Lamanites should perish by fire because of their belief—"]]},
  {num:6,words:[["Ona o le toatele o i latou ,", "For many of them,"], ["ina ua uma ona mafatia i le toesea tele ma le tele naua o puapuaga,", "after having suffered much loss and so many afflictions,"], ["sa amata ona faaosoina i le manatua o upu na talai atu ia te i latou e Arona ma ona uso i lo latou laueleele;", "began to be stirred up in remembrance of the words which Aaron and his brethren had preached to them in their land;"], ["o lea na amata ai ona latou le talitonu i uputuu a o latou tamā,", "therefore they began to disbelieve the traditions of their fathers,"], ["ma talitonu i le Alii,", "and to believe in the Lord,"], ["ma e faapea ua ia tuuina mai le mana tele ia Nifaē;", "and that he gave great power unto the Nephites;"], ["ma sa faapea ona liliu ai le toatele o i latou i le vao.", "and thus there were many of them converted in the wilderness."]]},
  {num:7,words:[["Ma sa oo ina o taitai na o e o le toe vaega o fanau a Amulona ,", "And it came to pass that those rulers who were the remnant of the children of Amulon caused that they should be put to death,"], ["sa latou faatonuina ia fasiotia i latou, ioe,", "yea,"], ["i latou uma o e na talitonu i nei mea.", "all those that believed in these things."]]},
  {num:8,words:[["O lenei o lea faamaturoga na mafua ai le faaosoina o le ita o le toatele o o latou uso;", "Now this martyrdom caused that many of their brethren should be stirred up to anger;"], ["ma sa amata ona i ai o finauga i le vao;", "and there began to be contention in the wilderness;"], ["ma sa amata ona saili e sa Lamanā fanau a Amulona ma ona uso ma amata ona fasioti o i latou;", "and the Lamanites began to hunt the seed of Amulon and his brethren and began to slay them;"], ["ma sa latou sosola i le vao i sasae.", "and they fled into the east wilderness."]]},
  {num:9,words:[["Ma faauta o loo saili i latou e sa Lamanā i le aso nei. Ua faapea ona taunuu ai o upu a Apinati,", "And behold they are hunted at this day by the Lamanites. Thus the words of Abinadi were brought to pass,"], ["ia na ia fai mai e uiga i fanau a faitaulaga o e na faatonuina ia faaoo ia te ia le oti i le afi.", "which he said concerning the seed of the priests who caused that he should suffer death by fire."]]},
  {num:10,words:[["Ona sa fai atu o ia ia te i latou: O le mea o le a outou faia ia te au,", "For he said unto them:"], ["o le a avea ma faatusa o mea o le a oo mai.", "What ye shall do unto me shall be a type of things to come."]]},
  {num:11,words:[["Ma o lenei o Apinati o le tagata muamua lea na mafatia i le oti i le afi ona o lona talitonu i le Atua;", "And now Abinadi was the first that suffered death by fire because of his belief in God;"], ["o lenei o le uiga lenei o lana upu,", "now this is what he meant,"], ["e toatele o le a mafatia i le oti i le afi,", "that many should suffer death by fire,"], ["e pei lava ona mafatia ai o ia.", "according as he had suffered."]]},
  {num:12,words:[["Ma sa ia fai atu i faitaulaga a Noa,", "And he said unto the priests of Noah that their seed should cause many to be put to death,"], ["o a latou fanau o le a mafua ai ona fasiotia o tagata e toatele,", "in the like manner as he was,"], ["i le ala e pei ona fasiotia ai o ia,", "and that they should be scattered abroad and slain,"], ["ma o le a faasalalauina solo i latou ma fasiotia,", "even as a sheep having no shepherd is driven and slain by wild  beasts;"], ["e pei lava o se mamoe ua leai se leoleo mamoe ua tulia ma faaumatia e manu feai; ma o lenei faauta,", "and now behold,"], ["ua faamaonia lava nei upu,", "these words were verified,"], ["ona sa tutulia i latou e sa Lamanā,", "for they were driven by the Lamanites,"], ["ma sa sailia i latou,", "and they were hunted,"], ["ma sa taiaina i latou.", "and they were smitten."]]},
  {num:13,words:[["Ma sa oo ina ua vaai sa Lamanā ua le mafai ona latou faatoilaloina sa Nifaē,", "And it came to pass that when the Lamanites saw that they could not overpower the Nephites they returned again to their own land;"], ["sa latou toe foi atu i lo latou lava laueleele;", "and many of them came over to dwell in the land of Ishmael and the land of Nephi,"], ["ma e toatele i latou na o mai e nonofo i le laueleele o Isamaeli ma le laueleele o Nifae, ma faatasi atu i latou lava i tagata o le Atua,", "and did join themselves to the people of God,"], ["o le nuu lea o Aneti-Nifae-Liae .", "who were the people of Anti– Nephi– Lehi."]]},
  {num:14,words:[["Ma sa latou tanumia foi a latou auupega o taua,", "And they did also bury their weapons of war,"], ["e pei ona sa faia e o latou uso,", "according as their brethren had,"], ["ma sa amata ona avea i latou ma tagata amiotonu;", "and they began to be a righteous people;"], ["ma sa latou savavali i ala o le Alii,", "and they did walk in the ways of the Lord,"], ["ma sa latou taulai e tausi ana poloaiga ma ana tulafono.", "and did observe to keep his commandments and his statutes."]]},
  {num:15,words:[["Ioe,", "Yea,"], ["ma sa latou tausia le tulafono a Mose;", "and they did keep the law of Moses;"], ["aua sa tatau ai ona latou tausia pea o le tulafono a Mose,", "for it was expedient that they should keep the law of Moses as yet,"], ["ona e lei faataunuuina uma. Ae e ui i le tulafono a Mose,", "for it was not all fulfilled. But notwithstanding the law of Moses,"], ["sa latou taulai i luma i le afio mai o Keriso,", "they did look forward to the coming of Christ,"], ["i le manatu e faapea o le tulafono a Mose o se faatusa lea o lona afio mai,", "considering that the law of Moses was a type of his coming,"], ["ma talitonu e tatau ona latou tausia pea tu a fafo seia oo i le taimi o le a faaali mai ai o ia ia te i latou.", "and believing that they must keep those outward performances until the time that he should be revealed unto them."]]},
  {num:16,words:[["O lenei sa latou le manatu e oo mai le olataga e ala i le tulafono a Mose;", "Now they did not suppose that salvation came by the law of Moses;"], ["ae sa aoga le tulafono a Mose e faamalosi ai lo latou faatuatua ia Keriso;", "but the law of Moses did serve to strengthen their faith in Christ;"], ["ma o lea sa latou taofi ai se faamoemoe e ala i le faatuatua,", "and thus they did retain a hope through faith,"], ["mo le olataga e faavavau,", "unto eternal salvation,"], ["ma le faalagolago i le agaga o valoaga,", "relying upon the spirit of prophecy,"], ["lea na fetalai mai e uiga i mea o le a oo mai.", "which spake of those things to come."]]},
  {num:17,words:[["Ma o lenei faauta,", "And now behold,"], ["sa olioli tele Amona,", "Ammon,"], ["ma Arona,", "and Aaron,"], ["ma Ominea,", "and Omner,"], ["ma Himinae,", "and Himni,"], ["ma o latou uso,", "and their brethren did rejoice exceedingly,"], ["i le manuia lea sa latou maua i totonu o sa Lamanā,", "for the success which they had had among the Lamanites,"], ["i le vaai i le foai mai e le Alii ia te i latou e tusa ma a latou talosaga ,", "seeing that the Lord had granted unto them according to their prayers,"], ["ma i le faamaoniaina foi e ia o lana afioga ia te i latou i mea uma taitasi.", "and that he had also verified his word unto them in every particular."]]},
];
renderVerseSet(al_ch_25_Verses, 'al-ch25-verses');

var al_ch_26_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["o upu nei a Amona i ona uso, ua faapea ona fai atu:", "these are the words of Ammon to his brethren,"], ["Ou uso e,", "which say thus:"], ["ma ou au uso, faauta ou te fai atu ia te outou,", "My brothers and my brethren,"], ["ua tele lava se pogai tatou te olioli ai;", "behold I say unto you,"], ["ona sa mafai ea ona tatou manatu, ina ua tatou amata mai le laueleele o Sara'emila,", "how great reason have we to rejoice;"], ["o le a tuuina mai e le Atua ia te i tatou ni faamanuiaga tetele faapenei?", "for could we have supposed when we started from the land of Zarahemla that God would have granted unto us such great blessings?"]]},
  {num:2,words:[["Ma o lenei,", "And now,"], ["ou te fesili atu,", "I ask,"], ["o a faamanuiaga silisili ua ia tuuina mai ia te i tatou? E mafai ona outou tau mai?", "what great blessings has he bestowed upon us? Can ye tell?"]]},
  {num:3,words:[["Faauta,", "Behold,"], ["ou te tali atu mo outou;", "I answer for you;"], ["ona o o tatou uso,", "for our brethren,"], ["o sa Lamanā,", "the Lamanites,"], ["sa i ai i le pouliuli,", "were in darkness,"], ["ioe,", "yea,"], ["i se to ua sili lava ona pouliuli;", "even in the darkest abyss,"], ["ae faauta,", "but behold,"], ["i le toatele o i latou ua aumai e vaai i le malamalama ofoofogia o le Atua! Ma o le faamanuiaga lenei ua faaee mai i o tatou luga,", "how many of them are brought to behold the marvelous light of God! And this is the blessing which hath been bestowed upon us,"], ["lea ua avea ai i tatou o ni mea faigaluega i aao o le Atua e faataunuu ai lenei galuega tele.", "that we have been made instruments in the hands of God to bring about this great work."]]},
  {num:4,words:[["Faauta,", "Behold,"], ["e afe ma afe i latou ua olioli,", "thousands of them do rejoice,"], ["ma ua aumai i le lafu a le Atua.", "and have been brought into the fold of God."]]},
  {num:5,words:[["Faauta,", "Behold,"], ["sa matua le faatoaga ,", "the field was ripe,"], ["ma amuia lava outou,", "and blessed are ye,"], ["ona sa outou sasau atu le selesaito ,", "for ye did thrust in the sickle,"], ["ma outou selesele mai ma lo outou malosi,", "and did reap with your might,"], ["ioe,", "yea,"], ["sa outou galulue i le aso atoa;", "all the day long did ye labor;"], ["ma faauta i le tele o a outou fusisaito ! Ma o le a faaputuputuina i latou i falesaito,", "and behold the number of your sheaves! And they shall be gathered into the garners,"], ["ina ia le faama'umauina i latou.", "that they are not wasted."]]},
  {num:6,words:[["Ioe,", "Yea,"], ["o le a le taia i latou i lalo e le afa i le aso gataaga;", "they shall not be beaten down by the storm at the last day;"], ["ioe,", "yea,"], ["pe lagā foi i luga i latou e le asiosio;", "neither shall they be harrowed up by the whirlwinds;"], ["ae a sau le afa o le a faaputuputu faatasi i latou i o latou nofoaga,", "but when the storm cometh they shall be gathered together in their place,"], ["ina ia le mafai e le afa ona ulu atu ia te i latou;", "that the storm cannot penetrate to them;"], ["ioe,", "yea,"], ["pe faalelea foi i latou e matagi malolosi i soo se mea e manao le fili e ave i ai i latou.", "neither shall they be driven with fierce winds whithersoever the enemy listeth to carry them."]]},
  {num:7,words:[["Ae faauta,", "But behold,"], ["ua i ai i latou i aao o le Alii o le seleselega ,", "they are in the hands of the Lord of the harvest,"], ["ma o i latou o ana;", "and they are his;"], ["ma o le a ia faatutu mai i latou i luga i le aso gataaga.", "and he will raise them up at the last day."]]},
  {num:8,words:[["Ia faamanuina lava le suafa o lo tatou Atua;", "Blessed be the name of our God;"], ["ia tatou pepese i lona viiga,", "let us sing to his praise,"], ["ioe,", "yea,"], ["ia tatou avatu le faafetai i lona suafa paia,", "let us give thanks to his holy name,"], ["ona ua faia e ia le amiotonu e faavavau.", "for he doth work righteousness forever."]]},
  {num:9,words:[["Aua a na tatou le o mai i fafo mai le laueleele o Sara'emila,", "For if we had not come up out of the land of Zarahemla,"], ["o o tatou uso pele nei,", "these our dearly beloved brethren,"], ["o e ua sili ona alolofa ia te i tatou,", "who have so dearly beloved us,"], ["po ua fālō pea i latou i le ita faasaga mai ia te i tatou,", "would still have been racked with hatred against us,"], ["ioe,", "yea,"], ["ma po ua avea foi i latou o ni tagata ese i le Atua.", "and they would also have been strangers to God."]]},
  {num:10,words:[["Ma sa oo ina ua uma ona fai mai e Amona nei upu,", "And it came to pass that when Ammon had said these words,"], ["sa aoai atu lona uso o Arona ia te ia,", "his brother Aaron rebuked him,"], ["ua fai atu:", "saying:"], ["Amona e,", "Ammon,"], ["ou te fefe ua aveese atu oe i le mitamitavale e lou olioli.", "I fear that thy joy doth carry thee away unto boasting."]]},
  {num:11,words:[["Ae sa fai mai Amona ia te ia:", "But Ammon said unto him:"], ["Ou te le mitamita i lo'u lava malosi,", "I do not boast in my own strength,"], ["po o lo'u lava poto;", "nor in my own wisdom;"], ["ae faauta,", "but behold,"], ["ua atoatoa lo'u olioli ,", "my joy is full,"], ["ioe,", "yea,"], ["ua tumu lo'u loto i le olioli,", "my heart is brim with joy,"], ["ma o le a ou olioli i lo'u Atua.", "and I will rejoice in my God."]]},
  {num:12,words:[["Ioe,", "Yea,"], ["ua ou iloa o au o se meanoa;", "I know that I am nothing;"], ["a faatatau i lo'u malosi ua ou vaivai;", "as to my strength I am weak;"], ["o lea ou te le mitamita ai ia te au lava ia,", "therefore I will not boast of myself,"], ["ae ou te mitamita i lo'u Atua,", "but I will boast of my God,"], ["ona o lona malosi e mafai ai ona ou faia o mea uma;", "for in his strength I can do all things;"], ["ioe,", "yea,"], ["faauta,", "behold,"], ["e tele vavega tetele ua tatou faia i lenei laueleele,", "many mighty miracles we have wrought in this land,"], ["o mea o le a tatou viia ai lona suafa e faavavau.", "for which we will praise his name forever."]]},
  {num:13,words:[["Faauta,", "Behold,"], ["e fia le tele o afe o o tatou uso ua ia tatalaina mai tiga o seoli ;", "how many thousands of our brethren has he loosed from the pains of hell;"], ["ma ua aumai ai i latou e pesea le alofa togiola, ma ua tupu mai lenei mea ona o le mana o lana afioga ua i totonu o i tatou,", "and they are brought to sing redeeming love,"], ["o lea,", "and this because of the power of his word which is in us,"], ["po ua le i ai ea ia te i tatou se pogai tele tatou te olioli ai?", "therefore have we not great reason to rejoice?"]]},
  {num:14,words:[["Ioe,", "Yea,"], ["ua ia i tatou se pogai e viia ai o ia e faavavau,", "we have reason to praise him forever,"], ["ona o ia o le Atua Silisili Ese,", "for he is the Most High God,"], ["ma ua ia tatalaina o tatou uso mai filifili o seoli.", "and has loosed our brethren from the chains of hell."]]},
  {num:15,words:[["Ioe,", "Yea,"], ["sa siosiomia faataamilo i latou i le pouliuli ma le faafanoga tumau-faavavau;", "they were encircled about with ever– lasting darkness and destruction;"], ["ae faauta,", "but behold,"], ["ua ia aumai i latou i lona malamalama tumau-faavavau,", "he has brought them into his everlasting light,"], ["ioe,", "yea,"], ["i le olataga tumau-faavavau,", "into everlasting salvation;"], ["ma ua siosiomia faataamilo i latou i le tele le mafaatusalia o lona alofa;", "and they are encircled about with the matchless bounty of his love;"], ["ioe,", "yea,"], ["ma a avea i tatou o ni mea faigaluega i ona aao i le faia o lenei galuega tele ma le ofoofogia.", "and we have been instruments in his hands of doing this great and marvelous work."]]},
  {num:16,words:[["O lea,", "Therefore,"], ["ia tatou mitamita ai,", "let us glory,"], ["ioe,", "yea,"], ["o le a tatou mitamita i le Alii;", "we will glory in the Lord;"], ["ioe,", "yea,"], ["o le a tatou olioli,", "we will rejoice,"], ["ona ua atoatoa lo tatou olioli;", "for our joy is full;"], ["ioe,", "yea,"], ["o le a tatou viia lo tatou Atua e faavavau. Faauta,", "we will praise our God forever. Behold,"], ["o ai ea e mafai ona tele naua lona mitamita i le Alii? Ioe,", "who can glory too much in the Lord? Yea,"], ["o ai e mafai ona tele naua upu na te faia e uiga i lona mana tele,", "who can say too much of his great power,"], ["ma e uiga i lona alofa mutimutivale,", "and of his  mercy,"], ["ma i lona tali-tiga i le fanauga a tagata? Faauta,", "and of his long– suffering towards the children of men? Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["e le mafai ona ou fai atu se vaega itiiti o le mea ua ou lagona.", "I cannot say the smallest part which I feel."]]},
  {num:17,words:[["O ai sa mafai ona manatu o le a alofa mutimutivale tele mai lo tatou Atua e sei ese i tatou mai lo tatou tulaga leaga matautia,", "Who could have supposed that our God would have been so merciful as to have snatched us from our awful,"], ["ma agasala,", "sinful,"], ["ma eleelea?", "and polluted state?"]]},
  {num:18,words:[["Faauta,", "Behold,"], ["sa tatou o atu i le ita,", "we went forth even in wrath,"], ["ma le faamatau tele e faaumatia lana ekalesia.", "with mighty threatenings to destroy his church."]]},
  {num:19,words:[["O lea,", "Oh then,"], ["aisea na ia le tuu atu ai i tatou i se faafanoga matautia,", "why did he not consign us to an awful destruction,"], ["ioe,", "yea,"], ["aisea na ia le faapau ifo ai i o tatou luga le pelu o lona faamasinotonu,", "why did he not let the sword of his justice fall upon us,"], ["ma faamalaia i tatou i le noa ma se faamoemoe e faavavau?", "and doom us to eternal despair?"]]},
  {num:20,words:[["E,", "Oh,"], ["lou agaga e,", "my soul,"], ["e pei ona sa toeitiiti oo i ai,", "almost as it were,"], ["ia sola ese mai lea manatu. Faauta,", "fleeth at the thought. Behold,"], ["sa ia le faaoo mai lona faamasinotonu i luga o i tatou,", "he did not exercise his justice upon us,"], ["ae na ia aumai i tatou i lona alofa mutimutivale tele i luga o lena vanu tumau-faavavau o le oti ma le pagatia,", "but in his great mercy hath brought us over that everlasting gulf of death and misery,"], ["mo le faaolaina lava o o tatou agaga.", "even to the salvation of our souls."]]},
  {num:21,words:[["Ma o lenei faauta,", "And now behold,"], ["ou uso e,", "my brethren,"], ["o ai se tagata natura o i ai ua ia iloaina nei mea? Ou te fai atu ia te outou,", "what natural man is there that knoweth these things? I say unto you,"], ["ua leai se tasi ua ia iloaina nei mea,", "there is none that knoweth these things,"], ["vagana ai i latou ua salamo.", "save it be the penitent."]]},
  {num:22,words:[["Ioe,", "Yea,"], ["o ia o le e salamo ma faaaoga le faatuatua ,", "he that repenteth and exerciseth faith,"], ["ma fai galuega lelei,", "and bringeth forth good works,"], ["ma tatalo pea e le aunoa—o tagata faapea ua tuuina mai i ai ia latou iloa mealilo a le Atua;", "and prayeth continually without ceasing—unto such it is given to know the mysteries of God;"], ["ioe,", "yea,"], ["o tagata faapea e tuuina mai i ai latou te faaali mai mea e lei faaalia lava;", "unto such it shall be given to reveal things which never have been revealed;"], ["ioe,", "yea,"], ["ma o le a tuuina mai i tagata faapea latou te aumai le afe ma afe o agaga i le salamo,", "and it shall be given unto such to bring thousands of souls to repentance,"], ["e pei lava ona tuuina mai ia i tatou e aumai o tatou uso nei i le salamo.", "even as it has been given unto us to bring these our brethren to repentance."]]},
  {num:23,words:[["O lenei pe tou te manatua ea,", "Now do ye remember,"], ["ou uso e,", "my brethren,"], ["sa tatou fai atu i o tatou uso i le laueleele o Sara'emila,", "that we said unto our brethren in the land of Zarahemla,"], ["o le a tatou o ae i le laueleele o Nifae,", "we go up to the land of Nephi,"], ["e talai atu i o tatou uso,", "to preach unto our brethren,"], ["o sa Lamanā,", "the Lamanites,"], ["ma sa latou tōē faatauemu mai ia te i tatou.", "and they laughed us to scorn?"]]},
  {num:24,words:[["Ona sa latou fai mai ia te i tatou:", "For they said unto us:"], ["Tou te manatu ea e mafai ona outou aumaia sa Lamanā i le malamalama o le upumoni? Tou te manatu e mafai ona outou faatalitonuina sa Lamanā i le sese o uputuu a o latou tamā,", "Do ye suppose that ye can bring the Lamanites to the knowledge of the truth? Do ye suppose that ye can convince the Lamanites of the incorrectness of the traditions of their fathers,"], ["ao avea pea i latou ma tagata ua maaa e pei ona latou i ai nei;", "as stiffnecked a people as they are;"], ["o e ua fiafia o latou loto i le faamasaaina o le toto; o e ua faaaluina o latou aso i le amioletonu sili ona leaga;", "whose hearts delight in the shedding of blood;"], ["o e o o latou ala o ala o se na solitulafono mai i le amataga? O lenei,", "whose days have been spent in the grossest iniquity;"], ["ou uso e,", "whose ways have been the ways of a transgressor from the beginning? Now my brethren,"], ["tou te manatua o la latou gagana lena.", "ye remember that this was their language."]]},
  {num:25,words:[["Ma e le gata i lea,", "And moreover they did say:"], ["sa latou fai mai:", "Let us take up arms against them,"], ["Ia tatou sii auupega o taua e faasaga ia te i latou, ina ia tatou faaumatia ese i latou ma lo latou amioletonu i fafo mai le laueleele,", "that we destroy them and their iniquity out of the land,"], ["nei latou solia i tatou ma faaumatia i tatou.", "lest they overrun us and destroy us."]]},
  {num:26,words:[["Ae faauta,", "But behold,"], ["ou uso pele e,", "my beloved brethren,"], ["sa tatou lei o mai i le vao ma le faamoemoe e faaumatia o tatou uso,", "we came into the wilderness not with the intent to destroy our brethren,"], ["ae ma le faamoemoe atonu e mafai ona tatou faaolaina ni isi e toaitiiti o o latou agaga.", "but with the intent that perhaps we might save some few of their souls."]]},
  {num:27,words:[["O lenei ina ua vaivai o tatou loto,", "Now when our hearts were depressed,"], ["ma toetoe a tatou toe foi i tua,", "and we were about to turn back,"], ["faauta,", "behold,"], ["sa faamafanafanaina i tatou e le Alii,", "the Lord comforted us,"], ["ma fetalai mai:", "and said:"], ["O atu i totonu o o outou uso,", "Go amongst thy brethren,"], ["o sa Lamanā,", "the Lamanites,"], ["ma tauave ma le onosai ou puapuaga ,", "and bear with patience  thine afflictions,"], ["ma o le a ou tuu atu ia te outou le manuia.", "and I will give unto you success."]]},
  {num:28,words:[["Ma o lenei faauta,", "And now behold,"], ["ua tatou o mai,", "we have come,"], ["ma ua tatou i ai i totonu ia te i latou;", "and been forth amongst them;"], ["ma sa tatou onosai i o tatou mafatiaga,", "and we have been patient in our sufferings,"], ["ma sa tatou mafatia i mea uma sa tatou le maua; ioe,", "and we have suffered every privation;"], ["sa tatou malaga atu mai lea fale i lea fale,", "yea,"], ["ma le faalagolago i luga o le alofa mutimutivale o le lalolagi—e le sa nao luga o le alofa mutimutivale o le lalolagi,", "we have traveled from house to house,"], ["ae i luga o le alofa mutimutivale o le Atua.", "relying upon the mercies of the world—not upon the mercies of the world alone but upon the mercies of God."]]},
  {num:29,words:[["Ma sa tatou ulu atu i totonu o o latou fale ma aoao i latou,", "And we have entered into their houses and taught them,"], ["ma sa tatou aoao i latou i o latou auala;", "and we have taught them in their streets;"], ["ioe,", "yea,"], ["ma sa tatou aoao i latou i luga o o latou maupuepue;", "and we have taught them upon their hills;"], ["ma sa tatou ulu atu foi i o latou malumalu ma o latou sunako ma aoao i latou;", "and we have also entered into their temples and their synagogues and taught them;"], ["ma sa tutuli i tatou i fafo,", "and we have been cast out,"], ["ma tauemuina,", "and mocked,"], ["ma feanu tagata i o tatou luga,", "and spit upon,"], ["ma fepo o tatou alafau;", "and smote upon our cheeks;"], ["ma sa fetogi i tatou i maa,", "and we have been stoned,"], ["ma ave ma saisai i maea malolosi,", "and taken and bound with strong cords,"], ["ma lafo i le falepuipui;", "and cast into prison;"], ["ma sa toe laveaiina i tatou e ala i le mana ma le poto o le Atua.", "and through the power and wisdom of God we have been delivered again."]]},
  {num:30,words:[["Ma sa tatou mafatia i ituaiga uma o puapuaga,", "And we have suffered all manner of afflictions,"], ["ma o nei mea uma na tutupu mai,", "and all this,"], ["atonu ina ia mafai ona avea ai i tatou ma ala e faaolaina ai ni nai agaga;", "that perhaps we might be the means of saving some soul;"], ["ma sa tatou manatu o le a atoatoa lo tatou olioli pe afai atonu e mafai ona avea i tatou ma ala e faaolaina ai ni isi.", "and we supposed that our joy would be full if perhaps we could be the means of saving some."]]},
  {num:31,words:[["O lenei faauta,", "Now behold,"], ["e mafai ona tatou vaai atu ma vaai i fua o a tatou galuega;", "we can look forth and see the fruits of our labors;"], ["ma ua itiiti ea i latou? Ou te fai atu ia te outou,", "and are they few? I say unto you,"], ["E leai,", "Nay,"], ["ua toatele i latou;", "they are many;"], ["ioe,", "yea,"], ["ma e mafai ona tatou molimau i lo latou faamaoni,", "and we can witness of their sincerity,"], ["ona o lo latou alolofa i o latou uso ma ia i tatou foi.", "because of their love towards their brethren and also towards us."]]},
  {num:32,words:[["Aua faauta,", "For behold,"], ["sa sili ia i latou le taulagaina o o latou ola nai lo le ave o le ola o so latou fili;", "they had rather sacrifice their lives than even to take the life of their enemy;"], ["ma ua latou tanu loloto i le eleele a latou auupega o taua,", "and they have buried their weapons of war deep in the earth,"], ["ona o lo latou alolofa i o latou uso.", "because of their love towards their brethren."]]},
  {num:33,words:[["Ma o lenei faauta ou te fai atu ia te outou,", "And now behold I say unto you,"], ["sa i ai ea se alofa tele faapea i le laueleele atoa? Faauta,", "has there been so great love in all the land? Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["E leai,", "Nay,"], ["sa lei i ai lava,", "there has not,"], ["e oo lava i totonu o sa Nifaē.", "even among the Nephites."]]},
  {num:34,words:[["Aua faauta,", "For behold,"], ["latou te sii auupega o taua e faasaga i o latou uso;", "they would take up arms against their brethren;"], ["latou te le fia tuu i latou lava ia fasiotia. Ae faauta pe toafia ea o i latou nei na tuuina atu o latou ola;", "they would not suffer themselves to be slain. But behold how many of these have laid down their lives;"], ["ma ua tatou iloa ua latou o atu i lo latou Atua,", "and we know that they have gone to their God,"], ["ona o lo latou alolofa ma ona o lo latou inoino i le agasala.", "because of their love and of their hatred to sin."]]},
  {num:35,words:[["O lenei pe le ua i ai ea ia te i tatou se pogai tatou te olioli ai? Ioe,", "Now have we not reason to rejoice? Yea,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["e lei i ai lava ni tagata na i ai se pogai tele naua latou te olioli ai e pei o i tatou,", "there never were men that had so great reason to rejoice as we,"], ["talu mai le amataga o le lalolagi;", "since the world began;"], ["ioe,", "yea,"], ["ma ua soona tele lava lo'u olioli,", "and my joy is carried away,"], ["ua oo lava i le mitamita i lo'u Atua;", "even unto boasting in my God;"], ["ona ua ia te ia le mana uma,", "for he has all power,"], ["ma le poto uma,", "all wisdom,"], ["ma le malamalama uma;", "and all understanding;"], ["ua silafia e ia mea uma,", "he comprehendeth all things,"], ["ma o ia o se Tagata alofa mutimutivale,", "and he is a merciful Being,"], ["e oo i le olataga,", "even unto salvation,"], ["o i latou o e e salamo ma talitonu i lona suafa.", "to those who will repent and believe on his name."]]},
  {num:36,words:[["O lenei afai o le mitamitavale lea,", "Now if this is boasting,"], ["o le a faapea lava ona ou mitamita;", "even so will I boast;"], ["ona o lo'u ola ma lo'u sulu lea,", "for this is my life and my light,"], ["o lo'u olioli ma lo'u olataga,", "my joy and my salvation,"], ["ma lo'u togiola lea mai le malaia tumau-faavavau. Ioe,", "and my redemption from everlasting wo. Yea,"], ["ia faamanuina lava le suafa o lo'u Atua,", "blessed is the name of my God,"], ["o le ua manatu mai i lenei nuu,", "who has been mindful of this people,"], ["o e o se lala o le laau o Isaraelu,", "who are a  branch of the tree of Israel,"], ["ma ua leiloa mai i lona tino i se laueleele ese;", "and has been lost from its body in a strange land;"], ["ioe,", "yea,"], ["ou te fai atu,", "I say,"], ["ia faamanuina lava le suafa o lo'u Atua,", "blessed be the name of my God,"], ["o le ua manatu mai ia te i tatou,", "who has been mindful of us,"], ["o ni tagata maumausolo i se laueleele ese.", "wanderers in a strange land."]]},
  {num:37,words:[["O lenei ou uso e,", "Now my brethren,"], ["ua tatou vaai e manatu mai le Atua i tagata uma,", "we see that God is mindful of every people,"], ["i soo se laueleele atonu ua latou i ai;", "whatsoever land they may be in;"], ["ioe,", "yea,"], ["ua ia faitauina ona tagata,", "he numbereth his people,"], ["ma o ona loto alofa mutimutivale ua i luga o le lalolagi uma. O lenei o lo'u olioli lea,", "and his bowels of mercy are over all the earth. Now this is my joy,"], ["ma la'u faafetai tele;", "and my great thanksgiving;"], ["ioe,", "yea,"], ["ma o le a ou avatu le faafetai i lo'u Atua e faavavau. Amene.", "and I will give thanks unto my God forever. Amen."]]},
];
renderVerseSet(al_ch_26_Verses, 'al-ch26-verses');

var al_ch_27_Verses = [
  {num:1,words:[["O lenei sa oo ina ua iloa e i latou o sa Lamanā o e na o atu e tau faasaga ia sa Nifaē,", "Now it came to pass that when those Lamanites who had gone to war against the Nephites had found,"], ["ina ua mavae a latou taumafaiga e tele e faaumatia i latou,", "after their many struggles to destroy them,"], ["ua le aoga lo latou saili e faaumatia i latou,", "that it was in vain to seek their destruction,"], ["sa latou toe foi i le laueleele o Nifae.", "they returned again to the land of Nephi."]]},
  {num:2,words:[["Ma sa oo ina sa feita tele sa Amalekā,", "And it came to pass that the Amalekites, because of their loss,"], ["ona o le toatele o o latou ua toesea.", "were exceedingly angry."], ["Ma ina ua latou vaai ua le mafai ona latou saili le taui ma sui mai ia sa Nifaē,", "And when they saw that they could not seek revenge from the Nephites,"], ["sa amata ona latou faaoso tagata ia feita e faasaga i o latou uso ,", "they began to stir up the people in anger against their brethren,"], ["le nuu lea o Aneti-Nifae-Liae ;", "the people of Anti– Nephi– Lehi;"], ["o lea na latou toe amata ai ona faaumatia o i latou.", "therefore they began again to destroy them."]]},
  {num:3,words:[["O lenei sa toe mumusu ia tagata e fetagofi ia latou auupega o taua,", "Now this people again refused to take their arms,"], ["ma sa latou tuu atu i latou lava ia fasiotia e tusa ma manao o o latou fili.", "and they suffered themselves to be slain according to the desires of their enemies."]]},
  {num:4,words:[["O lenei ina ua vaai atu Amona ma ona uso i lenei galuega o le faafanoga i totonu o i latou o e sa sili ona pele ia te i latou,", "Now when Ammon and his brethren saw this work of destruction among those whom they so dearly beloved,"], ["ma i totonu o i latou o e sa sili ona pele ia te i latou,", "and among those who had so dearly beloved them—for they were treated as though they were angels sent from God to save them from everlasting destruction – therefore,"], ["i latou—ona sa latou tausi ia te i latou e pei i latou o ni agelu na auina mai e le Atua e laveai i latou mai le faafanoga e faavavau—o lea, ina ua vaai atu Amona ma ona uso i lenei galuega o le faafanoga tele,", "when Ammon and his brethren saw this great work of destruction,"], ["sa ootia i latou i le agaalofa,", "they were moved with compassion,"], ["ma sa latou fai atu i le tupu:", "and they said unto the king:"]]},
  {num:5,words:[["Ia tatou faapotopoto faatasi lenei nuu o le Alii,", "Let us gather together this people of the Lord,"], ["ma ia tatou o i lalo i le laueleele o Sara'emila i o matou uso o sa Nifaē,", "and let us go down to the land of Zarahemla to our brethren the Nephites,"], ["ma tatou sosola ese i fafo mai lima o o tatou fili,", "and flee out of the hands of our enemies,"], ["ina ia le faaumatiaina i tatou.", "that we be not destroyed."]]},
  {num:6,words:[["Peitai sa fai mai le tupu ia te i latou:", "But the king said unto them:"], ["Faauta,", "Behold,"], ["o le a faaumatia i matou e sa Nifaē,", "the Nephites will destroy us,"], ["ona o fasiotiga tagata ma agasala e tele sa matou faia ia te i latou.", "because of the many murders and sins we have committed against them."]]},
  {num:7,words:[["Ma sa fai atu Amona:", "And Ammon said:"], ["O le a ou alu ma ole atu i le Alii,", "I will go and inquire of the Lord,"], ["ma afai e fetalai mai o ia ia te i tatou,", "and if he say unto us,"], ["ia tatou o i lalo i o matou uso,", "go down unto our brethren,"], ["pe tou te o ea?", "will ye go?"]]},
  {num:8,words:[["Ma sa fai mai le tupu ia te ia:", "And the king said unto him:"], ["Ioe,", "Yea,"], ["afai e fetalai mai le Alii ia te i matou e o,", "if the Lord saith unto us go,"], ["o le a matou o i lalo i o tatou uso,", "we will go down unto our brethren,"], ["ma o le a avea i matou ma a latou pologa seia oo ina matou toe totogi atu ia te i latou mo fasiotiga tagata ma agasala e tele na matou faia ia te i latou.", "and we will be their slaves until we repair unto them the many murders and sins which we have committed against them."]]},
  {num:9,words:[["Peitai sa fai atu Amona ia te ia:", "But Ammon said unto him:"], ["Ua tetee i le tulafono a o matou uso,", "It is against the law of our brethren,"], ["lea na faatu e lo'u tamā, le i ai o ni pologa i totonu ia te i latou;", "which was established by my father,"], ["o lea ia tatou o ai i lalo,", "that there should be any slaves among them;"], ["ma faalagolago i le alofa mutimutivale o o matou uso.", "therefore let us go down and rely upon the mercies of our brethren."]]},
  {num:10,words:[["Peitai sa fai mai le tupu ia te ia:", "But the king said unto him:"], ["Ole atu i le Alii,", "Inquire of the Lord,"], ["ma afai e fetalai mai o ia ia te i matou e o,", "and if he saith unto us go,"], ["o le a matou o;", "we will go;"], ["a leai o le a matou fano pea i le laueleele.", "otherwise we will perish in the land."]]},
  {num:11,words:[["Ma sa oo ina alu atu Amona ma ole i le Alii,", "And it came to pass that Ammon went and inquired of the Lord,"], ["ma sa fetalai mai le Alii ia te ia:", "and the Lord said unto him:"]]},
  {num:12,words:[["Aveese atu i fafo lenei nuu mai lenei laueleele,", "Get this people out of this land,"], ["ina ia le fano i latou;", "that they perish not;"], ["ona ua malosi tele le uu a Satani i loto o sa Amalekā,", "for Satan has great hold on the hearts of the Amalekites,"], ["o e ua faaosoina sa Lamanā ia feita i o latou uso, ia fasioti ia te i latou;", "who do stir up the Lamanites to anger against their brethren to slay them;"], ["o lea ia e alu ese atu ai i fafo mai lenei laueleele;", "therefore get thee out of this land;"], ["ma amuia lava lenei nuu i lenei tupulaga,", "and blessed are this people in this generation,"], ["ona o le a ou faasaoina i latou.", "for I will preserve them."]]},
  {num:13,words:[["Ma o lenei sa oo ina alu atu Amona ma tau atu i le tupu upu uma na fetalai mai ai le Alii ia te ia.", "And now it came to pass that Ammon went and told the king all the words which the Lord had said unto him."]]},
  {num:14,words:[["Ma sa latou faapotopoto faatasi o latou tagata uma,", "And they gathered together all their people,"], ["ioe,", "yea,"], ["tagata uma o le Alii,", "all the people of the Lord,"], ["ma faapotopoto faatasi a latou lafu ma fagaga uma,", "and did gather together all their flocks and herds,"], ["ma o ese atu i fafo o le laueleele,", "and departed out of the land,"], ["ma o mai i le vao lea sa vavae ai le laueleele o Nifae mai le laueleele o Sara'emila,", "and came into the wilderness which divided the land of Nephi from the land of Zarahemla,"], ["ma o mai i luga latalata i tuaoi o le laueleele.", "and came over near the borders of the land."]]},
  {num:15,words:[["Ma sa oo ina fai atu Amona ia te i latou:", "And it came to pass that Ammon said unto them:"], ["Faauta,", "Behold,"], ["o au ma ou uso o le a matou o atu i le laueleele o Sara'emila,", "I and my brethren will go forth into the land of Zarahemla,"], ["ae o le a outou faatali atu iinei seia matou foi mai;", "and ye shall remain here until we return;"], ["ma o le a matou tofotofoina loto o o matou uso,", "and we will try the hearts of our brethren,"], ["pe latou te loto ia outou o mai i lo latou laueleele.", "whether they will that ye shall come into their land."]]},
  {num:16,words:[["Ma sa oo ina ao alu atu Amona i le laueleele,", "And it came to pass that as Ammon was going forth into the land,"], ["sa feiloai o ia ma ona uso ma Alema,", "that he and his brethren met Alma,"], ["i le nofoaga lea sa taua;", "over in the place of which has been spoken;"], ["ma faauta,", "and behold,"], ["sa o se feiloaiga olioli tele lenei feiloaiga.", "this was a joyful meeting."]]},
  {num:17,words:[["O lenei sa matua tele lava le olioli o Amona sa oo ina faatumulia o ia;", "Now the joy of Ammon was so great even that he was full;"], ["ioe,", "yea,"], ["sa tofatumoanaina o ia i le olioli i lona Atua,", "he was swallowed up in the joy of his God,"], ["sa oo ina uma lona malosi;", "even to the exhausting of his strength;"], ["ma sa toe pau ai o ia i le eleele.", "and he fell again to the earth."]]},
  {num:18,words:[["O lenei pe le o le olioli tele ea lenei? Faauta, o le olioli lenei e le maua e se tasi,", "Now was not this exceeding joy? Behold,"], ["vagana ai le ua salamo faamaoni ma le ua saili mo le fiafia ma le lotomaualalo.", "this is joy which none receiveth save it be the truly penitent and humble seeker of happiness."]]},
  {num:19,words:[["O lenei sa matua tele moni lava le olioli o Alema i le feiloaiga ma ona uso,", "Now the joy of Alma in meeting his brethren was truly great,"], ["ma le olioli foi o Arona,", "and also the joy of Aaron,"], ["ma Ominea, ma Himinae;", "of Omner,"], ["peitai faauta,", "and Himni;"], ["sa le sili atu lo latou olioli nai lo latou malolosi.", "but behold their joy was not that to exceed their strength."]]},
  {num:20,words:[["Ma o lenei sa oo ina toe taitai atu e Alema ona uso i tua i le laueleele o Sara'emila;", "And now it came to pass that Alma conducted his brethren back to the land of Zarahemla;"], ["i lona lava fale. Ma sa latou o atu ma faamatala atu i le faamasino sili mea uma na oo ia te i latou i le laueleele o Nifae,", "even to his own house. And they went and told the chief judge all the things that had happened unto them in the land of Nephi,"], ["i totonu o o latou uso,", "among their brethren,"], ["o sa Lamanā.", "the Lamanites."]]},
  {num:21,words:[["Ma sa oo ina auina atu e le faamasino sili se folafolaga i le laueleele atoa,", "And it came to pass that the chief judge sent a proclamation throughout all the land,"], ["e fia iloa le leo o le nuu e uiga i le faatagaina o o latou uso,", "desiring the voice of the people concerning the admitting their brethren,"], ["o e o tagata o Aneti-Nifae-Liae.", "who were the people of Anti–Nephi–Lehi."]]},
  {num:22,words:[["Ma sa oo ina oo mai le leo o le nuu,", "And it came to pass that the voice of the people came,"], ["fai mai:", "saying:"], ["Faauta,", "Behold,"], ["o le a tatou tuu atu le laueleele o Seasona,", "we will give up the land of Jershon,"], ["lea o loo i le itu i sasae o le sami,", "which is on the east by the  sea,"], ["lea ua sosoo ma le laueleele o Nuumau,", "which joins the land Bountiful,"], ["lea o loo i le itu i saute o le laueleele o Nuumau;", "which is on the south of the land Bountiful;"], ["ma o le laueleele lenei o Seasona o le laueleele lea o le a tatou tuu atu i o tatou uso mo o latou tofi.", "and this land Jershon is the land which we will give unto our brethren for an inheritance."]]},
  {num:23,words:[["Ma faauta,", "And behold,"], ["o le a tatou tuu a tatou autau i le va o le laueleele o Seasona ma le laueleele o Nifae,", "we will set our armies between the land Jershon and the land Nephi,"], ["ina ia mafai ona tatou puipui o tatou uso i le laueleele o Seasona;", "that we may protect our brethren in the land Jershon;"], ["ma o le a tatou faia lenei mea mo o tatou uso,", "and this we do for our brethren,"], ["ona o lo latou matatau e fetagofi i auupega o taua e faasaga i o latou uso ne'i o latou faia le agasala;", "on account of their fear to take up arms against their brethren lest they should commit sin;"], ["ma ua oo mai ia te i latou lenei matau tele ona o lo latou salamo faanoanoa tele lea na oo ia te i latou,", "and this their great fear came because of their sore repentance which they had,"], ["ona o le tele o a latou fasiotiga tagata ma lo latou amioleaga matautia.", "on account of their many murders and their awful wickedness."]]},
  {num:24,words:[["Ma o lenei faauta,", "And now behold,"], ["o le a tatou faia lenei mea mo o tatou uso,", "this will we do unto our brethren,"], ["ina ia mafai ona fai mo o latou tofi le laueleele o Seasona;", "that they may inherit the land Jershon;"], ["ma o le a tatou puipuia i latou mai i o latou fili ia tatou autau,", "and we will guard them from their enemies with our armies,"], ["pe afai latou te tuu mai ia te i tatou se vaega o a latou mea e fesoasoani ia te i tatou ina ia mafai ona tatou tausia a tatou autau.", "on condition that they will give us a portion of their substance to assist us that we may maintain our armies."]]},
  {num:25,words:[["O lenei,", "Now,"], ["sa oo ina ua faalogo atu Amona i lenei mea,", "it came to pass that when Ammon had heard this,"], ["sa foi atu o ia i le nuu o Aneti-Nifae-Liae,", "he returned to the people of Anti– Nephi– Lehi,"], ["ma Alema foi faatasi ma ia,", "and also Alma with him,"], ["i le vao,", "into the wilderness,"], ["i le mea sa faatutu ai o latou faleie,", "where they had pitched their tents,"], ["ma faailoa atu ia te i latou nei mea uma. Ma sa faamatala atu foi e Alema ia te i latou e uiga i lona liliu mai,", "and made known unto them all these things. And Alma also related unto them his conversion,"], ["faatasi ma Amona ma Arona,", "with Ammon and Aaron,"], ["ma ona uso.", "and his brethren."]]},
  {num:26,words:[["Ma sa oo ina o lenei mea na oo ifo ai le olioli tele i totonu o i latou. Ma sa latou o atu i lalo i le laueleele o Seasona,", "And it came to pass that it did cause great joy among them. And they went down into the land of Jershon,"], ["ma avea le laueleele o Seasona e fai mo i latou;", "and took possession of the land of Jershon;"], ["ma sa taua i latou e sa Nifaē o le nuu o Amona;", "and they were called by the Nephites the people of Ammon;"], ["o lea na faailogaese ai i latou i lena igoa mai le taimi lena.", "therefore they were distinguished by that name ever after."]]},
  {num:27,words:[["Ma sa i ai i latou i totonu o le nuu o Nifae,", "And they were among the people of Nephi,"], ["ma faitauina foi i totonu o tagata o e sa auai i le ekalesia a le Atua. Ma sa ilogaese foi i latou i lo latou finafinau i le Atua,", "and also numbered among the people who were of the church of God. And they were also distinguished for their zeal towards God,"], ["ma i tagata foi;", "and also towards men;"], ["ona sa latou faamaoni atoatoa ma amiotonu i mea uma;", "for they were perfectly honest and upright in all things;"], ["ma sa latou mausali i lo latou faatuatua ia Keriso,", "and they were firm in the faith of Christ,"], ["e oo i le iuga.", "even unto the end."]]},
  {num:28,words:[["Ma sa latou manatu i le faamasaaina o le toto o o latou uso ma le inoino tele;", "And they did look upon shedding the blood of their brethren with the greatest abhorrence;"], ["ma sa le mafai lava ona faatauanauina i latou ia fetagofi i auupega o taua e faasaga i o latou uso;", "and they never could be prevailed upon to take up arms against their brethren;"], ["ma sa latou le vaai lava i le oti ma sina tikeri o le fefe, ona o lo latou faamoemoe ma taofi e uiga ia Keriso ma le toetutu;", "and they never did look upon death with any degree of terror,"], ["o lea,", "for their hope and views of Christ and the resurrection;"], ["ia te i latou lava,", "therefore,"], ["ua tofatumoanaina le oti i le manumalo ai o Keriso i ona luga.", "death was swallowed up to them by the victory of Christ over it."]]},
  {num:29,words:[["O lea,", "Therefore,"], ["na latou tuu ai le oti ia oo mai ia te i latou i le ala sili ona leaga ma tiga e mafai ona faia e o latou uso,", "they would suffer death in the most aggravating and distressing manner which could be inflicted by their brethren,"], ["ae latou te lei ave le pelu po o le simetea e taia ai i latou.", "before they would take the sword or cimeter to smite them."]]},
  {num:30,words:[["Ma sa faapea ona avea o i latou ma tagata finafinau ma peleina,", "And thus they were a zealous and beloved people,"], ["o se nuu faapitoa tele o le Alii.", "a highly favored people of the Lord."]]},
];
renderVerseSet(al_ch_27_Verses, 'al-ch27-verses');

var al_ch_28_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina ua mavae ona faamautuina o le nuu o Amona i le laueleele o Seasona ,", "And now it came to pass that after the people of Ammon were established in the land of Jershon,"], ["ma faatuina foi se aulotu i le laueleele o Seasona,", "and a church also established in the land of Jershon,"], ["ma faatutuina autau a sa Nifaē faataamilo i le laueleele o Seasona,", "and the armies of the Nephites  were set round about the land of Jershon,"], ["ioe,", "yea,"], ["i tuaoi uma faataamilo i le laueleele o Sara'emila;", "in all the borders round about the land of Zarahemla;"], ["faauta sa mulimuli mai autau a sa Lamanā i o latou uso i le vao.", "behold the armies of the Lamanites had followed their brethren into the wilderness."]]},
  {num:2,words:[["Ma sa faapea ona faia ai o se taua matautia tele;", "And thus there was a tremendous battle;"], ["ioe,", "yea,"], ["o se taua matautia tele faapea e lei vaaia muamua i totonu o tagata uma i le laueleele mai i le taimi na tuua ai Ierusalema e Liae;", "even such an one as never had been known among all the people in the land from the time Lehi left Jerusalem;"], ["ioe,", "yea,"], ["ma sa tai sefulu o afe o sa Lamanā na fasiotia ma faasalalau solo.", "and tens of thousands of the Lamanites were slain and scattered abroad."]]},
  {num:3,words:[["Ioe,", "Yea,"], ["ma sa i ai foi se fasiga tele i totonu o le nuu o Nifae;", "and also there was a tremendous slaughter among the people of Nephi;"], ["e ui i lea,", "nevertheless,"], ["sa tutulia ma faasalalauina sa Lamanā,", "the Lamanites were driven and scattered,"], ["ma toe foi mai tagata o Nifae i lo latou laueleele.", "and the people of Nephi returned again to their land."]]},
  {num:4,words:[["Ma o lenei o se taimi lea sa i ai se faanoanoa ma se auega tele sa faalogoina i le laueleele atoa,", "And now this was a time that there was a great mourning and lamentation heard throughout all the land,"], ["i totonu o tagata uma o Nifae—", "among all the people of Nephi—"]]},
  {num:5,words:[["Ioe,", "Yea,"], ["o le tagi a fafine na oti a latou tane i le faanoanoa mo a latou tane,", "the cry of widows mourning for their husbands,"], ["ma tamā foi i le faanoanoa mo o latou atalii,", "and also of fathers mourning for their sons,"], ["ma le afafine mo le tuagane,", "and the daughter for the brother,"], ["ioe,", "yea,"], ["o le tuagane mo le tamā;", "the brother for the father;"], ["ma sa faapea ona faalogoina o le tagi o le faanoanoa i totonu o i latou uma,", "and thus the cry of mourning was heard among all of them,"], ["i le faanoanoa mo tagata o o latou aiga o e ua fasiotia.", "mourning for their kindred who had been slain."]]},
  {num:6,words:[["Ma o lenei e moni o se aso sa faanoanoa tele lea;", "And now surely this was a sorrowful day;"], ["ioe,", "yea,"], ["o se taimi o le mafaufau loloto,", "a time of solemnity,"], ["ma o se taimi o le anapogi tele ma le tatalo.", "and a time of much fasting and prayer."]]},
  {num:7,words:[["Ma sa faapea ona iu o le lona sefulu lima o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae;", "And thus endeth the fifteenth year of the reign of the judges over the people of Nephi;"]]},
  {num:8,words:[["Ma o le tala lenei e uiga ia Amona ma ona uso,", "And this is the account of Ammon and his brethren,"], ["a latou malaga i le laueleele o Nifae,", "their journeyings in the land of Nephi,"], ["o latou mafatiaga i le laueleele,", "their sufferings in the land,"], ["o latou faanoanoaga,", "their sorrows,"], ["ma o latou puapuaga,", "and their afflictions,"], ["ma lo latou olioli le mafuatia,", "and their incomprehensible joy,"], ["ma le taliaina ma le saogalemu o le au uso i le laueleele o Seasona. Ma o lenei ia talosia ia faamanuiaina o latou agaga e le Alii,", "and the reception and safety of the brethren in the land of Jershon. And now may the Lord,"], ["le Togiola o tagata uma,", "the Redeemer of all men,"], ["e faavavau.", "bless their souls forever."]]},
  {num:9,words:[["Ma o le tala lenei o taua ma finauga i totonu o sa Nifaē,", "And this is the account of the wars and contentions among the Nephites,"], ["ma taua foi i le va o sa Nifaē ma sa Lamanā;", "and also the wars between the Nephites and the Lamanites;"], ["ma ua iu le lona sefulu lima o tausaga o le nofoaiga a faamasino.", "and the fifteenth year of the reign of the judges is ended."]]},
  {num:10,words:[["Ma mai i le tausaga muamua i le tausaga e sefulu lima,", "And from the first year to the fifteenth has brought to pass the destruction of many thousand lives;"], ["na aumai ai le faafanoga o le tele o afe o ola; ioe,", "yea,"], ["na oo mai ai se vaaiga matautia o le faamasaatoto.", "it has brought to pass an awful scene of bloodshed."]]},
  {num:11,words:[["Ma o tino o le tele o afe o tagata ua faataooto maualalalo i le eleele,", "And the bodies of many thousands are laid low in the earth,"], ["ao tino o isi afe e tele ua palanai i faupuega i luga o le eleele;", "while the bodies of many thousands are moldering in heaps upon the face of the earth;"], ["ioe,", "yea,"], ["ma e tele afe o tagata ua faanoanoa i le toesea o tagata o o latou aiga ua fasiotia,", "and many thousands are mourning for the loss of their kindred,"], ["ona sa ia te i latou se pogai sa matatau ai,", "because they have reason to fear,"], ["e tusa ma folafolaga a le Alii,", "according to the promises of the Lord,"], ["ua tuuina i latou i se tulaga o le malaia e le gata.", "that they are consigned to a state of endless wo."]]},
  {num:12,words:[["Ao o le tele o afe o isi tagata sa faanoanoa moni i le toesea o tagata o o latou aiga,", "While many thousands of others truly mourn for the loss of their kindred,"], ["peitai sa latou olioli ma fiafia i le faamoemoe,", "yet they rejoice and exult in the hope,"], ["ma e oo lava i lo latou mautinoa,", "and even know,"], ["e tusa ma folafolaga a le Alii,", "according to the promises of the Lord,"], ["e faatutu mai i latou e mau i le itu taumatau o le Atua,", "that they are raised to dwell at the right hand of God,"], ["i se tulaga o le fiafia e le gata.", "in a state of never– ending happiness."]]},
  {num:13,words:[["Ma ua faapea ona tatou vaai ai i le lē tutusa tele o tagata ona o le agasala ma le solitulafono,", "And thus we see how great the inequality of man is because of sin and transgression,"], ["ma le mana o le tiapolo,", "and the power of the devil,"], ["lea e ala mai i fuafuaga faitogafiti ia ua ia faia e mailei ai loto o tagata.", "which comes by the cunning plans which he hath devised to ensnare the hearts of men."]]},
  {num:14,words:[["Ma ua faapea ona tatou vaai ai i le valaau malosi atu i tagata ia filiga e galulue i tovine o le Alii;", "And thus we see the great call of diligence of men to labor in the vineyards of the Lord;"], ["ma ua faapea ona tatou vaai ai i le pogai tele o le faanoanoa,", "and thus we see the great reason of sorrow,"], ["ma o le olioli foi—o le faanoanoa ona o le oti ma faafanoga i totonu o tagata,", "and also of rejoicing—sorrow because of death and destruction among men,"], ["ma o le olioli ona o le malamalama o Keriso i le ola.", "and joy because of the light of Christ unto life."]]},
];
renderVerseSet(al_ch_28_Verses, 'al-ch28-verses');

var al_ch_29_Verses = [
  {num:1,words:[["E,", "O that I were an angel,"], ["pe ana o au o se agelu,", "and could have the wish of mine heart,"], ["ma mafai ona ou maua le moomooga o lo'u loto, ina ia mafai ona ou alu atu ma tautala atu ma le pu a le Atua,", "that I might go forth and speak with the trump of God,"], ["ma i se leo e luluina ai le eleele,", "with a voice to shake the earth,"], ["ma alaga atu le salamo i tagata uma!", "and cry repentance unto every people!"]]},
  {num:2,words:[["Ioe,", "Yea,"], ["po ua ou alaga atu i agaga uma taitoatasi,", "I would declare unto every soul,"], ["i se leo e pei o le faititili,", "as with the voice of thunder,"], ["le salamo ma le fuafuaga o le togiolaina,", "repentance and the plan of redemption,"], ["ina ia latou salamo ma o mai i lo tatou Atua,", "that they should repent and come unto our God,"], ["ina ia le toe i ai se faanoanoa i luga o le lalolagi uma.", "that there might not be more sorrow upon all the face of the earth."]]},
  {num:3,words:[["Ae faauta,", "But behold,"], ["o au o se tagata,", "I am a man,"], ["ma ua ou agasala i lo'u manao;", "and do sin in my wish;"], ["ona e tatau ona ou malie i mea ua tuuina mai e le Alii ia te au.", "for I ought to be content with the things which the Lord hath allotted unto me."]]},
  {num:4,words:[["E le tatau ona ou lagā i luga i ou mana'o le poloai mausali a le Atua amiotonu,", "I ought not to harrow up in my desires,"], ["ona ua ou iloa e tuu mai e ia i tagata e tusa ma o latou manao ,", "the firm decree of a just God,"], ["pe mo le oti pe mo le ola;", "for I know that he granteth unto men according to their desire,"], ["ioe,", "whether it be unto death or unto life;"], ["ua ou iloa e tuu mai e ia i tagata,", "yea,"], ["ioe,", "I know that he allotteth unto men,"], ["e poloai mai e ia ia te i latou poloaiga e le masuia,", "yea,"], ["e tusa ma o latou loto ,", "decreeth unto them decrees which are unalterable,"], ["pe mo le olataga i latou,", "according to their wills,"], ["pe mo le faafanoga.", "whether they be unto salvation or unto destruction."]]},
  {num:5,words:[["Ioe,", "Yea,"], ["ma ua ou iloa ua oo mai le lelei ma le leaga i luma o tagata uma;", "and I know that good and evil have come before all men;"], ["o ia o le ua ia le iloaina le lelei mai le leaga ua le tausalaina;", "he that knoweth not good from evil is blameless;"], ["ae o ia o le ua ia iloaina le lelei ma le leaga,", "but he that knoweth good and evil,"], ["e tuuina mai ia te ia e tusa ma ona manao,", "to him it is given according to his desires,"], ["pe manao o ia i le lelei po o le leaga,", "whether he desireth good or evil,"], ["le ola po o le oti,", "life or death,"], ["le olioli po o le faanoanoa o le mafaufau .", "joy or remorse of conscience."]]},
  {num:6,words:[["O lenei,", "Now,"], ["ona ua vaai ua ou iloa nei mea,", "seeing that I know these things,"], ["aisea ou te manao tele ai nai lo le faia o le galuega ua valaauina ai au?", "why should I desire more than to perform the work to which I have been called?"]]},
  {num:7,words:[["Aisea ou te manao ai pe a na o au o se agelu,", "Why should I desire that I were an angel,"], ["ina ia mafai ona ou tautala atu ai i tuluiga uma o le lalolagi?", "that I could speak unto all the ends of the earth?"]]},
  {num:8,words:[["Aua faauta,", "For behold,"], ["ua tuuina mai e le Alii i atunuu uma,", "the Lord doth grant unto all nations,"], ["ni isi o lo latou lava atunuu ma gagana ,", "of their own nation and tongue,"], ["latou te aoao atu lana afioga,", "to teach his word,"], ["ioe,", "yea,"], ["i le poto,", "in wisdom,"], ["mea uma ua ia silafia e tatau ona latou maua;", "all that he seeth fit that they should have;"], ["o lea ua tatou vaai ai e faatonu mai le Alii i le poto,", "therefore we see that the Lord doth counsel in wisdom,"], ["e tusa ma le mea ua tonu ma moni.", "according to that which is just and true."]]},
  {num:9,words:[["Ua ou iloa le mea ua poloaiina ai au e le Alii,", "I know that which the Lord hath commanded me,"], ["ma ua ou mitamita ai. Ou te le mitamita ona o au lava ia,", "and I glory in it. I do not glory of myself,"], ["ae ou te mitamita i le mea ua poloaiina ai au e le Alii;", "but I glory in that which the Lord hath commanded me;"], ["ioe,", "yea,"], ["ma o lou mitamitaga lenei,", "and this is my glory,"], ["atonu ia mafai ona avea au o se auupega i aao o le Atua e aumai ai se agaga i le salamo;", "that perhaps I may be an instrument in the hands of God to bring some soul to repentance;"], ["ma o lou olioli lea.", "and this is my joy."]]},
  {num:10,words:[["Ma faauta,", "And behold,"], ["a ou vaai atu i le toatele o ou uso ua salamo faamaoni,", "when I see many of my brethren truly penitent,"], ["ma ua o mai i le Alii lo latou Atua,", "and coming to the Lord their God,"], ["ona faatumulia lea o lou agaga i le olioli;", "then is my soul filled with joy;"], ["ona ou manatua lea o mea na faia e le Alii mo au,", "then do I remember what the Lord has done for me,"], ["ioe,", "yea,"], ["e oo lava i le faafofogaina e ia o lau tatalo;", "even that he hath heard my prayer;"], ["ioe,", "yea,"], ["ona ou manatua lea o lona aao alofa mutimuti tele na ia faaloaloa mai ia te au.", "then do I remember his merciful arm which he extended towards me."]]},
  {num:11,words:[["Ioe,", "Yea,"], ["ma ou te manatua foi le faatagataotauaina o ou tamā;", "and I also remember the captivity of my fathers;"], ["ona ua ou iloa moni lava sa laveaiina i latou e le Alii mai le pologa,", "for I surely do know that the Lord did deliver them out of bondage,"], ["ma o lenei mea na ia faatuina ai lana ekalesia;", "and by this did establish his church;"], ["ioe,", "yea,"], ["o le Alii le Atua,", "the Lord God,"], ["o le Atua o Aperaamo,", "the God of Abraham,"], ["o le Atua o Isaako,", "the God of Isaac,"], ["ma le Atua o Iakopo,", "and the God of Jacob,"], ["na laveaiina i latou mai le pologa.", "did deliver them out of bondage."]]},
  {num:12,words:[["Ioe,", "Yea,"], ["ua ou manatua pea le faatagataotauaina o ou tamā; ma o lena lava Atua e tasi o le na laveaiina i latou mai lima o tagata Aikupito,", "I have always remembered the captivity of my fathers;"], ["na laveaiina i latou mai le pologa.", "and that same God who delivered them out of the hands of the Egyptians did deliver them out of bondage."]]},
  {num:13,words:[["Ioe,", "Yea,"], ["ma o lena lava Atua e tasi na faatuina lana ekalesia i totonu o i latou;", "and that same God did establish his church among them;"], ["ioe,", "yea,"], ["ma o lena lava Atua na valaauina au i se valaauga paia,", "and that same God hath called me by a holy calling,"], ["e talai atu le afioga i lenei nuu,", "to preach the word unto this people,"], ["ma tuuina mai ia te au le manuia tele,", "and hath given me much success,"], ["o se mea ua atoatoa ai lou olioli .", "in the which my joy is full."]]},
  {num:14,words:[["Peitai ua le nao lou lava manuia ua ou olioli ai,", "But I do not joy in my own success alone,"], ["ae ua sili atu le atoatoa o lou olioli ona o le manuia o ou uso,", "but my joy is more full because of the success of my brethren,"], ["o e na o ae i le laueleele o Nifae.", "who have been up to the land of Nephi."]]},
  {num:15,words:[["Faauta,", "Behold,"], ["sa latou galulue malolosi,", "they have labored exceedingly,"], ["ma ua latou aumai fua e tele;", "and have brought forth much fruit;"], ["ma o le a tele lava lo latou taui!", "and how great shall be their reward!"]]},
  {num:16,words:[["O lenei,", "Now,"], ["pe a ou mafaufau i le manuia o ou uso nei e segia ese atu lou agaga,", "when I think of the success of these my brethren my soul is carried away,"], ["ua oo lava e peiseai ua vavae ese atu ai mai le tino,", "even to the separation of it from the body, as it were,"], ["i le tele naua o lou olioli.", "so great is my joy."]]},
  {num:17,words:[["Ma o lenei ia talosia lava ia tuuina mai e le Atua ia te i latou nei,", "And now may God grant unto these,"], ["o ou uso, ia mafai ona latou nonofo i lalo i le malo o le Atua;", "my brethren,"], ["ioe,", "that they may sit down in the kingdom of God;"], ["ma i latou uma foi o e o fua o a latou galuega,", "yea,"], ["ina ia latou le toe ulufafo atu,", "and also all those who are the fruit of their labors that they may go no more out,"], ["ae ia mafai ona latou viia o ia e faavavau; ma ia talosia lava ia tuuina mai e le Atua ia faia e tusa ma au upu,", "but that they may praise him forever. And may God grant that it may be done according to my words,"], ["e pei lava ona ou tautala atu ai. Amene.", "even as I have spoken. Amen."]]},
];
renderVerseSet(al_ch_29_Verses, 'al-ch29-verses');

var al_ch_30_Verses = [
  {num:1,words:[["Faauta,", "Behold,"], ["o lenei sa oo ina ua uma ona faamautuina o le nuu o Amona i le laueleele o Seasona,", "now it came to pass that after the people of Ammon were established in the land of Jershon,"], ["ioe,", "yea,"], ["ma ina ua uma foi ona tutuli ese o sa Lamanā i fafo mai le laueleele,", "and also after the Lamanites were driven out of the land,"], ["ma tanuina o latou tagata oti e tagata o le laueleele—", "and their dead were buried by the people of the land—"]]},
  {num:2,words:[["O lenei sa le faitauina o latou tagata oti ona o le toatele naua o lo latou aofai;", "Now their dead were not numbered because of the greatness of their numbers;"], ["sa le faitauina foi tagata oti o sa Nifaē—ae sa oo ina ua uma ona latou tanu o o latou tagata oti,", "neither were the dead of the Nephites numbered—but it came to pass after they had buried their dead,"], ["ma ina ua mavae atu foi aso o le anapogi,", "and also after the days of fasting,"], ["ma le faanoanoa,", "and mourning,"], ["ma le tatalo,", "and prayer,"], ["(ma sa tupu lenei mea i le lona sefulu ono o tausaga o le nofoaiga a faamasino i le nuu o Nifae) sa amata ona i ai o le filemu aveaveai i le laueleele atoa.", "(and it was in the sixteenth year of the reign of the judges over the people of Nephi) there began to be continual peace throughout all the land."]]},
  {num:3,words:[["Ioe,", "Yea,"], ["ma sa tausisi tagata e tausi i poloaiga a le Alii;", "and the people did observe to keep the commandments of the Lord;"], ["ma sa latou anaana i le tausiga o sauniga a le Atua,", "and they were strict in observing the ordinances of God,"], ["e tusa ma le tulafono a Mose;", "according to the law of Moses;"], ["ona sa aoaoina i latou e tausi i le tulafono a Mose seia oo ina faataunuuina.", "for they were  taught to keep the law of Moses until it should be fulfilled."]]},
  {num:4,words:[["Ma sa faapea ona leai o se faalavelave i le nuu i le tausaga atoa lona sefulu ono o le nofoaiga a faamasino i le nuu o Nifae.", "And thus the people did have no disturbance in all the sixteenth year of the reign of the judges over the people of Nephi."]]},
  {num:5,words:[["Ma sa oo i le amataga o le lona sefulu fitu o tausaga o le nofoaiga a faamasino,", "And it came to pass that in the commence– ment of the seventeenth year of the reign of the judges,"], ["sa i ai pea le filemu aveaveai.", "there was continual peace."]]},
  {num:6,words:[["Peitai sa oo i le taufaaiuiuga o le lona sefulu fitu o tausaga,", "But it came to pass in the latter end of the seventeenth year,"], ["sa sau ai se tagata i le laueleele o Sara'emila,", "there came a man into the land of Zarahemla,"], ["ma o ia o se Anetī-Keriso ,", "and he was Anti– Christ,"], ["ona sa amata ona ia talai atu i tagata e faasaga i valoaga ia na fetalaia e perofeta,", "for he began to preach unto the people against the prophecies which had been spoken by the prophets,"], ["e uiga i le afio mai o Keriso.", "concerning the coming of Christ."]]},
  {num:7,words:[["O lenei sa leai se tulafono e faasaga i talitonuga o se tagata;", "Now there was no law against a man's belief;"], ["ona sa matua le tusa ai ma poloaiga a le Atua le i ai o se tulafono o le a aumai ai tagata i ni tulaga le tutusa.", "for it was strictly contrary to the commands of God that there should be a law which should bring men on to unequal grounds."]]},
  {num:8,words:[["Ona ua faapea ona fai mai o tusitusiga paia:", "For thus saith the scripture:"], ["Ina filifili ia outou i le aso nei,", "Choose ye this day,"], ["po o ai tou te auauna i ai.", "whom ye will serve."]]},
  {num:9,words:[["O lenei afai ua manao se tagata e auauna i le Atua,", "Now if a man desired to serve God,"], ["o lana aia lea;", "it was his privilege;"], ["pe,", "or rather,"], ["afai ua talitonu o ia i le Atua o lana lava aia lea e auauna atu ai ia te ia;", "if he believed in God it was his privilege to serve him;"], ["ae afai e le talitonu o ia ia te ia sa leai se tulafono e faasala ai o ia.", "but if he did not believe in him there was no law to punish him."]]},
  {num:10,words:[["Peitai afai sa ia fasioti tagata sa faasalaina o ia i le oti ;", "But if he murdered he was punished unto death;"], ["ma afai sa ia faomea sa faasalaina foi o ia;", "and if he robbed he was also punished;"], ["ma afai sa gaoi o ia sa faasalaina foi o ia;", "and if he stole he was also punished;"], ["ma afai sa mulilua o ia sa faasalaina foi o ia;", "and if he committed adultery he was also punished;"], ["ioe,", "yea,"], ["sa faasalaina i latou mo nei amioleaga uma.", "for all this wickedness they were punished."]]},
  {num:11,words:[["Ona sa i ai se tulafono ia faamasinoina tagata e tusa ma a latou solitulafono. E ui i lea,", "For there was a law that men should be judged according to their crimes. Nevertheless,"], ["sa leai se tulafono e faasaga i talitonuga o se tagata;", "there was no law against a man's belief;"], ["o lea,", "therefore,"], ["sa faasalaina ai le tagata mo nao solitulafono sa ia faia;", "a man was punished only for the crimes which he had done;"], ["o lea sa tulaga tutusa tagata uma.", "therefore all men were on equal grounds."]]},
  {num:12,words:[["Ma o lenei Aneti-Keriso,", "And this Anti– Christ,"], ["o lona igoa o Kori'oa,", "whose name was Korihor,"], ["(ma sa le mafai e le tulafono ona taofi o ia) sa amata ona ia talai atu i le nuu o le a le i ai se Keriso. Ma sa faapenei ona talai atu o ia,", "(and the law could have no hold upon him) began to preach unto the people that there should be no Christ. And after this manner did he preach,"], ["ua fai atu:", "saying:"]]},
  {num:13,words:[["E, o outou e ua noanoatia i lalo i se faamoemoe valea ma le aoga,", "O ye that are bound down under a foolish and a vain hope,"], ["aisea ea ua outou faaamo ai outou lava i mea valea faapena? Aisea ua outou tulimatai atu ai mo se Keriso? Ona e leai se tagata e mafai ona ia iloa se mea o le a oo mai.", "why do ye yoke yourselves with such foolish things? Why do ye look for a Christ? For no man can know of anything which is to come."]]},
  {num:14,words:[["Faauta,", "Behold,"], ["o nei mea ua outou taua o valoaga,", "these things which ye call prophecies,"], ["ia ua outou fai mai na tuulima faasolo mai i lalo e perofeta paia,", "which ye say are handed down by holy prophets,"], ["faauta,", "behold,"], ["o ni uputuu valea i latou a o outou tamā.", "they are foolish traditions of your fathers."]]},
  {num:15,words:[["E faapefea ona outou iloa lo latou moni? Faauta,", "How do ye know of their surety? Behold,"], ["e le mafai ona outou iloa e uiga i ni mea tou te le vaai atu i ai;", "ye cannot know of things which ye do not see;"], ["o lea e le mafai ona outou iloa o le a i ai se Keriso.", "therefore ye cannot know that there shall be a Christ."]]},
  {num:16,words:[["Ua outou tulimatai i luma ma fai mai ua outou vaai i se faamagaloga o a outou agasala.", "Ye look forward and say that ye see a remission of your sins."], ["Ae faauta o se fua lea o se mafaufau valea;", "But behold,"], ["ma o lenei faavaleaina o o outou mafaufau ua oo mai ona o uputuu a o outou tamā,", "it is the effect of a frenzied mind; and this derangement of your minds comes because of the traditions of  your fathers,"], ["ia ua taitai ese atu ai outou i se talitonuga i mea ua le moni.", "which lead you away into a belief of things which are not so."]]},
  {num:17,words:[["Ma e tele ni isi mea faapena na ia fai atu ai ia te i latou,", "And many more such things did he say unto them,"], ["na fai atu ai ia te i latou e le mafai ona faia o se togiola mo agasala a tagata,", "telling them that there could be no atonement made for the sins of men,"], ["ae e lelei a tagata taitoatasi ia i le olaga lenei e tusa ma le pulea e le tagata o ia lava;", "but every man fared in this life according to the management of the creature;"], ["o lea e faamanuiaina tagata taitoatasi e tusa ma lona lava atamai,", "therefore every man prospered according to his genius,"], ["ma e manumalo tagata taitoatasi e tusa ma lona lava malosi;", "and that every man conquered according to his strength;"], ["ma o soo se mea sa fai e le tagata e le o se solitulafono.", "and whatsoever a man did was no crime."]]},
  {num:18,words:[["Ma sa faapea ona ia talai atu ia te i latou,", "And thus he did preach unto them,"], ["ma taitai ese atu ai loto o le toatele,", "leading away the hearts of many,"], ["ma faaoso ai i latou ia faamaualuluga i lo latou amioleaga,", "causing them to lift up their heads in their wickedness,"], ["ioe,", "yea,"], ["ma taitai ese atu ai fafine e toatele,", "leading away many women,"], ["ma tane foi,", "and also men,"], ["e fai le faitaaga—ua fai atu ia te i latou a oti le tagata,", "to commit whoredoms—telling them that when a man was dead,"], ["o lona iuga lena.", "that was the end thereof."]]},
  {num:19,words:[["O lenei sa alu atu foi lenei tagata i le laueleele o Seasona,", "Now this man went over to the land of Jershon also,"], ["e talai atu nei mea i le nuu o Amona,", "to preach these things among the people of Ammon,"], ["o e na avea muamua ma tagata o sa Lamanā.", "who were once the people of the Lamanites."]]},
  {num:20,words:[["Ae faauta sa sili atu lo latou popoto nai lo le toatele o sa Nifaē;", "But behold they were more wise than many of the Nephites;"], ["ona sa latou ave o ia,", "for they took him,"], ["ma saisai o ia,", "and bound him,"], ["ma avatu o ia i luma o Amona,", "and carried him before Ammon,"], ["o le sa avea o se faitaulaga sili i luga o lena nuu.", "who was a high priest over that people."]]},
  {num:21,words:[["Ma sa oo ina faatonu e ia ia ave atu o ia i fafo o le laueleele. Ma sa sau o ia i le laueleele o Kitiona,", "And it came to pass that he caused that he should be carried out of the land. And he came over into the land of Gideon,"], ["ma amata ona talai atu foi ia te i latou;", "and began to preach unto them also;"], ["ma sa ia le maua se manuia tele iinei,", "and here he did not have much success,"], ["ona sa ave o ia ma saisai ma avatu i luma o le faitaulaga sili,", "for he was taken and bound and carried before the high priest,"], ["ma i le faamasino sili foi i luga o le laueleele.", "and also the chief judge over the land."]]},
  {num:22,words:[["Ma sa oo ina fai atu le faitaulaga sili ia te ia:", "And it came to pass that the high priest said unto him:"], ["Aisea ua e fealuai ai e faapiopio ala o le Alii? Aisea ua e aoao atu ai i lenei nuu o le a leai se Keriso,", "Why do ye go about perverting the ways of the Lord? Why do ye teach this people that there shall be no Christ,"], ["e taofi ai lo latou olioli? Aisea ua e tautala faatautee ai i valoaga uma a perofeta paia?", "to interrupt their rejoicings? Why do ye speak against all the prophecies of the holy prophets?"]]},
  {num:23,words:[["O lenei o le igoa o le faitaulaga sili o Kitona. Ma sa fai mai Kori'oa ia te ia:", "Now the high priest's name was Giddonah. And Korihor said unto him:"], ["Ona ou te le aoao atu uputuu valea a o outou tamā,", "Because I do not teach the foolish traditions of your fathers,"], ["ma ona ou te le aoao atu i lenei nuu ia latou noanoatia i latou lava i lalo i sauniga ma tu valea ia na faataatitia i lalo e faitaulaga anamua,", "and because I do not teach this people to bind themselves down under the foolish ordinances and performances which are laid down by ancient priests,"], ["latou te ave ai le mana ma le pule i luga o i latou,", "to usurp power and authority over them,"], ["e taofi ai i latou i le valea,", "to keep them in ignorance,"], ["ina ia le mafai ona latou faaeaina o latou ulu,", "that they may not lift up their heads,"], ["ae aumai i latou i lalo e tusa ma au upu.", "but be brought down according to thy words."]]},
  {num:24,words:[["Ua e fai mai o lenei nuu o se nuu saoloto. Faauta,", "Ye say that this people is a free people. Behold,"], ["ou te fai atu ua pologa i latou. Ua e fai mai ua moni ia valoaga mai anamua. Faauta,", "I say they are in bondage. Ye say that those ancient prophecies are true. Behold,"], ["ou te fai atu e te le iloa pe ua moni i latou.", "I say that ye do not know that they are true."]]},
  {num:25,words:[["Ua e fai mai o lenei nuu o se nuu agasala ma se nuu ua pau,", "Ye say that this people is a guilty and a fallen people,"], ["ona o le solitulafono a se matua. Faauta,", "because of the transgression of a parent. Behold,"], ["ou te fai atu ua le sala se tamaitiiti ona o ona matua.", "I say that a child is not guilty because of its parents."]]},
  {num:26,words:[["Ma ua e fai mai foi o le a afio mai Keriso. Ae faauta,", "And ye also say that Christ shall come. But behold,"], ["ou te fai atu e te le iloaina pe o le a i ai se Keriso. Ma ua e fai mai foi o le a fasia o ia mo agasala a le lalolagi—", "I say that ye do not know that there shall  be a Christ. And ye say also that he shall be slain for the sins of the world—"]]},
  {num:27,words:[["Ma ua faapea ona e taitai ese lenei nuu ia mulimuli i uputuu valea a o outou tamā,", "And thus ye lead away this people after the foolish traditions of your fathers,"], ["ma e tusa ai ma ou lava manao;", "and according to your own desires;"], ["ma ua e taofi i latou i lalo,", "and ye keep them down,"], ["e pei lava ua pologa i latou,", "even as it were in bondage,"], ["ina ia outou faaloloto outou lava i galuega a o latou lima,", "that ye may glut yourselves with the labors of their hands,"], ["ua latou fefefe ai e tetepa ae i luga ma le lotoa,", "that they durst not look up with boldness,"], ["ma ua latou fefefe ai e faaaoga a latou aia ma avanoa tatau.", "and that they durst not enjoy their rights and privileges."]]},
  {num:28,words:[["Ioe,", "Yea,"], ["ua latou fefefe e faaaoga mea e a latou lava,", "they durst not make use of that which is their own lest they should offend their priests,"], ["ne'i o latou faatausuai i o latou faitaulaga,", "who do yoke them according to their desires,"], ["o e ua latou faaamo i latou e tusa ma o latou manao,", "and have brought them to believe,"], ["ma aumai i latou ia talitonu, e ala ia latou uputuu ma a latou miti ma o latou manatu valevale ma a latou faaaliga ma a latou mealilo faatagafai,", "by their traditions and their dreams and their whims and their visions and their pretended mysteries,"], ["o le a latou faatausuai ai,", "that they should,"], ["pe afai latou te le faia e tusa ma a latou upu,", "if they did not do according to their words,"], ["i se tagata ua le mailoa,", "offend some unknown being,"], ["o le ua latou fai mai o le Atua—o se tagata e lei vaaia lava pe ua iloaina e se tasi,", "who they say is God—a being who never has been seen or known,"], ["o se sa lei i ai lava pe o le a i ai.", "who never was nor ever will be."]]},
  {num:29,words:[["O lenei ina ua vaai atu le faitaulaga sili ma le faamasino sili i le maaa o lona loto,", "Now when the high priest and the chief judge saw the hardness of his heart,"], ["ioe,", "yea,"], ["ina ua la vaai atu e oo lava i le Atua ua upuleaga faasaga i ai o ia,", "when they saw that he would revile even against God,"], ["sa la le fai atu se tali i ana upu;", "they would not make any reply to his words;"], ["ae sa la faatonu ia saisai o ia;", "but they caused that he should be bound;"], ["ma sa la tuuina atu o ia i lima o e mautofi,", "and they delivered him up into the hands of the officers,"], ["ma auina atu o ia i le laueleele o Sara'emila,", "and sent him to the land of Zarahemla,"], ["ina ia mafai ona aumai o ia i luma o Alema,", "that he might be brought before Alma,"], ["ma le faamasino sili o le sa kovana i luga o le laueleele atoa.", "and the chief judge who was governor over all the land."]]},
  {num:30,words:[["Ma sa oo ina ua aumai o ia i luma o Alema ma le faamasino sili,", "And it came to pass that when he was brought before Alma and the chief judge,"], ["sa alu pea lava o ia i le ala e tasi e pei ona ia faia i le laueleele o Kitiona;", "he did go on in the same manner as he did in the land of Gideon;"], ["ioe,", "yea,"], ["sa alu pea lava o ia i le upuleaga .", "he went on to blaspheme."]]},
  {num:31,words:[["Ma sa tulai atu o ia ma upu leotetele i luma o Alema,", "And he did rise up in great swelling words before Alma,"], ["ma faifai faasaga i faitaulaga ma aoao,", "and did revile against the priests and teachers,"], ["ma tausala i latou i lo latou taitai ese o tagata ia mulimuli i uputuu valea a o latou tamā,", "accusing them of leading away the people after the silly traditions of their fathers,"], ["ina ia latou ola faaloloto ai i luga o galuega a tagata.", "for the sake of glutting on the labors of the people."]]},
  {num:32,words:[["O lenei sa fai atu Alema ia te ia:", "Now Alma said unto him:"], ["Ua e iloa matou te le o ola faaloloto i luga o galuega a lenei nuu;", "Thou knowest that we do not glut ourselves upon the labors of this people;"], ["ona faauta sa ou galue mai lava i le amataga o le nofoaiga a faamasino e oo mai i le taimi nei,", "for behold I have labored even from the commencement of the reign of the judges until now,"], ["i ou lava lima mo lou lava tausiga,", "with mine own hands for my support,"], ["e ui i au malaga e tele faataamilo i le laueleele e tau atu le afioga a le Atua i ou tagata.", "notwithstanding my many travels round about the land to declare the word of God unto my people."]]},
  {num:33,words:[["Ma e ui i le tele o galuega na ou faia i le ekalesia,", "And notwithstanding the many labors which I have performed in the church,"], ["ou te lei maua lava se mea e oo i sina se senine e tasi mo lau galuega;", "I have never received so much as even one senine for my labor;"], ["pe sa maua foi e soo se tasi o ou uso,", "neither has any of my brethren,"], ["vagana ai i le nofoa-faamasino;", "save it were in the judgment– seat;"], ["ma i le tulaga lena na matou maua ai se totogi mo nao lo matou taimi e tusa ai ma le tulafono.", "and then we have received only according to law for our time."]]},
  {num:34,words:[["Ma o lenei,", "And now,"], ["afai matou te le maua se mea mo a matou galuega i le ekalesia,", "if we do not receive anything for our labors in the church,"], ["o le a se aoga matou te galulue ai i le ekalesia sei vagana ai lo matou tau atu o le upumoni,", "what doth it profit us to labor in the church save it were to declare the truth,"], ["ina ia mafai ona matou maua ai fiafiaga i le olioli o o matou uso?", "that we may have rejoicings in the joy of our brethren?"]]},
  {num:35,words:[["Aisea ea la ua e fai mai ai ua matou talai atu i lenei nuu ina ia matou maua ai oa,", "Then why sayest thou that we preach unto this people to get gain,"], ["ae ua e iloa,", "when thou,"], ["e oe lava ia,", "of thyself,"], ["matou te le o mauaina ni oa? Ma o lenei,", "knowest that we receive no gain? And now,"], ["ua e talitonu ea o lo matou faaseseina o lenei nuu,", "believest thou that we deceive this people,"], ["ua tupu mai ai se olioli tele faapea i o latou loto?", "that causes such joy in their hearts?"]]},
  {num:36,words:[["Ma sa tali mai Kori'oa ia te ia,", "And Korihor answered him,"], ["Ioe.", "Yea."]]},
  {num:37,words:[["Ma ona fai atu lea o Alema ia te ia:", "And then Alma said unto him:"], ["E te talitonu o loo i ai se Atua?", "Believest thou that there is a God?"]]},
  {num:38,words:[["Ma sa tali mai o ia,", "And he answered,"], ["E leai.", "Nay."]]},
  {num:39,words:[["O lenei sa fai atu Alema ia te ia:", "Now Alma said unto him:"], ["E te toe faafitia ea o loo i ai se Atua,", "Will ye deny again that there is a God,"], ["ma faafitia foi le Keriso? Aua faauta,", "and also deny the Christ? For behold,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["ua ou mautinoa o loo i ai se Atua,", "I know there is a God,"], ["ma o le a afio mai foi Keriso.", "and also that Christ shall come."]]},
  {num:40,words:[["Ma o lenei o le a se faamaoniga ua ia te oe ua leai se Atua ,", "And now what evidence have ye that there is no God,"], ["pe o le a le afio mai foi Keriso? Ou te fai atu ia te oe ua leai se faamaoniga o ia te oe,", "or that Christ cometh not? I say unto you that ye have none,"], ["vagana ai lava lau upu.", "save it be your word only."]]},
  {num:41,words:[["Ae faauta,", "But,"], ["ua ia te au mea uma o se molimau ua moni nei mea;", "behold,"], ["ma ua ia te oe foi mea uma o se molimau ia te oe ua moni i latou;", "I have all things as a testimony that these things are true; and ye also have all things as a testimony unto you that they are true;"], ["ma e te faafitia ea i latou? E te talitonu ea ua moni nei mea?", "and will ye deny them? Believest thou that these things are true?"]]},
  {num:42,words:[["Faauta,", "Behold,"], ["ua ou iloa ua e talitonu,", "I know that thou believest,"], ["ae ua ulu ia te oe se agaga pepelo,", "but thou art possessed with a lying spirit,"], ["ma ua e tuu ese le Agaga o le Atua ina ia le maua e ia se nofoaga i totonu ia te oe;", "and ye have put off the Spirit of God that it may have no place in you;"], ["ae ua i ai i le tiapolo le mana i ou luga,", "but the devil has power over you,"], ["ma ua ia feaveai solo oe,", "and he doth carry you about,"], ["e fai auala e mafai ona ia faaumatia ai fanau a le Atua.", "working devices that he may destroy the children of God."]]},
  {num:43,words:[["Ma o lenei sa fai mai Kori'oa ia Alema:", "And now Korihor said unto Alma:"], ["Afai e te faaali mai ia te au se faailoga ,", "If thou wilt show me a sign,"], ["e mafai ona ou talitonu ai o loo i ai se Atua,", "that I may be convinced that there is a God,"], ["ioe,", "yea,"], ["faaali mai ia te au ua ia te ia le mana,", "show unto me that he hath power,"], ["ona ou talitonu ai lea i le moni o au upu.", "and then will I be convinced of the truth of thy words."]]},
  {num:44,words:[["Peitai sa fai atu Alema ia te ia:", "But Alma said unto him:"], ["Ua lava faailoga ua ia te oe;", "Thou hast had signs enough;"], ["e te faaosooso ea i lou Atua? E te fai mai ea,", "will ye tempt your God? Will ye say,"], ["Faaali mai ia te au se faailoga,", "Show unto me a sign,"], ["ae ua ia te oe le molimau a ou uso uma nei,", "when ye have the testimony of all these thy brethren,"], ["ma perofeta paia uma foi? Ua folasia i ou luma tusitusiga paia,", "and also all the holy prophets? The scriptures are laid before thee,"], ["ioe,", "yea,"], ["ma ua faailoa mai i mea uma o loo i ai se Atua;", "and all things denote there is a God;"], ["ioe,", "yea,"], ["e oo i le lalolagi ,", "even the earth,"], ["ma mea uma ua i ona luga,", "and all things that are upon the face of it,"], ["ioe,", "yea,"], ["ma lona faataamilosaga ,", "and its motion,"], ["ioe,", "yea,"], ["ma paneta uma foi o loo i o latou ala masani ai ua molimau mai o loo i ai se Foafoa Silisiliese.", "and also all the planets which move in their regular form do witness that there is a Supreme Creator."]]},
  {num:45,words:[["Ma e ui i lea e te fealuai solo ea,", "And yet do ye go about,"], ["ma taitai ese loto o lenei nuu,", "leading away the hearts of this people,"], ["ma molimau atu ia te i latou ua leai se Atua? Ma e ui i lea e te faafiti ea e faasaga i nei molimau uma? Ma sa fai mai o ia:", "testifying unto them there is no God? And yet will ye deny against all these witnesses? And he said:"], ["Ioe,", "Yea,"], ["ou te faafitia,", "I will deny,"], ["sei vagana ai ua e faaali mai ia te au se faailoga.", "except ye shall show me a sign."]]},
  {num:46,words:[["Ma o lenei sa oo ina fai atu Alema ia te ia:", "And now it came to pass that Alma said unto him:"], ["Faauta,", "Behold,"], ["ua ou faanoanoa ona o le maaa o lou loto,", "I am grieved because of the hardness of your heart,"], ["ioe,", "yea,"], ["i lou tetee pea o le agaga o le upumoni,", "that ye will still resist the spirit of the truth,"], ["o le a mafai ona faaumatia ai lou agaga.", "that thy soul may be destroyed."]]},
  {num:47,words:[["Peitai faauta,", "But behold,"], ["e sili ona lelei le toesea o lou agaga nai lo le avea o oe ma ala e aumai ai le toatele o agaga i lalo i le faafanoga,", "it is better that thy soul should be lost than that thou shouldst be the means of bringing many souls down to destruction,"], ["e ala i lou pepelo ma au upu faaviivii;", "by thy lying and by thy flattering words;"], ["o lea afai e te toe faafiti,", "therefore if thou shalt deny again,"], ["faauta o le a taia oe e le Atua,", "behold God shall smite thee,"], ["ina ia e gugu,", "that thou shalt become dumb,"], ["ina ia le mafai ona e toe tatala o lou gutu,", "that thou  shalt never open thy mouth any more,"], ["ina ia e le toe faaaseseina lenei nuu.", "that thou shalt not deceive this people any more."]]},
  {num:48,words:[["O lenei sa fai mai Kori'oa ia te ia:", "Now Korihor said unto him:"], ["Ou te le faafitia le i ai o se Atua,", "I do not deny the existence of a God,"], ["ae ou te le talitonu o loo i ai se Atua;", "but I do not believe that there is a God;"], ["ma ou te fai atu foi,", "and I say also,"], ["e te le iloa o loo i ai se Atua;", "that ye do not know that there is a God;"], ["ma sei vagana ai ua e faaali mai ia te au se faailoga,", "and except ye show me a sign,"], ["ou te le talitonu.", "I will not believe."]]},
  {num:49,words:[["O lenei sa fai atu Alema ia te ia:", "Now Alma said unto him:"], ["O le mea lenei o le a ou tuu atu ia te oe mo se faailoga,", "This will I give unto thee for a sign,"], ["o le a taia oe ia e gugu,", "that thou shalt be struck dumb,"], ["e tusa ma a'u upu;", "according to my words;"], ["ma ou te fai atu,", "and I say,"], ["i le suafa o le Atua,", "that in the name of God,"], ["ia taia oe ia e gugu,", "ye shall be struck dumb,"], ["ina ia le toe mafai ona e tautala.", "that ye shall no more have utterance."]]},
  {num:50,words:[["O lenei ina ua uma ona fai atu e Alema o nei upu,", "Now when Alma had said these words,"], ["sa taia Kori'oa i le gugu,", "Korihor was struck dumb,"], ["ua le mafai ona tautala o ia,", "that he could not have utterance,"], ["e tusa ai ma upu a Alema.", "according to the words of Alma."]]},
  {num:51,words:[["Ma o lenei ina ua vaai atu le faamasino sili i lenei mea,", "And now when the chief judge saw this,"], ["sa ia tuu atu lona lima ma sa tusi atu ia Kori'oa,", "he put forth his hand and wrote unto Korihor,"], ["ua fai atu:", "saying:"], ["Po ua e talitonu ea i le mana o le Atua? O ai na e manao ia faaali atu ai e Alema lana faailoga? O lou manao ea ia faatiga e ia isi,", "Art thou convinced of the power of God? In whom did ye desire that Alma should show forth his sign? Would ye that he should afflict others,"], ["e faaali atu ai ia te oe se faailoga? Faauta,", "to show unto thee a sign? Behold,"], ["ua ia faaali atu ia te oe se faailoga;", "he has showed unto you a sign;"], ["ma o lenei e te toe fia finau atili ea?", "and now will ye dispute more?"]]},
  {num:52,words:[["Ma sa tuu mai e Kori'oa lona lima i luma ma ia tusi,", "And Korihor put forth his hand and wrote,"], ["fai mai:", "saying:"], ["Ua ou iloa ua ou gugu,", "I know that I am dumb,"], ["ona ua le mafai ona ou tautala;", "for I cannot speak;"], ["ma ua ou iloa e leai se mea vagana ai le mana o le Atua e mafai ona aumaia lenei mea i ou luga;", "and I know that nothing save it were the power of God could bring this upon me;"], ["ioe,", "yea,"], ["ma sa ou iloa i taimi uma lava o loo i ai se Atua.", "and I always knew that there was a God."]]},
  {num:53,words:[["Ae faauta,", "But behold,"], ["sa faaseseina au e le tiapolo;", "the devil hath deceived me;"], ["ona sa sau o ia ia te au e foliga mai o se agelu,", "for he appeared unto me in the form of an angel,"], ["ma fai mai ia te au:", "and said unto me:"], ["Alu atu ma toe aumai lenei nuu,", "Go and reclaim this people,"], ["ona ua latou o atu sese uma e mulimuli i se Atua ua le mailoa. Ma sa fai mai o ia ia te au:", "for they have all gone astray after an unknown God. And he said unto me:"], ["E leai se Atua;", "There is no God;"], ["ioe,", "yea,"], ["ma sa ia aoao mai ia te au mea e tatau ona ou fai atu ai. Ma sa ou aoao atu ana upu;", "and he taught me that which I should say. And I have taught his words;"], ["ma sa ou aoao atu i latou ona sa logolelei i latou i le mafaufau faaletino;", "and I taught them because they were pleasing unto the carnal mind;"], ["ma sa ou aoao atu i latou,", "and I taught them,"], ["seia oo ina ou maua ai le manuia tele,", "even until I had much success,"], ["sa oo ina ou talitonu moni ai lava ua moni i latou;", "insomuch that I verily believed that they were true;"], ["ma o le pogai lenei sa ou tutetee ai i le upumoni,", "and for this cause I withstood the truth,"], ["seia oo lava ina ou aumaia ai lenei fetuu tele i ou luga.", "even until I have brought this great curse upon me."]]},
  {num:54,words:[["O lenei ina ua uma ona ia fai mai o nei upu,", "Now when he had said this,"], ["sa ia aioi mai ia tatalo atu Alema i le Atua,", "he besought that Alma should pray unto God,"], ["ina ia mafai ona aveese o le fetuu mai ia te ia.", "that the curse might be taken from him."]]},
  {num:55,words:[["Peitai sa fai atu Alema ia te ia:", "But Alma said unto him:"], ["Afai e aveese lenei fetuu mai ia te oe,", "If this curse should be taken from thee thou wouldst again lead away the hearts of this people;"], ["o le a e toe taitai ese foi loto o lenei nuu; o lea,", "therefore,"], ["ia faia ia te oe e pei ona finagalo i ai le Alii.", "it shall be unto thee even as the Lord will."]]},
  {num:56,words:[["Ma sa oo ina sa le aveeseina le fetuu mai ia Kori'oa;", "And it came to pass that the curse was not taken off of Korihor;"], ["ae sa tuli o ia i fafo,", "but he was cast out,"], ["ma sa alu atu mai lea fale i lea fale ma aisi mo ana meaai.", "and went about from house to house begging for his food."]]},
  {num:57,words:[["O lenei o le tala o le mea na tupu ia Kori'oa sa vave ona faasalalau atu i le laueleele atoa;", "Now the knowledge of what had happened unto Korihor was immediately published throughout all the land;"], ["ioe,", "yea,"], ["sa auina atu e le faamasino sili le folafolaga i tagata uma i le laueleele, sa tau atu ai ia i latou o e sa talitonu i upu a Kori'oa,", "the proclamation was sent forth by the chief judge to all the people in the land,"], ["e ao ina latou salamo vave,", "declaring unto those who had believed in the words of Korihor that they must  speedily repent,"], ["nei oo mai ia lava faasalaga ia te i latou.", "lest the same judgments would come unto them."]]},
  {num:58,words:[["Ma sa oo ina latou talitonu uma i le amioleaga o Kori'oa;", "And it came to pass that they were all convinced of the wickedness of Korihor;"], ["o lea sa latou toe liliu uma ai i le Alii;", "therefore they were all converted again unto the Lord;"], ["ma o lenei mea na faaiu ai le amioletonu e tusa ma le mea na faia e Kori'oa. Ma sa fealuai solo Kori'oa mai lea fale i lea fale,", "and this put an end to the iniquity after the manner of Korihor. And Korihor did go about from house to house,"], ["e aisi meaai mo lona tausiga.", "begging food for his support."]]},
  {num:59,words:[["Ma sa oo ina a'o alu atu o ia i totonu o le nuu,", "And it came to pass that as he went forth among the people,"], ["ioe,", "yea,"], ["i totonu o se nuu o e sa latou vavae ese i latou lava mai tagata sa Nifaē ma latou taua i latou lava o sa Soramā,", "among a people who had separated themselves from the Nephites and called themselves Zoramites,"], ["ona sa taitaia i latou e se tagata sa igoa ia Sorama—ma a'o alu atu o ia i totonu o i latou,", "being led by a man whose name was Zoram—and as he went forth amongst them,"], ["faauta,", "behold,"], ["sa taia o ia ma soli i lalo,", "he was run upon and trodden down,"], ["seia oo ina oti o ia.", "even until he was dead."]]},
  {num:60,words:[["Ma ua faapea ona tatou vaai ai i le iuga o ia o le na te faapiopio ala o le Alii;", "And thus we see the end of him who perverteth the ways of the Lord;"], ["ma ua faapea ona tatou vaai ai e le lagolagoina e le tiapolo ana fanau i le aso gataaga,", "and thus we see that the devil will not support his children at the last day,"], ["ae vave ona ia toso i lalo i latou i seoli .", "but doth speedily drag them down to hell."]]},
];
renderVerseSet(al_ch_30_Verses, 'al-ch30-verses');

var al_ch_31_Verses = [
  {num:1,words:[["O lenei sa oo ina ua mavae atu le iuga o Kori'oa,", "Now it came to pass that after the end of Korihor,"], ["ma ua maua e Alema ni tala e faapea ua faapiopio e sa Soramā ala o le Alii,", "Alma having received tidings that the Zoramites were perverting the ways of the Lord,"], ["ma e faapea o Sorama,", "and that Zoram,"], ["o le sa avea ma o latou taitai,", "who was their leader,"], ["o loo ia taitai atu loto o tagata ia ifo i lalo i tupua le gagana,", "was leading the hearts of the people to bow down to dumb idols,"], ["sa amata ona toe faagasegasea o lona loto ona o le amioletonu o le nuu.", "his heart again began to sicken because of the iniquity of the people."]]},
  {num:2,words:[["Ona sa avea ma pogai o le faanoanoa tele o Alema le iloa e uiga i le amioletonu i totonu o lona nuu; o lea sa faanoanoa tele ai lava lona loto,", "For it was the cause of great sorrow to Alma to know of iniquity among his people;"], ["ona o le o ese atu o sa Soramā mai ia sa Nifaē.", "therefore his heart was exceedingly sorrowful because of the separation of the Zoramites from the Nephites."]]},
  {num:3,words:[["O lenei sa faapotopoto faatasi e sa Soramā i latou lava i se laueleele sa latou taua o Anetionuma,", "Now the Zoramites had gathered themselves together in a land which they called Antionum,"], ["lea sa i le itu i sasae o le laueleele o Sara'emila,", "which was east of the land of Zarahemla,"], ["lea sa faalava latalata toeitiiti ane tuaoi ma le matafaga,", "which lay nearly bordering upon the seashore,"], ["lea sa i le itu i saute o le laueleele o Seasona,", "which was south of the land of Jershon,"], ["lea sa tuaoi foi ma le vao i le itu i saute,", "which also bordered upon the wilderness south,"], ["le vao lea sa tumu i sa Lamanā.", "which wilderness was full of the Lamanites."]]},
  {num:4,words:[["O lenei sa popole tele sa Nifaē nei faia e sa Soramā se fesootaiga ma sa Lamanā,", "Now the Nephites greatly feared that the Zoramites would enter into a correspondence with the Lamanites,"], ["ma avea ai ma ala o se toesega tele o le vaega a sa Nifaē.", "and that it would be the means of great loss on the part of the Nephites."]]},
  {num:5,words:[["Ma o lenei,", "And now,"], ["ona sa i ai i le talai atu o le afioga se uiga malosi e taitai atu ai tagata ia latou faia le mea tonu—ioe,", "as the preaching of the word had a great tendency to lead the people to do that which was just—yea,"], ["sa i ai sona uiga mamana tele atu i luga o mafaufau o tagata nai lo le pelu,", "it had had more powerful effect upon the minds of the people than the sword,"], ["po o se isi lava mea,", "or anything else,"], ["ua oo ia te i latou—o lea na manatu ai Alema e tatau ona latou faataitaia le mana o le afioga a le Atua.", "which had happened unto them—therefore Alma thought it was expedient that they should try the virtue of the word of God."]]},
  {num:6,words:[["O lea na ia ave ai Amona,", "Therefore he took Ammon,"], ["ma Arona,", "and Aaron,"], ["ma Ominea;", "and Omner;"], ["ae o Himinae sa ia tuu i le aulotu i Sara'emila;", "and Himni he did leave in the church in Zarahemla;"], ["ae o le toatolu muamua, na ia ave faatasi ma ia,", "but the former three he took with him,"], ["ma Amoleka foi ma Seseroma,", "and also Amulek and Zeezrom,"], ["o e sa i Meleka;", "who were at Melek;"], ["ma sa ia ave foi ni ona atalii e toalua.", "and he also took two of his sons."]]},
  {num:7,words:[["O lenei sa ia le avea le ulumatua o ona atalii faatasi ma ia,", "Now the eldest of his sons he took not with him,"], ["ma o lona igoa o Helamana ;", "and his name was Helaman;"], ["ae o igoa o i laua o e na ia ave faatasi ma ia o Sepulona ma Korianetona;", "but the names of those whom he took with him were Shiblon and Corianton;"], ["ma o igoa nei o i latou o e na o atu faatasi ma ia i totonu o sa Soramā ,", "and these are the names of those who went with him among the Zoramites,"], ["e talai atu ia te i latou le afioga.", "to preach unto them the word."]]},
  {num:8,words:[["O lenei o sa Soramā o ni tagata faatuiese mai sa Nifaē;", "Now the Zoramites were dissenters from the Nephites;"], ["o lea sa uma ona talai atu o le afioga a le Atua ia te i latou.", "therefore they had had the word of God preached unto them."]]},
  {num:9,words:[["Peitai ua pauu atu i latou i sese tetele,", "But they had fallen into great errors,"], ["ona sa latou le tausisi e tausi poloaiga a le Atua,", "for they would not observe to keep the commandments of God,"], ["ma ana tulafono,", "and his statutes,"], ["e tusa ma le tulafono a Mose.", "according to the law of Moses."]]},
  {num:10,words:[["Pe sa latou fia tausia foi tu o le ekalesia,", "Neither would they observe the performances of the church,"], ["ia tatalo ma aioi atu i le Atua e le aunoa i aso taitasi,", "to continue in prayer and supplication to God daily,"], ["ina ia latou le ulu atu i faaosoosoga.", "that they might not enter into temptation."]]},
  {num:11,words:[["Ioe,", "Yea,"], ["i se aotelega,", "in fine,"], ["sa latou faapiopio ala o le Alii i le tele o taimi;", "they did pervert the ways of the Lord in very many instances;"], ["o lea,", "therefore,"], ["ona o lenei pogai,", "for this cause,"], ["na o atu ai Alema ma ona uso i le laueleele e talai atu le afioga ia te i latou.", "Alma and his brethren went into the land to preach the word unto them."]]},
  {num:12,words:[["O lenei,", "Now,"], ["ina ua latou oo atu i le laueleele,", "when they had come into the land,"], ["faauta,", "behold,"], ["i lo latou ofo tele, sa latou maua atu ua fausia e sa Soramā o sunako,", "to their astonishment they found that the Zoramites had built synagogues,"], ["ma ua latou faapotopoto faatasi i latou lava i se aso e tasi o le vaiaso,", "and that they did gather themselves together on one day of the week,"], ["o se aso lea sa latou taua o se aso o le Alii;", "which day they did call the day of the Lord;"], ["ma sa latou tapuai atu i se ala sa lei vaai muamua lava i ai Alema ma ona uso;", "and they did worship after a manner which Alma and his brethren had never beheld;"]]},
  {num:13,words:[["Ona sa latou fausia se mea i le totonugalemu o lo latou sunako,", "For they had a place built up in the center of their synagogue,"], ["o se mea e tutu ai,", "a place for standing,"], ["lea sa maualuga a'e i luga o le ulu;", "which was high above the head,"], ["ma o ona luga sa nao le toatasi le tagata e mafai ona ofi ai.", "and the top thereof would only admit one person."]]},
  {num:14,words:[["O lea,", "Therefore,"], ["soo se tasi e fia tapuai atu,", "whosoever desired to worship must go forth and stand upon the top thereof,"], ["e ao ona alu atu ma tu i luga o lenei mea, ma faaloloa ona lima agai i le lagi,", "and stretch forth his hands towards heaven,"], ["ma alaga i le leo tele,", "and cry with a loud voice,"], ["ma fai atu:", "saying:"]]},
  {num:15,words:[["Le Atua paia,", "Holy,"], ["paia e;", "holy God;"], ["ua matou talitonu o oe o le Atua,", "we believe that thou art God,"], ["ma ua matou talitonu ua e paia;", "and we believe that thou art holy,"], ["ma sa avea oe o se agaga,", "and that thou wast a spirit,"], ["ma o oe o se agaga,", "and that thou art a spirit,"], ["ma o le a avea pea oe o se agaga e faavavau.", "and that thou wilt be a spirit forever."]]},
  {num:16,words:[["Le Atua paia e,", "Holy God,"], ["matou te talitonu o oe na e vavaeeseina i matou mai i o matou uso;", "we believe that thou hast separated us from our brethren;"], ["ma ua matou le talitonu i uputuu a o matou uso,", "and we do not believe in the tradition of our brethren,"], ["ia sa tuulima faasolo mai i lalo ia te i latou i manatu faatamaiti o o latou tamā;", "which was handed down to them by the childishness of their fathers;"], ["ae ua matou talitonu ua e filifilia i matou e avea ma au fanau paia ;", "but we believe that thou hast elected us to be thy holy children;"], ["ma ua e faailoa mai foi ia te i matou o le a leai se Keriso.", "and also thou hast made it known unto us that there shall be no Christ."]]},
  {num:17,words:[["Peitai ua tutusa oe o ananafi,", "But thou art the same yesterday,"], ["o le aso,", "today,"], ["ma le faavavau;", "and forever;"], ["ma ua e filifilia i matou,", "and thou hast elected us that we shall be saved,"], ["ma o lea o le a faaolaina ai i matou;", "whilst all around us are elected to be cast by thy wrath down to hell;"], ["ae o i latou uma ua siomia ai i matou ua filifilia e lafo e lou toasa i lalo i seoli;", "for the which holiness,"], ["mo lenei faapaiaga, le Atua e,", "O God,"], ["matou te faafetai atu ai ia te oe;", "we thank thee;"], ["ma e matou te faafetai atu foi ia te oe ua e filifilia i matou,", "and we also thank thee that thou hast elected us,"], ["ina ia le mafai ona taitai ese atu i matou ia mulimuli i uputuu valea a o matou uso,", "that we may not be led away after the foolish traditions of our brethren,"], ["ia ua saisaitia ai i latou i lalo i se talitonuga ia Keriso,", "which doth bind them down to a belief of Christ,"], ["lea ua taitai sese mamao ese atu ai o latou loto mai ia te oe,", "which doth lead their hearts to wander far from thee,"], ["lo matou Atua.", "our God."]]},
  {num:18,words:[["Ma e matou te toe faafetai atu ia te oe,", "And again we thank thee,"], ["le Atua e,", "O God,"], ["ona ua avea i matou o se nuu filifilia ma paia. Amene.", "that we are a chosen and a holy people. Amen."]]},
  {num:19,words:[["O lenei sa oo ina ua uma ona faalogo atu o Alema ma ona uso ma ona atalii i nei tatalo,", "Now it came to pass that after Alma and his brethren and his sons had heard these prayers,"], ["sa le mafuatiaina lo latou ofo tele.", "they were astonished beyond all measure."]]},
  {num:20,words:[["Aua faauta,", "For behold,"], ["sa o atu tagata taitoatasi uma ma tuu atu ia lava tatalo e tasi.", "every man did go forth and offer up these same prayers."]]},
  {num:21,words:[["O lenei o lea mea sa taua e i latou o Rameutoma,", "Now the place was called by them Rameumptom,"], ["o se mea,", "which,"], ["a faaliliuina,", "being interpreted,"], ["o le pulelaa paia.", "is the holy stand."]]},
  {num:22,words:[["O lenei,", "Now,"], ["mai lenei pulelaa,", "from this stand they did offer up,"], ["sa latou avae ai,", "every man,"], ["e tagata taitoatasi,", "the selfsame prayer unto God,"], ["le tatalo lava lea e tasi i le Atua, e faafetai atu ai i lo latou Atua ua ia filifilia i latou,", "thanking their God that they were chosen of him,"], ["ma ona sa ia le taitaiesea atu i latou ia latou mulimuli i uputuu a o latou uso,", "and that he did not lead them away after the tradition of their brethren,"], ["ma ona ua le aveesea atu o latou loto ia talitonu i mea o le a oo mai,", "and that their hearts were not stolen away to believe in things to come,"], ["o mea sa latou le iloa se mea e uiga i ai.", "which they knew nothing about."]]},
  {num:23,words:[["O lenei,", "Now,"], ["ina ua uma ona avatu e tagata uma le faafetai i lenei ala,", "after the people had all offered up thanks after this manner,"], ["sa latou foi atu i o latou fale,", "they returned to their homes,"], ["e le toe tautatala e uiga i lo latou Atua seia oo ina latou toe faapotopoto faatasi i latou lava i le pulelaa paia,", "never speaking of their God again until they had assembled themselves together again to the holy stand,"], ["e avatu le faafetai e tusa ma la latou ala.", "to offer up thanks after their manner."]]},
  {num:24,words:[["O lenei ina ua vaai atu Alema i lenei mea,", "Now when Alma saw this his heart was grieved;"], ["sa faanoanoa lava lona loto;", "for he saw that they were a wicked and a perverse people;"], ["ona sa ia vaai o i latou o se nuu amioleaga ma le faapiopio; ioe,", "yea,"], ["sa ia vaai ua pupu o latou loto i le auro,", "he saw that their hearts were set upon gold,"], ["ma le ario,", "and upon silver,"], ["ma oloa eseese uma.", "and upon all manner of fine goods."]]},
  {num:25,words:[["Ioe,", "Yea,"], ["ma sa vaai atu foi o ia ua faaneeneeina o latou loto i le mitamitavale tele,", "and he also saw that their hearts were lifted up unto great boasting,"], ["i lo latou faamaualuluga.", "in their pride."]]},
  {num:26,words:[["Ma sa ia sii ae lona leo i le lagi,", "And he lifted up his voice to heaven,"], ["ma aioi ,", "and cried,"], ["ua fai atu:", "saying:"], ["E,", "O,"], ["o le a ea le umi,", "how long,"], ["Le Alii e,", "O Lord,"], ["e te tuu ai au auauna ia nonofo i lalo nei i la le tino,", "wilt thou suffer that thy servants shall dwell here below in the flesh,"], ["e vaai i le amioleaga tele faapea i totonu o le fanauga a tagata?", "to behold such gross wickedness among the children of men?"]]},
  {num:27,words:[["Faauta,", "Behold,"], ["Le Atua e,", "O God,"], ["ua latou tagi atu ia te oe,", "they cry unto thee,"], ["a ua tofatumoanaina o latou loto i lo latou faamaualuluga. Faauta,", "and yet their hearts are swallowed up in their pride. Behold,"], ["Le Atua e,", "O God,"], ["ua latou tagi atu ia te oe i o latou gutu,", "they cry unto thee with their mouths,"], ["a ua latou fefete a'e,", "while they are puffed up,"], ["ua oo ina tele lava,", "even to greatness,"], ["i mea le aoga o le lalolagi.", "with the vain things of the world."]]},
  {num:28,words:[["Faauta,", "Behold,"], ["lo'u Atua e,", "O my God,"], ["i o latou ofu taugata,", "their costly apparel,"], ["ma a latou mama,", "and their ringlets,"], ["ma o latou taulima ,", "and their bracelets,"], ["ma a latou mea teuteu auro,", "and their ornaments of gold,"], ["ma a latou mea taua uma ia ua latou teuteuina ai i latou lava;", "and all their precious things which they are ornamented with;"], ["ma faauta,", "and behold,"], ["ua pupu atu o latou loto i ia mea,", "their hearts are set upon them,"], ["ae ua latou tagi atu ia te oe ma fai mai—matou te faafetai atu ia te oe,", "and yet they cry unto thee and say—We thank thee,"], ["le Atua e,", "O God,"], ["ona o i matou o se nuu ua filifilia mo oe,", "for we are a chosen people unto thee,"], ["a'o isi o le a fano.", "while others shall perish."]]},
  {num:29,words:[["Ioe,", "Yea,"], ["ma ua latou fai mai ua e faailoa mai ia te i latou e faapea o le a leai se Keriso.", "and they say that thou hast made it known unto them that there shall be no Christ."]]},
  {num:30,words:[["Le Alii e le Atua e,", "O Lord God,"], ["o le a le umi e te tuu ai ia i ai pea lena amioleaga ma le le faamaoni i totonu o lenei nuu? Le Alii e,", "how long wilt thou suffer that such wickedness and infidelity shall be among this people? O Lord,"], ["sei e tuu mai ia te au le malosi,", "wilt thou give me strength,"], ["ia mafai ai ona ou onosaia ou vaivaiga.", "that I may bear with mine infirmities."], ["Ona ua ou vaivai, ma o amioleaga faapea ua i totonu o lenei nuu,", "For I am infirm,"], ["ua tiga ai lou agaga.", "and such wickedness among this people doth pain my soul."]]},
  {num:31,words:[["Le Alii e,", "O Lord,"], ["ua faanoanoa tele lo'u loto;", "my heart is exceedingly sorrowful;"], ["sei e faamafanafanaina lo'u agaga ia Keriso. Le Alii e,", "wilt thou comfort my soul in Christ. O Lord,"], ["sei e tuu mai ia te au ina ia mafai ona ou maua le malosi,", "wilt thou grant unto me that I may have strength,"], ["ina ia mafai ona ou talitalia ma le onosai nei puapuaga o le a oo mai i ou luga,", "that I may suffer with patience these afflictions  which shall come upon me,"], ["ona o le amioletonu o lenei nuu.", "because of the iniquity of this people."]]},
  {num:32,words:[["Le Alii e,", "O Lord,"], ["sei e faamafanafanaina lo'u agaga,", "wilt thou comfort my soul,"], ["ma tuu mai ia te au le manuia,", "and give unto me success,"], ["ma ou uso-a-faigaluega foi o e ua faatasi ma au—ioe,", "and also my fellow laborers who are with me—yea,"], ["o Amona, ma Arona,", "Ammon,"], ["ma Ominea,", "and Aaron,"], ["ma Amoleka foi ma Seseroma,", "and Omner,"], ["ma ou atalii foi e toalua—ioe,", "and also Amulek and Zeezrom and also my two sons—yea,"], ["e oo ia i latou uma nei sei e faamafanafanaina,", "even all these wilt thou comfort,"], ["le Alii e.", "O Lord."], ["Ioe,", "Yea,"], ["sei e faamafanafanaina o latou agaga ia Keriso.", "wilt thou comfort their souls in Christ."]]},
  {num:33,words:[["Sei e tuu mai ia te i latou ia mafai ona latou maua le malosi,", "Wilt thou grant unto them that they may have strength,"], ["ina ia mafai ona latou onosaia o latou puapuaga ia o le a oo mai i o latou luga ona o amioletonu a lenei nuu.", "that they may bear their afflictions which shall come upon them because of the iniquities of this people."]]},
  {num:34,words:[["Le Alii e, sei e tuu mai ia te i matou ia mafai ona matou maua le manuia i le toe aumai o i latou ia te oe,", "O Lord,"], ["ia Keriso.", "wilt thou grant unto us that we may have success in bringing them again unto thee in Christ."]]},
  {num:35,words:[["Faauta,", "Behold,"], ["Le Alii e,", "O Lord,"], ["ua pele lava o latou agaga ,", "their souls are precious,"], ["ma o le toatele o i latou o o matou uso;", "and many of them are our brethren;"], ["o lea,", "therefore,"], ["tuu mai ia te i matou,", "give unto us,"], ["Le Alii e,", "O Lord,"], ["le mana ma le poto ina ia mafai ona matou toe aumai i latou nei,", "power and wisdom that we may bring these,"], ["o o matou uso,", "our brethren,"], ["ia te oe.", "again unto thee."]]},
  {num:36,words:[["O lenei sa oo ina ua uma ona fai atu e Alema o nei upu,", "Now it came to pass that when Alma had said these words,"], ["sa pati e ia ona lima i luga o i latou uma o e sa faatasi ma ia. Ma faauta,", "that he clapped his hands upon all them who were with him. And behold,"], ["ina ua pati e ia ona lima i luga o i latou,", "as he clapped his hands upon them,"], ["sa faatumulia i latou i le Agaga Paia.", "they were filled with the Holy Spirit."]]},
  {num:37,words:[["Ma ina ua mavae lea sa latou taapeape ese o le tasi mai le isi,", "And after that they did separate themselves one from another,"], ["e aunoa ma se manatu mo i latou lava po o a mea o le a latou ai,", "taking no thought for themselves what they should eat,"], ["po o a mea o le a latou feinu ai,", "or what they should drink,"], ["po o a mea o le a latou ofu ai.", "or what they should put on."]]},
  {num:38,words:[["Ma sa faia e le Alii mea mo i latou ina ia latou le fia aai,", "And the Lord provided for them that they should hunger not,"], ["pe ina ia latou le fia feinu;", "neither should they thirst;"], ["ioe,", "yea,"], ["ma sa ia tuu mai foi ia te i latou le malosi,", "and he also gave them strength,"], ["ina ia latou le mafatia i soo se ituaiga o puapuaga ,", "that they should suffer no manner of afflictions,"], ["vagana ai ua tofatumoanaina i le olioli ia Keriso. O lenei sa faia lava lenei mea e tusa ai ma le tatalo a Alema;", "save it were swallowed up in the joy of Christ. Now this was according to the prayer of Alma;"], ["ma sa faia lenei mea ona sa tatalo atu o ia i le faatuatua .", "and this because he prayed in faith."]]},
];
renderVerseSet(al_ch_31_Verses, 'al-ch31-verses');

var al_ch_32_Verses = [
  {num:1,words:[["Ma sa oo ina latou o atu,", "And it came to pass that they did go forth,"], ["ma amata ona talai atu o le afioga a le Atua i le nuu,", "and began to preach the word of God unto the people,"], ["i le ulu atu i o latou sunako,", "entering into their synagogues,"], ["ma o latou fale;", "and into their houses;"], ["ioe,", "yea,"], ["ma e oo lava i o latou auala sa latou talai atu ai le afioga.", "and even they did preach the word in their streets."]]},
  {num:2,words:[["Ma sa oo ina ua mavae galuega e tele i totonu o i latou,", "And it came to pass that after much labor among them,"], ["sa amata ona latou maua o le manuia i totonu o le vasega o tagata matitiva;", "they began to have success among the poor class of people;"], ["aua faauta,", "for behold,"], ["sa tutuli i latou i fafo mai sunako ona o le matuatua o o latou ofu—", "they were cast out of the synagogues because of the coarseness of their apparel—"]]},
  {num:3,words:[["O lea sa le faatagaina i latou e ulu atu i o latou sunako e tapuai i le Atua,", "Therefore they were not permitted to enter into their synagogues to worship God,"], ["ona sa manatu o latou uso e faapea ua latou eleelea;", "being esteemed as filthiness;"], ["o lea sa latou matitiva;", "therefore they were poor;"], ["ioe,", "yea,"], ["sa manatu o latou uso ia te i latou o ni otaota;", "they were esteemed by their brethren as dross;"], ["o lea sa latou matitiva e faatatau i mea o le lalolagi;", "therefore they were poor as to things of the world;"], ["ma sa latou matitiva foi i le loto.", "and also they were poor in heart."]]},
  {num:4,words:[["O lenei,", "Now,"], ["a'o aoao atu ma tautala atu Alema i tagata i luga o le maupuepue o Onaeta,", "as Alma was teaching and speaking unto the people upon the hill Onidah,"], ["sa o ane ia te ia se motu toatele o tagata,", "there came a great multitude unto him,"], ["i latou ia o e ua matou tautatala atu ai,", "who were those of whom we have been speaking,"], ["o e ua matitiva i le loto,", "of whom were  poor in heart,"], ["ona o lo latou matitiva e faatatau i mea o le lalolagi.", "because of their poverty as to the things of the world."]]},
  {num:5,words:[["Ma sa latou o ane ia Alema;", "And they came unto Alma;"], ["ma sa fai mai ia te ia le sa taimua i a i latou:", "and the one who was the foremost among them said unto him:"], ["Faauta,", "Behold,"], ["o le a se mea a fai e ou uso nei,", "what shall these my brethren do,"], ["ona ua inosia i latou i tagata uma ona o lo latou matitiva,", "for they are despised of all men because of their poverty,"], ["ioe,", "yea,"], ["ma aemaise lava e o matou faitaulaga;", "and more especially by our priests;"], ["ona ua latou tutuli i matou i fafo mai i o matou sunako ia sa matou galulue malosi e fausia i o matou lava lima;", "for they have cast us out of our synagogues which we have labored abundantly to build with our own hands;"], ["ma ua latou tutuli i matou i fafo ona o lo matou matitiva tele;", "and they have cast us out because of our exceeding poverty;"], ["ma ua leai se mea ua ia te i matou e tapuai ai i lo matou Atua;", "and we have no place to worship our God;"], ["ma faauta,", "and behold,"], ["o le a se mea a matou faia?", "what shall we do?"]]},
  {num:6,words:[["Ma o lenei ina ua faalogo atu Alema i nei upu,", "And now when Alma heard this,"], ["sa liliu atu o ia,", "he turned him about,"], ["ua faasaga sa'o atu ona fofoga ia te ia, ma vaai atu o ia ma le olioli tele;", "his face immediately towards him,"], ["ona ua ia vaai atu ua faalotomaualalaloina moni lava i latou e o latou puapuaga ,", "and he beheld with great joy;"], ["ma ua latou saunia e faalogo i le afioga.", "for he beheld that their afflictions had truly humbled them and that they were in a preparation to hear the word."]]},
  {num:7,words:[["O lea sa ia le toe fai atu ai ni isi mea i le isi motu o tagata;", "Therefore he did say no more to the other multitude;"], ["ae sa ia faaloaloa atu lona lima,", "but he stretched forth his hand,"], ["ma alaga atu ia te i latou o e na ia vaai atu i ai,", "and cried unto those whom he beheld,"], ["o e ua salamo moni,", "who were truly penitent,"], ["ma fai atu ia te i latou:", "and said unto them:"]]},
  {num:8,words:[["Ua ou vaai atu ua outou maualalalo i le loto;", "I behold that ye are lowly in heart;"], ["ma afai o lea,", "and if so,"], ["amuia outou.", "blessed are ye."]]},
  {num:9,words:[["Faauta ua fai mai lo outou uso,", "Behold thy brother hath said,"], ["O le a se mea a matou faia?—ona ua tutuli i matou i fafo mai i o matou sunako,", "What shall we do?—for we are cast out of our synagogues,"], ["ua le mafai ai ona matou tapuai atu i lo matou Atua.", "that we cannot worship our God."]]},
  {num:10,words:[["Faauta ou te fai atu ia te outou,", "Behold I say unto you,"], ["tou te manatu ea ua le mafai ona outou tapuai atu i le Atua sei vagana ai ua nao totonu o o outou sunako?", "do ye suppose that ye cannot worship God save it be in your synagogues only?"]]},
  {num:11,words:[["Ma e le gata i lea,", "Moreover,"], ["ou te fesili atu,", "I would ask,"], ["tou te manatu ea ua le tatau ona outou tapuai atu i le Atua ae nao le faatasi i se vaiaso?", "do ye suppose that ye must not worship God only once in a week?"]]},
  {num:12,words:[["Ou te fai atu ia te outou,", "I say unto you,"], ["o se mea lelei le tutuli o outou i fafo mai i o outou sunako,", "it is well that ye are cast out of your synagogues,"], ["ina ia mafai ona outou lotomaualalalo ai,", "that ye may be humble,"], ["ma ina ia mafai ona outou aoaoina ai le poto ;", "and that ye may learn wisdom;"], ["aua e tatau ona outou aoaoina le poto;", "for it is necessary that ye should learn wisdom;"], ["ona o le tutuli o outou i fafo,", "for it is because that ye are cast out,"], ["i le inosia o outou e o outou uso ona o lo outou matitiva tele,", "that ye are despised of your brethren because of your exceeding poverty,"], ["ua aumai ai outou i le maualalo o le loto;", "that ye are brought to a lowliness of heart;"], ["ona ua tatau ai ona aumai o outou ia faalotomaualalaloina.", "for ye are necessarily brought to be humble."]]},
  {num:13,words:[["Ma o lenei,", "And now,"], ["ona ua faamalolosia outou ia outou lotomaualalalo,", "because ye are compelled to be humble blessed are ye;"], ["amuia outou; ona o le tagata i ni isi taimi,", "for a man sometimes,"], ["afai e faamalosi o ia ia lotomaualalo,", "if he is compelled to be humble,"], ["e saili o ia ia salamo;", "seeketh repentance;"], ["ma o lenei e moni lava, ai se e salamo e maua e ia le alofa mutimutivale;", "and now surely,"], ["ma o ia na te maua le alofa mutimutivale ma tumau e oo i le iuga,", "whosoever repenteth shall find mercy;"], ["o ia lava lea o le a faaolaina.", "and he that findeth mercy and endureth to the end the same shall be saved."]]},
  {num:14,words:[["Ma o lenei,", "And now,"], ["e pei ona ou fai atu ia te outou,", "as I said unto you,"], ["talu ai ona ua faamalosia outou ia outou lotomaualalalo ua outou manuia ai,", "that because ye were compelled to be humble ye were blessed,"], ["pe tou te le manatu ea ua sili atu le manuia o i latou o e ua latou faalotomaualalaloina moni i latou lava ona o le afioga?", "do ye not suppose that they are more blessed who truly humble themselves because of the word?"]]},
  {num:15,words:[["Ioe,", "Yea,"], ["o ia o le ua ia faalotomaualaloina moni o ia lava,", "he that truly humbleth himself,"], ["ma salamo i ana agasala,", "and repenteth of his sins,"], ["ma tumau e oo i le iuga,", "and endureth to the end,"], ["o ia lava lea o le a faamanuiaina—ioe,", "the same shall be blessed—yea,"], ["e sili atu ona faamanuiaina nai lo i latou o e ua faamalolosia ia lotomaualalalo ona o lo latou matitiva tele.", "much more blessed than they who are compelled to be humble because of their exceeding poverty."]]},
  {num:16,words:[["O lea,", "Therefore,"], ["amuia i latou o e latou te faalotomaualalaloina i latou lava e aunoa ma le faamalosia ia lotomaualalalo;", "blessed are they who humble themselves without being compelled to be humble;"], ["po o,", "or rather,"], ["i ni isi upu,", "in other words,"], ["amuia o ia o le e talitonu i le afioga a le Atua,", "blessed is he that believeth in the word of God,"], ["ma ua papatiso e aunoa ma le maaa o le loto,", "and is baptized without stubbornness of heart,"], ["ioe,", "yea,"], ["e aunoa ma le tau aumai ia ona iloaina le afioga,", "without being brought to know the word,"], ["pe faamalosia ia ona iloaina,", "or even compelled to know,"], ["faatoa o latou talitonu ai.", "before they will believe."]]},
  {num:17,words:[["Ioe,", "Yea,"], ["ua i ai se toatele o e ua fai mai:", "there are many who do say:"], ["Afai e te faaali mai ia te i matou se faailoga mai le lagi,", "If thou wilt show unto us a sign from heaven,"], ["ona matou iloa ai lea ma le mautinoa,", "then we shall know of a surety;"], ["ona matou talitonu ai lea.", "then we shall believe."]]},
  {num:18,words:[["O lenei ou te fesili atu,", "Now I ask,"], ["o le faatuatua ea lea? Faauta,", "is this faith? Behold,"], ["ou te fai atu ia te outou, E leai;", "I say unto you,"], ["ona afai ua iloa e se tagata se mea,", "Nay;"], ["ua leai se pogai ia te ia e faatuatua ai,", "for if a man knoweth a thing he hath no cause to believe,"], ["ona ua ia iloaina.", "for he knoweth it."]]},
  {num:19,words:[["Ma o lenei,", "And now,"], ["ua le sili atu ea le fetuuina o ia o le ua ia iloaina le finagalo o le Atua ae ua ia le faia,", "how much more cursed is he that knoweth the will of God and doeth it not,"], ["nai lo o ia o le ua nao na talitonu,", "than he that only believeth,"], ["pe ua i ai nao se pogai e talitonu ai,", "or only hath cause to believe,"], ["ma pau atu i le solitulafono?", "and falleth into transgression?"]]},
  {num:20,words:[["O lenei e ao ina outou faamasino e faatatau i lenei mea. Faauta,", "Now of this thing ye must judge. Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["e pei ona i ai i le tasi itu ua faapea foi ona faia i le isi itu;", "that it is on the one hand even as it is on the other;"], ["ma o le a faia i tagata taitoatasi e tusa ma ana galuega.", "and it shall be unto every man according to his work."]]},
  {num:21,words:[["Ma o lenei e pei ona ou fai atu e uiga i le faatuatua—o le faatuatua e le o le maua lea o se malamalama atoatoa i mea;", "And now as I said concerning faith—faith is not to have a perfect knowledge of things;"], ["o lea afai ua ia te outou le faatuatua ua outou faamoemoe mo mea e le vaaia,", "therefore if ye have faith ye hope for things which are not seen,"], ["a e moni.", "which are true."]]},
  {num:22,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ma ou te manao ia outou manatua,", "and I would that ye should remember,"], ["e alofa mutimutivale le Atua i tagata uma o e e talitonu i lona suafa;", "that God is merciful unto all who believe on his name;"], ["o lea ua ia finagalo ai,", "therefore he desireth,"], ["i le tulaga muamua lava,", "in the first place,"], ["ia outou talitonu,", "that ye should believe,"], ["ioe,", "yea,"], ["i lana afioga lava.", "even on his word."]]},
  {num:23,words:[["Ma o lenei,", "And now,"], ["e faaali mai e ia lana afioga i tagata e ala mai i agelu,", "he imparteth his word by angels unto men,"], ["ioe,", "yea,"], ["e le i nao tane ae i fafine foi.", "not only men but women also."], ["O lenei ua le ona pau lea; o tamaiti laiti e i ai upu e tuuina mai ia te i latou i le tele o taimi,", "Now this is not all;"], ["e faamaasiasia ai e popoto ma e ua aoaoina.", "little children do have words given unto them many times which confound the wise and the learned."]]},
  {num:24,words:[["Ma o lenei,", "And now,"], ["ou uso pele e,", "my beloved brethren,"], ["ona ua outou fia iloa mai ia te au le mea ia outou faia ona ua outou puapuagatia ma tutulia i fafo—o lenei ou te le manao ia outou manatu e faapea ua ou faamasino ia te outou vagana ua tusa ai ma mea ua moni—", "as ye have desired to know of me what ye shall do because ye are afflicted and cast out—now I do not desire that ye should suppose that I mean to judge you only according to that which is true—"]]},
  {num:25,words:[["Ona ou te le faapea atu sa faamalolosia outou uma ia outou faalotomaualalaloina outou lava;", "For I do not mean that ye all of you have been compelled to humble yourselves;"], ["ona ou te talitonu moni lava e i ai ni isi i totonu o outou o e latou te faalotomaualalaloina i latou lava,", "for I verily believe that there are some among you who would humble themselves,"], ["e tusa lava po o a tulaga atonu latou te i ai.", "let them be in whatsoever circumstances they might."]]},
  {num:26,words:[["O lenei,", "Now,"], ["e pei ona ou fai atu e uiga i le faatuatua—e faapea e le o se malamalama ua atoatoa—ua faapea foi i au upu. E le mafai ona outou iloa i le amataga lo latou mautinoa,", "as I said concerning faith—that it was not a perfect knowledge—even so it is with my words. Ye cannot know of their surety at first,"], ["i le atoatoa,", "unto perfection,"], ["e sili atu nai lo le faapea o le faatuatua o se malamalama ua atoatoa.", "any more than faith is a perfect knowledge."]]},
  {num:27,words:[["Ae faauta,", "But behold,"], ["afai tou te ala mai ma fafagu o outou mafaufau,", "if ye will awake and arouse your faculties,"], ["e oo i le tofotofo i au upu,", "even to an experiment upon my words,"], ["ma faaaoga sina vaega itiiti o le faatuatua,", "and exercise a particle of faith,"], ["ioe,", "yea,"], ["e tusa pe ua le mafai ona e faia o se isi lava mea nai lo le fia talitonu,", "even if ye can no more than desire to believe,"], ["ia tuu lea manao e galue i totonu ia te oe,", "let this desire work in you,"], ["seia oo lava ina ia e talitonu ai i se ala e mafai ai ona e tuu ane o se avanoa mo se vaega o a'u upu.", "even until ye believe in a manner that ye can give place for a portion of my words."]]},
  {num:28,words:[["O lenei,", "Now,"], ["o le a tatou faatusaina le afioga i se fatu . O lenei,", "we will compare the word unto a seed. Now,"], ["afai e te tuu ane se avanoa,", "if ye give place,"], ["e mafai ona toto ai o se fatu i lou loto ,", "that a seed may be planted in your heart,"], ["faauta,", "behold,"], ["afai o se fatu moni,", "if it be a true seed,"], ["po o se fatu lelei,", "or a good seed,"], ["afai e te le tiaia i fafo i lou le talitonu,", "if ye do not cast it out by your unbelief,"], ["e te tetee ai le Agaga o le Alii,", "that ye will resist the Spirit of the Lord,"], ["faauta,", "behold,"], ["o le a amata ona malena ae i totonu o lou fatafata;", "it will begin to swell within your breasts;"], ["ma pe a e lagona ia faalogona o le malena ae,", "and when you feel these swelling motions,"], ["o le a amata ona e fai ifo ia te oe lava—Ua tatau ona lelei lenei fatu,", "ye will begin to say within yourselves—It must needs be that this is a good seed,"], ["pe ua lelei le afioga,", "or that the word is good,"], ["ona ua amata ona faalauteleina ai lo'u agaga;", "for it beginneth to enlarge my soul;"], ["ioe,", "yea,"], ["ua amata ona faamalamalama ai lo'u malamalamaaga ,", "it beginneth to enlighten my understanding,"], ["ioe,", "yea,"], ["ua amata ona suamalie ia te au.", "it beginneth to be delicious to me."]]},
  {num:29,words:[["O lenei faauta,", "Now behold,"], ["pe le faateleina ea i lenei mea lou faatuatua? Ou te fai atu ia te outou,", "would not this increase your faith? I say unto you,"], ["Ioe;", "Yea;"], ["e ui i lea e lei tupu ae i se malamalama ua atoatoa.", "nevertheless it hath not grown up to a perfect knowledge."]]},
  {num:30,words:[["Peitai faauta,", "But behold,"], ["a'o malena a'e le fatu,", "as the seed swelleth,"], ["ma totogo mai,", "and sprouteth,"], ["ma amata ona ola,", "and beginneth to grow,"], ["ona tatau lea ona e faapea ane ua lelei le fatu;", "then you must needs say that the seed is good;"], ["aua faauta ua malena a'e,", "for behold it swelleth,"], ["ma totogo mai,", "and sprouteth,"], ["ma ua amata ona ola.", "and beginneth to grow."], ["Ma o lenei,", "And now behold,"], ["faauta,", "will not this strengthen your faith? Yea,"], ["pe le faamalosia ea i lenei mea lou faatuatua? Ioe, o le a faamalosia ai lou faatuatua:", "it will strengthen your faith:"], ["ona o le a e faapea ane ua ou iloa o se fatu lelei lenei;", "for ye will say I know that this is a good seed;"], ["aua faauta ua totogo ae ma amata ona ola.", "for behold it sprouteth and beginneth to grow."]]},
  {num:31,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["ua e mautinoa ea o lenei fatu o se fatu ua lelei? Ou te fai atu ia te outou,", "are ye sure that this is a good seed? I say unto you,"], ["Ioe;", "Yea;"], ["ona e fua mai fatu taitasi i ona lava foliga .", "for every seed bringeth forth unto its ownlikeness."]]},
  {num:32,words:[["O lea,", "Therefore,"], ["afai e ola se fatu,", "if a seed groweth it is good,"], ["o se fatu lelei, ae afai e le ola,", "but if it growth not,"], ["faauta ua le lelei,", "behold it is not good,"], ["o lea e tiai ese ai.", "therefore it is cast away."]]},
  {num:33,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["ona sa e faataitaia le faataitaiga,", "because ye have tried the experiment,"], ["ma toto le fatu,", "and planted the seed,"], ["ma ua malena ae ma totogo mai,", "and it swelleth and sprouteth,"], ["ma ua amata ona ola,", "and beginneth to grow,"], ["e tatau ona e iloa ua lelei le fatu.", "ye must needs know that the seed is good."]]},
  {num:34,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["pe ua atoatoa ea lou malamalama ? Ioe,", "is your knowledge perfect? Yea,"], ["ua atoatoa lou malamalama i lena mea,", "your knowledge is perfect in that thing,"], ["ma ua moe lou faatuatua ;", "and your faith is dormant;"], ["ma o le pogai ona ua e iloa,", "and this because ye know,"], ["ona ua outou iloa ua malena ae le afioga i o outou agaga,", "for ye know that the word hath swelled your souls,"], ["ma ua outou iloa foi ua totogo ae,", "and ye also know that it hath sprouted up,"], ["ona ua amata ona faamalamalamaina o lou malamalamaaga,", "that your understanding doth begin to be enlightened,"], ["ma ua amata ona faalauteleina o lou mafaufau .", "and your mind doth begin to expand."]]},
  {num:35,words:[["O lea la,", "O then,"], ["pe ua le moni ea lenei mea? Ou te fai atu ia te outou,", "is not this real? I say unto you,"], ["Ioe,", "Yea,"], ["aua o le malamalama lea;", "because it is light;"], ["ma o soo se mea ua malamalama,", "and whatsoever is light,"], ["ua lelei,", "is good,"], ["aua ua iloatino,", "because it is discernible,"], ["o lea e tatau ona e iloa ai ua lelei;", "therefore ye must know that it is good;"], ["ma o lenei faauta,", "and now behold,"], ["ina ua uma ona e tofo i lenei malamalama pe ua atoatoa ea lou malamalama?", "after ye have tasted this light is your knowledge perfect?"]]},
  {num:36,words:[["Faauta ou te fai atu ia te outou,", "Behold I say unto you,"], ["E leai;", "Nay;"], ["pe tatau foi ona e tuu ese lou faatuatua,", "neither must ye lay aside your faith,"], ["ona sa nao lou faaaoga o lou faatuatua e toto ai le fatu ina ia mafai ona e faataitaia ai o le faataitaiga e iloa ai pe ua lelei le fatu.", "for ye have only exercised your faith to plant the seed that ye might try the experiment to know if the seed was good."]]},
  {num:37,words:[["Ma faauta,", "And behold,"], ["pe a amata ona tupu o le laau,", "as the tree beginneth to grow,"], ["o le a outou faapea ane:", "ye will say:"], ["Sei o tatou tausia ma le faaeteete tele,", "Let us nourish it with great care,"], ["ina ia mafai ona mauaa,", "that it may get root,"], ["ina ia mafai ona tupu ae,", "that it may grow up,"], ["ma fua mai ni fua mo i tatou. Ma o lenei faauta,", "and bring forth fruit unto us. And now behold,"], ["afai tou te tausi i ai ma le faaeteete tele o le a mauaa,", "if ye nourish it with much care it will get root,"], ["ma tupu ae,", "and grow up,"], ["ma fua mai.", "and bring forth fruit."]]},
  {num:38,words:[["Ae afai e te tuulafoai i le laau,", "But if ye neglect the tree,"], ["ma le manatu i ai mo lona tausiga,", "and take no thought for its nourishment,"], ["faauta o le a le mauaa; ma pe a oo mai le vevela o le la ma mu ai,", "behold it will not get any root;"], ["talu ai ona ua leai ni ona aa,", "and when the heat of the sun cometh and scorcheth it,"], ["o le a mamae,", "because it hath no root it withers away,"], ["ma o le a e liaina i luga ma lafo i fafo.", "and ye pluck it up and cast it out."]]},
  {num:39,words:[["O lenei,", "Now,"], ["sa lei tupu mai lenei mea ona e faapea sa le lelei le fatu,", "this is not because the seed was not good,"], ["pe faapea foi ona sa le manaomia ona fua;", "neither is it because the fruit thereof would not be desirable;"], ["ae ua tupu mai ona ua naumati lou eleele ,", "but it is because your ground is barren,"], ["ma sa e le fia tausia le laau,", "and ye will not nourish the tree,"], ["o lea ua le mafai ai ona e maua o ona fua.", "therefore ye cannot have the fruit thereof."]]},
  {num:40,words:[["Ma o lea,", "And thus,"], ["afai tou te le tausia le afioga,", "if ye will not nourish the word,"], ["ma tepa taulai i luma ma le mata o le faatuatua i lona fua,", "looking forward with an eye of faith to the fruit thereof,"], ["e le mafai lava ona outou tauina le fua o le laau o le ola.", "ye can never pluck of the fruit of the tree of life."]]},
  {num:41,words:[["Ae afai tou te tausia le afioga,", "But if ye will nourish the word,"], ["ioe,", "yea,"], ["tausi le laau ina ua amata ona ola mai,", "nourish the tree as it beginneth to grow,"], ["i lo outou faatuatua ma le filiga tele,", "by your faith with great diligence,"], ["ma le onosai ,", "and with patience,"], ["ma tepa taulai i luma i lona fua,", "looking forward to the fruit thereof,"], ["o le a mauaa;", "it shall take root;"], ["ma faauta o le a avea ma laau e puna ae i le ola tumau-faavavau.", "and behold it shall be a tree springing up unto everlasting life."]]},
  {num:42,words:[["Ma ona o lou filiga ma lou faatuatua ma lou onosai i le afioga i lona tausiga,", "And because of your diligence and your faith and your patience with the word in nourishing it,"], ["ina ia mafai ona mauaa i totonu ia te oe,", "that it may take root in you,"], ["faauta,", "behold,"], ["e lata le aso o le a e tauina ai lona fua ,", "by and by ye shall pluck the fruit thereof,"], ["lea ua sili ona pele,", "which is most precious,"], ["lea ua sili ona suamalie i luga o mea uma ua suamalie,", "which is sweet above all that is sweet,"], ["ma lea ua sili ona paepae i luga o mea uma ua papae,", "and which is white above all that is white,"], ["ioe,", "yea,"], ["ma mama i luga o mea mea uma ua mama;", "and pure above all that is pure;"], ["ma o le a outou taumamafa fiafia i lenei fua seia oo lava ina outou maoona,", "and ye shall feast upon this fruit even until ye are filled,"], ["o le a outou le fia aai,", "that ye hunger not,"], ["pe fia feinu ai.", "neither shall ye thirst."]]},
  {num:43,words:[["O le taimi lea,", "Then,"], ["ou uso e,", "my brethren,"], ["o le a outou selesele ai taui o lo outou faatuatua,", "ye shall reap the rewards of your faith,"], ["ma lo outou filiga,", "and your diligence,"], ["ma le onosai,", "and patience,"], ["ma le tali-tiga,", "and long– suffering,"], ["ma faatalitali mo le laau e fua mai fua mo outou.", "waiting for the tree to bring forth fruit unto you."]]},
];
renderVerseSet(al_ch_32_Verses, 'al-ch32-verses');

var al_ch_33_Verses = [
  {num:1,words:[["O lenei ina ua uma ona tautala atu e Alema nei upu,", "Now after Alma had spoken these words,"], ["sa latou feau mai ia te ia i le fia iloa pe tatau ona latou talitonu i se Atua e tasi,", "they sent forth unto him desiring to know whether they should believe in one God,"], ["ina ia mafai ona latou mauaina o lenei fua lea sa ia tautala i ai,", "that they might obtain this fruit of which he had spoken,"], ["pe faapefea ona latou toto o le fatu ,", "or how they should plant the seed,"], ["po o le afioga lea na ia tautala i ai,", "or the word of which he had spoken,"], ["lea na fai mai o ia e ao ina totoina i o latou loto;", "which he said must be planted in their hearts;"], ["po o le a le ala e tatau ona latou amata faaaoga ai lo latou faatuatua.", "or in what manner they should begin to exercise their faith."]]},
  {num:2,words:[["Ma sa fai atu Alema ia te i latou:", "And Alma said unto them:"], ["Faauta,", "Behold,"], ["sa outou fai mai ua le mafai ona outou tapuai atu i lo outou Atua ona ua tutuli ese outou i fafo mai i o outou sunako. Ae faauta,", "ye have said that ye could not worship your God because ye are cast out of your synagogues. But behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["afai ua outou manatu ua le mafai ona outou tapuai atu i le Atua,", "if ye suppose that ye cannot worship God,"], ["ua outou matua sese lava,", "ye do greatly err,"], ["ma e tatau ona outou sailiili i tusitusiga paia;", "and ye ought to search the scriptures;"], ["afai tou te manatu ua latou aoao mai ia te outou lenei mea,", "if ye suppose that they have taught you this,"], ["ua outou le malamalama i ai.", "ye do not understand them."]]},
  {num:3,words:[["Tou te manatua lo outou faitauina o le mea na fai mai ai Senosa ,", "Do ye remember to have read what Zenos,"], ["le perofeta anamua,", "the prophet of old,"], ["e uiga i le tatalo po o le tapuai atu?", "has said concerning prayer or worship?"]]},
  {num:4,words:[["Aua sa fai mai o ia:", "For he said:"], ["Ua e alofa mutimutivale lava,", "Thou art merciful,"], ["le Atua e,", "O God,"], ["ona ua e faafofoga mai i lau tatalo,", "for thou hast heard my prayer,"], ["a'o ou i ai lava i le vao;", "even when I was in the wilderness;"], ["ioe,", "yea,"], ["sa e alofa mutimutivale ina ua ou tatalo atu e uiga ia te i latou o e na avea ma o'u fili ,", "thou wast merciful when I prayed concerning those who were mine enemies,"], ["ma sa e liliu mai i latou ia te au.", "and thou didst turn them to me."]]},
  {num:5,words:[["Ioe,", "Yea,"], ["le Atua e,", "O God,"], ["sa e alofa mutimutivale mai ia te au ina ua ou tagi atu ia te oe i lo'u fanua ;", "and thou wast merciful unto me when I did cry unto thee in my field;"], ["ina ua ou tagi atu ia te oe i la'u tatalo,", "when I did cry unto thee in my prayer,"], ["sa e faafofoga mai ia te au.", "and thou didst hear me."]]},
  {num:6,words:[["O lenei foi,", "And again,"], ["le Atua e,", "O God,"], ["ina ua ou alu atu i lo'u fale sa e faafofoga mai ia te au i lau tatalo.", "when I did turn to my house thou didst hear me in my prayer."]]},
  {num:7,words:[["Ma ina ua ou alu atu i lo'u afeafe ,", "And when I did turn unto my closet,"], ["le Alii e,", "O Lord,"], ["ma tatalo atu ia te oe,", "and prayed unto thee,"], ["sa e faafofoga mai ia te au.", "thou didst hear me."]]},
  {num:8,words:[["Ioe,", "Yea,"], ["e te alofa mutimutivale i au fanau pe a latou tagi atu ia te oe,", "thou art merciful unto thy children when they cry unto thee,"], ["ina ia e faafofogaina i latou ae le o tagata,", "to be heard of thee and not of men,"], ["ma o le a e faafofoga mai lava ia te i latou.", "and thou wilt hear them."]]},
  {num:9,words:[["Ioe,", "Yea,"], ["le Atua e,", "O God,"], ["ua e alofa mutimutivale mai ia te au,", "thou hast been merciful unto me,"], ["ma e faafofogaina au tagi i le lotolotoi o au faapotopotoga.", "and heard my cries in the midst of thy congregations."]]},
  {num:10,words:[["Ioe,", "Yea,"], ["ma sa e faafofoga mai foi ia te au,", "and thou hast also heard me when I have been cast out and have been despised by mine enemies;"], ["ina ua tuli ese au i fafo ma inosia e o'u fili; ioe,", "yea,"], ["sa e faafofoga mai i au tagi,", "thou didst hear my cries,"], ["ma sa e toatamai i ou fili,", "and wast angry with mine enemies,"], ["ma sa e asiasi mai ia te i latou i lou toasa ma le faafanoga vave.", "and thou didst visit them in thine anger with speedy destruction."]]},
  {num:11,words:[["Ma sa e faafofoga mai ia te au ona o o'u puapuaga ma lo'u faamaoni;", "And thou didst hear me because of mine afflictions and my sincerity;"], ["ma ona o lou Alo ua e alofa mutimutivale tele mai ai ia te au,", "and it is because of thy Son that thou hast been thus merciful unto me,"], ["o lea o le a ou tagi atu ai ia te oe i ou puapuaga uma,", "therefore I will cry unto thee in all mine afflictions,"], ["ona o oe ua i ai lou olioli;", "for in thee is my joy;"], ["ona ua e liliu ese au faasalaga mai ia te au,", "for thou hast turned thy judgments away from me,"], ["ona o lou Alo.", "because of thy Son."]]},
  {num:12,words:[["Ma o lenei sa fai atu Alema ia te i latou:", "And now Alma said unto them:"], ["Tou te talitonu ea i ia tusitusiga paia na tusia e i latou o anamua?", "Do ye believe those scriptures which have been written by them of old?"]]},
  {num:13,words:[["Faauta,", "Behold,"], ["afai tou te talitonu i ai,", "if ye do,"], ["e ao ina outou talitonu i le mea ua fai mai ai Senosa ;", "ye must believe what Zenos said;"], ["aua faauta,", "for,"], ["na fai mai o ia:", "behold he said:"], ["Ua e liliu ese au faasalaga ona o lou Alo.", "Thou hast turned away thy judgments because of thy Son."]]},
  {num:14,words:[["O lenei faauta,", "Now behold,"], ["ou uso e,", "my brethren,"], ["ou te fia fesili atu pe ua outou faitauina ea tusitusiga paia? Afai ua outou faitauina,", "I would ask if ye have read the scriptures? If ye have,"], ["e mafai faapefea ona outou le talitonu i le Alo o le Atua?", "how can ye disbelieve on the Son of God?"]]},
  {num:15,words:[["Ona ua le tusia e faapea ua nao Senosa sa tautala mai e uiga i nei mea,", "For it is not written that Zenos alone spake of these things,"], ["ae sa tautala foi Senoka e uiga i nei mea—", "but Zenock also spake of these things—"]]},
  {num:16,words:[["Aua faauta,", "For behold,"], ["sa fai mai o ia:", "he said:"], ["Ua e toatamai,", "Thou art angry,"], ["le Alii e,", "O Lord,"], ["i lenei nuu,", "with this people,"], ["ona ua latou le fia malamalama i lou alofa mutimutivale ia ua e to mai i luga o i latou ona o lou Alo.", "because they will not understand thy mercies which thou hast bestowed upon them because of thy Son."]]},
  {num:17,words:[["Ma o lenei,", "And now,"], ["ou uso e,", "my brethren,"], ["ua outou vaai ua molimau mai se perofeta lona lua o anamua e uiga i le Alo o le Atua, ma ona sa le fia malamalama tagata i ana upu,", "ye see that a second prophet of old has testified of the Son of God,"], ["o lea na latou fetogi ai o ia i maa ia oti.", "and because the people would not understand his words they stoned him to death."]]},
  {num:18,words:[["Peitai faauta,", "But behold,"], ["ua le ona pau lea;", "this is not all;"], ["ua le nao i laua ia e na tautatala mai e uiga i le Alo o le Atua.", "these are not the only ones who have spoken concerning the Son of God."]]},
  {num:19,words:[["Faauta,", "Behold,"], ["sa tautalagia o ia e Mose ;", "he was spoken of by Moses;"], ["ioe,", "yea,"], ["ma faauta sa sii ae i luga se faatusa i le vao,", "and behold a type was raised up in the wilderness,"], ["e faapea o soo se tasi e tepa ae i ai e mafai ona ola. Ma e toatele sa tepa i ai ma ola ai.", "that whosoever would look upon it might live. And many did look and live."]]},
  {num:20,words:[["Peitai e toaitiiti sa malamalama i le uiga o ia mea,", "But few understood the meaning of those things,"], ["ma o le pogai ona o le maaa o o latou loto.", "and this because of the hardness of their hearts."], ["Peitai sa i ai le toatele o e sa sili atu ona maaa tele sa latou le fia tetepa ae ai,", "But there were many who were so hardened that they would not look,"], ["ma o lea na fano ai i latou.", "therefore  they perished."], ["O lenei o le pogai na latou le fia tetepa ae ai, ona sa latou le talitonu o le a faamaloloina ai i latou.", "Now the reason they would not look is because they did not believe that it would heal them."]]},
  {num:21,words:[["E,", "O my brethren,"], ["ou uso e,", "if ye could be healed by merely casting about your eyes that ye might be healed,"], ["afai e mafai ona faamaloloina outou i le nao le tepa atu o o outou mata ina ia mafai ona faamaloloina outou,", "would ye not behold quickly,"], ["pe tou te le fia tetepa vave atu ea, pe sili atu ia te outou le faamaaa o o outou loto i le le talitonu,", "or would ye rather harden your hearts in unbelief,"], ["ma faapaie,", "and be slothful,"], ["ma outou le fia tetepa atu ai o outou mata,", "that ye would not cast about your eyes,"], ["ma outou fano ai?", "that ye might perish?"]]},
  {num:22,words:[["Afai o lea,", "If so,"], ["o le a oo mai le malaia i o outou luga;", "wo shall come upon you;"], ["ae afai e le o lea,", "but if not so,"], ["ona tetepa ae lea o o outou mata ma amata ona talitonu i le Alo o le Atua,", "then cast about your eyes and begin to believe in the Son of God,"], ["o le a afio mai o ia e togiola ona tagata,", "that he will come to redeem his people,"], ["ma o le a mafatia ma maliu o ia e togiola mo a latou agasala;", "and that he shall suffer and die to atone for their sins;"], ["ma o le a toetu mai o ia mai le oti,", "and that he shall rise again from the dead,"], ["lea o le a faataunuu ai le toetutu mai,", "which shall bring to pass the resurrection,"], ["o le a laulaututu ai tagata uma i ona luma,", "that all men shall stand before him,"], ["e faamasinoina i le aso faamasino mulimuli,", "to be judged at the last and judgment day,"], ["e tusa ma a latou galuega .", "according to their works."]]},
  {num:23,words:[["Ma o lenei,", "And now,"], ["ou uso e,", "my brethren,"], ["ou te manao ia outou toto lenei afioga i o outou loto,", "I desire that ye shall plant this word in your hearts,"], ["ma a amata ona malena a'e ia faapea ona tausia i lo outou faatuatua.", "and as it beginneth to swell even so nourish it by your faith."], ["Ma faauta,", "And behold,"], ["o le a avea ma laau,", "it will become a tree,"], ["e puna ae i totonu o outou i le ola tumau-faavavau.", "springing up in you unto everlasting life."], ["Ma ona talosia lea ia tuuina mai e le Atua ia te outou ia mama a outou avega ,", "And then may God grant unto you that your burdens may be light,"], ["e ala i le olioli o lona Alo.", "through the joy of his Son."], ["Ma o nei mea uma lava e mafai ona outou faia, pe afai tou te loto i ai.", "And even all this can ye do if ye will."], ["Amene.", "Amen."]]},
];
renderVerseSet(al_ch_33_Verses, 'al-ch33-verses');

var al_ch_34_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina ua uma ona tautala atu e Alema o nei upu ia te i latou,", "And now it came to pass that after Alma had spoken these words unto them he sat down upon the ground,"], ["sa nofo o ia i lalo i luga o le eleele, ma sa tulai Amoleka ma amata ona aoao atu ia te i latou,", "and Amulek arose and began to teach them,"], ["ua fai atu:", "saying:"]]},
  {num:2,words:[["Ou uso e,", "My brethren,"], ["ou te manatu e le mafai ona outou pouliuli e uiga i mea ua tautalagia e uiga i le afio mai o Keriso,", "I think that it is impossible that ye should be ignorant of the things which have been spoken concerning the coming of Christ,"], ["o le ua matou aoao atu o le Alo o le Atua; ioe,", "who is taught by us to be the Son of God;"], ["ua ou iloa sa tele lava ona aoao atu o nei mea ia te outou,", "yea,"], ["ae tou te lei o ese mai ia i matou.", "I know that these things were taught unto you bountifully before your dissension from among us."]]},
  {num:3,words:[["Ma talu ai ona ua outou mananao mai i lo'u uso pele ia faailoa atu e ia ia te outou le mea e tatau ona outou faia,", "And as ye have desired of my beloved brother that he should make known unto you what ye should do,"], ["ona o o outou puapuaga;", "because of your afflictions;"], ["ma sa ia saunoa tele atu ia te outou e saunia ai o outou mafaufau;", "and he hath spoken somewhat unto you to prepare your minds;"], ["ioe,", "yea,"], ["ma sa ia apoapoaiina outou ia outou faatuatua ma onosai—", "and he hath exhorted you unto faith and to patience—"]]},
  {num:4,words:[["Ioe,", "Yea,"], ["seia oo lava ina outou maua le faatuatua tele tou te toto ai le afioga i o outou loto,", "even that ye would have so much faith as even to plant the word in your hearts,"], ["ina ia mafai ona outou tofotofo le faataitaiga o lona lelei.", "that ye may try the experiment of its goodness."]]},
  {num:5,words:[["Ma ua matou vaai o le fesili tele o loo i o outou mafaufau, pe ua i ai i le Alo o le Atua le afioga,", "And we have beheld that the great question which is in your minds is whether the word be in the Son of God,"], ["po o le a leai se Keriso.", "or whether there shall be no Christ."]]},
  {num:6,words:[["Ma sa outou vaai foi ua faamaonia atu e lou uso ia te outou,", "And ye also beheld that my brother has proved unto you,"], ["i le tele o mea,", "in many instances,"], ["ua i ai ia Keriso le afioga mo le olataga.", "that the word is in Christ unto salvation."]]},
  {num:7,words:[["Sa sii mai e lou uso upu a Senosa,", "My brother has called upon the words of Zenos,"], ["ma upu foi a Senoka,", "that redemption cometh through the Son of God,"], ["e faapea e oo mai le togiola e ala mai i le Alo o le Atua;", "and also upon the words of Zenock;"], ["ma sa ia tapa foi ia Mose,", "and  also he has appealed unto Moses,"], ["e faamaonia ai ua moni nei mea.", "to prove that these things are true."]]},
  {num:8,words:[["Ma o lenei,", "And now,"], ["faauta, o le a ou molimau atu ia te outou e au lava ia,", "behold,"], ["ua moni nei mea.", "I will testify unto you of myself that these things are true."], ["Faauta,", "Behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ua ou iloa o le a afio mai Keriso i totonu o le fanauga a tagata,", "that I do know that Christ shall come among the children of men,"], ["e ave i ona luga solitulafono a ona tagata;", "to take upon him the transgressions of his people,"], ["ma o le a ia togiola mo agasala a le lalolagi;", "and that he shall atone for the sins of the world;"], ["ona ua fetalai mai ai le Alii le Atua.", "for the Lord God hath spoken it."]]},
  {num:9,words:[["Aua e tatau ona faia o se togiola ;", "For it is expedient that an atonement should be made;"], ["ona e tusa ma le fuafuaga tele a le Atua Faavavau,", "for according to the great plan of the Eternal God there must be an atonement made,"], ["e ao ona faia o se togiola,", "or else all mankind must unavoidably perish;"], ["a leai o le a le maalofia le fano o tagata uma;", "yea,"], ["ioe, ua maaa uma;", "all are hardened;"], ["ioe,", "yea,"], ["ua pauu uma ma ua leiloloa,", "all are fallen and are lost,"], ["ma o le a fano vagana ai e ala i le togiola lea e tatau ona faia.", "and must perish except it be through the atonement which it is expedient should be made."]]},
  {num:10,words:[["Ona e tatau ona i ai o se taulaga tele ma mulimuli;", "For it is expedient that there should be a great and last sacrifice;"], ["ioe,", "yea,"], ["e le o se taulaga o se tagata,", "not a sacrifice of man,"], ["pe o se manu vaefa,", "neither of beast,"], ["pe o soo se ituaiga foi o manu felelei;", "neither of any manner of fowl;"], ["ona o le a le o se taulaga faatagata;", "for it shall not be a human sacrifice;"], ["ae o se taulaga e ao ina le gata ma faavavau.", "but it must be an infinite and eternal sacrifice."]]},
  {num:11,words:[["O lenei e leai se tagata e mafai ona ia taulagaina lona lava toto e togiola mo agasala a se tasi.", "Now there is not any man that can sacrifice his own blood which will atone for the sins of another."], ["O lenei,", "Now,"], ["afai e fasioti tagata se tagata,", "if a man murdereth,"], ["faauta, e ave ea e la tatou tulafono,", "behold will our law,"], ["lea ua tonu ,", "which is just,"], ["le ola o lona uso? Ou te fai atu ia te outou,", "take the life of his brother? I say unto you,"], ["E leai.", "Nay."]]},
  {num:12,words:[["Ae e manaomia e le tulafono le ola o ia o le na fasioti tagata;", "But the law requireth the life of him who hath murdered;"], ["o lea e le mafai ona i ai o se mea e itiiti mai i se togiola e le gata e lava mo agasala a le lalolagi.", "therefore there can be nothing which is short of an infinite atonement which will suffice for the sins of the world."]]},
  {num:13,words:[["O lea,", "Therefore,"], ["e tatau ona i ai o se taulaga tele ma mulimuli,", "it is expedient that there should be a great and last sacrifice;"], ["ma ona i ai lea,", "and then shall there be,"], ["pe tatau ona i ai lea,", "or it is expedient there should be,"], ["o se taofiga o le faamasaaina o le toto;", "a stop to the shedding of blood;"], ["ona faataunuu ai lea o le tulafono a Mose;", "then shall the law of Moses be fulfilled;"], ["ioe,", "yea,"], ["o le a faataunuuina uma lava,", "it shall be all fulfilled,"], ["o iota ma mataitusi taitasi,", "every jot and tittle,"], ["ma o le a leai se mea e mavae atu e le faataunuuina.", "and none shall have passed away."]]},
  {num:14,words:[["Ma faauta,", "And behold,"], ["o le uiga atoa lenei o le tulafono ,", "this is the whole meaning of the law,"], ["o iota uma lava e faasino atu i lena taulaga tele ma mulimuli;", "every whit pointing to that great and last sacrifice;"], ["ma o lena taulaga tele ma mulimuli o le Alo lea o le Atua,", "and that great and last sacrifice will be the Son of God,"], ["ioe,", "yea,"], ["ua le gata ma faavavau.", "infinite and eternal."]]},
  {num:15,words:[["Ma o le a faapea ona aumai e ia le olataga ia i latou uma o e e talitonu i lona suafa;", "And thus he shall bring salvation to all those who shall believe on his name;"], ["ona o le faamoemoe lea o lenei taulaga mulimuli,", "this being the intent of this last sacrifice,"], ["e aumai ai loto o le alofa mutimutivale,", "to bring about the bowels of mercy,"], ["ia ua faumalo i le faamasinotonu,", "which overpowereth justice,"], ["ma aumai ai ala i tagata e mafai ai ona latou maua o le faatuatua e salamo ai.", "and bringeth about means unto men that they may have faith unto repentance."]]},
  {num:16,words:[["Ma faapea ona mafai ai e le alofa mutimutivale ona faamalie manaoga o le faamasinotonu , ma siosiomia ai i latou i lima o le saogalemu,", "And thus mercy can satisfy the demands of justice,"], ["a'o ia o le na te le faaaoga se faatuatua e salamo ai,", "and encircles them in the arms of safety,"], ["ua tualiali i le tulafono atoa o manaoga o le faamasinotonu ;", "while he that exercises no faith unto repentance is exposed to the whole law of the demands of justice;"], ["o lea ua nao ia o le ua i ai le faatuatua e salamo ai, ua aumai ai le fuafuaga tele ma faavavau o le togiolaina.", "therefore only unto him that has faith unto repentance is brought about the great and eternal plan of redemption."]]},
  {num:17,words:[["O lea talosia ia tuu mai e le Atua ia te outou,", "Therefore may God grant unto you,"], ["ou uso e,", "my brethren,"], ["ia amata ona outou faaaoga o lo outou faatuatua e salamo ai,", "that ye may begin to exercise your faith unto repentance,"], ["ina ia amata ona outou valaau atu i luga i lona suafa paia,", "that ye begin to call upon his holy name,"], ["ina ia alofa mutimutivale mai o ia ia te outou.", "that he would have mercy upon you;"]]},
  {num:18,words:[["Ioe,", "Yea,"], ["tagi atu ia te ia mo le alofa mutimutivale;", "cry unto him for mercy;"], ["ona ua malosi o ia e faaola.", "for he is mighty to save."]]},
  {num:19,words:[["Ioe,", "Yea,"], ["ia outou faalotomaualalalo outou lava,", "humble yourselves,"], ["ma tatalo atu pea ia te ia.", "and continue in prayer unto him."]]},
  {num:20,words:[["Tagi atu ia te ia pe a outou i ai i o outou fanua,", "Cry unto him when ye are in your fields,"], ["ioe,", "yea,"], ["mo a outou lafu uma.", "over all your flocks."]]},
  {num:21,words:[["Tagi atu ia te ia i o outou fale,", "Cry unto him in your houses,"], ["ioe,", "yea,"], ["mo lo outou auaiga uma,", "over all your household,"], ["i le taeao,", "both morning,"], ["aoauli,", "mid– day,"], ["ma le afiafi.", "and evening."]]},
  {num:22,words:[["Ioe,", "Yea,"], ["tagi atu ia te ia e faasaga i le mana o o outou fili.", "cry unto him against the power of your enemies."]]},
  {num:23,words:[["Ioe,", "Yea,"], ["tagi atu ia te ia e faasaga i le tiapolo ,", "cry unto him against the devil,"], ["o le o se fili i le amiotonu uma.", "who is an enemy to all righteousness."]]},
  {num:24,words:[["Tagi atu ia te ia mo laau toto o o outou fanua,", "Cry unto him over the crops of your fields,"], ["ina ia outou manuia ai.", "that ye may prosper in them."]]},
  {num:25,words:[["Tagi atu mo lafu o o outou fanua,", "Cry over the flocks of your fields,"], ["ina ia faateleina.", "that they may increase."]]},
  {num:26,words:[["Ae ua le ona pau lea;", "But this is not all;"], ["e ao ina outou sasaa atu o outou agaga i totonu o o outou afeafe ,", "ye must pour out your souls in your closets,"], ["ma o outou nofoaga lilo,", "and your secret places,"], ["ma i o outou vao.", "and in your wilderness."]]},
  {num:27,words:[["Ioe,", "Yea,"], ["ma a outou le tagi atu i le Alii,", "and when you do not cry unto the Lord,"], ["ia tuu o outou loto ia faatumuina , ia alu atu pea ia te ia i le tatalo e le aunoa,", "let your hearts be full,"], ["mo lo outou manuia,", "drawn out in prayer unto him continually for your welfare,"], ["ma le manuia foi o i latou o e ua siomia ai outou.", "and also for the welfare of those who are around you."]]},
  {num:28,words:[["Ma o lenei faauta,", "And now behold,"], ["ou uso pele e,", "my beloved brethren,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["aua tou te manatu ona pau lea;", "do not suppose that this is all;"], ["aua a uma ona outou faia o nei mea uma,", "for after ye have done all these things,"], ["afai tou te liliu ese e ua le tagolima ,", "if ye turn away the needy,"], ["ma e ua le lavalava,", "and the naked,"], ["ma le asiasi atu i e ua mamai ma puapuagatia,", "and visit not the sick and afflicted, and impart of your substance,"], ["ma le faasoa atu a outou mea,", "if ye have,"], ["pe afai ua i ai ia te outou ni mea e faasoa atu ia i latou o e ua tutu le tagolima—ou te fai atu ia te outou,", "to those who stand in need—I say unto you,"], ["afai tou te le faia se tasi o ia mea,", "if ye do not any of these things,"], ["faauta,", "behold,"], ["ua le aoga lau tatalo ,", "your prayer is vain,"], ["ma ua leai se mea e te maua mai ai,", "and availeth you nothing,"], ["ma ua tusa outou o ni tagata pepelo o e ua faafitia le faatuatuaga.", "and ye are as hypocrites who do deny the faith."]]},
  {num:29,words:[["O lea,", "Therefore,"], ["afai tou te le manatua ia outou alolofafua ,", "if ye do not remember to be charitable,"], ["ua tusa outou o ni otaota,", "ye are as dross,"], ["ia e tiai i fafo e faamama auro,", "which the refiners do cast out,"], ["(ona ua le aoga) ma soli i lalo o vae o tagata.", "(it being of no worth) and is trodden under foot of men."]]},
  {num:30,words:[["Ma o lenei,", "And now,"], ["ou uso e,", "my brethren,"], ["ou te manao,", "I would that,"], ["ona ua uma ona outou maua o molimau e tele naua,", "after ye have received so many witnesses,"], ["ona ua outou vaai ua molimau mai tusitusiga paia e uiga i nei mea,", "seeing that the holy scriptures testify of these things,"], ["ia outou o mai ma aumai fua o le salamo.", "ye come forth and bring fruit unto repentance."]]},
  {num:31,words:[["Ioe,", "Yea,"], ["ou te manao ia outou o mai ma aua le toe faamaaaina o outou loto;", "I would that ye would come forth and harden not your hearts any longer;"], ["aua faauta,", "for behold,"], ["o le taimi ma le aso lenei o lo outou olataga;", "now is the time and the day of your salvation;"], ["ma o lea,", "and therefore,"], ["afai tou te salamo ma le faamaaaina o outou loto,", "if ye will repent and harden not your hearts,"], ["o le taimi nei lava o le a faataunuu ai le fuafuaga tele o le togiolaina ia te outou.", "immediately shall the great plan of redemption be brought about unto you."]]},
  {num:32,words:[["Aua faauta,", "For behold,"], ["o le olaga lenei o le taimi lea mo tagata e saunia ai e feiloai ma le Atua;", "this life is the time for men to prepare to meet God;"], ["ioe,", "yea,"], ["faauta o le aso o le olaga lenei o le aso lea mo tagata e fai ai a latou galuega.", "behold the day of this life is the day for men to perform their labors."]]},
  {num:33,words:[["Ma o lenei,", "And now,"], ["e pei ona ou fai atu muamua ia te outou,", "as I said unto you before,"], ["talu ai ona ua uma ona outou maua o molimau e tele,", "as ye have had so many witnesses,"], ["o lea,", "therefore,"], ["ou te aioi atu ai ia te outou, ia aua ne'i o outou faatuai le aso o lo outou salamo seia oo i le iuga;", "I beseech of you that ye do not procrastinate the day of your repentance until the end;"], ["aua a mavae le aso lenei o le olaga,", "for after this day of life,"], ["lea ua tuuina mai ia i tatou e saunia ai mo le faavavau,", "which is given us to prepare for eternity,"], ["faauta,", "behold,"], ["afai tatou te le faalelei atili o tatou taimi a'o tatou i ai i lenei olaga,", "if we do not improve our time while in  this life,"], ["ona oo mai ai lea o le po o le pouliuli e le mafai ona faia ai o se galuega.", "then cometh the night of darkness wherein there can be no labor performed."]]},
  {num:34,words:[["E le mafai ona e fai mai,", "Ye cannot say,"], ["pe a aumai oe i lena tulaga matautia,", "when ye are brought to that awful crisis,"], ["o le a ou salamo,", "that I will repent,"], ["o le a ou foi atu i lou Atua. E leai,", "that I will return to my God. Nay,"], ["e le mafai ona e fai mai o nei upu;", "ye cannot say this;"], ["ona o lena lava agaga e tasi sa mau i o outou tino i le taimi tou te o ese atu ai i fafo o lenei olaga,", "for that same spirit which doth possess your bodies at the time that ye go out of this life,"], ["o lena lava agaga o le a i ai le mana e mau ai i lou tino i lena lalolagi faavavau.", "that same spirit will have power to possess your body in that eternal world."]]},
  {num:35,words:[["Aua faauta,", "For behold,"], ["afai sa e faatuai le aso o lou salamo seia oo i le oti,", "if ye have procrastinated the day of your repentance even until death,"], ["faauta,", "behold,"], ["ua avea oe o se ua pulea e le agaga o le tiapolo,", "ye have become subjected to the spirit of the devil,"], ["ma ua ia faamaufaailogaina oe o sana;", "and he doth seal you his;"], ["o lea,", "therefore,"], ["ua alu ese ai le Agaga o le Alii mai ia te oe,", "the Spirit of the Lord hath withdrawn from you,"], ["ma ua leai sona nofoaga i totonu o oe,", "and hath no place in you,"], ["ma ua i ai i le tiapolo le mana atoa i ou luga;", "and the devil hath all power over you;"], ["ma o le tulaga faaiu lenei o e e amioleaga.", "and this is the final state of the wicked."]]},
  {num:36,words:[["Ma ua ou iloa lenei mea,", "And this I know,"], ["ona ua fetalai mai le Alii,", "because the Lord hath said he dwelleth not in unholy temples,"], ["e le afio o ia i totonu o ni malumalu ua le paia,", "but in the hearts of the righteous doth he dwell;"], ["ae o totonu o loto o e ua amiotonu e afio ai o ia; ioe,", "yea,"], ["ma ua fetalai mai foi o ia o e e amiotonu o le a nonofo i lalo i totonu o lona malo,", "and he has also said that the righteous shall sit down in his kingdom,"], ["e le toe o atu i fafo;", "to go no more out;"], ["ae o le a faasinasinaina o latou ofu e ala i le toto o le Tamai Mamoe.", "but their garments should be made white through the blood of the Lamb."]]},
  {num:37,words:[["Ma o lenei,", "And now,"], ["ou uso pele e,", "my beloved brethren,"], ["ou te manao ia outou manatua nei mea,", "I desire that ye should remember these things,"], ["ma e tatau ona outou galueaiina lo outou olataga ma le matau i luma o le Atua,", "and that ye should work out your salvation with fear before God,"], ["ma ia outou le toe faafitia le afio mai o Keriso;", "and that ye should no more deny the coming of Christ;"]]},
  {num:38,words:[["Ia outou le toe finau e faasaga i le Agaga Paia,", "That ye contend no more against the Holy Ghost,"], ["ae ia outou talia o ia,", "but that ye receive it,"], ["ma ave i o outou luga le suafa o Keriso;", "and take upon you the name of Christ;"], ["ma ia outou faalotomaualalaloina outou lava ia oo ifo lava i le efuefu,", "that ye humble yourselves even to the dust,"], ["ma tapuai i le Atua,", "and worship God,"], ["i soo se mea atonu tou te i ai,", "in whatsoever place ye may be in,"], ["i le agaga ma le upumoni;", "in spirit and in truth;"], ["ma ia outou ola i le faafetai i aso uma,", "and that ye live in thanksgiving daily,"], ["mo le alofa mutimutivale ma faamanuiaga e tele ua ia to mai i o outou luga.", "for the many mercies and blessings which he doth bestow upon you."]]},
  {num:39,words:[["Ioe,", "Yea,"], ["ma ou te apoapoai atu foi ia te outou,", "and I also exhort you,"], ["ou uso e,", "my brethren,"], ["ia outou mataala i le tatalo e le aunoa,", "that ye be watchful unto prayer continually,"], ["ina ia le taitaieseina outou e faaosoosoga a le tiapolo,", "that ye may not be led away by the temptations of the devil,"], ["ina ia le manumalo o ia ia te outou,", "that he may not overpower you,"], ["ina ia le avea outou ona tagata i le aso gataaga;", "that ye may not become his subjects at the last day;"], ["aua faauta,", "for behold,"], ["na te le tauia outou i se mea lelei.", "he rewardeth you no good thing."]]},
  {num:40,words:[["Ma o lenei o'u uso pele e,", "And now my beloved brethren,"], ["ou te fia apoapoai atu ia te outou,", "I would exhort you to have patience,"], ["ia i ai ia te outou le onosai , ma ia outou talitalia puapuaga eseese uma lava;", "and that ye bear with all manner of afflictions;"], ["ma ia outou le upuleaga faasaga atu ia te i latou o e na tutulia outou i fafo ona o lo outou matitiva tele,", "that ye do not revile against those who do cast you out because of your exceeding poverty,"], ["nei avea outou ma tagata agasala e pei o i latou.", "lest ye become sinners like unto them;"]]},
  {num:41,words:[["Ae ia i ai ia te outou le onosai,", "But that ye have patience,"], ["ma talitalia ia puapuaga,", "and bear with those afflictions,"], ["faatasi ma le faamoemoe mausali o le a outou mapu mai i o outou puapuaga uma i se aso.", "with a firm hope that ye shall one day rest from all your afflictions."]]},
];
renderVerseSet(al_ch_34_Verses, 'al-ch34-verses');

var al_ch_35_Verses = [
  {num:1,words:[["O lenei sa oo ina ua uma ona faaiu e Amoleka nei upu,", "Now it came to pass that after Amulek had made an end of these words,"], ["sa latou tuumuli ese i latou lava mai le motu o tagata ma o mai i le laueleele o Seasona.", "they withdrew themselves from the multitude and came over into the land of Jershon."]]},
  {num:2,words:[["Ioe,", "Yea,"], ["ma o le vaega na totoe o le au uso,", "and the rest of the brethren,"], ["ina ua uma ona latou talai atu o le afioga ia sa Soramā,", "after they had preached the word unto the Zoramites,"], ["sa latou o mai foi i le laueleele o Seasona.", "also came over into the land of Jershon."]]},
  {num:3,words:[["Ma sa oo ina ua uma ona talanoa faatasi o le vaega sili ona lauiloa o sa Soramā e uiga i upu ia sa talai atu ia te i latou,", "And it came to pass that after the more popular part of the Zoramites had consulted together concerning the words which had been preached unto them,"], ["sa latou feita ona o le afioga,", "they were angry because of the word,"], ["ona sa faaumatia ai lo latou atamai ;", "for it did destroy their craft;"], ["o lea na latou le fia faalogo ai i upu.", "therefore they would not hearken unto the words."]]},
  {num:4,words:[["Ma sa latou feau atu ma faapotopoto faatasi tagata uma i le laueleele atoa,", "And they sent and gathered together through– out all the land all the people,"], ["ma talanoa faatasi ma i latou e uiga i upu sa fofogaina.", "and consulted with them concerning the words which had been spoken."]]},
  {num:5,words:[["O lenei sa le faailoa atu e o latou pule ma o latou faitaulaga ma o latou aoao i tagata, e uiga i o latou manao;", "Now their rulers and their priests and their teachers did not let the people know concerning their desires;"], ["o lea na latou maua mai ai faalilolilo manatu o le nuu atoa.", "therefore they found out privily the minds of all the people."]]},
  {num:6,words:[["Ma sa oo ina ua uma ona latou iloa o manatu o tagata uma,", "And it came to pass that after they had found out the minds of all the people,"], ["o i latou o e sa fiafia i upu ia na tautalagia e Alema ma ona uso,", "those who were in favor of the words which had been spoken by Alma and his brethren were cast out of the land;"], ["sa tutuli ese i fafo mai le laueleele; ma sa toatele i latou;", "and they were many;"], ["ma sa latou o mai foi i le laueleele o Seasona.", "and they came over also into the land of Jershon."]]},
  {num:7,words:[["Ma sa oo ina auauna atu Alema ma ona uso ia te i latou.", "And it came to pass that Alma and his brethren did minister unto them."]]},
  {num:8,words:[["O lenei sa feita tagata o sa Soramā i tagata o Amona o e sa i Seasona, ma sa auina atu e le pule taitai sili o sa Soramā,", "Now the people of the Zoramites were angry with the people of Ammon who were in Jershon,"], ["o se tagata amioleaga tele, i le nuu o Amona se feau,", "and the chief ruler of the Zoramites,"], ["e manao ia te i latou ia latou tutuli ese i fafo mai lo latou laueleele atoa,", "being a very wicked man,"], ["i latou uma o e na o mai i lo latou laueleele, mai ia te i latou.", "sent over unto the people of Ammon desiring them that they should cast out of their land all those who came over from them into their land."]]},
  {num:9,words:[["Ma sa ia manava mai ni faamatauga e tele e faasaga ia te i latou. Ma o lenei sa le matatau le nuu o Amona ia latou upu;", "And he breathed out many threatenings against them. And now the people of Ammon did not fear their words;"], ["o lea sa latou le tutuli ese ai i latou i fafo,", "therefore they did not cast them out,"], ["ae sa latou talia tagata matitiva uma o sa Soramā o e na o mai ia te i latou;", "but they did receive all the poor of the Zoramites that came over unto them;"], ["ma sa latou tausia i latou,", "and they did nourish them,"], ["ma faalavalava i latou,", "and did clothe them,"], ["ma tuu atu fanua ia te i latou e fai mo o latou tofi;", "and did give unto them lands for their inheritance;"], ["ma sa latou auauna atu ia te i latou e tusa ma o latou manaoga.", "and they did administer unto them according to their wants."]]},
  {num:10,words:[["O lenei, o lenei mea sa oso ai le ita o sa Soramā e faasaga i le nuu o Amona,", "Now this did stir up the Zoramites to anger against the people of Ammon,"], ["ma sa amata ona latou femiomioai ma sa Lamanā ma faaoso foi i latou ia feita e faasaga ia te i latou.", "and they began to mix with the Lamanites and to stir them up also to anger against them."]]},
  {num:11,words:[["Ma sa faapea ona amata e sa Soramā ma sa Lamanā ona faia o sauniuniga mo le taua e faasaga i le nuu o Amona,", "And thus the Zoramites and the Lamanites began to make preparations for war against the people of Ammon,"], ["ma e faasaga foi ia sa Nifaē.", "and also against the Nephites."]]},
  {num:12,words:[["Ma sa faapea ona iu o le lona sefulu fitu o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae.", "And thus ended the seventeenth year of the reign of the judges over the people of Nephi."]]},
  {num:13,words:[["Ma sa o ese atu i fafo le nuu o Amona mai le laueleele o Seasona,", "And the people of Ammon departed out of the land of Jershon,"], ["ma o mai i le laueleele o Meleka,", "and came over into the land of Melek,"], ["ma faaavanoa le laueleele o Seasona mo autau a sa Nifaē,", "and gave place in the land of Jershon for the armies of the Nephites,"], ["ina ia mafai ona latou tau ma autau a sa Lamanā ma autau a sa Soramā;", "that they might contend with the armies of the Lamanites and the armies of the Zoramites;"], ["ma sa faapea ona amata o se taua i le va o sa Lamanā ma sa Nifaē,", "and thus commenced a war betwixt the Lamanites and the Nephites,"], ["i le lona sefulu valu o tausaga o le nofoaiga a faamasino;", "in the eighteenth year of the reign  of the judges;"], ["ma o le a tuuina atu se tala o a latou taua i se taimi o mulimuli mai.", "and an account shall be given of their wars hereafter."]]},
  {num:14,words:[["Ma sa toe foi atu Alema,", "And Alma,"], ["ma Amona,", "and Ammon,"], ["ma o laua uso,", "and their brethren,"], ["ma atalii foi e toalua o Alema i le laueleele o Sara'emila,", "and also the two sons of Alma returned to the land of Zarahemla,"], ["ina ua mavae ona avea o i latou o ni meafaigaluega i aao o le Atua i le aumaia o le toatele o sa Soramā i le salamo;", "after having been instruments in the hands of God of bringing many of the Zoramites to repentance;"], ["ma o le toatele o i latou o e na aumai i le salamo, sa tutuli ese i fafo mai lo latou laueleele;", "and as many as were brought to repentance were driven out of their land;"], ["peitai ua latou maua ni fanua mo o latou tofi i le laueleele o Seasona,", "but they have lands for their inheritance in the land of Jershon,"], ["ma ua latou fetagofi i auupega o taua e puipui ai i latou lava,", "and they have taken up arms to defend themselves,"], ["ma a latou ava,", "and their wives,"], ["ma fanau,", "and children,"], ["ma o latou laueleele.", "and their lands."]]},
  {num:15,words:[["O lenei o Alema,", "Now Alma,"], ["i le faanoanoa tele i le amioletonu o lona nuu,", "being grieved for the iniquity of his people,"], ["ioe,", "yea for the wars,"], ["mo taua,", "and the bloodsheds,"], ["ma le faamasaatoto,", "and the contentions which were among them;"], ["ma finauga sa i ai i totonu o i latou; ma ona sa alu atu o ia e tau atu le afioga,", "and having been to declare the word,"], ["pe na auina atu e tau atu le afioga,", "or sent to declare the word,"], ["i totonu o tagata uma i aai uma;", "among all the people in every city;"], ["ma i le vaai atu ua amata ona faasolo maaa loto o tagata,", "and seeing that the hearts of the people began to wax hard,"], ["ma ua amata ona latou le fiafia ona o le le matuumamaina o le afioga,", "and that they began to be offended because of the strictness of the word,"], ["sa matua faanoanoa tele lava lona loto.", "his heart was exceedingly sorrowful."]]},
  {num:16,words:[["O lea,", "Therefore,"], ["sa ia faatonu atu ai ia faapotopoto faatasi mai ona atalii,", "he caused that his sons should be gathered together,"], ["ina ia mafai ona ia tuu eseese atu ia te i latou uma taitoatasi lana poloaiga ,", "that he might give unto them every one his charge, separately,"], ["e faatatau i mea e uiga i le amiotonu.", "concerning the things pertaining unto righteousness."], ["Ma ua ia i matou se tala o ana poloaiga,", "And we have an account of his commandments,"], ["ia na ia tuu atu ia te i latou e tusa ma lana lava talafaamaumau.", "which he gave unto them according to his own record."]]},
];
renderVerseSet(al_ch_35_Verses, 'al-ch35-verses');

var al_ch_36_Verses = [
  {num:1,words:[["Lou atalii e,", "My son,"], ["ua'i mai ia ou taliga i au upu,", "give ear to my words;"], ["ona ou te tauto atu ia te oe, o le tulaga e oo i ai lau tausiga o poloaiga a le Atua,", "for I swear unto you,"], ["o le a e manuia i le laueleele.", "that inasmuch as ye shall keep the commandments of God ye shall prosper in the land."]]},
  {num:2,words:[["Ou te manao ina ia e faia e pei ona ou faia,", "I would that ye should do as I have done,"], ["i le manatuaina o le faatagataotauaina o o tatou tamā;", "in remembering the captivity of our fathers;"], ["ona sa i ai i latou i le pologa ,", "for they were in bondage,"], ["ma sa leai se tasi sa mafai ona laveaiina i latou vagana ai le Atua o Aperaamo,", "and none could deliver them except it was the God of Abraham,"], ["ma le Atua o Isaako,", "and the God of Isaac,"], ["ma le Atua o Iakopo;", "and the God of Jacob;"], ["ma sa ia laveaiina moni i latou i o latou puapuaga.", "and he surely did deliver them in their afflictions."]]},
  {num:3,words:[["Ma o lenei,", "And now,"], ["lou atalii e, Helamana,", "O my son Helaman,"], ["faauta,", "behold,"], ["ua e i ai i lou talavou,", "thou art in thy youth,"], ["ma o lea,", "and therefore,"], ["ou te aioi atu ai ia te oe, ia e faalogo mai i au upu,", "I beseech of thee that thou wilt hear my words and learn of me;"], ["ma aoao mai ia te au;", "for I do know that whosoever shall put their trust in God shall be supported in their trials,"], ["ona ua ou iloa o ai lava e tuu atu lo latou faalagolago i le Atua e lagolagoina i o latou tofotofoga ,", "and their troubles,"], ["ma o latou faalavelave, ma o latou puapuaga,", "and their afflictions,"], ["ma o le a sii ae i latou i luga i le aso gataaga.", "and shall be lifted up at the last day."]]},
  {num:4,words:[["Ma ou te le manao ia e manatu ua ou iloa e au lava ia—e le mai la le tino ae mai la le agaga,", "And I would not that ye think that I know of myself—not of the temporal but of the spiritual,"], ["e le mai le mafaufau faaletino ae mai i le Atua.", "not of the carnal mind but of God."]]},
  {num:5,words:[["O lenei,", "Now,"], ["faauta,", "behold,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["a na le fanauina au i la le Atua,", "if I had not been born of God I should not have known these things;"], ["po ua ou le iloa nei mea;", "but God has,"], ["ae o le Atua na ia faailoa mai ia te au nei mea,", "by the mouth of his holy angel,"], ["e ala i le fofoga o lana agelu paia,", "made these things known unto me,"], ["ae le o so'u lava agavaa ;", "not of any worthiness of myself."]]},
  {num:6,words:[["Ona sa ou fealuai solo faatasi ma atalii o Mosaea,", "For I went about with the sons of Mosiah,"], ["e saili e faaumatia le ekalesia a le Atua;", "seeking to destroy the church of God;"], ["ae faauta,", "but behold,"], ["sa auina mai e le Atua lana agelu paia e taofi i matou i le ala.", "God sent his holy angel to stop us by the way."]]},
  {num:7,words:[["Ma faauta,", "And behold,"], ["sa fetalai mai o ia ia te i matou,", "he spake unto us,"], ["e peiseai o le leo o le faititili,", "as it were the voice of thunder,"], ["ma sa gatete ai le laueleele atoa i lalo ifo o o matou vae;", "and the whole earth did tremble beneath our feet;"], ["ma sa matou pauu uma i le eleele,", "and we all fell to the earth,"], ["ona sa oo mai i o matou luga le matau i le Alii.", "for the fear of the Lord came upon us."]]},
  {num:8,words:[["Ae faauta,", "But behold,"], ["sa fetalai mai le siufofoga ia te au:", "the voice said unto me:"], ["Tulai ia. Ma sa ou tu a'e ma tu i luga,", "Arise. And I arose and stood up,"], ["ma vaai atu i le agelu.", "and beheld the angel."]]},
  {num:9,words:[["Ma sa fetalai mai o ia ia te au:", "And he said unto me:"], ["Afai ua e manao ia faaumatia oe lava ia,", "If thou wilt of thyself be destroyed,"], ["aua e te toe saili e faaumatia le ekalesia a le Atua.", "seek no more to destroy the church of God."]]},
  {num:10,words:[["Ma sa oo ina ou pau i le eleele;", "And it came to pass that I fell to the earth;"], ["ma sa ou le mafai ona tatala lou gutu i le va o aso e tolu ma po e tolu,", "and it was for the space of three days and three nights that I could not open my mouth,"], ["pe na mafai foi ona ou faaaoga ou lima ma ou vae.", "neither had I the use of my limbs."]]},
  {num:11,words:[["Ma sa fetalai mai e le agelu ia te au ni isi mea e tele,", "And the angel spake more things unto me,"], ["ia na lagona e ou uso,", "which were heard by my brethren,"], ["ae sa ou le lagonaina;", "but I did not hear them;"], ["aua ina ua ou faalogo atu i nei upu—Afai ua e manao ia faaumatiaina oe lava ia,", "for when I heard the words—If thou wilt be destroyed of thyself,"], ["aua e te toe saili e faaumatia le ekalesia a le Atua—sa ou taia i le matau tele lava ma le ofo ne'i faaumatia au,", "seek no more to destroy the church of God—I was struck with such great fear and amazement lest perhaps I should be destroyed,"], ["sa ou pau ai i le eleele ma sa ou le toe lagona se mea.", "that I fell to the earth and I did hear no more."]]},
  {num:12,words:[["Ae sa falo tigaina au i le mafatia faavavau, ona sa laga atuatuvale lo'u agaga i le tulaga silisili atu ona tele,", "But I was racked with eternal torment,"], ["ma falo tigaina i au agasala uma.", "for my soul was harrowed up to the greatest degree and racked with all my sins."]]},
  {num:13,words:[["Ioe,", "Yea,"], ["sa ou manatua au agasala ma amioletonu uma,", "I did remember all my sins and iniquities,"], ["ia sa ou mafatia ai i tiga o seoli;", "for which I was tormented with the pains of hell;"], ["ioe,", "yea,"], ["sa ou vaai ua ou fouvale faasaga i lo'u Atua,", "I saw that I had rebelled against my God,"], ["ma sa ou le tausia ana poloaiga paia.", "and that I had not kept his holy commandments."]]},
  {num:14,words:[["Ioe,", "Yea,"], ["ma sa ou fasiotia le toatele o ana fanau,", "and I had murdered many of his children,"], ["pe sa ou taitai ese atu i latou i le faafanoga; ioe,", "or rather led them away unto destruction;"], ["ma i se aotelega,", "yea,"], ["sa matua tele lava au amioletonu,", "and in fine so great had been my iniquities,"], ["o le mafaufau ifo i lou alu atu i luma o lou Atua sa matua falo tigaina ai lo'u agaga i le matau tele e le mafaamatalaina.", "that the very thought of coming into the presence of my God did rack my soul with inexpressible horror."]]},
  {num:15,words:[["Sa ou mafaufau ifo,", "Oh,"], ["e,", "thought I,"], ["pe a na mafai ona faaaunuua o au ma tinei i le agaga ma le tino,", "that I could be banished and become extinct both soul and body,"], ["ina ia le aumaia ai au e tu i luma o lo'u Atua,", "that I might not be brought to stand in the presence of my God,"], ["e faamasinoina i au galuega .", "to be judged of my deeds."]]},
  {num:16,words:[["Ma o lenei,", "And now,"], ["mo le tolu ao ma le tolu po sa falo tigaina ai au,", "for three days and for three nights was I racked,"], ["i tiga o se agaga lava ua faasalaina .", "even with the pains of a damned soul."]]},
  {num:17,words:[["Ma sa oo ina a'o faapea ona falo tigaina o au i le mafatia,", "And it came to pass that as I was thus racked with torment,"], ["a'o lagā au i le atuatuvale i le manatuaina o au agasala e tele,", "while I was harrowed up by the memory of my many sins,"], ["faauta,", "behold,"], ["sa ou manatuaina foi lo'u faalogo i lo'u tamā o vavalo atu i tagata e uiga i le afio mai o se tasi o Iesu Keriso,", "I remembered also to have heard my father prophesy unto the people concerning the coming of one Jesus Christ,"], ["o se Atalii o le Atua,", "a Son of God,"], ["e togiola mo agasala a le lalolagi.", "to atone for the sins of the world."]]},
  {num:18,words:[["O lenei,", "Now,"], ["ina ua tau ane lou mafaufau i lenei manatu,", "as my mind caught hold upon this thought,"], ["sa ou tagi ifo i totonu o lo'u loto:", "I cried within my heart:"], ["E,", "O Jesus,"], ["Iesu e, oe le Alo o le Atua,", "thou Son of God,"], ["ia e alofa mutimutivale mai ia te au,", "have mercy on me,"], ["o se ua i ai i le au oona,", "who am in the gall of bitterness,"], ["ma ua siomia faataamilo e filifili tumau-faavavau o le oti.", "and am encircled about by the everlasting chains of death."]]},
  {num:19,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["ina ua ou mafaufauina lenei mea,", "when I thought this,"], ["sa ou le toe manatuaina o'u tiga;", "I could remember my pains no more;"], ["ioe,", "yea,"], ["sa ou le toe lagā atuatuvaleina au i le manatuaina o au agasala.", "I was harrowed up by the memory of my sins no more."]]},
  {num:20,words:[["Ma 'oi,", "And oh,"], ["le olioli e,", "what joy,"], ["ma le malamalama ofoofogia tele na ou vaaia;", "and what marvelous light I did behold;"], ["ioe,", "yea,"], ["sa faatumulia lo'u agaga i le olioli sa sili atu ona tele e pei o lo'u tiga!", "my soul was filled with joy as exceeding as was my pain!"]]},
  {num:21,words:[["Ioe,", "Yea,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["lo'u atalii e,", "my son,"], ["e leai se mea e faapea ona silisili ona 'malosi ma faapea ona silisili le oona e pei o ou tiga. Ioe,", "that there could be nothing so exquisite and so bitter as were my pains. Yea,"], ["ma ou te toe fai atu foi ia te oe,", "and again I say unto you,"], ["lo'u atalii e,", "my son,"], ["i le tasi itu,", "that on the other hand,"], ["e leai se mea e faapea ona silisili ona logolelei ma suamalie e pei o lo'u olioli.", "there can be nothing so exquisite and sweet as was my joy."]]},
  {num:22,words:[["Ioe,", "Yea,"], ["sa ou manatu sa ou vaai,", "methought I saw,"], ["e pei lava ona vaai lo tatou tamā o Liae ,", "even as our father Lehi saw,"], ["i le Atua,", "God sitting upon his throne,"], ["o afio i lona nofoalii, ua siosiomia e au agelu e le masino,", "surrounded with numberless concourses of angels,"], ["e peiseai o loo pepese ma vivii atu i lo latou Atua;", "in the attitude of singing and praising their God;"], ["ioe,", "yea,"], ["ma sa moomoo lo'u agaga i le fia i ai iina.", "and my soul did long to be there."]]},
  {num:23,words:[["Ae faauta,", "But behold,"], ["sa toe maua e ou lima ma ou vae lo latou malosi ,", "my limbs did receive their strength again,"], ["ma sa ou tu i luga i ou vae,", "and I stood upon my feet,"], ["ma faailoa atu i tagata ua fanauina au i la le Atua.", "and did manifest unto the people that I had been born of God."]]},
  {num:24,words:[["Ioe,", "Yea,"], ["ma mai i lena taimi e oo mai i le taimi nei,", "and from that time even until now,"], ["o ou galue e le taofia,", "I have labored without ceasing,"], ["ina ia mafai ona ou aumai o agaga i le salamo;", "that I might bring souls unto repentance;"], ["ina ia mafai ona ou aumai i latou e totofo i le olioli tele lea sa ou tofo i ai;", "that I might bring them to taste of the exceeding joy of which I did taste;"], ["ina ia mafai foi ona fanauina i latou i la le Atua,", "that they might also be born of God,"], ["ma faatumuina i le Agaga Paia.", "and be filled with the Holy Ghost."]]},
  {num:25,words:[["Ioe,", "Yea,"], ["ma o lenei faauta,", "and now behold,"], ["lo'u atalii e,", "O my son,"], ["ua tuuina mai e le Alii ia te au le olioli e silisili ona tele i le fua o au galuega;", "the Lord doth give me exceedingly great joy in the fruit of my labors;"]]},
  {num:26,words:[["Aua ona o le afioga lea na ia tuuina mai ia te au,", "For because of the word which he has imparted unto me,"], ["faauta,", "behold,"], ["e toatele ua fanauina i la le Atua,", "many have been born of God,"], ["ma totofo e pei ona ou tofo,", "and have tasted as I have tasted,"], ["ma vaai mata i le mata e pei ona ou vaai;", "and have seen eye to eye as I have seen;"], ["o lea ua latou iloa ai e uiga i nei mea sa ou tautala i ai,", "therefore they do know of these things of which I have spoken,"], ["e pei ona ou iloa;", "as I do know;"], ["ma o le malamalama ua ia te au ua mai i le Atua.", "and the knowledge which I have is of God."]]},
  {num:27,words:[["Ma sa lagolagoina au a'o ou i ai i lalo o tofotofoga ma faalavelave o ituaiga eseese uma,", "And I have been supported under trials and troubles of every kind,"], ["ioe,", "yea,"], ["ma puapuaga uiga eseese uma;", "and in all manner of afflictions;"], ["ioe,", "yea,"], ["sa laveaiina au e le Atua mai le falepuipui,", "God has delivered me from prison,"], ["ma mai i noanoaga,", "and from bonds,"], ["ma mai i le oti,", "and from death;"], ["ioe,", "yea,"], ["ma ou te tuu atu lo'u faalagolago ia te ia;", "and I do put my trust in him,"], ["ma o le a ia laveai mai pea ia te au.", "and he will still deliver me."]]},
  {num:28,words:[["Ma ua ou iloa o le a ia faatu mai au i luga i le aso gataaga,", "And I know that he will raise me up at the last day,"], ["e mau faatasi ma ia i le mamalu ;", "to dwell with him in glory;"], ["ioe,", "yea,"], ["ma o le a ou viia o ia e faavavau,", "and I will praise him forever,"], ["ona sa ia aumai o tatou tamā i fafo mai Aikupito,", "for he has brought our fathers out of Egypt,"], ["ma ia tofatumoanaina tagata Aikupito i le Sami Ulaula;", "and he has swallowed up the Egyptians in the Red Sea;"], ["ma sa ia taitai atu i latou i lona mana i le laueleele na folafolaina;", "and he led them by his power into the promised land;"], ["ioe,", "yea,"], ["ma sa ia laveaiina i latou i fafo mai le pologa ma le faatagataotauaina mai lea taimi i lea taimi.", "and he has delivered them out of bondage and captivity from time to time."]]},
  {num:29,words:[["Ioe,", "Yea,"], ["ma sa ia aumai foi o tatou tamā i fafo mai le laueleele o Ierusalema;", "and he has also brought our fathers out of the land of Jerusalem;"], ["ma sa ia laveaiina foi i latou,", "and he has also,"], ["e ala i lona mana tumau-faavavau,", "by his everlasting power,"], ["i fafo mai le pologa ma le faatagataotauaina,", "delivered them out of bondage and captivity,"], ["mai lea taimi i lea taimi, e oo mai lava i lalo i le aso nei;", "from time to time even down to the present day;"], ["ma ua ou taofi pea i le manatua i taimi uma lo latou faatagataotauaina;", "and I have always retained in remembrance their captivity;"], ["ioe,", "yea,"], ["ma e tatau foi ona e taofi i le manatua,", "and ye also ought to retain in remembrance,"], ["e pei ona sa ou faia,", "as I have done,"], ["lo latou faatagataotauaina.", "their captivity."]]},
  {num:30,words:[["Ae faauta,", "But behold,"], ["lo'u atalii e,", "my son,"], ["ua le ona pau lea;", "this is not all;"], ["ona e tatau ona e iloa e pei ona ou iloa, e faapea o le tulaga e oo i ai lau tausiga o poloaiga a le Atua o le a e manuia i le laueleele;", "for ye ought to know as I do know,"], ["ma e tatau foi ona e iloa,", "that inasmuch as ye shall keep the commandments of God ye shall prosper in the land;"], ["e faapea o le tulaga e oo i ai lau lē tausia o poloaiga a le Atua,", "and ye ought to know also,"], ["o le a vavae ese oe mai ona luma.", "that inasmuch as ye will not keep the commandments of God ye shall be cut off from his presence."], ["O lenei ua tusa lea ma lana afioga.", "Now this is according to his word."]]},
];
renderVerseSet(al_ch_36_Verses, 'al-ch36-verses');

var al_ch_37_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["lou atalii e, Helamana,", "my son Helaman,"], ["ou te poloai atu ia te oe ia e ave talafaamaumau ia na tuuina mai ia te au;", "I command you that ye take the records which have been entrusted with me;"]]},
  {num:2,words:[["Ma ou te poloai atu foi ia te oe,", "And I also command you that ye keep a record of this people,"], ["ia e tausia se talafaamaumau o lenei nuu,", "according as I have done,"], ["e pei ona sa ou faia, i luga o papatusi a Nifae,", "upon the plates of Nephi,"], ["ma tausi i le paia nei mea uma sa ou tausia,", "and keep all these things sacred which I have kept,"], ["e pei lava ona sa ou tausia ai i latou;", "even as I have kept them;"], ["ona ua mo se faamoemoega poto ua tausia ai.", "for it is for a wise purpose that they are kept."]]},
  {num:3,words:[["Ma o papatusi apamemea nei,", "And these plates of brass,"], ["ia ua i ai nei togitogiga,", "which contain these engravings,"], ["ia ua i ai talafaamaumau o tusitusiga paia i o latou luga,", "which have the records of the holy scriptures upon them,"], ["ia ua i ai le gafa o o tatou tamā,", "which have the genealogy of our forefathers,"], ["mai lava i le amataga—", "even from the beginning—"]]},
  {num:4,words:[["Faauta,", "Behold,"], ["na valoia e o tatou tamā,", "it has been prophesied by our fathers,"], ["e faapea o le a tausia i latou ma tuulima faasolo i lalo mai le tasi tupulaga i le isi,", "that they should be kept and handed down from one generation to another,"], ["ma tausia ma faasaosaoina e le aao o le Alii seia oo ina o atu i atunuu,", "and be kept and preserved by the hand of the Lord until they should go forth unto every nation, kindred,"], ["ma ituaiga,", "tongue,"], ["ma gagana ma nuu uma,", "and people,"], ["ina ia latou iloa mealilo o i ai i luga.", "that they shall know of the mysteries contained thereon."]]},
  {num:5,words:[["Ma o lenei faauta,", "And now behold,"], ["afai e tausia i latou o le a tumau pea lo latou pupula;", "if they are kept they must retain their brightness;"], ["ioe,", "yea,"], ["ma o le a tumau pea lo latou pupula;", "and they will retain their brightness;"], ["ioe,", "yea,"], ["ma o le a faapea foi papatusi uma ia ua i ai tusitusiga ua paia.", "and also shall all the plates which do contain that which is holy writ."]]},
  {num:6,words:[["O lenei atonu e te manatu ua ou valea i lenei mea;", "Now ye may suppose that this is foolishness in me;"], ["ae faauta ou te fai atu ia te oe,", "but behold I say unto you,"], ["o mea laiti ma faatauvaa e faataunuu ai mea tetele; ma o auala laiti i le tele o taimi,", "that by small and simple things are great things brought to pass;"], ["e faamaasiasia ai e popoto.", "and small means in many instances doth confound the wise."]]},
  {num:7,words:[["Ma e galue le Alii le Atua i auala e faataunuu ai ona faamoemoega tetele ma faavavau; ma o auala laiti lava e faamaasiasi ai e le Alii e popoto,", "And the Lord God doth work by means to bring about his great and eternal purposes;"], ["ma aumai ai le olataga o agaga e toatele.", "and by very small means the Lord doth confound the wise and bringeth about the salvation of many souls."]]},
  {num:8,words:[["Ma o lenei,", "And now,"], ["e oo mai i le taimi nei,", "it has hitherto been wisdom in God that these things should be preserved;"], ["o le poto o loo i le Atua ua faasaosaoina ai nei mea;", "for behold,"], ["aua faauta, ua latou faalauteleina le manatu o lenei nuu,", "they have enlarged the memory of this people,"], ["ioe,", "yea,"], ["ma faatalitonu le toatele i le sese o o latou ala,", "and convinced many of the error of their ways,"], ["ma aumai i latou i le malamalama o lo latou Atua mo le olataga o o latou agaga.", "and brought them to the knowledge of their God unto the salvation of their souls."]]},
  {num:9,words:[["Ioe,", "Yea,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["a na leai nei mea ua i ai i nei talafaamaumau,", "were it not for these things that these records do contain,"], ["ia ua i ai i nei papatusi,", "which are on these plates,"], ["po ua le mafai e Amona ma ona uso ona faatalitonu le tele tele o afe o sa Lamanā, i le sese o uputuu a o latou tamā;", "Ammon and his brethren could not have convinced so many thousands of the Lamanites of the incorrect tradition of their fathers;"], ["ioe,", "yea,"], ["o nei talafaamaumau ma a latou upu na aumai ai i latou i le salamo;", "these records and their words brought them unto repentance;"], ["o lona uiga,", "that is,"], ["sa latou aumai i latou i le malamalama o le Alii lo latou Atua,", "they brought them to the knowledge of the Lord their God,"], ["ma ia olioli ia Iesu Keriso lo latou Togiola.", "and to rejoice in Jesus Christ their Redeemer."]]},
  {num:10,words:[["Ma o ai na te iloa ae le avea i latou ma auala e aumai ai le tele o afe o i latou,", "And who knoweth but what they will be the means of bringing many thousands of them,"], ["ioe,", "yea,"], ["ma le tele foi o afe o o tatou uso ua maaa,", "and also many thousands of our stiffnecked brethren,"], ["o sa Nifaē,", "the Nephites,"], ["o e o loo faamaaa nei o latou loto i le agasala ma amioletonu,", "who are now hardening  their hearts in sin and iniquities,"], ["i le malamalama o lo latou Togiola?", "to the knowledge of their Redeemer?"]]},
  {num:11,words:[["O lenei o nei mea lilo e lei faailoa atoatoa mai ia ia te au i le taimi nei;", "Now these mysteries are not yet fully made known unto me;"], ["o lea o le a ou taofia ai.", "therefore I shall forbear."]]},
  {num:12,words:[["Ma atonu ua lava pe a nao na ou fai atu ua faasaosaoina i latou mo se faamoemoega poto,", "And it may suffice if I only say they are preserved for a wise purpose,"], ["o se faamoemoega ua silafia e le Atua;", "which purpose is known unto God;"], ["ona ua fautua mai o ia ma le poto i luga o ana galuega uma,", "for he doth counsel in wisdom over all his works,"], ["ma ua sasa'o ona ala,", "and his paths are straight,"], ["ma o lona ala o se taamilosaga faavavau e tasi.", "and his course is one eternal round."]]},
  {num:13,words:[["E, ia e manatua,", "O remember,"], ["ia e manatua,", "remember,"], ["lou atalii e,", "my son Helaman,"], ["Helamana, le saolele tele o poloaiga a le Atua.", "how strict are the commandments of God."], ["Ma ua fetalai mai o ia:", "And he said:"], ["Afai e te tausia au poloaiga o le a e manuia i le laueleele—ae afai e te le tausia ana poloaiga o le a vavae ese oe mai ona luma.", "If ye will keep my commandments ye shall prosper in the land—but if ye keep not his commandments ye shall be cut off from his presence."]]},
  {num:14,words:[["Ma o lenei ia e manatua,", "And now remember,"], ["lou atalii e,", "my son,"], ["ua tuuina mai nei mea e le Atua ia te oe,", "that God has entrusted you with these things,"], ["o ni mea ua paia ,", "which are sacred,"], ["ia sa ia tausia i le paia,", "which he has kept sacred,"], ["ma o ni mea foi o le a ia tausia ma faasaosaoina mo se faamoemoega poto ua ia te ia,", "and also which he will keep and preserve for a wise purpose in him,"], ["ina ia mafai ona ia faailoa atu lona mana i tupulaga o lumanai.", "that he may show forth his power unto future generations."]]},
  {num:15,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te tau atu ia te oe e ala i le agaga o valoaga,", "I tell you by the spirit of prophecy,"], ["afai e te solia poloaiga a le Atua,", "that if ye transgress the commandments of God,"], ["faauta,", "behold,"], ["o nei mea ua paia o le a aveese mai ia te oe e le mana o le Atua,", "these things which are sacred shall be taken away from you by the power of God,"], ["ma o le a tuu atu oe ia Satani,", "and ye shall be delivered up unto Satan,"], ["ina ia mafai ona ia luluina oe e pei o le aputi o saito i luma o le matagi.", "that he may sift you as chaff before the wind."]]},
  {num:16,words:[["Ae afai e te tausia poloaiga a le Atua,", "But if ye keep the commandments of God,"], ["ma e faia i nei mea ua paia e tusa ma mea e poloaiina ai oe e le Atua,", "and do with these things which are sacred according to that which the Lord doth command you,"], ["(ona e ao ona e aioi atu i le Alii mo mea uma i soo se mea e ao ona e faia ia i latou) faauta,", "(for you must appeal unto the Lord for all things whatsoever ye must do with them) behold,"], ["e leai se mana o le lalolagi po o seoli e mafai ona aveesea i latou mai ia te oe,", "no power of earth or hell can take them from you,"], ["ona ua mamana le Atua e faataunuu ana afioga uma.", "for God is powerful to the fulfilling of all his words."]]},
  {num:17,words:[["Ona o le a ia faataunuuina ana folafolaga uma ia o le a ia faia ia te oe,", "For he will fulfil all his promises which he shall make unto you,"], ["ona ua ia faataunuuina ana folafolaga ia na ia faia i o tatou tamā.", "for he has fulfilled his promises which he has made unto our fathers."]]},
  {num:18,words:[["Aua sa folafola mai o ia ia te i latou o le a ia faasaosaoina nei mea mo se faamoemoega poto o ia te ia,", "For he promised unto them that he would preserve these things for a wise purpose in him,"], ["ina ia mafai ona ia faaali atu lona mana i tupulaga o lumanai.", "that he might show forth his power unto future generations."]]},
  {num:19,words:[["Ma o lenei faauta,", "And now behold,"], ["ua ia faataunuuina se tasi faamoemoega,", "one purpose hath he fulfilled,"], ["o le toefuataiga lava lea o le tele o afe o sa Lamanā i le malamalama o le upumoni;", "even to the restoration of many thousands of the Lamanites to the knowledge of the truth;"], ["ma ua ia faaali mai lona mana e ala mai ia i latou,", "and he hath shown forth his power in them,"], ["ma o le a ia faaali atu foi lona mana e ala atu ia i latou i tupulaga o lumanai,", "and he will also still show forth his power in them unto future generations;"], ["o lea o le a faasaosaoina ai i latou.", "therefore they shall be preserved."]]},
  {num:20,words:[["O lea ou te poloai atu ai ia te oe,", "Therefore I command you,"], ["lou atalii e,", "my son Helaman,"], ["Helamana, ia e filiga e faataunuu au upu uma,", "that ye be diligent in fulfilling all my words,"], ["ma ia e filiga i le tausiga o poloaiga a le Atua e pei ona tusia i latou.", "and that ye be diligent in keeping the commandments of God as they are written."]]},
  {num:21,words:[["Ma o lenei,", "And now,"], ["o le a ou tautala atu ia te oe e uiga i papatusi na e lua sefulu fa,", "I will speak unto you concerning those twenty– four plates,"], ["ina ia e tausia,", "that ye keep them,"], ["ina ia mafai ona faailoa atu o mealilo ma galuega o le pouliuli,", "that the mysteries and the works of darkness,"], ["ma a latou galuega lilo,", "and their secret works,"], ["po o galuega lilo a ia tagata o e ua faaumatiaina,", "or the secret works of  those people who have been destroyed,"], ["i lenei nuu;", "may be made manifest unto this people; yea,"], ["ioe,", "all their murders,"], ["ina ia mafai ona faailoa atu i lenei nuu a latou fasiotiga tagata uma,", "and robbings,"], ["ma faomeaga,", "and their plunderings,"], ["ma a latou vetega,", "and all their wickedness and abominations,"], ["ma a latou amioleaga uma ma mea inosia;", "may be made manifest unto this people;"], ["ioe,", "yea,"], ["ma ia e faasaoina nei faamatalaupu .", "and that ye preserve these interpreters."]]},
  {num:22,words:[["Aua faauta,", "For behold,"], ["sa silasila le Alii ua amata ona galulue ona tagata i le pouliuli,", "the Lord saw that his people began to work in darkness,"], ["ioe,", "yea,"], ["ua latou faia faalilolilo le fasioti tagata ma mea inosia;", "work secret murders and abominations;"], ["o lea na fetalai mai ai le Alii,", "therefore the Lord said,"], ["afai latou te le salamo o le a faaumatia ese i latou mai luga o le lalolagi.", "if they did not repent they should be destroyed from off the face of the earth."]]},
  {num:23,words:[["Ma sa fetalai mai le Alii:", "And the Lord said:"], ["O le a ou saunia mo lau auauna o Kaselema,", "I will prepare unto my servant Gazelem,"], ["se maa ,", "a stone,"], ["lea o le a susulu atu mai le pouliuli i le malamalama,", "which shall shine forth in darkness unto light,"], ["ina ia mafai ona ou faailoa atu i ou tagata, o e e auauna mai ia te au,", "that I may discover unto my people who serve me,"], ["ina ia mafai ona ou faailoa atu ia te i latou galuega a o latou uso,", "that I may discover unto them the works of their brethren,"], ["ioe,", "yea,"], ["a latou galuega lilo,", "their secret works,"], ["a latou galuega o le pouliuli,", "their works of darkness,"], ["ma a latou amioleaga ma mea inosia.", "and their wickedness and abominations."]]},
  {num:24,words:[["Ma o lenei,", "And now,"], ["lou atalii e,", "my son,"], ["o nei faamatalaupu na saunia ina ia mafai ona faataunuuina o le afioga a le Atua,", "these interpreters were prepared that the word of God might be fulfilled,"], ["na ia fetalai mai ai,", "which he spake,"], ["fai mai:", "saying:"]]},
  {num:25,words:[["O le a ou aumai i fafo o le pouliuli i le malamalama a latou galuega lilo uma ma a latou mea inosia;", "I will bring forth out of darkness unto light all their secret works and their abominations;"], ["ma vagana ai ua latou salamo,", "and except they repent I will destroy them from off the face of the earth;"], ["o le a ou faaumatia ese i latou mai luga o le lalolagi; ma o le a ou aumai i le malamalama a latou mealilo uma ma mea inosia,", "and I will bring to light all their secrets and abominations,"], ["i atunuu uma o le a fai mo i latou lenei laueleele pe a mavae atu le taimi nei.", "unto every nation that shall hereafter possess the land."]]},
  {num:26,words:[["Ma o lenei,", "And now,"], ["lou atalii e,", "my son,"], ["ua tatou vaai sa latou le salamo;", "we see that they did not repent;"], ["o lea na faaumatia ai i latou;", "therefore they have been destroyed,"], ["ma ua faapea ona faataunuu ai o le afioga a le Atua;", "and thus far the word of God has been fulfilled;"], ["ioe,", "yea,"], ["o a latou mea inosia faalilolilo ua aumai i fafo o le pouliuli ma ua faailoa mai ia te i tatou.", "their secret abominations have been brought out of darkness and made known unto us."]]},
  {num:27,words:[["Ma o lenei,", "And now,"], ["lou atalii e,", "my son,"], ["ou te poloai atu ia te oe,", "I command you that ye retain all their oaths,"], ["ia e taofi a latou tautoga uma,", "and their covenants,"], ["ma a latou feagaiga, ma a latou maliega ia latou mea inosia faalilolilo;", "and their agreements in their secret abominations;"], ["ioe,", "yea,"], ["ma o a latou faailoga uma ma a latou mea e ofo ai ia e taofia mai lenei nuu,", "and all their signs and their wonders ye shall keep from this people,"], ["ina ia latou le iloaina i latou,", "that they know them not,"], ["nei o latou pauu atu foi i le pouliuli ma faaumatia ai.", "lest peradventure they should fall into darkness also and be destroyed."]]},
  {num:28,words:[["Aua faauta,", "For behold,"], ["e i ai se fetuu ua i luga o lenei laueleele atoa,", "there is a curse upon all this land,"], ["e faapea o le a oo mai, e tusa ma le mana o le Atua,", "that destruction shall come upon all those workers of darkness,"], ["le faafanoga i luga o i latou uma o e e faia galuega o le pouliuli,", "according to the power of God,"], ["pe a oo ina latou matua atoatoa;", "when they are fully ripe;"], ["o lea ou te manao ia le faaumatiaina lenei nuu.", "therefore I desire that this people might not be destroyed."]]},
  {num:29,words:[["O lea ia e taofia ai nei fuafuaga faalilolilo o a latou tautoga ma a latou feagaiga, mai lenei nuu,", "Therefore ye shall keep these secret plans of their oaths and their covenants from this people,"], ["ma ia nao a latou amioleaga ma a latou fasiotiga tagata ma a latou mea inosia, ia e faailoa atu ia te i latou;", "and only their wickedness and their murders and their abominations shall ye make known unto them;"], ["ma ia e aoaoina i latou ia latou inosia amioleaga ma mea inosia ma fasiotiga tagata faapea;", "and ye shall teach them to abhor such wickedness and abominations and murders;"], ["ma ia e aoao atu foi ia te i latou, ua faaumatiaina nei tagata ona o a latou amioleaga ma mea inosia ma a latou fasiotiga tagata.", "and ye shall also teach them that these people were destroyed on account of their wickedness and abominations and their murders."]]},
  {num:30,words:[["Aua faauta,", "For behold,"], ["sa latou fasiotia perofeta uma a le Alii o e na o mai i a i latou e tau atu ia te i latou e uiga ia latou amioletonu;", "they murdered all the prophets of the Lord who came among them to declare unto them concerning their iniquities;"], ["ma o toto o e na latou fasiotia sa tagi ae i le Alii lo latou Atua mo le taui ma sui i luga o i latou o e na fasiotia i latou;", "and the blood of those whom they murdered did cry unto the Lord their God for vengeance upon those who were their murderers;"], ["ma sa faapea ona oo mai ai o faamasinoga a le Atua i luga o ia tagata o e fai galuega o le pouliuli ma faapotopotoga faalilolilo.", "and thus the judgments of  God did come upon these workers of darkness and secret combinations."]]},
  {num:31,words:[["Ioe,", "Yea,"], ["ma ia fetuuina lava e faavavau faavavau lava le laueleele ia te i latou o e faia galuega o le pouliuli ma faapotopotoga faalilolilo,", "and cursed be the land forever and ever unto those workers of darkness and secret combinations,"], ["e oo lava i le faaumatiaina,", "even unto destruction,"], ["vagana ai ua latou salamo ae lei oo ina latou matua atoatoa.", "except they repent before they are fully ripe."]]},
  {num:32,words:[["Ma o lenei,", "And now,"], ["lou atalii e,", "my son,"], ["ia e manatua upu ua ou tautala atu ai ia te oe;", "remember the words which I have spoken unto you;"], ["aua nei e faatuatuaina atu ia fuafuaga faalilolilo i lenei nuu,", "trust not those secret plans unto this people,"], ["a ia e aoao atu ia te i latou se inoino e faavavau e faasaga i le agasala ma le amioletonu.", "but teach them an everlasting hatred against sin and iniquity."]]},
  {num:33,words:[["Talai atu ia te i latou le salamo,", "Preach unto them repentance,"], ["ma le faatuatua i le Alii o Iesu Keriso;", "and faith on the Lord Jesus Christ;"], ["aoao atu ia te i latou ia latou faalotomaualalalo i latou lava ma ia agamalu ma ia maualalalo i le loto;", "teach them to humble themselves and to be meek and lowly in heart;"], ["aoao atu ia te i latou ia tetee atu i faaosoosoga uma a le tiapolo,", "teach them to withstand every temptation of the devil,"], ["faatasi ma lo latou faatuatua i le Alii o Iesu Keriso.", "with their faith on the Lord Jesus Christ."]]},
  {num:34,words:[["Aoao atu ia te i latou ia aua nei faavaivai i le faia o galuega lelei,", "Teach them to never be weary of good works,"], ["ae ia agamalu ma ia maualalalo i le loto;", "but to be meek and lowly in heart;"], ["aua o e faapea o le a latou maua le malologa mo o latou agaga.", "for such shall find rest to their souls."]]},
  {num:35,words:[["E,", "O,"], ["ia e manatua,", "remember,"], ["lou atalii e,", "my son,"], ["ma aoao le poto i lou talavou;", "and learn wisdom in thy youth;"], ["ioe,", "yea,"], ["aoao i lou talavou e tausi i poloaiga a le Atua.", "learn in thy youth to keep the commandments of God."]]},
  {num:36,words:[["Ioe,", "Yea,"], ["ma tagi atu i le Atua mo lou tausiga atoa;", "and cry unto God for all thy support;"], ["ioe,", "yea,"], ["tuu atu i le Alii au mea uma e fai,", "let all thy doings be unto the Lord,"], ["ma soo se mea e te alu i ai ia tuu atu i le Alii;", "and whithersoever thou goest let it be in the Lord;"], ["ioe,", "yea,"], ["ia tuu atu ou manatu uma i le Alii;", "let all thy thoughts be directed unto the Lord;"], ["ioe,", "yea,"], ["ia tuu atu alofaaga o lou loto i le Alii e faavavau.", "let the affections of thy heart be placed upon the Lord forever."]]},
  {num:37,words:[["Filifili faatasi ma le Alii i au mea uma e fai,", "Counsel with the Lord in all thy doings,"], ["ma o le a ia taitai oe mo le lelei;", "and he will direct thee for good;"], ["ioe, pe a e taoto i lalo i le po,", "yea,"], ["taoto i lalo i le Alii,", "when thou liest down at night lie down unto the Lord,"], ["ina ia mafai ona leoleo mai o ia i ou luga a'o e moe;", "that he may watch over you in your sleep;"], ["ma a e ala mai i le taeao, ia tuu lou loto ia tumu i le faafetai i le Atua;", "and when thou risest in the morning let thy heart be full of thanks unto God;"], ["ma afai e te faia nei mea,", "and if ye do these things,"], ["o le a sii ae oe i luga i le aso gataaga.", "ye shall be lifted up at the last day."]]},
  {num:38,words:[["Ma o lenei,", "And now,"], ["lou atalii e,", "my son,"], ["ua ia te au ni upu teisi ou te fai atu ai e uiga i le mea lea ua taua e o tatou tamā o se polo,", "I have somewhat to say concerning the thing which our fathers call a ball,"], ["po o se faasinoala—pe sa taua e o tatou tamā o le Liahona ,", "or director—or our fathers called it Liahona,"], ["o lona uiga,", "which is,"], ["pe a faaliliuina,", "being interpreted,"], ["o se tapasa;", "a com– pass;"], ["ma o le Alii na sauniaina.", "and the Lord prepared it."]]},
  {num:39,words:[["Ma faauta,", "And behold,"], ["e le mafai e se tagata ona faia se mea e faapea le uiga ese o le gaosiga. Ma faauta,", "there cannot any man work after the manner of so curious a workmanship. And behold,"], ["sa saunia e faaali mai ai i o tatou tamā le ala e tatau ona latou malaga ai i le vao.", "it was prepared to show unto our fathers the course which they should travel in the wilderness."]]},
  {num:40,words:[["Ma sa galue mo i latou e tusa ma lo latou faatuatua i le Atua;", "And it did work for them according to their faith in God;"], ["o lea,", "therefore,"], ["afai sa ia te i latou le faatuatua e talitonu ai e mafai e le Atua ona faia ia tusi mai e ona vae le ala e tatau ona latou ui ai,", "if they had faith to believe that God could cause that those spindles should point the way they should go,"], ["faauta,", "behold,"], ["sa faia lava;", "it was done;"], ["o lea sa ia te i latou lenei vavega,", "therefore they had this miracle,"], ["ma le tele foi o isi vavega na faia i le mana o le Atua,", "and also many other miracles wrought by the power of God,"], ["i lea aso ma lea aso.", "day by day."]]},
  {num:41,words:[["E ui i lea,", "Nevertheless,"], ["e ui ina sa faia ia vavega i ala faatauvaa sa faaalia ai ia te i latou galuega ofoofogia.", "because those miracles were worked by small means it did show unto them marvelous works."], ["Ae ina ua oo ina latou faapaie,", "They were slothful,"], ["ma galo ona faaaoga lo latou faatuatua ma le filiga, sa oo ina taofia ia galuega ofoofogia,", "and forgot to exercise their faith and diligence and then those marvelous works ceased,"], ["ma latou le alualu i luma i la latou malaga;", "and they did not progress in their journey;"]]},
  {num:42,words:[["O lea,", "Therefore,"], ["na latou nonofo ai i le vao,", "they tarried in the wilderness,"], ["pe na le malaga ai i se ala sa'o,", "or did not travel a direct course,"], ["ma puapuagatia ai i le fia aai ma le fia feinu,", "and were afflicted with hunger and thirst,"], ["ona o a latou solitulafono.", "because of their transgressions."]]},
  {num:43,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["ou te manao ia e malamalama, ua le aunoa nei mea ma so latou faataataga;", "I would that ye should understand that these things are not without a shadow;"], ["ona e pei ona sa faapaie o tatou tamā e uai atu i lenei tapasa (o lenei o nei mea ua faaletino) sa latou le manuia;", "for as our fathers were slothful to give heed to this compass (now these things were temporal) they did not prosper;"], ["ua faapea lava foi i mea faaleagaga.", "even so it is with things which are spiritual."]]},
  {num:44,words:[["Aua faauta,", "For behold,"], ["e tusa le faigofie o le uai atu i le afioga a Keriso,", "it is as easy to give heed to the word of Christ,"], ["lea o le a faasino mai ai ia te oe se ala sa'o e tau atu i le olioli faavavau,", "which will point to you a straight course to eternal bliss,"], ["e pei o le faigofie i o tatou tamā ona uai atu i lenei tapasa,", "as it was for our fathers to give heed to this compass,"], ["lea sa faasino mai ai ia te i latou se ala sa'o e tau atu i le laueleele na folafolaina.", "which would point unto them a straight course to the promised land."]]},
  {num:45,words:[["Ma o lenei ou te fai atu,", "And now I say,"], ["ua leai ea se faatusa i lenei mea? Ona e pei ona mautinoa le aumai e lenei faasinoala o o tatou tamā,", "is there not a type in this thing? For just as surely as this director did bring our fathers,"], ["i le mulimuli i ona ala,", "by following its course,"], ["i le laueleele na folafolaina, o le a faapea foi ona ave o i tatou e afioga a Keriso,", "to the promised land,"], ["pe afai tatou te mulimuli i lo latou ala,", "shall the words of Christ,"], ["i tala atu o lenei vanu o le faanoanoa,", "if we follow their course,"], ["i se laueleele o le folafolaga ua silisili atu ona lelei.", "carry us beyond this vale of sorrow into a far better land of promise."]]},
  {num:46,words:[["E,", "O my son,"], ["lou atalii e,", "do not let us be slothful because of the easiness of the way;"], ["ia aua nei o tatou faapaie ona o le faigofie o le ala ; ona sa faapea ona i ai i o tatou tamā;", "for so was it with our fathers;"], ["ona sa faapea ona saunia mo i latou,", "for so was it prepared for them,"], ["ina ia mafai ona latou ola pe afai latou te tepa atu i ai;", "that if they would look they might live;"], ["ua faapea foi ona i ai ia i tatou.", "even so it is with us."], ["Ua uma ona saunia o le ala,", "The way is prepared,"], ["ma afai tatou te tepa atu e mafai ona tatou ola e faavavau.", "and if we will look we may live forever."]]},
  {num:47,words:[["Ma o lenei,", "And now,"], ["lou atalii e,", "my son,"], ["vaai ia e tausia nei mea paia,", "see that ye take care of these sacred things,"], ["ioe,", "yea,"], ["vaai ia e tepa atu i le Atua ma e ola ai. Alu atu i lenei nuu ma tau atu le afioga,", "see that ye look to God and live. Go unto this people and declare the word,"], ["ma ia e faamamalu. Lou atalii e,", "and be sober. My son,"], ["tofa.", "farewell."]]},
];
renderVerseSet(al_ch_37_Verses, 'al-ch37-verses');

var al_ch_38_Verses = [
  {num:1,words:[["Lo'u atalii e,", "My son,"], ["uai mai ou taliga i au upu,", "give ear to my words,"], ["aua ou te fai atu ia te oe,", "for I say unto you,"], ["e pei ona ou fai atu ia Helamana,", "even as I said unto Helaman,"], ["o le tulaga e oo i ai lau tausiga o poloaiga a le Atua o le a e manuia i le laueleele;", "that inasmuch as ye shall keep the commandments of God ye shall prosper in the land;"], ["ma o le tulaga e oo i ai lau lē tausia o poloaiga a le Atua o le a vavae ese oe mai ona luma.", "and inasmuch as ye will not keep the commandments of God ye shall be cut off from his presence."]]},
  {num:2,words:[["Ma o lenei,", "And now,"], ["lou atalii e,", "my son,"], ["ou te faalagolago o le a ou maua le olioli tele ia te oe,", "I trust that I shall have great joy in you,"], ["ona o lou maumaututu ma lou faamaoni i le Atua;", "because of your steadiness and your faithfulness unto God;"], ["aua e pei ona e amata mai i lou talavou ona e vaai atu i le Alii lou Atua,", "for as you have commenced in your youth to look to the Lord your God,"], ["ua faapea lava ona ou faamoemoe o le a aveaveai pea ona e tausia o ana poloaiga;", "even so I hope that you will continue in keeping his commandments;"], ["aua e amuia lava o ia o le e tumau e oo i le iuga.", "for blessed is he that endureth to the end."]]},
  {num:3,words:[["Ou te fai atu ia te oe,", "I say unto you,"], ["lo'u atalii e,", "my son,"], ["ua uma ona ou maua o le olioli tele ia te oe,", "that I have had great joy in thee already,"], ["ona o lou faamaoni ma lou filiga,", "because of thy faithfulness and thy diligence,"], ["ma lou onosai ma lou tali-tiga i totonu o tagata sa Soramā.", "and thy patience and thy long– suffering among the people of the Zoramites."]]},
  {num:4,words:[["Ona ua ou iloa sa e i ai i noanoaga;", "For I know that thou wast in bonds;"], ["ioe,", "yea,"], ["ma ua ou iloa foi sa fetogi oe i maa ona o le afioga;", "and I also know that thou wast stoned for the word's sake;"], ["ma sa e talitalia nei mea uma ma le onosai ona sa faatasi le Alii ma oe;", "and thou didst bear all these things with patience because the Lord was with thee;"], ["ma o lenei ua e iloa o le Alii na laveaiina oe.", "and now thou knowest that the Lord did deliver thee."]]},
  {num:5,words:[["Ma o lenei,", "And now my son,"], ["lo'u atalii e, Sepulona,", "Shiblon,"], ["ou te manao ia e manatua,", "I would that ye should remember,"], ["afai e te tuu atu lou faalagolago i le Atua seia faapea ona tele,", "that as much as ye shall put your trust in God even so much ye shall be delivered out of your trials,"], ["o le a ia laveaiina oe i fafo mai ou tofotofoga,", "and your troubles,"], ["ma ou faalavelave , ma ou puapuaga,", "and your afflictions,"], ["ma o le a sii oe i luga i le aso gataaga.", "and ye shall be lifted up at the last day."]]},
  {num:6,words:[["O lenei,", "Now,"], ["lo'u atalii e,", "my son,"], ["ou te le manao ia e manatu e faapea ua ou iloa nei mea e au lava ia, ae o le Agaga o le Atua ua i totonu ia te au na ia faailoa mai ia nei mea ia te au;", "I would not that ye should think that I know these things of myself,"], ["a na le fanauina au i la le Atua,", "but it is the Spirit of God which is in me which maketh these things known unto me;"], ["po ua ou le iloaina nei mea.", "for if I had not been born of God I should not have known these things."]]},
  {num:7,words:[["Ae faauta,", "But behold,"], ["o le Alii i lona alofa mutimutivale tele na ia auina mai ai lana agelu e tau mai ia te au e ao ina ou tuu le galuega o le faafanoga i totonu o lona nuu;", "the Lord in his great mercy sent his angel to declare unto me that I must stop the work of destruction among his people;"], ["ioe,", "yea,"], ["ma sa ou vaai i se agelu faafesagai lava,", "and I have seen an angel face to face,"], ["ma sa ia fetalai mai ia te au,", "and he spake with me,"], ["ma o lona siufofoga sa pei o le faititili,", "and his voice was as thunder,"], ["ma sa lulu ai le eleele atoa.", "and it shook the whole earth."]]},
  {num:8,words:[["Ma sa oo ina ou i ai i ao e tolu ma po e tolu i se tiga oona ma le atuatuvale tele o le agaga;", "And it came to pass that I was three days and three nights in the most bitter pain and anguish of soul;"], ["ma sa ou le maua lava,", "and never,"], ["seia oo ina ou tagi atu i le Alii o Iesu Keriso mo le alofa mutimutivale,", "until I did cry out unto the Lord Jesus Christ for mercy,"], ["se faamagaloga o au agasala. Ae faauta,", "did I receive a remission of my sins. But behold,"], ["sa ou tagi atu lava ia te ia ma ou maua ai le filemu i lo'u agaga.", "I did cry unto him and I did find peace to my soul."]]},
  {num:9,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e, ua ou tau atu ia te oe lenei mea ina ia mafai ona e aoao le poto,", "my son,"], ["ina ia mafai ona e iloa mai ia te au,", "I have told you this that ye may learn wisdom,"], ["ua leai se isi lava ala po o ni auala e mafai ona faaolaina ai o le tagata, ua nao ia,", "that ye may learn of me that there is no other way or means whereby man can be saved,"], ["ma ala mai ia Keriso.", "only in and through Christ."], ["Faauta,", "Behold,"], ["o ia o le ola ma le malamalama o le lalolagi.", "he is the life and the light of the world."], ["Faauta,", "Behold,"], ["o ia o le afioga o le upumoni ma le amiotonu.", "he is the word of truth and righteous– ness."]]},
  {num:10,words:[["Ma o lenei,", "And now,"], ["ona ua amata ona e aoao atu o le afioga ua faapea lava ona ou manao ia e aoao atu pea;", "as ye have begun to teach the word even so I would that ye should continue to teach;"], ["ma ou te manao ia e filiga ma faautauta i mea uma.", "and I would that ye would be diligent and temperate in all things."]]},
  {num:11,words:[["Vaai ia aua ne'i faafefeteina oe i luga i le faamaualuga;", "See that ye are not lifted up unto pride;"], ["ioe,", "yea,"], ["vaai ia aua ne'i e mitamitavale i lou lava poto,", "see that ye do not boast in your own wisdom,"], ["po o lou malosi tele.", "nor of your much strength."]]},
  {num:12,words:[["Faaaoga le lotoa,", "Use boldness,"], ["ae le o le faafiamalosi;", "but not overbearance;"], ["ma vaai foi ia pulea ou tuinanau uma,", "and also see that ye bridle all your passions,"], ["ina ia mafai ona faatumuina oe i le alofa;", "that ye may be filled with love;"], ["vaai ia e aloese mai le faapaie.", "see that ye refrain from idleness."]]},
  {num:13,words:[["Aua e te tatalo e pei ona faia e sa Soramā,", "Do not pray as the Zoramites do,"], ["ona sa e vaai ua latou tatalo ina ia lagona mai e tagata,", "for ye have seen that they pray to be heard of men,"], ["ma ina ia viia i latou mo lo latou popoto.", "and to be praised for their wisdom."]]},
  {num:14,words:[["Aua e te fai atu:", "Do not say:"], ["Le Atua e,", "O God,"], ["ou te faafetai atu ia te oe ona ua sili atu lo matou lelei nai lo o matou uso;", "I thank thee that we are better than our brethren;"], ["ae ia fai atu:", "but rather say:"], ["Le Alii e,", "O Lord,"], ["faamagalo mai lo'u le agavaa,", "forgive my unworthiness,"], ["ma ia e manatua ou uso i le alofa mutimutivale—ioe,", "and remember my brethren in mercy yea,"], ["tautau atu lou le agavaa i luma o le Atua i taimi uma lava.", "acknowledge your unworthiness before God at all times."]]},
  {num:15,words:[["Ma ia alofa le Alii ia faamanuia mai i lou agaga,", "And may the Lord bless your soul,"], ["ma talia oe i le aso gataaga i lona malo,", "and receive you at the last day into his kingdom,"], ["e nofo i lalo i le filemu. O lenei alu ia,", "to sit down in peace. Now go,"], ["lo'u atalii e,", "my son,"], ["ma aoao atu le afioga i lenei nuu. Ia e faamamalu. Lo'u atalii e,", "and teach the word unto this people. Be sober. My son,"], ["tofa.", "farewell."]]},
];
renderVerseSet(al_ch_38_Verses, 'al-ch38-verses');

var al_ch_39_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["e i ai ni mea e tele atu ou te fia fai atu ai ia te oe nai lo mea na ou fai atu ai i lou uso;", "I have somewhat more to say unto thee than what I said unto thy brother;"], ["aua faauta,", "for behold,"], ["e te lei vaai ea i le maumaututu o lou uso,", "have ye not observed the steadiness  of thy brother,"], ["lona faamaoni,", "his faithfulness,"], ["ma lona filiga i le tausiga o poloaiga a le Atua? Faauta,", "and his diligence in keeping the commandments of God? Behold,"], ["sa ia lei faia ea mo oe se faataitaiga lelei?", "has he not set a good example for thee?"]]},
  {num:2,words:[["Ona sa e le uai tele mai i au upu e pei ona sa faia e lou uso,", "For thou didst not give so much heed unto my words as did thy brother,"], ["i totonu o tagata sa Soramā.", "among the people of the Zoramites."], ["O lenei, o le mea lenei ua ia te au e faasaga ia te oe;", "Now this is what I have against thee;"], ["sa e alu atu i le mitamitavale i lou malosi ma lou poto.", "thou didst go on unto boasting in thy strength and thy wisdom."]]},
  {num:3,words:[["Ma ua le ona pau lea,", "And this is not all,"], ["lo'u atalii e.", "my son."], ["Sa e faia se mea sa sili ona mamafa ia te au;", "Thou didst do that which was grievous unto me;"], ["ona sa e tuu le galuega,", "for thou didst forsake the ministry,"], ["ma e alu atu i le laueleele o Sairona e i totonu o tuaoi o sa Lamanā,", "and did go over into the land of Siron, among the borders of the Lamanites,"], ["i le fafine talitane o Isapela.", "after the harlot Isabel."]]},
  {num:4,words:[["Ioe,", "Yea,"], ["sa ia faatosina ese loto o le toatele;", "she did steal away the hearts of many;"], ["peitai, lo'u atalii e,", "but this was no excuse for thee,"], ["sa le o se 'alofaga tatau lea mo oe.", "my son."], ["Sa tatau ona e tausi i le galuega na faatuatuaina ai oe.", "Thou shouldst have tended to the ministry wherewith thou wast entrusted."]]},
  {num:5,words:[["Ua e le iloa ea,", "Know ye not,"], ["lo'u atalii e,", "my son,"], ["o nei mea o ni mea inosia i le silafaga a le Alii;", "that these things are an abomination in the sight of the Lord;"], ["ioe,", "yea,"], ["ua silisili ona inosia i lo o agasala uma vagana ai le faamasaaina o le toto le sala po o le faafitia o le Agaga Paia?", "most abominable above all sins save it be the shedding of innocent blood or denying the Holy Ghost?"]]},
  {num:6,words:[["Aua faauta,", "For behold,"], ["afai e te faafitia le Agaga Paia ina ua uma ona mau ia te oe,", "if ye deny the Holy Ghost when it once has had place in you,"], ["ma ua e iloa ua e faafitia o ia,", "and ye know that ye deny it,"], ["faauta,", "behold,"], ["o se agasala lenei e le mafaamagaloina ;", "this is a sin which is unpardonable;"], ["ioe,", "yea,"], ["ma o soo se tasi e fasioti tagata e faasaga i le malamalama ma le iloa o le Atua,", "and whosoever murdereth against the light and knowledge of God,"], ["e le faigofie ia te ia ona maua o le faamagaloga ;", "it is not easy for him to obtain forgiveness;"], ["ioe,", "yea,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["lo'u atalii e,", "my son,"], ["e le faigofie ia te ia ona maua o se faamagaloga.", "that it is not easy for him to obtain a forgiveness."]]},
  {num:7,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["ou te moomoo i le Atua ma'umau pe a na e le sala i se solitulafono tele faapea. Ou te le fia taua pea au solitulafono,", "I would to God that ye had not been guilty of so great a crime. I would not dwell upon your crimes,"], ["e laga ai i luga lou agaga,", "to harrow up your soul,"], ["pe a na ua le mo lou lelei.", "if it were not for your good."]]},
  {num:8,words:[["Ae faauta,", "But behold,"], ["e le mafai ona e natia au solitulafono mai le Atua; ma e vagana ai ua e salamo,", "ye cannot hide your crimes from God;"], ["o le a tutu o se molimau e faasaga ia te oe i le aso gataaga.", "and except ye repent they will stand as a testimony against you at the last day."]]},
  {num:9,words:[["O lenei,", "Now my son,"], ["lo'u atalii e, ou te manao ia e salamo ma lafoai au agasala,", "I would that ye should repent and forsake your sins,"], ["ma aua e te toe alu e tusa ma tuinanau o ou mata,", "and go no more after the lusts of your eyes,"], ["ae ia e faafiti oe lava i nei mea uma; ona e vagana ai ua e faia lenei mea,", "but cross yourself in all these things;"], ["e le mafai lava ona e mautofi i le malo o le Atua.", "for except ye do this ye can in nowise inherit the kingdom of God."], ["E,", "Oh,"], ["ia e manatua,", "remember,"], ["ma ia e ave i ou luga,", "and take it upon you,"], ["ma faafiti oe lava i nei mea.", "and cross yourself in these things."]]},
  {num:10,words:[["Ma ou te poloai atu ia te oe ia e ave i ou luga e filifili faatasi ma ou uso matutua i au mea e fai;", "And I command you to take it upon you to counsel with your elder brothers in your undertakings;"], ["aua faauta,", "for behold,"], ["o loo e i lou talavou,", "thou art in thy youth,"], ["ma ua e manaomia ona tausia oe e ou uso. Ma uai atu ia laua fautuaga.", "and ye stand in need to be nourished by your brothers. And give heed to their counsel."]]},
  {num:11,words:[["Aua e te tuu atu oe lava, ia taitai ese e soo se mea ua le aoga pe ua faavalevalea;", "Suffer not yourself to be led away by any vain or foolish thing;"], ["aua e te tuu atu i le tiapolo na te toe taitai ese atu lou loto i na fafine talitane amioleaga.", "suffer not the devil to lead away your heart again after those wicked harlots."], ["Faauta,", "Behold,"], ["lo'u atalii e,", "O my son,"], ["sa matua tele lava le amioletonu na e aumai i luga o sa Soramā; aua ina ua latou vaai i lau amio ,", "how great iniquity ye brought upon the Zoramites;"], ["sa latou le fia talitonu i a'u upu.", "for when they saw your conduct they would not believe in my words."]]},
  {num:12,words:[["Ma o lenei ua fetalai mai le Agaga o le Alii ia te au:", "And now the Spirit of the Lord doth say unto me:"], ["Ia faatonu lau fanau ia latou faia mea lelei,", "Command thy children to do good,"], ["ne'i o latou taitai ese atu loto o tagata e toatele i le faafanoga;", "lest they  lead away the hearts of many people to destruction;"], ["o lea ou te poloai atu ai ia te oe,", "therefore I command you,"], ["lo'u atalii e,", "my son,"], ["i le matau i le Atua,", "in the fear of God,"], ["ia e taofi mai au amioletonu;", "that ye refrain from your iniquities;"]]},
  {num:13,words:[["Ma ia e liliu atu i le Alii ma lou manatu atoa,", "That ye turn to the Lord with all your mind,"], ["mafaufau atoa,", "might,"], ["ma lou malosi atoa;", "and strength;"], ["ina ia leai ni isi tagata e te toe taitaia ese o latou loto e fai le amioleaga;", "that ye lead away the hearts of no more to do wickedly;"], ["ae ia e toe foi atu ia te i latou,", "but rather return unto them,"], ["ma tautino atu ou 'aleu ma lena sese na e faia.", "and acknowledge your faults and that wrong which ye have done."]]},
  {num:14,words:[["Aua e te saili i oa po o mea le aoga a lenei lalolagi;", "Seek not after riches nor the vain things of this world;"], ["aua faauta,", "for behold,"], ["e le mafai ona e avea i latou faatasi ma oe.", "you cannot carry them with you."]]},
  {num:15,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["ou te fia fai atu teisi ia te oe e uiga i le afio mai o Keriso. Faauta,", "I would say somewhat unto you concerning the coming of Christ. Behold,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["o ia lava lea ua mautinoa o le a afio mai e aveese agasala a le lalolagi;", "that it is he that surely shall come to take away the sins of the world;"], ["ioe,", "yea,"], ["e afio mai o ia e tau mai tala fiafia o le olataga i ona tagata.", "he cometh to declare glad tidings of salvation unto his people."]]},
  {num:16,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["o le galuega lenei na valaauina i ai oe, e tau atu nei tala fiafia i lenei nuu,", "this was the ministry unto which ye were called,"], ["e saunia ai o latou mafaufau;", "to declare these glad tidings unto this people to prepare their minds;"], ["pe ina ia mafai ona oo mai o le olataga ia te i latou,", "or rather that salvation might come unto them,"], ["ina ia mafai ona latou saunia mafaufau o a latou fanau ia faalogo i le afioga i le taimi o lona afio mai.", "that they may prepare the minds of their children to hear the word at the time of his coming."]]},
  {num:17,words:[["Ma o lenei o le a ou faafilemuina teisi lou mafaufau e uiga i lenei mataupu. Faauta,", "And now I will ease your mind somewhat on this subject. Behold,"], ["ua e ofo pe aisea ua tatau ai ona mamao ona iloa muamua o nei mea ae lei oo mai. Faauta,", "you marvel why these things should be known so long beforehand. Behold,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["ua le tusa ea le pele i le Atua o se agaga i le taimi nei e pei o se agaga i le taimi o lona afio mai?", "is not a soul at this time as precious unto God as a soul will be at the time of his coming?"]]},
  {num:18,words:[["Pe ua le tutusa ea le tatau ai ona faaali mai o le fuafuaga o le togiola i lenei nuu e pei ona tatau ai foi ia latou fanau?", "Is it not as necessary that the plan of redemption should be made known unto this people as well as unto their children?"]]},
  {num:19,words:[["Pe ua le tutusa ea le faigofie i le Alii le auina mai i le taimi nei o lana agelu e tau mai nei tala fiafia ia te i tatou e pei o a tatou fanau,", "Is it not as easy at this time for the Lord to send his angel to declare these glad tidings unto us as unto our children,"], ["pe e pei o le taimi pe a mavae le taimi o lona afio mai?", "or as after the time of his coming?"]]},
];
renderVerseSet(al_ch_39_Verses, 'al-ch39-verses');

var al_ch_40_Verses = [
  {num:1,words:[["O lenei,", "Now my son,"], ["lo'u atalii e, o ni isi nei o mea tele teisi atu ou te fia fai atu ai ia te oe;", "here is somewhat more I would say unto thee;"], ["ona ua ou vaai ua popole lou mafaufau e uiga i le toetutu mai o e ua oti.", "for I perceive that thy mind is worried concerning the resurrection of the dead."]]},
  {num:2,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["e leai se toetutu—pe,", "that there is no resurrection—or,"], ["ou te faapea atu,", "I would say,"], ["i ni isi upu,", "in other words,"], ["o lenei tino faaletino e le faaofuina i le ola pea,", "that this mortal does not put on immortality,"], ["o lenei tino le atoatoa e le faaofuina i le tino atoatoa— seia mavae le afio mai o Keriso.", "this corruption does not put on incorruption—until after the coming of Christ."]]},
  {num:3,words:[["Faauta,", "Behold,"], ["e faataunuu e ia le toetutu mai o e ua oti.", "he bringeth to pass the resurrection of the dead."], ["Peitai faauta,", "But behold,"], ["lo'u atalii e,", "my son,"], ["e lei oo mai le toetutu.", "the resurrection is not yet."], ["O lenei,", "Now,"], ["ou te fofola atu ia te oe se mealilo;", "I unfold unto you a mystery;"], ["e ui i lea,", "nevertheless,"], ["e tele mealilo ua taofia ,", "there are many mysteries which are kept,"], ["e leai se tasi na te iloaina vagana ai le Atua lava ia.", "that no one knoweth them save God himself."], ["Ae ou te faailoa atu ia te oe se mea e tasi sa ou ole atu ai ma le filiga i le Atua, ina ia mafai ona ou iloaina—o lena mea e faatatau i le toetutu.", "But I show unto you one thing which I have inquired diligently of God that I might know—that is concerning the resurrection."]]},
  {num:4,words:[["Faauta,", "Behold,"], ["e i ai se taimi ua tuupoina o le a tutulai mai ai tagata uma mai le oti. O lenei o afea e oo mai ai lenei taimi e leai se tasi na te iloa;", "there is a time appointed that all shall come forth from the dead. Now when this time cometh no one knows;"], ["peitai ua silafia e le Atua le taimi ua tuupoina.", "but God knoweth the time which is appointed."]]},
  {num:5,words:[["O lenei,", "Now,"], ["pe o le a i ai se taimi e tasi,", "whether there shall be one time,"], ["po o se taimi lona lua ,", "or a second time,"], ["po o se taimi lona tolu,", "or a third time,"], ["o le a toetutu mai ai tagata mai le oti,", "that men shall come forth from the dead,"], ["ua le afaina;", "it mattereth not;"], ["ona ua silafia e le Atua nei mea uma;", "for God knoweth all these things;"], ["ma ua lava ia te au le iloa o le tulaga lenei ua i ai—e i ai se taimi ua tuupoina e toetutu mai ai tagata uma mai le oti.", "and it sufficeth me to know that this is the case—that there is a time appointed that all shall rise from the dead."]]},
  {num:6,words:[["O lenei e tatau ona i ai se va i le va o le taimi o le oti ma le taimi o le toetutu mai.", "Now there must needs be a space betwixt the time of death and the time of the resurrection."]]},
  {num:7,words:[["Ma o lenei ou te fia fesili o le a le mea e oo i agaga o tagata mai lenei taimi o le oti seia oo i le taimi ua tuupoina mo le toetutu mai?", "And now I would inquire what becometh of the souls of men from this time of death to the time appointed for the resurrection?"]]},
  {num:8,words:[["O lenei pe sili atu i le tasi le taimi ua tuupoina mo tagata e toetutu mai ai,", "Now whether there is more than one time appointed for men to rise it mattereth not;"], ["ua le afaina;", "for all do not die at once,"], ["ona e le feoti tagata uma i le taimi e tasi, ma ua le afaina lea;", "and this mattereth not;"], ["o mea uma ua pei o se aso e tasi i le Atua,", "all is as one day with God,"], ["ma ua nao le tagata ua fuaina le taimi.", "and time only is measured unto men."]]},
  {num:9,words:[["O lea,", "Therefore,"], ["e i ai se taimi ua tuupoina mo tagata latou te tutulai mai ai mai le oti;", "there is a time appointed unto men that they shall rise from the dead;"], ["ma ua i ai se va i le va o le taimi o le oti ma le toetutu mai.", "and there is a space between the time of death and the resurrection."], ["Ma o lenei,", "And now,"], ["e faatatau i le va lea o le taimi,", "concerning this space of time,"], ["o le a le mea e oo i agaga o tagata i le va lea, o le mea lena na ou ole atu ai i le Alii ma le filiga ia ou iloa;", "what becometh of the souls of men is the thing which I have inquired diligently of the Lord to know;"], ["ma o le mea lenei ua ou iloa.", "and this is the thing of which I do know."]]},
  {num:10,words:[["Ma pe a oo mai le taimi o le a toetutu mai tagata uma,", "And when the time cometh when all shall rise,"], ["ona latou iloa lea ua silafia e le Atua taimi uma ua tuupoina i le tagata.", "then shall they know that God knoweth all the times which are appointed unto man."]]},
  {num:11,words:[["O lenei,", "Now,"], ["e faatatau i le tulaga o le agaga i le va o le oti ma le toetutu mai—Faauta,", "concerning the state of the soul between death and the resurrection—Behold,"], ["ua faailoa mai ia te au e se agelu,", "it has been made known unto me by an angel,"], ["e faapea o agaga o tagata uma,", "that the spirits of all men,"], ["o le taimi lava latou te o ese atu ai mai lenei tino faaletino,", "as soon as they are departed from this mortal body,"], ["ioe,", "yea,"], ["agaga o tagata uma,", "the spirits of all men,"], ["pe sa latou lelei pe sa leaga,", "whether they be good or evil,"], ["e ave atu i fanua i lena Atua o le na ia tuuina ia te i latou le ola.", "are taken home to that God who gave them life."]]},
  {num:12,words:[["Ma ona oo lea,", "And then shall it come to pass,"], ["o agaga o i latou o e ua amiotonu e talia i se nofoaga o le fiafia ,", "that the spirits of those who are righteous are received into a state of happiness,"], ["lea ua taua o le parataiso ,", "which is called paradise, a state of rest,"], ["o se nofoaga e malolo ai,", "a state of peace,"], ["o se nofoaga o le filemu o le a latou malolo ai mai i o latou faalavelave uma ma mai le popole uma,", "where they shall rest from all their troubles and from all care,"], ["ma le faanoanoa.", "and sorrow."]]},
  {num:13,words:[["Ma ona oo ai lea,", "And then shall it come to pass,"], ["o agaga o e ua amioleaga,", "that the spirits of the wicked,"], ["ioe,", "yea,"], ["o e ua leaga—aua faauta,", "who are evil—for behold,"], ["ua latou le maua se vaega po o se mea itiiti o le Agaga o le Alii;", "they have no part nor portion of the Spirit of the Lord;"], ["aua faauta,", "for behold,"], ["sa latou filifili galuega leaga nai lo le lelei;", "they chose evil works rather than good;"], ["o lea na ulu ai le agaga o le tiapolo i totonu o i latou,", "therefore the spirit of the devil did enter into them,"], ["ma fai mona o latou fal—ma o i latou ia o le a tutuli ese i fafo i le pouliuli i fafo;", "and take possession of their house—and these shall be cast out into outer darkness;"], ["o iina o le a i ai le taufaitagi ,", "there shall be weeping,"], ["ma le tagiaue,", "and wailing,"], ["ma le lilivau o nifo;", "and gnashing of teeth,"], ["ma o le pogai o lenei mea ona o lo latou lava amioletonu,", "and this because of their own iniquity,"], ["ona sa taitai faatagataotauaina i latou e le loto o le tiapolo.", "being led captive by the will of the devil."]]},
  {num:14,words:[["O lenei o le tulaga lenei o agaga o e ua amioleaga ,", "Now this is the state of the souls of the wicked,"], ["ioe,", "yea,"], ["i le pouliuli,", "in darkness,"], ["ma o se tulaga o le leaga matautia tele o le faatalitali ma le matatau mo le toasa mumu o le toatamai o le Atua o le a oo mai i luga o i latou;", "and a state of awful, fearful looking for the fiery indignation of the wrath of God upon them;"], ["e faapea ona latou nonofo i lenei tulaga ,", "thus they remain in this state,"], ["faapea foi e ua amiotonu i le parataiso,", "as well as the righteous in paradise,"], ["seia oo i le taimi o lo latou toetutu mai.", "until the time of their resurrection."]]},
  {num:15,words:[["O lenei,", "Now,"], ["e i ai ni isi ua malamalama e faapea o lenei tulaga o le fiafia ma lenei tulaga o le pagatia o le agaga,", "there are some that have understood that this state of happiness and this state of misery of the soul,"], ["ao lei oo mai le toetutu,", "before the resurrection,"], ["o le uluai toetutu lea. Ioe,", "was a first resurrection. Yea,"], ["ou te ioe atonu e mafai ona taua o se toetutu,", "I admit it may be termed a resurrection,"], ["le faatu mai lea o le agaga po o le tagata ma lo latou tofia i le fiafia po o le pagatia,", "the raising of the spirit or the soul and their consignation to happiness or misery,"], ["e tusa ma upu ua fetalaia.", "according to the words which have been spoken."]]},
  {num:16,words:[["Ma faauta,", "And behold,"], ["ua toe fetalaia foi,", "again it hath been spoken,"], ["e faapea ua i ai se uluai toetutu ;", "that there is a first resurrection,"], ["o le toetutu mai lea o i latou uma o e na i ai,", "a resurrection of all those who have been,"], ["po o e o i ai,", "or who are,"], ["po o e o le a i ai,", "or who shall be,"], ["e oo mai i lalo i le toetu mai o Keriso mai le oti.", "down to the resurrection of Christ from the dead."]]},
  {num:17,words:[["O lenei,", "Now,"], ["tatou te le manatu faapea o lenei uluai toetutu,", "we do not suppose that this first resurrection,"], ["lea ua taua mai i lenei ala,", "which is spoken of in this manner,"], ["o le toetutu mai lea o tagata ma lo latou tofia i le fiafia po o le pagatia. E le mafai ona e manatu faapea o le uiga lena o lenei mea.", "can be the resurrection of the souls and their consignation to happiness or misery. Ye cannot suppose that this is what it meaneth."]]},
  {num:18,words:[["Faauta,", "Behold,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["E leai;", "Nay;"], ["ae o lona uiga,", "but it meaneth the reuniting of the soul with the body,"], ["o le toetuufaatasia lea o le agaga ma le tino o i latou mai i ona po o Atamu seia oo mai i lalo i le toetu mai o Keriso.", "of those from the days of Adam down to the resurrection of Christ."]]},
  {num:19,words:[["O lenei,", "Now,"], ["pe toetuufaatasia i le taimi e tasi agaga ma tino o i latou o e ua taua,", "whether the souls and the bodies of those of whom has been spoken shall all be reunited at once,"], ["o e ua amioleaga faapea foi ma e ua amiotonu,", "the wicked as well as the righteous,"], ["ou te le fai atu;", "I do not say;"], ["ae ua lava ona ou fai atu,", "let it suffice;"], ["o le a latou tutu uma mai;", "that I say that they all come forth;"], ["po o i ni isi upu,", "or in other words,"], ["o le a oo mai lo latou toetutu mai ae lei oo mai le toetutu mai o i latou o e e maliliu pe a mavae le toetu mai o Keriso.", "their resurrection cometh to pass before the resurrection of those who die after the resurrection of Christ."]]},
  {num:20,words:[["O lenei,", "Now,"], ["lou atalii e,", "my son,"], ["ou te le fai atu e oo mai lo latou toetutu i le toetu mai o Keriso,", "I do not say that their resurrection cometh at the resurrection of Christ;"], ["ae faauta,", "but behold,"], ["ou te tuu atu o so'u manatu,", "I give it as my opinion,"], ["o le a toetuufaatasia agaga ma tino,", "that the souls and the bodies are reunited,"], ["o e ua amiotonu,", "of the righteous,"], ["i le toetu mai o Keriso,", "at the resurrection of Christ,"], ["ma lona afio ae i le lagi.", "and his ascension into heaven."]]},
  {num:21,words:[["Ae pe i lona toetu mai pe i le mavae atu,", "But whether it be at his resurrection or after,"], ["ou te le fai atu;", "I do not say;"], ["ae o le tele lenei o se mea ou te fai atu,", "but this much I say,"], ["e faapea e i ai se va i le va o le oti ma le toetu mai o le tino,", "that there is a space between death and the resurrection of the body,"], ["ma se tulaga o le agaga i le fiafia po o le pagatia seia oo i le taimi ua tuupoina e le Atua e toetutu mai ai e ua oti,", "and a state of the soul in happiness or in misery until the time which is appointed of God that the dead shall come forth,"], ["ma toetuufaatasia,", "and be reunited,"], ["o le agaga faapea ma le tino,", "both soul and body,"], ["ma aumai e tutu i luma o le Atua,", "and be brought to stand before God,"], ["ma faamasinoina e tusa ma a latou galuega.", "and be judged according to their works."]]},
  {num:22,words:[["Ioe,", "Yea,"], ["o lenei mea e faataunuu ai le toefuataiga o mea na na fetalaia e fofoga o perofeta.", "this bringeth about the restoration of those things of which has been spoken by the mouths of the prophets."]]},
  {num:23,words:[["O le agaga o le a toefuataia i le tino ,", "The soul shall be restored to the body,"], ["ma le tino i le agaga;", "and the body to the soul;"], ["ioe,", "yea,"], ["ma o le a toefuataia vae ma lima ma sooga uma i lona tino;", "and every limb and joint shall be restored to its body;"], ["ioe,", "yea,"], ["e oo i se lauulu o le ulu o le a le leiloa;", "even a hair of the head shall not be lost;"], ["ae o le a toefuataia mea uma i o latou autino tatau ai ma atoatoa.", "but all things shall be restored to their proper and perfect frame."]]},
  {num:24,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["o le toefuataiga lenei lea na fetalaia e fofoga o perofeta—", "this is the restoration of which has been spoken by the mouths of the prophets—"]]},
  {num:25,words:[["Ma ona susulu ai lea o e amiotonu i le malo o le Atua.", "And then shall the righteous shine forth in the kingdom of God."]]},
  {num:26,words:[["Ae faauta,", "But behold,"], ["e oo mai se oti leaga matautia i luga o e ua amioleaga;", "an awful death cometh upon the wicked;"], ["ona e oti i latou e faatatau i mea tau i le amiotonu;", "for they die as to things pertaining to things of righteousness;"], ["ona ua latou le mama,", "for they are unclean,"], ["ma e leai se mea le mama e mafai ona mautofi i le malo o le Atua;", "and no unclean thing can inherit the kingdom of God;"], ["ae e tutuli i latou i fafo,", "but they are cast out,"], ["ma tofia e aai i fua o a latou mea na fai po o a latou galuega,", "and consigned to partake of the fruits of their labors or their works,"], ["ia sa leaga;", "which have been evil;"], ["ma latou inuina 'alu o se ipu oona.", "and they drink the dregs of a bitter cup."]]},
];
renderVerseSet(al_ch_40_Verses, 'al-ch40-verses');

var al_ch_41_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["e i ai ni isi mea e tele teisi atu ou te fai atu ai e uiga i le toefuataiga lea ua taua;", "I have somewhat to say concerning the restoration of which has been spoken;"], ["aua faauta,", "for behold,"], ["e i ai ni isi ua latou mimilo tusitusiga paia,", "some have wrested the scriptures,"], ["ma ua o sese mamao ese ai ona o lenei mea. Ma ua ou vaai ua popole foi lou mafaufau i lenei mea. Ae faauta,", "and have gone far astray because of this thing. And I perceive that thy mind has been worried also concerning this thing. But behold,"], ["o le a ou faamalamalama atu ia te oe lenei mea.", "I will explain it unto thee."]]},
  {num:2,words:[["Ou te fai atu ia te oe,", "I say unto thee,"], ["lo'u atalii e,", "my son,"], ["o le fuafuaga o le toefuataiga ua tatau ai e tusa ma le faamasinotonu o le Atua;", "that the plan of restoration is requisite with the justice of God;"], ["ona e tatau ona toefuatai o mea uma i o latou tulaga e tatau ai. Faauta,", "for it is requisite that all things should be restored to their proper order. Behold,"], ["o se mea ua tatau ai ma tonu,", "it is requisite and just,"], ["e tusa ma le mana ma le toetu mai o Keriso,", "according to the power and resurrection of Christ,"], ["le tatau ona toefuatai o le agaga o le tagata i lona tino,", "that the soul of man should be restored to its body,"], ["ma le tatau ona toefuatai o vaega uma o le tino ia te ia lava.", "and that every part of the body should be restored to itself."]]},
  {num:3,words:[["Ma ua tatau ai e tusa ma le faamasinotonu o le Atua le tatau ai ona faamasinoina o tagata e tusa ma a latou galuega ;", "And it is requisite with the justice of God that men should be judged according to their works;"], ["ma afai sa lelei a latou galuega i le olaga lenei,", "and if their works were good in this life,"], ["ma sa lelei manaoga o o latou loto,", "and the desires of their hearts were good,"], ["e tatau foi,", "that they should also,"], ["i le aso gataaga,", "at the last day,"], ["ona toefuatai i latou i le mea ua lelei.", "be restored unto that which is good."]]},
  {num:4,words:[["Ae afai ua leaga a latou galuega o le a toefuatai ia te i latou mo le leaga. O lea,", "And if their works are evil they shall be restored unto them for evil. Therefore,"], ["o le a toefuataiina mea uma i o latou tulaga e tatau ai,", "all things shall be restored to their proper order,"], ["o mea taitasi uma i lona lava autino natura moni—o le faaletino e faatu i le ola pea;", "every thing to its natural frame—mortality raised to immortality,"], ["o le le atoatoa i le atoatoa—e faatutu mai i le fiafia e le gata e mautofi i le malo o le Atua,", "corruption to incorruption—raised to endless happiness to inherit the kingdom of God,"], ["po o le pagatia e le gata e mautofi i le malo o le tiapolo;", "or to endless misery to inherit the kingdom of the devil,"], ["o le isi i le tasi itu,", "the one on one hand,"], ["o le isi i le isi itu—", "the other on the other—"]]},
  {num:5,words:[["O le tasi e faatuina i le fiafia e tusa ma ona manaoga mo le fiafia,", "The one raised to happiness according to his desires of happiness,"], ["po o le lelei e tusa ma ona manaoga mo le lelei;", "or good according to his desires of good;"], ["ao le tasi i le leaga e tusa ma ona manaoga mo le leaga; ona e pei ona sa manao o ia e fai le leaga i le umi o le aso atoa,", "and the other to evil according to his desires of evil;"], ["o le a faapea lava ona maua e ia lona taui o le leaga pe a oo mai le po.", "for as he has desired to do evil all the day long even so shall he have his reward of evil when the night cometh."]]},
  {num:6,words:[["Ma ua faapea ona i ai i le isi itu. Afai sa salamo o ia i ana agasala,", "And so it is on the other hand. If he hath repented of his sins,"], ["ma sa manao i le amiotonu seia oo i le iuga o ona aso,", "and desired righteousness until the end of his days,"], ["o le a faapea lava ona tauia o ia i le amiotonu.", "even so he shall be rewarded unto righteousness."]]},
  {num:7,words:[["O i latou ia o e ua togiolaina e le Alii;", "These are they that are redeemed of the Lord;"], ["ioe,", "yea,"], ["o i latou ia e ave i fafo,", "these are they that are taken out,"], ["ua laveaiina mai lena po o le pouliuli e le gata;", "that are delivered from that endless night of darkness;"], ["ma e faapea ona latou tutu pe pauu;", "and thus they stand or fall;"], ["aua faauta,", "for behold,"], ["o i latou o o latou lava faamasino,", "they are their own judges,"], ["pe latou te faia le lelei pe fai le leaga.", "whether to do good or do evil."]]},
  {num:8,words:[["O lenei,", "Now,"], ["o tulafono a le Atua e le masuia;", "the decrees of God are unalterable;"], ["o lea,", "therefore,"], ["ua uma ona saunia o le ala o soo se tasi e manao i ai e mafai ona ia savali ai i totonu ma faaolaina ai.", "the way is prepared that whosoever will may walk therein and be saved."]]},
  {num:9,words:[["Ma o lenei faauta,", "And now behold,"], ["lo'u atalii e,", "my son,"], ["aua e te toe faia ma le taumatemate se isi lava agasala e tasi e faasaga i lou Atua e faatatau i matautu na o le mataupu faavae,", "do not risk one more offense against your God upon those points of doctrine,"], ["ia sa e faia ma le taumatemate e oo mai i le taimi nei e te faia ai le agasala.", "which ye have hitherto risked to commit sin."]]},
  {num:10,words:[["Aua e te manatu,", "Do not suppose,"], ["ona ua taua mai e uiga i le toefuataiga,", "because it has been spoken concerning restoration,"], ["o le a toefuatai oe mai le agasala i le fiafia. Faauta,", "that ye shall be restored from sin to happiness. Behold,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["e lei avea lava le amioleaga ma fiafia.", "wickedness never was happiness."]]},
  {num:11,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["o tagata uma ua i ai i se tulaga o le natura ,", "all men that are in a state of nature,"], ["pe ou te fai atu,", "or I would say,"], ["ua i ai se tulaga faaletino,", "in a carnal state,"], ["ua i ai i latou i totonu o le au oona ma i totonu o noanoaga o le amioletonu;", "are in the gall of bitterness and in the bonds of iniquity;"], ["ua aunoa i latou ma le Atua i le lalolagi,", "they are without God in the world,"], ["ma ua latou o e le tusa ai ma le natura o le Atua;", "and they have gone contrary to the nature of God;"], ["o lea,", "therefore,"], ["ua latou i ai i se tulaga ua le tusa ai ma le natura o le fiafia.", "they are in a state contrary to the nature of happiness."]]},
  {num:12,words:[["Ma o lenei faauta,", "And now behold,"], ["o le uiga ea o le upu o le toefuataiga o le ave lea o se mea mai lona tulaga natura moni ma tuu i se tulaga e le o sona tulaga natura moni,", "is the meaning of the word restoration to take a thing of a natural state and place it in an unnatural state,"], ["pe tuu i se tulaga e ese mai lona natura moni?", "or to place it in a state opposite to its nature?"]]},
  {num:13,words:[["E,", "O,"], ["lo'u atalii e,", "my son,"], ["e le o le tulaga lea;", "this is not the case;"], ["ae o le uiga o le upu o le toefuataiga,", "but the meaning of the word restoration is to bring back again evil for evil,"], ["o le toe aumai lea o le leaga mo le leaga, po o le faaletino mo le faaletino,", "or carnal for carnal,"], ["po o le faatiapolo mo le faatiapolo—o le lelei mo le mea ua lelei;", "or devilish for devilish—good for that which is good;"], ["o le amiotonu mo le mea ua amiotonu;", "righteous for that which is righteous;"], ["o le mea tonu mo le mea ua tonu;", "just for that which is just;"], ["o le alofa mutimutivale mo le mea ua alofa mutimutivale.", "merciful for that which is merciful."]]},
  {num:14,words:[["O lea,", "Therefore,"], ["lo'u atalii e,", "my son,"], ["vaai ia e alofa mutimutivale i ou uso;", "see that you are merciful unto your brethren;"], ["fai mea tonu ,", "deal justly,"], ["faamasino ma le amiotonu,", "judge righteously,"], ["ma fai mea lelei e le aunoa;", "and do good continually;"], ["ma afai e te faia nei mea uma ona e maua lea o lou taui;", "and if ye do all these things then shall ye receive your reward;"], ["ioe,", "yea,"], ["o le a toefuatai mai ia te oe le alofa mutimutivale;", "ye shall have mercy restored unto you again;"], ["o le a toefuatai mai ia te oe le faamasinotonu;", "ye shall have justice restored unto you again;"], ["o le a toefuatai mai ia te oe se faamasinoga amiotonu;", "ye shall have a righteous judgment restored unto you again;"], ["ma o le a toe tauia mai ia te oe le lelei.", "and ye shall have good rewarded unto you again."]]},
  {num:15,words:[["Ona o le mea e te auina atu o le a toe faafoi mai ia te oe,", "For that which ye do send out shall return unto you again,"], ["ma toefuatai mai;", "and be restored;"], ["o lea,", "therefore,"], ["o le upu o le toefuataiga e tausala atoatoa ai le tagata agasala,", "the word restoration more fully condemneth the sinner,"], ["ma le tauamiotonuina ai o ia i soo se ala.", "and justifieth him not at all."]]},
];
renderVerseSet(al_ch_41_Verses, 'al-ch41-verses');

var al_ch_42_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["ua ou vaai ua i ai isi mea e tele teisi atu ua popole i ai lou mafaufau,", "I perceive there is somewhat more which doth worry your mind,"], ["ia ua le mafai ona e malamalama i ai—ia ua faatatau i le faamasinotonu o le Atua i le faasalaina o le tagata agasala;", "which ye cannot understand—which is concerning the justice of God in the punishment of the sinner;"], ["ona ua e taumafai e mafaufau e faapea ua le o se faamasinotonu le tofia o le tagata agasala i se tulaga o le pagatia.", "for ye do try to suppose that it is injustice that the sinner should be consigned to a state of misery."]]},
  {num:2,words:[["O lenei faauta,", "Now behold,"], ["lo'u atalii e,", "my son,"], ["o le a ou faamalamalama atu ia te oe lenei mea. Aua faauta,", "I will explain this thing unto thee. For behold,"], ["ina ua uma ona auina ese atu e le Alii le Atua o tatou uluai matua mai le faatoaga o Etena ,", "after the Lord God sent our first parents forth from the garden of Eden,"], ["e galueaiina le eleele,", "to till the ground,"], ["lea na aumai ai i laua—ioe,", "from whence they were taken—yea,"], ["sa ia aveese i fafo le tagata,", "he drew out the man,"], ["ma sa ia tuu i le pito i sasae o le faatoaga o Etena,", "and he placed at the east end of the garden of Eden,"], ["kerupi ,", "cherubim,"], ["ma se pelu afi mumu e feliuliuai i itu uma,", "and a flaming sword which turned every way,"], ["e leoleo le laau o le ola.", "to keep the tree of life—"]]},
  {num:3,words:[["O lenei,", "Now,"], ["ua tatou vaai ua avea le tagata e pei o le Atua,", "we see that the man had become as God,"], ["i le iloa o le lelei ma le leaga;", "knowing good and evil;"], ["ma ina ne'i tuu atu lona lima,", "and lest he should put forth his hand,"], ["ma ia ave foi mai le laau o le ola,", "and take also of the tree of life,"], ["ma 'ai ma ola ai e faavavau,", "and eat and live forever,"], ["o lea na tuu ai e le Alii le Atua kerupi ma le pelu afi mumu,", "the Lord God placed cherubim and the flaming sword,"], ["ina ia le mafai ona 'ai o ia i le fua—", "that he should not partake of the fruit—"]]},
  {num:4,words:[["Ma ua faapea ona tatou vaai ai,", "And thus we see,"], ["e i ai se taimi ua tuu mai i le tagata e salamo ai,", "that there was a time granted unto man to repent,"], ["ioe,", "yea,"], ["o se taimi vaavaai ,", "a probationary time,"], ["o se taimi e salamo ma auauna ai i le Atua.", "a time to repent and serve God."]]},
  {num:5,words:[["Aua faauta,", "For behold,"], ["a na vave ona aapa atu o le lima o Atamu,", "if Adam had put forth his hand immediately,"], ["ma 'ai i le laau o le ola,", "and partaken of the tree of life,"], ["po ua ola o ia e faavavau,", "he would have lived forever,"], ["e tusa ma le afioga a le Atua,", "according to the word of God,"], ["ua leai se taimi e salamo ai;", "having no space for repentance;"], ["ioe,", "yea,"], ["ma po ua leai foi se aoga o le afioga a le Atua,", "and also the word of God would have been void,"], ["ma po ua le taulau le fuafuaga tele o le olataga.", "and the great plan of salvation would have been frustrated."]]},
  {num:6,words:[["Ae faauta,", "But behold,"], ["sa tofia mo le tagata ia oti —o lea,", "it was appointed unto man to die—therefore,"], ["e pei ona vavae ese i laua mai le laau o le ola sa tatau foi ona vavae ese i laua mai luga o le lalolagi—ma sa oo ina leiloa le tagata e faavavau,", "as they were cut off from the tree of life they should be cut off from the face of the earth—and man became lost forever,"], ["ioe,", "yea,"], ["ua avea i laua ma tagata pau.", "they became fallen man."]]},
  {num:7,words:[["Ma o lenei,", "And now,"], ["ua e vaai o lenei mea na vavae ese ai faaletino ma faaleagaga o tatou uluai matua mai luma o le Alii;", "ye see by this that our first parents were cut off both temporally and spiritually from the presence of the Lord;"], ["ma ua faapea ona tatou vaai ai sa avea i laua ma ni tagata e mulimuli i o laua lava loto .", "and thus we see they became subjects to follow after their own will."]]},
  {num:8,words:[["O lenei faauta,", "Now behold,"], ["sa le tatau ona toe laveai o le tagata mai lenei oti faaletino,", "it was not expedient that man should be reclaimed from this temporal death,"], ["ona e faaumatia i lena mea le fuafuaga tele o le fiafia.", "for that would destroy the great plan of happiness."]]},
  {num:9,words:[["O lea,", "Therefore,"], ["ona e le mafai lava ona oti o le agaga,", "as the soul could never die,"], ["ma ua aumai e le pau i luga o tagata uma se oti faaleagaga faapea foi ma se oti faaletino,", "and the fall had brought upon all mankind a spiritual death as well as a temporal,"], ["o lona uiga,", "that is,"], ["ua vavae ese i latou mai luma o le Alii,", "they were cut off from the presence of the Lord,"], ["o lea sa tatau ai ona toe laveai o tagata mai lenei oti faaleagaga.", "it was expedient that mankind should be reclaimed from this spiritual death."]]},
  {num:10,words:[["O lea,", "Therefore,"], ["talu ai ona ua avea i latou ma ni tagata faaletino ,", "as they had become carnal,"], ["tuinanau,", "sensual,"], ["ma faatiapolo,", "and devilish,"], ["i o latou natura ,", "by nature,"], ["o lea ua avea ai lenei olaga vaavaaia o se olaga mo i latou e saunia ai;", "this probationary state became a state for them to prepare;"], ["ua avea o se olaga sauniuni.", "it became a preparatory state."]]},
  {num:11,words:[["Ma o lenei ia e manatua,", "And now remember,"], ["lo'u atalii e,", "my son,"], ["a na leai le fuafuaga o le togiolaina, (pe a tuu ese),", "if it were not for the plan of redemption,"], ["o le taimi lava latou te feoti ai e pagatia ai o latou agaga,", "(laying it aside) as soon as they were dead their souls were miserable,"], ["ona ua vavae ese mai luma o le Alii.", "being cut off from the presence of the Lord."]]},
  {num:12,words:[["Ma o lenei,", "And now,"], ["sa leai se auala e laveai ai tagata mai lenei tulaga pau,", "there was no means to reclaim men from this fallen state,"], ["lea na aumai e le tagata i ona lava luga ona o lona lava le usiusitai;", "which man had brought upon himself because of his own disobedience;"]]},
  {num:13,words:[["O lea,", "Therefore,"], ["e tusa ma le faamasinotonu,", "according to justice,"], ["e le mafai ona faataunuuina o le fuafuaga o le togiola,", "the plan of redemption could not be brought about,"], ["ua nao tulaga lava o le salamo o tagata i lenei olaga vaavaaia e mafai ai,", "only on conditions of repentance of men in this probationary state,"], ["ioe,", "yea,"], ["lenei olaga vaavaaia;", "this preparatory state;"], ["ona vagana ai nei tulaga,", "for except it were for these conditions,"], ["e le mafai ona aoga le alofa mutimutivale vagana ai ua ia faaumatiaina le galuega a le faamasinotonu. O lenei e le mafai ona faaumatiaina le galuega a le faamasinotonu;", "mercy could not take effect except it should destroy the work of justice. Now the work of justice could not be destroyed;"], ["a faapea,", "if so,"], ["po ua le toe avea le Atua ma Atua.", "God would cease to be God."]]},
  {num:14,words:[["Ma ua faapea ona tatou vaai ai ua pauu tagata uma,", "And thus we see that all mankind were fallen,"], ["ma ua latou i ai i le uu a le faamasinotonu ;", "and they were in the grasp of justice;"], ["ioe,", "yea,"], ["le faamasinotonu o le Atua,", "the justice of God,"], ["lea e tofiaina i latou ia vavae ese mai ona luma e faavavau.", "which consigned them forever to be cut off from his presence."]]},
  {num:15,words:[["Ma o lenei,", "And now,"], ["e le mafai ona faataunuuina le fuafuaga o le alofa mutimutivale vagana ai ua faia se togiola;", "the plan of mercy could not be brought about except an atonement should be  made;"], ["o lea ua togiola ai e le Atua lava ia mo agasala a le lalolagi,", "therefore God himself atoneth for the sins of the world,"], ["e faataunuu ai le fuafuaga o le alofa mutimutivale,", "to bring about the plan of mercy,"], ["e faamalie ai manaoga o le faamasinotonu ,", "to appease the demands of justice,"], ["ina ia mafai ona avea le Atua ma Atua ua atoatoa ,", "that God might be a perfect,"], ["faamasinotonu,", "just God,"], ["ma se Atua alofa mutimutivale foi.", "and a merciful God also."]]},
  {num:16,words:[["O lenei,", "Now,"], ["e le mafai ona oo mai le salamo i tagata vagana ua i ai se faasalaga,", "repentance could not come unto men except there were a punishment,"], ["o lea ua faavavau foi e pei ona tatau ai i le ola o le agaga,", "which also was eternal as the life of the soul should be,"], ["ua faapipii e faafeagai ma le fuafuaga o le fiafia,", "affixed opposite to the plan of happiness,"], ["lea ua faavavau foi e pei o le ola o le agaga.", "which was as eternal also as the life of the soul."]]},
  {num:17,words:[["O lenei,", "Now,"], ["e mafai faapefea ona salamo o se tagata vagana ai ua agasala o ia? E mafai faapefea ona agasala o ia pe afai ua leai se tulafono ? E faapefea ona i ai o se tulafono vagana ai ua i ai se faasalaga?", "how could a man repent except he should sin? How could he sin if there was no law? How could there be a law save there was a punishment?"]]},
  {num:18,words:[["O lenei,", "Now,"], ["e i ai se faasalaga sa faapipiiina,", "there was a punishment affixed,"], ["ma se tulafono faamasinotonu na tuuina mai,", "and a just law given,"], ["lea ua aumai ai le faanoanoa o le mafaufau i le tagata.", "which brought remorse of conscience unto man."]]},
  {num:19,words:[["O lenei,", "Now,"], ["afai e leai se tulafono na tuuina mai—afai e fasioti tagata se tagata e tatau ona oti o ia—pe fefe ea o le a oti o ia pe afai e fasioti tagata?", "if there was no law given—if a man murdered he should die—would he be afraid he would die if he should murder?"]]},
  {num:20,words:[["O lenei foi,", "And also,"], ["afai e leai se tulafono e tuuina mai e faasaga i le agasala o le a le fefefe tagata e agasala.", "if there was no law given against sin men would not be afraid to sin."]]},
  {num:21,words:[["Ma afai e leai se tulafono e tuuina mai,", "And if there was no law given,"], ["afai e agasala tagata,", "if men sinned what could justice do,"], ["o le a se mea e mafai ona fai e le faamasinotonu, po o le alofa mutimutivale foi,", "or mercy either,"], ["ona o le a leai sa laua aia i le tagata?", "for they would have no claim upon the creature?"]]},
  {num:22,words:[["Peitai e i ai se tulafono ua tuuina mai,", "But there is a law given,"], ["ma se faasalaga ua faapipiiina,", "and a punishment affixed,"], ["ma se salamo ua tuuina mai;", "and a repentance granted;"], ["le salamo lea,", "which repentance mercy claimeth;"], ["ua aia ai le alofa mutimutivale; a leai,", "otherwise,"], ["e maua e le faamasinotonu le tagata ma faataunuu le tulafono,", "justice claimeth the creature and executeth the law,"], ["ma o le tulafono na te faaooina le faasalaga;", "and the law inflicteth the punishment;"], ["afai e le faapea,", "if not so,"], ["o le a faaumatia galuega a le faamasinotonu,", "the works of justice would be destroyed,"], ["ma o le a le toe avea le Atua ma Atua.", "and God would cease to be God."]]},
  {num:23,words:[["Peitai ua le taofia le avea o le Atua ma Atua,", "But God ceaseth not to be God,"], ["ma e maua e le alofa mutimutivale le aia i le tagata ua salamo,", "and mercy claimeth the penitent,"], ["ma e oo mai le alofa mutimutivale ona o le togiola ;", "and mercy cometh because of the atonement;"], ["ma ua aumai e le togiola le toetutu mai o e ua oti;", "and the atonement bringeth to pass the resurrection of the dead;"], ["ma o le toetutu mai o e ua oti ua toe aumai ai tagata i luma o le Atua;", "and the resurrection of the dead bringeth back men into the presence of God;"], ["ma faapea ona toefuatai ai o i latou i ona luma,", "and thus they are restored into his presence,"], ["e faamasinoina e tusa ma a latou galuega,", "to be judged according to their works,"], ["e tusa ma le tulafono ma le faamasinotonu.", "according to the law and justice."]]},
  {num:24,words:[["Aua faauta,", "For behold,"], ["e faaaoga e le faamasinotonu ona manaoga uma;", "justice exerciseth all his demands,"], ["ma e maua foi e le alofa mutimutivale mea uma e a ia lava;", "and also mercy claimeth all which is her own;"], ["ma o lea,", "and thus,"], ["e leai se tasi ae ua nao e lava ua salamo moni e faaolaina.", "none but the truly penitent are saved."]]},
  {num:25,words:[["E a ea,", "What,"], ["e te manatu ea e mafai e le alofa mutimutivale ona faoa le faamasinotonu ? Ou te fai atu ia te oe,", "do ye suppose that mercy can rob justice? I say unto you,"], ["E leai;", "Nay;"], ["e leai sina iota e tasi. Afai e faapea,", "not one whit. If so,"], ["po ua le toe avea le Atua ma Atua.", "God would cease to be God."]]},
  {num:26,words:[["Ma e faapea ona faataunuu e le Atua ona faamoemoega tetele ma faavavau,", "And thus God bringeth about his great and eternal purposes,"], ["ia sa saunia mai le faavaega o le lalolagi. Ma e faapea ona oo mai o le olataga ma le togiolaina o tagata,", "which were prepared from the foundation of the world. And thus cometh about the salvation and the redemption of men,"], ["ma lo latou faafanoga ma lo latou pagatia foi.", "and also their destruction and misery."]]},
  {num:27,words:[["O lea, lo'u atalii e,", "Therefore,"], ["soo se tasi e fia sau,", "O my son,"], ["e mafai ona sau ma inu saoloto i vai o le ola; ma soo se tasi e le fia sau,", "whosoever will come may come and partake of the waters of life freely;"], ["o ia lava lea ua le faamalosia e sau;", "and whosoever will not come the same is not compelled to come;"], ["ae i le aso gataaga, o le a toefuatai mai ia te ia e tusa ma ana galuega .", "but in the last day it shall be restored unto him according to his deeds."]]},
  {num:28,words:[["Afai sa manao o ia e fai le leaga ,", "If he has desired to do evil,"], ["ma sa lei salamo i ona aso,", "and has not repented in his days,"], ["faauta,", "behold,"], ["o le a faia le leaga ia te ia,", "evil shall be done unto him,"], ["e tusa ma le toefuataiga a le Atua.", "according to the restoration of God."]]},
  {num:29,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "my son,"], ["ou te manao ia e tuu nei mea ia le toe faalavelave ia te oe,", "I desire that ye should let these things trouble you no more,"], ["ae ia nao au agasala ia e popole i ai,", "and only let your sins trouble you,"], ["le popole lena e aumai ai oe i lalo i le salamo.", "with that trouble which shall bring you down unto repentance."]]},
  {num:30,words:[["E, lo'u atalii e,", "O my son,"], ["ou te manao ia e le toe faafitia le faamasinotonu a le Atua.", "I desire that ye should deny the justice of God no more."], ["Aua e te taumafai e tauamiotonuina oe lava i se matautu itiiti lava ona o au agasala,", "Do not endeavor to excuse yourself in the least point because of your sins,"], ["i lou faafitia o le faamasinotonu o le Atua;", "by denying the justice of God;"], ["ae ia e tuu le faamasinotonu o le Atua,", "but do you let the justice of God,"], ["ma lona alofa mutimutivale,", "and his mercy,"], ["ma lona tali-tiga e tosina atoa ai lou loto;", "and his long– suffering have full sway in your heart;"], ["ma ia e tuu lenei mea e ave ifo ai oe i lalo i le efuefu i le lotomaualalo .", "and let it bring you down to the dust in humility."]]},
  {num:31,words:[["Ma o lenei,", "And now,"], ["lo'u atalii e,", "O my son,"], ["ua valaauina oe e le Atua e te talai atu le afioga i lenei nuu. Ma o lenei,", "ye are called of God to preach the word unto this people. And now,"], ["lo'u atalii e,", "my son,"], ["alu ia i lou ala,", "go thy way,"], ["tau atu le afioga ma le faamaoni ma le mamalu,", "declare the word with truth and soberness,"], ["ina ia mafai ona e aumai o agaga i le salamo,", "that thou mayest bring souls unto repentance,"], ["ina ia mafai ona maua e le fuafuaga tele o le alofa mutimutivale le aia ia i latou. Ma ia alofa le Atua ia tuuina mai ia te oe e tusa ai ma a'u upu. Amene.", "that the great plan of mercy may have claim upon them. And may God grant unto you even according to my words. Amen."]]},
];
renderVerseSet(al_ch_42_Verses, 'al-ch42-verses');

var al_ch_43_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina o atu atalii o Alema i totonu o le nuu,", "And now it came to pass that the sons of Alma did go forth among the people,"], ["e talai atu le afioga ia te i latou.", "to declare the word unto them."], ["Ma o Alema,", "And Alma,"], ["o ia lava foi,", "also,"], ["sa le mafai ona malolo,", "himself, could not rest,"], ["ma sa alu atu foi o ia.", "and he also went forth."]]},
  {num:2,words:[["O lenei o le a matou le toe fai atu ni isi mea e uiga i la latou talaiga,", "Now we shall say no more concerning their preaching,"], ["vagana ai sa latou talai atu le afioga,", "except that they preached the word,"], ["ma le upumoni,", "and the truth,"], ["e tusa ma le agaga o valoaga ma faaaliga;", "according to the spirit of prophecy and revelation;"], ["ma sa latou talai atu e tusa ma le faatulagaga paia a le Atua lea na valaaulia i ai i latou.", "and they preached after the holy order of God by which they were called."]]},
  {num:3,words:[["Ma o lenei ou te toe foi i se tala o taua i le va o sa Nifaē ma sa Lamanā,", "And now I return to an account of the wars between the Nephites and the Lamanites,"], ["i le lona sefulu valu o tausaga o le nofoaiga a faamasino.", "in the eighteenth year of the reign of the judges."]]},
  {num:4,words:[["Aua faauta,", "For behold,"], ["sa oo ina avea sa Soramā ma ni sa Lamanā;", "it came to pass that the Zoramites became Lamanites;"], ["o lea,", "therefore,"], ["i le amataga o le tausaga e sefulu valu na vaai ai tagata o Nifaē ua o mai sa Lamanā ia i latou;", "in the commencement of the eighteenth year the people of the Nephites saw that the Lamanites were coming upon them;"], ["o lea na latou faia ai sauniuniga mo le taua;", "therefore they made preparations for war;"], ["ioe,", "yea,"], ["sa latou faapotopoto faatasi a latou autau i le laueleele o Seasona.", "they gathered together their armies in the land of Jershon."]]},
  {num:5,words:[["Ma sa oo ina o mai sa Lamanā ma a latou afe ma afe;", "And it came to pass that the Lamanites came with their thousands;"], ["ma sa latou o mai i le laueleele o Anetionuma,", "and they came into the land of Antionum,"], ["o le laueleele lea o sa Soramā;", "which is the land of the Zoramites;"], ["ma o le tagata e igoa ia Sera'emina sa avea ma o latou taitai.", "and a man by the name of Zerahemnah was their leader."]]},
  {num:6,words:[["Ma o lenei,", "And now,"], ["ona o tagata sa Amalekā,", "as the Amalekites were of a more wicked and murderous disposition than the Lamanites were,"], ["ia i latou lava,", "in and of themselves,"], ["sa sili atu ona amioleaga ma amio fasioti tagata nai lo sa Lamanā,", "therefore,"], ["o lea na tofia ai e Sera'emina kapeteni sili i luga o sa Lamanā,", "Zerahemnah appointed chief captains over the Lamanites,"], ["ma o i latou uma o ni sa Amalekā ma sa Soramā.", "and they were all Amalekites and Zoramites."]]},
  {num:7,words:[["O lenei sa ia faia lenei mea ina ia mafai ona ia faatumauina lo latou ita e faasaga ia sa Nifaē,", "Now this he did that he might preserve their hatred towards the Nephites,"], ["ina ia mafai ona ia aumai o i latou i lalo o lana pule e faataunuu ai ana fuafuaga.", "that he might bring them into subjection to the accomplishment of his designs."]]},
  {num:8,words:[["Aua faauta,", "For behold,"], ["o ana fuafuaga o le faaoso lea o sa Lamanā ia feita e faasaga ia sa Nifaē;", "his designs were to stir up the Lamanites to anger against the Nephites;"], ["sa ia faia lenei mea ina ia mafai ona ia ave ai le pule tele i luga o i latou,", "this he did that he might usurp great power over them,"], ["ma ina ia mafai foi ona ia maua ai o le pule i luga o sa Nifaē i le aumaia o i latou i le pologa.", "and also that he might gain power over the Nephites by bringing them into bondage."]]},
  {num:9,words:[["Ma o lenei o le faamoemoe o sa Nifaē o le tausia lea o o latou fanua,", "And now the design of the Nephites was to support their lands,"], ["ma o latou fale,", "and their houses,"], ["ma a latou ava ,", "and their wives,"], ["ma a latou fanau,", "and their children,"], ["ina ia mafai ona latou faasaoina i latou mai lima o o latou fili;", "that they might preserve them from the hands of their enemies;"], ["ma ina ia mafai foi ona latou faatumau a latou aia ma o latou avanoa,", "and also that they might preserve their rights and their privileges,"], ["ioe,", "yea,"], ["ma lo latou saolotoga foi,", "and also their liberty,"], ["ina ia mafai ona latou tapuai i le Atua e tusa ma o latou manao.", "that they might worship God according to their desires."]]},
  {num:10,words:[["Ona sa latou iloa afai latou te pauu atu i lima o sa Lamanā,", "For they knew that if they should fall into the hands of the Lamanites,"], ["soo se tasi e tapuai i le Atua,", "that whosoever should worship God in spirit and in truth,"], ["le Atua moni ma soifua, i le agaga ma le upumoni,", "the true and the living God,"], ["e faaumatia e sa Lamanā.", "the Lamanites would destroy."]]},
  {num:11,words:[["Ioe,", "Yea,"], ["ma sa latou iloa foi le feita tele o sa Lamanā e faasaga i o latou uso ,", "and they also knew the extreme hatred of the Lamanites towards their brethren,"], ["o e o tagata o Aneti-Nifae-Liae,", "who were the people of Anti– Nephi– Lehi,"], ["o e sa taua o le nuu o Amona—ma sa latou le fia fetagofi i auupega,", "who were called the people of Ammon—and they would not take up arms,"], ["ioe,", "yea,"], ["sa uma ona latou ulu atu i se feagaiga ma sa latou le fia solia—o lea,", "they had entered into a covenant and they would not break it—therefore,"], ["afai e pauu atu i latou i lima o sa Lamanā o le a faaumatia i latou.", "if they should fall into the hands of the Lamanites they would be destroyed."]]},
  {num:12,words:[["Ma sa le fia tuua i latou e sa Nifaē ia faaumatiaina;", "And the Nephites would not suffer that they should be destroyed;"], ["o lea na latou tuu atu ai ia te i latou laueleele mo o latou tofi.", "therefore they gave them lands for their inheritance."]]},
  {num:13,words:[["Ma sa tuu atu e le nuu o Amona ia sa Nifaē se vaega tele o a latou mea e tausi ai a latou autau;", "And the people of Ammon did give unto the Nephites a large portion of their substance to support their armies;"], ["ma sa faapea ona faamalosiina sa Nifaē,", "and thus the Nephites were compelled,"], ["nao i latou lava,", "alone,"], ["e tutu tetee atu e faasaga ia sa Lamanā,", "to withstand against the Lamanites,"], ["o e o se tuufaatasiga o Lamana ma Lemuelu,", "who were a compound of Laman and Lemuel,"], ["ma atalii o Isamaeli,", "and the sons of Ishmael,"], ["ma i latou uma o e na faatuiese mai sa Nifaē,", "and all those who had dissented from the Nephites,"], ["o e o sa Amalekā ma sa Soramā,", "who were Amalekites and Zoramites,"], ["ma e na tupuga mai i faitaulaga a Noa.", "and the descendants of the priests of Noah."]]},
  {num:14,words:[["O lenei o ia tagata na tupuga mai i faitaulaga a Noa,", "Now those descendants were as numerous,"], ["sa matua toatele lava,", "nearly,"], ["toeitiiti lava, pei o le toatele o sa Nifaē;", "as were the Nephites;"], ["ma sa faapea ona faamalosiina sa Nifaē e tau ma o latou uso,", "and thus the Nephites were obliged to contend with their brethren,"], ["e oo lava i le faamasaaina o le toto.", "even unto bloodshed."]]},
  {num:15,words:[["Ma sa oo ina a'o faapotopoto faatasi autau a sa Lamanā i le laueleele o Anetionuma,", "And it came to pass as the armies of the Lamanites had gathered together in the land of Antionum,"], ["faauta,", "behold,"], ["sa sauni autau a sa Nifaē e fetaiai ma i latou i le laueleele o Seasona.", "the armies of the Nephites were prepared to meet them in the land of Jershon."]]},
  {num:16,words:[["O lenei,", "Now,"], ["o le taitai o sa Nifaē,", "the leader of the Nephites,"], ["po o le tagata o le na tofia e avea ma kapeteni sili ia sa Nifaē—o lenei o le kapeteni sili na puleaina autau uma a sa Nifaē—ma o lona igoa o Moronae.", "or the man who had been appointed to be the chief captain over the Nephites—now the chief captain took the command of all the armies of the Nephites—and his name was Moroni;"]]},
  {num:17,words:[["Ma sa ave e Moronae le pule atoa,", "And Moroni took all the command,"], ["ma le puleaina o a latou taua. Ma sa nao le lua sefulu ma le lima ona tausaga ina ua tofia o ia e avea ma kapeteni sili i autau a sa Nifaē.", "and the government of their wars. And he was only twenty and five years old when he was appointed chief captain over the armies of the Nephites."]]},
  {num:18,words:[["Ma sa oo ina ia faafetaiaia sa Lamanā i tuaoi o Seasona,", "And it came to pass that he met the Lamanites in the borders of Jershon,"], ["ma sa faaauupegaina ana tagata i pelu,", "and his people were armed with swords,"], ["ma simetea,", "and with cimeters,"], ["ma ituaiga o auupega eseese uma o taua.", "and all manner of weapons of war."]]},
  {num:19,words:[["Ma ina ua vaai mai autau a sa Lamanā ua sauni le nuu o Nifae,", "And when the armies of the Lamanites saw that the people of Nephi,"], ["pe ua sauni e Moronae,", "or that Moroni,"], ["ana tagata ma ufifatafata ma talitaogalima,", "had prepared his people with breastplates and with arm– shields,"], ["ioe,", "yea,"], ["ma talita foi e puipui ai o latou ulu,", "and also shields to defend their heads,"], ["ma ua latou oofu foi i ofu mafiafia—", "and also they were dressed with thick clothing—"]]},
  {num:20,words:[["O lenei sa lei saunia le autau a Sera'emina i ni mea faapea;", "Now the army of Zerahemnah was not prepared with any such thing;"], ["sa nao a latou pelu,", "they had only their swords and their cimeters,"], ["ma a latou simetea, ma a latou aufana,", "their bows and their arrows,"], ["ma a latou ufanafana,", "their stones and their slings;"], ["ma a latou maa ma a latou maata sa ia te i latou;", "and they were naked,"], ["ma sa latou le lavalava,", "save it were a skin which was girded about their loins;"], ["vagana ai se pau manu sa fusi i o latou sulugatiti; ioe,", "yea,"], ["sa le lavalava uma i latou,", "all were naked,"], ["vagana ai sa Soramā ma sa Amalekā;", "save it were the Zoramites and the Amalekites;"]]},
  {num:21,words:[["Ae sa lei faaauupegaina i latou i ni ufifatafata,", "But they were not armed with breastplates,"], ["po o ni talita—o lea,", "nor shields — therefore,"], ["sa latou matua fefefe tele ai i autau a sa Nifaē ona o o latou ofutau,", "they were exceedingly afraid of the armies of the Nephites because of their armor,"], ["e ui ina sa silisili mamao atu lo latou toatele nai lo sa Nifaē.", "notwithstanding their number being so much greater than the Nephites."]]},
  {num:22,words:[["Faauta,", "Behold,"], ["o lenei sa oo ina latou fefefe e o mai e faasaga ia sa Nifaē i tuaoi o Seasona;", "now it came to pass that they durst not come against the Nephites in the borders of Jershon;"], ["o lea na latou o ese atu ai i fafo mai le laueleele o Anetionuma i le vao,", "therefore they departed out of the land of Antionum into the wilderness,"], ["ma alu la latou malaga taamilo atu i le vao,", "and took their journey round about in the wilderness,"], ["e mamao i tafatafa ane o le mata o le vaitafe o Saitonu,", "away by the head of the river Sidon,"], ["ina ia mafai ona latou o mai i le laueleele o Maneti ma ave le laueleele mo i latou;", "that they might come into the land of Manti and take possession of the land;"], ["ona sa latou le manatu e iloa e autau a Moronae le mea ua latou o i ai.", "for they did not suppose that the armies of Moroni would know whither they had gone."]]},
  {num:23,words:[["Peitai sa oo ina o le taimi lava na latou o ese atu ai i le vao na auina atu ai e Moronae ni sipai i le vao e matai la latou togalauapi;", "But it came to pass,"], ["ma o Moronae,", "as soon as they had departed into the wilderness Moroni sent spies into the wilderness to watch their camp; and Moroni,"], ["i lona iloa foi e uiga i valoaga a Alema,", "also,"], ["sa ia auina atu ni tagata faapitoa ia te ia,", "knowing of the prophecies of Alma, sent certain men unto him,"], ["e manao ia te ia ia ole atu o ia i le Alii po o fea e tatau ona o i ai autau a sa Nifaē e puipuia ai i latou lava e faasaga ia sa Lamanā.", "desiring him that he should inquire of the Lord whither the armies of the Nephites should go to defend themselves against the Lamanites."]]},
  {num:24,words:[["Ma sa oo ina oo mai le afioga a le Alii ia Alema,", "And it came to pass that the word of the Lord came unto Alma,"], ["ma sa tau atu e Alema i avefeau a Moronae,", "and Alma informed the messengers of Moroni,"], ["o loo savali taamilo atu autau a sa Lamanā i le vao,", "that the armies of the Lamanites were marching round about in the wilderness,"], ["ina ia mafai ona latou o mai i le laueleele o Maneti,", "that they might come over into the land of Manti,"], ["ina ia mafai ona latou amata se osofaiga i luga o le vaega sili ona vaivai o le nuu. Ma sa o atu ia avefeau ma avatu le savali ia Moronae.", "that they might commence an attack upon the weaker part of the people. And those messengers went and delivered the message unto Moroni."]]},
  {num:25,words:[["O lenei,", "Now Moroni,"], ["sa tuu e Moronae se vaega o lana autau i le laueleele o Seasona,", "leaving a part of his army in the land of Jershon,"], ["ina nei o mai se vaega o sa Lamanā i le laueleele ma latou ave le aai mo i latou,", "lest by any means a part of the Lamanites should come into that land and take possession of the city,"], ["ma ia ave le vaega na toe o lana autau ma savavali atu i le laueleele o Maneti.", "took the remaining part of his army and marched over into the land of Manti."]]},
  {num:26,words:[["Ma sa ia faatonu atu e tatau i tagata uma o loo i lena vaega o le laueleele ona latou faapotopoto faatasi i latou lava e tau e tetee ia sa Lamanā,", "And he caused that all the people in that quarter of the land should gather themselves together to battle against the Lamanites,"], ["e puipui ai o latou laueleele ma lo latou atunuu,", "to defend their lands and their country,"], ["o a latou aia ma o latou saolotoga;", "their rights  and their liberties;"], ["o lea na latou saunia ai aua le taimi e o mai ai sa Lamanā.", "therefore they were prepared against the time of the coming of the Lamanites."]]},
  {num:27,words:[["Ma sa oo ina faatonu atu Moronae ia lalafi lana autau i le vanu lea sa latalata ane i le auvai o le vaitafe o Saitonu,", "And it came to pass that Moroni caused that his army should be secreted in the valley which was near the bank of the river Sidon,"], ["lea sa i le itu i sisifo o le vaitafe o Saitonu i le vao.", "which was on the west of the river Sidon in the wilderness."]]},
  {num:28,words:[["Ma sa tuu e Moronae sipai e faataamilo ai,", "And Moroni placed spies round about,"], ["ina ia mafai ona ia iloa le taimi e o mai ai le togalauapi a sa Lamanā.", "that he might know when the camp of the Lamanites should come."]]},
  {num:29,words:[["Ma o lenei,", "And now,"], ["ina ua iloa e Moronae le faamoemoe o sa Lamanā,", "as Moroni knew the intention of the Lamanites,"], ["ma o lo latou faamoemoe o le faaumatia lea o o latou uso,", "that it was their intention to destroy their brethren,"], ["po o le pulea lea o i latou ma aumai i latou i le pologa ina ia mafai ona latou faatu o se malo mo i latou lava i luga o le laueleele atoa;", "or to subject them and bring them into bondage that they might establish a kingdom unto themselves over all the land;"]]},
  {num:30,words:[["Ma ona ua ia iloa foi ona pau lava le manao o sa Nifaē o le faasaoina lea o o latou laueleele,", "And he also knowing that it was the only desire of the Nephites to preserve their lands,"], ["ma lo latou saolotoga ,", "and their liberty,"], ["ma la latou ekalesia,", "and their church,"], ["o lea na ia manatu ai e le o se agasala le tatau ai ia te ia le puipuia o i latou i se togafiti;", "therefore he thought it no sin that he should defend them by stratagem;"], ["o lea,", "therefore,"], ["sa ia iloa mai i ana sipai le ala o le a ui atu ai sa Lamanā.", "he found by his spies which course the Lamanites were to take."]]},
  {num:31,words:[["O lea,", "Therefore,"], ["na ia vaelua ai lana autau ma aumai se vaega i totonu o le vanu,", "he divided his army and brought a part over into the valley,"], ["ma faalalafi i latou i le itu i sasae,", "and concealed them on the east,"], ["ma le itu i saute o le maupuepue o Ripela;", "and on the south of the hill Riplah;"]]},
  {num:32,words:[["Ma o le vaega na totoe sa ia faalalafi i le vanu i sisifo,", "And the remainder he concealed in the west valley,"], ["i le itu i sisifo o le vaitafe o Saitonu,", "on the west of the river Sidon,"], ["ma faapea lava ona fai sei oo atu i lalo i tuaoi o le laueleele o Maneti.", "and so down into the borders of the land Manti."]]},
  {num:33,words:[["Ma ina ua uma ona faapea ona ia tuu o lana autau e tusa ma lona manao,", "And thus having placed his army according to his desire,"], ["sa saunia o ia e faafetaiai i latou.", "he was prepared to meet them."]]},
  {num:34,words:[["Ma sa oo ina o ae sa Lamanā i luga o le itu i matu o le maupuepue,", "And it came to pass that the Lamanites came up on the north of the hill,"], ["lea sa lalafi ai se vaega o le autau a Moronae.", "where a part of the army of Moroni was concealed."]]},
  {num:35,words:[["Ma ina ua pasia e sa Lamanā le maupuepue o Ripela,", "And as the Lamanites had passed the hill Riplah,"], ["ma o mai i totonu o le vanu,", "and came into the valley,"], ["ma amata ona latou sopoia le vaitafe o Saitonu,", "and began to cross the river Sidon,"], ["o le autau lea sa lalafi i le itu i saute o le maupuepue,", "the army which was concealed on the south of the hill,"], ["lea sa taitai e se tagata e igoa ia Liae ,", "which was led by a man whose name was Lehi,"], ["sa ia taitai atu lana autau ma sio mai tua o sa Lamanā i le itu i sasae.", "and he led his army forth and encircled the Lamanites about on the east in their rear."]]},
  {num:36,words:[["Ma sa oo ina ua vaai mai sa Lamanā,", "And it came to pass that the Lamanites,"], ["ua o mai sa Nifaē i luga i o latou tua,", "when they saw the Nephites coming upon them in their rear,"], ["sa latou liliu mai ma amata ona tau ma le autau a Liae.", "turned them about and began to contend with the army of Lehi."]]},
  {num:37,words:[["Ma sa amata ona faia o le galuega o le fasi oti i itu uma e lua,", "And the work of death commenced on both sides,"], ["ae sa sili atu ona matautia i le vaega a sa Lamanā,", "but it was more dreadful on the part of the Lamanites,"], ["ona sa aliali lo latou le lavalava i ta mamafa a sa Nifaē ia latou pelu ma a latou simetea,", "for their nakedness was exposed to the heavy blows of the Nephites with their swords and their cimeters,"], ["lea na toe a ta ai lava ma le oti.", "which brought death almost at every stroke."]]},
  {num:38,words:[["A'o i le tasi itu,", "While on the other hand,"], ["sa i ai ni tagata i totonu o sa Nifaē sa pauu i 'i ma 'o,", "there was now and then a man fell among the Nephites,"], ["ia latou pelu ma le masaa o le toto,", "by their swords and the loss of blood,"], ["ona sa talitaina vaega tau o le ola o o latou tino,", "they being shielded from the more vital parts of the body,"], ["pe ona sa talitaina vaega tau o le ola o o latou tino mai ta a sa Lamanā,", "or the more vital parts of the body being shielded from the strokes of the Lamanites,"], ["e o latou ufifatafata ,", "by their breastplates,"], ["ma a latou talitaogalima,", "and their armshields,"], ["ma latou puloutau;", "and their head– plates;"], ["ma sa faapea ona faia e sa Nifaē le galuega o le oti i totonu o sa Lamanā.", "and thus the Nephites did carry on the work of death among the Lamanites."]]},
  {num:39,words:[["Ma sa oo ina fefefe sa Lamanā,", "And it came to pass that the Lamanites became frightened,"], ["ona o le tele o le faafanoga i totonu o i latou,", "because of the great destruction among them,"], ["seia oo ina amata ona latou sosola agai i le vaitafe o Saitonu.", "even until they began to flee towards the river Sidon."]]},
  {num:40,words:[["Ma sa tuliloa i latou e Liae ma ana tagata;", "And they were pursued by Lehi and his men;"], ["ma sa tutuli i latou e Liae i le vaitafe o Saitonu,", "and they were driven by Lehi into the waters of Sidon,"], ["ma sa latou sopoia le vaitafe o Saitonu. Ma sa taofi e Liae lana autau i luga o le auvai o le vaitafe o Saitonu ina ia latou le sopoiaina.", "and they crossed the waters of Sidon. And Lehi retained his armies upon the bank of the river Sidon that they should not cross."]]},
  {num:41,words:[["Ma sa oo ina faafetaiai sa Lamanā e Moronae ma lana autau i le vanu,", "And it came to pass that Moroni and his army met the Lamanites in the valley,"], ["i le isi itu o le vaitafe o Saitonu,", "on the other side of the river Sidon,"], ["ma amata ona pauu ifo i o latou luga ma fasioti i latou.", "and began to fall upon them and to slay them."]]},
  {num:42,words:[["Ma sa toe sosola sa Lamanā i o latou luma,", "And the Lamanites did flee again before them,"], ["agai i le laueleele o Maneti,", "towards the land of Manti;"], ["ma sa toe faafetaiai i latou e autau a Moronae.", "and they were met again by the armies of Moroni."]]},
  {num:43,words:[["O lenei,", "Now in this case the Lamanites did fight exceedingly;"], ["i le tulaga lenei, sa matua tau malolosi ai lava sa Lamanā;", "yea,"], ["ioe,", "never had the Lamanites been known to fight with such exceedingly great strength and courage,"], ["sa lei iloa lava se tau faapea o sa Lamana ma le malolosi tele ma le totoa, e leai,", "no,"], ["sa lei faapea lava mai le amataga.", "not even from the beginning."]]},
  {num:44,words:[["Ma sa musuia i latou e sa Soramā ma sa Amalekā,", "And they were inspired by the Zoramites and the Amalekites,"], ["o e o o latou kapeteni sili ma taitai,", "who were their chief captains and leaders,"], ["ma Sera'emina,", "and by Zerahemnah,"], ["o le o lo latou kapeteni sili,", "who was their chief captain,"], ["po o lo latou taitai silisili ma taitai au;", "or their chief leader and commander;"], ["ioe,", "yea,"], ["sa latou tau e pei o tarako,", "they did fight like dragons,"], ["ma e toatele sa Nifaē na fasiotia i o latou lima,", "and many of the Nephites were slain by their hands,"], ["ioe,", "yea,"], ["ona sa latou taisiluaina le tele o o latou puloutau,", "for they did smite in two many of their head– plates,"], ["ma sa latou tuiati le tele o o latou ufifatafata,", "and they did pierce many of their breastplates,"], ["ma sa latou sala ese le tele o o latou lima;", "and they did smite off many of their arms;"], ["ma sa faapea ona ta mai o sa Lamanā i lo latou ita tele.", "and thus the Lamanites did smite in their fierce anger."]]},
  {num:45,words:[["E ui i lea,", "Nevertheless,"], ["sa musuia sa Nifaē i se pogai e sili atu ona lelei, ona sa latou le tau mo se pule toatasi po o le pule,", "the Nephites were inspired by a better cause,"], ["ae sa latou tau mo o latou aiga ma o latou saolotoga ,", "for they were not fighting for monarchy nor power but they were fighting for their homes and their liberties,"], ["a latou ava,", "their wives and their children,"], ["ma a latou fanau,", "and their all,"], ["ma a latou mea uma, ioe,", "yea,"], ["mo a latou sauniga o tapuaiga ma la latou ekalesia.", "for their rites of worship and their church."]]},
  {num:46,words:[["Ma sa latou faia le mea sa latou lagona o se tiute ua latou nonofo aitalafu ai i lo latou Atua;", "And they were doing that which they felt was the duty which they owed to their God;"], ["ona sa fetalai mai le Alii ia te i latou,", "for the Lord had said unto them,"], ["ma i o latou tamā foi,", "and also unto their fathers,"], ["e faapea:", "that:"], ["Talu ai ona tou te lei sala i le oso muamua,", "Inasmuch as ye are not guilty of the first offense,"], ["pe o le lona lua,", "neither the second,"], ["ia aua ne'i o outou tuu outou lava ia fasiotia e lima o o outou fili.", "ye shall not suffer yourselves to be slain by the hands of your enemies."]]},
  {num:47,words:[["O lenei foi,", "And again,"], ["sa fetalai mai le Alii e faapea:", "the Lord has said that:"], ["Ia outou puipui o outou aiga e oo lava i le faamasaaina o le toto. O lea o le pogai lenei na tau ai sa Nifaē e faasaga ia sa Lamanā,", "Ye shall defend your families even unto bloodshed. Therefore for this cause were the Nephites contending with the Lamanites,"], ["e puipui i latou lava,", "to defend themselves,"], ["ma o latou aiga,", "and their families,"], ["ma o latou laueleele,", "and their lands,"], ["lo latou atunuu,", "their country,"], ["ma a latou aia,", "and their rights,"], ["ma la latou tapuaiga.", "and their religion."]]},
  {num:48,words:[["Ma sa oo ina ua vaai atu tagata a Moronae i le aasa ma le ita o sa Lamanā,", "And it came to pass that when the men of Moroni saw the fierceness and the anger of the Lamanites,"], ["sa latou tau tuumuli ma sosola mai ia te i latou. Ma o Moronae,", "they were about to shrink and flee from them. And Moroni,"], ["ina ua iloa e ia o latou faamoemoe,", "perceiving their intent,"], ["sa ia auina atu se faalototelega ma musuia o latou loto i manatu nei—ioe,", "sent forth and inspired their hearts with these thoughts—yea,"], ["o manatu i o latou laueleele,", "the thoughts of their lands,"], ["lo latou saoloto,", "their liberty,"], ["ioe,", "yea,"], ["lo latou saolotoga mai le pologa.", "their freedom from bondage."]]},
  {num:49,words:[["Ma sa oo ina latou liliu atu i luga o sa Lamanā,", "And it came to pass that they turned upon the Lamanites,"], ["ma sa latou alalaga atu faatasi i le leo e tasi i le Alii lo latou Atua,", "and they cried with one voice unto the Lord their God,"], ["mo lo latou saoloto ma lo latou saolotoga mai le pologa.", "for their liberty and their freedom from bondage."]]},
  {num:50,words:[["Ma sa amata ona latou tutu faasaga atu ma le malosi ia sa Lamanā;", "And they began to stand against the Lamanites with power;"], ["ma i totonu o lena lava itula na latou alalaga atu ai i le Alii mo lo latou saolotoga,", "and in that selfsame hour that they cried unto the Lord for their freedom,"], ["na amata ai ona sosola o sa Lamanā mai i o latou luma;", "the Lamanites began to flee before them;"], ["ma sa latou sosola sei oo lava i vai o Saitonu.", "and they fled even to the waters of Sidon."]]},
  {num:51,words:[["O lenei,", "Now,"], ["sa sili atu le toatele o sa Lamanā,", "the Lamanites were more numerous,"], ["ioe,", "yea,"], ["sa sili atu i le faaluaina o le aofai o sa Nifaē;", "by more than double the number of the Nephites;"], ["e ui i lea,", "nevertheless,"], ["sa tutulia i latou sa oo ina latou faapotopoto faatasi i se tino e tasi i le vanu,", "they were driven insomuch that they were gathered together in one body in the valley,"], ["i luga o le auvai i tafatafa o le vaitafe o Saitonu.", "upon the bank by the river Sidon."]]},
  {num:52,words:[["O lea na sio faataamilo ai i latou e autau a Moronae,", "Therefore the armies of Moroni encircled them about,"], ["ioe,", "yea,"], ["i itu uma e lua o le vaitafe,", "even on both sides of the river,"], ["aua faauta,", "for behold,"], ["o le itu i sasae sa i ai tagata a Liae.", "on the east were the men of Lehi."]]},
  {num:53,words:[["O lea ina ua vaai mai Sera'emina i tagata a Liae i le itu i sasae o le vaitafe o Saitonu,", "Therefore when Zerahemnah saw the men of Lehi on the east of the river Sidon,"], ["ma autau a Moronae i le itu i sisifo o le vaitafe o Saitonu,", "and the armies of Moroni on the west of the river Sidon,"], ["ma ua sio faataamilo i latou e sa Nifaē,", "that they were encircled about by the Nephites,"], ["sa taia i latou i le matau tele.", "they were struck with terror."]]},
  {num:54,words:[["O lenei o Moronae,", "Now Moroni,"], ["ina ua vaai atu o ia i lo latou matatau tele,", "when he saw their terror,"], ["sa ia faatonu ai ana tagata ia latou taofi le faamasaaina o o latou toto.", "commanded his men that they should stop shedding their blood."]]},
];
renderVerseSet(al_ch_43_Verses, 'al-ch43-verses');

var al_ch_44_Verses = [
  {num:1,words:[["Ma sa oo ina latou taofi ma solomuli i tua mai ia te i latou i sina va itiiti. Ma sa fai atu Moronae ia Sera'emina:", "And it came to pass that they did stop and withdrew a pace from them. And Moroni said unto Zerahemnah:"], ["Faauta,", "Behold,"], ["Sera'emina,", "Zerahemnah,"], ["matou te le mananao ia avea i matou ma tagata faamasaatoto. Ua e iloa ua outou i ai i o matou lima,", "that we do not desire to be men of blood. Ye know that ye are in our hands,"], ["peitai matou te le mananao e fasioti outou.", "yet we do not desire to slay you."]]},
  {num:2,words:[["Faauta,", "Behold,"], ["matou te lei o mai e tau faasaga ia te outou ina ia mafai ona matou faamasaa o outou toto mo le pule;", "we have not come out to battle against you that we might shed your blood for power;"], ["pe matou te mananao foi e aumai se tasi i le amo o le pologa. Peitai o le pogai tonu lava lea ua outou o mai ai e faasaga mai ia te i matou;", "neither do we desire to bring any one to the yoke of bondage. But this is the very cause for which ye have come against us;"], ["ioe,", "yea,"], ["ma ua outou feita ia te i matou ona o la matou tapuaiga.", "and ye are angry with us because of our religion."]]},
  {num:3,words:[["Ae o lenei,", "But now,"], ["ua outou vaai ua faatasi le Alii ma i matou;", "ye behold that the Lord is with us;"], ["ma ua outou vaai ua ia tuuina mai outou i o matou lima. Ma o lenei ou te manao ia outou malamalama ua faia lenei mea ia te i matou ona o la matou tapuaiga ma lo matou faatuatua ia Keriso. Ma o lenei ua outou vaai e le mafai ona outou faaumatiaina lo matou nei faatuatuaga.", "and ye behold that he has delivered you into our hands. And now I would that ye should understand that this is done unto us because of our religion and our faith in Christ. And now ye see that ye cannot destroy this our faith."]]},
  {num:4,words:[["O lenei ua outou vaai,", "Now ye see that this is the true faith of God;"], ["o le faatuatuaga moni lenei i le Atua;", "yea,"], ["ioe,", "ye see that God will support,"], ["ua outou vaai o le a lagolagoina,", "and keep,"], ["ma tausia, ma faasaoina i matou e le Atua,", "and preserve us,"], ["pe afai matou te faamaoni ia te ia,", "so long as we are faithful unto him,"], ["ma lo matou faatuatuaga,", "and unto our faith,"], ["ma la matou tapuaiga;", "and our religion;"], ["ma o le a le tuuina lava e le Alii ia faaumatiaina i matou vagana ai ua matou pauu atu i le solitulafono ma faafiti lo matou faatuatuaga.", "and never will the Lord suffer that we shall be destroyed except we should fall into transgression and deny our faith."]]},
  {num:5,words:[["Ma o lenei,", "And now,"], ["Sera'emina,", "Zerahemnah,"], ["ou te faatonu atu ia te oe,", "I command you,"], ["i le suafa o lena Atua mamana-aoao,", "in the name of that all– powerful God,"], ["o le na faamalolosia o matou lima ua matou maua ai le mana i o outou luga,", "who has strengthened our arms that we have gained power over you,"], ["i lo matou faatuatua,", "by our faith,"], ["i la matou tapuaiga,", "by our religion, and by our rites of worship,"], ["ma ia matou sauniga o le tapuaiga,", "and by our church,"], ["ma i la matou ekalesia,", "and by the sacred support which we owe to our  wives and our children,"], ["ma i le tausiga paia ua matou nonofo aitalafu ai ia matou ava ma a matou fanau,", "by that liberty which binds us to our lands and our country;"], ["i le saolotoga lena ua fusia ai i matou i o matou laueleele ma lo matou atunuu;", "yea,"], ["ioe,", "and also by the maintenance of the sacred word of God,"], ["ma i le tausiga foi o le afioga paia a le Atua lea ua matou nonofo aitalafu ai mo lo matou fiafia atoa;", "to which we owe all our happiness;"], ["ma i mea uma ua sili ona pele ia te i matou—", "and by all that is most dear unto us—"]]},
  {num:6,words:[["Ioe,", "Yea,"], ["ma ua le ona pau lea;", "and this is not all;"], ["ou te faatonu atu ia te outou i manaoga uma ua ia te outou mo le fia ola,", "I command you by all the desires which ye have for life,"], ["ia outou tuu mai a outou auupega o le taua ia te i matou,", "that ye deliver up your weapons of war unto us,"], ["ma o le a matou le sailia o outou toto,", "and we will seek not your blood,"], ["ae o le a matou faasaoina o outou ola,", "but we will spare your lives,"], ["pe afai tou te o i lo outou ala ma le toe o mai e tau faasaga mai ia te i matou.", "if ye will go your way and come not again to war against us."]]},
  {num:7,words:[["Ma o lenei,", "And now,"], ["afai tou te le faia lenei mea,", "if ye do not this,"], ["faauta,", "behold,"], ["ua outou i ai i o matou lima,", "ye are in our hands,"], ["ma o le a ou faatonu atu i ou tagata ia latou o atu ia te outou,", "and I will command my men that they shall fall upon you,"], ["ma faaoo manua o le oti i o outou tino,", "and inflict the wounds of death in your bodies,"], ["ina ia le toe i ai;", "that ye may become extinct;"], ["ma ona tatou vaai ai lea po o ai o le a i ai le mana i luga o lenei nuu;", "and then we will see who shall have power over this people;"], ["ioe,", "yea,"], ["o le a tatou vaai po o ai o le a aumai i le pologa.", "we will see who shall be brought into bondage."]]},
  {num:8,words:[["Ma o lenei sa oo ina ua uma ona faalogo mai o Sera'emina i nei upu sa sau o ia i luma ma tuu mai lana pelu ma lana simetea,", "And now it came to pass that when Zerahemnah had heard these sayings he came forth and delivered up his sword and his cimeter,"], ["ma lana aufana i lima o Moronae,", "and his bow into the hands of Moroni,"], ["ma fai mai ia te ia:", "and said unto him:"], ["Faauta,", "Behold,"], ["o a matou auupega ia o taua;", "here are our weapons of war;"], ["o le a matou tuu atu ia te outou,", "we will deliver them up unto you,"], ["ae o le a matou le tuuina atu i matou lava e fai se tautoga ia te outou,", "but we will not suffer ourselves to take an oath unto you,"], ["ua matou iloa o le a matou solia,", "which we know that we shall break,"], ["ma a matou fanau foi;", "and also our children;"], ["ae ave a matou auupega o taua,", "but take our weapons of war,"], ["ma tuu mai ia mafai ona matou o atu i le vao;", "and suffer that we may depart into the wilderness;"], ["a leai o le a matou taofia a matou pelu,", "otherwise we will retain our swords,"], ["ma o le a matou fano pe manumalo.", "and we will perish or conquer."]]},
  {num:9,words:[["Faauta,", "Behold,"], ["e le o i matou o ni o la outou faatuatuaga;", "we are not of your faith;"], ["matou te le talitonu o le Atua na ia tuuina atu i matou i o outou lima;", "we do not believe that it is God that has delivered us into your hands;"], ["ae matou te talitonu o lo outou popoto ua faasaoina ai outou mai ia matou pelu. Faauta,", "but we believe that it is your cunning that has preserved you from our swords. Behold,"], ["o a outou ufifatafata ma a outou talita ua faasaoina ai outou.", "it is your breastplates and your shields that have preserved you."]]},
  {num:10,words:[["Ma o lenei ina ua uma ona faaiu e Sera'emina le tautala mai o nei upu,", "And now when Zerahemnah had made an end of speaking these words,"], ["sa toe faafoi atu e Moronae le pelu ma auupega o le taua,", "Moroni returned the sword and the weapons of war,"], ["ia na ia talia,", "which he had received,"], ["ia Sara'emina,", "unto Zerahemnah,"], ["ma fai atu:", "saying:"], ["Faauta,", "Behold,"], ["o le a tatou faauma le taua.", "we will end the conflict."]]},
  {num:11,words:[["O lenei e le mafai ona ou toe faafoi mai upu sa ou tautala atu ai,", "Now I cannot recall the words which I have spoken,"], ["o lea e pei ona soifua le Alii,", "therefore as the Lord liveth,"], ["e le mafai ona outou o ese atu vagana ai ua outou o ese atu ma se tautoga o le a outou le toe foi mai e faasaga mai ia te i matou e tau.", "ye shall not depart except ye depart with an oath that ye will not return again against us to war."], ["O lenei, ona ua outou i ai i o matou lima o le a matou faamasaa o outou toto i luga o le eleele,", "Now as ye are in our hands we will spill your blood upon the ground,"], ["po o lo outou ioe mai i tulaga ia na ou ofo atu.", "or ye shall submit to the conditions which I have proposed."]]},
  {num:12,words:[["Ma o lenei ina ua uma ona fai atu e Moronae o nei upu,", "And now when Moroni had said these words,"], ["sa taofi e Sera'emina lana pelu,", "Zerahemnah retained his sword,"], ["ma sa ita o ia ia Moronae,", "and he was angry with Moroni,"], ["ma sa oso mai o ia i luma ina ia mafai ona ia fasioti ia Moronae;", "and he rushed forward that he might slay Moroni;"], ["ae ina o sii a'e e ia lana pelu,", "but as he raised his sword,"], ["faauta,", "behold,"], ["sa ta e se tasi o fitafita a Moronae i le eleele,", "one of Moroni's soldiers smote it even to the earth,"], ["ma sa gau latalata i lona au;", "and it broke by the hilt;"], ["ma sa ia sogi foi Sera'emina sa oo ina ia aveese ai lona tumuai ma pau i le eleele. Ma sa solomuli Sera'emina mai i o latou luma i totonu o le lotolotoi o ana fitafita.", "and he also smote Zerahemnah that he took off his scalp and it fell to the earth. And Zerahemnah withdrew from before them into the midst of his soldiers."]]},
  {num:13,words:[["Ma sa oo ina tago atu le fitafita sa tu latalata ane,", "And it came to pass that the soldier who stood by,"], ["o le na ia sala ese le tumuai o Sera'emina,", "who smote off the scalp of Zerahemnah,"], ["ma uu ae i luga le tumuai mai le eleele i lauulu,", "took up the scalp from off the ground by the hair,"], ["ma faataatia i luga o le mata o lana pelu,", "and laid it upon the point of his sword,"], ["ma faaloaloa atu ia te i latou,", "and stretched it forth unto them,"], ["ma fai atu ia te i latou i se leo tele:", "saying unto them with a loud voice:"]]},
  {num:14,words:[["E pei ona pau le tumuai lenei i le eleele,", "Even as this scalp has fallen to the earth,"], ["o le tumuai lea o lo outou taitai,", "which is the scalp of your chief,"], ["o le a faapea lava ona outou pauu i le eleele vagana ai o le a outou tuu mai a outou auupega o le taua ma o ese atu ma se feagaiga o le filemu.", "so shall ye fall to the earth except ye will deliver up your weapons of war and depart with a covenant of peace."]]},
  {num:15,words:[["O lenei e toatele na i ai,", "Now there were many,"], ["ina ua latou faalogo mai i nei upu ma vaai mai i le tumuai lea sa i luga o le pelu,", "when they heard these words and saw the scalp which was upon the sword,"], ["sa taia i le matau;", "that were struck with fear;"], ["ma e toatele na o mai i luma ma lafo i lalo a latou auupega o taua i vae o Moronae,", "and many came forth and threw down their weapons of war at the feet of Moroni,"], ["ma ulu atu i se feagaiga o le filemu. Ma o le toatele o i latou na ulu atu i le feagaiga sa latou tuu e o ese atu i le vao.", "and entered into a covenant of peace. And as many as entered into a covenant they suffered to depart into the wilderness."]]},
  {num:16,words:[["O lenei sa oo ina ita tele Sera'emina,", "Now it came to pass that Zerahemnah was exceedingly wroth,"], ["ma sa ia faaoso le vaega na totoe o ana fitafita i le ita,", "and he did stir up the remainder of his soldiers to anger,"], ["e tau ma le malolosi silisili atu e faasaga ia sa Nifaē.", "to contend more powerfully against the Nephites."]]},
  {num:17,words:[["Ma o lenei sa ita Moronae,", "And now Moroni was angry,"], ["ona o le finauvale o sa Lamanā;", "because of the stubbornness of the Lamanites;"], ["o lea na ia faatonu ai ana tagata ia latou o atu i o latou luga ma fasioti i latou. Ma sa oo ina amata ona latou fasioti i latou;", "therefore he commanded his people that they should fall upon them and slay them. And it came to pass that they began to slay them;"], ["ioe,", "yea,"], ["ma sa tau sa Lamanā ma a latou pelu ma lo latou malosi.", "and the Lamanites did contend with their swords and their might."]]},
  {num:18,words:[["Ae faauta,", "But behold,"], ["sa aliali o latou pau le lavalava ma o latou ulu e le ufiufia i pelu maai a sa Nifaē;", "their naked skins and their bare heads were exposed to the sharp swords of the Nephites;"], ["ioe,", "yea,"], ["faauta,", "behold they were pierced and smitten,"], ["sa tuia ma taiaina i latou, ioe,", "yea,"], ["ma sa vave lava ona latou pauu i pelu a sa Nifaē;", "and did fall exceedingly fast before the swords of the Nephites;"], ["ma sa amata ona salaina o i latou i lalo,", "and they began to be swept down,"], ["e pei lava ona sa valoia e le fitafita a Moronae.", "even as the soldier of Moroni had prophesied."]]},
  {num:19,words:[["O lenei o Sera'emina,", "Now Zerahemnah,"], ["ina ua ia vaai o le a tauau ina faaumatia i latou uma,", "when he saw that they were all about to be destroyed,"], ["sa ia alaga malosi mai ia Moronae, ua folafola mai o le a ia osifeagaiga,", "cried mightily unto Moroni,"], ["ma lona nuu foi faatasi ma i latou,", "promising that he would covenant and also his people with them,"], ["pe afai latou te faasaoina ola o e o totoe o i latou,", "if they would spare the remainder of their lives,"], ["o le a latou le toe o mai lava e tau faasaga mai ia te i latou.", "that they never would come to war again against them."]]},
  {num:20,words:[["Ma sa oo ina faatonu atu Moronae ia toe taofi le galuega o le fasi oti i totonu o tagata.", "And it came to pass that Moroni caused that the work of death should cease again among the people."], ["Ma sa ia ave auupega o taua mai ia sa Lamanā; ma ina ua uma ona latou ulu atu i se feagaiga o le filemu faatasi ma ia,", "And he took the weapons of war from the Lamanites;"], ["sa tuu atu i latou e o ese atu i le vao.", "and after they had entered into a covenant with him of peace they were suffered to depart into the wilderness."]]},
  {num:21,words:[["O lenei o le aofai o o latou tagata oti sa le faitauina ona o le toatele naua o le aofai;", "Now the number of their dead was not numbered because of the greatness of the number;"], ["ioe,", "yea,"], ["o le aofai o o latou tagata oti sa matua tele lava,", "the number of their dead was exceedingly great,"], ["i itu uma e lua o sa Nifaē ma sa Lamanā.", "both on the Nephites and on the Lamanites."]]},
  {num:22,words:[["Ma sa oo ina latou lafo o latou tagata oti i totonu o vai o Saitonu,", "And it came to pass that they did cast their dead into the waters of Sidon,"], ["ma sa tafefea atu i latou ma ua tanumia i le loloto o le sami.", "and they have gone forth and are buried in the depths of the sea."]]},
  {num:23,words:[["Ma o autau a sa Nifaē,", "And the armies of the Nephites,"], ["po o a Moronae,", "or of Moroni,"], ["sa toe foi mai ma o atu i o latou fale ma o latou laueleele.", "returned and came to their houses and their lands."]]},
  {num:24,words:[["Ma sa faapea ona iu o le lona sefulu valu o tausaga o le nofoaiga a faamasino i le nuu o Nifae. Ma ua faapea ona iu o le talafaamaumau a Alema,", "And thus ended the eighteenth year of the reign of the judges over the people of Nephi. And thus ended the record of Alma,"], ["lea na tusia i luga o papatusi a Nifae.", "which was written upon the plates of Nephi."]]},
];
renderVerseSet(al_ch_44_Verses, 'al-ch44-verses');

var al_ch_45_Verses = [
  {num:1,words:[["Faauta,", "Behold,"], ["o lenei sa oo ina olioli tele le nuu o Nifae,", "now it came to pass that the people of Nephi were exceedingly rejoiced,"], ["ona ua toe laveaiina i latou e le Alii mai lima o o latou fili;", "because the Lord had again delivered them out of the hands of their enemies;"], ["o lea na latou avatu ai le faafetai i le Alii lo latou Atua;", "therefore they gave thanks unto the Lord their God;"], ["ioe,", "yea,"], ["ma sa latou anapopogi soo ma sa tatalo tele,", "and they did fast much and pray much,"], ["ma sa latou tapuai atu i le Atua ma le olioli tele naua.", "and they did worship God with exceedingly great joy."]]},
  {num:2,words:[["Ma sa oo i le lona sefulu iva o tausaga o le nofoaiga a faamasino i le nuu o Nifae,", "And it came to pass in the nineteenth year of the reign of the judges over the people of Nephi,"], ["na sau ai Alema i lona atalii o Helamana ma fai atu ia te ia:", "that Alma came unto his son Helaman and said unto him:"], ["Ua e talitonu i upu na ou tautala atu ai ia te oe e uiga i na talafaamaumau ua tausia?", "Believest thou the words which I spake unto thee concerning those records which have been kept?"]]},
  {num:3,words:[["Ma sa fai atu Helamana ia te ia:", "And Helaman said unto him:"], ["Ioe,", "Yea,"], ["ua ou talitonu i ai.", "I believe."]]},
  {num:4,words:[["Ma sa toe fai mai Alema:", "And Alma said again:"], ["Ua e talitonu ia Iesu Keriso,", "Believest thou in Jesus Christ,"], ["le o le a afio mai?", "who shall come?"]]},
  {num:5,words:[["Ma sa fai atu o ia:", "And he said:"], ["Ioe,", "Yea,"], ["ua ou talitonu i upu uma na e tautala mai ai.", "I believe all the words which thou hast spoken."]]},
  {num:6,words:[["Ma sa toe fai mai Alema ia te ia:", "And Alma said unto him again:"], ["O le a e tausia ea au poloaiga?", "Will ye keep my commandments?"]]},
  {num:7,words:[["Ma sa fai atu o ia:", "And he said:"], ["Ioe,", "Yea,"], ["o le a ou tausia au poloaiga ma lou loto atoa.", "I will keep thy commandments with all my heart."]]},
  {num:8,words:[["Ona fai mai lea o Alema ia te ia:", "Then Alma said unto him:"], ["Amuia lava oe;", "Blessed art thou;"], ["ma o le a faamanuiaina oe e le Alii i lenei laueleele.", "and the Lord shall prosper thee in this land."]]},
  {num:9,words:[["Ae faauta,", "But behold,"], ["ua ia te au ni isi mea teisi ou te vavalo atu ia te oe;", "I have somewhat to prophesy unto thee;"], ["ae o mea ou te vavalo atu ai ia te oe ia aua nei e faailoa atu;", "but what I prophesy unto thee ye shall not make known;"], ["ioe,", "yea,"], ["o mea ou te vavalo atu ai ia te oe o le a le faailoa atu lava,", "what I prophesy unto thee shall not be made known,"], ["seia oo ina faataunuuina le valoaga;", "even until the prophecy is fulfilled;"], ["o lea ia tusi upu o le a ou fai atu ai.", "therefore write the words which I shall say."]]},
  {num:10,words:[["Ma o upu nei:", "And these are the words:"], ["Faauta,", "Behold,"], ["ua ou iloa,", "I perceive that this very people,"], ["o lenei lava nuu, o sa Nifaē,", "the Nephites,"], ["e tusa ma le agaga o faaaliga ua ia te au,", "according to the spirit of revelation which is in me,"], ["i le fa selau tausaga mai le taimi o le a faaali mai ai e Iesu Keriso o ia lava ia te i latou,", "in four hundred years from the time that Jesus Christ shall manifest himself unto them,"], ["o le a faaitiitia i le le talitonu.", "shall dwindle in unbelief."]]},
  {num:11,words:[["Ioe,", "Yea,"], ["ma ona latou vaai ai lea i taua ma faamai,", "and then shall they see wars and pestilences,"], ["ioe,", "yea,"], ["i oge ma le faamasaa toto,", "famines and bloodshed,"], ["seia oo lava ina le toe i ai le nuu o Nifae—", "even until the people of Nephi shall become extinct—"]]},
  {num:12,words:[["Ioe,", "Yea,"], ["ma o le pogai o lenei mea ona o le a faaitiitia i latou i le le talitonu ma pauu atu i galuega a le pouliuli,", "and this because they shall dwindle in unbelief and fall into the works of darkness,"], ["ma le mataaitu ,", "and lasciviousness,"], ["ma ituaiga o amioletonu uma;", "and all manner of iniquities;"], ["ioe,", "yea,"], ["ou te fai atu ia te oe, ona o le a latou agasala e faasaga i le malamalama ma le poto sili ona tele,", "I say unto you,"], ["ioe,", "that because they shall sin against so great light and knowledge,"], ["ou te fai atu ia te oe,", "yea,"], ["e mai i lena aso,", "I say unto you,"], ["e oo i le tupulaga lona fa,", "that from that day,"], ["o le a le mavae atu uma ae lei oo mai lenei amioletonu tele.", "even the fourth generation shall not all pass away before this great iniquity shall come."]]},
  {num:13,words:[["Ma a oo mai lena aso tele,", "And when that great day cometh,"], ["faauta,", "behold,"], ["e lata lava ona oo mai o le taimi, o i latou o e o i ai nei,", "the time very soon cometh that those who are now,"], ["po o fanau a i latou o e ua faitauina nei i totonu o tagata o Nifae,", "or the seed of those who are now numbered among the people of Nephi,"], ["o le a le toe faitauina i totonu o tagata o Nifae.", "shall no more be numbered among the people of Nephi."]]},
  {num:14,words:[["Ae o soo se tasi e totoe,", "But whosoever remaineth,"], ["ma ua le faaumatiaina i lena aso tele ma le matautia,", "and is not destroyed in that great and dreadful day,"], ["o le a faitauina i totonu o sa Lamanā,", "shall be numbered among the Lamanites,"], ["ma o le a avea e pei o i latou,", "and shall become like unto them,"], ["i latou uma,", "all,"], ["vagana ai ni isi e toaitiiti o e o le a taua o soo o le Alii;", "save it be a few who shall be called the disciples of the Lord;"], ["ma o i latou ia o le a saili e sa Lamanā seia oo lava ina latou le toe i ai. Ma o lenei,", "and them shall the Lamanites pursue even until they shall become extinct. And now,"], ["ona o le amioletonu,", "because of iniquity,"], ["o lenei valoaga o le a faataunuuina lava.", "this prophecy shall be fulfilled."]]},
  {num:15,words:[["Ma o lenei sa oo ina ua uma ona fai mai e Alema nei mea ia Helamana,", "And now it came to pass that after Alma had said these things to Helaman,"], ["sa ia faamanuia o ia,", "he blessed him,"], ["ma isi foi ona atalii;", "and also his other sons;"], ["ma sa ia faamanuia foi le eleele mo le manuia o e e amiotonu.", "and he also blessed the earth for the righteous' sake."]]},
  {num:16,words:[["Ma sa fai mai o ia:", "And he said:"], ["Ua faapea ona fetalai mai o le Alii le Atua—O le a fetuuina le laueleele,", "Thus saith the Lord God—Cursed shall be the land,"], ["ioe,", "yea,"], ["le laueleele lenei,", "this land,"], ["i atunuu,", "unto every nation,"], ["ituaiga,", "kindred,"], ["gagana,", "tongue,"], ["ma nuu uma,", "and people,"], ["e oo lava i le faaumatiaina o e fai amioleaga,", "unto destruction,"], ["pe a latou matua atoatoa;", "which do wickedly,"], ["ma e pei ona ou fai atu,", "when they are fully ripe;"], ["o le a faapea lava ona faia;", "and as I have said so shall it be;"], ["ona o le fetuu lenei ma le faamanuiaga a le Atua i luga o le laueleele,", "for this is the cursing and the blessing of God upon the land,"], ["ona e le mafai ona silasila o le Alii i le agasala ma se tikeri itiiti o le taliaina.", "for the Lord cannot look upon sin with the least degree of allowance."]]},
  {num:17,words:[["Ma o lenei,", "And now,"], ["ina ua uma ona fai mai e Alema o nei upu,", "when Alma had said these words he blessed the church,"], ["sa ia faamanuiaina le ekalesia , ioe,", "yea,"], ["i latou uma o e o le a tutumau mausali i le faatuatuaga mai i lena taimi e oo i le lumanai.", "all those who should stand fast in the faith from that time henceforth."]]},
  {num:18,words:[["Ma ina ua uma ona faia e Alema lenei mea sa ia alu ese atu i fafo o le laueleele o Sara'emila,", "And when Alma had done this he departed out of the land of Zarahemla,"], ["e peiseai e alu atu i le laueleele o Meleka. Ma sa oo ina le toe faalogoina se isi tala e uiga ia te ia;", "as if to go into the land of Melek. And it came to pass that he was never heard of more;"], ["ao lona oti po o lona tanuga ua matou le iloa se mea e uiga i ai.", "as to his death or burial we know not of."]]},
  {num:19,words:[["Faauta,", "Behold,"], ["o le mea lenei ua matou iloa,", "this we know,"], ["o ia o se tagata sa amiotonu;", "that he was a righteous man;"], ["ma sa alu se tala i le ekalesia atoa ua aveina ae o ia e le Agaga,", "and the saying went abroad in the church that he was taken up by the Spirit,"], ["pe ua tanumia o ia e le aao o le Alii,", "or buried by the hand of the Lord,"], ["e pei lava o Mose.", "even as Moses."], ["Ae faauta,", "But behold,"], ["ua fai mai tusitusiga paia sa aveina e le Alii Mose ia te ia lava;", "the scriptures saith the Lord took Moses unto himself;"], ["ma ua matou manatu ua ia talia foi Alema i le agaga, ia te ia lava;", "and we suppose that he has also received Alma in the spirit,"], ["o lea,", "unto himself;"], ["o le pogai lenei,", "therefore,"], ["ua matou le iloa ai se mea e uiga i lona maliu ma lona tanuga.", "for this cause we know nothing concerning his death and burial."]]},
  {num:20,words:[["Ma o lenei sa oo i le amataga o le lona sefulu iva o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae,", "And now it came to pass in the commencement of the nineteenth year of the reign of the judges over the people of Nephi,"], ["na alu atu ai Helamana i totonu o le nuu e talai atu le afioga ia te i latou.", "that Helaman went forth among the people to declare the word unto them."]]},
  {num:21,words:[["Aua faauta,", "For behold,"], ["ona o a latou taua ma sa Lamanā ma le tele o faatuiesega ma faalavelave laiti sa i ai i totonu o le nuu,", "because of their wars with the Lamanites and the many little dissensions and disturbances which had been among the people,"], ["o lea sa tatau ai ona talai atu o le afioga a le Atua i totonu o i latou,", "it became expedient that the word of God should be declared among them,"], ["ioe,", "yea,"], ["ma tatau ona faia ai o se faatonutonuga i le ekalesia atoa.", "and that a regulation should be made throughout the church."]]},
  {num:22,words:[["O lea,", "Therefore,"], ["na o atu ai Helamana ma ona uso e toe faatumauina le ekalesia i le laueleele atoa,", "Helaman and his brethren went forth to establish the church again in all the land,"], ["ioe,", "yea,"], ["i aai uma i le laueleele atoa sa maua e le nuu o Nifae. Ma sa oo ina latou tofia ni faitaulaga ma ni aoao i le laueleele atoa,", "in every city throughout all the land which was possessed by the people of Nephi. And it  came to pass that they did appoint priests and teachers throughout all the land,"], ["i luga o aulotu uma.", "over all the churches."]]},
  {num:23,words:[["Ma o lenei sa oo ina ua uma ona tofia e Helamana ma ona uso o faitaulaga ma aoao i luga o aulotu uma, sa oo ina tulai mai se faatuiesega i totonu o i latou,", "And now it came to pass that after Helaman and his brethren had appointed priests and teachers over the churches that there arose a dissension among them,"], ["ma sa latou le fia uai mai i upu a Helamana ma ona uso;", "and they would not give heed to the words of Helaman and his brethren;"]]},
  {num:24,words:[["Ae ua latou tutupu ae i le faamaualuluga,", "But they grew proud,"], ["i le faafefeteina o o latou loto,", "being lifted up in their hearts,"], ["ona o a latou oa e sili ona tele;", "because of their exceedingly great riches;"], ["o lea sa faateleina ai lo latou mauoa i o latou lava mata,", "therefore they grew rich in their own eyes,"], ["ma le fia uai atu ia latou upu,", "and would not give heed to their words,"], ["ia savavali ma le tonu i luma o le Atua.", "to walk uprightly before God."]]},
];
renderVerseSet(al_ch_45_Verses, 'al-ch45-verses');

var al_ch_46_Verses = [
  {num:1,words:[["Ma sa oo ina o le toatele o e sa le fia faalogo i upu a Helamana ma ona uso, sa faapotopoto faatasi e faasaga tetee i o latou uso.", "And it came to pass that as many as would not hearken to the words of Helaman and his brethren were gathered together against their brethren."]]},
  {num:2,words:[["Ma o lenei faauta,", "And now behold,"], ["sa latou feita tele,", "they were exceedingly wroth,"], ["sa oo ina latou mauai e fasioti i latou.", "insomuch that they were determined to slay them."]]},
  {num:3,words:[["O lenei o le taitai o i latou o e na feita e faasaga i o latou uso o se tagata tino ese ma le malosi;", "Now the leader of those who were wroth against their brethren was a large and a strong man;"], ["ma o lona igoa o Amalekia.", "and his name was Amalickiah."]]},
  {num:4,words:[["Ma sa manao Amalekia ia avea o ia ma tupu;", "And Amalickiah was desirous to be a king;"], ["ma o tagata ia o e sa feita sa latou mananao foi ia avea o ia ma o latou tupu;", "and those people who were wroth were also desirous that he should be their king;"], ["ma o le toatele o i latou o faamasino maualalalo o le laueleele,", "and they were the greater part of them the lower judges of the land,"], ["ma sa latou saili mo le pule.", "and they were seeking for power."]]},
  {num:5,words:[["Ma sa taitaiina i latou i upu faaviivii a Amalekia,", "And they had been led by the flatteries of Amalickiah,"], ["e faapea afai latou te lagolagoina o ia ma faatu o ia e avea ma o latou tupu o le a ia faia i latou ma pule i luga o le nuu.", "that if they would support him and establish him to be their king that he would make them rulers over the people."]]},
  {num:6,words:[["Sa faapea ona taitaieseina i latou e Amalekia i le faatuiese,", "Thus they were led away by Amalickiah to dissensions,"], ["e ui lava i le talaiga a Helamana ma ona uso,", "notwithstanding the preaching of Helaman and his brethren,"], ["ioe,", "yea,"], ["e ui lava i lo latou matua faaeteete tele i le leoleoina o le ekalesia,", "notwithstanding their exceedingly great care over the church,"], ["ona o i latou o faitaulaga sili o le ekalesia.", "for they were high priests over the church."]]},
  {num:7,words:[["Ma sa i ai le toatele i le ekalesia o e sa talitonu i upu faaviivii a Amalekia,", "And there were many in the church who believed in the flattering words of Amalickiah,"], ["o le mea lea na latou faatuiese atu ai lava mai le ekalesia;", "therefore they dissented even from the church;"], ["ma sa faapea ona lugā ma tugā tele ai mataupu o le nuu o Nifae,", "and thus were the affairs of the people of Nephi exceedingly precarious and dangerous,"], ["e ui i lo latou manumalo tele sa latou maua ia sa Lamanā,", "not– withstanding their great victory which they had had over the Lamanites,"], ["ma lo latou olioli tele sa maua ona o le laveaiina o i latou e le aao o le Alii.", "and their great rejoicings which they had had because of their deliverance by the hand of the Lord."]]},
  {num:8,words:[["Ua faapea ona tatou vaai ai i le vave tele ona galo i le fanauga a tagata o le Alii lo latou Atua,", "Thus we see how quick the children of men do forget the Lord their God,"], ["ioe,", "yea,"], ["le vave tele ona fai o le amioletonu,", "how quick to do iniquity,"], ["ma taitaieseina e le ua leaga.", "and to be led away by the evil one."]]},
  {num:9,words:[["Ioe,", "Yea,"], ["ma ua tatou vaai ai foi i le amioleaga tele e mafai e se tagata amioleaga e toatasi ona faatupuina i totonu o le fanauga a tagata.", "and we also see the great wickedness one very wicked man can cause to take place among the children of men."]]},
  {num:10,words:[["Ioe,", "Yea,"], ["ua tatou vaai o Amalekia,", "we see that Amalickiah,"], ["ona o ia o se tagata faitogafiti poto leaga ma o se tagata mauupu faaviivii,", "because he was a man of cunning device and a man of many flattering words,"], ["sa ia taitai ese ai loto o tagata e toatele e fai le amioleaga;", "that he led away the hearts of many people to do wickedly;"], ["ioe,", "yea,"], ["ma saili e faaumatia le ekalesia a le Atua,", "and to seek to destroy the church of God,"], ["ma faaumatia le faavae o le saolotoga lea na tuuina mai e le Atua ia te i latou,", "and to destroy the foundation of liberty which God had granted unto them,"], ["po o se faamanuiaga lea na auina mai e le Atua i luga o le laueleele mo le manuia o e e amiotonu.", "or which blessing God had sent upon the face of the land for the righteous' sake."]]},
  {num:11,words:[["Ma o lenei sa oo ina ua faalogo Moronae,", "And now it came to pass that when Moroni,"], ["o le sa avea ma taitaiau sili o autau a sa Nifaē,", "who was the chief commander of the armies of the Nephites,"], ["i nei faatuiesega,", "had heard of these dissensions,"], ["sa ita o ia ia Amalekia.", "he was angry with Amalickiah."]]},
  {num:12,words:[["Ma sa oo ina saeia e ia lona ofu;", "And it came to pass that he rent his coat;"], ["ma sa ia ave sina fasi mea,", "and he took a piece thereof,"], ["ma ia tusi ai i luga— mo le manatuaina o lo tatou Atua,", "and wrote upon it—In memory of our God,"], ["ma la tatou tapuaiga,", "our religion,"], ["ma le saolotoga,", "and freedom,"], ["ma lo tatou filemu,", "and our peace,"], ["a tatou ava,", "our wives,"], ["ma a tatou fanau—ma ia nonoaina i luga o le pito o se pou.", "and our children—and he fastened it upon the end of a pole."]]},
  {num:13,words:[["Ma sa ia faamaulu lona puloutau,", "And he fastened on his head– plate,"], ["ma lona ufifatafata,", "and his breastplate,"], ["ma ana talita,", "and his shields,"], ["ma sulu lona ofutau faataamilo i ona sulugatiti;", "and girded on his armor about his loins;"], ["ma sa ia ave le pou,", "and he took the pole,"], ["lea sa i ai i lona pito lona ofu ua sasae,", "which had on the end thereof his rent coat,"], ["(ma sa ia taua o le tagavai o le saolotoga) ma sa ifo o ia lava i le eleele,", "(and he called it the title of liberty) and he bowed himself to the earth,"], ["ma ia tatalo faatauanau atu i lona Atua mo faamanuiaga o le saolotoga ia malolo ifo i luga o ona uso,", "and he prayed mightily unto his God for the blessings of liberty to rest upon his brethren,"], ["pe afai e i ai pea se vaega o tagata Kerisiano e totoe e fai mo i latou le laueleele—", "so long as there should a band of Christians remain to possess the land—"]]},
  {num:14,words:[["Ona sa faapea ona taua o tagata uma sa talitonu moni ia Keriso,", "For thus were all the true believers of Christ,"], ["o e sa auai i le ekalesia a le Atua,", "who belonged to the church of God,"], ["e i latou o e sa le auai i le ekalesia.", "called by those who did not belong to the church."]]},
  {num:15,words:[["Ma o i latou o e sa auai i le ekalesia sa faamaoni;", "And those who did belong to the church were faithful;"], ["ioe,", "yea, all those who were true believers in Christ took upon them,"], ["o i latou uma o e sa talitonu moni ia Keriso sa latou ave ma le fiafia i o latou luga le suafa o Keriso,", "gladly,"], ["po o le au Kerisiano e pei ona sa taua ai i latou,", "the name of Christ, or Christians as they were called,"], ["ona o lo latou talitonu ia Keriso o le o le a afio mai.", "because of their belief in Christ who should come."]]},
  {num:16,words:[["Ma o lea,", "And therefore,"], ["na tatalo atu ai Moronae,", "at this time,"], ["i le taimi lea, ina ia mafai ona alofagia le faamoemoe o le au Kerisiano,", "Moroni prayed that the cause of the Christians,"], ["ma le saolotoga o le laueleele.", "and the freedom of the land might be favored."]]},
  {num:17,words:[["Ma sa oo ina ua uma ona ia sasaa atu lona agaga i le Atua,", "And it came to pass that when he had poured out his soul to God,"], ["sa ia taua le laueleele atoa lea sa i le itu i saute o le laueleele o Tuufua ,", "he named all the land which was south of the land Desolation,"], ["ioe,", "yea,"], ["ma i se aotelega,", "and in fine,"], ["le laueleele uma lea,", "all the land,"], ["i matu uma ma saute—O se laueleele filifilia,", "both on the north and on the south—A chosen land,"], ["ma laueleele o le saolotoga.", "and the land of liberty."]]},
  {num:18,words:[["Ma sa ia fai mai:", "And he said:"], ["E moni o le a le tuu lava e le Atua i tatou,", "Surely God shall not suffer that we,"], ["o e ua inosia ona ua tatou ave i o tatou luga le suafa o Keriso,", "who are despised because we take upon us the name of Christ,"], ["ia solia i tatou i lalo ma faaumatiaina,", "shall be trodden down and destroyed,"], ["vagana ai ua tatou aumaia i o tatou luga e ala ia tatou lava solitulafono.", "until we bring it upon us by our own transgressions."]]},
  {num:19,words:[["Ma ina ua uma ona fai mai e Moronae o nei upu,", "And when Moroni had said these words,"], ["sa ia alu atu i totonu o le nuu,", "he went forth among the people,"], ["ua faaagiagia atu i le ea le vaega o lona ofu na sasae,", "waving the rent part of his garment in the air,"], ["ina ia mafai e tagata uma ona iloa mai tusitusiga ia na ia tusia i luga o le vaega o le ofu na sasae,", "that all might see the writing which he had written upon the rent part,"], ["ma alaga atu ma se leo tele,", "and crying with a loud voice,"], ["ua fai atu:", "saying:"]]},
  {num:20,words:[["Faauta,", "Behold,"], ["soo se tasi e loto ia faatumauina lenei tagavai i luga o le laueleele,", "whosoever will maintain this title upon the land,"], ["ia latou o mai i luma i le malosi o le Alii,", "let them come forth in the strength of the Lord,"], ["ma ulu atu i se feagaiga o le a latou faatumauina a latou aia,", "and enter into a covenant that they will maintain their rights,"], ["ma la latou tapuaiga,", "and their religion,"], ["ina ia faamanuiaina i latou e le Alii le Atua.", "that the Lord God may bless them."]]},
  {num:21,words:[["Ma sa oo ina ua uma ona alaga atu e Moronae o nei upu,", "And it came to pass that when Moroni had proclaimed these words,"], ["faauta,", "behold,"], ["sa taufetuli faatasi mai le nuu ma o latou ofutau ua sulu faataamilo i o latou sulugatiti,", "the people came running together with their armor girded about their loins,"], ["ma saeia o latou ofu e fai ma faailoga,", "rending their garments in token,"], ["po o se feagaiga,", "or as a covenant,"], ["o le a latou le tuulafoaiina lava le Alii lo latou Atua;", "that they would not forsake the Lord their God;"], ["pe,", "or,"], ["i ni isi upu,", "in other words,"], ["afai latou te solia poloaiga a le Atua,", "if they should transgress the commandments of God,"], ["pe pauu atu i le solitulafono,", "or fall into transgression,"], ["ma mama e ave i o latou luga le suafa o Keriso,", "and be ashamed to take upon them the name of Christ,"], ["ia saeia i latou e le Atua e pei lava ona latou saeia o latou ofu.", "the Lord should rend them even as they had rent their garments."]]},
  {num:22,words:[["O lenei o le feagaiga lenei sa latou faia,", "Now this was the covenant which they made,"], ["ma sa latou lafo atu o latou ofu i vae o Moronae,", "and they cast their garments at the feet of Moroni,"], ["ua fai mai:", "saying:"], ["Matou te osi feagaiga ma lo matou Atua,", "We covenant with our God,"], ["ia faaumatia i matou,", "that we shall be destroyed,"], ["e pei lava o o matou uso i le laueleele i matu,", "even as our brethren in the land northward,"], ["pe afai matou te pauu atu i le solitulafono;", "if we shall fall into transgression;"], ["ioe,", "yea,"], ["ia lafoina e ia i matou i vae o o matou fili,", "he may cast us at the feet of our enemies,"], ["e pei lava ona matou lafo atu o matou ofu i ou vae ia soli i lalo e vae,", "even as we have cast our garments at thy feet to be trodden under foot,"], ["pe afai matou te pauu atu i le solitulafono.", "if we shall fall into transgression."]]},
  {num:23,words:[["Sa fai atu Moronae ia te i latou:", "Moroni said unto them:"], ["Faauta,", "Behold,"], ["o i tatou o se toe vaega o le fanau a Iakopo;", "we are a remnant of the seed of Jacob;"], ["ioe,", "yea,"], ["o i tatou o se toe vaega o le fanau a Iosefa ,", "we are a remnant of the seed of Joseph,"], ["o le e ona le 'ofu na saeia e ona uso i ni fasi ie e tele;", "whose coat was rent by his brethren into many pieces;"], ["ioe,", "yea,"], ["ma o lenei faauta,", "and now behold,"], ["ia tatou manatua e tausi i poloaiga a le Atua,", "let us remember to keep the commandments of God,"], ["a leai o le a saeia o tatou ofu e o tatou uso,", "or our garments shall be rent by our brethren,"], ["ma lafo i tatou i le falepuipui,", "and we be cast into prison,"], ["pe faatau atu i tatou,", "or be sold,"], ["pe fasiotia.", "or be slain."]]},
  {num:24,words:[["Ioe,", "Yea,"], ["ia tatou faasaoina lo tatou saolotoga o se toe vaega o Iosefa;", "let us preserve our liberty as a remnant of Joseph;"], ["ioe,", "yea,"], ["ia tatou manatua upu a Iakopo,", "let us remember the words of Jacob,"], ["ae lei maliu o ia,", "before his death,"], ["aua faauta,", "for behold,"], ["sa vaai o ia ua faasaoina se vaega o le toega o le ofu o Iosefa ma sa lē pala. Ma sa fai mai o ia—E pei ona faasaoina lenei toega o le ofu o lou atalii,", "he saw that a part of the remnant of the coat of Joseph was preserved and had not decayed. And he said—Even as this remnant of garment of my son hath been preserved,"], ["o le a faapea lava ona faasaoina e le aao o le Atua se toe vaega o le fanau a lou atalii,", "so shall a remnant of the seed of my son be preserved by the hand of God,"], ["ma ia avea mo ia lava,", "and be taken unto himself,"], ["ao le vaega e totoe o le fanau a Iosefa o le a fano,", "while the remainder of the seed of Joseph shall perish,"], ["e pei lava o le vaega na totoe o lona ofu.", "even as the remnant of his garment."]]},
  {num:25,words:[["O lenei faauta,", "Now behold,"], ["ua aumai e lenei mea le faanoanoa i lou agaga;", "this giveth my soul sorrow;"], ["e ui i lea,", "nevertheless,"], ["ua olioli lou agaga i lou atalii,", "my soul hath joy in my son,"], ["ona o lena vaega o lana fanau lea o le a avea i le Atua.", "because of that part of his seed which shall be taken unto God."]]},
  {num:26,words:[["O lenei faauta,", "Now behold,"], ["o le gagana lea a Iakopo.", "this was the language of Jacob."]]},
  {num:27,words:[["Ma o lenei o ai na te iloa ae le o le toe vaega o le fanau a Iosefa,", "And now who knoweth but what the remnant of the seed of Joseph,"], ["lea o le a fano e pei o lona ofu,", "which shall perish as his garment,"], ["o i latou ia o e ua faatuiese mai ia te i tatou? Ioe,", "are those who have dissented from us? Yea,"], ["ma o i tatou foi ia pe afai tatou te le tutumau mausali i le faatuatua ia Keriso.", "and even it shall be ourselves if we do not stand fast in the faith of Christ."]]},
  {num:28,words:[["Ma o lenei sa oo ina ua uma ona fai atu e Moronae nei upu sa alu atu o ia,", "And now it came to pass that when Moroni had said these words he went forth,"], ["ma auina atu foi ni avefeau i vaega uma o le laueleele sa i ai faatuiesega,", "and also sent forth in all the parts of the land where there were dissensions,"], ["ma faapotopoto faatasi tagata uma o e sa mananao e faatumauina lo latou saolotoga,", "and gathered together all the people who were desirous to maintain their liberty,"], ["e tutu tetee faasaga atu ia Amalekia ma i latou o e na faatuiese,", "to stand against Amalickiah and those who had dissented,"], ["o e ua taua o sa Amalekiā.", "who were called Amalickiahites."]]},
  {num:29,words:[["Ma sa oo ina ua vaai Amalekia ua sili atu ona toatele tagata a Moronae nai lo sa Amaleki—ma sa ia vaai foi ua masalosalo ona tagata e uiga i le tonu o le faamoemoe ua latou faia—o lea,", "And it came to pass that when Amalickiah saw that the people of Moroni were more numerous than the Amalickiahites—and he also  saw that his people were doubtful concerning the justice of the cause in which they had undertaken—therefore,"], ["i le fefe nei ona le maua le faamoemoe, na ia ave ai i latou o ona tagata o e na mananao i ai,", "fearing that he should not gain the point,"], ["ma ua o ese atu i le laueleele o Nifae.", "he took those of his people who would and departed into the land of Nephi."]]},
  {num:30,words:[["O lenei sa manatu Moronae sa le tatau ona toe maua e sa Lamanā se malosi faateleina;", "Now Moroni thought it was not expedient that the Lamanites should have any more strength;"], ["o lea na manatu ai o ia e sisio mai tagata o Amalekia,", "therefore he thought to cut off the people of Amalickiah,"], ["pe taofi i latou ma toe aumai i latou,", "or to take them and bring them back,"], ["ma ia fasioti Amalekia;", "and put Amalickiah to death;"], ["ioe,", "yea,"], ["ona sa ia iloa o le a ia faaosoina sa Lamanā ia feita e faasaga mai ia te i latou,", "for he knew that he would stir up the Lamanites to anger against them,"], ["ma uunai i latou ia o mai tau e faasaga mai ia te i latou;", "and cause them to come to battle against them;"], ["ma sa iloa e ia o le a fai e Amalekia lenei mea ina ia mafai ona ia maua ai o ona faamoemoega.", "and this he knew that Amalickiah would do that he might obtain his purposes."]]},
  {num:31,words:[["O lea na manatu ai Moronae e tatau ona ia ave o ana autau,", "Therefore Moroni thought it was expedient that he should take his armies,"], ["o e ua latou faapotopoto faatasi i latou lava,", "who had gathered themselves together,"], ["ma ua faaauupegaina i latou lava,", "and armed themselves,"], ["ma ua ulu atu i se feagaiga e tausi le filemu—ma sa oo ina ave e ia lana autau ma savali atu i fafo faatasi ma ona faleie i le vao,", "and entered into a covenant to keep the peace—and it came to pass that he took his army and marched out with his tents into the wilderness,"], ["e sisio mai Amalekia i le vao.", "to cut off the course of Amalickiah in the wilderness."]]},
  {num:32,words:[["Ma sa oo ina faia e ia e tusa ma ona manao,", "And it came to pass that he did according to his desires,"], ["ma savali atu i le vao,", "and marched forth into the wilderness,"], ["ma taofi mai autau a Amalekia.", "and headed the armies of Amalickiah."]]},
  {num:33,words:[["Ma sa oo ina sosola Amalekia ma se vaega toaitiiti o ana tagata,", "And it came to pass that Amalickiah fled with a small number of his men,"], ["ae o e na totoe na tuu mai i lima o Moronae ma sa toe ave i latou i tua i le laueleele o Sara'emila.", "and the remainder were delivered up into the hands of Moroni and were taken back into the land of Zarahemla."]]},
  {num:34,words:[["O lenei,", "Now,"], ["ona o Moronae o se tagata o le na tofia e faamasino sili ma le leo o le nuu,", "Moroni being a man who was appointed by the chief judges and the voice of the people,"], ["o lea na i ai ia te ia le pule e faia ai soo se mea e tusa ma le mea e loto i ai, i autau a sa Nifaē,", "therefore he had power according to his will with the armies of the Nephites,"], ["e faatu ma faaaoga ai le pule i luga o i latou.", "to establish and to exercise authority over them."]]},
  {num:35,words:[["Ma sa oo ina o soo se tasi o sa Amalekiā sa le fia ulu i le feagaiga e lagolago le faamoemoe o le saolotoga,", "And it came to pass that whomsoever of the Amalickiahites that would not enter into a covenant to support the cause of freedom,"], ["ina ia mafai ona latou maua pea se malo saoloto,", "that they might maintain a free government,"], ["sa ia faatonu ia fasiotia;", "he caused to be put to death;"], ["ma sa i ai se toaitiiti sa latou faafitia le feagaiga o le saolotoga.", "and there were but few who denied the covenant of freedom."]]},
  {num:36,words:[["Ma sa oo foi ina ia faatonu atu,", "And it came to pass also,"], ["ia sisi i luga le tagavai o le saolotoga i olo uma sa i le laueleele atoa,", "that he caused the title of liberty to be hoisted upon every tower which was in all the land,"], ["lea sa maua e sa Nifaē;", "which was possessed by the Nephites;"], ["ma sa faapea ona faatu e Moronae le tagavai o le saolotoga i sa Nifaē.", "and thus Moroni planted the standard of liberty among the Nephites."]]},
  {num:37,words:[["Ma sa amata ona latou toe maua o le filemu i le laueleele;", "And they began to have peace again in the land;"], ["ma sa faapea ona latou tausia o le filemu i le laueleele seia oo mai toeitiiti lava i le faaiuga o le lona sefulu iva o tausaga o le nofoaiga a faamasino.", "and thus they did maintain peace in the land until nearly the end of the nineteenth year of the reign of the judges."]]},
  {num:38,words:[["Ma sa faatumauina foi e Helamana ma faitaulaga sili le maopoopo i le ekalesia;", "And Helaman and the high priests did also maintain order in the church;"], ["ioe,", "yea,"], ["sa oo lava ina latou maua le filemu tele ma le olioli i le ekalesia i le va o le fa tausaga.", "even for the space of four years did they have much peace and rejoicing in the church."]]},
  {num:39,words:[["Ma sa oo ina feoti le toatele,", "And it came to pass that there were many who died,"], ["ma le talitonu mausali ua togiolaina o latou agaga e le Alii o Iesu Keriso;", "firmly believing that their souls were redeemed by the Lord Jesus Christ;"], ["o lea na latou o ese atu ai i fafo mai le lalolagi ma le olioli.", "thus they went out of the world rejoicing."]]},
  {num:40,words:[["Ma sa i ai ni isi o e na oti i mai-fiva,", "And there were some who died with fevers,"], ["ia sa masani ona pepesi i le laueleele i ni isi vaitau o le tausaga—ae sa le toatele naua na feoti i mai-fiva,", "which at some seasons of the year were very frequent in the land—but not so much so with fevers,"], ["ona o le lelei tele o le tele o laau ma aa na saunia e le Atua e aveese ai le pogai o mai,", "because of the excellent qualities of the many plants and roots which God had prepared to remove the cause of diseases,"], ["ia sa maua ai tagata ona o le uiga o le tau—", "to which men were subject by the nature of the climate—"]]},
  {num:41,words:[["Ae sa toatele e na oti i le tele o o latou tausaga;", "But there were many who died with old age;"], ["ma o i latou o e na oti ma le faatuatua ia Keriso ua fiafia ia te ia,", "and those who died in the faith of Christ are happy in him,"], ["e pei ona ao ina tatau ona tatou manatu i ai.", "as we must needs suppose."]]},
];
renderVerseSet(al_ch_46_Verses, 'al-ch46-verses');

var al_ch_47_Verses = [
  {num:1,words:[["O lenei o le a tatou toe foi atu i la tatou talafaamaumau ia Amalekia ma i latou o e na sosola faatasi ma ia i le vao;", "Now we will return in our record to Amalickiah and those who had fled with him into the wilderness;"], ["aua,", "for,"], ["faauta,", "behold,"], ["sa ia ave i latou o e na o faatasi ma ia,", "he had taken those who went with him,"], ["ma o ae i le laueleele o Nifae i totonu o sa Lamanā,", "and went up in the land of Nephi among the Lamanites, and did stir up the Lamanites to anger against the people of Nephi,"], ["ma faaoso sa Lamanā ia feita e faasaga i le nuu o Nifae sa oo ina auina atu ai e le tupu o sa Lamanā se folafolaga i lona laueleele atoa,", "insomuch that the king of the Lamanites sent a proclamation throughout all his land,"], ["i totonu o ona tagata uma,", "among all his people,"], ["ia latou toe faapotopoto faatasi i latou lava e o atu e tau faasaga ia sa Nifaē.", "that they should gather themselves together again to go to battle against the Nephites."]]},
  {num:2,words:[["Ma sa oo ina ua alu atu le folafolaga i totonu o i latou,", "And it came to pass that when the proclamation had gone forth among them they were exceedingly afraid;"], ["sa latou matatau tele lava;", "yea,"], ["ioe, sa latou fefefe e faalemalie i le tupu,", "they feared to displease the king,"], ["ma sa latou fefefe foi e o e tau ma sa Nifaē nei aveesea o latou ola.", "and they also feared to go to battle against the Nephites lest they should lose their lives."], ["Ma sa oo ina sa latou mumusu,", "And it came to pass that they would not,"], ["pe sa mumusu le toatele o i latou,", "or the more part of them would not,"], ["e usiusitai i poloaiga a le tupu.", "obey the commandments of the king."]]},
  {num:3,words:[["Ma o lenei sa oo ina ita le tupu ona o lo latou le usiusitai;", "And now it came to pass that the king was wroth because of their disobedience;"], ["o lea na ia tuu atu ai ia Amalekia le pule i le vaega lena o lana autau lea sa usiusitai i ana poloaiga,", "therefore he gave Amalickiah the command of that part of his army which was obedient unto his commands,"], ["ma faatonu o ia e alu atu ma faamalosi i latou e o atu e tau.", "and commanded him that he should go forth and compel them to arms."]]},
  {num:4,words:[["O lenei faauta,", "Now behold,"], ["o le mea lenei sa manao i ai Amalekia;", "this was the desire of Amalickiah;"], ["ona o ia o se tagata faitogafiti faaoleole tele o lea na ia fafau ai se fuafuaga i lona loto e aveese ai le tupu o sa Lamanā mai le nofoalii.", "for he being a very subtle man to do evil therefore he laid the plan in his heart to dethrone the king of the Lamanites."]]},
  {num:5,words:[["Ma o lenei ua ia maua le pule i vaega na o sa Lamanā o e sa fiafia i le tupu;", "And now he had got the command of those parts of the Lamanites who were in favor of the king;"], ["ma sa ia saili ia maua le fiafia mai o i latou o e sa le usiusitai;", "and he sought to gain favor of those who were not obedient;"], ["o lea na ia alu atu ai i le nofoaga sa taua o Onaeta ,", "therefore he went forward to the place which was called Onidah,"], ["ona o iina na sosola atu i ai sa Lamanā uma;", "for thither had all the Lamanites fled;"], ["ona sa latou iloa ua o mai le autau,", "for they discovered the army coming,"], ["ma,", "and,"], ["i le manatu ua latou o mai e faaumatia i latou,", "supposing that they were coming to destroy them,"], ["o lea na latou sosola ai i Onaeta,", "therefore they fled to Onidah,"], ["i le nofoaga o auupega o taua.", "to the place of arms."]]},
  {num:6,words:[["Ma sa latou tofia se tagata e avea ma o latou tupu ma taitai,", "And they had appointed a man to be a king and a leader over them,"], ["i le maumaututu i o latou mafaufau ma se tautinoga mauai o le a le faamalolosia i latou e o atu e faasaga ia sa Nifaē.", "being fixed in their minds with a determined resolution that they would not be subjected to go against the Nephites."]]},
  {num:7,words:[["Ma sa oo ina latou faapotopoto faatasi i latou lava i luga o le tumutumu o le mauga lea sa taua o Anetipa,", "And it came to pass that they had gathered themselves together upon the top of the mount which was called Antipas,"], ["i le sauniuniga e tau.", "in preparation to battle."]]},
  {num:8,words:[["O lenei sa le o le faamoemoe o Amalekia ia tau ma i latou e tusa ma poloaiga a le tupu;", "Now it was not Amalickiah's intention to give them battle according to the commandments of the king;"], ["ae faauta,", "but behold,"], ["o lona faamoemoe o le maua mai lea o le fiafia mai o autau a sa Lamanā ia te ia,", "it was his intention to gain favor with the armies of the Lamanites,"], ["ina ia mafai ona ia tuu o ia lava i lo latou ao ma aveese le tupu mai le nofoalii ma ia ave le malo.", "that he might place himself at their head and dethrone the king and take possession of the kingdom."]]},
  {num:9,words:[["Ma faauta,", "And behold,"], ["sa oo ina ia faatonu lana autau ia faatutu o latou faleie i le vanu lea sa latalata i le mauga o Anetipa.", "it came to pass that he caused his army to pitch their tents in the valley which was near the mount Antipas."]]},
  {num:10,words:[["Ma sa oo ina ua po,", "And it came to pass that when it was night he sent a secret embassy into the mount Antipas,"], ["sa ia auina atu se avefeau faalilolilo i le mauga o Anetipa,", "desiring that the leader of those who were upon the mount,"], ["e manao i le taitai o e sa i luga o le mauga, o lona igoa o Leoneti,", "whose name was Lehonti,"], ["ia sau o ia i lalo i le auvae o le mauga,", "that he should come down to the foot of the mount,"], ["ona sa ia manao e talanoa ma ia.", "for he desired to speak with him."]]},
  {num:11,words:[["Ma sa oo ina ua maua e Leoneti le savali, sa fefe o ia e alu ifo i lalo i vae o le mauga.", "And it came to pass that when Lehonti received the message he durst not go down to the foot of the mount."], ["Ma sa oo ina toe auina atu faalua e Amalekia le savali,", "And it came to pass that Amalickiah sent again the second time,"], ["e manao ia te ia e sau i lalo.", "desiring him to come down."], ["Ma sa musu Leoneti;", "And it came to pass that Lehonti would not;"], ["ma sa ia toe auina atu le savali faatolu.", "and he sent again the third time."]]},
  {num:12,words:[["Ma sa oo ina ua iloa e Amalekia ua le mafai ona ia faia ia sau Leoneti i lalo mai le mauga,", "And it came to pass that when Amalickiah found that he could not get Lehonti to come down off from the mount,"], ["sa ia alu ae i luga o le mauga,", "he went up into the mount,"], ["toeitiiti lava oo atu i le togalauapi a Leoneti;", "nearly to Lehonti's camp;"], ["ma sa ia toe auina atu lana savali faafa ia Leoneti,", "and he sent again the fourth time his message unto Lehonti,"], ["e manao ia sau o ia i lalo,", "desiring that he would come down,"], ["ma ia aumai ana leoleo faatasi ma ia.", "and that he would bring his guards with him."]]},
  {num:13,words:[["Ma sa oo ina alu ifo Leoneti i lalo faatasi ma ana leoleo ia Amalekia,", "And it came to pass that when Lehonti had come down with his guards to Amalickiah,"], ["sa manao Amalekia ia te ia ia o mai i lalo faatasi ma lana autau i le po,", "that Amalickiah desired him to come down with his army in the night– time,"], ["ma sio tagata ia sa ia latou togalauapi o e na tuu mai e le tupu ia te ia ia pule ai i o latou luga,", "and surround those men in their camps over whom the king had given him command,"], ["ma o le a ia tuu atu i latou ia i lima o Leoneti,", "and that he would deliver them up into Lehonti's hands,"], ["pe a ia faia o ia (Amalekia) ma taitai lona lua i le autau atoa.", "if he would make him (Amalickiah) a second leader over the whole army."]]},
  {num:14,words:[["Ma sa oo ina o ifo i lalo Leoneti faatasi ma ana tagata ma sio tagata a Amalekia,", "And it came to pass that Lehonti came down with his men and surrounded the men of Amalickiah,"], ["ma ae latou te lei ala mai i le tafa o ata ua siomia i latou e autau a Leoneti.", "so that before they awoke at the dawn of day they were surrounded by the armies of Lehonti."]]},
  {num:15,words:[["Ma sa oo ina ua latou vaai atu ua siomia i latou,", "And it came to pass that when they saw that they were surrounded,"], ["sa latou aioi mai ia Amalekia ia ona tuu mai i latou ia aufaatasi ma o latou uso,", "they plead with Amalickiah that he would suffer them to fall in with their brethren,"], ["ina ia le faaumatiaina i latou. O lenei o le mea tonu lava lenei na manao i ai Amalekia.", "that they might not be destroyed. Now this was the very thing which Amalickiah desired."]]},
  {num:16,words:[["Ma sa oo ina laveai e ia ana tagata,", "And it came to pass that he delivered his men,"], ["sa le tusa ai ma poloaiga a le tupu. O lenei o le mea lenei sa manao i ai Amalekia,", "contrary to the commands of the king. Now this was the thing that Amalickiah desired,"], ["ina ia mafai ona ia faataunuu o ana fuafuaga i le aveeseina o le tupu mai le nofoalii.", "that he might accomplish his designs in dethroning the king."]]},
  {num:17,words:[["O lenei o le tu masani i totonu o sa Lamanā,", "Now it was the custom among the Lamanites,"], ["afai e fasiotia lo latou taitai sili,", "if their chief leader was killed,"], ["e tofia le taitai lona lua e avea mo o latou taitai sili.", "to appoint the second leader to be their chief leader."]]},
  {num:18,words:[["Ma sa oo ina faatonu e Amalekia se tasi o ana auauna e avatu fuafua vai ona ia Leoneti,", "And it came to pass that Amalickiah caused that one of his servants should administer poison by degrees to Lehonti,"], ["na iu ina oti ai o ia.", "that he died."]]},
  {num:19,words:[["O lenei,", "Now,"], ["ina ua oti Leoneti,", "when Lehonti was dead,"], ["sa tofia e sa Lamanā Amalekia e avea mo o latou taitai ma o latou taitaiau sili.", "the Lamanites appointed Amalickiah to be their leader and their chief commander."]]},
  {num:20,words:[["Ma sa oo ina savavali atu Amalekia ma ana autau (ona ua ia maua o ona manao) i le laueleele o Nifae,", "And it came to pass that Amalickiah marched with his armies (for he had gained his desires) to the land of Nephi,"], ["i le aai o Nifae,", "to the city of Nephi,"], ["o le aai autu lea.", "which was the chief city."]]},
  {num:21,words:[["Ma sa sau i fafo le tupu ma ana leoleo e fetaiai ma ia,", "And the king came out to meet him with his guards,"], ["ona sa manatu o ia ua uma ona faataunuu e Amalekia ana faatonuga,", "for he supposed that Amalickiah had fulfilled his commands,"], ["ma ua faapotopoto faatasi e Amalekia se autau toatele naua e o atu e faasagatau ia sa Nifaē.", "and that Amalickiah had gathered together so great an army to go against the Nephites to battle."]]},
  {num:22,words:[["Ae faauta, ao sau le tupu i fafo e fetaiai ma ia,", "But behold,"], ["sa faatonu e Amalekia ana auauna ia o atu i luma e faafeiloai le tupu.", "as the king came out to meet him Amalickiah caused that his servants should go forth to meet the king."], ["Ma sa latou o atu ma latou ifo i luma o le tupu,", "And they went and bowed themselves before the king,"], ["e peiseai e faaali atu le faaaloalo ia te ia ona o lona silisili.", "as if to reverence him because of his greatness."]]},
  {num:23,words:[["Ma sa oo ina tuu atu e le tupu lona lima e faatutulai ia te i latou,", "And it came to pass that the king put forth his hand to raise them,"], ["e pei o le tu masani a sa Lamanā,", "as was the custom with the Lamanites,"], ["o se faailoga lea o le filemu,", "as a token of peace,"], ["o se tu lea sa latou aumai mai ia sa Nifaē.", "which custom they had taken from the Nephites."]]},
  {num:24,words:[["Ma sa oo ina ua uma ona ia faatu ae o le tagata muamua mai le eleele,", "And it came to pass that when he had raised the first from the ground,"], ["faauta sa ia tui le tupu i le fatu;", "behold he stabbed the king to the heart;"], ["ma sa pau o ia i le eleele.", "and he fell to the earth."]]},
  {num:25,words:[["O lenei sa sosola auauna a le tupu;", "Now the servants of the king fled;"], ["ma sa manu e auauna a Amalekia se alaga,", "and the servants of Amalickiah raised a cry,"], ["ua fai mai:", "saying:"]]},
  {num:26,words:[["Faauta,", "Behold,"], ["ua tui e auauna a le tupu o ia i le fatu,", "the servants of the king have stabbed him to the heart,"], ["ma ua pau o ia, ma ua sosola i latou;", "and he has fallen and they have fled;"], ["faauta,", "behold,"], ["o mai ma vaai i ai.", "come and see."]]},
  {num:27,words:[["Ma sa oo ina faatonu e Amalekia ia savavali atu i luma ana autau ma vaai po o le a le mea ua tupu i le tupu;", "And it came to pass that Amalickiah commanded that his armies should march forth and see what had happened to the king;"], ["ma ina ua latou oo atu i le mea sa i ai le tupu,", "and when they had come to the spot,"], ["ma latou maua ai le tupu ua taatia i lona toto,", "and found the king lying in his gore,"], ["sa faataga ita Amalekia,", "Amalickiah pretended to be wroth,"], ["ma fai mai:", "and said:"], ["Soo se tasi e alofa i le tupu,", "Whosoever loved the king,"], ["ia alu atu o ia,", "let him go forth,"], ["ma tuliloa ana auauna ina ia fasioti i latou.", "and pursue his servants that they may be slain."]]},
  {num:28,words:[["Ma sa oo ina faalogo i latou uma o e na alolofa i le tupu i nei upu,", "And it came to pass that all they who loved the king, when they heard these words,"], ["sa latou o mai i luma ma tuliloa auauna a le tupu.", "came forth and pursued after the servants of the king."]]},
  {num:29,words:[["O lenei ina ua vaai mai auauna a le tupu ua tuliloa atu i latou e se autau,", "Now when the servants of the king saw an army pursuing after them,"], ["sa latou toe fefefe,", "they were frightened again,"], ["ma sosola i le vao,", "and fled into the wilderness,"], ["ma o mai i le laueleele o Sara'emila ma aufaatasi ma le nuu o Amona.", "and came over into the land of Zarahemla and joined the people of Ammon."]]},
  {num:30,words:[["Ma o le autau lea sa tuliloa mai i latou ua toe foi,", "And the army which pursued after them returned,"], ["ona ua fiu e tuliloa mai i latou ae le maua;", "having pursued after them in vain;"], ["ma sa faapea ona maua e Amalekia,", "and thus Amalickiah,"], ["e ala i lona taufaasese,", "by his fraud,"], ["loto o le nuu.", "gained the hearts of the people."]]},
  {num:31,words:[["Ma sa oo o le aso na sosoo ai, na ulu atu ai o ia i le aai o Nifae ma ana autau,", "And it came to pass on the morrow he entered the city Nephi with his armies,"], ["ma ave mo ia le aai.", "and took possession of the city."]]},
  {num:32,words:[["Ma o lenei sa oo ina ua faafofoga le masiofo ua fasiotia le tupu—aua sa auina atu e Amalekia se avefeau i le masiofo e tau atu ia te ia ua fasiotia le tupu e ana auauna,", "And now it came to pass that the queen,"], ["ma sa ia tuliloaina i latou i lana autau,", "when she had heard that the king was slain—for Amalickiah had sent an embassy to the queen informing her that the king had been slain by his  servants,"], ["a ua le maua,", "that he had pursued them with his army, but it was in vain,"], ["ma ua sosola i latou—", "and they had made their escape—"]]},
  {num:33,words:[["O lea, ina ua maua e le masiofo lenei savali,", "Therefore,"], ["sa ia auina atu se talosaga ia Amalekia, e manao ia te ia,", "when the queen had received this message she sent unto Amalickiah,"], ["ia ona faasaoina tagata o le aai; ma sa ia manao foi ia te ia,", "desiring him that he would spare the people of the city;"], ["ia sau i totonu ia te ia; ma sa ia manao foi ia te ia,", "and she also desired him that he should come in unto her;"], ["ia ona aumai ni molimau faatasi ma ia, e molimau e uiga i le maliu o le tupu.", "and she also desired him that he should bring witnesses with him to testify concerning the death of the king."]]},
  {num:34,words:[["Ma sa oo ina ave e Amalekia le auauna lava lea na fasiotia le tupu,", "And it came to pass that Amalickiah took the same servant that slew the king,"], ["ma i latou uma o e na faatasi ma ia,", "and all them who were with him,"], ["ma o atu i totonu i le masiofo,", "and went in unto the queen,"], ["i le mea sa nofo ai o ia;", "unto the place where she sat;"], ["ma sa latou molimau atu uma ia te ia, o le tupu na fasiotia e ana lava auauna;", "and they all testified unto her that the king was slain by his own servants;"], ["ma sa latou fai atu foi:", "and they said also:"], ["Ua sosola i latou;", "They have fled;"], ["pe ua le molimau ea lenei mea e faasaga ia te i latou? Ma sa faapea ona latou faamalieina ai le masiofo e uiga i le maliu o le tupu.", "does not this testify against them?  And thus they satisfied the queen concerning the death of the king."]]},
  {num:35,words:[["Ma sa oo ina saili e Amalekia le alofa o le masiofo,", "And it came to pass that Amalickiah sought the favor of the queen,"], ["ma avea o ia ma ana ava;", "and took her unto him to wife;"], ["ma sa faapea i lona taufaasese,", "and thus by his fraud,"], ["ma i le fesoasoani a ana auauna popoto,", "and by the assistance of his cunning servants,"], ["ona ia maua o le malo;", "he obtained the kingdom;"], ["ioe,", "yea,"], ["sa aloaia o ia o le tupu i le laueleele atoa,", "he was acknowledged king throughout all the land,"], ["i totonu o tagata uma o sa Lamanā,", "among all the people of the Lamanites,"], ["o e sa aofia ai sa Lamanā ma sa Lemuelū ma sa Isamaelī,", "who were composed of the Lamanites and the Lemuelites and the Ishmaelites,"], ["ma tagata faatuiese uma o sa Nifaē,", "and all the dissenters of the Nephites,"], ["mai i le nofoaiga a Nifae e oo mai i lalo i le taimi nei.", "from the reign of Nephi down to the present time."]]},
  {num:36,words:[["O lenei o nei tagata faatuiese,", "Now these dissenters,"], ["sa i ai aoaoga e tasi ma faamatalaga e tasi o sa Nifaē;", "having the same instruction and the same information of the Nephites,"], ["ioe,", "yea,"], ["ona ua uma ona aoaoina i le malamalama e tasi o le Alii,", "having been instructed in the same knowledge of the Lord,"], ["e ui i lea,", "nevertheless,"], ["o se mea uiga ese le tau atu,", "it is strange to relate,"], ["e lei umi ona mavae atu a latou faatuiesega ae avea i latou ma tagata sili atu ona maaa ma lē fia salamo,", "not long after their dissensions they became more hardened and impenitent,"], ["ma sili atu ona aivao,", "and more wild,"], ["amioleaga ma feai nai lo sa Lamanā—ua inu i totonu faatasi ma tu a sa Lamanā;", "wicked and ferocious than the Lamanites—drinking in with the traditions of the Lamanites;"], ["ua gauai i le faapaie,", "giving way to indolence,"], ["ma ituaiga uma o le mataaitu;", "and all manner of lasciviousness;"], ["ioe,", "yea,"], ["ua galo atoa le Alii lo latou Atua.", "entirely forgetting the Lord their God."]]},
];
renderVerseSet(al_ch_47_Verses, 'al-ch47-verses');

var al_ch_48_Verses = [
  {num:1,words:[["Ma o lenei sa oo o le vave lava na maua ai e Amalekia le malo,", "And now it came to pass that,"], ["na amata ai e ia ona uunai loto o sa Lamanā e faasaga i tagata o Nifae;", "as soon as Amalickiah had obtained the kingdom he began to inspire the hearts of the Lamanites against the people of Nephi;"], ["ioe,", "yea,"], ["sa ia tofia tagata e tautatala atu i sa Lamanā mai i o latou olo,", "he did appoint men to speak unto the Lamanites from their towers,"], ["e faasaga ia sa Nifaē.", "against the Nephites."]]},
  {num:2,words:[["Ma sa faapea ona ia uunai o o latou loto e faasaga ia sa Nifaē,", "And thus he did inspire their hearts against the Nephites,"], ["sa oo ina ia saili foi i le taufaasiusiuga o le lona sefulu iva o tausaga o le nofoaiga a faamasino,", "insomuch that in the latter end of the nineteenth year of the reign of the judges,"], ["ina ua ia faataunuuina lea o ana fuafuaga e oo mai i le taimi lea,", "he having accomplished his designs thus far,"], ["ioe,", "yea,"], ["ina ua avea o ia ma tupu o sa Lamanā,", "having been made king over the Lamanites,"], ["ia nofotupu i luga o le laueleele atoa,", "he sought also to reign over all the land,"], ["ioe,", "yea,"], ["ma tagata uma lava sa i ai i le laueleele,", "and all the people who were in the land,"], ["o sa Nifaē atoa foi ma sa Lamanā.", "the Nephites as well as the Lamanites."]]},
  {num:3,words:[["O lea sa ia faataunuuina ai lana fuafuaga,", "Therefore he had accomplished his design,"], ["ona sa ia faamaaa loto o sa Lamanā ma faatauaso o latou mafaufau,", "for he had hardened the hearts of the Lamanites and blinded their minds,"], ["ma faaoso le ita ia te i latou,", "and stirred them up to anger,"], ["sa oo ina ia faapotopoto se autau e toatele e o atu e tau faasaga ia sa Nifaē.", "insomuch that he had gathered together a numerous host to go to battle against the Nephites."]]},
  {num:4,words:[["Ona sa mauai o ia,", "For he was determined,"], ["ona o le toatele o le aofai o ana tagata,", "because of the greatness of the number of his people,"], ["e faatoilalo sa Nifaē ma aumai i latou i le pologa.", "to overpower the Nephites and to bring them into bondage."]]},
  {num:5,words:[["Ma sa faapea ona ia tofia o kapeteni sili o lo sa Soramā,", "And thus he did appoint chief captains of the Zoramites,"], ["ona sa sili atu ona latou masani ma le malosi o sa Nifaē,", "they being the most acquainted with the strength of the Nephites,"], ["ma o latou nofoaga mapu,", "and their places of resort,"], ["ma vaega sili ona vaivai o o latou aai;", "and the weakest parts of their cities;"], ["o lea na ia tofia ai i latou e avea ma kapeteni sili i ana autau.", "therefore he appointed them to be chief captains over his armies."]]},
  {num:6,words:[["Ma sa oo ina latou ave la latou tolauapiga,", "And it came to pass that they took their camp,"], ["ma o atu i le vao agai i le laueleele o Sara'emila.", "and moved forth toward the land of Zarahemla in the wilderness."]]},
  {num:7,words:[["O lenei sa oo ina ao faapea ona maua e Amalekia le pule e ala i le pepelo ma le taufaasese,", "Now it came to pass that while Amalickiah had thus been obtaining power by fraud and deceit,"], ["o Moronae,", "Moroni,"], ["i le isi itu,", "on the other hand,"], ["sa ia sauniunia mafaufau o tagata ia faamaoni i le Alii lo latou Atua.", "had been preparing the minds of the people to be faithful unto the Lord their God."]]},
  {num:8,words:[["Ioe,", "Yea,"], ["sa ia faamalolosia autau a sa Nifaē,", "he had been strengthening the armies of the Nephites,"], ["ma faatutu ni olo laiti,", "and erecting small forts,"], ["po o ni nofoaga o le mapu;", "or places of resort;"], ["ma ati i luga faupuega eleele faataamilo e puipui ai i totonu ana autau,", "throwing up banks of earth round about to enclose his armies,"], ["ma ati foi pa maa e sio faataamilo ai i latou,", "and also building walls of stone to encircle them about,"], ["e faataamilo i o latou aai ma tuaoi o o latou laueleele;", "round about their cities and the borders of their lands;"], ["ioe,", "yea,"], ["e faataamilo i le laueleele atoa.", "all round about the land."]]},
  {num:9,words:[["Ma i o latou olotui sa sili ona vaivai sa ia tuu ai le toatele o tane;", "And in their weakest fortifications he did place the greater number of men;"], ["ma sa faapea ona ia tuiolo ma faamalosia le laueleele lea sa maua e sa Nifaē.", "and thus he did fortify and strengthen the land which was possessed by the Nephites."]]},
  {num:10,words:[["Ma sa faapea ona ia sauniuni e puipui lo latou saolotoga,", "And thus he was preparing to support their liberty,"], ["o latou laueleele,", "their lands,"], ["a latou ava,", "their wives,"], ["ma a latou fanau,", "and their children,"], ["ma lo latou filemu,", "and their peace,"], ["ma ina ia mafai ona latou ola mo le Alii lo latou Atua,", "and that they might live unto the Lord their God,"], ["ma ina ia mafai ona latou faatumauina o le mea ua taua e o latou fili o le faamoemoe o Kerisiano.", "and that they might maintain that which was called by their enemies the cause of Christians."]]},
  {num:11,words:[["Ma o Moronae o se tagata malosi ma tautaua tele;", "And Moroni was a strong and a mighty man;"], ["o ia o se tagata ua atoatoa le malamalama ;", "he was a man of a perfect under– standing;"], ["ioe,", "yea,"], ["o se tagata sa le fiafia i le faamasaa toto;", "a man that did not delight in bloodshed;"], ["o se tagata sa olioli lona agaga i le filifiliga saoloto ma le saolotoga o lona atunuu,", "a man whose soul did joy in the liberty and the freedom of his country,"], ["ma ona uso mai i le pologa ma le faapologaina;", "and his brethren from bondage and slavery;"]]},
  {num:12,words:[["Ioe,", "Yea,"], ["o se tagata sa tumu lona loto i le faafetai i lona Atua,", "a man whose heart did swell with thanksgiving to his God,"], ["mo avanoa ma faamanuiaga e tele na ia faaee mai i luga o lona nuu;", "for the many privileges and blessings which he bestowed upon his people;"], ["o se tagata sa galue malosi lava mo le manuia ma le saogalemu o ona tagata.", "a man who did labor exceedingly for the welfare and safety of his people."]]},
  {num:13,words:[["Ioe,", "Yea,"], ["ma o ia o se tagata sa mausali i le faatuatua ia Keriso,", "and he was a man who was firm in the faith of Christ,"], ["ma sa tauto o ia i se tautoga e puipui i ona tagata,", "and he had sworn with an oath to defend his people,"], ["ana aia,", "his rights,"], ["ma lona atunuu,", "and his country,"], ["ma lana tapuaiga,", "and his religion,"], ["e oo lava i le faamaligiina ai o lona toto.", "even to the loss of his blood."]]},
  {num:14,words:[["O lenei sa aoaoina sa Nifaē e puipui i latou lava e faasaga i o latou fili,", "Now the Nephites were taught to defend themselves against their enemies,"], ["e oo lava i le faamasaaina o le toto pe afai e tatau ai;", "even to the shedding of blood if it were necessary;"], ["ioe,", "yea, and  they were also taught never to give an offense,"], ["ma sa aoaoina foi i latou e aua lava nei faia se faatausuai ioe,", "yea,"], ["ma aua lava nei siia le pelu vagana ai e tetee faasaga atu ai i se fili,", "and never to raise the sword except it were against an enemy,"], ["vagana ai ua mo le faasaoina o o latou ola.", "except it were to preserve their lives."]]},
  {num:15,words:[["Ma o lo latou faatuatuaga lenei,", "And this was their faith,"], ["e faapea o lo latou faia faapea o le a faamanuia ai i latou e le Atua i le laueleele,", "that by so doing God would prosper them in the land,"], ["pe i ni isi upu,", "or in other words,"], ["afai latou te faamaoni i le tausiga o poloaiga a le Atua o le a ia faamanuiaina i latou i le laueleele;", "if they were faithful in keeping the commandments of God that he would prosper them in the land;"], ["ioe,", "yea,"], ["lapatai i latou ia sosola,", "warn them to flee,"], ["pe ia saunia mo le taua,", "or to prepare for war,"], ["e tusa ma lo latou tuga;", "according to their danger;"]]},
  {num:16,words:[["O lenei foi,", "And also,"], ["o le a faailoa mai e le Atua ia te i latou le mea latou te o i ai e puipui ai i latou e faasaga i o latou fili,", "that God would make it known unto them whither they should go to defend themselves against their enemies,"], ["ma o lo latou faia faapea,", "and by so doing,"], ["o le a laveai ai i latou e le Alii;", "the Lord would deliver them;"], ["ma o le faatuatuaga lenei o Moronae,", "and this was the faith of Moroni,"], ["ma sa olioli i ai lona loto i lea mea;", "and his heart did glory in it;"], ["e le i le faamasaaina o le toto ae i le faia o mea lelei,", "not in the shedding of blood but in doing good,"], ["i le faasaoina o ona tagata,", "in preserving his people,"], ["ioe,", "yea,"], ["i le tausia o poloaiga a le Atua,", "in keeping the commandments of God,"], ["ioe,", "yea,"], ["ma le tetee atu i le amioletonu.", "and resisting iniquity."]]},
  {num:17,words:[["Ioe,", "Yea,"], ["e moni,", "verily,"], ["e moni,", "verily I say unto you,"], ["ou te fai atu ia te outou,", "if all men had been,"], ["a na pei tagata uma sa i ai,", "and were,"], ["ma o i ai, ma o le a i ai,", "and ever would be,"], ["o Moronae,", "like unto Moroni,"], ["faauta,", "behold,"], ["po ua luluina i lalo e faavavau mana o seoli;", "the very powers of hell would have been shaken forever;"], ["ioe,", "yea,"], ["po ua le maua e le tiapolo se mana i luga o loto o le fanauga a tagata.", "the devil would never have power over the hearts of the children of men."]]},
  {num:18,words:[["Faauta,", "Behold,"], ["o ia o se tagata sa pei o Amona,", "he was a man like unto Ammon,"], ["le atalii o Mosaea,", "the son of Mosiah,"], ["ioe,", "yea,"], ["ma isi foi atalii o Mosaea,", "and even the other sons of Mosiah,"], ["ioe,", "yea,"], ["ma Alema foi ma ona atalii,", "and also Alma and his sons,"], ["ona o i latou uma o ni tagata o le Atua.", "for they were all men of God."]]},
  {num:19,words:[["O lenei faauta,", "Now behold,"], ["sa le itiiti foi le auaunaga a Helamana ma ona uso i le nuu nai lo Moronae;", "Helaman and his brethren were no less serviceable unto the people than was Moroni;"], ["ona sa latou talai atu le afioga a le Atua,", "for they did preach the word of God,"], ["ma sa latou papatiso i le salamo tagata uma o soo se tasi sa fia faalogo ia latou upu.", "and they did baptize unto repentance all men whosoever would hearken unto their words."]]},
  {num:20,words:[["Ma sa faapea ona latou o atu,", "And thus they went forth,"], ["ma sa faalotomaualalalo e tagata i latou lava ona o a latou upu,", "and the people did humble themselves because of their words,"], ["sa oo ina alofagia tele i latou e le Alii,", "insomuch that they were highly favored of the Lord,"], ["ma sa faapea ona latou aunoa ai mai taua ma finauga i totonu o i latou lava,", "and thus they were free from wars and contentions among themselves,"], ["ioe,", "yea,"], ["mo le va lava o le fa tausaga.", "even for the space of four years."]]},
  {num:21,words:[["Peitai,", "But,"], ["e pei ona ou fai atu,", "as I have said,"], ["o le taufaaiuiuga o le lona sefulu iva o tausaga,", "in the latter end of the nineteenth year,"], ["ioe,", "yea,"], ["e ui lava i lo latou filemu i totonu o i latou lava,", "notwithstanding their peace amongst themselves,"], ["sa faamalosia i latou ma le toa'i e tau ma o latou uso,", "they were compelled reluctantly to contend with their brethren,"], ["o sa Lamanā.", "the Lamanites."]]},
  {num:22,words:[["Ioe,", "Yea,"], ["ma i se aotelega,", "and in fine,"], ["sa le taofia lava a latou taua ma sa Lamanā mo le va o le tele o tausaga,", "their wars never did cease for the space of many years with the Lamanites,"], ["e ui i lo latou mumusu tele.", "notwithstanding their much reluctance."]]},
  {num:23,words:[["O lenei,", "Now,"], ["sa latou faanoanoa e fetagofi i auupega e faasaga ia sa Lamanā,", "they were sorry to take up arms against the Lamanites,"], ["ona sa latou le fiafia i le faamasaaina o le toto;", "because they did not delight in the shedding of blood;"], ["ioe,", "yea,"], ["ma sa le ona pau lea—sa latou faanoanoa i le avea ma auala e auina atu ai i fafo le toatele o o latou uso mai lenei lalolagi i se lalolagi faavavau,", "and this was not all—they were sorry to be the means of sending so many of their brethren out of this world into an eternal world,"], ["ua le sauni e fetaiai ma lo latou Atua.", "unprepared to meet their God."]]},
  {num:24,words:[["E ui i lea,", "Nevertheless,"], ["sa le mafai ona latou tuu i lalo o latou ola,", "they could not suffer to lay down their lives,"], ["ina ia fasiotia a latou ava ma a latou fanau e le saua faapaupau o i latou o e sa avea muamua ma o latou uso,", "that their wives and their children should be massacred by the barbarous cruelty of those who were once their brethren,"], ["ioe,", "yea,"], ["ma ua faatuiese atu mai i la latou ekalesia,", "and had dissented from their church,"], ["ma ua latou tuua i latou ma ua o atu e faaumatia i latou i le auai faatasi ma sa Lamanā.", "and  had left them and had gone to destroy them by joining the Lamanites."]]},
  {num:25,words:[["Ioe,", "Yea,"], ["sa le mafai ona latou talitalia ia fiafia o latou uso i luga o le toto o sa Nifaē,", "they could not bear that their brethren should rejoice over the blood of the Nephites,"], ["pe a i ai lava ni isi o e e tausia poloaiga a le Atua,", "so long as there were any who should keep the commandments of God,"], ["ona o le folafolaga a le Alii e faapea,", "for the promise of the Lord was,"], ["afai latou te tausia ana poloaiga o le a latou manuia i le laueleele.", "if they should keep his commandments they should prosper in the land."]]},
];
renderVerseSet(al_ch_48_Verses, 'al-ch48-verses');

var al_ch_49_Verses = [
  {num:1,words:[["Ma o lenei sa oo i le masina e sefulu tasi o le lona sefulu iva o tausaga,", "And now it came to pass in the eleventh month of the nineteenth year,"], ["i le aso sefulu o le masina,", "on the tenth day of the month,"], ["na vaaia ai autau a sa Lamanā ua agai latalata atu i le laueleele o Amonaea.", "the armies of the Lamanites were seen approaching towards the land of Ammonihah."]]},
  {num:2,words:[["Ma faauta,", "And behold,"], ["sa uma ona toe fausia o le aai,", "the city had been rebuilt,"], ["ma sa tuu e Moronae se autau i tafatafa o tuaoi o le aai,", "and Moroni had stationed an army by the borders of the city,"], ["ma sa latou lafo i luga le eleele faataamilo e puipuia ai i latou mai i ufanafana ma maa a sa Lamanā;", "and they had cast up dirt around about to shield them from the arrows and the stones of the Lamanites;"], ["aua faauta,", "for behold,"], ["sa latou tau i maa ma ufanafana.", "they fought with stones and with arrows."]]},
  {num:3,words:[["Faauta,", "Behold,"], ["ua ou fai atu sa toe fausia le aai o Amonaea . Ou te fai atu ia te outou,", "I said that the city of Ammonihah had been rebuilt. I say unto you,"], ["ioe,", "yea,"], ["sa toe fausia se vaega;", "that it was in part rebuilt;"], ["ma ona sa faaumatia e sa Lamanā i se taimi muamua ona o le amioletonu o tagata,", "and because the Lamanites had destroyed it once because of the iniquity of the people,"], ["o lea na latou manatu ai o le a faigofie ona latou toe mauaina mo i latou.", "they supposed that it would again become an easy prey for them."]]},
  {num:4,words:[["Ae faauta,", "But behold,"], ["sa matua tele lava lo latou faanoanoa;", "how great was their disappointment;"], ["aua faauta,", "for behold,"], ["sa eli e sa Nifaē se faupuega o eleele faataamilo ia i latou,", "the Nephites had dug up a ridge of earth round about them,"], ["lea sa matua maualuga tele lava sa le mafai e sa Lamanā ona ta a latou maa ma fana a latou ufanafana ia te i latou ina ia lavevea ai,", "which was so high that the Lamanites could not cast their stones and their arrows at them that they might take effect,"], ["pe na mafai foi ona latou o mai i luga o i latou vagana ai ua ala mai i lo latou nofoaga e ulu mai ai.", "neither could they come upon them save it was by their place of entrance."]]},
  {num:5,words:[["O lenei sa matua ofo lava kapeteni sili o sa Lamanā i le taimi lea,", "Now at this time the chief captains of the Lamanites were astonished exceedingly,"], ["ona o le popoto o sa Nifaē i le sauniuniga o o latou nofoaga o le saogalemu.", "because of the wisdom of the Nephites in preparing their places of security."]]},
  {num:6,words:[["O lenei sa manatu taitai o sa Lamanā,", "Now the leaders of the Lamanites had supposed,"], ["ona o le toatele o lo latou aofai,", "because of the greatness of their numbers,"], ["ioe,", "yea,"], ["sa latou manatu e tatau ona latou maua le avanoa latou te o mai ai i luga o i latou e pei ona latou faia muamua;", "they supposed that they should be privileged to come upon them as they had hitherto done;"], ["ioe,", "yea,"], ["ma sa latou saunia foi i latou lava faatasi ma talita,", "and they had also prepared themselves with shields,"], ["ma ufifatafata;", "and with breastplates;"], ["ma sa latou saunia foi i latou lava faatasi ma ofu pau,", "and they had also prepared themselves with garments of skins,"], ["ioe,", "yea,"], ["o ofu mafiafia lava e ufiufi ai lo latou le lavalava.", "very thick garments to cover their nakedness."]]},
  {num:7,words:[["Ma ona sa faapea ona latou saunia, sa latou manatu ai o le a faigofie ona latou faatoilalo ma pulea o latou uso i le amo o le pologa,", "And being thus prepared they supposed that they should easily overpower and subject their brethren to the yoke of bondage,"], ["pe fasioti ma fasi faatauna i latou e tusa ma lo latou loto.", "or slay and massacre them according to their pleasure."]]},
  {num:8,words:[["Ae faauta,", "But behold,"], ["i lo latou ofo tele,", "to their uttermost astonishment,"], ["sa saunia i latou mo i latou,", "they were prepared for them,"], ["i se ala sa lei iloa lava i totonu o le fanau a Liae. O lenei sa latou saunia mo sa Lamanā,", "in a manner which never had been known among the children of Lehi. Now they were prepared for the Lamanites,"], ["e tau e tusa ai ma faatonuga a Moronae.", "to battle after the manner of the instructions of Moroni."]]},
  {num:9,words:[["Ma sa oo ina matua ofo tele sa Lamanā,", "And it came to pass that the Lamanites,"], ["po o sa Amalekiā,", "or the Amalickiahites,"], ["i le ala sa latou saunia ai mo taua.", "were exceedingly astonished at their manner of preparation for war."]]},
  {num:10,words:[["O lenei,", "Now,"], ["a na sau i lalo i fafo o le laueleele o Nifae le tupu o Amalekia,", "if king Amalickiah had come down out of the land of Nephi,"], ["e taimua i lana autau,", "at the head of his army,"], ["atonu ua ia faatonu sa Lamanā ia latou osofaia sa Nifaē i le aai o Amonaea;", "perhaps he would have caused the Lamanites to have attacked the Nephites at the city of Ammonihah;"], ["aua faauta,", "for behold,"], ["sa le popole o ia mo le toto o ana tagata.", "he did care not for the blood of his people."]]},
  {num:11,words:[["Ae faauta,", "But behold,"], ["sa lei sau i lalo Amalekia lava ia e tau. Ma faauta,", "Amalickiah did not come down himself to battle. And behold,"], ["sa fefefe ana kapeteni sili e osofai sa Nifaē i le aai o Amonaea,", "his chief captains durst not attack the Nephites at the city of Ammonihah,"], ["ona ua sui e Moronae le puleaina o mea i totonu o sa Nifaē,", "for Moroni had altered the management of affairs among the Nephites,"], ["sa oo ina faanoanoa sa Lamanā i o latou nofoaga tuumuli ma sa le mafai ona latou o atu i luga o i latou.", "insomuch that the Lamanites were disappointed in their places of retreat and they could not come upon them."]]},
  {num:12,words:[["O lea na latou tuumuli atu ai i le vao,", "Therefore they retreated into the wilderness,"], ["ma alu la latou togalauapiga ma savavali atu agai i le laueleele o Noa,", "and took their camp and marched towards the land of Noah,"], ["i le manatu o le nofoaga lena e sosoo le sili ona lelei mo i latou e o atu i ai e osofai ai sa Nifaē.", "supposing that to be the next best place for them to come against the Nephites."]]},
  {num:13,words:[["Ona sa latou le iloa ua uma ona tuiolo e Moronae,", "For they knew not that Moroni had fortified,"], ["pe ua uma ona ia fausia o olo puipui,", "or had built forts of security,"], ["mo aai taitasi i le laueleele faataamilo atoa;", "for every city in all the land round about; therefore,"], ["o lea na latou savavali atu ai i le laueleele o Noa ma se mauai maumaututu;", "they marched forward to the land of Noah with a firm determination;"], ["ioe,", "yea,"], ["sa o mai i luma o latou kapeteni sili ma faia se tautoga o le a latou faaumatiaina tagata o le aai lena.", "their chief captains came forward and took an oath that they would destroy the people of that city."]]},
  {num:14,words:[["Ae faauta,", "But behold,"], ["i lo latou ofo tele,", "to their astonishment,"], ["o le aai o Noa,", "the city of Noah,"], ["lea sa avea ma nofoaga vaivai i aso ua mavae,", "which had hitherto been a weak place,"], ["ua avea nei,", "had now,"], ["ona o Moronae,", "by the means of Moroni,"], ["ma aai malosi,", "become strong,"], ["ioe,", "yea,"], ["ua sili atu i le malosi o le aai o Amonaea.", "even to exceed the strength of the city Ammonihah."]]},
  {num:15,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["o le poto lea sa ia Moronae;", "this was wisdom in Moroni;"], ["ona sa manatu o ia o le a latou matatau i le aai o Amonaea;", "for he had supposed that they would be frightened at the city Ammonihah;"], ["ma ona o le aai o Noa sa avea ma vaega aupito sili ona vaivai o le laueleele i aso ua mavae,", "and as the city of Noah had hitherto been the weakest part of the land,"], ["o lea o le a latou savavali atu ai iina e tau ai;", "therefore they would march thither to battle;"], ["ma sa faapea lava ona oo e tusa ma ona manao.", "and thus it was according to his desires."]]},
  {num:16,words:[["Ma faauta,", "And behold,"], ["sa tofia e Moronae o Liae e avea ma kapeteni sili i luga o tane o lena aai;", "Moroni had appointed Lehi to be chief captain over the men of that city;"], ["ma o Liae lava lea o le na tau ma sa Lamanā i le vanu i le itu i sasae o le vaitafe o Saitonu.", "and it was that same Lehi who fought with the Lamanites in the valley on the east of the river Sidon."]]},
  {num:17,words:[["Ma o lenei faauta sa oo ina ua iloa e sa Lamanā o Liae ua pulea le aai sa latou toe faanoanoa,", "And now behold it came to pass, that when the Lamanites had found that Lehi commanded the city they were again disappointed,"], ["ona sa latou fefefe tele ia Liae;", "for they feared Lehi exceedingly;"], ["e ui i lea sa faia e o latou kapeteni sili se tautoga e osofai le aai;", "nevertheless their chief captains had sworn with an oath to attack the city;"], ["o lea na latou avae ai a latou autau.", "therefore, they brought up their armies."]]},
  {num:18,words:[["O lenei faauta,", "Now behold,"], ["sa le mafai e sa Lamanā ona o atu i totonu o o latou olo o le saogalemu i se isi lava ala vagana ai i le mea e ulu mai ai,", "the Lamanites could not get into their forts of security by any other way save by the entrance,"], ["ona o le maualuga o le faupuega sa ati i luga,", "because of the highness of the bank which had been thrown up,"], ["ma le loloto o le utu sa eli faataamilo ai,", "and the depth of the ditch which had been dug round about,"], ["vagana ai i le mea e ulu mai ai.", "save it were by the entrance."]]},
  {num:19,words:[["Ma sa faapea ona saunia o sa Nifaē e faaumatia i latou uma o e e taumafai e feaei ae i luga e ulu mai totonu i le olo i soo se isi lava auala,", "And thus were the Nephites prepared to destroy all such as should attempt to climb up to enter the fort by any other way,"], ["i le ta atu i luga o maa ma le fana atu o ufanafana ia i latou.", "by casting over stones and arrows at them."]]},
  {num:20,words:[["Sa faapea ona latou saunia,", "Thus they were prepared,"], ["ioe,", "yea,"], ["o se vaega o o latou tane malolosi,", "a body of their strongest men,"], ["latou te ta i lalo ia latou pelu ma a latou maata,", "with their swords and their slings,"], ["i latou uma o e e taumafai e o mai i totonu o lo latou nofoaga o le saogalemu e ala mai i le mea e ulu mai ai;", "to smite down all who should attempt to come into their place of security by the place of entrance;"], ["ma sa faapea ona latou saunia e puipui i latou lava e faasaga ia sa Lamanā.", "and thus were they prepared to defend themselves against the Lamanites."]]},
  {num:21,words:[["Ma sa oo ina avae e kapeteni a sa Lamanā a latou autau i luma o le mea e ulu mai ai,", "And it came to pass that the captains of the Lamanites brought up their armies before the place of entrance,"], ["ma amata ona tau ma sa Nifaē,", "and began to contend with the Nephites,"], ["ina ia o mai i totonu o lo latou nofoaga o le saogalemu;", "to get into their place of security;"], ["ae faauta,", "but behold,"], ["sa tulia i latou i tua mai lea taimi i lea taimi,", "they were driven back from time to time,"], ["sa oo ina fasiotia i latou i se fasiga tele.", "insomuch that they were slain with an immense slaughter."]]},
  {num:22,words:[["O lenei ina ua latou iloa ua le mafai ona latou maua se mana i luga o sa Nifaē i le mea e ui mai ai,", "Now when they found that they could not obtain power over the Nephites by the pass,"], ["sa amata ona latou eli i lalo o latou faupuega eleele ina ia mafai ona latou maua o se ala mo a latou autau,", "they began to dig down their banks of earth that they might obtain a pass to their armies,"], ["ina ia mafai ona latou maua se avanoa tutusa e tau ai;", "that they might have an equal chance to fight;"], ["ae faauta, i ia taumafaiga,", "but behold,"], ["sa tafi ese ai i latou i maa ma ufanafana na sasau ma fana atu ia te i latou;", "in these attempts they were swept off by the stones and arrows which were thrown at them;"], ["ma nai lo le faatumuina o o latou utu i le solofa i lalo o faupuega eleele,", "and instead of filling up their ditches by pulling down the banks of earth,"], ["sa faatumuina se vaega o ia utu i o latou tagata oti ma tagata manunua.", "they were filled up in a measure with their dead and wounded bodies."]]},
  {num:23,words:[["Sa faapea ona maua e sa Nifaē le mana atoatoa i luga o o latou fili;", "Thus the Nephites had all power over their enemies;"], ["ma sa faapea ona taumafai o sa Lamanā e faaumatia sa Nifaē seia oo ina fasiotia uma ai o latou kapeteni sili;", "and thus the Lamanites did attempt to destroy the Nephites until their chief captains were all slain;"], ["ioe,", "yea,"], ["ma e sili atu i le afe sa Lamanā sa fasiotia;", "and more than a thousand of the Lamanites were slain;"], ["ae,", "while,"], ["i le isi itu,", "on the other hand,"], ["sa leai se tagata e toatasi o sa Nifaē na fasiotia.", "there was not a single soul of the Nephites which was slain."]]},
  {num:24,words:[["Sa i ai le pe a ma le lima sefulu o e na manunua,", "There were about fifty who were wounded,"], ["o e na aliali i ufanafana a sa Lamanā i le mea e ui mai ai,", "who had been exposed to the arrows of the Lamanites through the pass,"], ["peitai sa puipuia i latou ia latou talita,", "but they were shielded by their shields,"], ["ma a latou ufifatafata,", "and their breastplates,"], ["ma o latou puloutau,", "and their head– plates,"], ["sa oo o le tele o o latou manunua sa i o latou vae,", "insomuch that their wounds were upon their legs,"], ["ma o le tele o ia manua sa leaga tele.", "many of which were very severe."]]},
  {num:25,words:[["Ma sa oo ina ua vaai sa Lamanā ua fasiotia uma o latou kapeteni sili,", "And it came to pass,"], ["sa latou sosola i le vao. Ma sa oo ina latou toe foi atu i le laueleele o Nifae,", "that when the Lamanites saw that their chief captains were all slain they fled into the wilderness. And it came to pass that they returned to the land of Nephi,"], ["e tau i lo latou tupu,", "to inform their king,"], ["o Amalekia,", "Amalickiah,"], ["o le o se sa Nifaē i lona fanau mai,", "who was a Nephite by birth,"], ["e uiga i lo latou toesea tele.", "concerning their great loss."]]},
  {num:26,words:[["Ma sa oo ina ita tele o ia i ana tagata,", "And it came to pass that he was exceedingly angry with his people,"], ["ona ua le taulau lona manao mo sa Nifaē;", "because he had not obtained his desire over the Nephites;"], ["sa le mafai e ia ona pulea i latou i le amo o le pologa.", "he had not subjected them to the yoke of bondage."]]},
  {num:27,words:[["Ioe,", "Yea,"], ["sa ita tele o ia,", "he was exceedingly wroth,"], ["ma sa ia upuvale i le Atua,", "and he did curse God,"], ["ma Moronae foi,", "and also Moroni,"], ["ma tauto i se tautoga o le a ia inuina lona toto;", "swearing with an oath that he would drink his blood;"], ["ma o le pogai o lenei mea ona sa tausi e Moronae poloaiga a le Atua i le saunia mo le saogalemu o ona tagata.", "and this because Moroni had kept the commandments of God in preparing for the safety of his people."]]},
  {num:28,words:[["Ma sa oo i le tasi itu,", "And it came to pass,"], ["sa faafetai atu le nuu o Nifae i le Alii lo latou Atua,", "that on the other hand, the people of Nephi did thank the Lord their God,"], ["ona o lona mana le mafaatusalia i le laveaiina o i latou mai lima o o latou fili.", "because of his matchless power in delivering them from the hands of their enemies."]]},
  {num:29,words:[["Ma sa faapea ona iu o le lona sefulu iva o tausaga o le nofoaiga a faamasino i le nuu o Nifae.", "And thus ended the nineteenth year of the reign of the judges over the people of Nephi."]]},
  {num:30,words:[["Ioe,", "Yea,"], ["ma sa i ai le filemu faaauau pea i totonu o i latou,", "and there was continual peace among them,"], ["ma le manuia tele lava i le ekalesia ona o lo latou uai atu ma le filiga sa latou tuuina atu i le afioga a le Atua,", "and exceedingly great prosperity in the church because of their heed and diligence which they gave unto the word of God,"], ["lea sa talai atu ia te i latou e Helamana,", "which was declared unto them by Helaman,"], ["ma Sepulona,", "and Shiblon,"], ["ma Korianetona,", "and Corianton,"], ["ma Amona ma ona uso,", "and Ammon and his brethren,"], ["ioe,", "yea,"], ["ma i latou uma o e na faauuina i le faatulagaga paia a le Atua,", "and by all those who had been ordained by the holy order of God,"], ["ua papatisoina i le salamo,", "being baptized unto repentance,"], ["ma auina atu e talai i totonu o le nuu.", "and sent forth to preach among the people."]]},
];
renderVerseSet(al_ch_49_Verses, 'al-ch49-verses');

var al_ch_50_Verses = [
  {num:1,words:[["Ma o lenei sa oo sa le taofia e Moronae le faia o sauniuniga mo taua,", "And now it came to pass that Moroni did not stop making preparations for war,"], ["po o le leoleoina o ona tagata e faasaga ia sa Lamanā;", "or to defend his people against the Lamanites;"], ["ona sa ia faatonu atu ia amata e ana autau i le amataga o le tausaga e lua sefulu o le nofoaiga a faamasino,", "for he caused that his armies should commence in the commencement of the twentieth year of the reign of the judges,"], ["e tatau ona amata ona latou eli i luga faupuega eleele faataamilo i aai uma,", "that they should commence in digging up heaps of earth round about all the cities,"], ["i le laueleele atoa lea sa maua e sa Nifaē.", "throughout all the land which was possessed by the Nephites."]]},
  {num:2,words:[["Ma i le tumutumu o ia faupuega eleele sa ia faatonu atu e tatau ona i ai ni laau tetele,", "And upon the top of these ridges of earth he caused that there should be timbers,"], ["ioe,", "yea,"], ["se pa laau tetele e tusa ma le maualuga o se tagata,", "works of timbers built up to the height of a man,"], ["e faatutu faataamilo i aai.", "round about the cities."]]},
  {num:3,words:[["Ma sa ia faatonu atu ia fausia faataamilo i luga o ia pa laau tetele, se pa laau maamaai;", "And he caused that upon those works of timbers there should be a frame of pickets built upon the timbers round about;"], ["ma sa malolosi ma maualuluga.", "and they were strong and high."]]},
  {num:4,words:[["Ma sa ia faatonu ia fausia ni olo e iloa atu ai ia pa laau maamaai,", "And he caused towers to be erected that overlooked those works of pickets,"], ["ma sa ia faatonu atu ia fausia ni nofoaga o le saogalemu i luga o ia olo,", "and he caused places of security to be built upon those towers,"], ["ina ia le mafai ona latou lavevea i maa ma ufanafana a sa Lamanā.", "that the stones and the arrows of the Lamanites could not hurt them."]]},
  {num:5,words:[["Ma sa latou saunia ina ia mafai ona latou lafo ifo o maa mai le tumutumu o ia olo,", "And they were prepared that they could cast stones from the top thereof,"], ["e tusa ma o latou loto ma lo latou malolosi,", "according to their pleasure and their strength,"], ["ma fasioti o ia o le e taumafai e faalatalata mai i le pa o le aai.", "and slay him who should attempt to approach near the walls of the city."]]},
  {num:6,words:[["Ma sa faapea ona saunia e Moronae nofoaga malolosi faataamilo i aai taitasi i le laueleele atoa,", "Thus Moroni did prepare strongholds against the coming of their enemies,"], ["aua le o mai o o latou fili.", "round about every city in all the land."]]},
  {num:7,words:[["Ma sa oo ina faatonu e Moronae ana autau ia latou o atu i le vao i sasae;", "And it came to pass that Moroni caused that his armies should go forth into the east wilderness;"], ["ioe,", "yea,"], ["ma sa latou o atu ma tutuli ese atu sa Lamanā uma o e sa i ai i le vao i sasae i o latou lava laueleele,", "and they went forth and drove all the Lamanites who were in the east wilderness into their own lands,"], ["ia sa i saute o le laueleele o Sara'emila.", "which were south of the land of Zarahemla."]]},
  {num:8,words:[["Ma o le laueleele o Nifae sa taoto i se laina sao mai le sami i sasae e oo atu i sisifo.", "And the land of Nephi did run in a straight course from the east sea to the west."]]},
  {num:9,words:[["Ma sa oo ina ua uma ona tutuli ese i fafo e Moronae sa Lamanā uma mai le vao i sasae,", "And it came to pass that when Moroni had driven all the Lamanites out of the east wilderness,"], ["lea sa i le itu i matu o o latou lava laueleele ua maua,", "which was north of the lands of their own possessions,"], ["sa ia faatonu atu e tatau i tagata o e sa i le laueleele o Sara'emila ma le laueleele faataamilo ai, ona o atu i le vao i sasae,", "he caused that the inhabitants who were in the land of Zarahemla and in the land round about should go forth into the east wilderness,"], ["sei oo atu i tuaoi i tafatafa o le matafaga,", "even to the borders by the seashore,"], ["ma fai mo i latou le laueleele.", "and possess the land."]]},
  {num:10,words:[["Ma sa ia tuu foi autau i le itu i saute,", "And he also placed armies on the south,"], ["i tuaoi o o latou laueleele;", "in the borders of their possessions,"], ["ma faatonu i latou ia faatutu ni olo ina ia mafai ona latou puipui a latou autau ma o latou tagata mai lima o o latou fili.", "and caused them to erect fortifications that they might secure their armies and their people from the hands of their enemies."]]},
  {num:11,words:[["Ma sa faapea ona ia tapui o vaega malolosi uma o sa Lamanā i le vao i sasae,", "And thus he cut off all the strongholds of the Lamanites in the east wilderness,"], ["ioe,", "yea,"], ["ma le itu foi i sisifo,", "and also on the west,"], ["ma tuiolo le laina i le va o sa Nifaē ma sa Lamanā,", "fortifying the line between the Nephites and the Lamanites,"], ["i le va o le laueleele o Sara'emila ma le laueleele o Nifae,", "between the land of Zarahemla and the land of Nephi,"], ["mai i le sami i sisifo,", "from the west sea,"], ["e faasolo atu i tafatafa o le mata o le vaitafe o Saitonu—ua maua ai e sa Nifaē le laueleele uma i matu,", "running by the head of the river Sidon—the Nephites possessing all the land northward,"], ["ioe,", "yea,"], ["le laueleele uma lava lea sa i le itu i matu o le laueleele o Nuumau,", "even all the land which was northward of the land Bountiful,"], ["e tusa ma lo latou manao.", "according to their pleasure."]]},
  {num:12,words:[["Sa faapea ona saili o Moronae,", "Thus Moroni,"], ["faatasi ma ana autau,", "with his armies,"], ["ia sa faatoateleina i aso taitasi ona o le mautinoa o le puipuiga lea sa oo mai i o latou luga i ana galuega,", "which did increase daily because of the assurance of protection which his works did bring forth unto them,"], ["e tapui le malosi ma le pule a sa Lamanā mai o latou laueleele,", "did seek to cut off the strength and the power of the Lamanites from off the lands of their possessions,"], ["ina ia leai sa latou pule i luga o o latou laueleele.", "that they should have no power upon the lands of their possession."]]},
  {num:13,words:[["Ma sa oo ina amata ona faia e sa Nifaē le faavae o se aai,", "And it came to pass that the Nephites began the foundation of a city,"], ["ma sa latou taua le igoa o le aai o Moronae;", "and they called the name of the city Moroni;"], ["ma sa tu i tafatafa o le sami i sasae;", "and it was by the east sea;"], ["ma sa i le itu i saute i tafatafa o le laina o laueleele o sa Lamanā.", "and it was on the south by the line of the possessions of the Lamanites."]]},
  {num:14,words:[["Ma sa amata foi ona latou faia o se faavae mo se aai i le va o le aai o Moronae ma le aai o Arona,", "And they also began a foundation for a city between the city of Moroni and the city of Aaron,"], ["ua sosoo faatasi ai tuaoi o Arona ma Moronae. Ma sa latou taua le igoa o le aai,", "joining the borders of Aaron and Moroni;"], ["po o le laueleele,", "and they called the name of the city, or the land,"], ["o Nifaea.", "Nephihah."]]},
  {num:15,words:[["Ma sa latou amata foi i lena lava tausaga ona fausia aai e tele i le itu i matu,", "And they also began in that same year to build many cities on the north,"], ["o se tasi sa latou fausia i se ala ese lava sa latou faaigoaina o Liae,", "one in a particular manner which they called Lehi,"], ["lea sa i le itu i matu i tafatafa o tuaoi o le matafaga.", "which was in the north by the borders of the seashore."]]},
  {num:16,words:[["Ma sa faapea ona iu o o le tausaga e lua sefulu.", "And thus ended the twentieth year."]]},
  {num:17,words:[["Ma o tulaga ia o le manuia sa i ai le nuu o Nifae i le amataga o le tausaga e lua sefulu ma le tasi o le nofoaiga a faamasino i le nuu o Nifae.", "And in these prosperous circumstances were the people of Nephi in the commence– ment of the twenty and first year of the reign of the judges over the people of Nephi."]]},
  {num:18,words:[["Ma sa latou manuia tele lava,", "And they did prosper exceedingly,"], ["ma sa latou mauoa tele;", "and they became exceedingly rich;"], ["ioe,", "yea,"], ["ma sa latou uluola ma solo malolosi i le laueleele.", "and they did multiply and wax strong in the land."]]},
  {num:19,words:[["Ma ua faapea ona tatou vaai ai i le alofa mutimutivale tele ma le tonu o aloaiga uma a le Alii,", "And thus we see how merciful and just are all the dealings of the Lord,"], ["i le faataunuuina o ana fetalaiga uma i le fanauga a tagata;", "to the fulfilling of all his words unto the children of men;"], ["ioe,", "yea,"], ["e mafai ona tatou vaai,", "we can behold that his words are verified,"], ["i le taimi nei lava,", "even at this time,"], ["i le faamaonia o ana afioga ia na ia fetalai ai ia Liae,", "which he spake unto Lehi,"], ["fai mai:", "saying:"]]},
  {num:20,words:[["Amuia lava oe ma lau fanau;", "Blessed art thou and thy children;"], ["ma o le a faamanuiaina i latou;", "and they shall be blessed,"], ["o le tulaga e oo i ai la latou tausiga o au poloaiga o le a latou manuia i le laueleele. Ae ia manatua,", "inasmuch as they shall keep my commandments they shall prosper in the land.  But remember,"], ["o le tulaga e oo i ai la latou lē tausia o au poloaiga o le a vavae ese i latou mai luma o le Alii.", "inasmuch as they will not keep my commandments they shall be cut off from the presence of the Lord."]]},
  {num:21,words:[["Ma ua tatou vaai ua faamaonia ia folafolaga i le nuu o Nifae;", "And we see that these promises have been verified to the people of Nephi;"], ["ona o a latou misa ma a latou finauga,", "for it has been their quarrelings and their contentions,"], ["ioe,", "yea,"], ["a latou fasiotiga tagata,", "their murderings,"], ["ma a latou vetega,", "and their plunderings,"], ["lo latou ifo i tupua,", "their idolatry,"], ["a latou faitaaga,", "their whoredoms,"], ["ma lo latou fai mea inosia,", "and their  abominations,"], ["sa i ai i totonu o i latou lava,", "which were among them– selves,"], ["na aumai ai i luga o i latou a latou taua ma o latou faafanoga.", "which brought upon them their wars and their destructions."]]},
  {num:22,words:[["Ma o i latou o e sa faamaoni i le tausiga o poloaiga a le Alii sa laveaiina i taimi uma,", "And those who were faithful in keeping the commandments of the Lord were delivered at all times,"], ["ao le afe ma afe o o latou uso amioleaga sa tuu atu i le pologa,", "whilst thousands of their wicked brethren have been consigned to bondage,"], ["pe fano i le pelu,", "or to perish by the sword,"], ["pe faaitiitia i le le talitonu,", "or to dwindle in unbelief,"], ["ma aufaatasi ma sa Lamanā.", "and mingle with the Lamanites."]]},
  {num:23,words:[["Ae faauta sa leai se taimi sili ona fiafia i totonu o le nuu o Nifae,", "But behold there never was a happier time among the people of Nephi,"], ["talu mai aso o Nifae,", "since the days of Nephi,"], ["nai lo aso o Moronae,", "than in the days of Moroni,"], ["ioe,", "yea,"], ["e oo mai lava i le taimi nei,", "even at this time,"], ["i le tausaga lea e lua sefulu ma le tasi o le nofoaiga a faamasino.", "in the twenty and first year of the reign of the judges."]]},
  {num:24,words:[["Ma sa oo ina iu foi i le filemu le tausaga e lua sefulu ma le lua o le nofoaiga a faamasino;", "And it came to pass that the twenty and second year of the reign of the judges also ended in peace;"], ["ioe,", "yea,"], ["ma le tausaga foi e lua sefulu ma le tolu.", "and also the twenty and third year."]]},
  {num:25,words:[["Ma sa oo i le amataga o le tausaga e lua sefulu ma le fa o le nofoaiga a faamasino,", "And it came to pass that in the commence– ment of the twenty and fourth year of the reign of the judges,"], ["semanu foi e i ai le filemu i totonu o le nuu o Nifae,", "there would also have been peace among the people of Nephi had it not been for a contention which took place among them concerning the land of Lehi,"], ["pe a na leai se finauga na tupu mai i totonu o i latou e uiga i le laueleele o Liae ma le laueleele o Morianetona,", "and the land of Morianton,"], ["lea sa sosoo ma tuaoi o Liae;", "which joined upon the borders of Lehi;"], ["ia sa i ai uma i tuaoi i tafatafa o le matafaga o le sami.", "both of which were on the borders by the seashore."]]},
  {num:26,words:[["Aua faauta,", "For behold,"], ["o tagata o e sa mau i le laueleele o Morianetona,", "the people who possessed the land of Morianton did claim a part of the land of Lehi;"], ["sa fai mai e o latou se vaega o le laueleele o Liae; o lea na amata ai se finauga vevela i lo latou va,", "therefore there began to be a warm contention between them,"], ["sa oo ina sii ai e le nuu o Morianetona auupega o taua e faasaga i o latou uso,", "insomuch that the people of Morianton took up arms against their brethren,"], ["ma sa latou mauai e fasioti i latou i le pelu.", "and they were determined by the sword to slay them."]]},
  {num:27,words:[["Ae faauta,", "But behold,"], ["sa sosola tagata sa nonofo i le laueleele o Liae i le togalauapi a Moronae,", "the people who possessed the land of Lehi fled to the camp of Moroni,"], ["ma aioi atu ia te ia mo se fesoasoani;", "and appealed unto him for assistance;"], ["aua faauta sa latou le sese.", "for behold they were not in the wrong."]]},
  {num:28,words:[["Ma sa oo ina ua iloa e le nuu o Morianetona,", "And it came to pass that when the people of Morianton,"], ["o e sa taitaia e se tagata sa igoa ia Morianetona,", "who were led by a man whose name was Morianton,"], ["ua sosola atu le nuu o Liae i le togalauapi a Moronae,", "found that the people of Lehi had fled to the camp of Moroni,"], ["sa latou matatau tele lava nei o mai le autau a Moronae i luga o i latou ma faaumatia i latou.", "they were exceedingly fearful lest the army of Moroni should come upon them and destroy them."]]},
  {num:29,words:[["O lea,", "Therefore,"], ["na tuu ai e Morianetona i o latou loto,", "Morianton put it into their hearts that they should flee to the land which was northward,"], ["ia latou sosola atu i le laueleele lea sa i le itu i matu, lea sa ufitia i vaituloto tetele,", "which was covered with large bodies of water,"], ["ma ave mo i latou le laueleele lea sa i le itu i matu.", "and take possession of the land which was northward."]]},
  {num:30,words:[["Ma faauta,", "And behold,"], ["semanu latou te faataunuuina lenei fuafuaga,", "they would have carried this plan into effect,"], ["(lea semanu e tupu mai ai se faanoanoa) ae faauta,", "(which would have been a cause to have been lamented) but behold,"], ["ona o Morianetona o se tagata faalii tele,", "Morianton being a man of much passion,"], ["o lea na ita ai o ia i se tasi o ana auauna fafine,", "therefore he was angry with one of his maid servants,"], ["ma ia oo atu ai ia te ia ma fasi tele ia te ia.", "and he fell upon her and beat her much."]]},
  {num:31,words:[["Ma sa oo ina sola le auauna fafine,", "And it came to pass that she fled,"], ["ma sau i le togalauapi a Moronae,", "and came over to the camp of Moroni,"], ["ma tau mai ia Moronae mea uma e uiga i le mataupu,", "and told Moroni all things concerning the matter,"], ["ma e uiga foi i lo latou faamoemoe e sosola atu i le laueleele i le itu i matu.", "and also concerning their intentions to flee into the land northward."]]},
  {num:32,words:[["O lenei faauta,", "Now behold,"], ["o tagata sa i le laueleele o Nuumau,", "the people who were in the land Bountiful,"], ["po o Moronae,", "or rather Moroni,"], ["sa popole nei o latou faalogo i upu a Morianetona ma aufaatasi ai ma ona tagata,", "feared that they would hearken to the words of Morianton and unite with his people,"], ["ma faapea ona ia maua ai o vaega na o le laueleele,", "and thus he would obtain possession of those parts of the land,"], ["lea o le a faataatia ai se faavae o iuga tuga i totonu o le nuu o Nifae,", "which would lay a foundation for serious consequences among the people of Nephi,"], ["ioe,", "yea,"], ["iuga ia e tau i le faatoilaloina o lo latou saolotoga .", "which consequences would lead to the overthrow of their liberty."]]},
  {num:33,words:[["O lea na auina atu ai e Moronae se autau,", "Therefore Moroni sent an army,"], ["faatasi ma la latou togalauapi,", "with their camp,"], ["e sisio mai tagata o Morianetona,", "to head the people of Morianton,"], ["e taofi la latou solaaga i le laueleele i matu.", "to stop their flight into the land northward."]]},
  {num:34,words:[["Ma sa oo ina latou le sisio maia i latou seia oo ina latou oo atu i tuaoi o le laueleele o Tuufua ;", "And it came to pass that they did not head them until they had come to the borders of the land Desolation;"], ["ma o iina na latou sisio mai ai i latou,", "and there they did head them,"], ["i tafatafa o le ala vaapiapi lea sa ui atu i tafatafa o le sami e tau i le laueleele i matu,", "by the narrow pass which led by the sea into the land northward,"], ["ioe,", "yea,"], ["i tafatafa o le sami,", "by the sea,"], ["i le itu i sisifo ma le itu i sasae.", "on the west and on the east."]]},
  {num:35,words:[["Ma sa oo ina fetaiai le autau na auina atu e Moronae,", "And it came to pass that the army which was sent by Moroni,"], ["lea na taitai e se tagata o lona igoa o Teanekuma,", "which was led by a man whose name was Teancum,"], ["ma tagata o Morianetona;", "did meet the people of Morianton;"], ["ma sa matua finauvale tele tagata o Morianetonu,", "and so stubborn were the people of Morianton,"], ["(ona sa uunaia i latou e lona amioleaga ma ana upu faaviivii) sa oo ina tupu se taua i lo latou va,", "(being inspired by his wickedness and his flattering words) that a battle commenced between them,"], ["lea na fasioti ai Morianetona e Teanekuma ma faatoilalo lana autau,", "in the which Teancum did slay Morianton and defeat his army,"], ["ma ave i latou faapagota,", "and took them prisoners,"], ["ma toe foi mai i le togalauapi a Moronae. Ma sa faapea ona iu o le tausaga e lua sefulu ma le fa o le nofoaiga a faamasino i luga o le nuu o Nifae.", "and returned to the camp of Moroni. And thus ended the twenty and fourth year of the reign of the judges over the people of Nephi."]]},
  {num:36,words:[["Ma sa faapea ona toe aumai o le nuu o Morianetona.", "And thus were the people of Morianton brought back."], ["Ma i luga o lo latou osifeagaiga e tausi le filemu,", "And upon their covenanting to keep the peace they were restored to the land of Morianton,"], ["na toefuatai atu ai i latou i le laueleele o Morianetona, ma sa faia se sootaga i lo latou va ma le nuu o Liae;", "and a union took place between them and the people of Lehi;"], ["ma sa toefuatai foi i latou i o latou laueleele.", "and they were also restored to their lands."]]},
  {num:37,words:[["Ma sa oo i le tausaga lava lea na toefuatai mai ai e le nuu o Nifae le filemu ia te i latou,", "And it came to pass that in the same year that the people of Nephi had peace restored unto them,"], ["na maliu ai Nifaea,", "that Nephihah,"], ["le faamasino sili lona lua,", "the second chief judge, died,"], ["ina ua uma ona ia nofo i le nofoa-faamasino ma le amiosao atoatoa i luma o le Atua.", "having filled the judgment– seat with perfect uprightness before God."]]},
  {num:38,words:[["E ui i lea,", "Nevertheless,"], ["sa ia teena Alema na te ave e tausi talafaamaumau ma mea sa manatu i ai Alema ma lona tamā ua sili ona paia;", "he had refused Alma to take possession of those records and those things which were esteemed by Alma and his fathers to be most sacred; therefore Alma had conferred them upon his son,"], ["o lea na tuu atu ai e Alema ia mea i lona atalii o Helamana.", "Helaman."]]},
  {num:39,words:[["Faauta,", "Behold,"], ["sa oo ina tofia le atalii o Nifaea e nofo i le nofoa-faamasino,", "it came to pass that the son of Nephihah was appointed to fill the judgment– seat,"], ["e sui i lona tamā;", "in the stead of his father;"], ["ioe,", "yea,"], ["sa tofia o ia e faamasino sili ma kovana i luga o le nuu,", "he was appointed chief judge and governor over the people,"], ["faatasi ma se tautoga ma se sauniga paia e faamasino ma le amiotonu,", "with an oath and sacred ordinance to judge righteously,"], ["ma tausi le filemu ma le saolotoga o le nuu,", "and to keep the peace and the freedom of the people,"], ["ma tuu atu ia te i latou o latou avanoa paia e tapuai ai i le Alii lo latou Atua,", "and to grant unto them their sacred privileges to worship the Lord their God,"], ["ioe,", "yea,"], ["e lagolago ma faatumau le galuega a le Atua i ona aso uma,", "to support and maintain the cause of God all his days,"], ["ma aumai e amioleaga i le faamasinoga e tusa ma a latou solitulafono.", "and to bring the wicked to justice according to their crime."]]},
  {num:40,words:[["O lenei faauta,", "Now behold,"], ["o lona igoa o Paorana. Ma sa nofo Paorana i le nofoaga o lona tamā,", "his name was Pahoran. And Pahoran did fill the seat of his father,"], ["ma sa amata lana nofoaiga i luga o le nuu o Nifae,", "and did commence his reign in the end of the twenty and fourth year,"], ["i le faaiuga o le tausaga e lua sefulu ma le fa.", "over the people of Nephi."]]},
];
renderVerseSet(al_ch_50_Verses, 'al-ch50-verses');

var al_ch_51_Verses = [
  {num:1,words:[["Ma o lenei sa oo i le amataga o le tausaga e lua sefulu ma le lima o le nofoaiga a faamasino i luga o le nuu o Nifae,", "And now it came to pass in the commence– ment of the twenty and fifth year of the reign of the judges over the people of Nephi,"], ["ina ua uma lea ona latou faatu o le filemu i le va o le nuu o Liae ma le nuu o Morianetona e uiga i o latou laueleele,", "they having established peace between the people of Lehi and the people of Morianton concerning their lands,"], ["ma ina uma ona amata o le tausaga e lua sefulu ma le lima i le filemu;", "and having commenced the twenty and fifth year in peace;"]]},
  {num:2,words:[["E ui i lea,", "Nevertheless,"], ["sa lei umi ona latou faatumauina o se filemu atoatoa i le laueleele,", "they did not long maintain an entire peace in the land,"], ["ona sa amata ona i ai o se finauga i totonu o le nuu e uiga i le faamasino sili o Paorana;", "for there began to be a contention among the people concerning the chief judge Pahoran;"], ["aua faauta,", "for behold,"], ["sa i ai se vaega o le nuu o e sa mananao e tatau ona suia ni matautu faapitoa o le tulafono.", "there were a part of the people who desired that a few particular points of the law should be altered."]]},
  {num:3,words:[["Ae faauta,", "But behold,"], ["sa le manao Paorana e suia pe tuu atu le tulafono ia suia;", "Pahoran would not alter nor suffer the law to be altered;"], ["o lea,", "therefore,"], ["sa ia le faalogo ai ia te i latou o e na auina mai o latou leo faatasi ma a latou talosaga e uiga i le suia o le tulafono.", "he did not hearken to those who had sent in their voices with their petitions concerning the altering of the law."]]},
  {num:4,words:[["O lea,", "Therefore,"], ["o i latou o e sa mananao e sui le tulafono sa feita ia te ia,", "those who were desirous that the law should be altered were angry with him,"], ["ma mananao e tatau ona le toe avea o ia ma faamasino sili i luga o le laueleele;", "and desired that he should no longer be chief judge over the land;"], ["o lea na tupu mai ai se finauga vevela e uiga i le mataupu,", "therefore there arose a warm dispute concerning the matter,"], ["ae sa lei oo i le faamasaatoto.", "but not unto bloodshed."]]},
  {num:5,words:[["Ma sa oo ina o i latou o e na mananao e aveese Paorana mai le nofoa-faamasino, sa taua o tagata-tupu,", "And it came to pass that those who were desirous that Pahoran should be dethroned from the judgment– seat were called king– men,"], ["ona sa latou mananao e tatau ona sui le tulafono i se ala e aveese ai le malo saoloto ma ia faatu se tupu i luga o le laueleele.", "for they were desirous that the law should be altered in a manner to overthrow the free government and to establish a king over the land."]]},
  {num:6,words:[["Ma o i latou o e na mananao e tatau ona tumau pea Paorana ma faamasino sili i luga o le laueleele, sa latou ave i o latou luga le igoa o tagata-saoloto;", "And those who were desirous that Pahoran should remain chief judge over the land took upon them the name of freemen;"], ["ma sa faapea le vaeluaga sa i ai i totonu o i latou, ona sa tauto,", "and thus was the division among them,"], ["pe sa osifeagaiga tagata-saoloto, e taofi mau a latou aia ma avanoa o la latou tapuaiga e ala i se malo saoloto.", "for the freemen had sworn or covenanted to maintain their rights and the privileges of their religion by a free government."]]},
  {num:7,words:[["Ma sa oo ina foiaina lenei mataupu o la latou finauga i le leo o le nuu.", "And it came to pass that this matter of their contention was settled by the voice of the people."], ["Ma sa oo ina oo mai le leo o le nuu,", "And it came to pass that the voice of the people came in favor of the freemen,"], ["ua latou lagolagoina tagata-saoloto,", "and Pahoran retained the judgment– seat,"], ["ma sa taofi pea e Paorana le nofoa-faamasino, o se mea sa tupu mai ai se olioli tele i totonu o uso o Paorana ma le toatele foi o tagata o le saolotoga,", "which caused much rejoicing among the brethren of Pahoran and also many of the people of liberty,"], ["o e na latou faafilemuina foi tagata-tupu,", "who also put the king– men to silence,"], ["na latou fefefe ai e tetee ae ua faamalosia e tausi le faamoemoe o le saolotoga.", "that they durst not oppose but were obliged to maintain the cause of freedom."]]},
  {num:8,words:[["O lenei o i latou o e sa mananao i tupu o i latou ia o tamalii ,", "Now those who were in favor of kings were those of high birth,"], ["ma sa latou saili ia avea i latou ma tupu;", "and they sought to be kings;"], ["ma sa lagolagoina i latou e i latou o e sa latou saili le mana ma le pule i luga o le nuu.", "and they were supported by those who sought power and authority over the people."]]},
  {num:9,words:[["Ae faauta,", "But behold,"], ["o se taimi ogaoga tele lea mo finauga faapea i totonu o le nuu o Nifae;", "this was a critical time for such contentions to be among the people of Nephi;"], ["aua faauta,", "for behold,"], ["ua toe faaoso e Amalekia loto o sa Lamanā e faasaga i tagata sa Nifaē,", "Amalickiah had again stirred up the hearts of the people of the Lamanites against the people of the Nephites,"], ["ma sa ia faapotopoto faatasi fitafita mai itu uma o lona laueleele,", "and he was gathering together soldiers from all parts of his land,"], ["ma faaauupega i latou,", "and arming them,"], ["ma sauniuni ma le filiga atoa mo le taua;", "and preparing for war with all diligence;"], ["ona sa ia tauto na te inuina le toto o Moronae.", "for he had sworn to drink the blood of Moroni."]]},
  {num:10,words:[["Ae faauta,", "But behold,"], ["o le a tatou vaai ua vavevave lana folafolaga lea na ia fai;", "we shall see that his promise which he made was rash;"], ["e ui i lea,", "nevertheless,"], ["na ia saunia o ia lava ma ana autau e o mai e tau faasaga ia sa Nifaē.", "he did prepare himself and his armies to come to battle against the Nephites."]]},
  {num:11,words:[["O lenei sa le toatele ana autau e pei ona sa latou i ai i taimi ua mavae,", "Now his armies were not so great as they had hitherto been,"], ["ona o le tele o afe na fasiotia i lima o sa Nifaē;", "because of the many thousands who had been slain by the hand of the Nephites;"], ["ae e ui i lo latou toesega tele,", "but notwithstanding their great loss,"], ["sa faapotopoto faatasi e Amalekia se autau ofoofogia le toatele,", "Amalickiah had gathered together a wonderfully great army,"], ["sa oo ina le fefe o ia e alu ifo i lalo i le laueleele o Sara'emila.", "insomuch that he feared not to come down to the land of Zarahemla."]]},
  {num:12,words:[["Ioe,", "Yea,"], ["sa alu ifo i lalo Amalekia lava ia,", "even Amalickiah did himself come down,"], ["i le tumua o sa Lamanā. Ma o le tausaga e lua sefulu ma le lima o le nofoaiga a faamasino na alu ifo ai;", "at the head of the Lamanites. And it was in the twenty and fifth year of the reign of the judges;"], ["ma o le taimi lava lea na amata ai ona latou foia o mataupu o a latou finauga e uiga i le faamasino sili,", "and it was at the same time that they had begun to settle the affairs of their contentions concerning the chief judge,"], ["o Paorana.", "Pahoran."]]},
  {num:13,words:[["Ma sa oo ina ua faalogo tagata sa taua o tagata-tupu ua o mai sa Lamanā i lalo e tau faasaga mai ia te i latou,", "And it came to pass that when the men who were called king– men had heard that the Lamanites were coming down to battle against them,"], ["sa latou fiafia i o latou loto;", "they were glad in their hearts;"], ["ma sa latou mumusu e fetagofi i auupega o taua,", "and they refused to take up arms,"], ["ona sa latou feita tele i le faamasino sili,", "for they were so wroth with the chief judge,"], ["ma tagata saoloto foi,", "and also with the people of liberty,"], ["sa latou le fia fetagofi ai i auupega o taua e puipui lo latou atunuu.", "that they would not take up arms to defend their country."]]},
  {num:14,words:[["Ma sa oo ina ua vaai atu Moronae i lenei mea,", "And it came to pass that when Moroni saw this,"], ["ma vaai atu foi ua o mai sa Lamanā i tuaoi o le laueleele,", "and also saw that the Lamanites were coming into the borders of the land,"], ["sa matua ita tele o ia ona o le finauvale o ia tagata o e sa ia galue ma le filiga tele e faasaoina;", "he was exceedingly wroth because of the stubbornness of those people whom he had labored with so much diligence to preserve;"], ["ioe,", "yea,"], ["sa ita tele lava o ia;", "he was exceedingly wroth;"], ["sa tumu lona agaga i le ita ia te i latou.", "his soul was filled with anger against them."]]},
  {num:15,words:[["Ma sa oo ina auina atu e ia se talosaga,", "And it came to pass that he sent a petition,"], ["faatasi ma le leo o le nuu,", "with the voice of the people,"], ["i le kovana o le laueleele, e manao e tatau ona ia faitau,", "unto the governor of the land,"], ["ma tuu mai ia te ia (o Moronae) le pule e faamalosi ai tagata fouvale na,", "desiring that he should read it,"], ["e puipui lo latou atunuu pe fasioti i latou.", "and give him (Moroni) power to compel those dissenters to defend their country or to put them to death."]]},
  {num:16,words:[["O lona popole muamua lava o le faaumaina lea o finauga ma fouvalega faapea i totonu o le nuu;", "For it was his first care to put an end to such contentions and dissensions among the people;"], ["aua faauta,", "for behold,"], ["o le mea lea sa avea ma pogai o o latou faafanoga uma. Ma sa oo ina tuuina mai lena pule e tusa ma le leo o le nuu.", "this had been hitherto a cause of all their destruction. And it came to pass that it was granted according to the voice of the people."]]},
  {num:17,words:[["Ma sa oo ina faatonu e Moronae e tatau ona o atu lana autau e faasaga i ia tagata-tupu,", "And it came to pass that Moroni commanded that his army should go against those king– men,"], ["ia toso i lalo lo latou faamaualuluga ma lo latou fiatamalii ma faalaugatasia i latou ma le eleele,", "to pull down their pride and their nobility and level them with the earth,"], ["po o lo latou fetagofi i auupega o taua ma lagolago le faamoemoe o le saolotoga.", "or they should take up arms and support the cause of liberty."]]},
  {num:18,words:[["Ma sa oo ina savavali atu autau e faasaga ia te i latou;", "And it came to pass that the armies did march forth against them;"], ["ma sa latou toso i lalo lo latou faamaualuluga ma lo latou fiatamalii, sa oo ina ao latou sii ae a latou auupega o taua e faasaga mai i tagata a Moronae,", "and they did pull down their pride and their nobility,"], ["sa salaina i latou i lalo ma faalaugatasia ma le eleele.", "insomuch that as they did lift their weapons of war to fight against the men of Moroni they were hewn down and leveled to the earth."]]},
  {num:19,words:[["Ma sa oo ina fa afe i latou o ia tagata fouvale o e na salaina i lalo i le pelu;", "And it came to pass that there were four thousand of those dissenters who were hewn down by the sword;"], ["ma o i latou o o latou taitai o e sa lei fasiotia i le taua, sa ave ma lafo i le falepuipui,", "and those of their leaders who were not slain in battle were taken and cast into prison,"], ["ona sa leai se taimi mo o latou faamasinoga i le vaitaimi lea.", "for there was no time for their trials at this period."]]},
  {num:20,words:[["Ma o le vaega na totoe o ia tagata fouvale,", "And the remainder of those dissenters,"], ["nai lo le taia i lalo i le eleele i le pelu,", "rather than be smitten down to the earth by the sword,"], ["sa latou malolo mai i le tagavai o le saolotoga,", "yielded to the standard of liberty,"], ["ma faamalolosia e sisi le tagavai o le saolotoga i luga o o latou olo,", "and were compelled to hoist the title of liberty upon their towers,"], ["ma o latou aai,", "and in their cities,"], ["ma fetagofi i auupega o taua i le puipuiga o lo latou atunuu.", "and to take up arms in defense of their country."]]},
  {num:21,words:[["Ma sa faapea ona faaumaina e Moronae ia tagata-tupu,", "And thus Moroni put an end to those king– men,"], ["sa oo ina le toe i ai se isi sa taua i le igoa o tagata-tupu;", "that there were not any known by the appellation of king– men;"], ["ma sa faapea ona ia faaumaina o le finauvale ma le faamaualuluga o ia tagata o e sa fai mai ua ia i latou le toto tamalii;", "and thus he put an end to the stubbornness and the pride of those people who professed the blood of nobility;"], ["ae sa ave ifo i latou i lalo ina ia faalotomaualalaloina i latou lava e pei o o latou uso,", "but they were brought down to humble themselves like unto their brethren,"], ["ma tau ma le totoa mo lo latou saolotoga mai le pologa.", "and to fight valiantly for their freedom from bondage."]]},
  {num:22,words:[["Faauta,", "Behold,"], ["sa oo ina faapea ona lepeti i lalo e Moronae o taua ma finauga i totonu o ona lava tagata,", "it came to pass that while Moroni was thus breaking down the wars and contentions among his own people,"], ["ma pulea i latou i le filemu ma tumalamalama,", "and subjecting them to peace and civilization,"], ["ma faia tulafono e saunia ai mo taua e faasaga ia sa Lamanā,", "and making regulations to prepare for war against the Lamanites,"], ["faauta,", "behold,"], ["ua o mai sa Lamanā i le laueleele o Moronae,", "the Lamanites had come into the land of Moroni,"], ["lea sa i tuaoi i tafatafa o le matafaga.", "which was in the borders by the seashore."]]},
  {num:23,words:[["Ma sa oo ina sa le lava le malosi o sa Nifaē i le aai o Moronae;", "And it came to pass that the Nephites were not sufficiently strong in the city of Moroni;"], ["o lea na tutuli ai i latou e Amalekia,", "therefore Amalickiah did drive them,"], ["ma fasiotia le toatele. Ma sa oo ina maua e Amalekia le aai,", "slaying many. And it came to pass that Amalickiah took possession of the city,"], ["ioe,", "yea,"], ["o latou faaologa uma lava.", "possession of all their fortifications."]]},
  {num:24,words:[["Ma o i latou o e na sosola i fafo mai le aai o Moronae,", "And those who fled out of the city of Moroni came to the city of Nephihah;"], ["sa o mai i le aai o Nifaea; ma o tagata foi o le aai o Liae sa latou faapotopoto faatasi i latou lava,", "and also the people of the city of Lehi gathered themselves together,"], ["ma fai sauniuniga ma sa saunia e tali sa Lamanā i le taua.", "and made preparations and were ready to receive the Lamanites to battle."]]},
  {num:25,words:[["Peitai sa oo ina le tuu atu e Amalekia sa Lamanā e o atu e faasaga i le aai o Nifaea i le taua,", "But it came to pass that Amalickiah would not suffer the Lamanites to go against the city of Nephihah to battle,"], ["ae sa ia taofia i latou i lalo i tafatafa o le matafaga,", "but kept them down by the seashore,"], ["ma tuu tagata i aai taitasi e puleaina ma puipuia.", "leaving men in every city to maintain and defend it."]]},
  {num:26,words:[["Ma sa faapea ona alu atu o ia,", "And thus he went on,"], ["ma maua le tele o aai,", "taking possession of many cities,"], ["o le aai o Nifaea,", "the city of Nephihah,"], ["ma le aai o Liae,", "and the city of Lehi,"], ["ma le aai o Morianetona,", "and the city of Morianton,"], ["ma le aai o Ominea,", "and the city of Omner,"], ["ma le aai o Kita,", "and the city of Gid,"], ["ma le aai o Moleka,", "and the city of Mulek,"], ["ia sa i ai uma i tuaoi i sasae i tafatafa o le matafaga.", "all of which were on the east borders by the seashore."]]},
  {num:27,words:[["Ma sa faapea ona maua e sa Lamanā,", "And thus had the Lamanites obtained,"], ["i le faitogafiti o Amalekia,", "by the cunning of Amalickiah,"], ["le tele naua o aai,", "so many cities,"], ["e ala ia latou au e le masino,", "by their numberless hosts,"], ["o aai uma ia sa tuiolo malolosi e tusa ma le ala o tuiologa a Moronae;", "all of which were strongly fortified after the manner of the fortifications of Moroni;"], ["o aai uma ia na maua ai e sa Lamanā ni olo malolosi.", "all of which afforded strongholds for the Lamanites."]]},
  {num:28,words:[["Ma sa oo ina latou savavali atu i tuaoi o le laueleele o Nuumau,", "And it came to pass that they marched to the borders of the land Bountiful,"], ["ma tutuli sa Nifaē i o latou luma ma fasiotia le toatele.", "driving the Nephites before them and slaying many."]]},
  {num:29,words:[["Peitai sa oo ina faafetaiai i latou e Teanekuma,", "But it came to pass that they were met by Teancum,"], ["o le na fasiotia Morianetona ma sisio mai ona tagata i lana solaaga.", "who had slain Morianton and had headed his people in his flight."]]},
  {num:30,words:[["Ma sa oo ina ia sisio foi Amalekia,", "And it came to pass that he headed Amalickiah also,"], ["ao savavali atu o ia faatasi ma lana autau toatele ina ia mafai e ia ona ave le laueleele o Nuumau,", "as he was marching forth with his numerous army that he might take possession of the land Bountiful,"], ["ma le laueleele foi i matu.", "and also the land northward."]]},
  {num:31,words:[["Ae faauta sa ia feiloai ma le faanoanoa i le faafetaui mai o ia e Teanekuma ma ana tagata,", "But behold he met with a disappointment by being repulsed by Teancum and his men,"], ["ona o i latou o ni tagata tau lelei silisili;", "for they were great warriors;"], ["ona o tagata taitoatasi a Teanekuma sa sili atu lo latou malolosi ma lo latou atamamai i taua i lo sa Lamanā,", "for every man of Teancum did exceed the Lamanites in their strength and in their skill of war,"], ["sa oo ina latou maua ai se lelei sili atu i luga o sa Lamanā.", "insomuch that they did gain advantage over the Lamanites."]]},
  {num:32,words:[["Ma sa oo ina latou osofaia i latou,", "And it came to pass that they did harass them,"], ["sa oo ina latou fasia i latou seia oo lava ina pogisa. Ma sa oo ina faatutu e Teanekuma ma ana tagata o latou faleie i tuaoi o le laueleele o Nuumau;", "insomuch that they did slay them even until it was dark. And it came to pass that Teancum and his men did pitch their tents in the borders of the land Bountiful;"], ["ae faatutu e Amalekia ona faleie i tuaoi i le faga i tafatafa o le matafaga,", "and Amalickiah did pitch his tents in the borders on the beach by the seashore,"], ["ma sa faapea le ala sa tutulia ai i latou.", "and after this manner were they driven."]]},
  {num:33,words:[["Ma sa oo ina ua oo mai le po,", "And it came to pass that when the night had come,"], ["sa tolotolo lemu atu Teanekuma ma lana auauna ma ua o atu i fafo i le po,", "Teancum and his servant stole forth and went out by night,"], ["ma o atu i le togalauapi a Amalekia;", "and went into the camp of Amalickiah;"], ["ma faauta,", "and behold,"], ["ua manumalo le moe ia te i latou ona o lo latou vaivai tele,", "sleep had overpowered them because of their much fatigue,"], ["lea na mafua mai i galuega ma le vevela o le aso.", "which was caused by the labors and heat of the day."]]},
  {num:34,words:[["Ma sa oo ina tolotolo faalilolilo atu Teanekuma i totonu o le faleie o le tupu,", "And it came to pass that Teancum stole privily into the tent of the king,"], ["ma tutui se tao i lona fatu;", "and put a javelin to his heart;"], ["ma sa ia faaoo vave lava le oti i le tupu sa le fafagua e ia ana auauna.", "and he did cause the death of the king immediately that he did not awake his servants."]]},
  {num:35,words:[["Ma sa ia toe foi faalilolilo mai i lana lava togalauapi,", "And he returned again privily to his own camp,"], ["ma faauta,", "and behold,"], ["sa momoe ona tagata,", "his men were asleep,"], ["ma sa ia fafagu i latou ma tau atu ia te i latou mea uma na ia faia.", "and he awoke them and told them all the things that he had done."]]},
  {num:36,words:[["Ma sa ia faatonu atu e tatau ona nonofo sauniuni lana autau,", "And he caused that his armies should stand in readiness,"], ["nei ala mai sa Lamanā ma o mai i luga o i latou.", "lest the Lamanites had awakened and should come upon them."]]},
  {num:37,words:[["Ma sa faapea ona iu o le lona lua sefulu ma le lima o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae;", "And thus endeth the twenty and fifth year of the reign of the judges over the people of Nephi;"], ["ma sa faapea ona iu o aso o Amalekia.", "and thus endeth the days of Amalickiah."]]},
];
renderVerseSet(al_ch_51_Verses, 'al-ch51-verses');

var al_ch_52_Verses = [
  {num:1,words:[["Ma o lenei,", "And now,"], ["sa oo i le lona lua sefulu ma le ono o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae,", "it came to pass in the twenty and sixth year of the reign of the judges over the people of Nephi,"], ["faauta,", "behold,"], ["ina ua feala ae sa Lamanā i le taeao muamua o le masina muamua,", "when the Lamanites awoke on the first morning of the first month,"], ["faauta,", "behold,"], ["sa latou maua Amalekia ua oti i lona lava faleie;", "they found Amalickiah was dead in his  own tent;"], ["ma sa vaai foi ua saunia Teanekuma e tau ma i latou i le aso lena.", "and they also saw that Teancum was ready to give them battle on that day."]]},
  {num:2,words:[["Ma o lenei,", "And now,"], ["ina ua vaai mai sa Lamanā i lenei mea sa latou matatau;", "when the Lamanites saw this they were affrighted;"], ["ma sa latou lafoai la latou fuafuaga e savavali atu i le laueleele i matu,", "and they abandoned their design in marching into the land northward,"], ["ae solomuli faatasi ma la latou autau atoa i le aai o Moleka,", "and retreated with all their army into the city of Mulek,"], ["ma saili le puipuiga i o latou olo.", "and sought protection in their fortifications."]]},
  {num:3,words:[["Ma sa oo ina tofia le uso o Amalekia e avea ma tupu i luga o le nuu;", "And it came to pass that the brother of Amalickiah was appointed king over the people;"], ["ma o lona igoa o Amorona;", "and his name was Ammoron;"], ["o lea o le tupu o Amorona,", "thus king Ammoron,"], ["le uso o le tupu o Amalekia,", "the brother of king Amalickiah,"], ["sa tofia e nofotupu i lona tulaga.", "was appointed to reign in his stead."]]},
  {num:4,words:[["Ma sa oo ina poloai atu o ia e tatau i ona tagata ona latou taofi aai na,", "And it came to pass that he did command that his people should maintain those cities,"], ["ia na latou ave e ala i le faamasaaina o le toto;", "which they had taken by the shedding of blood;"], ["ona e leai se aai sa latou avea sa le faamasaaina ai le tele o lo latou toto.", "for they had not taken any cities save they had lost much blood."]]},
  {num:5,words:[["Ma o lenei,", "And now,"], ["sa vaai atu Teanekuma ua mauai sa Lamanā e taofi aai ia ua latou avea,", "Teancum saw that the Lamanites were determined to maintain those cities which they had taken,"], ["ma vaega na o le laueleele ia ua latou maua;", "and those parts of the land which they had obtained possession of;"], ["ma vaai atu foi le toatele o lo latou aofai,", "and also seeing the enormity of their number,"], ["o lea na manatu ai Teanekuma e le tatau ona ia taumafai e osofaia i latou i o latou olo.", "Teancum thought it was not expedient that he should attempt to attack them in their forts."]]},
  {num:6,words:[["Ae sa ia tuu ana tagata faataamilo,", "But he kept his men round about,"], ["e peiseai o loo latou faia ni sauniuniga mo taua;", "as if making preparations for war;"], ["ioe, ma o le mea moni,", "yea,"], ["sa ia sauniuni e puipuia o ia lava e faasaga ia te i latou,", "and truly he was preparing to defend himself against them,"], ["i le ati ae lea o pa faataamilo ma sauniuni nofoaga e malu i ai.", "by casting up walls round about and preparing places of resort."]]},
  {num:7,words:[["Ma sa oo ina sa faapea ona ia sauniuni mo taua seia oo ina auina mai e Moronae se vaega toatele o tagata e faamalosi ai lana autau.", "And it came to pass that he kept thus preparing for war until Moroni had sent a large number of men to strengthen his army."]]},
  {num:8,words:[["Ma sa auina atu foi e Moronae ni faatonuga ia te ia e tatau ona ia taofia pagota uma o e sa pauu mai i ona lima;", "And Moroni also sent orders unto him that he should retain all the prisoners who fell into his hands;"], ["ona talu ai ona ua ave e sa Lamanā pagota e toatele,", "for as the Lamanites had taken many prisoners,"], ["e tatau ona ia taofi o pagota uma o sa Lamanā e avea ma totogi mo i latou o e ua ave e sa Lamanā.", "that he should retain all the prisoners of the Lamanites as a ransom for those whom the Lamanites had taken."]]},
  {num:9,words:[["Ma sa ia auina atu foi ni faatonuga ia te ia e tatau ona ia tuiolo le laueleele o Nuumau,", "And he also sent orders unto him that he should fortify the land Bountiful,"], ["ma puipui mau le ala vaapiapi lea e alu atu i le laueleele i matu,", "and secure the narrow pass which led into the land northward,"], ["nei maua e sa Lamanā le vaimea lena ma latou maua ai le malosi e osofaia ai i latou i itu uma.", "lest the Lamanites should obtain that point and should have power to harass them on every side."]]},
  {num:10,words:[["Ma sa auina atu foi e Moronae ia te ia,", "And Moroni also sent unto him,"], ["e manao ia te ia e tatau ona ia faamaoni i le taofiga o le vaega lena o le laueleele,", "desiring him that he would be faithful in maintaining that quarter of the land,"], ["ma tatau ona ia saili avanoa uma e sasa ai sa Lamanā i lena itu,", "and that he would seek every opportunity to scourge the Lamanites in that quarter,"], ["e tusa ai ma le malosi ua ia te ia, atonu e mafai ona ia toe maua mai ai i se togafiti po o se isi auala,", "as much as was in his power,"], ["aai ia ua aveesea mai i o latou lima;", "that perhaps he might take again by stratagem or some other way those cities which had been taken out of their hands;"], ["ma e tatau foi ona ia tuiolo ma faamalolosi aai taamilo ai,", "and that he also would fortify and strengthen the cities round about,"], ["ia e lei pauu atu i lima o sa Lamanā.", "which had not fallen into the hands of the Lamanites."]]},
  {num:11,words:[["Ma sa ia fai atu foi ia te ia,", "And he also said unto him,"], ["ou te fia alu atu ia te oe,", "I would come unto you,"], ["ae faauta,", "but behold,"], ["ua oo mai sa Lamanā i o matou luga i tuaoi o le laueleele i tafatafa o le sami i sisifo;", "the Lamanites are upon us in the borders of the land by the west sea;"], ["ma faauta,", "and  behold,"], ["ou te alu e faasaga ia te i latou,", "I go against them,"], ["o lea ua le mafai ai ona ou alu atu ia te oe.", "therefore I cannot come unto you."]]},
  {num:12,words:[["O lenei,", "Now,"], ["sa alu ese atu le tupu (o Amorona) i fafo o le laueleele o Sara'emila,", "the king (Ammoron) had departed out of the land of Zarahemla,"], ["ma sa ia faailoa atu i le masiofo e uiga i le oti o lona uso,", "and had made known unto the queen concerning the death of his brother,"], ["ma ua ia faapotopoto faatasi se aofai toatele o tagata,", "and had gathered together a large number of men,"], ["ma ua savavali atu e faasaga ia sa Nifaē i tuaoi i tafatafa o le sami i sisifo.", "and had marched forth against the Nephites on the borders by the west sea."]]},
  {num:13,words:[["Ma sa faapea ona ia taumafai e osofaia sa Nifaē,", "And thus he was endeavoring to harass the Nephites,"], ["ma faatosina ese se vaega o a latou au i le vaega lena o le laueleele,", "and to draw away a part of their forces to that part of the land,"], ["ae ia faatonu i latou o e na ia tuua e mau i aai ia ua ia avea,", "while he had commanded those whom he had left to possess the cities which he had taken,"], ["ia latou osofaia foi sa Nifaē sa i tuaoi i tafatafa o le sami i sasae,", "that they should also harass the Nephites on the borders by the east sea,"], ["ma ia latou ave o latou laueleele e tusa ma le tele o le malosi e ia te i latou,", "and should take possession of their lands as much as it was in their power,"], ["e tusa ma le malolosi o a latou autau.", "according to the power of their armies."]]},
  {num:14,words:[["Ma sa faapea ona i ai o sa Nifaē i ia tulaga tuga i le faaiuga o le lona lua sefulu ma le ono o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae.", "And thus were the Nephites in those dangerous circumstances in the ending of the twenty and sixth year of the reign of the judges over the people of Nephi."]]},
  {num:15,words:[["Ae faauta,", "But behold,"], ["sa oo i le tausaga e lua sefulu ma le fitu o le nofoaiga a faamasino,", "it came to pass in the twenty and seventh year of the reign of the judges,"], ["na maua ai e Teanekuma,", "that Teancum,"], ["e ala i se poloaiga mai ia Moronae—o le na ia faatutu ni autau e puipuia tuaoi i saute ma sisifo o le laueleele,", "by the command of Moroni—who had established armies to protect the south and the west borders of the land,"], ["ma ua amata lana savaliga agai i le laueleele o Nuumau,", "and had begun his march towards the land Bountiful,"], ["ina ia mafai ona ia fesoasoani ia Teanekuma ma ana tagata i le toe aumaia o aai ia na aveesea mai ia te i latou—", "that he might assist Teancum with his men in retaking the cities which they had lost—"]]},
  {num:16,words:[["Sa oo ina maua ai e Teanekuma ni faatonuga ia faia se osofaiga i luga o le aai o Moleka,", "And it came to pass that Teancum had received orders to make an attack upon the city of Mulek,"], ["ma toe ave le aai pe afai e mafai.", "and retake it if it were possible."]]},
  {num:17,words:[["Ma sa oo ina faia e Teanekuma sauniuniga e fai ai se osofaiga i luga o le aai o Moleka,", "And it came to pass that Teancum made preparations to make an attack upon the city of Mulek,"], ["ma savavali atu ma lana autau e faasaga ia sa Lamanā;", "and march forth with his army against the Lamanites;"], ["peitai sa ia vaai atu e le mafai ona ia faatoilalo i latou ao i ai i latou i o latou olo;", "but he saw that it was impossible that he could overpower them while they were in their fortifications;"], ["o lea na ia lafoai ai ana fuafuaga ma toe foi mai i le aai o Nuumau,", "therefore he abandoned his designs and returned again to the city Bountiful,"], ["e faatalitali ai mo le sau o Moronae,", "to wait for the coming of Moroni,"], ["ina ia mafai ona ia maua o se faamalosiga i lana autau.", "that he might receive strength to his army."]]},
  {num:18,words:[["Ma sa oo ina ua taunuu mai Moronae ma lana autau i le laueleele o Nuumau,", "And it came to pass that Moroni did arrive with his army at the land of Bountiful,"], ["i le taufaaiuga o le lona lua sefulu ma le fitu o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae.", "in the latter end of the twenty and seventh year of the reign of the judges over the people of Nephi."]]},
  {num:19,words:[["Ma i le amataga o le lona lua sefulu ma le valu o tausaga,", "And in the commencement of the twenty and eighth year,"], ["na faia ai e Moronae ma Teanekuma ma le toatele o kapeteni sili se fono o le taua—i se mea e tatau ona latou faia e faatosina ai sa Lamanā ia o mai i fafo e faasaga mai ia te i latou i le taua;", "Moroni and Teancum and many of the chief captains held a council of war—what they should do to cause the Lamanites to come out against them to battle;"], ["po o se togafiti e mafai ai ona latou faamimita ai i latou ia o ese ai mai i o latou olomau, ina ia mafai ona latou maua o se tulaga lelei sili atu i luga o i latou,", "or that they might by some means flatter them out of their strongholds,"], ["ma toe ave ai le aai o Moleka.", "that they might gain advantage over them and take again the city of Mulek."]]},
  {num:20,words:[["Ma sa oo ina latou aauina atu ni avefeau i le autau a sa Lamanā,", "And it came to pass they sent embassies to the army of the Lamanites,"], ["ia sa puipuia le aai o Moleka,", "which protected the city of Mulek,"], ["i lo latou taitai, o lona igoa o Iakopo,", "to their leader,"], ["e manao ia te ia,", "whose name was Jacob,"], ["ia o mai i fafo ma ana autau e fetaiai ma i latou i luga o laugatasi sa i le va o aai e lua.", "desiring him that he would come out with his armies to meet them upon the plains between the two cities."], ["Peitai faauta,", "But behold,"], ["o Iakopo,", "Jacob,"], ["o le o se sa Soramā,", "who was a  Zoramite,"], ["sa le fia sau o ia i fafo ma lana autau e fetaiai ma i latou i luga o laugatasi.", "would not come out with his army to meet them upon the plains."]]},
  {num:21,words:[["Ma sa oo ina ua leai se faamoemoe o Moronae,", "And it came to pass that Moroni,"], ["e fetaiai ai ma i latou i luga o ni tulaga tutusa,", "having no hopes of meeting them upon fair grounds,"], ["o lea,", "therefore,"], ["na ia manatu ai i se fuafuaga e mafai ona ia maunu ai i fafo sa Lamanā mai i o latou olomau.", "he resolved upon a plan that he might decoy the Lamanites out of their strongholds."]]},
  {num:22,words:[["O lea na ia faatonu ai Teanekuma ia ona ave se vaega toaitiiti o tagata tau ma savavali ifo i lalo latalata i le matafaga;", "Therefore he caused that Teancum should take a small number of men and march down near the seashore;"], ["ae o Moronae ma lana autau,", "and Moroni and his army,"], ["sa savavali atu i le po i le vao,", "by night,"], ["i le itu i sisifo o le aai o Moleka;", "marched in the wilderness,"], ["ma o lea,", "on the west of the city Mulek; and thus,"], ["i le aso na sosoo ai,", "on the morrow,"], ["ina ua iloa mai e leoleo a sa Lamanā Teanekuma,", "when the guards of the Lamanites had discovered Teancum,"], ["sa latou taufetuli ma tau atu ia Iakopo,", "they ran and told it unto Jacob,"], ["lo latou taitai.", "their leader."]]},
  {num:23,words:[["Ma sa oo ina savavali atu autau a sa Lamanā e faasaga ia Teanekuma,", "And it came to pass that the armies of the Lamanites did march forth against Teancum,"], ["i le manatu o le a latou faatoilalo Teanekuma i lo latou toatele ona o le toaitiiti o lana aofai.", "supposing by their numbers to overpower Teancum because of the smallness of his numbers."], ["Ma ina ua vaai atu Teanekuma ua o mai autau a sa Lamanā e faasaga mai ia te ia, sa amata ona ia solomuli i lalo i tafatafa o le matafaga,", "And as Teancum saw the armies of the Lamanites coming out against him he began to retreat down by the seashore,"], ["i le itu i matu.", "northward."]]},
  {num:24,words:[["Ma sa oo ina ua vaai mai sa Lamanā ua amata ona sola o ia,", "And it came to pass that when the Lamanites saw that he began to flee,"], ["sa latou lototetele ma tuliloa mai i latou ma le malosi.", "they took courage and pursued them with vigor."], ["Ma ao faapea ona taitai ese e Teanekuma sa Lamanā o e na latou tuliloa mai i latou ae le maua,", "And while Teancum was thus leading away the Lamanites who were pursuing them in vain,"], ["faauta,", "behold,"], ["sa poloai atu Moronae i se vaega o lana autau o e sa faatasi ma ia, e tatau ona savavali atu i le aai,", "Moroni commanded that a part of his army who were with him should march forth into the city,"], ["ma ave.", "and take possession of it."]]},
  {num:25,words:[["Ma sa faapea ona latou faia,", "And thus they did,"], ["ma fasiotia i latou uma o e sa tuu e puipuia le aai,", "and slew all those who had been left to protect the city,"], ["ioe,", "yea,"], ["i latou uma ia o e sa le mananao e tuu mai a latou auupega o taua.", "all those who would not yield up their weapons of war."]]},
  {num:26,words:[["Ma sa faapea ona maua e Moronae le aai o Moleka i se vaega o lana autau,", "And thus Moroni had obtained possession of the city Mulek with a part of his army,"], ["ao ia savavali atu ma e na totoe e faafetaiai sa Lamanā pe a latou foi mai i le tuliloaina o Teanekuma.", "while he marched with the remainder to meet the Lamanites when they should return from the pursuit of Teancum."]]},
  {num:27,words:[["Ma sa oo ina tuliloa e sa Lamanā Teanekuma seia oo ina latou o mai latalata i le aai o Nuumau,", "And it came to pass that the Lamanites did pursue Teancum until they came near the city Bountiful,"], ["ma ona faafetaiai ai lea o i latou e Liae ma se autau toaitiiti,", "and then they were met by Lehi and a small army,"], ["lea sa tuu e puipuia le aai o Nuumau.", "which had been left to protect the city Bountiful."]]},
  {num:28,words:[["Ma o lenei faauta,", "And now behold,"], ["ina ua vaai mai kapeteni sili o sa Lamanā ua o mai Liae ma lana autau e faasaga mai ia te i latou,", "when the chief captains of the Lamanites had beheld Lehi with his army coming against them,"], ["sa latou sosola ma le fememeai tele,", "they fled in much confusion,"], ["ina nei maua mai i latou e Liae ae latou te lei oo i le aai o Moleka;", "lest perhaps they should not obtain the city Mulek before Lehi should overtake them;"], ["ona sa latou vaivai ona o la latou savaliga,", "for they were wearied because of their march,"], ["ae o tagata a Liae o loo malolosi.", "and the men of Lehi were fresh."]]},
  {num:29,words:[["O lenei sa le iloa e sa Lamanā ua i ai Moronae ma lana autau i o latou tua; ma o le mea atoa sa latou fefefe i ai,", "Now the Lamanites did not know that Moroni had been in their rear with his army;"], ["o Liae ma ona tagata.", "and all they feared was Lehi and his men."]]},
  {num:30,words:[["O lenei sa le manao Liae ia maua i latou seia ona ina latou fetaiai ma Moronae ma lana autau.", "Now Lehi was not desirous to overtake them till they should meet Moroni and his army."]]},
  {num:31,words:[["Ma sa oo ina ao lei mamao atu le solomuli a sa Lamanā ae ua siomia i latou e sa Nifaē,", "And it came to pass that before the Lamanites had retreated far they were surrounded by the Nephites,"], ["e tagata a Moronae i le tasi itu,", "by the men of Moroni on one hand,"], ["ma tagata a Liae i le isi itu,", "and the men of Lehi on the other,"], ["o tagata uma o e sa le sesela ma tumu i le malosi;", "all of whom  were fresh and full of strength;"], ["ae o sa Lamanā sa vaivai lava ona o la latou savaliga umi.", "but the Lamanites were wearied because of their long march."]]},
  {num:32,words:[["Ma sa poloaiina e Moronae ana tagata ia latou osofaia i latou seia oo ina latou tuu ese a latou auupega o taua.", "And Moroni commanded his men that they should fall upon them until they had given up their weapons of war."]]},
  {num:33,words:[["Ma o Iakopo,", "And it came to pass that Jacob,"], ["ona o ia o lo latou taitai,", "being their leader,"], ["ma ona o ia foi o se sa Soramā,", "being also a Zoramite,"], ["ma ona sa ia te ia se agaga le mafiatoilalo,", "and having an unconquerable spirit,"], ["sa ia taitai atu sa Lamanā e tau ma le ita tele e faasaga ia Moronae.", "he led the Lamanites forth to battle with exceeding fury against Moroni."]]},
  {num:34,words:[["Ona sa i ai Moronae i le auala o la latou savaliga, o lea na tumau Iakopo i le manatu e fasioti i latou ma sala atu lona ala e ala atu ia te i latou,", "Moroni being in their course of march,"], ["i le aai o Moleka.", "therefore Jacob was determined to slay them and cut his way through to the city of Mulek."], ["Ae faauta,", "But behold,"], ["sa sili atu le malolosi o Moronae ma ana tagata;", "Moroni and his men were more powerful;"], ["o lea sa latou maumaututu ai i luma o sa Lamanā.", "therefore they did not give way before the Lamanites."]]},
  {num:35,words:[["Ma sa oo ina latou tau i itu uma e lua ma le ita tele;", "And it came to pass that they fought on both hands with exceeding fury;"], ["ma sa toatele na fasiotia i itu uma e lua;", "and there were many slain on both sides;"], ["ioe,", "yea,"], ["ma sa manua Moronae ma sa fasiotia Iakopo.", "and Moroni was wounded and Jacob was killed."]]},
  {num:36,words:[["Ma sa fetaomi malosi mai Liae ma ana tagata malolosi ma le ita tele i luga o i latou mai i o latou tua,", "And Lehi pressed upon their rear with such fury with his strong men,"], ["sa oo ina tuu mai e sa Lamanā i le muliau a latou auupega o le taua;", "that the Lamanites in the rear delivered up their weapons of war;"], ["ae o e na totoe o i latou,", "and the remainder of them,"], ["ona ua fememeai tele,", "being much confused,"], ["sa le iloa le mea e o i ai pe ta.", "knew not whither to go or to strike."]]},
  {num:37,words:[["O lenei ina ua vaai Moronae i lo latou fememeai,", "Now Moroni seeing their confusion,"], ["sa ia fai atu ia te i latou:", "he said unto them:"], ["Afai tou te aumai a outou auupega o taua ma tuu mai,", "If ye will bring forth your weapons of war and deliver them up,"], ["faauta o le a matou tuu le faamasaaina o outou toto.", "behold we will forbear shedding your blood."]]},
  {num:38,words:[["Ma sa oo ina ua faalogo mai sa Lamanā i nei upu,", "And it came to pass that when the Lamanites had heard these words,"], ["o o latou kapeteni sili,", "their chief captains,"], ["ma i latou uma o e sa lei fasiotia, sa o mai i luma ma lafo i lalo a latou auupega o taua,", "all those who were not slain,"], ["i vae o Moronae,", "came forth and threw down their weapons of war at the feet of Moroni,"], ["ma poloaia foi a latou tagata e tatau ona latou faia lea lava mea e tasi.", "and also commanded their men that they should do the same."]]},
  {num:39,words:[["Ae faauta,", "But behold,"], ["sa i ai le toatele sa latou le fia faia;", "there were many that would not;"], ["ma o i latou o e sa le fia tuuina mai a latou pelu sa ave ma saisai,", "and those who would not deliver up their swords were taken and bound,"], ["ma sa aveese mai ia te i latou a latou auupega o le taua,", "and their weapons of war were taken from them,"], ["ma faamalosi i latou e savavali atu faatasi ma o latou uso i le laueleele o Nuumau.", "and they were compelled to march with their brethren forth into the land Bountiful."]]},
  {num:40,words:[["Ma o lenei o le aofai o pagota o e na ave sa sili atu i lo le aofai o e na fasiotia,", "And now the number of prisoners who were taken exceeded more than the number of those who had been slain,"], ["ioe,", "yea,"], ["sa sili atu i e na fasia i itu uma e lua.", "more than those who had been slain on both sides."]]},
];
renderVerseSet(al_ch_52_Verses, 'al-ch52-verses');

var al_ch_53_Verses = [
  {num:1,words:[["Ma sa oo ina latou tuu ni leoleo i luga o pagota sa Lamanā,", "And it came to pass that they did set guards over the prisoners of the Lamanites,"], ["ma faamalosi i latou e o atu ma tanu o latou tagata oti,", "and did compel them to go forth and bury their dead,"], ["ioe,", "yea,"], ["ma tagata oti foi o sa Nifaē o e na fasiotia;", "and also the dead of the Nephites who were slain;"], ["ma sa tuu e Moronae tagata i luga o i latou e leoleo i latou ao latou faia a latou galuega.", "and Moroni placed men over them to guard them while they should perform their labors."]]},
  {num:2,words:[["Ma sa alu atu Moronae faatasi ma Liae i le aai o Moleka,", "And Moroni went to the city of Mulek with Lehi,"], ["ma pulea le aai ma tuu atu ia Liae. O lenei faauta,", "and took command of the city and gave it unto Lehi. Now behold,"], ["o Liae lenei o se tagata lea sa faatasi ma Moronae i le vaega tele o ana taua;", "this Lehi was a man who had been with Moroni in the more part of all his battles;"], ["ma o ia o se tagata e pei lava o Moronae,", "and he was a man like unto  Moroni,"], ["ma sa laua taufai olioli i le saogalemu o le tasi;", "and they rejoiced in each other's safety;"], ["ioe,", "yea,"], ["sa taufai pele uma ia i laua le tasi,", "they were beloved by each other,"], ["ma pele foi i tagata uma o Nifae.", "and also beloved by all the people of Nephi."]]},
  {num:3,words:[["Ma sa oo ina ua uma ona tanu e sa Lamanā o latou tagata oti ma tagata oti foi o sa Nifaē,", "And it came to pass that after the Lamanites had finished burying their dead and also the dead of the Nephites,"], ["sa toe faasavavali atu i latou i le laueleele o Nuumau;", "they were marched back into the land Bountiful;"], ["ma sa faatonu i latou e Teanekuma,", "and Teancum,"], ["e ala i ni faatonuga a Moronae,", "by the orders of Moroni,"], ["ia amata ona latou galulue i le eliga o se utu faataamilo i le laueleele,", "caused that they should commence laboring in digging a ditch round about the land,"], ["po o le aai,", "or the city,"], ["o Nuumau.", "Bountiful."]]},
  {num:4,words:[["Ma sa ia faatonu e tatau ona latou fausia se pa laau tetele i luga o le itu i totonu o le utu;", "And he caused that they should build a breastwork of timbers upon the inner bank of the ditch;"], ["ma sa latou lafo ae i luga palapala mai le utu e tatao i le pa laau tetele;", "and they cast up dirt out of the ditch against the breastwork of timbers;"], ["ma sa faapea ona latou faatonu sa Lamanā e galulue seia oo ina latou siomia le aai o Nuumau faataamilo i se pa malosi o laau ma le eleele,", "and thus they did cause the Lamanites to labor until they had encircled the city of Bountiful round about with a strong wall of timbers and earth,"], ["i se maualuga tele lava.", "to an exceeding height."]]},
  {num:5,words:[["Ma sa avea lenei aai ma olo malosi tele talu mai lena taimi;", "And this city became an exceeding stronghold ever after;"], ["ma o le aai lenei sa latou leoleoina ai pagota sa Lamanā;", "and in this city they did guard the prisoners of the Lamanites;"], ["ioe,", "yea,"], ["i totonu lava o se pa sa latou faatonu i latou e fausia i o latou lava lima. O lenei sa faamalosia Moronae e faatonu ia faafaigaluega sa Lamanā,", "even within a wall which they had caused them to build with their own hands. Now Moroni was compelled to cause the Lamanites to labor,"], ["ona sa faigofie ona leoleo o i latou ao latou galulue;", "because it was easy to guard them while at their labor;"], ["ona sa ia manaomia ana autau uma pe a tatau ona ia faia se osofaiga i luga o sa Lamanā.", "and he desired all his forces when he should make an attack upon the Lamanites."]]},
  {num:6,words:[["Ma sa oo ina faapea ona maua e Moronae se manumalo i luga o se tasi o autau silisili a sa Lamanā,", "And it came to pass that Moroni had thus gained a victory over one of the greatest of the armies of the Lamanites,"], ["ma ia maua le aai o Moleka,", "and had obtained possession of the city of Mulek,"], ["o se tasi lea o olo sili ona malosi o sa Lamanā i le laueleele o Nifae;", "which was one of the strongest holds of the Lamanites in the land of Nephi;"], ["ma sa faapea foi ona ia fausia se olo malosi e taofi ai ana pagota.", "and thus he had also built a stronghold to retain his prisoners."]]},
  {num:7,words:[["Ma sa oo ina sa ia le toe taumafai e fai se taua ma sa Lamanā i le tausaga lena;", "And it came to pass that he did no more attempt a battle with the Lamanites in that year,"], ["ae sa ia faafaigaluega ana tagata i le sauniuni mo taua,", "but he did employ his men in preparing for war,"], ["ioe,", "yea,"], ["ma le faia o olo e leoleo faasaga ia sa Lamanā,", "and in making fortifications to guard against the Lamanites,"], ["ioe,", "yea,"], ["ma le laveaiina foi o o latou fafine ma a latou fanau mai le oge ma le puapuaga,", "and also delivering their women and their children from famine and affliction,"], ["ma le mauaina o meaai mo a latou autau.", "and providing food for their armies."]]},
  {num:8,words:[["Ma o lenei sa oo ina maua e autau a sa Lamanā sa i le sami i sisifo,", "And now it came to pass that the armies of the Lamanites,"], ["i saute,", "on the west sea,"], ["ao lei i ai Moronae ona o se mea faalilolilo sa i ai i totonu o sa Nifaē,", "south,"], ["lea na mafua mai ai faatuiesega i totonu o i latou,", "while in the absence of Moroni on account of some intrigue amongst the Nephites, which caused dissensions amongst them,"], ["ona manumalo ai lea o au a sa Lamanā i sa Nifaē,", "had gained some ground over the Nephites,"], ["ioe,", "yea,"], ["sa oo ina latou maua ai se aofai o o latou aai i le vaega lena o le laueleele.", "insomuch that they had obtained possession of a number of their cities in that part of the land."]]},
  {num:9,words:[["Ma sa faapea, ona o le amioletonu sa i totonu o i latou lava,", "And thus because of iniquity amongst themselves,"], ["ioe,", "yea,"], ["ona o faatuiesega ma mea faalilolilo sa i totonu o i latou lava, na tuu ai i latou i ni tulaga sili ona tuga.", "because of dissensions and intrigue among themselves they were placed in the most dangerous circumstances."]]},
  {num:10,words:[["Ma o lenei faauta,", "And now behold,"], ["ua ia te au ni mea teisi ou te fai atu ai e uiga i le nuu o Amona,", "I have somewhat to say concerning the people of Ammon,"], ["o e,", "who in the beginning,"], ["i le amataga,", "were Lamanites;"], ["o ni sa Lamanā; ae ona o Amona ma ona uso,", "but by Ammon and his brethren,"], ["pe ona o le mana ma le afioga a le Atua,", "or rather by the power and word of God,"], ["sa faaliliuina i latou i le Alii;", "they had been converted unto the Lord;"], ["ma sa aumai i latou i lalo i le laueleele o Sara'emila,", "and they had been brought down into the land of  Zarahemla,"], ["ma talu mai le taimi lena o puipuia pea e sa Nifaē.", "and had ever since been protected by the Nephites."]]},
  {num:11,words:[["Ma ona o la latou tautoga,", "And because of their oath they had been kept from taking up arms against their brethren;"], ["o lea na taofia ai i latou mai i le fetagofi i auupega o taua e faasaga i o latou uso;", "for they had taken an oath that they never would shed blood more;"], ["ona sa latou faia se tautoga o le a latou le toe faamasaaina se toto; ma semanu ua fano i latou ona o la latou tautoga;", "and according to their oath they would have perished;"], ["ioe,", "yea,"], ["po ua latou tuu atu i latou lava ia pauu atu i lima o o latou uso,", "they would have suffered themselves to have fallen into the hands of their brethren,"], ["pe a na leai le mutimutivale ma le alofa tele lea sa ia Amona ma ona uso mo i latou.", "had it not been for the pity and the exceeding love which Ammon and his brethren had had for them."]]},
  {num:12,words:[["Ma ona o lenei pogai na aumai ai i latou i lalo i le laueleele o Sara'emila;", "And for this cause they were brought down into the land of Zarahemla;"], ["ma ua faapea ona puipuia ai o i latou e sa Nifaē mai i le taimi lena.", "and they ever had been protected by the Nephites."]]},
  {num:13,words:[["Peitai sa oo ina ua latou vaai atu i le tulaga faigata,", "But it came to pass that when they saw the danger,"], ["ma le tele o puapuaga ma faigata ia na onosaia e sa Nifaē ona o i latou,", "and the many afflictions and tribulations which the Nephites bore for them,"], ["sa uunaia i latou i le agaalofa ma mananao e fetagofi i auupega o taua i le puipuiga o lo latou atunuu.", "they were moved with compassion and were desirous to take up arms in the defense of their country."]]},
  {num:14,words:[["Ae faauta,", "But behold,"], ["ina o le a latou fetagofi atu i auupega o taua,", "as they were about to take their weapons of war,"], ["sa faalofituina i latou i faatauanauga a Helamana ma ona uso,", "they were overpowered by the persuasions of Helaman and his brethren,"], ["ona ua fai o le a latou solia le tautoga lea na latou faia.", "for they were about to break the oath which they had made."]]},
  {num:15,words:[["Ma sa matau Helamana nei maumau o latou agaga i lo latou faia o lenei mea;", "And Helaman feared lest by so doing they should lose their souls;"], ["o lea o i latou uma o e na ulu atu i lenei feagaiga sa faamalosiina e vaai atu i o latou uso o asa atu i o latou puapuaga,", "therefore all those who had entered into this covenant were compelled to behold their brethren wade through their afflictions,"], ["i o latou tulaga tiga i le taimi lea.", "in their dangerous circumstances at this time."]]},
  {num:16,words:[["Ae faauta,", "But behold,"], ["sa oo ina sa i ai ia te i latou ni atalii e toatele,", "it came to pass they had many sons,"], ["o e sa lei ulu atu i se feagaiga e faapea o le a latou le fetagofi ia latou auupega o taua e puipui ai i latou lava e faasaga i o latou fili;", "who had not entered into a covenant that they would not take their weapons of war to defend themselves against their enemies;"], ["o lea na latou faapotopoto faatasi ai i latou lava i le taimi lea,", "therefore they did assemble themselves together at this time,"], ["le toatele lea o i latou o e sa mafai ona latou ave auupega o taua,", "as many as were able to take up arms,"], ["ma latou taua i latou lava o sa Nifaē.", "and they called themselves Nephites."]]},
  {num:17,words:[["Ma sa latou ulu atu i se feagaiga e tau mo le saolotoga o sa Nifaē,", "And they entered into a covenant to fight for the liberty of the Nephites,"], ["ioe,", "yea,"], ["e puipui le laueleele e oo lava i le tuuina i lalo o o latou ola;", "to protect the land unto the laying down of their lives;"], ["ioe,", "yea,"], ["sa latou osifeagaiga lava o le a latou le tuu atu lava lo latou saolotoga ,", "even they covenanted that they never would give up their liberty,"], ["ae o le a latou tau i tulaga uma e puipui ai sa Nifaē ma i latou lava mai le pologa.", "but they would fight in all cases to protect the Nephites and themselves from bondage."]]},
  {num:18,words:[["O lenei faauta,", "Now behold,"], ["e lua afe ia tama talavou sa i ai,", "there were two thousand of those young men,"], ["o e na ulu atu i lenei feagaiga ma latou ave a latou auupega o taua e puipui lo latou atunuu.", "who entered into this covenant and took their weapons of war to defend their country."]]},
  {num:19,words:[["Ma o lenei faauta,", "And now behold,"], ["ona sa lei avea lava i latou e oo mai i lea taimi ma faalavelave ia sa Nifaē,", "as they never had hitherto been a disadvantage to the Nephites,"], ["ua avea nei foi i latou i lenei taimi ma fesoasoani tele;", "they became now at this period of time also a great support;"], ["ona sa latou ave a latou auupega o taua,", "for they took their weapons of war,"], ["ma latou mananao ia avea Helamana ma o latou taitai.", "and they would that Helaman should be their leader."]]},
  {num:20,words:[["Ma o i latou uma lava o ni tama talavou,", "And they were all young men,"], ["ma sa latou matuā totoa i le lototetele ,", "and they were exceedingly valiant for courage,"], ["ma malolosi foi ma toaaga;", "and also for strength and activity;"], ["ae faauta,", "but behold,"], ["sa le ona pau lea—o i latou o ni alii o e sa faamaoni i taimi uma i soo se mea na faatuatuaina ai i latou.", "this was not all—they were men who were true at all times in whatsoever thing they were entrusted."]]},
  {num:21,words:[["Ioe,", "Yea,"], ["o i latou o ni alii o le upumoni ma le mamalu,", "they were men of truth and soberness,"], ["ona sa aoaoina i latou e tausi i poloaiga a le Atua ma savavali ma le tonu i ona luma.", "for they had been taught to keep the commandments of God and to walk uprightly before him."]]},
  {num:22,words:[["Ma o lenei sa oo ina savali Helamana i le ulu o lana lua afe o fitafita talavou,", "And now it came to pass that Helaman did march at the head of his two thousand stripling soldiers,"], ["e lagolago i tagata sa i tuaoi o le laueleele i saute i tafatafa o le sami i sisifo.", "to the support of the people in the borders of the land on the south by the west sea."]]},
  {num:23,words:[["Ma sa faapea ona iu o le lona lua sefulu ma le valu o tausaga o le nofoaiga a faamasino i luga o le nuu o Nifae.", "And thus ended the twenty and eighth year of the reign of the judges over the people of Nephi."]]},
];
renderVerseSet(al_ch_53_Verses, 'al-ch53-verses');

var al_ch_54_Verses = [
  {num:1,words:[["Ma o lenei sa oo i le amataga o le lona lua sefulu ma le iva o tausaga o faamasino,", "And now it came to pass in the commencement of the twenty and ninth year of the judges,"], ["na auina mai ai e Amorona se savali ia Moronae e manao mai ia te ia la te faafesuiai pagota.", "that Ammoron sent unto Moroni desiring that he would exchange prisoners."]]},
  {num:2,words:[["Ma sa oo ina lagona e Moronae le olioli tele i lenei talosaga,", "And it came to pass that Moroni felt to rejoice exceedingly at this request,"], ["ona sa ia manaomia meaai ia sa tuu atu mo le tausiga o pagota sa Lamanā mo le tausiga o ana lava tagata;", "for he desired the provisions which were imparted for the support of the Lamanite prisoners for the support of his own people;"], ["ma sa ia manaomia foi ana lava tagata mo le faamalosiga o lana autau.", "and he also desired his own people for the strengthening of his army."]]},
  {num:3,words:[["O lenei sa toatele fafine ma tamaiti sa ave e sa Lamanā,", "Now the Lamanites had taken many women and children,"], ["ae sa leai se fafine po o se tamaitiiti i totonu o pagota uma a Moronae,", "and there was not a woman nor a child among all the prisoners of Moroni,"], ["po o pagota o e na ave e Moronae; o lea na mafaufau ai Moronae i se togafiti e maua mai ai le tele o pagota sa Nifaē mai sa Lamanā,", "or the prisoners whom Moroni had taken;"], ["pe a mafai.", "therefore Moroni resolved upon a stratagem to obtain as many prisoners of the Nephites from the Lamanites as it were possible."]]},
  {num:4,words:[["O lea na ia tusi atu ai se tusi,", "Therefore he wrote an epistle,"], ["ma auina atu e ala atu i le auauna a Amorona,", "and sent it by the servant of Ammoron,"], ["ia lava lea na aumaia le tusi ia Moronae. O lenei o upu nei na ia tusi atu ia Amorona,", "the same who had brought an epistle to Moroni. Now these are the words which he wrote unto Ammoron,"], ["ua fai atu:", "saying:"]]},
  {num:5,words:[["Faauta,", "Behold,"], ["Amorona,", "Ammoron,"], ["ua ou tusi teisi atu ia te oe e uiga i lenei taua ua e sii mai e faasaga i lo'u nuu,", "I have written unto you somewhat concerning this war which ye have waged against my people,"], ["po o lea na sii mai e lou uso e faasaga ia te i latou,", "or rather which thy brother hath waged against them,"], ["ma lea ua e mauai ia faia pea ina ua mavae lona oti.", "and which ye are still determined to carry on after his death."]]},
  {num:6,words:[["Faauta,", "Behold,"], ["ou te fia faamatala teisi atu ia te oe e uiga i le faamasinotonu a le Atua,", "I would tell you somewhat concerning the justice of God,"], ["ma le pelu o lona toasa malosi aoao, lea ua tautau ifo i ou luga,", "and the sword of his almighty wrath,"], ["vagana ai ua e salamo ma aveese atu au autau i o outou lava laueleele,", "which doth hang over you except ye repent and withdraw your armies into your own lands,"], ["po o le laueleele ua outou maua,", "or the land of your possessions,"], ["le laueleele lea o Nifae.", "which is the land of Nephi."]]},
  {num:7,words:[["Ioe,", "Yea,"], ["ou te fia faamatala atu ia te oe nei mea pe a na fai e mafai ona e faalogo mai i ai;", "I would tell you these things if ye were capable of hearkening unto them;"], ["ioe,", "yea,"], ["ou te fia faamatala atu ia te oe e uiga i le seoli matautia lena o loo faatalitali mai e tali tagata fasioti tagata faapena e pei ona i ai oe ma lou uso,", "I would tell you concerning that awful hell that awaits to receive such murderers as thou and thy brother have been,"], ["vagana ai ua e salamo ma aveese ou faamoemoega fasioti tagata,", "except ye repent and withdraw your murderous purposes,"], ["ma fo'i atu ma au autau i o outou lava laueleele.", "and return with your armies to your own lands."]]},
  {num:8,words:[["Ae ona sa e teteeina muamua nei mea,", "But as ye have once rejected these things,"], ["ma e tau e faasaga i tagata o le Alii,", "and have fought against the people of the Lord,"], ["ua faapea lava ona ou manatu o le a e toe faia foi lenei mea.", "even so I may expect you will do it again."]]},
  {num:9,words:[["Ma o lenei faauta,", "And now behold,"], ["ua matou sauni e tali outou;", "we are prepared to receive you;"], ["ioe,", "yea,"], ["ma vagana ai ua e aveese ou faamoemoega, faauta,", "and except you withdraw your purposes,"], ["o le a e to ifo i lalo le toasa o le Atua lena o le ua e teena,", "behold,"], ["i o outou luga,", "ye will pull down the wrath of that God whom you have rejected upon you,"], ["e oo lava i le faaumatiaina atoa o outou.", "even to your utter destruction."]]},
  {num:10,words:[["Ae,", "But,"], ["e pei ona soifua le Alii,", "as the Lord liveth,"], ["o le a o atu a matou autau i o outou luga,", "our armies shall come upon you except ye withdraw,"], ["vagana ai ua outou o ese, ma o le a le pine ai ona asia o outou i le oti,", "and ye shall soon be visited with death,"], ["ona o le a matou taofi o matou aai ma o matou laueleele;", "for we will retain our cities and our lands;"], ["ioe,", "yea,"], ["ma o le a matou taofi mau la matou tapuaiga ma le savali a lo matou Atua.", "and we will maintain our religion and the cause of our God."]]},
  {num:11,words:[["Ae faauta,", "But behold,"], ["ou te manatu ua leai se aoga ou te tautala atu ai ia te oe e uiga i nei mea;", "it supposeth me that I talk to you concerning these things in vain;"], ["po o i lo'u manatu o oe o se tama a seoli;", "or it supposeth me that thou art a child of hell;"], ["o lea o le a ou faaiu ai lau tusi i le tau atu ia te oe ou te le fia faafesuiai pagota,", "therefore I will close my epistle by telling you that I will not exchange prisoners,"], ["vagana ai ua faia i luga o tulaga o lou tatala mai o se tane ma lana ava ma lana fanau,", "save it be on conditions that ye will deliver up a man and his wife and his children,"], ["mo se pagota e toatasi;", "for one prisoner;"], ["afai o le tulaga lenei e te faia ai,", "if this be the case that ye will do it,"], ["o le a ou faafesuiai.", "I will exchange."]]},
  {num:12,words:[["Ma faauta,", "And behold,"], ["afai e te le faia lenei mea,", "if you do not this,"], ["o le a ou alu atu faatasi ma au autau e faasaga ia te oe;", "I will come against you with my armies;"], ["ioe,", "yea,"], ["o le a ou faaauupegaina foi ou fafine ma ou tamaiti,", "even I will arm my women and my children,"], ["ma o le a ou alu atu e faasaga ia te oe,", "and I will come against you,"], ["ma o le a ou mulimuli atu ia te outou e oo atu lava i lo outou lava laueleele, le laueleele lava lea o lo matou uluai tofi;", "and I will follow you even into your own land,"], ["ioe,", "which is the land of our first inheritance;"], ["ma o le toto mo le toto,", "yea,"], ["ioe,", "and it shall be blood for blood,"], ["ola mo le ola;", "yea,"], ["ioe,", "life for life;"], ["ma o le a ou tau ma oe seia oo ina faaumatia ese oe mai luga o le eleele.", "and I will give you battle even until you are destroyed from off the face of the earth."]]},
  {num:13,words:[["Faauta,", "Behold,"], ["ua ou ita,", "I am in my anger,"], ["ma lou nuu foi;", "and also my people;"], ["ua outou saili e fasioti i matou,", "ye have sought to murder us,"], ["ae ua nao na matou saili e puipui i matou lava.", "and we have only sought to defend ourselves."], ["Ae faauta,", "But behold,"], ["afai tou te saili pea e faaumatia i matou,", "if ye seek to destroy us more we will seek to destroy you;"], ["o le a matou saili e faaumatia outou; ioe,", "yea,"], ["ma o le a matou saili lo matou laueleele,", "and we will seek our land,"], ["le laueleele lea o lo matou uluai tofi.", "the land of our first inheritance."]]},
  {num:14,words:[["O lenei ua ou faaiu lau tusi. O au o Moronae;", "Now I close my epistle. I am Moroni;"], ["o au o se taitai o tagata o sa Nifaē.", "I am a leader of the people of the Nephites."]]},
  {num:15,words:[["O lenei sa oo ina ua maua e Amorona lenei tusi,", "Now it came to pass that Ammoron,"], ["sa ita o ia;", "when he had received this epistle,"], ["ma sa ia tusi mai se isi tusi ia Moronae,", "was angry; and he wrote another epistle unto Moroni,"], ["ma o upu nei sa ia tusia,", "and these are the words which he wrote,"], ["fai mai:", "saying:"]]},
  {num:16,words:[["O au o Amorona,", "I am Ammoron,"], ["o le tupu o sa Lamanā;", "the king of the Lamanites;"], ["o au o le uso o Amalekia o le na outou fasiotia .", "I am the brother of Amalickiah whom ye have murdered."], ["Faauta,", "Behold,"], ["o le a ou tauia lona toto i ou luga;", "I will avenge his blood upon you,"], ["ioe, ma o le a ou alu atu i o outou luga faatasi ma au autau,", "yea,"], ["ona ou te le fefe i au faamatauga.", "and I will come upon you with my armies for I fear not your threatenings."]]},
  {num:17,words:[["Aua faauta,", "For behold,"], ["sa fai e o outou tamā le sese i o latou uso, sa oo ina latou faoa ai i latou i la latou aia i le malo,", "your fathers did wrong their brethren,"], ["ae o se aia ua a latou moni.", "insomuch that they did rob them of their right to the government when it rightly belonged unto them."]]},
  {num:18,words:[["Ma o lenei faauta,", "And now behold,"], ["afai tou te tuu i lalo a outou auupega o taua,", "if ye will lay down your arms,"], ["ma tuu mai outou lava e pulea e i latou o e e ona moni lava le malo,", "and subject yourselves to be governed by those to whom the government doth rightly belong,"], ["ona ou faatonu lea o ou tagata ia tuu i lalo a latou auupega o taua ma o le a le toe tau.", "then will I cause that my people shall lay down their weapons and shall be at war no more."]]},
  {num:19,words:[["Faauta,", "Behold,"], ["ua e manava mai faamatauga e tele e faasaga ia te au ma ou tagata;", "ye have breathed out many threatenings against me and my people;"], ["ae faauta,", "but behold,"], ["matou te le fefefe i au faamatauga.", "we fear not your threatenings."]]},
  {num:20,words:[["E ui i lea,", "Nevertheless,"], ["o le a ou tuu atu e faafesuiai pagota e tusa ma lau talosaga,", "I will grant to exchange prisoners according to your request,"], ["ma le fiafia,", "gladly,"], ["ina ia mafai ona ou faasaoina au meaai mo au tagata tau;", "that I may preserve my food for my men of war;"], ["ma o le a matou sii atu se taua o le a faavavau,", "and we will wage a war which shall be eternal,"], ["a le pulea ai sa Nifaē i la matou pule o le a tineia ai i latou e faavavau.", "either to the subjecting the Nephites to our authority or to their eternal extinction."]]},
  {num:21,words:[["Ma e faatatau i le Atua lena na e fai mai ua matou teena,", "And as concerning that God whom ye say we have rejected,"], ["faauta,", "behold,"], ["ua matou le iloa se tagata faapena;", "we know not such a being;"], ["pe o outou foi;", "neither do ye;"], ["peitai afai e i ai se tagata faapena,", "but if it so be that there is such a thing,"], ["matou te le iloa ae pe na ia faia foi i matou e pei o outou.", "we know not but that he hath made us as well as you."]]},
  {num:22,words:[["Ma afai e faapea ua i ai se tiapolo ma se seoli, faauta,", "And if it so be that there is a devil and a hell,"], ["pe na te le auina atu ea oe iina e nonofo faatasi ai ma lou uso,", "behold will he not send you there to dwell with my brother whom ye have murdered,"], ["o le na outou fasiotia, o le na e tau faaataata mai ua alu atu o ia i se nofoaga faapena? Ae faauta ua le afaina ia mea.", "whom ye have hinted that he hath gone to such a place? But behold these things matter not."]]},
  {num:23,words:[["O au o Amorona,", "I am Ammoron,"], ["ma o se tupuga mai ia Sorama ,", "and a descendant of Zoram,"], ["o le na faamalosi e o outou tamā ma aumai i fafo o Ierusalema.", "whom your fathers pressed and brought out of Jerusalem."]]},
  {num:24,words:[["Ma faauta nei,", "And behold now,"], ["o au o se sa Lamanā toa;", "I am a bold Lamanite;"], ["faauta,", "behold,"], ["ua sii le taua lenei e taui ai sese na faia ia te i latou,", "this war hath been waged to avenge their wrongs,"], ["ma taofi ma maua mai ai a latou aia i le malo;", "and to maintain and to obtain their rights to the government;"], ["ma ua ou faaiu lau tusi ia Moronae.", "and I close my epistle to Moroni."]]},
];
renderVerseSet(al_ch_54_Verses, 'al-ch54-verses');

var al_ch_55_Verses = [
  {num:1,words:[["O lenei sa oo ina ua maua e Moronae lenei tusi sa atili ita o ia,", "Now it came to pass that when Moroni had received this epistle he was more angry,"], ["ona sa ia iloa ua iloa lelei lava e Amorona lona lava pepelo ;", "because he knew that Ammoron had a perfect knowledge of his fraud;"], ["ioe,", "yea,"], ["sa ia iloa ua iloa e Amorona e le o se faamoemoe ua tonu lea na ala ai ona ia sii mai le taua e faasaga i le nuu o Nifae.", "he knew that Ammoron knew that it was not a just cause that had caused him to wage a war against the people of Nephi."]]},
  {num:2,words:[["Ma sa ia fai mai:", "And he said:"], ["Faauta,", "Behold,"], ["o le a ou le faafesuiai pagota ma Amorona vagana ai ua ia aveese lona faamoemoe,", "I will not exchange prisoners with Ammoron save he will withdraw his purpose,"], ["e pei ona ou fai atu ai i lau tusi;", "as I have stated in my epistle;"], ["ona o le a ou le tuu atu ia te ia ia toe maua e ia se malosi e sili atu nai lo lea ua ia maua.", "for I will not grant unto him that he shall have any more power than what he hath got."]]},
  {num:3,words:[["Faauta,", "Behold,"], ["ua ou iloa le nofoaga lea ua leoleo ai e sa Lamanā ou tagata o e ua latou ave faapagota;", "I know the place where the Lamanites do guard my people whom they have taken prisoners;"], ["ma talu ai ona ua le tuu mai ia te au e Amorona e tusa ai ma lau tusi,", "and as Ammoron would not grant unto me mine epistle,"], ["faauta,", "behold,"], ["o le a ou avatu ia te ia e tusa ma au upu;", "I will give unto him according to my words;"], ["ioe,", "yea,"], ["o le a ou saili e faaoo atu le oti i totonu o i latou seia latou aioi mai mo le filemu.", "I will seek death among them until they shall sue for peace."]]},
  {num:4,words:[["Ma o lenei sa oo ina ua uma ona fai atu e Moronae nei upu,", "And now it came to pass that when Moroni had said these words,"], ["sa ia faatonu atu ia faia se suesuega i totonu o ana tagata,", "he caused that a search should be made among his men,"], ["atonu e maua ai e ia se tagata na tupuga mai ia Lamana i totonu o i latou.", "that perhaps he might find a man who was a descendant of Laman among them."]]},
  {num:5,words:[["Ma sa oo ina latou maua se tasi,", "And it came to pass that they found one,"], ["o lona igoa o Lamana;", "whose name was Laman;"], ["ma o ia o se tasi o auauna a le tupu o le na fasioti e Amalekia.", "and he was one of the servants of the king who was murdered by Amalickiah."]]},
  {num:6,words:[["O lenei sa faatonu Lamana ma se vaega toaitiiti o ana tagata e Moronae, ia o atu i leoleo o e sa leoleoina tagata sa Nifaē.", "Now Moroni caused that Laman and a small number of his men should go forth unto the guards who were over the Nephites."]]},
  {num:7,words:[["O lenei sa leoleoina tagata sa Nifaē i le aai o Kita;", "Now the Nephites were guarded in the city of Gid;"], ["o lea na tofia ai Lamana e Moronae ma faatonu e tatau ona o atu se vaega toaitiiti o tagata faatasi ma ia.", "therefore Moroni appointed Laman and caused that a small number of men should go with him."]]},
  {num:8,words:[["Ma ina ua oo i le afiafi sa alu atu Lamana i leoleo o e na leoleoina tagata sa Nifaē,", "And when it was evening Laman went to the guards who were over the Nephites,"], ["ma faauta,", "and behold,"], ["sa latou vaai mai ua alu atu o ia,", "they saw him coming and they hailed him;"], ["ma sa latou valaau mai ia te ia; ae sa ia fai atu ia te i latou:", "but he saith unto them:"], ["aua tou te fefefe;", "Fear not;"], ["faauta,", "behold,"], ["o au o se sa Lamanā.", "I am a Lamanite."], ["Faauta,", "Behold,"], ["ua matou sosola mai sa Nifaē,", "we have escaped from the  Nephites,"], ["ma o loo momoe i latou;", "and they sleep;"], ["ma faauta ua matou aveina ni a latou uaina ma ua matou aumaia faatasi ma i matou.", "and behold we have taken of their wine and brought with us."]]},
  {num:9,words:[["O lenei ina ua faalogo mai sa Lamanā i nei upu,", "Now when the Lamanites heard these words they received him with joy;"], ["sa latou talia o ia ma le olioli;", "and they said unto him:"], ["ma sa latou fai mai ia te ia: Tuu mai ia ia i matou sina vaega o a tou uaina,", "Give us of your wine,"], ["sei o matou inu;", "that we may drink;"], ["ua matou fiafia ua faapea ona outou aumai o le uaina faatasi ma outou ona ua matou vaivai.", "we are glad that ye have thus taken wine with you for we are weary."]]},
  {num:10,words:[["Peitai sa fai atu Lamana ia te i latou:", "But Laman said unto them:"], ["Tatou taofi a tatou uaina sei tatou o atu i le taua e faasaga ia sa Nifaē. Ae o nei upu ua nao na latou mananao atili ai e inu i le uaina;", "Let us keep of our wine till we go against the Nephites to battle. But this saying only made them more desirous to drink of the wine;"]]},
  {num:11,words:[["Ona sa latou fai mai:", "For,"], ["Ua matou vaivai,", "said they:"], ["o lea sei tuu mai sei o matou inu sina uaina,", "We are weary, therefore let us take of the wine,"], ["ma i sina taimi ona tatou maua lea o le uaina mo a matou meaai alauni,", "and by and by we shall receive wine for our rations,"], ["ia o le a faamalosia ai i matou e o atu e faasaga ia sa Nifaē.", "which will strengthen us to go against the Nephites."]]},
  {num:12,words:[["Ma sa fai atu Lamana ia te i latou:", "And Laman said unto them:"], ["E mafai ona outou faia e tusa ai ma o outou manao.", "You may do according to your desires."]]},
  {num:13,words:[["Ma sa oo ina latou inu saoloto i le uaina;", "And it came to pass that they did take of the wine freely;"], ["ma sa lelei i la latou tofo,", "and it was pleasant to their taste,"], ["o lea sa latou inu saoloto atili ai i ai;", "therefore they took of it more freely;"], ["ma sa malosi le uaina,", "and it was strong,"], ["ona sa saunia le uaina i lona malosi atoatoa.", "having been prepared in its strength."]]},
  {num:14,words:[["Ma sa oo ina latou inu ma fiafia,", "And it came to pass they did drink and were merry,"], ["ma ua fai fai ua latou onana uma.", "and by and by they were all drunken."]]},
  {num:15,words:[["Ma o lenei ina ua vaai atu Lamana ma ana tagata ua latou onana uma,", "And now when Laman and his men saw that they were all drunken,"], ["ma ua momoe gagase,", "and were in a deep sleep,"], ["sa latou toe foi mai ia Moronae ma tau mai ia te ia mea uma na tutupu.", "they returned to Moroni and told him all the things that had happened."]]},
  {num:16,words:[["Ma o lenei sa tusa lenei mea ma le fuafuaga a Moronae. Ma sa saunia e Moronae ana tagata ma auupega o taua;", "And now this was according to the design of Moroni. And Moroni had prepared his men with weapons of war;"], ["ma sa ia alu atu i le aai o Kita,", "and he went to the city Gid,"], ["ao momoe gagase ma onana sa Lamanā,", "while the Lamanites were in a deep sleep and drunken,"], ["ma ua lafo atu auupega o taua i totonu i pagota,", "and cast in weapons of war unto the prisoners,"], ["sa oo ina faaauupegaina ai i latou uma;", "insomuch that they were all armed;"]]},
  {num:17,words:[["Ioe,", "Yea,"], ["e oo lava i o latou fafine,", "even to their women,"], ["ma i latou uma o a latou fanau,", "and all those of their children,"], ["le toatele lea sa mafai ona faaaoga se auupega o taua,", "as many as were able to use a weapon of war,"], ["ina ua faaauupegaina e Moronae ia pagota uma;", "when Moroni had armed all those prisoners;"], ["ma o na mea uma sa faia ma le le pisa lava.", "and all those things were done in a profound silence."]]},
  {num:18,words:[["Ae a na latou fafagua sa Lamanā, faauta ua latou onana,", "But had they awakened the Lamanites,"], ["ma po ua mafai e sa Nifaē ona fasioti i latou.", "behold they were drunken and the Nephites could have slain them."]]},
  {num:19,words:[["Ae faauta,", "But behold,"], ["e le o le mea lea sa manao i ai Moronae;", "this was not the desire of Moroni;"], ["sa le fiafia o ia i le fasioti tagata po o le faamasaatoto ,", "he did not delight in murder or bloodshed,"], ["ae sa fiafia o ia i le faaolaina o ona tagata mai faafanoga;", "but he delighted in the saving of his people from destruction;"], ["ma ina ia le aumaia e ia i ona lava luga le faamasinoletonu,", "and for this cause he might not bring upon him injustice,"], ["o le pogai lea na le manao ai o ia e pauu ifo i luga o sa Lamanā ma faaumatia i latou ao latou onana.", "he would not fall upon the Lamanites and destroy them in their drunkenness."]]},
  {num:20,words:[["Ae ua ia maua mea sa manao i ai;", "But he had obtained his desires;"], ["ona ua ia faaauupegaina na pagota sa Nifaē o e sa i totonu o pa o le aai,", "for he had armed those prisoners of the Nephites who were within the wall of the city,"], ["ma tuu atu ia te i latou le malosi latou te maua ai vaega na sa i totonu o pa.", "and had given them power to gain possession of those parts which were within the walls."]]},
  {num:21,words:[["Ma ona ia faatonu lea o tagata o e sa faatasi ma ia, ia solomuli mai i tua i se va mai ia te i latou,", "And then he caused the men who were with him to withdraw a pace from them,"], ["ma sio autau a sa Lamanā.", "and surround the armies of the Lamanites."]]},
  {num:22,words:[["O lenei faauta sa faia lenei mea i le po,", "Now behold this was done in the nighttime,"], ["sa oo ina ua ala mai sa Lamanā i le taeao sa latou vaai atu ua sio i latou e sa Nifaē i fafo,", "so that when the Lamanites awoke in the morning they beheld that they were surrounded by the Nephites without,"], ["ma ua limaauupega o latou pagota i totonu.", "and that their prisoners were armed within."]]},
  {num:23,words:[["Ma sa faapea ona latou vaai atu ua umia e sa Nifaē le pule i luga o i latou;", "And thus they saw that the Nephites had power over them;"], ["ma i ia tulaga sa oo ina latou iloa ai e le tatau ona latou tau ma sa Nifaē;", "and in these circumstances they found that it was not expedient that they should fight with the Nephites;"], ["o lea na faatonu atu ai o latou kapeteni sili ia aumai a latou auupega o taua,", "therefore their chief captains demanded their weapons of war,"], ["ma sa latou aumai a latou auupega ma lafo atu i vae o sa Nifaē,", "and they brought them forth and cast them at the feet of the Nephites,"], ["ma aioi mai mo le alofa mutimutivale.", "pleading for mercy."]]},
  {num:24,words:[["O lenei faauta,", "Now behold,"], ["o le manao lenei sa ia Moronae. Sa ia ave i latou faapagota o le taua,", "this was the desire of Moroni. He took them prisoners of war,"], ["ma ave le aai,", "and took possession of the city,"], ["ma faatonu atu ia tatala saoloto pagota uma,", "and caused that all the prisoners should be liberated,"], ["o e o lo sa Nifaē;", "who were Nephites;"], ["ma sa latou auai i le autau a Moronae,", "and they did join the army of Moroni,"], ["ma sa avea ma malosi tele i lana autau.", "and were a great strength to his army."]]},
  {num:25,words:[["Ma sa oo ina ia faatonu atu e tatau ona ave sa Lamanā,", "And it came to pass that he did cause the Lamanites,"], ["o e na ia ave faapagotaina,", "whom he had taken prisoners,"], ["ma amata ona latou faia se galuega o le faamalosiga o olo faataamilo i le aai o Kita.", "that they should commence a labor in strengthening the fortifications round about the city Gid."]]},
  {num:26,words:[["Ma sa oo ina ua uma ona ia faamalosia o le aai o Kita,", "And it came to pass that when he had fortified the city Gid,"], ["e tusa ma mea na ia manao i ai,", "according to his desires,"], ["sa ia faatonu atu e tatau ona ave ana pagota i le aai o Nuumau;", "he caused that his prisoners should be taken to the city Bountiful;"], ["ma sa ia leoleoina foi lena aai i se autau malosi tele.", "and he also guarded that city with an exceedingly strong force."]]},
  {num:27,words:[["Ma sa oo ina latou taofi ma le puipui pagota uma o e na latou ave,", "And it came to pass that they did,"], ["ma taofi foi laueleele ma lelei uma na latou toe ave,", "notwithstanding all the intrigues of the Lamanites, keep and protect all the prisoners whom they had taken,"], ["e ui i ala faatogafiti uma a sa Lamanā.", "and also maintain all the ground and the advantage which they had retaken."]]},
  {num:28,words:[["Ma sa oo ina amata ona toe manumalo sa Nifaē,", "And it came to pass that the Nephites began again to be victorious,"], ["ma toe maua mai a latou aia ma o latou avanoa.", "and to reclaim their rights and their privileges."]]},
  {num:29,words:[["E tele taimi sa taumafai ai sa Lamanā e sio i latou i le po,", "Many time did the Lamanites attempt to encircle them about by night,"], ["ae i nei taumafaiga sa aveesea ai faapagota le toatele mai ia i latou.", "but in these attempts they did lose many prisoners."]]},
  {num:30,words:[["Ma e tele taimi sa latou taumafai ai e avatu a latou uaina ia sa Nifaē,", "And many times did they attempt to administer of their wine to the Nephites,"], ["ina ia mafai ai ona latou faaumatia o i latou i mea oona po o le onana.", "that they might destroy them with poison or with drunkenness."]]},
  {num:31,words:[["Peitai faauta,", "But behold,"], ["sa le gese ona manatua e sa Nifaē le Alii lo latou Atua i le taimi lea o lo latou puapuaga. Sa le mafai ona maua i latou ia latou mailei;", "the Nephites were not slow to remember the Lord their God in this their time of affliction. They could not be taken in their snares;"], ["ioe,", "yea,"], ["sa latou le fia inuina a latou uaina,", "they would not partake of their wine,"], ["vagana ua latou avatu muamua i ni isi o pagota sa Lamanā.", "save they had first given to some of the Lamanite prisoners."]]},
  {num:32,words:[["Ma sa faapea ona latou faaeteete ina ia leai se mea oona e avatu i totonu o i latou;", "And they were thus cautious that no poison should be administered among them;"], ["aua afai e onā le sa Lamanā i la latou uaina e onā ai foi le sa Nifaē;", "for if their wine would poison a Lamanite it would also poison a Nephite;"], ["ma sa faapea ona latou tofo i a latou ava malolosi uma.", "and thus they did try all their liquors."]]},
  {num:33,words:[["Ma o lenei sa oo ina tatau ia Moronae ona faia ni sauniuniga e osofai ai le aai o Morianetona;", "And now it came to pass that it was expedient for Moroni to make preparations to attack the city Morianton;"], ["aua faauta,", "for behold,"], ["ua tuiolo faamalosi e sa Lamanā,", "the Lamanites had,"], ["e ala ia latou galuega,", "by their labors,"], ["le aai o Morianetona seia oo ina avea ma olo sili ona malosi.", "fortified the city Morianton until it had become an exceeding stronghold."]]},
  {num:34,words:[["Ma sa latou aumai pea lava pea autau fou i totonu o lena aai,", "And they were continually bringing new forces into that city,"], ["ma sapalai fou foi o meaai ma isi mea.", "and also new supplies of provisions."]]},
  {num:35,words:[["Ma sa faapea ona iu o le tausaga e lua sefulu ma le iva o le nofoaiga a faamasino i luga o le nuu o Nifae.", "And thus ended the twenty and ninth year of the reign of the judges over the people of Nephi."]]},
];
renderVerseSet(al_ch_55_Verses, 'al-ch55-verses');

var al_ch_56_Verses = [
  {num:1,words:[["Ma o lenei sa oo i le amataga o le tausaga e tolu sefulu o le nofoaiga a faamasino,", "And now it came to pass in the commence– ment of the thirtieth year of the reign of the judges,"], ["i le aso lona lua o le masina muamua,", "on the second day in the first month,"], ["na maua ai e Moronae se tusi mai ia Helamana,", "Moroni received an epistle from Helaman,"], ["sa faamatala mai ai mataupu o le nuu i lena vaega o le laueleele.", "stating the affairs of the people in that quarter of the land."]]},
  {num:2,words:[["Ma o upu nei na ia tusia,", "And these are the words which he wrote,"], ["fai mai:", "saying:"], ["Lou uso pele e,", "My dearly beloved brother,"], ["o Moronae,", "Moroni,"], ["i la le Alii e faapea foi i puapuaga o a tatou taua;", "as well in the Lord as in the tribulations of our warfare;"], ["faauta,", "behold,"], ["lou uso pele e,", "my beloved brother,"], ["ua ia te au ni mea teisi e faamatala atu ia te oe e uiga i la tatou taua i lenei vaega o le laueleele.", "I have somewhat to tell you concerning our warfare in this part of the land."]]},
  {num:3,words:[["Faauta,", "Behold,"], ["o le lua afe o atalii o tagata ia o e na aumai e Amona mai le laueleele o Nifae—o lenei, ua e silafia o i latou ia o suli o Lamana,", "two thousand of the sons of those men whom Ammon brought down out of the land of Nephi—now ye have known that these were descendants of Laman,"], ["o le o le atalii matua o lo tatou tamā o Liae;", "who was the eldest son of our father Lehi;"]]},
  {num:4,words:[["O lenei e le manaomia ona ou toe faamatala atu ia te oe e uiga ia latou uputuu po o lo latou le talitonu,", "Now I need not rehearse unto you concerning their traditions or their unbelief,"], ["ona ua e silafia lelei e uiga i ia mea uma—", "for thou knowest concerning all these things—"]]},
  {num:5,words:[["O lea ua lava ai ia te au ona ou faamatala atu ia te oe,", "Therefore it sufficeth me that I tell you that two thousand of these young men have taken their weapons of war,"], ["o le lua afe o ia tama talavou ua latou fetagofi ia latou auupega o taua, ma ua mananao ia avea au mo o latou taitai;", "and would that I should be their leader;"], ["ma ua matou o mai e puipui lo tatou atunuu.", "and we have come forth to defend our country."]]},
  {num:6,words:[["Ma o lenei ua e silafia foi e uiga i le feagaiga lea na faia e o latou tamā,", "And now ye also know concerning the covenant which their fathers made,"], ["o le a latou le toe fetagofi lava ia latou auupega o taua e faasaga i o latou uso e faamasaa le toto.", "that they would not take up their weapons of war against their brethren to shed blood."]]},
  {num:7,words:[["Ae i le tausaga e lua sefulu ma le ono,", "But in the twenty and sixth year,"], ["ina ua latou vaai i o tatou puapuaga ma o tatou fita mo i latou,", "when they saw our afflictions and our tribulations for them,"], ["sa toeitiiti o latou solia le feagaiga lea sa latou faia ma fetagofi ia latou auupega o taua e puipui ai i tatou.", "they were about to break the covenant which they had made and take up their weapons of war in our defense."]]},
  {num:8,words:[["Peitai sa ou le tuu i latou ia latou solia lenei feagaiga ua latou faia,", "But I would not suffer them that they should break this covenant which they had made,"], ["i le manatu o le a faamalosia i matou e le Atua,", "supposing that God would strengthen us,"], ["o le a matou le mafatia tele ai ona o le tausia o le tautoga lea na latou faia.", "insomuch that we should not suffer more because of the fulfilling the oath which they had taken."]]},
  {num:9,words:[["Ae faauta,", "But behold,"], ["o se tasi lenei o mea e mafai ona tatou maua ai le olioli tele.", "here is one thing in which we may have great joy."], ["Aua faauta,", "For behold,"], ["i le tausaga e lua sefulu ma le ono,", "in the twenty and sixth year,"], ["o au,", "I,"], ["o Helamana, sa ou savali atu e taimua nei tama talavou e lua afe,", "Helaman,"], ["i le aai o Iutaia,", "did march at the head of these two thousand young men to the city of Judea,"], ["e fesoasoani ia Anetipa,", "to assist Antipus,"], ["o le na e tofia e avea ma taitai i luga o tagata o le vaega lena o le laueleele.", "whom ye had appointed a leader over the people of that part of the land."]]},
  {num:10,words:[["Ma sa ou faaopoopo atu i ai ou atalii e lua afe,", "And I did join my two thousand sons,"], ["(ona ua latou agavavaa e taua o atalii) i le autau a Anetipa,", "(for they are worthy to be called sons) to the army of Antipus,"], ["ma o se malosi lea sa olioli tele ai Anetipa; aua faauta,", "in which strength Antipus did rejoice exceedingly;"], ["sa faaitiitia lana autau e sa Lamanā,", "for behold,"], ["ona sa fasiotia e a latou autau se aofai toatele o a tatou tagata,", "his army had been reduced by the Lamanites because their forces  had slain a vast number of our men,"], ["o se pogai tatou te faanoanoa ai.", "for which cause we have to mourn."]]},
  {num:11,words:[["E ui i lea,", "Nevertheless,"], ["e mafai ona tatou faamafanafanaina i tatou lava i le matautu lenei,", "we may console ourselves in this point,"], ["ua feoti i latou i le savali a lo latou atunuu ma a lo latou Atua,", "that they have died in the cause of their country and of their God,"], ["ioe,", "yea,"], ["ma ua latou fiafia .", "and they are happy."]]},
  {num:12,words:[["Ma ua taofia foi e sa Lamanā le toatele o pagota,", "And the Lamanites had also retained many prisoners,"], ["o i latou uma o e o kapeteni sili,", "all of whom are chief captains,"], ["ona sa latou le faaolaina ni isi sa ese mai ai. Ma ua matou manatu o loo i ai nei i latou i le taimi nei i le laueleele o Nifae;", "for none other have they spared alive. And we suppose that they are now at this time in the land of Nephi;"], ["o lea lava pe afai e lei fasiotia i latou.", "it is so if they are not slain."]]},
  {num:13,words:[["Ma lenei foi, o aai nei ua maua e sa Lamanā e ala i le faamasaaina o le toto o le toatele o o tatou tagata totoa:", "And now these are the cities of which the Lamanites have obtained possession by the shedding of the blood of so many of our valiant men:"]]},
  {num:14,words:[["O le laueleele o Maneti,", "The land of Manti,"], ["po o le aai o Maneti,", "or the city of Manti,"], ["ma le aai o Seseroma,", "and the city of Zeezrom,"], ["ma le aai o Kumenae,", "and the city of Cumeni,"], ["ma le aai o Anetipara.", "and the city of Antiparah."]]},
  {num:15,words:[["Ma o aai nei sa latou maua ina ua ou taunuu atu i le aai o Iutaia;", "And these are the cities which they possessed when I arrived at the city of Judea;"], ["ma sa ou maua atu Anetipa ma ana tagata o galulue ma lo latou malosi e tuiolo le aai.", "and I found Antipus and his men toiling with their might to fortify the city."]]},
  {num:16,words:[["Ioe,", "Yea,"], ["ma sa vaivai i latou i le tino faapea foi i le agaga,", "and they were depressed in body as well as in spirit,"], ["ona sa latou tau malolosi i le ao ma galulue i le po e taofi mau a latou aai;", "for they had fought valiantly by day and toiled by night to maintain their cities;"], ["ma sa faapea ona latou mafatia i puapuaga tetele uiga eseese.", "and thus they had suffered great afflictions of every kind."]]},
  {num:17,words:[["Ma o lenei sa latou mauai ia latou manumalo i lenei nofoaga,", "And now they were determined to conquer in this place or die;"], ["pe feoti ai; o lea atonu e oo ifo i lou finagalo le manatu fiafia,", "therefore you may well suppose that this little force which I brought with me,"], ["o lenei autau toaitiiti na ou aumai faatasi ma au,", "yea,"], ["ioe, ou atalii ia,", "those sons of mine,"], ["na oo ifo ai ia te i latou le faamoemoe malosi ma le olioli tele.", "gave them great hopes and much joy."]]},
  {num:18,words:[["Ma o lenei sa oo ina vaai mai sa Lamanā ua maua e Anetipa se faamalosiga tele i lana autau,", "And now it came to pass that when the Lamanites saw that Antipus had received a greater strength to his army,"], ["sa taofi faamalosia i latou i ni faatonuga mai ia Amorona,", "they were compelled by the orders of Ammoron to not come against the city of Judea,"], ["ia aua nei o mai e faasaga i le aai o Iutaia, pe faasaga mai ia i matou,", "or against us,"], ["e tau.", "to battle."]]},
  {num:19,words:[["Ma sa faapea ona faapitoa i matou e le Alii;", "And thus were we favored of the Lord;"], ["aua a na latou o mai i luga o i matou i lo matou vaivai lea, atonu po ua mafai ona latou faaumatia si a matou autau toaitiiti;", "for had they come upon us in this our weakness they might have perhaps destroyed our little army;"], ["peitai sa faapea ona faasaoina o i matou.", "but thus were we preserved."]]},
  {num:20,words:[["Sa poloaiina i latou e Amorona ia latou taofimau aai ia ua latou ave. Ma sa faapea ona iu o le tausaga e lua sefulu ma le ono. Ma i le amataga o le tausaga e lua sefulu ma le fitu na matou saunia ai lo matou aai ma i matou lava mo le puipuiga.", "They were commanded by Ammoron to maintain those cities which they had taken. And thus ended the twenty and sixth year. And in the commencement of the twenty and seventh year we had prepared our city and ourselves for defense."]]},
  {num:21,words:[["O lenei sa matou mananao ia o mai sa Lamanā i o matou luga;", "Now we were desirous that the Lamanites should come upon us;"], ["ona sa matou le mananao e fai se osofaiga i luga o i latou i o latou olo malolosi.", "for we were not desirous to make an attack upon them in their strongholds."]]},
  {num:22,words:[["Ma sa oo ina matou tuu ni sipai faataamilo,", "And it came to pass that we kept spies out round about,"], ["e vaavaai feoaiga a sa Lamanā,", "to watch the movements of the Lamanites,"], ["ina ia le mafai ona latou pasi ane ia te i matou i le po po o le ao e fai se osofaiga i luga o isi o tatou aai sa i le itu i matu.", "that they might not pass us by night nor by day to make an attack upon our other cities which were on the northward."]]},
  {num:23,words:[["Ona sa matou iloa, sa le lava le malosi sa i ai ia i latou sa i totonu o ia aai,", "For we knew in those cities they were not sufficiently strong to meet them;"], ["e faafetaiai ai i latou;", "therefore we  were desirous,"], ["o lea na matou mananao ai, afai latou te pasi ane ia i matou,", "if they should pass by us,"], ["o le a matou pauu ifo i luga o i latou mai i o latou tua,", "to fall upon them in their rear,"], ["ma faapea ona aveina ai i latou mai tua ma faafetaiai ai i latou i luma, i le taimi e tasi.", "and thus bring them up in the rear at the same time they were met in the front."], ["Sa matou manatu e mafai ona matou faatoilaloina i latou;", "We supposed that we could overpower them;"], ["ae faauta,", "but behold,"], ["sa matou faanoanoa i lo matou mananao lea.", "we were disappointed in this our desire."]]},
  {num:24,words:[["Sa latou fefefe e pasi ane ia i matou faatasi ma la latou autau atoa,", "They durst not pass by us with their whole army,"], ["pe sa latou totoa foi e o ane ma nao se vaega, nei le lava lo latou malosi,", "neither durst they with a part,"], ["ma latou pauu ai.", "lest they should not be sufficiently strong and they should fall."]]},
  {num:25,words:[["Pe sa latou totoa foi e savavali i lalo e faasaga i le aai o Sara'emila;", "Neither durst they march down against the city of Zarahemla;"], ["pe sa latou totoa foi e sopo le mata o le vaitafe o Saitonu,", "neither durst they cross the head of Sidon,"], ["i luga atu i le aai o Nifaea.", "over to the city of Nephihah."]]},
  {num:26,words:[["Ma sa faapea,", "And thus,"], ["faatasi ma a latou autau,", "with their forces,"], ["ona latou mauai e taofimau aai ia ua latou ave.", "they were determined to maintain those cities which they had taken."]]},
  {num:27,words:[["Ma o lenei sa oo i le masina lona lua o le tausaga nei,", "And now it came to pass in the second month of this year,"], ["na aumai ai ia te i matou ni meaai ma isi mea e tele mai tamā o ou atalii na e lua afe.", "there was brought unto us many provisions from the fathers of those my two thousand sons."]]},
  {num:28,words:[["Ma sa auina mai foi ia te i matou ni tagata e lua afe mai le laueleele o Sara'emila. Ma sa faapea ona matou saunia ai faatasi ma le sefulu afe o tagata,", "And also there were sent two thousand men unto us from the land of Zarahemla. And thus we were prepared with ten thousand men,"], ["ma meaai mo i latou,", "and provisions for them,"], ["ma mo a latou ava foi ma a latou fanau.", "and also for their wives and their children."]]},
  {num:29,words:[["Ma o sa Lamanā,", "And the Lamanites,"], ["ina ua faapea ona vaai mai i le faatoateleina o a matou autau i aso taitasi,", "thus seeing our forces increase daily,"], ["ma le taunuu mai o meaai mo lo matou tausiga, sa amata ona latou matatau,", "and provisions arrive for our support,"], ["ma amata ona latou faataalise ane,", "they began to be fearful,"], ["e taofi lo matou mauaina o meaai ma le malosi,", "and began to sally forth,"], ["pe a mafai.", "if it were possible to put an end to our receiving provisions and strength."]]},
  {num:30,words:[["O lenei ina ua matou vaai atu ua amata ona tupu ae o le popole o sa Lamanā i lenei mea, sa matou mananao e aumai se togafiti e faaaoga ia te i latou;", "Now when we saw that the Lamanites began to grow uneasy on this wise,"], ["o lea na poloai mai ai Anetipa e tatau ia te au,", "we were desirous to bring a stratagem into effect upon them;"], ["faatasi ma ou atalii laiti,", "therefore Antipus ordered that I should march forth with my little sons to a neighboring city,"], ["ona matou savavali atu i se aai tuaoi mai, e peiseai o matou avatu ni meaai i se aai tuaoi mai.", "as if we were carrying provisions to a neighboring city."]]},
  {num:31,words:[["Ma sa faatonu i matou ia matou savavali atu latalata ane i le aai o Anetipara,", "And we were to march near the city of Antiparah,"], ["e peiseai o loo matou malaga atu i le aai i tala atu,", "as if we were going to the city beyond,"], ["i tuaoi i tafatafa o le matafaga.", "in the borders by the seashore."]]},
  {num:32,words:[["Ma sa oo ina matou savavali atu,", "And it came to pass that we did march forth,"], ["e peiseai ua matou o atu faatasi ma a matou meaai,", "as if with our provisions,"], ["i lena aai.", "to go to that city."]]},
  {num:33,words:[["Ma sa oo ina savavali atu Anetipa ma se vaega o lana autau,", "And it came to pass that Antipus did march forth with a part of his army,"], ["ae tuu le vaega na totoe e tausi le aai. Peitai sa le savali atu o ia seia mavae ona ou alu atu faatasi ma lau autau laitiiti,", "leaving the remainder to maintain the city. But he did not march forth until I had gone forth with my little army,"], ["ma oo latalata atu i le aai o Anetipara.", "and came near the city Antiparah."]]},
  {num:34,words:[["Ma o lenei,", "And now,"], ["o le aai o Anetipara sa faanonofo ai le autau sili ona malosi a sa Lamanā;", "in the city Antiparah were stationed the strongest army of the Lamanites;"], ["ioe,", "yea,"], ["le autau sili ona toatele lea.", "the most numerous."]]},
  {num:35,words:[["Ma sa oo ina ua tau atu ia te i latou e a latou sipai,", "And it came to pass that when they had been informed by their spies,"], ["sa latou o mai ma la latou autau ma savavali faasaga mai ia te i matou.", "they came forth with their army and marched against us."]]},
  {num:36,words:[["Ma sa oo ina matou sosola mai i o latou luma,", "And it came to pass that we did flee before them,"], ["agai i matu. Ma sa faapea ona matou taitai ese o le autau sili ona malosi a sa Lamanā;", "northward. And thus we did lead away the most powerful army of the Lamanites;"]]},
  {num:37,words:[["Ioe,", "Yea,"], ["i se va mamao tele lava,", "even to a considerable distance,"], ["sa oo ina ua latou vaai mai i le autau a Anetipa ua tuliloa atu i latou,", "insomuch that when they saw the army of Antipus pursuing them,"], ["ma lo latou malosi,", "with their might,"], ["sa latou le liliu i le itu taumatau po o le itu tauagavale,", "they  did not turn to the right nor to the left, but pursued their march in a straight course after us;"], ["a ua tuli mai pea la latou savaliga i se ala sao e tuli mai i matou;", "and,"], ["ma sa matou manatu,", "as we suppose,"], ["o lo latou faamoemoe ia latou fasioti i matou ae lei maua mai i latou e Anetipa,", "it was their intent to slay us before Antipus should overtake them,"], ["ma o lo latou faamoemoe lea ina ia le mafai ona siomia i latou e a matou tagata.", "and this that they might not be surrounded by our people."]]},
  {num:38,words:[["Ma o lenei o Anetipa,", "And now Antipus,"], ["ina ua vaai mai i lo matou tulaga tuga,", "beholding our danger,"], ["sa faatelevave mai le savaliga a lana autau. Ae faauta,", "did speed the march of his army. But behold,"], ["sa po;", "it was night;"], ["o lea na latou le maua mai ai i matou,", "therefore they did not overtake us,"], ["pe na maua mai ai foi i latou e Anetipa;", "neither did Antipus overtake them;"], ["o lea na matou tolauapi ai mo le po.", "therefore we did camp for the night."]]},
  {num:39,words:[["Ma sa oo ina e lei tafa mai ata o le taeao,", "And it came to pass that before the dawn of the morning,"], ["ae faauta,", "behold,"], ["ua tuliloa mai i matou e sa Lamanā. O lenei sa le lava lo matou malosi e tau ai ma i latou;", "the Lamanites were pursuing us. Now we were not sufficiently strong to contend with them;"], ["ioe,", "yea,"], ["sa ou le manao e tuu ou atalii laiti ia pauu atu i o latou lima;", "I would not suffer that my little sons should fall into their hands;"], ["o lea na alu ai pea la matou savaliga,", "therefore we did continue our march,"], ["ma sa alu la matou savaliga i le vao.", "and we took our march into the wilderness."]]},
  {num:40,words:[["O lenei sa latou fefefe e liliu i le itu taumatau po o le itu tauagavale ina nei siomia i latou;", "Now they durst not turn to the right nor to the left lest they should be surrounded;"], ["pe sa ou manao foi e liliu i le itu taumatau po o le itu tauagavale ina nei o latou maua mai au,", "neither would I turn to the right nor to the left lest they should overtake me,"], ["ona sa le mafai ona matou tutu faasaga atu ia te i latou,", "and we could not stand against them,"], ["e aunoa ma le fasiotia o i matou,", "but be slain,"], ["ma latou sosola ai;", "and they would make their escape;"], ["ma sa faapea ona matou sosola ai i le aso atoa lena i le vao,", "and thus we did flee all that day into the wilderness,"], ["sa oo lava ina ua pogisa.", "even until it was dark."]]},
  {num:41,words:[["Ma sa oo ina ua toe malama le taeao,", "And it came to pass that again,"], ["sa matou vaai atu ua i o matou luga lava sa Lamanā,", "when the light of the morning came we saw the Lamanites upon us,"], ["ma sa matou sosola mai i o latou luma.", "and we did flee before them."]]},
  {num:42,words:[["Peitai sa oo ina sa lei mamao ona latou tuliloa mai o i matou ae latou tutu;", "But it came to pass that they did not pursue us far before they halted;"], ["ma o le taeao lea o le aso lona tolu o le masina lona fitu.", "and it was in the morning of the third day of the seventh month."]]},
  {num:43,words:[["Ma o lenei,", "And now,"], ["pe sa maua mai i latou e Anetipasa sa matou le iloa,", "whether they were overtaken by Antipus we knew not,"], ["ae sa ou fai atu i au tagata:", "but I said unto my men:"], ["Faauta,", "Behold,"], ["tatou le iloa ae pe ua latou tutu mo le faamoemoe ia tatou o atu e faasaga ia te i latou,", "we know not but they have halted for the purpose that we should come against them,"], ["ina ia latou maua ai i tatou i la latou mailei;", "that they might catch us in their snare;"]]},
  {num:44,words:[["O lea ou atalii e,", "Therefore what say ye,"], ["pe ni a fa outou,", "my sons,"], ["tou te fia o atu ea e faasaga ia te i latou i le taua?", "will ye go against them to battle?"]]},
  {num:45,words:[["Ma o lenei ou te fai atu ia te oe,", "And now I say unto you,"], ["lou uso pele e Moronae,", "my beloved brother Moroni,"], ["ou te lei vaaia lava se lototetele tele faapea,", "that never had I seen so great courage,"], ["leai,", "nay,"], ["e lei vaaia lava i totonu o sa Nifaē atoa.", "not amongst all the Nephites."]]},
  {num:46,words:[["Ona talu mai le taimi na ou taua ai i latou o ou atalii,", "For as I had ever called them my sons (for they were all of them very young) even so they said unto me:"], ["(ona sa laiti lava i latou uma) sa faapea lava ona latou fai mai ia te au:", "Father,"], ["Tamā e,", "behold our God is with us,"], ["faauta ua faatasi mai lo tatou Atua ma i tatou,", "and he will not suffer that we should fall;"], ["ma o le a ia le tuua ia tatou pauu; o lea ia tatou o atu;", "then let us go forth;"], ["tatou te le fasiotia o tatou uso pe afai latou te tuu pea i tatou;", "we would not slay our brethren if they would let us alone;"], ["o lea ia tatou o atu ai,", "therefore let us go,"], ["ina nei o latou faatoilaloina le autau a Anetipa.", "lest they should overpower the army of Antipus."]]},
  {num:47,words:[["O lenei latou te lei tau lava,", "Now they never had fought,"], ["peitai sa latou le fefefe i le oti;", "yet they did not fear death;"], ["ma sa sili atu ona latou mafaufau i le saolotoga o o latou tamā nai lo o o latou ola;", "and they did think more upon the liberty of their fathers than they did upon their lives;"], ["ioe,", "yea,"], ["sa aoaoina i latou e o latou tinā ,", "they had been taught by their mothers,"], ["e faapea afai latou te le masalosalo,", "that if they did not doubt,"], ["o le a laveaiina i latou e le Atua.", "God would deliver them."]]},
  {num:48,words:[["Ma sa latou faamatala mai ia te au upu a o latou tinā,", "And they rehearsed unto me the words of their mothers,"], ["fai mai:", "saying:"], ["Matou te le masalosalo lava sa mautinoa lena mea e o matou tinā.", "We do not doubt our mothers knew it."]]},
  {num:49,words:[["Ma sa oo ina ou toe liliu mai faatasi ma lau lua afe e faasaga ia sa Lamanā o e sa tuli maia i matou. Ma o lenei faauta,", "And it came to pass that I did return with my two thousand against these Lamanites who had pursued us. And now behold,"], ["sa maua mai i latou e autau a Anetipa,", "the armies of Antipus had overtaken them,"], ["ma sa amata ai se taua matautia tele.", "and a terrible battle had commenced."]]},
  {num:50,words:[["Ona o le vaivai o le autau a Anetipa,", "The army of Antipus being weary,"], ["ona o la latou savaliga umi i le va o se taimi puupuu lava,", "because of their long march in so short a space of time,"], ["sa tauau o le a pauu atu i lima o sa Lamanā;", "were about to fall into the hands of the Lamanites;"], ["ma a na ou le toe liliu mai faatasi ma lau lua afe po ua latou maua lo latou faamoemoe.", "and had I not returned with my two thousand they would have obtained their purpose."]]},
  {num:51,words:[["Ona ua pau Anetipa i le pelu,", "For Antipus had fallen by the sword,"], ["ma le toatele o ana taitai,", "and many of his leaders,"], ["ona o lo latou vaivai,", "because of their weariness,"], ["lea na pogai mai i le vave o la latou savaliga—o lea o tagata a Anetipa,", "which was occasioned by the speed of their march—therefore the men of Antipus,"], ["ina ua fememeai ona o le pauu o o latou taitai,", "being confused because of the fall of their leaders,"], ["sa amata ona solomuli i luma o sa Lamanā.", "began to give way before the Lamanites."]]},
  {num:52,words:[["Ma sa oo ina lototele sa Lamanā,", "And it came to pass that the Lamanites took courage,"], ["ma amata ona tuli o i latou;", "and began to pursue them;"], ["ma sa faapea ona tuli o i latou e sa Lamanā ma le faamalosi tele ae oo mai loa Helamana i o latou tua faatasi ma lana lua afe,", "and thus were the Lamanites pursuing them with great vigor when Helaman came upon their rear with his two thousand,"], ["ma amata ona matua fafasi ia te i latou,", "and began to slay them exceedingly,"], ["sa oo ina tutu le autau atoa a sa Lamanā ma liliu mai i luga o Helamana.", "insomuch that the whole army of the Lamanites halted and turned upon Helaman."]]},
  {num:53,words:[["O lenei ina ua vaai mai tagata a Anetipa ua toe liliu i tua sa Lamanā,", "Now when the people of Antipus saw that the Lamanites had turned them about,"], ["sa latou faapotopoto faatasi a latou tagata ma ua toe o mai i muliau o sa Lamanā.", "they gathered together their men and came again upon the rear of the Lamanites."]]},
  {num:54,words:[["Ma o lenei sa oo ina o i matou,", "And now it came to pass that we,"], ["o tagata a Nifae,", "the people of Nephi,"], ["o tagata a Anetipa,", "the people of Antipus,"], ["ma au faatasi ma lau lua afe,", "and I with my two thousand,"], ["sa matou siomiaina sa Lamanā, ma fasioti i latou;", "did surround the Lamanites,"], ["ioe,", "and did slay them;"], ["sa oo ina faamalosia i latou e tuu mai a latou auupega o taua ma i latou lava foi,", "yea,"], ["o ni pagota o le taua.", "insomuch that they were compelled to deliver up their weapons of war and also themselves as prisoners of war."]]},
  {num:55,words:[["Ma o lenei sa oo ina ua uma ona latou ifo mai i latou lava ia te i matou,", "And now it came to pass that when they had surrendered themselves up unto us,"], ["faauta,", "behold,"], ["sa ou faitauina ia tama talavou o e na tau faatasi ma au,", "I numbered those young men who had fought with me,"], ["ma lou fefe nei i ai se toatele o i latou ua fasiotia.", "fearing lest there were many of them slain."]]},
  {num:56,words:[["Ae faauta,", "But behold,"], ["i lo'u olioli tele,", "to my great joy,"], ["sa leai se tasi o i latou na pau i le eleele;", "there had not one soul of them fallen to the earth;"], ["ioe,", "yea,"], ["ma sa latou tau e peiseai ma le malosi o le Atua;", "and they had fought as if with the strength of God;"], ["ioe,", "yea,"], ["e lei iloa ni tane ua tau ma le malosi faavavega faapea;", "never were men known to have fought with such miraculous strength;"], ["ma sa latou pauu ifo i luga o sa Lamana faatasi ma le mana malosi faapea,", "and with such mighty power did they fall upon the Lamanites,"], ["sa latou faamatatauina i latou;", "that they did frighten them;"], ["ma o le pogai lea na tuu mai ai e sa Lamanā i latou lava o ni pagota o le taua.", "and for this cause did the Lamanites deliver themselves up as prisoners of war."]]},
  {num:57,words:[["Ma ona sa le i ai ia i matou se nofoaga mo a matou pagota,", "And as we had no place for our prisoners,"], ["e mafai ona matou leoleoina ai i latou e taofi ai i latou mai autau a sa Lamanā,", "that we could guard them to keep them from the armies of the Lamanites,"], ["o lea na matou auina atu ai i latou i le laueleele o Sara'emila,", "therefore we sent them to the land of Zarahemla,"], ["ma se vaega o tagata na a Anetipa o e sa lei fasiotia,", "and a part of those men who were not slain of Antipus,"], ["faatasi ma i latou;", "with them;"], ["ae o le vaega na totoe sa ou avea ma faatasi mai i latou i au sa Amonā talavou,", "and the remainder I took and joined them to my stripling Ammonites,"], ["ma toe alu i tua la matou savaliga i le aai o Iutaia.", "and took our march back to the city of Judea."]]},
];
renderVerseSet(al_ch_56_Verses, 'al-ch56-verses');

var al_ch_57_Verses = [
  {num:1,words:[["Ma o lenei, sa oo ina ou maua se tusi mai ia Amorona,", "And now it came to pass that I received an epistle from Ammoron,"], ["le tupu,", "the king,"], ["fai mai e faapea afai ou te tuu atu pagota ia o le taua o e na matou ave, o le a ia tuu mai le aai o Anetipara ia te i matou.", "stating that if I would deliver up those prisoners of war whom we had taken that he would deliver up the city of Antiparah unto us."]]},
  {num:2,words:[["Peitai sa ou auina atu se tusi i le tupu,", "But I sent an epistle unto the king,"], ["ua matou mautinoa ua lava a matou autau e ave faamalosi ai le aai o Anetipara;", "that we were sure our forces were sufficient to take the city of Antiparah by our force;"], ["ma o le tuuina atu o pagota mo lena aai ua matou manatu ia i matou lava e le o se mea poto,", "and by delivering up the prisoners for that city we should suppose ourselves unwise,"], ["ma ua nao le faafesuiai o pagota matou te tuu atu ai a matou pagota.", "and that we would only deliver up our prisoners on exchange."]]},
  {num:3,words:[["Ma sa le talia e Amorona lau tusi,", "And Ammoron refused mine epistle,"], ["ona sa musu o ia e faafesuiai pagota;", "for he would not exchange prisoners;"], ["o lea na matou amata ai ona faia o sauniuniga matou te o atu ai e faasaga i le aai o Anetipara.", "therefore we began to make preparations to go against the city of Antiparah."]]},
  {num:4,words:[["Peitai sa tuua e tagata o Anetipara le aai,", "But the people of Antiparah did leave the city,"], ["ma sa sosola atu i isi o latou aai,", "and fled to their other cities,"], ["ia sa latou mauaina,", "which they had possession of,"], ["e tuiolo i latou;", "to fortify them;"], ["ma sa faapea ona pau mai ai o le aai o Anetipara i o matou lima.", "and thus the city of Antiparah fell into our hands."]]},
  {num:5,words:[["Ma sa faapea ona iu o le tausaga e lua sefulu ma le valu o le nofoaiga a faamasino.", "And thus ended the twenty and eighth year of the reign of the judges."]]},
  {num:6,words:[["Ma sa oo i le amataga o le tausaga e lua sefulu ma le iva,", "And it came to pass that in the commencement of the twenty and ninth year,"], ["sa matou maua ai se sapalai o meaai,", "we received a supply of provisions,"], ["ma se faaopoopoga foi i la matou autau,", "and also an addition to our army,"], ["mai le laueleele o Sara'emila,", "from the land of Zarahemla,"], ["ma mai i le laueleele faataamilo, i le aofai o le ono afe alii,", "and from the land round about,"], ["e ese mai i le ono sefulu o atalii o sa Amonā,", "to the number of six thousand men,"], ["o e na o mai e faatasi ma o latou uso,", "besides sixty of the sons of the Ammonites who had come to join their brethren,"], ["o lau au laiti lea e lua afe.", "my little band of two thousand."], ["Ma o lenei faauta,", "And now behold,"], ["sa matou malolosi,", "we were strong,"], ["ioe,", "yea,"], ["ma sa matou maua foi meaai e tele na aumai ia te i matou.", "and we had also plenty of provisions brought unto us."]]},
  {num:7,words:[["Ma sa oo ina matou mananao e tauina se taua ma le autau lea sa tuu e puipuia le aai o Kumenae.", "And it came to pass that it was our desire to wage a battle with the army which was placed to protect the city Cumeni."]]},
  {num:8,words:[["Ma o lenei faauta,", "And now behold,"], ["o le a ou faaali atu ia te oe sa lei umi ae matou faataunuuina lo matou faamoemoe;", "I will show unto you that we soon accomplished our desire;"], ["ioe,", "yea,"], ["faatasi ma la matou autau malosi,", "with our strong force,"], ["pe faatasi ma se vaega o la matou autau malosi,", "or with a part of our strong force,"], ["sa matou siomia ai,", "we did surround,"], ["i le po,", "by night,"], ["le aai o Kumenae,", "the city Cumeni,"], ["i se taimi puupuu ae lei oo i le taimi sa faapea o le a latou maua ai se sapalai o meaai.", "a little before they were to receive a supply of provisions."]]},
  {num:9,words:[["Ma sa oo ina matou tolauapi faataamilo i le aai mo le tele o po;", "And it came to pass that we did camp round about the city for many nights;"], ["ae sa matou momoe i luga o a matou pelu,", "but we did sleep upon our swords,"], ["ma faatutu ni leoleo,", "and keep guards,"], ["ina ia le mafai ona o mai sa Lamanā i luga o i matou i le po ma fasioti i matou,", "that the Lamanites could not come upon us by night and slay us,"], ["o se mea sa latou taumafaia i le tele o taimi;", "which they attempted many times;"], ["peitai o le tele o taimi na latou taumafaia ai lenei mea na faamasaa ai o latou toto.", "but as many times as they attempted this their blood was spilt."]]},
  {num:10,words:[["Ina ua mavae se taimi, sa oo ina taunuu ane a latou meaai,", "At length their provisions did arrive,"], ["ma sa toeitiiti o latou ulu ane i le aai i le po.", "and they were about to enter the city by night."], ["Ae o i matou,", "And we,"], ["ua le o ni sa Lamanā,", "instead of being Lamanites,"], ["ae o ni sa Nifaē;", "were Nephites;"], ["o lea,", "therefore,"], ["na matou ave ai i latou ma a latou meaai.", "we did take them and their provisions."]]},
  {num:11,words:[["Ma e ui ina vavae ese sa Lamanā mai mea e tausi ai i latou i lenei ala,", "And notwithstanding the Lamanites being cut off from their support after this manner,"], ["sa latou mauai pea e taofi le aai;", "they were still determined to maintain the city;"], ["o lea sa tatau ai ona matou ave o ia meaai ma auina atu i Iutaia,", "therefore it became expedient that we should take those provisions and send them to Judea,"], ["ma a matou pagota i le laueleele o Sara'emila.", "and our prisoners to the land of Zarahemla."]]},
  {num:12,words:[["Ma sa oo ina sa lei tele ni aso na mavae,", "And it came to pass that not many days had passed away before the Lamanites began to lose all hopes of succor;"], ["ae amata ona aveese o faamoemoega uma o sa Lamanā mo se fesoasoani; o lea na latou tuu mai ai le aai i o matou lima;", "therefore they yielded up the city unto our hands;"], ["ma sa faapea ona matou faataunuuina o a matou fuafuaga mo le mauaina o le aai o Kumenae.", "and thus we had accomplished our designs in obtaining the city Cumeni."]]},
  {num:13,words:[["Peitai sa oo ina matua toatele naua a matou pagota,", "But it came to pass that our prisoners were so numerous that,"], ["e ui i le toatele o lo matou aofai,", "notwithstanding the enormity of our numbers,"], ["sa tatau ia i matou ona faaaoga la matou autau atoa e leoleo i latou,", "we were obliged to employ all our force to keep them,"], ["po o le fasioti o i latou.", "or to put them to death."]]},
  {num:14,words:[["Aua faauta,", "For behold,"], ["e sosola i fafo le toatele o i latou,", "they would break out in great numbers,"], ["ma tau i maa,", "and would fight with stones,"], ["ma uatogi,", "and with clubs,"], ["po o soo se mea e mafai ona latou uu i o latou lima,", "or whatsoever thing they could get into their hands,"], ["sa oo ina matou fasiotia ai le sili atu i le lua afe o i latou ina ua uma ona latou tuu mai o i latou lava o ni pagota o taua.", "insomuch that we did slay upwards of two thousand of them after they had surrendered themselves prisoners of war."]]},
  {num:15,words:[["O lea sa tatau ai ia i matou,", "Therefore it became expedient for us,"], ["ona matou faaumaina o latou ola,", "that we should put an end to their lives,"], ["pe leoleo i latou,", "or guard them,"], ["ma le pelu i le lima,", "sword in hand,"], ["i lalo i le laueleele o Sara'emila;", "down to the land of Zarahemla;"], ["ma o a matou meaai foi sa le sili atu mai mea sa lava mo o matou lava tagata,", "and also our provisions were not any more than sufficient for our own people,"], ["e ui i meaai ia na matou avea mai ia sa Lamanā.", "notwithstanding that which we had taken from the Lamanites."]]},
  {num:16,words:[["Ma o lenei,", "And now,"], ["i ia tulaga ogaoga,", "in those critical circumstances,"], ["sa avea ai ma mataupu mamafa tele le filifili o se mea e tatau ona fai e uiga i nei pagota o le taua;", "it became a very serious matter to determine concerning these prisoners of war;"], ["e ui i lea,", "nevertheless,"], ["sa tonu ia i matou e auina atu i latou i lalo i le laueleele o Sara'emila;", "we did resolve to send them down to the land of Zarahemla;"], ["o lea na matou filifilia ai se vaega o a matou tagata,", "therefore we selected a part of our men,"], ["ma tuu atu ia i latou le vaaiga o a matou pagota e o ifo i lalo i le laueleele o Sara'emila.", "and gave them charge over our prisoners to go down to the land of Zarahemla."]]},
  {num:17,words:[["Ae sa oo i le aso na sosoo ai, sa latou toe foi mai.", "But it came to pass that on the morrow they did return."], ["Ma o lenei faauta,", "And now behold,"], ["sa matou lei fesili atu ia i latou e uiga i pagota;", "we did not inquire of them concerning the prisoners;"], ["aua faauta,", "for behold,"], ["sa oo mai sa Lamanā i o matou luga,", "the Lamanites were upon us,"], ["ma sa latou foi tonu mai lava i le taimi e laveai ai i matou mai le pauu atu i o latou lima.", "and they returned in season to save us from falling into their hands."], ["Aua faauta,", "For behold,"], ["sa auina mai e Amorona mo lo latou lagolagoina se sapalai fou o meaai ma se autau toatele foi o tane.", "Ammoron had sent to their support a new supply of provisions and also a numerous army of men."]]},
  {num:18,words:[["Ma sa oo ina taunuu mai tagata ia o e na matou auina atu faatasi ma pagota i le taimi tonu lava e taofi ai i latou,", "And it came to pass that those men whom we sent with the prisoners did arrive in season to check them,"], ["ae toeitiiti lava o latou faatoilaloina i matou.", "as they were about to overpower us."]]},
  {num:19,words:[["Ae faauta,", "But behold,"], ["sa tau ma le aunoa ma se manatu i le oti si au au laiti e lua afe ono sefulu;", "my little band of two thousand and sixty fought most desperately;"], ["ioe,", "yea,"], ["sa latou tutumamau i luma o sa Lamanā,", "they were firm before the Lamanites,"], ["ma faaoo atu le oti ia te i latou uma o e na faasaga mai ia te i latou.", "and did administer death unto all those who opposed them."]]},
  {num:20,words:[["Ma ina o le a solomuli le vaega na totoe o la matou autau mai luma o sa Lamanā,", "And as the remainder of our army were about to give way before the Lamanites,"], ["faauta,", "behold,"], ["o lena lua afe ma le ono sefulu sa tutumau ma le le faavaivai.", "those two thousand and sixty were firm and undaunted."]]},
  {num:21,words:[["Ioe,", "Yea,"], ["ma sa latou usiusitai ma tausisi e fai upu uma o poloaiga ma le sao atoatoa;", "and they did obey and observe to perform every word of command with exactness;"], ["ioe,", "yea,"], ["ma sa faia ia te i latou e tusa ma lo latou faatuatua;", "and even according to their faith it was done unto them;"], ["ma sa ou manatua upu na latou fai mai ia te au sa aoaoina ai i latou e o latou tinā .", "and I did remember the words which they said unto me that their mothers had taught them."]]},
  {num:22,words:[["Ma o lenei faauta,", "And now behold,"], ["o ou atalii nei,", "it was these my sons,"], ["ma tagata ia o e na filifilia e ave pagota,", "and those men who had been selected to convey the prisoners,"], ["o i latou ia ua matou nonofo aitalafu i ai mo lenei manumalo tele;", "to whom we owe this great victory;"], ["ona o i latou ia o e na faatoilaloina sa Lamanā;", "for it was they who did beat the Lamanites;"], ["o lea na toe tutuli ai i latou i tua i le aai o Maneti.", "therefore they were driven back to the city of Manti."]]},
  {num:23,words:[["Ma sa matou taofia lo tatou aai o Kumenae,", "And we retained our city Cumeni,"], ["ma sa lei faaumatiaina uma i matou i le pelu;", "and were not all destroyed by the sword;"], ["e ui i lea,", "nevertheless,"], ["sa matou mafatia i le toatele o e na fasiotia.", "we had suffered great loss."]]},
  {num:24,words:[["Ma sa oo ina ua uma ona sosola o sa Lamanā,", "And it came to pass that after the Lamanites had fled,"], ["sa vave ona ou tuu atu o ni faatonuga ia aveese mai totonu o tagata oti au o tagata o e na manunua,", "I immediately gave orders that my men who had been wounded should be taken from among the dead,"], ["ma faatonu atu ia fusifusia o latou manua.", "and caused that their wounds should be dressed."]]},
  {num:25,words:[["Ma sa oo ina sa i ai le toalua selau,", "And it came to pass that there were two hundred,"], ["mai lau lua afe ma le onosefulu,", "out of my two thousand and sixty,"], ["o e na matapogia ona o le tele o le toto sa masaa;", "who had fainted because of the loss of blood;"], ["e ui i lea,", "nevertheless,"], ["e tusa ma le agalelei o le Atua,", "according to the goodness of God,"], ["ma lo matou ofo tele,", "and to our great astonishment,"], ["ma le olioli foi o la matou autau atoa,", "and also the joy of our whole army,"], ["sa leai se tagata e toatasi o i latou na fano;", "there was not one soul of them who did perish;"], ["ioe,", "yea,"], ["pe sa i ai foi se tagata e toatasi i totonu o i latou sa lei oo i ai ni manua e tele.", "and neither was there one soul among them who had not received many wounds."]]},
  {num:26,words:[["Ma o lenei,", "And now,"], ["o lo latou faasaoina,", "their preservation was astonishing to our whole army,"], ["o se mea sa ofoofogia tele i la matou autau atoa, ioe,", "yea,"], ["i le faasaoina o i latou ae sa i ai se afe o o tatou uso o e na fasiotia.", "that they should be spared while there was a thousand of our brethren who were slain."], ["Ma ua matou tuuina tonu lava lenei mea i le mana faavavega o le Atua,", "And we do justly ascribe it to the miraculous power of God,"], ["ona o lo latou faatuatua tele i ia mea sa aoaoina i latou ia talitonu i ai—e faapea o loo i ai se Atua faamasinotonu,", "because of their exceeding faith in that which they had been taught to believe—that there was a just God,"], ["ma o soo se tasi e le masalosalo,", "and whosoever did not doubt,"], ["o le a faasaoina i latou i lona mana faavavega.", "that they should be preserved by his marvelous power."]]},
  {num:27,words:[["O lenei o le faatuatua lenei o i latou nei o e ua ou tautala atu ai;", "Now this was the faith of these of whom I have spoken;"], ["ua latou talavou,", "they are young,"], ["ma ua mausali o latou mafaufau,", "and their minds are firm,"], ["ma ua latou tuu atu o latou faalagolago i le Atua e le aunoa.", "and they do put their trust in God continually."]]},
  {num:28,words:[["Ma o lenei sa oo ina ua uma ona faapea ona matou tausi o a matou tagata na manunua,", "And now it came to pass that after we had thus taken care of our wounded men,"], ["ma tanu o matou tagata oti ma tagata oti foi o sa Lamanā,", "and had buried our dead and also the dead of the Lamanites,"], ["o e sa toatele lava,", "who were many,"], ["faauta,", "behold,"], ["sa matou fesili atu ia Kita e uiga i pagota o e na amata ona latou o ifo faatasi i lalo i le laueleele o Sara'emila.", "we did inquire of Gid concerning the prisoners whom they had started to go down to the land of Zarahemla with."]]},
  {num:29,words:[["O lenei o Kita o le kapeteni sili lea i luga o le vaega na tofia e leoleo i latou e o atu i le laueleele o Sara'emila.", "Now Gid was the chief captain over the band who was appointed to guard them down to the land."]]},
  {num:30,words:[["Ma o lenei,", "And now,"], ["o upu nei na fai mai ai Kita ia te au:", "these are the words which Gid said unto me:"], ["Faauta,", "Behold,"], ["sa amata ona matou o atu i lalo i le laueleele o Sara'emila faatasi ma a tatou pagota. Ma sa oo ina matou fetaiai ma sipai o a tatou autau,", "we did start to go down to the land of Zarahemla with our prisoners. And it came to pass that we did meet the spies of our armies,"], ["o e na auina atu i fafo e vaavaai le togalauapi a sa Lamanā.", "who had been sent out to watch the camp of the Lamanites."]]},
  {num:31,words:[["Ma sa latou fono mai ia te i matou,", "And they cried unto us,"], ["fai mai:", "saying—Behold,"], ["Faauta,", "the armies of the Lamanites are marching towards the city of Cumeni;"], ["o loo savavali atu nei le autau a sa Lamanā agai atu i le aai o Kumenae; ma faauta,", "and behold,"], ["o le a latou pauu ifo i luga o i latou,", "they will fall upon them,"], ["ioe,", "yea,"], ["ma o le a latou faaumatiaina o tatou tagata.", "and will destroy our people."]]},
  {num:32,words:[["Ma sa oo ina lagona atu e a matou pagota la latou fono mai,", "And it came to pass that our prisoners did hear their cries,"], ["lea na latou lototetele ai;", "which caused them to take courage;"], ["ma latou tutulai ai e fouvale faasaga mai ia te i matou.", "and they did rise up in rebellion against us."]]},
  {num:33,words:[["Ma ona o lo latou fouvale, o lea na matou faia ai ia faaoo atu a matou pelu i luga o i latou.", "And it came to pass because of their rebellion we did cause that our swords should come upon them."], ["Ma sa oo ina latou taufetuli mai o se vaega e tasi i luga o a matou pelu,", "And it came to pass that they did in a body run upon our swords,"], ["o se mea na fasiotia ai le toatele o i latou;", "in the which,"], ["ma o e na totoe o i latou,", "the greater number of them were slain;"], ["na matalatala mai ma sosola ese atu mai ia i matou.", "and the remainder of them broke through and fled from us."]]},
  {num:34,words:[["Ma faauta,", "And behold,"], ["ina ua latou sosola,", "when they had fled and we could not overtake them,"], ["ma le mafai ona matou maua o i latou, o lea na faanatinati ai ona sau o la matou savaliga agai mai i le aai o Kumenae;", "we took our march with speed towards the city Cumeni;"], ["ma faauta,", "and behold,"], ["na matou taunuu tonu mai lava i le taimi na mafai ai ona matou fesoasoani i o tatou uso i le faasaoina o le aai.", "we did arrive in time that we might assist our brethren in preserving the city."]]},
  {num:35,words:[["Ma faauta,", "And behold,"], ["ua toe laveaiina foi i tatou i fafo mai lima o o tatou fili. Ma ia faamanūina lava le suafa o lo tatou Atua;", "we are again delivered out of the hands of our enemies. And blessed is the name of our God;"], ["aua faauta,", "for behold,"], ["o ia lava na laveaiina i tatou;", "it is he that has delivered us;"], ["ioe,", "yea,"], ["o ia lava na ia faia lenei mea tele mo i tatou.", "that has done this great thing for us."]]},
  {num:36,words:[["O lenei sa oo ina ua uma ona faalogo atu o au,", "Now it came to pass that when I,"], ["o Helamana,", "Helaman,"], ["i nei upu a Kita,", "had heard these words of Gid,"], ["sa faatumuina au i le olioli tele ona o le agalelei o le Atua i le faasaoina o i matou,", "I was filled with exceeding joy because of the goodness of God in preserving us,"], ["ina ia le fano uma i matou;", "that we might not all perish;"], ["ioe,", "yea,"], ["ma ou te faalagolago o agaga o i latou o e ua fasiotia ua ulu atu i le malologa o lo latou Atua.", "and I trust that the souls of them who have been slain have entered into the rest of their God."]]},
];
renderVerseSet(al_ch_57_Verses, 'al-ch57-verses');

var al_ch_58_Verses = [
  {num:1,words:[["Ma faauta,", "And behold,"], ["o lenei sa oo ina o lo matou faamoemoe na sosoo ai o le mauaina lea o le aai o Maneti;", "now it came to pass that our next object was to obtain the city of Manti;"], ["ae faauta,", "but behold,"], ["sa leai se ala sa mafai ai ona matou taitai ese o i latou i fafo mai le aai ia matou autau toaitiiti. Aua faauta,", "there was no way that we could lead them out of the city by our small bands. For behold,"], ["sa latou manatua mea ia na matou faia e oo mai i le taimi nei;", "they remembered that which we had hitherto done;"], ["o lea na le mafai ai ona matou maunu ese o i latou mai o latou olo malolosi.", "therefore we could not decoy them away from their strongholds."]]},
  {num:2,words:[["Ma sa silisili atu lo latou toatele nai la matou autau, sa matou le fia o atu ai ma osofai i latou i o latou olo malolosi.", "And they were so much more numerous than was our army that we durst not go forth and attack them in their strongholds."]]},
  {num:3,words:[["Ioe,", "Yea,"], ["ma sa oo ina tatau ia te i matou ona faaaoga a matou tagata e taofi ai vaega na o le laueleele ia na matou toe maua mai;", "and it became expedient that we should employ our men to the maintaining those parts of the land which we had regained of our possessions;"], ["o lea sa oo ai ina tatau ia te i matou ona faatalitali,", "therefore it became expedient that we should wait,"], ["ina ia mafai ona matou maua o se malosi atili mai i le laueleele o Sara'emila ma se sapalai fou o meaai.", "that we might receive more strength from the land of Zarahemla and also a new supply of provisions."]]},
  {num:4,words:[["Ma sa oo ina faapea ona ou auina atu o se avefeau i le kovana o lo tatou laueleele,", "And it came to pass that I thus did send an embassy to the governor of our land,"], ["e faailoa atu ia te ia e uiga i mea ua tutupu i o tatou tagata. Ma sa oo ina matou faatalitali ia maua mai ni meaai ma se malosi mai le laueleele o Sara'emila.", "to acquaint him concerning the affairs of our people. And it came to pass that we did wait to receive provisions and strength from the land of Zarahemla."]]},
  {num:5,words:[["Ae faauta,", "But behold,"], ["sa laitiiti se aoga na matou maua mai i lenei mea;", "this did profit us but little;"], ["ona sa maua foi e sa Lamanā se malosi tele mai lea aso i lea aso,", "for the Lamanites were also receiving great strength from day to day,"], ["ma le tele foi o meaai;", "and also many provisions;"], ["ma sa faapea o matou tulaga i lea vaitaimi.", "and thus were our circumstances at this period of time."]]},
  {num:6,words:[["Ma sa o mai sa Lamanā e faasaga mai ia te i matou i lea taimi i lea taimi,", "And the Lamanites were sallying forth against us from time to time,"], ["ua tautino e faaumatia i matou i togafiti;", "resolving by stratagem to destroy us;"], ["e ui i lea sa le mafai ona matou o atu e tau ma i latou,", "nevertheless we could not come to battle with them,"], ["ona o o latou malutaga ma o latou olo malolosi.", "because of their retreats and their strongholds."]]},
  {num:7,words:[["Ma sa oo ina matou faatalitali i nei tulaga faigata mo le va o masina e tele,", "And it came to pass that we did wait in these difficult circumstances for the space of many months,"], ["seia oo lava ina tauau a matou fano i le leai o se meaai.", "even until we were about to perish for the want of food."]]},
  {num:8,words:[["Peitai sa oo ina matou maua ni meaai,", "But it came to pass that we did receive food,"], ["ia sa momoli puipui mai ia i matou e se autau o tane e lua afe,", "which was guarded to us by an army of two thousand men to our assistance;"], ["e fesoasoani ia te i matou; ma ona pau lea o le fesoasoani na matou maua mai,", "and this is all the assistance which we did receive,"], ["e puipui ai i matou lava ma lo tatou atunuu mai le pauu atu i lima o o tatou fili,", "to defend ourselves and our country from falling into the hands of our enemies,"], ["ioe,", "yea,"], ["e tau ai ma se fili sa le mafaitaulia le toatele.", "to contend with an enemy which was innumerable."]]},
  {num:9,words:[["Ma o lenei o le pogai o o matou maasiasi nei,", "And now the cause of these our embarrass– ments,"], ["po o le pogai na latou le auina mai ai se malosi atili ia te i matou,", "or the cause why they did not send more strength unto us,"], ["ua matou le iloa;", "we knew not;"], ["o lea na matou faanoanoa ai ma faatumulia foi i le fefefe,", "therefore we were grieved and also filled with fear,"], ["ina nei i ai se ala e oo mai ai faamasinoga a le Atua i luga o lo tatou laueleele,", "lest by any means the judgments of God should come upon our land,"], ["e faatoilalo ma faaumatia atoa ai i tatou.", "to our overthrow and utter destruction."]]},
  {num:10,words:[["O lea na sasaa atu ai o matou agaga i le Atua i le tatalo,", "Therefore we did pour out our souls in prayer to God,"], ["ina ia faamalosia e ia i matou ma laveai i matou i fafo mai lima o o tatou fili,", "that he would strengthen us and deliver us out of the hands of our enemies,"], ["ioe,", "yea,"], ["ma tuu mai foi ia i matou le malosi e mafai ai ona matou taofi o tatou aai,", "and also give us strength that we might retain our cities,"], ["ma o tatou laueleele,", "and our lands,"], ["ma a tatou meatotino,", "and our possessions,"], ["mo le tausiga o o tatou tagata.", "for the support of our people."]]},
  {num:11,words:[["Ioe,", "Yea,"], ["ma sa oo ina asiasi mai le Alii lo tatou Atua ia i matou ma ni tautinoga o le a ia laveaiina i matou;", "and it came to pass that the Lord our God did visit us with assurances that he would deliver us;"], ["ioe,", "yea,"], ["sa oo ina ia fetalai mai le filemu i o matou agaga,", "insomuch that he did speak peace to our souls,"], ["ma tuu mai ia te i matou le faatuatua tele,", "and did grant unto us great faith,"], ["ma faatonu i matou ia matou faamoemoe mo le laveaiga mai ia te ia.", "and did cause us that we should hope for our deliverance in him."]]},
  {num:12,words:[["Ma sa matou maua le lototetele i la matou autau toaitiiti lea na matou maua mai,", "And we did take courage with our small force which we had received,"], ["ma sa matou tautino ma le mauai e faatoilalo o tatou fili,", "and were fixed with a determination to conquer our enemies,"], ["ma taofi mau o tatou laueleele,", "and to maintain our lands,"], ["ma a tatou meatotino,", "and our possessions,"], ["ma a tatou ava,", "and our wives,"], ["ma a tatou fanau,", "and our children,"], ["ma le faamoemoe o lo tatou saolotoga .", "and the cause of our liberty."]]},
  {num:13,words:[["Ma sa faapea ona matou o atu faatasi ma lo matou malosi atoa e faasaga ia sa Lamanā,", "And thus we did go forth with all our might against the Lamanites,"], ["o e sa i le aai o Maneti;", "who were in the city of Manti;"], ["ma sa matou faatutu o matou faleie i tafatafa o le vao,", "and we did pitch our tents by the wilderness side,"], ["lea sa latalata atu i le aai.", "which was near to the city."]]},
  {num:14,words:[["Ma sa oo i le aso na sosoo ai,", "And it came to pass that on the morrow,"], ["ina ua vaai mai sa Lamanā ua matou i ai i tuaoi i tafatafa o le vao lea sa latalata atu i le aai,", "that when the Lamanites saw that we were in the borders by the wilderness which was near the city,"], ["sa latou aauina mai i fafo a latou sipai faataamilo ia te i matou ina ia mafai ona latou iloa le aofai ma le malosi o la matou autau.", "that they sent out their spies round about us that they might discover the number and the strength of our army."]]},
  {num:15,words:[["Ma sa oo ina latou vaai mai ua matou le malolosi,", "And it came to pass that when they saw that we were not strong,"], ["e tusa ma lo matou aofai,", "according to our numbers,"], ["ma i le fefefe nei matou vavae ese i latou mai ia latou mea e fesoasoani ia i latou vagana ai ua latou o mai e tau faasaga mai ia te i matou ma fasioti i matou,", "and fearing that we should cut them off from their support except they should come out to battle against us and kill us,"], ["ma i le manatu foi e faigofie ona latou faaumatia i matou i le toatele o a latou autau,", "and also supposing that they could easily destroy us with their numerous hosts,"], ["o lea na amata ai ona latou faia o sauniuniga e o mai i fafo e faasaga mai ia i matou i le taua.", "therefore they began to make preparations to come out against us to battle."]]},
  {num:16,words:[["Ma ina ua matou vaai atu ua latou faia sauniuniga e o mai i fafo e faasaga mai ia te i matou,", "And when we saw that they were making preparations to come out against us,"], ["faauta,", "behold,"], ["sa ou faatonu atu ia Kita, faatasi ma se aofai toaitiiti o tagata,", "I caused that Gid,"], ["e alu o ia e lafi i le vao,", "with a small number of men,"], ["ma e tatau foi ia Teominea ma se aofai toaitiiti o tagata,", "should secrete himself in the wilderness,"], ["ona lalafi foi i latou i le vao.", "and also that Teomner and a small number of men  should secrete themselves also in the wilderness."]]},
  {num:17,words:[["O lenei o Kita ma ana tagata sa i le itu taumatau,", "Now Gid and his men were on the right and the others on the left;"], ["ae o isi sa i le itu tauagavale; ma ina ua faapea ona uma ona latou lalafi,", "and when they had thus secreted themselves,"], ["faauta,", "behold,"], ["sa ou nofo pea,", "I remained,"], ["faatasi ma e na totoe o lau autau, i le mea lava sa matou muai faatutu ai o matou faleie,", "with the remainder of my army,"], ["e faatalitali ai le taimi e o mai ai sa Lamanā i fafo e tau.", "in that same place where we had first pitched our tents against the time that the Lamanites should come out to battle."]]},
  {num:18,words:[["Ma sa oo ina o mai i fafo sa Lamanā ma la latou autau toatele e faasaga mai ia te i matou.", "And it came to pass that the Lamanites did come out with their numerous army against us."], ["Ma ina ua latou o mai ma toeitiiti pauu ifo ma le pelu i o matou luga,", "And when they had come and were about to fall upon us with the sword,"], ["sa ou faatonu atu,", "I caused that my men,"], ["e tatau i au tagata, i latou ia o e na faatasi ma au,", "those who were with me,"], ["ona solomuli atu i le vao.", "should retreat into the wilderness."]]},
  {num:19,words:[["Ma sa oo ina tuliloa mai i matou e sa Lamanā ma le televavave tele,", "And it came to pass that the Lamanites did follow after us with great speed,"], ["ona sa latou naunau lava ia latou maua mai i matou,", "for they were exceedingly desirous to overtake us that they might slay us;"], ["ina ia mafai ona latou fasioti i matou; o lea na latou mulimuli mai ai ia i matou i le vao;", "therefore they did follow us into the wilderness;"], ["ma sa matou ui atu i le va o Kita ma Teominea,", "and we did pass by in the midst of Gid and Teomner,"], ["i se ala sa le iloa ai i latou e sa Lamanā.", "insomuch that they were not discovered by the Lamanites."]]},
  {num:20,words:[["Ma sa oo ina ua tea atu sa Lamanā,", "And it came to pass that when the Lamanites had passed by,"], ["pe ina ua tea atu le autau,", "or when the army had passed by,"], ["sa tutulai mai Kita ma Teominea mai o laua lafitaga, ma ua sisio ese sipai a sa Lamanā,", "Gid and Teomner did rise up from their secret places,"], ["ina ia latou le toe foi atu i le aai.", "and did cut off the spies of the Lamanites that they should not return to the city."]]},
  {num:21,words:[["Ma sa oo ina ua uma ona latou sisio ese o i latou,", "And it came to pass that when they had cut them off,"], ["sa latou tamomoe atu i le aai ma pauu atu i luga o leoleo o e na tuu e leoleoina le aai,", "they ran to the city and fell upon the guards who were left to guard the city,"], ["sa oo ina latou faaumatia i latou ma latou ave le aai.", "insomuch that they did destroy them and did take possession of the city."]]},
  {num:22,words:[["O lenei sa faia lenei mea,", "Now this was done because the Lamanites did suffer their whole army,"], ["ona sa tuu e sa Lamanā la latou autau atoa, vagana ai nao ni leoleo toaitiiti,", "save a few guards only,"], ["ia taitai ese atu i le vao.", "to be led away into the wilderness."]]},
  {num:23,words:[["Ma sa oo ina maua e Kita ma Teominea i lenei ala o latou olo mau.", "And it came to pass that Gid and Teomner by this means had obtained possession of their strongholds."], ["Ma sa oo ina alu lo matou ala, ina ua mavae la matou malaga mamao i le vao,", "And it came to pass that we took our course,"], ["agai i le laueleele o Sara'emila.", "after having traveled much in the wilderness towards the land of Zarahemla."]]},
  {num:24,words:[["Ma ina ua vaai mai sa Lamanā ua latou savavali agai atu i le laueleele o Sara'emila,", "And when the Lamanites saw that they were marching towards the land of Zarahemla,"], ["sa latou matatau tele,", "they were exceedingly afraid,"], ["nei i ai se fuafuaga ua tatao e taitai atu ai i latou i le faafanoga;", "lest there was a plan laid to lead them on to destruction;"], ["o lea na amata ai ona latou toe solomuli i le vao,", "therefore they began to retreat into the wilderness again,"], ["ioe,", "yea,"], ["i tua i le auala lava lea na latou o mai ai.", "even back by the same way which they had come."]]},
  {num:25,words:[["Ma faauta, sa po,", "And behold,"], ["ma sa latou faatutu ai o latou faleie,", "it was night and they did pitch their tents,"], ["ona sa manatu kapeteni sili o sa Lamanā ua vaivai sa Nifaē ona o la latou savaliga;", "for the chief captains of the Lamanites had supposed that the Nephites were weary because of their march;"], ["ma i le manatu ua latou tuliloaina la latou autau atoa, o lea sa latou le manatu ai e uiga i le aai o Maneti.", "and supposing that they had driven their whole army therefore they took no thought concerning the city of Manti."]]},
  {num:26,words:[["O lenei sa oo ina ua po,", "Now it came to pass that when it was night,"], ["sa ou faatonu atu ia aua nei momoe au tagata,", "I caused that my men should not sleep,"], ["ae e tatau ona latou savavali atu i se tasi auala agai i le laueleele o Maneti.", "but that they should march forward by another way towards the land of Manti."]]},
  {num:27,words:[["Ma ona o la matou savaliga lenei i le po,", "And because of this our march in the night– time,"], ["faauta,", "behold,"], ["o le aso na sosoo ai, na matou i ai i tala atu o sa Lamanā,", "on the morrow we were beyond the Lamanites,"], ["sa oo ina matou taunuu i le aai o Maneti i luma atu o i latou.", "insomuch that we did arrive before them at the city of Manti."]]},
  {num:28,words:[["Ma sa faapea ona oo ina matou maua o le aai o Maneti, e ala i lenei togafiti,", "And thus it came to pass,"], ["e aunoa ma le faamasaaina o le toto.", "that by this stratagem we did take possession of the city of Manti without the shedding of blood."]]},
  {num:29,words:[["Ma sa oo ina ua taunuu latalata mai autau a sa Lamanā i le aai,", "And it came to pass that when the armies of the Lamanites did arrive near the city,"], ["ma vaai mai ua matou saunia e faafetaiai i latou,", "and saw that we were prepared to meet them,"], ["sa latou ofo tele ma taia i le matau tele,", "they were astonished exceedingly and struck with great fear,"], ["sa oo ina latou sosola i le vao.", "insomuch that they did flee into the wilderness."]]},
  {num:30,words:[["Ioe,", "Yea,"], ["ma sa oo ina sosola ese i fafo autau a sa Lamanā mai lenei vaega uma o le laueleele.", "and it came to pass that the armies of the Lamanites did flee out of all this quarter of the land."], ["Ae faauta, sa latou ave faatasi ma i latou o fafine ma tamaiti e toatele,", "But behold,"], ["i fafo o le laueleele.", "they have carried with them many women and children out of the land."]]},
  {num:31,words:[["Ma o aai ia na ave e sa Lamanā, o ia aai uma ua matou mauaina i le taimi nei;", "And those cities which had been taken by the Lamanites,"], ["ma o o tatou tamā,", "all of them are at this period of time in our possession;"], ["ma o tatou fafine,", "and our fathers and our women and our children are returning to their homes,"], ["ma a tatou tamaiti ua toe foi atu i o latou fale, i latou uma lava ia vagana ai i latou o e ua ave faapagota ma aveese atu e sa Lamanā.", "all save it be those who have been taken prisoners and carried off by the Lamanites."]]},
  {num:32,words:[["Ae faauta,", "But behold,"], ["ua toaitiiti a matou autau e taofia le tele naua o aai ma le tele o mea ua maua.", "our armies are small to maintain so great a number of cities and so great possessions."]]},
  {num:33,words:[["Peitai faauta,", "But behold,"], ["matou te faalagolago i lo tatou Atua o le na ia foai mai ia te i tatou le manumalo i luga o ia laueleele,", "we trust in our God who has given us victory over those lands,"], ["ua oo ina tatou maua ai ia aai ma ia laueleele,", "insomuch that we have obtained those cities and those lands,"], ["ia sa a tatou lava.", "which were our own."]]},
  {num:34,words:[["O lenei matou te le iloa le pogai ua le tuuina mai ai e le malo se faamalosiga atili ia te i matou; pe ua iloa foi e tagata ia o e na o mai ia te i matou,", "Now we do not know the cause that the government does not grant us more strength;"], ["le pogai ua matou le maua ai se faamalosiga atili.", "neither do those men who came up unto us know why we have not received greater strength."]]},
  {num:35,words:[["Faauta,", "Behold,"], ["ua matou le iloa ae pe ua outou le manuia,", "we do not know but what ye are unsuccessful,"], ["ma ua e aveese atu ai autau i lena vaega o le laueleele;", "and ye have drawn away the forces into that quarter of the land;"], ["afai o lea,", "if so,"], ["matou te le fia muimui.", "we do not desire to murmur."]]},
  {num:36,words:[["Ae afai e le o lea,", "And if it is not so,"], ["faauta,", "behold,"], ["matou te popole ua i ai se fevaevaega i le malo,", "we fear that there is some faction in the government,"], ["ua latou le auina mai ai ni tagata faaopoopo e fesoasoani ia te i matou;", "that they do not send more men to our assistance;"], ["ona ua matou iloa ua sili atu lo latou toatele nai lo le aofai na latou auina mai.", "for we know that they are more numerous than that which they have sent."]]},
  {num:37,words:[["Ae,", "But,"], ["faauta,", "behold,"], ["ua le afaina—matou te faalagolago o le a laveaiina i matou e le Atua,", "it mattereth not—we trust God will deliver us,"], ["e ui i le vaivai o a matou autau,", "notwithstanding the weakness of our armies,"], ["ioe,", "yea,"], ["ma laveai i matou i fafo mai lima o o tatou fili.", "and deliver us out of the hands of our enemies."]]},
  {num:38,words:[["Faauta,", "Behold,"], ["o le tausaga lea e lua sefulu ma le iva,", "this is the twenty and ninth year,"], ["i le taufaaiuiuga,", "in the latter end,"], ["ma ua matou mauaina o tatou laueleele;", "and we are in the possession of our lands;"], ["ma ua sosola sa Lamanā i le laueleele o Nifae.", "and the Lamanites have fled to the land of Nephi."]]},
  {num:39,words:[["Ma o atalii na o le nuu o Amona,", "And those sons of the people of Ammon,"], ["o e sa ou tautala maualuga atu ai,", "of whom I have so highly spoken,"], ["o loo faatasi ma au i le aai o Maneti;", "are with me in the city of Manti;"], ["ma ua lagolagoina i latou e le Alii,", "and the Lord had supported them,"], ["ioe,", "yea,"], ["ma taofi i latou mai le pauu i le pelu,", "and kept them from falling by the sword,"], ["ua oo lava ina leai se tagata e toatasi ua fasiotia.", "insomuch that even one soul has not been slain."]]},
  {num:40,words:[["Ae faauta,", "But behold,"], ["sa oo ia i latou manua e tele;", "they have received many wounds;"], ["e ui i lea ua latou tutu mausali i le saolotoga lena na faasaoloto ai i latou e le Atua;", "nevertheless they stand fast in that  liberty wherewith God has made them free;"], ["ma ua latou tausisisi ia manatua le Alii lo latou Atua mai lea aso i lea aso;", "and they are strict to remember the Lord their God from day to day;"], ["ioe,", "yea,"], ["ua latou tausisisi e tausi i ana tulafono,", "they do observe to keep his statutes,"], ["ma ana faamasinoga,", "and his judgments,"], ["ma ana poloaiga e le aunoa;", "and his commandments continually;"], ["ma ua malolosi o latou faatuatua i valoaga e uiga i mea o le a oo mai.", "and their faith is strong in the prophecies concerning that which is to come."]]},
  {num:41,words:[["Ma o lenei,", "And now,"], ["lou uso pele e,", "my beloved brother,"], ["Moronae,", "Moroni,"], ["tau ina ia alofa le Alii lo tatou Atua,", "may the Lord our God,"], ["o le ua ia togiolaina i tatou ma faasaolotoina i tatou,", "who has redeemed us and made us free,"], ["ia tausia pea oe i ona luma e le aunoa;", "keep you continually in his presence;"], ["ioe,", "yea,"], ["ma talosia ia faapitoa e ia lenei nuu,", "and may he favor this people,"], ["seia oo lava ina mafai ona outou maua le manuia i le mauaina o mea uma na ave e sa Lamanā mai ia te i tatou,", "even that ye may have success in obtaining the possession of all that which the Lamanites have taken from us,"], ["ia sa mo lo tatou tausiga. Ma o lenei,", "which was for our support. And now,"], ["faauta,", "behold,"], ["ou te faaiu lau tusi. O au o Helamana,", "I close mine epistle. I am Helaman,"], ["le atalii o Alema.", "the son of Alma."]]},
];
renderVerseSet(al_ch_58_Verses, 'al-ch58-verses');

var al_ch_59_Verses = [
  {num:1,words:[["O lenei sa oo i le tausaga e tolu sefulu o le nofoaiga a faamasino i luga o le nuu o Nifae,", "Now it came to pass in the thirtieth year of the reign of the judges over the people of Nephi,"], ["ina ua mavae ona maua ma faitau e Moronae le tusi a Helamana,", "after Moroni had received and had read Helaman's epistle,"], ["sa olioli tele o ia ona o le manuia,", "he was exceedingly rejoiced because of the welfare,"], ["ioe,", "yea,"], ["le manuia tele lea na maua e Helamana,", "the exceeding success which Helaman had had,"], ["i le mauaina mai o laueleele ia na faoa.", "in obtaining those lands which were lost."]]},
  {num:2,words:[["Ioe,", "Yea,"], ["ma sa ia faailoa atu lenei mea i ona tagata uma,", "and he did make it known unto all his people,"], ["i le laueleele atoa e latalata ane i le vaega lena sa i ai o ia,", "in all the land round about in that part where he was,"], ["ina ia latou olioli foi.", "that they might rejoice also."]]},
  {num:3,words:[["Ma sa oo ina auina atu vave e ia se tusi ia Paorana ,", "And it came to pass that he immediately sent an epistle to Pahoran,"], ["e manao e tatau ia te ia ona faatonu atu ia faapotopoto faatasi ni tagata e faamalosi ia Helamana,", "desiring that he should cause men to be gathered together to strengthen Helaman,"], ["po o autau a Helamana,", "or the armies of Helaman,"], ["ina ia faigofie ia te ia ona taofi lena vaega o le laueleele lea sa faamanuiaina faavavega o ia i le toe maua mai.", "insomuch that he might with ease maintain that part of the land which he had been so miraculously prospered in regaining."]]},
  {num:4,words:[["Ma sa oo ina ua uma ona auina atu e Moronae lenei tusi i le laueleele o Sara'emila,", "And it came to pass when Moroni had sent this epistle to the land of Zarahemla,"], ["sa amata ona ia toe faataoto o se fuafuaga e mafai ai ona ia maua o laueleele ma aai ia na totoe na ave e sa Lamanā mai ia te i latou.", "he began again to lay a plan that he might obtain the remainder of those possessions and cities which the Lamanites had taken from them."]]},
  {num:5,words:[["Ma sa oo ina ao faapea ona faia e Moronae sauniuniga e o atu e faasaga ia sa Lamanā i le taua,", "And it came to pass that while Moroni was thus making preparations to go against the Lamanites to battle,"], ["faauta,", "behold,"], ["o tagata o Nifaea,", "the people of Nephihah,"], ["o e na faapotopoto faatasi mai le aai o Moronae ma le aai o Liae ma le aai o Morianetona,", "who were gathered together from the city of Moroni and the city of Lehi and the city of Morianton,"], ["sa osofaia e sa Lamanā.", "were attacked by the Lamanites."]]},
  {num:6,words:[["Ioe,", "Yea,"], ["e oo ia i latou o e na faamalosia e sosola ese mai le laueleele o Maneti,", "even those who had been compelled to flee from the land of Manti,"], ["ma mai le laueleele faataamilo ai,", "and from the land round about,"], ["ua o atu ma ua aufaatasi ma sa Lamanā i le vaega lenei o le laueleele.", "had come over and joined the Lamanites in this part of the land."]]},
  {num:7,words:[["Ma ona o lo latou matua toatele lava faapea,", "And thus being exceedingly numerous,"], ["ioe, ma lo latou maua o le malosi mai lea aso i lea aso,", "yea,"], ["na latou o mai ai,", "and receiving strength from day to day,"], ["e ala i le poloaiga a Amorona, e faasaga i tagata o Nifaea,", "by the command of Ammoron they came forth against the people of Nephihah,"], ["ma sa amata ona latou fasi o i latou i se fasiga tele lava.", "and they did begin to slay them with an exceedingly great slaughter."]]},
  {num:8,words:[["Ma sa matua toatele lava a latou autau sa oo ina faamalosia tagata na totoe o Nifaea e sosola mai i o latou luma;", "And their armies were so numerous that the remainder of the people of Nephihah were obliged to flee before them;"], ["ma sa latou o mai lava ma auai i le autau a Moronae.", "and they came even and joined the army of Moroni."]]},
  {num:9,words:[["Ma o lenei,", "And now as Moroni had supposed that there should be men sent to the city Nephihah,"], ["ona sa manatu Moronae e tatau ona i ai ni tagata e auina atu i le aai o Nifaea e fesoasoani i tagata e taofi lena aai,", "to the assistance of the people to maintain that city,"], ["ma i lona iloa e sili atu ona faigofie le taofi o le aai mai le pau atu i lima o sa Lamanā nai lo le toe ave o le aai mai ia te i latou,", "and knowing that it was easier to keep the city from falling into the hands of the Lamanites than to retake it from them,"], ["sa manatu o ia o le a faigofie ona latou taofia o lena aai.", "he supposed that they would easily maintain that city."]]},
  {num:10,words:[["O lea na ia taofi ai lana autau atoa e taofi nofoaga ia sa ia toe maua mai.", "Therefore he retained all his force to maintain those places which he had recovered."]]},
  {num:11,words:[["Ma o lenei,", "And now,"], ["ina ua vaai Moronae ua faoa le aai o Nifaea,", "when Moroni saw that the city of Nephihah was lost he was exceedingly sorrowful,"], ["sa faanoanoa tele o ia, ma amata ona masalosalo,", "and began to doubt,"], ["ona o le amioleaga o le nuu,", "because of the wickedness of the people,"], ["pe o le a latou le pauu atu ai i lima o o latou uso.", "whether they should not fall into the hands of their brethren."]]},
  {num:12,words:[["O lenei o le tulaga lenei sa i ai i ana kapeteni sili uma. Sa latou masalosalo ma ofo foi ona o le amioleaga o le nuu,", "Now this was the case with all his chief captains. They doubted and marveled also because of the wickedness of the people,"], ["ma o le mafuaaga o lenei mea ona o le manumalo o sa Lamanā ia i latou.", "and this because of the success of the Lamanites over them."]]},
  {num:13,words:[["Ma sa oo ina ita Moronae i le malo,", "And it came to pass that Moroni was angry with the government,"], ["ona o lo latou le popole e uiga i le saolotoga o lo latou atunuu.", "because of their indifference concerning the freedom of their country."]]},
];
renderVerseSet(al_ch_59_Verses, 'al-ch59-verses');

var al_ch_60_Verses = [
  {num:1,words:[["Ma sa oo ina toe tusi atu o ia i le kovana o le laueleele,", "And it came to pass that he wrote again to the governor of the land,"], ["o Paorana,", "who was Pahoran,"], ["ma o upu nei sa ia tusia,", "and these are the words which he wrote,"], ["ua fai atu:", "saying:"], ["Faauta,", "Behold,"], ["ou te faasino tonu lau tusi ia Paorana,", "I direct mine epistle to Pahoran,"], ["i le aai o Sara'emila,", "in the city of Zarahemla,"], ["o ia o le faamasino sili ma le kovana i luga o le laueleele,", "who is the chief judge and the governor over the land,"], ["ma i latou uma foi o e na filifilia e lenei nuu e pulea ma faatautaia mataupu o lenei taua.", "and also to all those who have been chosen by this people to govern and manage the affairs of this war."]]},
  {num:2,words:[["Aua faauta,", "For behold,"], ["ua ia te au ni mea ou te fai atu ai ia te i latou e ala i le tausalaina;", "I have somewhat to say unto them by the way of condemnation;"], ["ona faauta,", "for behold,"], ["ua outou iloa lava na tofia outou e faapotopoto faatasi tagata,", "ye yourselves know that ye have been appointed to gather together men,"], ["ma faaauupega i latou i pelu,", "and arm them with swords,"], ["ma simetea,", "and with cimeters,"], ["ma ituaiga o auupega eseese uma o taua,", "and all manner of weapons of war of every kind,"], ["ma aauina atu e faasaga ia sa Lamanā,", "and send forth against the Lamanites,"], ["i soo se vaega o le a latou o mai ai i lo tatou laueleele.", "in whatsoever parts they should come into our land."]]},
  {num:3,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te fai atu ia te oe,", "I say unto you that myself,"], ["o au lava,", "and also my men,"], ["ma au tagata foi,", "and also Helaman and his men,"], ["ma Helamana foi ma ana tagata, ua mafatia i mafatiaga tetele lava;", "have suffered exceedingly great sufferings;"], ["ioe,", "yea,"], ["e oo i le fia ai,", "even hunger,"], ["fia inu,", "thirst,"], ["ma le vaivai,", "and fatigue,"], ["ma ituaiga uma o puapuaga eseese.", "and all manner of afflictions of every kind."]]},
  {num:4,words:[["Ae faauta, a na fai ona pau ia o mea na matou mafatia ai,", "But behold,"], ["po ua matou le muimui pe tomumu.", "were this all we had suffered we would not murmur nor complain."]]},
  {num:5,words:[["Ae faauta,", "But behold,"], ["ua tele lava le fasiga ua i ai i totonu o o tatou tagata;", "great has been the slaughter among our people;"], ["ioe,", "yea,"], ["e afe ma afe ua pauu i le pelu,", "thousands have fallen by the sword,"], ["ae semanu o se isi tulaga pe a na outou tuu mai ia matou autau le malosi ia lava ma le fesoasoani mo i latou. Ioe,", "while it might have otherwise been if ye had rendered unto our armies sufficient strength and succor for them. Yea,"], ["ua tele lo outou faatamala mai ia te i matou.", "great has been your neglect towards us."]]},
  {num:6,words:[["Ma o lenei faauta,", "And now behold,"], ["matou te fia iloa le pogai o lenei faatamala tele;", "we desire to know the cause of this exceedingly great neglect;"], ["ioe,", "yea,"], ["matou te fia iloa le pogai o lo outou tulaga le mafaufau.", "we desire to know the cause of your thoughtless state."]]},
  {num:7,words:[["E mafai ea ona outou manatu tou te nonofo i luga o o outou nofoalii i se tulaga o le papa ma se mafaufau,", "Can you think to sit upon your thrones in a state of thoughtless stupor,"], ["ao loo faasosolo atu e o outou fili faataamilo ia te outou le galuega o le oti? Ioe,", "while your enemies are spreading the work of death around you? Yea,"], ["ao loo latou fasioti le afe ma afe o o outou uso—", "while they are murdering thousands of your brethren—"]]},
  {num:8,words:[["Ioe,", "Yea,"], ["i latou lava ia o e na vaai atu ia te outou mo le puipuiga,", "even they who have looked up to you for protection,"], ["ioe,", "yea,"], ["na tuuina outou i se tulaga manu e mafai ona outou fesoasoani atu ai ia te i latou,", "have placed you in a situation that ye might have succored them,"], ["ioe,", "yea,"], ["manu e mafai ona outou auina atu ai ni autau ia te i latou,", "ye might have sent armies unto them,"], ["e faamalolosi i latou,", "to have strengthened them,"], ["ma manu ua faasaoina ai le afe ma afe o i latou mai le pauu i le pelu.", "and have saved thousands of them from falling by the sword."]]},
  {num:9,words:[["Ae faauta,", "But behold,"], ["ua le ona pau lea—ua outou taofi a outou meaai mai ia te i latou,", "this is not all—ye have withheld your provisions from them,"], ["sa oo ina toatele na tau ma faamaligi o latou ola, ona o o latou naunauga tetele ia sa ia te i latou mo le manuia o lenei nuu;", "insomuch that many have fought and bled out their lives because of their great desires which they had for the welfare of this people;"], ["ioe,", "yea,"], ["ma sa latou faia lenei mea ao toeitiiti o latou fano i le fia aai,", "and this they have done when they were about to perish with hunger,"], ["ona o lo outou faatamala tele naua ia te i latou.", "because of your exceedingly great neglect towards them."]]},
  {num:10,words:[["Ma o lenei,", "And now,"], ["ou uso pele e—ona e tatau ona pele outou;", "my beloved brethren—for ye ought to be beloved;"], ["ioe,", "yea,"], ["ma ua tatau ona outou faaosofia outou lava ia outou filiga atili mo le manuia ma le saolotoga o lenei nuu;", "and ye ought to have stirred yourselves more diligently for the welfare and the freedom of this people;"], ["ae faauta,", "but behold,"], ["ua outou tuulafoaiina i latou i le tulaga o le a oo mai ai i luga o o outou ulu le toto o le afe ma afe mo le taui ma sui;", "ye have neglected them insomuch that the blood of thousands shall come upon your heads for vengeance;"], ["ioe,", "yea,"], ["ona ua silafia e le Atua a latou tagi uma,", "for known unto God were all their cries,"], ["ma o latou mafatiaga uma—", "and all their sufferings—"]]},
  {num:11,words:[["Faauta, tou te manatu ea e mafai ona outou nonofo i luga o o outou nofoalii ma manatu,", "Behold,"], ["ona o le agalelei tele o le Atua, o le a ia laveaiina ai lava outou,", "could ye suppose that ye could sit upon your thrones,"], ["i le le mafai ona outou faia o se mea? Faauta,", "and because of the exceeding goodness of God ye could do nothing and he would deliver you? Behold,"], ["afai o lo outou manatu lea, ua le aoga lo outou manatu.", "if ye have supposed this ye have supposed in vain."]]},
  {num:12,words:[["Tou te manatu ea e faapea ua fasiotia le toatele o o outou uso ona o lo latou amioleaga? Ou te fai atu ia te outou afai o lo outou manatu lea,", "Do ye suppose that,"], ["ua le aoga lo outou manatu;", "because so many of your brethren have been killed it is because of their wickedness? I say unto you,"], ["ona ou te fai atu ia te outou,", "if ye have supposed this ye have supposed in vain; for I say unto you,"], ["e toatele o e ua pauu i le pelu;", "there are many who have fallen by the sword;"], ["ma faauta o le a tausalaina outou i lenei mea;", "and behold it is to your condemnation;"]]},
  {num:13,words:[["Ona e tuu e le Alii e amiotonu ia fasiotia,", "For the Lord suffereth the righteous to be slain that his justice and judgment may come upon the wicked;"], ["ina ia mafai ona oo mai o lona faamasinotonu ma lana faamasinoga i luga o e amioleaga;", "therefore ye need not suppose that the righteous are lost because they are slain;"], ["o lea e le tatau ai ona outou manatu faapea ua malaia e amiotonu ona ua fasiotia i latou; ae faauta,", "but behold,"], ["latou te ulu atu i le malologa o le Alii lo latou Atua.", "they do enter into the rest of the Lord their God."]]},
  {num:14,words:[["Ma o lenei faauta,", "And now behold,"], ["ou te fai atu ia te outou,", "I say unto you,"], ["ua ou fefe tele lava o le a oo mai faamasinoga a le Atua i luga o lenei nuu,", "I fear exceedingly that the judgments of God will come upon this people,"], ["ona o lo latou faatalale tele,", "because of their exceeding slothfulness,"], ["ioe,", "yea,"], ["le faatalale lea o lo tatou malo,", "even the slothfulness of our government,"], ["ma lo latou faatamala tele e faasaga i o latou uso,", "and their exceedingly great neglect towards their brethren,"], ["ioe,", "yea,"], ["e faasaga ia i latou o e ua fasiotia.", "towards those who have been slain."]]},
  {num:15,words:[["Aua a na leai le amioleaga lea na muamua amata mai i lo tatou ulu,", "For were it not for the wickedness which first commenced at our head,"], ["po ua mafai ona tatou tutetee atu i o tatou fili ma le mafai ai ona latou maua o se mana i luga o i tatou.", "we could have withstood our enemies that they could have gained no power over us."]]},
  {num:16,words:[["Ioe,", "Yea,"], ["a na leai le taua lea na tupu ae i totonu o i tatou lava;", "had it not been for the war which broke out among ourselves;"], ["ioe,", "yea,"], ["a na leai nei tagata-tupu ,", "were it not for these king– men,"], ["o e na pogai mai ai le faamasaa toto tele i totonu o i tatou lava;", "who caused so much bloodshed  among ourselves;"], ["ioe,", "yea,"], ["i le taimi sa tatou fefinauai ai i totonu o i tatou lava,", "at the time we were contending among ourselves,"], ["a na tatou tuufaatasi lo tatou malosi e pei ona tatou faia e oo mai i le taimi nei;", "if we had united our strength as we hitherto have done;"], ["ioe,", "yea,"], ["a na leai le mananao i le mana ma le pule sa i ia tagata-tupu sa i luga o i tatou;", "had it not been for the desire of power and authority which those king– men had over us; had they been true to the cause of our freedom,"], ["a na latou faamaoni i le faamoemoe o lo tatou saolotoga,", "and united with us,"], ["ma aufaatasi ma i tatou,", "and gone forth against our enemies,"], ["ma o atu e faasaga i o tatou fili,", "instead of taking up their swords against us,"], ["nai lo le fetagofi ia latou pelu e faasaga mai ia te i tatou,", "which was the cause of so much bloodshed among ourselves;"], ["lea na mafua mai ai le faamasaa toto tele i totonu o i tatou lava;", "yea,"], ["ioe,", "if we had gone forth against them in the strength of the Lord,"], ["a na fai tatou te o atu e faasaga ia te i latou i le malosi o le Alii,", "we should have dispersed our enemies,"], ["po ua tatou faataapeapeina o tatou fili,", "for it would have been done,"], ["aua po ua faia lava e tusa ma le faataunuuina o lana afioga.", "according to the fulfilling of his word."]]},
  {num:17,words:[["Ae faauta,", "But behold,"], ["ua o mai nei sa Lamanā i luga o i tatou,", "now the Lamanites are coming upon us,"], ["ua ave o tatou laueleele,", "taking possession of our lands,"], ["ma o loo latou fasioti o tatou tagata i le pelu,", "and they are murdering our people with the sword,"], ["ioe,", "yea,"], ["o tatou fafine ma a tatou fanau,", "our women and our children,"], ["ma ave foi i latou faatagataotaua,", "and also carrying them away captive,"], ["ma faia ia i latou ia latou mafatia i ituaiga uma o puapuaga eseese,", "causing them that they should suffer all manner of afflictions,"], ["ma ua mafua mai lenei mea ona o le amioleaga tele o i latou o e o loo saili mo le mana ma le pule,", "and this because of the great wickedness of those who are seeking for power and authority,"], ["ioe,", "yea,"], ["i latou lava ia o tagata-tupu.", "even those king– men."]]},
  {num:18,words:[["Ae aisea ea e tatau ai ona ou tautala tele atu e uiga i lenei mataupu? Ona matou te le iloa ae o loo saili foi outou lava mo le pule. Matou te iloa ae atonu o outou foi o ni tagata faalata i lo outou atunuu.", "But why should I say much concerning this matter? For we know not but what ye yourselves are seeking for authority. We know not but what ye are also traitors to your country."]]},
  {num:19,words:[["Pe ua outou tuulafoai mai ia te i matou ona ua outou i ai i le totonugalemu o lo tatou atunuu ma ua siomia outou i le saogalemu,", "Or is it that ye have neglected us because ye are in the heart of our country and ye are surrounded by security,"], ["ua outou le faatonu ai ia auina mai ni meaai ia te i matou,", "that ye do not cause food to be sent unto us,"], ["ma ni tagata foi e faamalolosi ai a matou autau?", "and also men to strengthen our armies?"]]},
  {num:20,words:[["Ua galo ea ia te outou poloaiga a le Alii lo outou Atua? Ioe,", "Have ye forgotten the commandments of the Lord your God? Yea,"], ["ua galo ia te outou le faatagataotauaina o o tatou tamā? Ua galo ea ia te outou taimi e tele na laveai ai i tatou i fafo mai lima o o tatou fili?", "have ye forgotten the captivity of our fathers? Have ye forgotten the many times we have been delivered out of the hands of our enemies?"]]},
  {num:21,words:[["Pe tou te manatu o le a laveai pea i tatou e le Alii,", "Or do ye suppose that the Lord will still deliver us,"], ["ao tatou nonofo i luga o o tatou nofoaalii ma le faaaogaina mea ua saunia e le Alii mo i tatou?", "while we sit upon our thrones and do not make use of the means which the Lord has provided for us?"]]},
  {num:22,words:[["Ioe,", "Yea,"], ["tou te nofonofo ea i le paie ao siomia outou i le afe ma afe o i latou,", "will ye sit in idleness while ye are surrounded with thousands of those,"], ["ioe,", "yea,"], ["ma le sefulu o afe o i latou,", "and tens of thousands,"], ["o e o loo nofonofo foi i le paie,", "who do also sit in idleness,"], ["ao loo i ai le afe ma afe faataamilo i tuaoi o le laueleele o e o loo pauu i le pelu,", "while there are thousands round about in the borders of the land who are falling by the sword,"], ["ioe,", "yea,"], ["ua manunua ma sagatoto?", "wounded and bleeding?"]]},
  {num:23,words:[["Tou te manatu ea o le a silasila mai le Atua i o outou luga e peiseai ua outou le sala ao outou nonofo fifilemu ma vaai atu i nei mea? Faauta, ou te fai atu ia te outou,", "Do ye suppose that God will look upon you as guiltless while ye sit still and behold these things? Behold I say unto you,"], ["E leai.", "Nay."], ["O lenei ou te manao ia outou manatua na fetalai mai le Atua o le a muamua ona faamama o totonu o le ipu,", "Now I would that ye should remember that God has said that the inward vessel shall be cleansed first,"], ["ona faamama ai foi lea o fafo o le ipu.", "and then shall the outer vessel be cleansed also."]]},
  {num:24,words:[["Ma o lenei,", "And now,"], ["vagana ai ua outou salamo i mea ua outou faia,", "except ye do repent of that which ye have done,"], ["ma amata ona outou tutu i luga ma gaoioi,", "and begin to be up and doing,"], ["ma auina mai ni meaai ma ni tagata ia te i matou,", "and send forth food and men unto us,"], ["ma ia Helamana foi, ina ia mafai ona ia tausia vaega na o lo tatou atunuu ia ua ia toe maua mai,", "and also unto Helaman,"], ["ma ia mafai foi ona matou toe maua mai a tatou meatotino o totoe i nei vaega o le laueleele,", "that he may support those parts of our country which he has regained,"], ["faauta,", "and that we may  also recover the remainder of our possessions in these parts,"], ["o le a tatau ai ona matou le toe finau ma sa Lamanā seia muamua ona matou faamama o totonu o la tatou ipu,", "behold it will be expedient that we contend no more with the Lamanites until we have first cleansed our inward vessel,"], ["ioe,", "yea,"], ["le ulu tele lava lea o lo tatou malo.", "even the great head of our government."]]},
  {num:25,words:[["Ma e vagana ai ua outou tuu mai e tusa ma lau tusi,", "And except ye grant mine epistle,"], ["ma o mai i fafo ma faaali mai ia te au se agaga moni o le saolotoga,", "and come out and show unto me a true spirit of freedom,"], ["ma taumafai e faamalosi ma faatutu malolosi a tatou autau,", "and strive to strengthen and fortify our armies,"], ["ma tuu atu ia te i latou meaai mo lo latou tausiga, faauta,", "and grant unto them food for their support,"], ["o le a ou tuu se vaega o au tagata saoloto e taofi le vaega lenei o lo tatou laueleele,", "behold I will leave a part of my freemen to maintain this part of our land,"], ["ma o le a ou tuu le malosi ma faamanuiaga a le Atua i luga o i latou,", "and I will leave the strength and the blessings of God upon them,"], ["ina ia leai se isi mana e mafai ona gaoioi faasaga mai ia te i latou—", "that none other power can operate against them—"]]},
  {num:26,words:[["Ma o lea ona o lo latou faatuatua tele,", "And this because of their exceeding faith,"], ["ma lo latou onosai i o latou fita—", "and their patience in their tribulations—"]]},
  {num:27,words:[["Ma o le a ou alu atu ia te outou,", "And I will come unto you,"], ["ma afai o i ai soo se tasi i totonu o outou ua i ai se manao mo le saolotoga,", "and if there be any among you that has a desire for freedom,"], ["ioe,", "yea,"], ["afai o i ai lava sina aloi o le saolotoga o totoe,", "if there be even a spark of freedom remaining,"], ["faauta o le a ou faaosoina fouvalega i totonu o outou,", "behold I will stir up insurrections among you,"], ["seia oo lava ina tineia i latou uma o e ua i ai manao e avefua faamalosi le mana ma le pule.", "even until those who have desires to usurp power and authority shall become extinct."]]},
  {num:28,words:[["Ioe,", "Yea,"], ["faauta,", "behold I do not fear your power nor your authority,"], ["ou te le fefe i lo outou mana po o la outou pule, ae o lou Atua o le ua ou matau i ai;", "but it is my God whom I fear;"], ["ma o ana poloaiga ua ou tago ai i lau pelu e puipui le faamoemoe o lou atunuu,", "and it is according to his commandments that I do take my sword to defend the cause of my country,"], ["ma o lo outou amioletonu ua tatou mafatia ai i le tele o mea ua toesea.", "and it is because of your iniquity that we have suffered so much loss."]]},
  {num:29,words:[["Faauta ua oo i le taimi,", "Behold it is time,"], ["ioe,", "yea,"], ["ua oo mai nei le taimi,", "the time is now at hand,"], ["vagana ai ua outou faagaoioia outou lava i le puipuiga o lo outou atunuu ma a outou tamaiti,", "that except ye do bestir yourselves in the defense of your country and your little ones,"], ["ua tautau ifo le pelu o le faamasinoga i o outou luga;", "the sword of justice doth hang over you;"], ["ioe,", "yea,"], ["ma o le a pau ifo i o outou luga ma asiasi mai ia te outou e oo lava i lo outou faaumatiaga atoa.", "and it shall fall upon you and visit you even to your utter destruction."]]},
  {num:30,words:[["Faauta,", "Behold,"], ["ou te faatalitali mo le fesoasoani mai ia te outou;", "I wait for assistance from you;"], ["ma vagana ai ua outou fesoasoani mai mo lo matou mapusaga,", "and,"], ["faauta,", "except ye do administer unto our relief,"], ["ou te alu atu ia te outou,", "behold, I come unto you,"], ["i le laueleele lava o Sara'emila,", "even in the land of Zarahemla,"], ["ma ta outou i le pelu,", "and smite you with the sword,"], ["seia oo ina outou le toe maua se mana e taofi ai le alualu i luma o lenei nuu i le faamoemoe o lo tatou saolotoga.", "insomuch that ye can have no more power to impede the progress of this people in the cause of our freedom."]]},
  {num:31,words:[["Aua faauta,", "For behold,"], ["o le a le tuua e le Alii ia outou ola ma faasolo malolosi ia outou amioletonu e faaumatia ai ona tagata amiotonu.", "the Lord will not suffer that ye shall live and wax strong in your iniquities to destroy his righteous people."]]},
  {num:32,words:[["Faauta,", "Behold,"], ["e mafai ea ona outou manatu o le a faaolaina outou e le Alii ma afio mai i faamasinoga e faasaga ia sa Lamanā,", "can you suppose that the Lord will spare you and come out in judgment against the Lamanites,"], ["ae o uputuu a o latou tamā na pogai mai ai lo latou ita,", "when it is the tradition of their fathers that has caused their hatred,"], ["ioe,", "yea,"], ["ma ua faaluaina e i latou o e na faatuiese mai ia te i tatou,", "and it has been redoubled by those who have dissented from us,"], ["ae o lo outou amioletonu ua afua mai i lo outou naunau i le mamalu ma mea le aoga o le lalolagi?", "while your iniquity is for the cause of your love of glory and the vain things of the world?"]]},
  {num:33,words:[["Ua outou iloa ua outou solia tulafono a le Atua,", "Ye know that ye do transgress the laws of God,"], ["ma ua outou iloa ua outou solia ia tulafono i lalo o o outou vae. Faauta,", "and ye do know that ye do trample them under your feet. Behold,"], ["ua fetalai mai le Alii ia te au:", "the Lord saith unto me:"], ["Afai e le salamo i latou o e na outou tofia e avea ma o outou kovana ia latou agasala ma a latou amioletonu,", "If those whom ye have appointed your governors do not repent of their sins and iniquities,"], ["ia outou o atu e tau ma i latou.", "ye shall go up to battle against them."]]},
  {num:34,words:[["Ma o lenei faauta,", "And now behold,"], ["o au,", "I,"], ["o Moronae,", "Moroni,"], ["ua faamalosia au ia ou gaioi,", "am constrained,"], ["e tusa ma le feagaiga lea na ou osia e tausi poloaiga a lo'u Atua;", "according to the covenant which I have made to keep the commandments of my God;"], ["o lea ou te manao ai ia outou usitai i le afioga a le Atua,", "therefore I would that ye should adhere to the word of God,"], ["ma auina vave mai ia te au ni isi o a outou meaai ma ni isi o o outou tagata,", "and send speedily unto me of your provisions and of your men,"], ["ma ia Helamana foi.", "and also to Helaman."]]},
  {num:35,words:[["Ma faauta,", "And behold,"], ["afai tou te le faia lenei mea,", "if ye will not do this I come unto you speedily;"], ["o le a ou alu atu vave ia te outou; aua faauta,", "for behold,"], ["o le a le tuua e le Atua ia matou fano i le fia aai;", "God will not suffer that we should perish with hunger;"], ["o lea o le a ia tuu mai ai ia te i matou ni isi o a outou meaai,", "therefore he will give unto us of your food,"], ["e tusa pe tatau ai ona faia o lenei mea e ala i le pelu.", "even if it must be by the sword."], ["O lenei ia vaai ia outou faataunuuina le afioga a le Atua.", "Now see that ye fulfil the word of God."]]},
  {num:36,words:[["Faauta,", "Behold,"], ["o au o Moronae,", "I am Moroni,"], ["o lo outou kapeteni silisili. Ou te le saili mo le pule,", "your chief captain. I seek not for power,"], ["ae ia to ifo i lalo. Ou te le saili mo le mamalu o le lalolagi,", "but to pull it down. I seek not for honor of the world,"], ["ae mo le mamalu o lo'u Atua,", "but for the glory of my God,"], ["ma le saolotoga ma le manuia o lou atunuu. Ma ua faapea ona ou faaiu o lau tusi.", "and the freedom and welfare of my country. And thus I close mine epistle."]]},
];
renderVerseSet(al_ch_60_Verses, 'al-ch60-verses');

var al_ch_61_Verses = [
  {num:1,words:[["Faauta,", "Behold,"], ["o lenei sa oo ina sa lei umi ona auina atu e Moronae lana tusi i le kovana sili,", "now it came to pass that soon after Moroni had sent his epistle unto the chief governor,"], ["ae ia maua se tusi mai ia Paorana ,", "he received an epistle from Pahoran,"], ["le kovana sili. Ma o upu nei na ia maua mai:", "the chief governor. And these are the words which he received:"]]},
  {num:2,words:[["O au,", "I,"], ["o Paorana,", "Pahoran,"], ["o le o au o le kovana sili o lenei laueleele,", "who am the chief governor of this land,"], ["ou te auina atu nei upu ia Moronae,", "do send these words unto Moroni,"], ["le kapeteni sili i luga o le autau. Faauta,", "the chief captain over the army. Behold,"], ["ou te fai atu ia te oe,", "I say unto you,"], ["Moronae,", "Moroni,"], ["ou te le olioli i o outou puapuaga tele,", "that I do not joy in your great afflictions,"], ["ioe,", "yea,"], ["ua faanoanoa tele ai lou agaga.", "it grieves my soul."]]},
  {num:3,words:[["Ae faauta,", "But behold,"], ["o loo i ai i latou o e ua olioli i o outou puapuaga,", "there are those who do joy in your afflictions,"], ["ioe,", "yea,"], ["ua oo ina latou tutu mai e fouvale faasaga mai ia te au, ioe,", "insomuch that they have risen up in rebellion against me,"], ["ma i latou uma foi o e o o'u tagata o e o tagata-saoloto ,", "and also those of my people who are freemen,"], ["ioe,", "yea,"], ["ma o i latou o e ua tutu fouvale mai ua matua toatele lava.", "and those who have risen up are exceedingly numerous."]]},
  {num:4,words:[["Ma o i latou o e na saili e aveese le nofoa-faamasino mai ia te au,", "And it is those who have sought to take away the judgment– seat from me that have been the cause of this great iniquity;"], ["o i latou ia o le pogai o lenei amioletonu tele;", "for they have used great flattery,"], ["ona ua latou faaaoga le faaviivii tele, ma ua latou taitai ese loto o le toatele o tagata,", "and they have led away the hearts of many people,"], ["lea o le a a avea ma pogai o puapuaga tiga i totonu o i tatou;", "which will be the cause of sore affliction among us;"], ["ua latou taofi a matou meaai,", "they have withheld our provisions,"], ["ma ua latou faamatau o tatou tagata saoloto ua latou le o atu ai ia te outou.", "and have daunted our freemen that they have not come unto you."]]},
  {num:5,words:[["Ma faauta,", "And behold,"], ["ua latou tuli au i fafo mai o latou luma,", "they have driven me out before them,"], ["ma ua ou sola mai i le laueleele o Kitiona,", "and I have fled to the land of Gideon,"], ["faatasi ma le toatele o tagata sa mafai ona ou maua.", "with as many men as it were possible that I could get."]]},
  {num:6,words:[["Ma faauta,", "And behold,"], ["ua ou auina atu se folafolaga i le vaega atoa lenei o le laueleele;", "I have sent a proclamation throughout this part of the land;"], ["ma faauta,", "and behold,"], ["ua latou lolofi mai ia te i matou i aso taitasi,", "they are flocking to us daily,"], ["ma a latou auupega,", "to their arms,"], ["i le puipuiga o lo latou atunuu ma lo latou saolotoga ,", "in the defense of their country and their freedom,"], ["ma taui sese ua fai mai ia te i tatou.", "and to avenge our wrongs."]]},
  {num:7,words:[["Ma ua latou o mai ia te i matou,", "And they have come unto us,"], ["ua oo ina tutu tetee faasaga mai ia te i matou i latou o e na tutulai e fouvale,", "insomuch that those who have risen up in rebellion against us are set at defiance,"], ["ioe,", "yea,"], ["sa oo ina latou fefefe ia te i matou ma fefefe e o mai i fafo matou te tau.", "insomuch that they do fear us and durst not come out against us to battle."]]},
  {num:8,words:[["Ua latou maua le laueleele,", "They have got possession of the land,"], ["po o le aai,", "or the city,"], ["o Sara'emila;", "of Zarahemla;"], ["ua latou tofia se tupu i luga o i latou,", "they have appointed a king over them,"], ["ma ua tusi atu o ia i le tupu o sa Lamanā,", "and he hath written unto the king of  the Lamanites,"], ["lea na ia faia ai se soo ma ia;", "in the which he hath joined an alliance with him;"], ["le soo lea na ia ioe ai na te taofia le aai o Sara'emila,", "in the which alliance he hath agreed to maintain the city of Zarahemla,"], ["le taofiga lea na ia manatu o le a mafai ai e sa Lamanā ona manumalo i le vaega o totoe o le laueleele,", "which maintenance he supposeth will enable the Lamanites to conquer the remainder of the land,"], ["ma o le a faanofo ai o ia o le tupu i luga o lenei nuu pe a pulea i latou i lalo o sa Lamanā.", "and he shall be placed king over this people when they shall be conquered under the Lamanites."]]},
  {num:9,words:[["Ma o lenei,", "And now,"], ["ua e tausalaina au i lau tusi,", "in your epistle you have censured me,"], ["ae ua le afaina lea;", "but it mattereth not;"], ["ou te le o ita,", "I am not angry,"], ["a ua ou olioli i le tele o lou loto. O au,", "but do rejoice in the greatness of your heart. I,"], ["o Paorana,", "Pahoran,"], ["ou te le saili mo le pule,", "do not seek for power,"], ["nao lou fia taofi i lou nofoa-faamasino ina ia mafai ona ou faasaoina aia ma le saolotoga o ou tagata. Ua tumau mausali pea lou agaga i lena saolotoga ua faasaolotoina ai i tatou e le Atua.", "save only to retain my judgment– seat that I may preserve the rights and the liberty of my people. My soul standeth fast in that liberty in the which God hath made us free."]]},
  {num:10,words:[["Ma o lenei,", "And now,"], ["faauta,", "behold,"], ["o le a matou tetee atu i le amioleaga e oo lava i le faamasaa toto. Matou te le faamasaaina toto o sa Lamanā pe afai latou te nonofo pea i o latou lava laueleele.", "we will resist wickedness even unto bloodshed. We would not shed the blood of the Lamanites if they would stay in their own land."]]},
  {num:11,words:[["Matou te le faamasaaina toto o o tatou uso pe afai latou te le tutu ae i le fouvale ma ave le pelu e faasaga mai ia te i matou.", "We would not shed the blood of our brethren if they would not rise up in rebellion and take the sword against us."]]},
  {num:12,words:[["Matou te tuu atu i matou lava i lalo o le amo o le pologa pe afai e tusa ai lea mea ma le faamasinotonu o le Atua,", "We would subject ourselves to the yoke of bondage if it were requisite with the justice of God,"], ["pe afai foi na te poloaiina ai i matou ia faapea ona matou faia.", "or if he should command us so to do."]]},
  {num:13,words:[["Ae faauta ua le poloaiina e ia i tatou ia tatou tuu atu i tatou lava ia pulea e o tatou fili,", "But behold he doth not command us that we shall subject ourselves to our enemies,"], ["ae e tatau ona tatou tuu atu lo tatou faalagolago ia te ia,", "but that we should put our trust in him,"], ["ma o le a ia laveaiina i tatou.", "and he will deliver us."]]},
  {num:14,words:[["O lea,", "Therefore,"], ["lou uso pele e,", "my beloved brother,"], ["Moronae,", "Moroni,"], ["ia tatou tetee atu i le leaga,", "let us resist evil,"], ["ma o soo se mea leaga e le mafai ona tatou teena ia tatou upu,", "and whatsoever evil we cannot resist with our words,"], ["ioe,", "yea,"], ["e pei o fouvalega ma faatuiesega,", "such as rebellions and dissensions,"], ["ia tatou teena i latou ia tatou pelu,", "let us resist them with our swords,"], ["ina ia mafai ona tatou taofi o lo tatou saolotoga,", "that we may retain our freedom,"], ["ina ia mafai ona tatou olioli i le avanoa tele o la tatou ekalesia,", "that we may rejoice in the great privilege of our church,"], ["ma i le faamoemoe o lo tatou Togiola ma lo tatou Atua.", "and in the cause of our Redeemer and our God."]]},
  {num:15,words:[["O lea,", "Therefore,"], ["ia e sau vave ia te au faatasi ma ni au tagata toaitiiti,", "come unto me speedily with a few of your men,"], ["ae tuu le vaega e totoe i le vaaiga a Liae ma Teanekuma;", "and leave the remainder in the charge of Lehi and Teancum;"], ["tuu atu ia i laua le pule e taitai ai le taua i le vaega lena o le laueleele,", "give unto them power to conduct the war in that part of the land,"], ["e tusa ma le Agaga o le Atua,", "according to the Spirit of God,"], ["o le agaga foi lea o le saolotoga lea o loo ia te i laua.", "which is also the Spirit of freedom which is in them."]]},
  {num:16,words:[["Faauta ua ou auina atu ni meaai itiiti ia te i latou, ina ia latou le fano,", "Behold I have sent a few provisions unto them,"], ["seia mafai ona e sau ia te au.", "that they may not perish until ye can come unto me."]]},
  {num:17,words:[["Faapotopoto faatasi se autau e mafai ona e faapotopoto i lau savaliga mai iinei,", "Gather together whatsoever force ye can upon your march hither,"], ["ma o le a tatou o atu vave e faasaga i ia tagata faatuiese, i le malosi o lo tatou Atua,", "and we will go speedily against those dissenters,"], ["e tusa ma le faatuatua ua ia te i tatou.", "in the strength of our God according to the faith which is in us."]]},
  {num:18,words:[["Ma o le a tatou ave le aai o Sara'emila,", "And we will take possession of the city of Zarahemla,"], ["ina ia mafai ona tatou maua o ni meaai e tele e auina atu ia Liae ma Teanekuma;", "that we may obtain more food to send forth unto Lehi and Teancum;"], ["ioe,", "yea,"], ["o le a tatou o atu e faasaga ia te i latou i le malosi o le Alii,", "we will go forth against them in the strength of the Lord,"], ["ma o le a tatou faaiuina lenei amioletonu tele.", "and we will put an end to this great iniquity."]]},
  {num:19,words:[["Ma o lenei,", "And now,"], ["Moronae e,", "Moroni,"], ["ua ou olioli lava i lo'u maua mai o lau tusi,", "I do joy in receiving your epistle,"], ["ona sa ou popole teisi e uiga i se mea e tatau ona tatou faia,", "for I was somewhat worried concerning what we should do,"], ["pe ua tonu ia i tatou ona tatou o atu e tetee i o tatou uso.", "whether it should be just in us to go against our brethren."]]},
  {num:20,words:[["Peitai na e saunoa mai, vagana ai ua latou salamo,", "But ye have said,"], ["ua fetalai mai le Alii ia te oe, e tatau ona e alu atu e faasaga ia te i latou.", "except they repent the Lord hath commanded you that ye should go against them."]]},
  {num:21,words:[["Tagai ia e faamalosia Liae ma Teanekuma i la le Alii;", "See that ye strengthen Lehi and Teancum in the Lord;"], ["fai atu ia te i laua e aua nei fefefe,", "tell them to fear not,"], ["ona o le a laveaiina i latou e le Alii,", "for God will deliver them,"], ["ioe,", "yea,"], ["ma i latou uma foi o e e tutumau mausali i le saolotoga lena ua faasaolotoina ai i latou e le Atua. Ma o lenei ua ou faaiu lau tusi i lou uso pele,", "and also all those who stand fast in that liberty wherewith God hath made them free. And now I close mine epistle to my beloved brother,"], ["o Moronae.", "Moroni."]]},
];
renderVerseSet(al_ch_61_Verses, 'al-ch61-verses');

var al_ch_62_Verses = [
  {num:1,words:[["Ma o lenei sa oo ina ua maua e Moronae lenei tusi sa faalototeleina o ia,", "And now it came to pass that when Moroni had received this epistle his heart did take courage,"], ["ma sa tumu i le olioli tele lava ona o le faamaoni o Paorana,", "and was filled with exceedingly great joy because of the faithfulness of Pahoran,"], ["ona o ia sa le o se faalata foi i le saolotoga ma le faamoemoe o lona atunuu.", "that he was not also a traitor to the freedom and cause of his country."]]},
  {num:2,words:[["Ae sa ia faanoanoa tele foi ona o le amioletonu o i latou o e na tulieseina Paorana mai le nofoa-faamasino,", "But he did also mourn exceedingly because of the iniquity of those who had driven Pahoran from the judgment– seat,"], ["ioe, i se aotelega,", "yea,"], ["ona o i latou o e na fouvale faasaga i lo latou atunuu ma lo latou Atua foi.", "in fine because of those who had rebelled against their country and also their God."]]},
  {num:3,words:[["Ma sa oo ina ave e Moronae se vaega toaitiiti o ona tagata,", "And it came to pass that Moroni took a small number of men,"], ["e tusa ma le manao mai o Paorana,", "according to the desire of Pahoran,"], ["ma tuu atu ia Liae ma Teanekuma le pule i luga o e na totoe o lana autau,", "and gave Lehi and Teancum command over the remainder of his army,"], ["ma alu lana savaliga agai i le laueleele o Kitiona.", "and took his march towards the land of Gideon."]]},
  {num:4,words:[["Ma sa ia sisi le tagavai o le saolotoga i soo se nofoaga sa ia ulu atu i ai,", "And he did raise the standard of liberty in whatsoever place he did enter,"], ["ma maua mai ai soo se autau sa mafai ona ia maua i lana savaliga atoa agai atu i le laueleele o Kitiona.", "and gained whatsoever force he could in all his march towards the land of Gideon."]]},
  {num:5,words:[["Ma sa oo ina lolofi mai le afe ma afe i lana tagavai,", "And it came to pass that thousands did flock unto his standard,"], ["ma sa latou ave a latou pelu i le puipuiga o lo latou saolotoga,", "and did take up their swords in the defense of their freedom,"], ["ina ia le mafai ona latou o atu i le pologa.", "that they might not come into bondage."]]},
  {num:6,words:[["Ma sa faapea,", "And thus,"], ["ina ua uma ona faapotopoto faatasi e Moronae ni tagata sa mafai ona ia maua i lana savaliga atoa,", "when Moroni had gathered together whatsoever men he could in all his march,"], ["ona ia oo atu lea i le laueleele o Kitiona; ma ina ua tuufaatasi ana au ma au a Paorana,", "he came to the land of Gideon;"], ["sa oo ina latou malolosi tele lava,", "and uniting his forces with those of Pahoran they became exceedingly strong,"], ["sa sili atu ona malolosi e oo lava nai lo tagata a Pakusa,", "even stronger than the men of Pachus,"], ["o le sa avea ma tupu o tagata faatuiese na o e na tutulieseina tagata-saoloto i fafo o le laueleele o Sara'emila ma latou ave le laueleele.", "who was the king of those dissenters who had driven the freemen out of the land of Zarahemla and had taken possession of the land."]]},
  {num:7,words:[["Ma sa oo ina o ifo Moronae ma Paorana ma a laua autau i lalo i le laueleele o Sara'emila,", "And it came to pass that Moroni and Pahoran went down with their armies into the land of Zarahemla,"], ["ma o atu e faasaga i le aai,", "and went forth against the city,"], ["ma sa fetaiai ma tagata a Pakusa,", "and did meet the men of Pachus,"], ["sa oo ina latou tau.", "insomuch that they did come to battle."]]},
  {num:8,words:[["Ma faauta,", "And behold,"], ["sa fasiotia Pakusa ma ave faapagota ana tagata,", "Pachus was slain and his men were taken prisoners,"], ["ma sa toefuatai Paorana i lona nofoa-faamasino.", "and Pahoran was restored to his judgment seat."]]},
  {num:9,words:[["Ma sa maua e tagata o Pakusa lo latou faamasinoga,", "And the men of Pachus received their trial,"], ["e tusa ma le tulafono,", "according to the law,"], ["ma tagata-tupu foi ia o e na ave ma lafo i le falepuipui;", "and also those king– men who had been taken and cast into prison;"], ["ma sa fasiotia i latou e tusa ma le tulafono;", "and they were executed according to the law;"], ["ioe,", "yea,"], ["o tagata na a Pakusa ma soo se tasi o tagata-tupu na,", "those men of Pachus and those kingmen,"], ["o e na mumusu e fetagofi i auupega o taua i le puipuiga o lo latou atunuu,", "whosoever would not take up arms in the defense of their country,"], ["ae sa tau tetee i ai,", "but would fight against it,"], ["sa fasiotia.", "were put to death."]]},
  {num:10,words:[["Ma sa faapea ona tatau ona tausia saolele lava lenei tulafono mo le saogalemu o lo latou atunuu;", "And thus it became expedient that this law should be strictly observed for the safety of their country;"], ["ioe,", "yea,"], ["ma o soo se tasi na maua ua ia taofia lo latou saolotoga sa vave lava ona fasioti e tusa ma le tulafono.", "and whosoever was found denying their freedom was speedily executed according to the law."]]},
  {num:11,words:[["Ma sa faapea ona iu o le tausaga e tolu sefulu o le nofoaiga a faamasino i le nuu o Nifae;", "And thus ended the thirtieth year of the reign of the judges over the people of Nephi;"], ["ua uma ona toefuatai e Moronae ma Paorana le filemu i le laueleele o Sara'emila,", "Moroni and Pahoran having restored peace to the land of Zarahemla,"], ["i totonu o o latou lava tagata,", "among their own people,"], ["ina ua uma lea ona faaoo o le oti ia i latou uma o e sa le faamaoni i le faamoemoe o le saolotoga.", "having inflicted death upon all those who were not true to the cause of freedom."]]},
  {num:12,words:[["Ma sa oo i le amataga o le tausaga e tolu sefulu ma le tasi o le nofoaiga a faamasino i luga o le nuu o Nifae,", "And it came to pass in the commencement of the thirty and first year of the reign of the judges over the people of Nephi,"], ["sa vave ona faatonu atu o Moronae e tatau ona auina atu ni meaai,", "Moroni immediately caused that provisions should be sent,"], ["ma tatau foi ona auina atu se autau o tagata e ono afe ia Helamana,", "and also an army of six thousand men should be sent unto Helaman,"], ["e fesoasoani ia te ia i le puipuiga o lena vaega o le laueleele.", "to assist him in preserving that part of the land."]]},
  {num:13,words:[["Ma sa ia faatonu atu foi ia auina atu se autau o ni tagata e ono afe,", "And he also caused that an army of six thousand men,"], ["faatasi ma se aofai o meaai ia lava,", "with a sufficient quantity of food,"], ["i autau a Liae ma Teanekuma. Ma sa oo ina faia lenei mea e faamalosi ai le laueleele faasaga ia sa Lamanā.", "should be sent to the armies of Lehi and Teancum. And it came to pass that this was done to fortify the land against the Lamanites."]]},
  {num:14,words:[["Ma sa oo ina tuu e Moronae ma Paorana se tino tele o tagata i le laueleele o Sara'emila,", "And it came to pass that Moroni and Pahoran,"], ["ae alu la laua savaliga faatasi ma se tino tele o tagata agai i le laueleele o Nifaea,", "leaving a large body of men in the land of Zarahemla, took their march with a large body of men towards the land of Nephihah,"], ["ma le mauai e faatoilalo sa Lamanā sa i lena aai.", "being determined to overthrow the Lamanites in that city."]]},
  {num:15,words:[["Ma sa oo ina ao latou savavali agai atu i le laueleele,", "And it came to pass that as they were marching towards the land,"], ["sa latou ave se tino tele o tagata sa Lamanā,", "they took a large body of men of the Lamanites,"], ["ma fasioti le toatele o i latou,", "and slew many of them,"], ["ma ave a latou meaai ma a latou auupega o taua.", "and took their provisions and their weapons of war."]]},
  {num:16,words:[["Ma sa oo ina ua uma ona latou ave o i latou,", "And it came to pass after they had taken them,"], ["sa latou faatonu i latou ia latou osia se feagaiga ia latou le toe fetagofi ia latou auupega o taua e faasaga ia sa Nifaē.", "they caused them to enter into a covenant that they would no more take up their weapons of war against the Nephites."]]},
  {num:17,words:[["Ma ina ua uma ona latou osia o lenei feagaiga, sa latou auina atu i latou e nonofo faatasi ma le nuu o Amona,", "And when they had entered into this covenant they sent them to dwell with the people of Ammon,"], ["ma o le aofai o i latou o e sa lei fasiotia e tusa o le fa afe.", "and they were in number about four thousand who had not been slain."]]},
  {num:18,words:[["Ma sa oo ina ua uma ona latou auina ese atu o i latou sa latou tuliloa la latou savaliga agai atu i le laueleele o Nifaea. Ma sa oo ina ua latou oo atu i le aai o Nifaea,", "And it came to pass that when they had sent them away they pursued their march towards the land of Nephihah. And it came to pass that when they had come to the city of Nephihah,"], ["sa latou faatutu o latou faleie i laugatasi o Nifaea,", "they did pitch their tents in the plains of Nephihah,"], ["ia sa latalata i le aai o Nifaea.", "which is near the city of Nephihah."]]},
  {num:19,words:[["O lenei sa manao Moronae ia o mai sa Lamanā i fafo e tau ma i latou,", "Now Moroni was desirous that the Lamanites should come out to battle against them,"], ["i luga o laugatasi;", "upon the plains;"], ["ae ona ua iloa e sa Lamanā lo latou lototetele tele,", "but the Lamanites, knowing of their exceedingly great courage,"], ["ma latou vaaia le toatele tele o lo latou aofai,", "and beholding the greatness of their numbers,"], ["o lea na latou fefefe ai e o mai i fafo e faasaga mai ia te i latou;", "therefore they durst not come out against them;"], ["o lea na latou le o mai ai e tau i le aso lena.", "therefore they did not come to battle in that day."]]},
  {num:20,words:[["Ma ina ua oo mai le po,", "And when the night came,"], ["sa alu atu Moronae i le pogisa o le po,", "Moroni went forth in the darkness of the night,"], ["ma alu ae i luga o le tumutumu o le pa e sipai po o le a le vaega o le aai o tolauapi ai sa Lamanā faatasi ma la latou autau.", "and came upon the top of the wall to spy out in what part of the city the Lamanites did camp with their army."]]},
  {num:21,words:[["Ma sa oo ina sa latou i ai i le itu i sasae,", "And it came to pass that they were on the east,"], ["i tafatafa o le faitotoa;", "by the entrance;"], ["ma sa latou momoe uma.", "and they were all asleep."], ["Ma o lenei sa toe foi mai Moronae i lana autau,", "And now Moroni returned to his army,"], ["ma faatonu ia latou saunia vave ni maea malolosi ma apefai, e tuutuu ifo i lalo mai le tumutumu o le pa,", "and caused that they should prepare in haste strong cords and ladders,"], ["i le itu i totonu o le pa.", "to be let down from the top of the wall into the inner part of the wall."]]},
  {num:22,words:[["Ma sa oo ina faatonu e Moronae ia savavali atu ana tagata ma o ae i le tumutumu i luga o le pa,", "And it came to pass that Moroni caused that his men should march forth and come upon the top of the wall,"], ["ma tuutuu ifo i latou lava i lalo i totonu o le vaega lena o le aai,", "and let themselves down into that part of the city,"], ["ioe,", "yea,"], ["le itu lava lea i sisifo,", "even on the west,"], ["lea sa le tolauapi ai sa Lamanā faatasi ma a latou autau.", "where the Lamanites did not camp with their armies."]]},
  {num:23,words:[["Ma sa oo ina tuutuu ifo i latou uma i lalo i totonu o le aai i le po,", "And it came to pass that they were all let down into the city by night,"], ["e ala ia latou maea malolosi ma a latou apefai;", "by the means of their strong cords and their ladders;"], ["o lea e malama ae le taeao ua latou i ai uma i totonu o pa o le aai.", "thus when the morning came they were all within the walls of the city."]]},
  {num:24,words:[["Ma o lenei,", "And now,"], ["ina ua ala mai sa Lamanā ma vaai mai ua i ai autau a Moronae i totonu o pa,", "when the Lamanites awoke and saw that the armies of Moroni were within the walls,"], ["sa latou matatau lava,", "they were affrighted exceedingly,"], ["sa oo ina latou sosola i fafo e ala atu i le mea e ui mai ai i totonu.", "insomuch that they did flee out by the pass."]]},
  {num:25,words:[["Ma o lenei,", "And now when Moroni saw that they were fleeing before him,"], ["ina ua vaai atu Moronae ua latou sosola mai i ona luma,", "he did cause that his men should march forth against them,"], ["sa ia faatonu ia savavali atu ana tagata e faasaga ia te i latou,", "and slew many,"], ["ma fasioti le toatele, ma sio isi e toatele,", "and surrounded many others,"], ["ma ave i latou faapagota;", "and took them prisoners;"], ["ae o i latou o e na totoe sa sosola atu i le laueleele o Moronae,", "and the remainder of them fled into the land of Moroni,"], ["lea sa i tuaoi i tafatafa o le matafaga.", "which was in the borders by the seashore."]]},
  {num:26,words:[["Sa faapea ona maua e Moronae ma Paorana le aai o Nifaea e aunoa ma se tagata e toatasi na toesea;", "Thus had Moroni and Pahoran obtained the possession of the city of Nephihah without the loss of one soul;"], ["ma sa toatele sa Lamanā o e na fasiotia.", "and there were many of the Lamanites who were slain."]]},
  {num:27,words:[["O lenei sa oo ina o le toatele o sa Lamanā sa faapagota, sa mananao e faatasi ma le nuu o Amona ma avea ma tagata saoloto.", "Now it came to pass that many of the Lamanites that were prisoners were desirous to join the people of Ammon and become a free people."]]},
  {num:28,words:[["Ma sa oo ina o le toatele o i latou sa mananao faapea,", "And it came to pass that as many as were desirous,"], ["sa tuuina atu ia i latou e tusa ma o latou manao.", "unto them it was granted according to their desires."]]},
  {num:29,words:[["O lea,", "Therefore,"], ["o pagota uma sa Lamanā,", "all the prisoners of the Lamanites did join the people of Ammon,"], ["sa aufaatasi ma le nuu o Amona,", "and did begin to labor exceedingly,"], ["ma sa amata ona latou galulue malolosi,", "tilling the ground,"], ["i le galueaiina o le eleele, ma toto saito o ituaiga eseese uma,", "raising all manner of grain,"], ["ma fai lafu ma fagaga o ituaiga o manu eseese;", "and flocks and herds of every kind;"], ["ma sa faapea ona mapu ai o sa Nifaē mai se avega tele;", "and thus were the Nephites relieved from a great burden;"], ["ioe,", "yea,"], ["sa oo ina latou mapu mai pagota sa Lamanā uma.", "insomuch that they were relieved from all the prisoners of the Lamanites."]]},
  {num:30,words:[["O lenei sa oo ina ua uma ona maua e Moronae le aai o Nifaea,", "Now it came to pass that Moroni,"], ["ina ua uma ona ia ave o pagota e toatele,", "after he had obtained possession of the city of Nephihah,"], ["lea na faaitiitia tele ai lava autau a sa Lamanā,", "having taken many prisoners, which did reduce the armies of the Lamanites exceedingly,"], ["ma ina ua toe maua mai le toatele o sa Nifaē o e na ave faapagota,", "and having regained many of the Nephites who had been taken prisoners,"], ["lea na faamalosia tele ai le autau a Moronae;", "which did strengthen the army of Moroni exceedingly;"], ["o lea na alu atu ai loa Moronae mai le laueleele o Nifaea i le laueleele o Liae.", "therefore Moroni went forth from the land of Nephihah to the land of Lehi."]]},
  {num:31,words:[["Ma sa oo ina ua vaai mai sa Lamanā ua alu atu Moronae e faasaga ia te i latou,", "And it came to pass that when the Lamanites saw that Moroni was coming against them,"], ["sa latou toe fefefe ma sosola mai luma o le autau a Moronae.", "they were again frightened and fled before the army of Moroni."]]},
  {num:32,words:[["Ma sa oo ina tuli i latou e Moronae ma lana autau mai lea aai i lea aai,", "And it came to pass that Moroni and his army did pursue them from city to city,"], ["seia oo ina faafetaiai i latou e Liae ma Teanekuma;", "until they were met by Lehi and Teancum;"], ["ma sa sosola sa Lamanā mai ia Liae ma Teanekuma,", "and the Lamanites fled from Lehi and Teancum,"], ["sei oo atu lava i lalo i luga o tuaoi e i tafatafa o le matafaga,", "even down upon the borders by the seashore,"], ["seia oo ina latou oo mai i le laueleele o Moronae.", "until they came to the land of Moroni."]]},
  {num:33,words:[["Ma sa faapotopoto faatasi autau uma a sa Lamanā,", "And the armies of the Lamanites were all gathered together,"], ["sa oo ina latou i ai uma i se tino e tasi i le laueleele o Moronae.", "insomuch that they were all in one body in the land of Moroni."], ["O lenei o Amorona,", "Now,"], ["le tupu o sa Lamanā,", "Ammoron, the king of the Lamanites,"], ["sa faatasi foi ma i latou.", "was also with them."]]},
  {num:34,words:[["Ma sa oo ina tolauapi Moronae ma Liae ma Teanekuma ma a latou autau faataamilo i tuaoi o le laueleele o Moronae,", "And it came to pass that Moroni and Lehi and Teancum did encamp with their armies round about in the borders of the land of Moroni,"], ["sa oo ina siomia faataamilo ai sa Lamanā i totonu o tuaoi e i tafatafa o le vao i le itu i saute,", "insomuch that the Lamanites were encircled about in the borders by the wilderness on the south,"], ["ma i tuaoi e i tafatafa o le vao i le itu i sasae.", "and in the borders by the wilderness on the east."]]},
  {num:35,words:[["Ma sa faapea ona latou tolauapi mo le po.", "And thus they did encamp for the night."], ["Aua faauta,", "For behold,"], ["sa vaivai foi sa Nifaē ma sa Lamanā ona o le tele tele o le savaliga;", "the Nephites and the Lamanites also were weary because of the greatness of the march;"], ["o lea sa latou le mafaufau ai e uiga i se togafiti e fai i le taimi o le po,", "therefore they did not resolve upon any stratagem in the night– time,"], ["vagana ai Teanekuma;", "save it were Teancum;"], ["ona sa ita tele o ia ia Amorona;", "for he was exceedingly angry with Ammoron,"], ["ona sa manatu o ia, o Amorona,", "insomuch that he considered that Ammoron,"], ["ma lona uso o Amalekia,", "and Amalickiah his brother,"], ["na pogai mai ai lenei taua tele ma le umi i lo latou va ma sa Lamanā,", "had been the cause of this great and lasting war between them and the Lamanites,"], ["lea ua mafua mai ai taua e tele ma le faamasaa toto tele,", "which had been the cause of so much war and bloodshed,"], ["ioe,", "yea,"], ["ma le oge tele naua.", "and so much famine."]]},
  {num:36,words:[["Ma sa oo ina alu atu Teanekuma i lona ita i le tolauapiga a sa Lamanā,", "And it came to pass that Teancum in his anger did go forth into the camp of the Lamanites,"], ["ma tuu ifo o ia lava i lalo mai luga o pa o le aai. Ma sa alu atu o ia ma se maea,", "and did let himself down over the walls of the city. And he went forth with a cord,"], ["mai lea mea i lea mea,", "from place to place,"], ["sa oo ina ia maua le tupu;", "insomuch that he did find the king;"], ["ma sa ia velo o ia i se tao,", "and he did cast a javelin at him,"], ["lea sa tutuia ai o ia latalata i le fatu. Peitai faauta,", "which did pierce him near the heart. But behold,"], ["sa fafagu e le tupu ana auauna ae lei oti o ia,", "the king did awaken his servants before he died,"], ["sa oo ina latou tuliloa Teanekuma,", "insomuch that they did pursue Teancum,"], ["ma fasioti ia te ia.", "and slew him."]]},
  {num:37,words:[["O lenei sa oo ina ua iloa e Liae ma Moronae ua oti Teanekuma,", "Now it came to pass that when Lehi and Moroni knew that Teancum was dead they were exceedingly sorrowful;"], ["sa la faanoanoa tele lava;", "for behold,"], ["ona faauta, o ia o se tagata sa tau ma le faamaoni mo lona atunuu,", "he had been a man who had fought valiantly for his country,"], ["ioe,", "yea,"], ["o se uo moni i le saolotoga;", "a true friend to liberty;"], ["ma sa ia mafatia i le tele o puapuaga tiga.", "and he had suffered very many exceedingly sore afflictions."], ["Ae faauta,", "But behold,"], ["ua maliu o ia,", "he was dead,"], ["ma ua alu atu i le ala o le lalolagi uma.", "and had gone the way of all the earth."]]},
  {num:38,words:[["O lenei sa oo ina savali atu Moronae i le aso na sosoo ai,", "Now it came to pass that Moroni marched forth on the morrow,"], ["ma oo atu i luga o sa Lamanā,", "and came upon the Lamanites,"], ["sa oo ina latou fasia ai i latou i se fasiga tele;", "insomuch that they did slay them with a great slaughter;"], ["ma sa latou tutuli ese i latou mai le laueleele;", "and they did drive them out of the land;"], ["ma sa latou sosola,", "and they did flee,"], ["sa oo ina latou le toe foi mai i le taimi lena e faasaga mai ia sa Nifaē.", "even that they did not return at that time against the Nephites."]]},
  {num:39,words:[["Ma sa faapea ona iu o le tausaga e tolu sefulu ma le tasi o le nofoaiga a faamasino i le nuu o Nifae;", "And thus ended the thirty and first year of the reign of the judges over the people of Nephi;"], ["ma sa faapea ona oo ia i latou o taua,", "and thus they had had wars,"], ["ma le totomasaa,", "and bloodsheds,"], ["ma oge,", "and famine,"], ["ma puapuaga,", "and affliction,"], ["mo le va o le tele o tausaga.", "for the space of many years."]]},
  {num:40,words:[["Ma sa i ai le fasioti tagata,", "And there had been murders,"], ["ma finauga,", "and contentions,"], ["ma faatuiesega,", "and dissensions,"], ["ma ituaiga uma o amioletonu eseese i totonu o le nuu o Nifae;", "and all manner of iniquity among the people of Nephi;"], ["e ui i lea mo le manuia o e amiotonu,", "never– theless for the righteous' sake,"], ["ioe,", "yea,"], ["ona o talosaga a e amiotonu,", "because of the prayers of the righteous,"], ["sa faasaoina i latou.", "they were spared."]]},
  {num:41,words:[["Ae faauta,", "But behold,"], ["ona o le umi tele o le taua i le va o sa Nifaē ma sa Lamanā,", "because of the exceedingly great length of the war between the Nephites and the Lamanites many had become hardned,"], ["sa toatele na faamaaaina, ona o le umi tele naua o le taua;", "because of the exceedingly great length of the war;"], ["ae e toatele sa faamaluluina ona o o latou puapuaga ,", "and many were softened because of their afflictions,"], ["sa oo ina latou faalotomaualalaloina i latou lava i luma o le Atua,", "insomuch that they did humble themselves before God,"], ["sa oo lava i le loloto o le lotomaualalo.", "even in the depth of humility."]]},
  {num:42,words:[["Ma sa oo ina ua uma ona tuiolo e Moronae vaega na o le laueleele ia sa sili ona tulalata atu ia sa Lamanā,", "And it came to pass that after Moroni had fortified those parts of the land which were most exposed to the Lamanites,"], ["seia oo ina lava lo latou malolosi,", "until they were sufficiently strong,"], ["sa ia toe foi atu i le aai o Sara'emila;", "he returned to the city of Zarahemla;"], ["ma sa toe foi atu foi Helamana i le nofoaga o lona tofi;", "and also Helaman returned to the place of his inheritance;"], ["ma sa toe faatuina le filemu i totonu o le nuu o Nifae.", "and there was once more peace established among the people of Nephi."]]},
  {num:43,words:[["Ma sa tuu atu e Moronae le pule i ana autau i lima o lona atalii,", "And Moroni yielded up the command of his armies into the hands of his son,"], ["o lona igoa o Moronaea;", "whose name was Moronihah;"], ["ma sa malolo atu o ia i lona lava fale ina ia mafai ona ia faaaluina ona aso na totoe i le filemu.", "and he retired to his own house that he might spend the remainder of his days in peace."]]},
  {num:44,words:[["Ma sa toe foi atu Paorana i lona nofoa-faamasino;", "And Pahoran did return to his judgment– seat;"], ["ma sa toe ave e Helamana i ona lava luga e talai atu i tagata le afioga a le Atua;", "and Helaman did take upon him again to preach unto the people the word of God;"], ["ona talu ai le tele naua o taua ma finauga o lea na tatau ai ona toe faia o se faatonutonuga i le ekalesia.", "for because of so many wars and contentions it had become expedient that a regulation should be made again in the church."]]},
  {num:45,words:[["O lea,", "Therefore,"], ["na o atu ai Helamana ma ona uso,", "Helaman and his brethren went forth,"], ["ma talai atu le afioga a le Atua faatasi ma le mana tele sa oo ina talitonu ai le toatele o tagata i lo latou amioleaga,", "and did declare the word of God with much power unto the convincing of many people of their wickedness,"], ["o se mea sa uunaia ai i latou ia salamo ia latou agasala ma papatiso i le Alii lo latou Atua.", "which did cause them to repent of their sins and to be baptized unto the Lord their God."]]},
  {num:46,words:[["Ma sa oo ina latou toe faatuina le ekalesia a le Atua,", "And it came to pass that they did establish again the church of God,"], ["i le laueleele atoa.", "throughout all the land."]]},
  {num:47,words:[["Ioe,", "Yea,"], ["ma sa faia ni faatonutonuga e uiga i le tulafono. Ma sa filifilia o latou faamasino ,", "and regulations were made concerning the law. And their judges,"], ["ma o latou faamasino sili.", "and their chief judges were chosen."]]},
  {num:48,words:[["Ma sa amata ona toe manuia tagata o Nifae i le laueleele,", "And the people of Nephi began to prosper again in the land,"], ["ma amata ona uluola ma faasolo ina toe malolosi tele lava i le laueleele. Ma sa amata ona latou tutupu mauoa tele lava.", "and began to multiply and to wax exceedingly strong again in the land. And they began to grow exceedingly rich."]]},
  {num:49,words:[["Ae e ui ia latou oa,", "But notwithstanding their riches,"], ["po o lo latou malosi,", "or their strength,"], ["po o lo latou manuia,", "or their prosperity,"], ["sa le faafefeteina i latou i le faamaualuluga o o latou mata;", "they were not lifted up in the pride of their eyes;"], ["pe sa gese foi ona latou manatua o le Alii lo latou Atua;", "neither were they slow to remember the Lord their God;"], ["ae sa latou faalotomaualalalo tele lava i latou lava i ona luma.", "but they did humble themselves exceedingly before him."]]},
  {num:50,words:[["Ioe,", "Yea,"], ["sa latou manatua mea tetele na faia e le Alii mo i latou,", "they did remember how great things the Lord had done for them,"], ["sa ia laveai ai i latou mai le oti, ma mai noanoaga,", "that he had delivered them from death,"], ["ma mai falepuipui,", "and from bonds,"], ["ma mai ituaiga uma o puapuaga eseese,", "and from prisons,"], ["ma sa ia laveai i latou i fafo o lima o o latou fili.", "and from all manner of afflictions and he had delivered them out of the hands of their enemies."]]},
  {num:51,words:[["Ma sa latou tatalo atu i le Alii lo latou Atua e le aunoa,", "And they did pray unto the Lord their God continually,"], ["sa oo ina faamanuiaina i latou e le Alii,", "insomuch that the Lord did bless them,"], ["e tusa ma lana afioga,", "according to his word,"], ["sa oo ina latou faasolo malolosi ma manuia ai i le laueleele.", "so that they did wax strong and prosper in the land."]]},
  {num:52,words:[["Ma sa oo ina o mea uma nei sa faia. Ma sa maliu Helamana,", "And it came to pass that all these things were done. And Helaman died,"], ["i le tausaga e tolu sefulu ma le lima o le nofoaiga a faamasino i luga o le nuu o Nifae.", "in the thirty and fifth year of the reign of the judges over the people of Nephi."]]},
];
renderVerseSet(al_ch_62_Verses, 'al-ch62-verses');

var al_ch_63_Verses = [
  {num:1,words:[["Ma sa oo i le amataga o le tausaga e tolu sefulu ma le ono o le nofoaiga a faamasino i luga o le nuu o Nifae,", "And it came to pass in the commencement of the thirty and sixth year of the reign of the judges over the people of Nephi,"], ["na ave ai e Sepulona le tausiga o mea paia na na tuu atu ia Helamana e Alema.", "that Shiblon took possession of those sacred things which had been delivered unto Helaman by Alma."]]},
  {num:2,words:[["Ma o ia o se tagata amiotonu,", "And he was a just man,"], ["ma sa savali ma le tonu o ia i luma o le Atua;", "and he did walk uprightly before God;"], ["ma sa ia tausi e fai mea lelei e le aunoa,", "and he did observe to do good continually,"], ["e tausi poloaiga a le Alii lona Atua;", "to keep the commandments of the Lord his God;"], ["ma sa faapea foi lona uso.", "and also did his brother."]]},
  {num:3,words:[["Ma sa oo ina maliu foi Moronae. Ma sa faapea ona iu o le tausaga e tolu sefulu ma le ono o le nofoaiga a faamasino.", "And it came to pass that Moroni died also. And thus ended the thirty and sixth year of the reign of the judges."]]},
  {num:4,words:[["Ma sa oo i le tausaga e tolu sefulu ma le fitu o le nofoaiga a faamasino,", "And it came to pass that in the thirty and seventh year of the reign of the judges,"], ["sa i ai se vaega toatele o tagata,", "there was a large company of men,"], ["sa oo le aofai i le lima afe ma le fa selau o tane,", "even to the amount of five thousand and four hundred men,"], ["faatasi ma a latou ava ma a latou fanau,", "with their wives and their children,"], ["sa o ese atu i fafo mai le laueleele o Sara'emila i le laueleele lea sa i matu .", "departed out of the land of Zarahemla into the land which was northward."]]},
  {num:5,words:[["Ma o Hakota,", "And it came to pass that Hagoth,"], ["ona o ia o se tagata sogasoga tele,", "he being an exceedingly curious man,"], ["o lea na alu atu ai o ia ma fau mo ia se vaa tele lava,", "therefore he went forth and built him an exceedingly large ship,"], ["i tuaoi o le laueleele o Nuumau,", "on the borders of the land Bountiful,"], ["i tafatafa o le laueleele o Tuufua,", "by the land Desolation,"], ["ma tuuvaa atu i le sami i sisifo,", "and launched it forth into the west sea,"], ["i tafatafa ane o le laueleele vaitiiti lea sa tau atu i le laueleele i matu.", "by the narrow neck which led into the land northward."]]},
  {num:6,words:[["Ma faauta,", "And behold,"], ["sa i ai le toatele o sa Nifaē sa ulu atu i totonu o lena vaa ma folau atu ai ma sauniuniga e tele,", "there were many of the Nephites who did enter therein and did sail forth with much provisions,"], ["ma le toatele foi o fafine ma tamaiti e toatele;", "and also many women and children;"], ["ma sa alu lo latou ala agai i matu. Ma sa faapea ona iu o le tausaga e tolu sefulu ma le fitu.", "and they took their course northward. And thus ended the thirty and seventh year."]]},
  {num:7,words:[["Ma i le tausaga e tolu sefulu ma le valu,", "And in the thirty and eighth year,"], ["na fau ai e lenei tagata ni isi vaa. Ma sa toe foi mai le vaa muamua,", "this man built other ships. And the first ship did also return,"], ["ma sa sili atu le toatele o tagata na ulu atu i ai i totonu;", "and many more people did enter into it;"], ["ma sa latou ave foi sauniuniga e tele,", "and they also took much provisions,"], ["ma toe folau atu i fafo i le laueleele i matu.", "and set out again to the land northward."]]},
  {num:8,words:[["Ma sa oo ina le toe faalogoina se tala e uiga ia te i latou.", "And it came to pass that they were never heard of more."], ["Ma ua matou manatu ua malelemo i latou i le loloto o le sami.", "And we suppose that they were drowned in the depths of the sea."], ["Ma sa oo ina sa i ai foi se isi vaa e tasi sa folau atu; ma o le mea ua alu i ai,", "And it came to pass that one other ship also did sail forth;"], ["ua matou le iloa.", "and whither she did go we know not."]]},
  {num:9,words:[["Ma sa oo ina sa toatele tagata o e na o atu i le laueleele i matu i le tausaga lenei. Ma sa faapea ona iu o le tausaga e tolu sefulu ma le valu.", "And it came to pass that in this year there were many people who went forth into the land northward. And thus ended the thirty and eighth year."]]},
  {num:10,words:[["Ma sa oo i le tausaga e tolu sefulu ma le iva o le nofoaiga a faamasino,", "And it came to pass in the thirty and ninth year of the reign of the judges,"], ["na maliu ai foi Sepulona,", "Shiblon died also,"], ["ma sa alu Korianetona i le laueleele i matu i se vaa,", "and Corianton had gone forth to the land northward in a ship,"], ["e momoli atu meaai i tagata o e na o atu i lena laueleele.", "to carry forth provisions  unto the people who had gone forth into that land."]]},
  {num:11,words:[["O lea sa tatau ai ia Sepulona ona faaee atu ia mea paia,", "Therefore it became expedient for Shiblon to confer those sacred things,"], ["ae lei maliu o ia,", "before his death,"], ["i luga o le atalii o Helamana ,", "upon the son of Helaman,"], ["o le na igoa ia Helamana,", "who was called Helaman,"], ["sa faaigoa i le igoa o lona tamā.", "being called after the name of his father."]]},
  {num:12,words:[["O lenei faauta,", "Now behold,"], ["o ia togitogiga uma sa i ai i le tausiga a Helamana sa tusia ma auina atu i totonu o le fanauga a tagata i le laueleele atoa,", "all those engravings which were in the possession  of Helaman were written and sent forth among the children of men  throughout all the land,"], ["vagana ai vaega ia sa poloaiina e Alema e le tatau ona auina atu.", "save it were those parts which had been  commanded by Alma should not go forth."]]},
  {num:13,words:[["E ui i lea,", "Nevertheless,"], ["o nei mea sa poloaia ia tausia i le paia,", "these things were to be kept sacred,"], ["ma tuulima faasolo atu i lalo mai le tasi tupulaga i le isi tupulaga;", "and handed down from one generation to another;"], ["o lea,", "therefore,"], ["o le tausaga lenei,", "in this year,"], ["na tuu atu ai ia mea i luga o Helamana,", "they had been conferred upon Helaman,"], ["ae lei maliu Sepulona.", "before the death of Shiblon."]]},
  {num:14,words:[["Ma sa oo o le tausaga foi lenei sa i ai ni isi tagata faatuiese o e na o atu i sa Lamanā;", "And it came to pass also in this year that there were some dissenters who had gone forth unto the Lamanites;"], ["ma sa toe faaosoina ai foi i latou i le ita e faasaga ia sa Nifaē.", "and they were stirred up again to anger against the Nephites."]]},
  {num:15,words:[["Ma o le tausaga foi lenei e tasi na latou o mai ai i lalo ma se autau toatele lava e tau faasaga mai i le nuu o Moronaea ,", "And also in this same year they came down with a numerous army to war against the people of Moronihah,"], ["pe e faasaga i le autau a Moronaea,", "or against the army of Moronihah,"], ["lea na latou toilalo ai ma toe tutulia i tua i o latou lava laueleele,", "in the which they were beaten and driven back again to their own lands,"], ["ma mafatia ai i se toesega tele.", "suffering great loss."]]},
  {num:16,words:[["Ma sa faapea ona iu o le tausaga e tolu sefulu ma le iva o le nofoaiga a faamasino i luga o le nuu o Nifae.", "And thus ended the thirty and ninth year of the reign of the judges over the people of Nephi."]]},
  {num:17,words:[["Ma ua faapea ona iu o le tala a Alema,", "And thus ended the account of Alma,"], ["ma Helamana lona atalii,", "and Helaman his son,"], ["ma Sepulona,", "and also Shiblon,"], ["o le o lona atalii.", "who was his son."]]},
];
renderVerseSet(al_ch_63_Verses, 'al-ch63-verses');

})();